window.PLANT_DATA = [{"id":1,"seq":1,"zh":"无油樟","en":"Amborella trichopoda","sci":"Amborella trichopoda","order_en":"Amborellales","order_zh":"无油樟目","family_en":"Amborellaceae","family_zh":"无油樟科","iucn":"LC","langs":38,"desc_zh":"无油樟（学名：Amborella trichopoda）又名互叶梅，自成一目、一科、一属，只生长在新喀里多尼亚，是一种孑遗植物。 无油樟是现存被子植物中已知最早和其它被子植物分开演化的，因而倍受植物学家注目。","desc_en":"Amborella is a monotypic genus of understory shrubs or small trees endemic to the main island, Grande Terre, of New Caledonia in the southwest Pacific Ocean.","img":"images/1.jpg","thumb":"images/t/1.jpg","file":"Amborella trichopoda 1.jpg","ar":1.311,"py":"wuyouzhang wyz","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["大洋洲"]},{"id":2,"seq":2,"zh":"白睡莲","en":"Nymphaea alba","sci":"Nymphaea alba","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":64,"desc_zh":"白睡莲（ 学名：Nymphaea alba）又名欧洲白睡莲，是一种源自于欧洲的睡莲属植物。其种加词“alba”意为“白色的”。","desc_en":"Nymphaea alba – commonly called the white water lily, European white water lily, or white nenuphar ( NEN-yuu-far) – is an aquatic flowering plant in the family Nymphaeaceae.","img":"images/2.jpg","thumb":"images/t/2.jpg","file":"Nymphaea alba in Duisburg.jpg","ar":1.471,"py":"baishuilian bsl","cr_by":"DerHexer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/2.jpg","illus_thumb":"images/i/t/2.jpg","illus_file":"Illustration Nymphaea alba0.jpg","illus_ar":0.664,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":3,"seq":3,"zh":"欧亚萍蓬草","en":"Nuphar lutea","sci":"Nuphar lutea","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":58,"desc_zh":"欧亚萍蓬草（学名：Nuphar lutea）（又名：青荷根、大荷根、荷根、荷根草、露特萍蓬草），是睡莲科萍蓬草属的植物。分布于伊朗、欧洲、中亚、俄罗斯、西伯利亚以及中国大陆的新疆等地，见于池沼，目前尚未由人工引种栽培。","desc_en":"Nuphar lutea, the yellow water-lily, is an aquatic plant of the family Nymphaeaceae, native to northern temperate and some subtropical regions of Europe, northwest Africa, and western Asia.","img":"images/3.jpg","thumb":"images/t/3.jpg","file":"Nuphar lutea (habitus).jpg","ar":1.333,"py":"ouyapingpengcao oyppc","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/3.jpg","illus_thumb":"images/i/t/3.jpg","illus_file":"Nuphar lutea - Deutschlands Flora in Abbildungen nach der natur - vol. 5 t. 34 - clean.jpg","illus_ar":0.667,"illus_by":"Jacob Sturm","illus_lic":"Public domain","illus_licurl":null},{"id":4,"seq":4,"zh":"王莲","en":"Victoria amazonica","sci":"Victoria amazonica","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":null,"langs":45,"desc_zh":"亚马逊王莲（学名：Victoria amazonica），又称亚马逊皇莲或皇家睡莲，是王莲属下的一种，是睡莲科最大的植物。 它原产于亚马逊河盆地，被圭亚那当作国花。 亚马逊王莲的叶子直径可达三米，茎长可达七至八米。刚开的花呈白色，但一夜之间就会变成粉色。花的直径也有40厘米。 刚开花时，白色花瓣散发浓烈香味，将强力吸引金龟子(或其他昆虫)前来授粉，当金龟子飞来时，花朵会轻轻阖上，让包裹在花瓣中的金龟全身沾满睡莲的花粉。","desc_en":"Victoria amazonica (\"giant water lily\") is a species of flowering plant, the second largest in the water lily family Nymphaeaceae. It is called Vitória-Régia or Iaupê-Jaçanã (\"the jacana's waterlily\") in Brazil and Atun Sisac (\"great flower\") in Inca (Quechua)…","img":"images/4.jpg","thumb":"images/t/4.jpg","file":"Victoria amazonica edit 1.jpg","ar":0.833,"py":"wanglian wl","cr_by":"Bilby","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":5,"seq":5,"zh":"芡","en":"Euryale ferox","sci":"Euryale ferox","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":40,"desc_zh":"芡（学名：Euryale ferox），又名䓈，民间俗称“鸡头莲”，是属于睡莲科芡属的水生植物，芡属是个单型属，只有这一物种。芡的种子称为“芡实”或“芡米”、“鸡头米”。芡实磨成“芡粉”后可用于“勾芡”。产于广东省肇庆的芡实可被标记为“肇实”，如同山药中“淮山”。","desc_en":"Euryale ferox, commonly known as prickly waterlily, makhānā, or Gorgon plant, is a species of water lily found in southern and eastern Asia, and the only extant member of the genus Euryale.","img":"images/5.jpg","thumb":"images/t/5.jpg","file":"Euryale ferox.jpg","ar":1.268,"py":"qian q","cr_by":"John Sims","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":1002,"seq":6,"zh":"白花穗莼","en":"Cabomba caroliniana","sci":"Cabomba caroliniana","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Cabombaceae","family_zh":"莼菜科","iucn":null,"langs":27,"desc_zh":"白花穗莼（学名：Cabomba caroliniana），又名水盾草、绿菊、绿菊花草，是莼菜科穗莼属的一种水生植物。原产于南美洲东部。","desc_en":"Cabomba caroliniana, commonly known as Carolina fanwort, is a rhizomatous, aquatic, perennial herb native to North and South America. Having been a popular aquarium plant, it has been exported around the world and has become an invasive species in Europe and A…","img":"images/1002.jpg","thumb":"images/t/1002.jpg","file":"Algal Bloom - പായൽ 03.JPG","ar":1.333,"py":"baihuasuichun bhsc","cr_by":"കാക്കര","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["南美洲"]},{"id":1003,"seq":7,"zh":"Trithuria australis","en":"Trithuria australis","sci":"Trithuria australis","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Hydatellaceae","family_zh":"独蕊草科","iucn":null,"langs":6,"desc_zh":null,"desc_en":"Trithuria australis is a species of aquatic plant in the family Hydatellaceae endemic to Western Australia.","img":"images/1003.jpg","thumb":"images/t/1003.jpg","file":"Botanische Jahrbücher für Systematik, Pflanzengeschichte und Pflanzengeographie (1904) (20402793025).jpg","ar":0.738,"py":"","cr_by":"Engler, Adolf, 1844-1930","cr_lic":"No restrictions","cr_licurl":"https://www.flickr.com/commons/usage/","habit":null,"origin":["大洋洲"]},{"id":7,"seq":8,"zh":"八角","en":"Illicium verum","sci":"Illicium verum","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Schisandraceae","family_zh":"五味子科","iucn":null,"langs":76,"desc_zh":"八角（学名：Illicium verum），又称八角茴香、大料和大茴香（在某些地方、场合，大茴香指的是茴芹种子），是木兰藤目五味子科八角属的一种植物。其同名的干燥果实是中国菜和东南亚地区烹饪的调味料之一。","desc_en":"Illicium verum (star anise or badian, Chinese star anise, star anise seed, star aniseed and star of anise) is a medium-sized evergreen tree native to South China and northeast Vietnam.","img":"images/7.jpg","thumb":"images/t/7.jpg","file":"Illicium verum 4zz.jpg","ar":1.504,"py":"bajiao bj","cr_by":"Photo by David J. Stang","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":8,"seq":9,"zh":"五味子","en":"Schisandra chinensis","sci":"Schisandra chinensis","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Schisandraceae","family_zh":"五味子科","iucn":null,"langs":38,"desc_zh":"五味子（学名：Schisandra chinensis），又称作五味、北五味子、山五味、山花椒、荎藸（拼音：chíchú），六亭剂、为五味子科五味子属下的一种植物。唐朝《新修本草》载“五味皮肉甘酸，核中辛苦，都有咸味”，所以得名。","desc_en":"Schisandra chinensis, whose fruit is called schisandra, magnolia berry or five-flavor fruit, is a vine plant native to forests of Northern China, the Russian Far East, Korea, and Japan. It is hardy in USDA Zones 4-8.","img":"images/8.jpg","thumb":"images/t/8.jpg","file":"Schisandra sinensis.jpg","ar":0.665,"py":"wuweizi wwz","cr_by":"Doronenko","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"藤本","origin":["亚洲"]},{"id":1004,"seq":10,"zh":"日本莽草","en":"Illicium anisatum","sci":"Illicium anisatum","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Schisandraceae","family_zh":"五味子科","iucn":null,"langs":32,"desc_zh":"日本莽草（学名：Illicium anisatum）为五味子科八角属常绿乔木。与八角相似，但剧毒，不可食用。可用于制香供佛。","desc_en":"Illicium anisatum, with common names Japanese star anise, aniseed tree, and sacred anise tree, known in Japanese as shikimi (樒; シキミ), is an evergreen shrub or small tree closely related to the Chinese star anise (Illicium verum).","img":"images/1004.jpg","thumb":"images/t/1004.jpg","file":"Illicium anisatum - Köhler–s Medizinal-Pflanzen-075.jpg","ar":0.738,"py":"ribenmangcao rbmc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"],"illus_img":"images/i/1004.jpg","illus_thumb":"images/i/t/1004.jpg","illus_file":"Illicium anisatum - Köhler–s Medizinal-Pflanzen-075.jpg","illus_ar":0.738,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1005,"seq":11,"zh":"木兰藤","en":"Austrobaileya scandens","sci":"Austrobaileya scandens","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Austrobaileyaceae","family_zh":"木兰藤科","iucn":null,"langs":24,"desc_zh":"木兰藤（学名：Austrobaileya scandens）属被子植物木兰藤目，为木兰藤科（Austrobaileyaceae）木兰藤属下已知唯一种，是生长在澳大利亚昆士兰湿热带地区的特有种。","desc_en":"Austrobaileya is the sole genus in the plant family Austrobaileyaceae – the family is thus 'monotypic' as it includes a single child taxon. It is one of the basal angiosperm families, the most ancient group of flowering plants.","img":"images/1005.jpg","thumb":"images/t/1005.jpg","file":"Austrobaileya scandens 01.jpg","ar":1.333,"py":"mulanteng mlt","cr_by":"tanetahi","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["大洋洲"]},{"id":1006,"seq":12,"zh":"大八角","en":"Illicium majus","sci":"Illicium majus","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Illiciaceae","family_zh":"八角茴香科","iucn":"LC","langs":8,"desc_zh":"大八角（学名：Illicium majus）是八角茴香科八角属的植物。分布于越南、缅甸以及中国大陆的广东、贵州、广西、湖南、云南等地，生长于海拔200米至2,300米的地区，一般生于混交林、灌丛中、密林或有林的石坡溪流沿岸，目前尚未由人工引种栽培。","desc_en":"Illicium majus is a species of flowering plant in the family Schisandraceae. It is a tree with subleathery leaves and poisonous fruits. The species is native to China, Myanmar, and Vietnam.","img":"images/1006.jpg","thumb":"images/t/1006.jpg","file":"Illicium majus in Kunming Botanical Garden.jpg","ar":0.657,"py":"dabajiao dbj","cr_by":"Zhangmoon618","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":9,"seq":13,"zh":"荷花玉兰","en":"Magnolia grandiflora","sci":"Magnolia grandiflora","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":54,"desc_zh":"荷花玉兰（学名：Magnolia grandiflora），又名洋玉兰（中国树木分类学）、广玉兰（上海），为木兰科木兰属的植物，原产美洲，北美洲以及中国大陆的长江流域及其以南有栽培，北方如北京、兰州等地有引种。供观赏，花含芳香油。 种名grandiflora意为“大花的”。","desc_en":"Magnolia grandiflora, commonly known as the southern magnolia or bull bay, is a tree of the family Magnoliaceae native to the Southeastern United States coastal plain, from Virginia to central Florida, and west to East Texas. Reaching 27.","img":"images/9.jpg","thumb":"images/t/9.jpg","file":"Magnolia flower Duke campus.jpg","ar":1.6,"py":"hehuayulan hhyl","cr_by":"DavetheMage","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["北美洲"],"illus_img":"images/i/9.jpg","illus_thumb":"images/i/t/9.jpg","illus_file":"T2 65 Magnolia grandiflora par Pierre-Joseph Redouté.jpeg","illus_ar":0.707,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":10,"seq":14,"zh":"北美鹅掌楸","en":"Liriodendron tulipifera","sci":"Liriodendron tulipifera","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":44,"desc_zh":"北美鹅掌楸（学名：Liriodendron tulipifera）为木兰科鹅掌楸属下的一个种。分布在北美东部。","desc_en":"Liriodendron tulipifera—known as the tulip tree, American tulip tree, tulipwood, tuliptree, tulip poplar, whitewood, fiddletree, lynn-tree, hickory-poplar, and yellow-poplar—is the North American representative of the two-species genus Liriodendron (the other…","img":"images/10.jpg","thumb":"images/t/10.jpg","file":"Liriodendron tulipifera JPG5a.jpg","ar":0.667,"py":"beimeiezhangqiu bmezq","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["北美洲"],"illus_img":"images/i/10.jpg","illus_thumb":"images/i/t/10.jpg","illus_file":"The American Flora. Vol. 3, 1855 - pl. 12 Liriodendron tulipifera (10172224925).jpg","illus_ar":1.419,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":11,"seq":15,"zh":"黄玉兰","en":"Magnolia champaca","sci":"Magnolia champaca","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":44,"desc_zh":"黄玉兰（学名：Michelia champaca），俗称南洋乌心石，为木兰科含笑属下的一个种。原产地为喜马拉雅山、中国南部、印度、爪哇岛和菲律宾，台湾在1800年间引进，目前各地有零星栽培。小乔木或灌木，高及蓬径3－6米，叶革质，翠绿色，达16厘米长；花芬芳，橙黄色或乳白色，春季开花，可提取精油用于制作香水。 《中国植物志》认为《植物名实图考》的“黄兰”为此种，但从描述和绘图来看“黄兰”也可能是小依兰。","desc_en":"Magnolia champaca, known in English as champak (), is a large evergreen tree in the family Magnoliaceae. It was previously classified as Michelia champaca. It is known for its fragrant flowers, and its timber used in woodworking.","img":"images/11.jpg","thumb":"images/t/11.jpg","file":"Michelia champaca Blanco1.191-cropped.jpg","ar":0.899,"py":"huangyulan hyl","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":12,"seq":16,"zh":"日本辛夷","en":"Magnolia kobus","sci":"Magnolia kobus","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"DD","langs":32,"desc_zh":"日本辛夷（学名：Magnolia kobus，又名日本玉兰）属于木兰科木兰属，是一种原产于日本的玉兰，落叶小乔木，生长率低，但株高可达7.6公尺，树干直径可达10.7公尺。1920年代引种至中国青岛。","desc_en":"Magnolia kobus, known as mokryeon, kobus magnolia, or kobushi magnolia, is a species of Magnolia native to Japan (Kyushu, Honshu, and Hokkaido) and Korea and occasionally cultivated in temperate areas.","img":"images/12.jpg","thumb":"images/t/12.jpg","file":"Magnolia kobus borealis.jpg","ar":1.174,"py":"ribenxinyi rbxy","cr_by":"Bruce Marlin","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":13,"seq":17,"zh":"玉兰","en":"Magnolia denudata","sci":"Magnolia denudata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":31,"desc_zh":"玉兰（学名：Magnolia denudata），别名白玉兰、望春花、玉兰花，原产中国中部山野，现于世界各地庭园常见栽培。玉兰是上海市市花。中文中惯称含笑属的白兰（学名：Michelia x alba）为「玉兰花」，但实际上两者为不同种不同属的植物。","desc_en":"Magnolia denudata, the lilytree or Yulan magnolia (simplified Chinese: 玉兰花; traditional Chinese: 玉蘭花; pinyin: yùlánhuā; lit. 'jade orchid/lily'), is native to central and eastern China. It has been cultivated in Chinese Buddhist temple gardens since 600 AD.","img":"images/13.jpg","thumb":"images/t/13.jpg","file":"Yulan 1.JPG","ar":1.333,"py":"yulan yl","cr_by":"The original uploader was Yongxinge at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"],"illus_img":"images/i/13.jpg","illus_thumb":"images/i/t/13.jpg","illus_file":"The American Flora. Vol. 2, 1855 - pl. 29 Magnolia denudata (8079589055).jpg","illus_ar":0.719,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":14,"seq":18,"zh":"白背玉兰","en":"Magnolia virginiana","sci":"Magnolia virginiana","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Magnolia virginiana, most commonly known as sweetbay magnolia, or merely sweetbay (also laurel magnolia, swampbay, swamp magnolia, white bay, or beaver tree), is a member of the magnolia family, Magnoliaceae.","img":"images/14.jpg","thumb":"images/t/14.jpg","file":"Sweetbay Magnolia Magnolia virginiana Comparison 4400px.jpg","ar":2.085,"py":"baibeiyulan bbyl","cr_by":"Photo by and (c)2008 Derek Ramsey ( Ram-Man ). Co-attribution must be given to the Chanticleer Garden.","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null,"illus_img":"images/i/14.jpg","illus_thumb":"images/i/t/14.jpg","illus_file":"T2 66 (a) Magnolia virginiana par Pierre-Joseph Redouté.jpeg","illus_ar":0.709,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":15,"seq":19,"zh":"星花木兰","en":"Magnolia stellata","sci":"Magnolia stellata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"EN","langs":30,"desc_zh":"星花木兰（学名：Magnolia stellata），又名日本毛木兰，为木兰科木兰属的植物。分布于日本以及中国大陆的青岛、南京等地，目前已由人工引种栽培。星花兰木的原产地为日本，因为开花的时间开得比较早，所以被视为春天的开始。《二如亭群芳谱》中记载着「玉兰，花九瓣，色白，微碧，香味似兰，故名。丛生，一干一花皆著木末，绝无柔条。隆冬结蕾，三月盛开。」，星花木兰清香扑鼻，颜色鲜艳，是春季最具代表的观赏花之一，深受花迷的喜欢。","desc_en":"Magnolia stellata, the star magnolia, is a slow-growing deciduous shrub or small tree native to Japan. It bears large, showy white or pink flowers in early spring, before its leaves open.","img":"images/15.jpg","thumb":"images/t/15.jpg","file":"Magnolia stellata fleurs.jpg","ar":1.18,"py":"xinghuamulan xhml","cr_by":"Myrabella","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":19,"seq":20,"zh":"刺果番荔枝","en":"Annona muricata","sci":"Annona muricata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":82,"desc_zh":"刺果番荔枝（学名：Annona muricata），新马一带俗称红毛榴梿（马来语：durian belanda），一种热带水果，属番荔枝科番荔枝属。虽然别名里有「榴梿」二字，但不具臭味，分类上与台湾所产的释迦（即番荔枝）相近。果肉呈乳白色，酸甜多汁，种子黑色，散在果肉纹理中。 原产于美洲热带地区，现广泛引种于世界各地。中国大陆产区为海南、云南、广西等气温较高地区。","desc_en":"Soursop (also called graviola, guyabano, and in Hispanic America guanábana) is the fruit of Annona muricata, a broadleaf, flowering, evergreen tree. It is native to the tropical Americas and is widely propagated.","img":"images/19.jpg","thumb":"images/t/19.jpg","file":"Annona muricata 1.jpg","ar":0.75,"py":"ciguofanlizhi cgflz","cr_by":"Damien Boilley from suburbs of Paris, France","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":null},{"id":20,"seq":21,"zh":"番荔枝","en":"Annona squamosa","sci":"Annona squamosa","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":77,"desc_zh":"番荔枝（学名：Annona squamosa），又称释迦、佛头果、佛果、释迦果、亚大菓子（指其果实）、亚大树（指果树）、林檎（广东潮汕地区）、唛螺陀（广西）、洋菠萝（广西龙州）、假菠萝（广西凭祥，因其外形与结构都酷似广西盛产的菠萝蜜）、番鬼荔枝（广东粤语区、香港、澳门）、麻窝楂（云南德宏）或蜜檎（印尼西加里曼丹省）等，为番荔枝科番荔枝属多年生半落叶性小乔木植物。多种植做经济作物，果肉白而甜。","desc_en":"Annona squamosa is a small, well-branched tree or shrub from the family Annonaceae that bears edible fruits called sugar apples or sweetsops or custard apples.","img":"images/20.jpg","thumb":"images/t/20.jpg","file":"Pomme cannelle ou zato.jpg","ar":1.333,"py":"fanlizhi flz","cr_by":"Chirocca77","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":21,"seq":22,"zh":"依兰","en":"Cananga odorata","sci":"Cananga odorata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":64,"desc_zh":"依兰（学名：Cananga odorata）是番荔枝科依兰属的植物。原产于东南亚的爪哇、马来西亚、菲律宾。一般生于热带地区，分布在印度尼西亚、菲律宾、台湾、缅甸、马来西亚以及中国大陆的广东、四川、云南、福建、广西等地。目前已由人工引种栽培，在亚洲的热带地区广泛种植。花可提炼香精，可制造高级香水。","desc_en":"Cananga odorata, commonly known as ylang-ylang (), Macassar oil tree, perfume tree or cananga, is a species of plant in the custard apple family Annonaceae.","img":"images/21.jpg","thumb":"images/t/21.jpg","file":"Cananga odorata flowers-cropped.jpg","ar":1,"py":"yilan yl","cr_by":"User:B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":22,"seq":23,"zh":"秘鲁番荔枝","en":"Annona cherimola","sci":"Annona cherimola","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":58,"desc_zh":"秘鲁番荔枝（学名：Annona cherimola），别名毛叶番荔枝、冷子番荔枝，是一种番荔枝科的植物。它是一种常绿约三至九米高的枝叶密集的树或者灌木。原产于秘鲁、厄瓜多尔及智利。","desc_en":"The cherimoya (Annona cherimola), also spelled cherimoyer and chirimoya, and called chirimuya by the Quechua people, is a species of edible fruit-bearing plant in the genus Annona, within the family Annonaceae, which also includes the closely related sweetsop…","img":"images/22.jpg","thumb":"images/t/22.jpg","file":"Annona cherimola fruit, Pedra Bela, Brazil.jpg","ar":1.333,"py":"bilufanlizhi blflz","cr_by":"Marcelo RosaMelo","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["北美洲","南美洲"]},{"id":23,"seq":24,"zh":"牛心番荔枝","en":"Annona reticulata","sci":"Annona reticulata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":55,"desc_zh":"牛心番荔枝（学名：Annona reticulata）又叫牛心果、牛心梨，是番荔枝科番荔枝属的植物。分布在亚洲、美洲、台湾以及中国大陆的云南、广东、福建、广西等地，目前已由人工引种养培。 果皮光滑淡绿色，成熟后颜色呈鲜红色，果肉香甜。果树高大约达三层楼建筑高度，产季整颗树上果实累累。 其种加词“reticuluma”意为“网纹的”。","desc_en":"Annona reticulata is a small deciduous or semi-evergreen tree in the plant family Annonaceae. It is best known for its fruit, called custard apple, a common name shared with fruits of several other species in the same genus: A. cherimola and A. squamosa.","img":"images/23.jpg","thumb":"images/t/23.jpg","file":"Annona reticulata Blanco1.197-cropped.jpg","ar":0.663,"py":"niuxinfanlizhi nxflz","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":24,"seq":25,"zh":"波波树","en":"Asimina triloba","sci":"Asimina triloba","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":47,"desc_zh":"泡泡果（学名：Asimina triloba）又名巴婆果、泡泡树，皆音译自其英文名称“pawpaw”，为番荔枝科泡泡属的物种，是一种原产于美国东部和加拿大的小落叶树，高35英尺（11米），直径8—12英寸（20—30厘米）。其果实为黄绿色至棕色。泡泡果和释迦、刺果番荔枝等同属番荔枝科，其果实是美国本土原产的水果中最大的可食用水果。果实味道具甜味，通常生吃，但也可用来制作冰淇淋。","desc_en":"Asimina triloba, the American papaw, pawpaw, paw paw, or paw-paw, among many regional names, is a species of small deciduous tree. It has large leaves and produces a large, yellowish-green to brown fruit.","img":"images/24.jpg","thumb":"images/t/24.jpg","file":"Asimina triloba3.jpg","ar":1.52,"py":"boboshu bbs","cr_by":"Scott Bauer, USDA","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["北美洲"],"illus_img":"images/i/24.jpg","illus_thumb":"images/i/t/24.jpg","illus_file":"T2 25 Asimina triloba par Pierre-Joseph Redouté.jpeg","illus_ar":0.712,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":26,"seq":26,"zh":"肉豆蔻","en":"Myristica fragrans","sci":"Myristica fragrans","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Myristicaceae","family_zh":"肉豆蔻科","iucn":"DD","langs":63,"desc_zh":"肉豆蔻（学名：Myristica fragrans），又名肉蔻、肉果、玉果、麻醉果，是一种重要的香料、药用植物。其种加词fragrans意为“芳香的”。肉豆蔻生长于热带地区的常绿植物，常见于东南亚、澳洲及加勒比海地区，尤以印度尼西亚和格林纳达产量最大。肉豆蔻的果实是肉豆蔻（英语：nutmeg；肉豆蔻的种子）和肉豆蔻皮/肉豆蔻衣/肉豆蔻花（英语：mace；肉豆蔻的假种皮）的来源，二者都是常见的香料，用于食品、菜肴的调味，前者可制作香精油。","desc_en":"Myristica fragrans, commonly known as the nutmeg tree, is an evergreen species indigenous to the Maluku Islands of Indonesia. This aromatic tree is economically significant as the primary source of two distinct spices: nutmeg, derived from its seed, and mace,…","img":"images/26.jpg","thumb":"images/t/26.jpg","file":"Myristica fragrans at Elmina West in Seksyen U15, Shah Alam 20231126 100924.jpg","ar":0.75,"py":"roudoukou rdk","cr_by":"Wiki Farazi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/26.jpg","illus_thumb":"images/i/t/26.jpg","illus_file":"Myristica fragrans - Köhler–s Medizinal-Pflanzen-097.jpg","illus_ar":0.752,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":27,"seq":27,"zh":"刺茎肉荳蔻","en":"Virola surinamensis","sci":"Virola surinamensis","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Myristicaceae","family_zh":"肉豆蔻科","iucn":"LC","langs":15,"desc_zh":null,"desc_en":"Virola surinamensis, known commonly as baboonwood, ucuuba, ucuhuba and chalviande, is a species of flowering plant in the family Myristicaceae. It is found in Bolivia, northern and central Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, Trini…","img":"images/27.jpg","thumb":"images/t/27.jpg","file":"Virola surinamensis (Wild nutmeg) Paramin Trinidad 2.jpg","ar":1.06,"py":"cijingroudoukou cjrdk","cr_by":"Feroze Omardeen","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["南美洲"]},{"id":1007,"seq":28,"zh":"安哥拉密花楠","en":"Pycnanthus angolensis","sci":"Pycnanthus angolensis","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Myristicaceae","family_zh":"肉豆蔻科","iucn":"LC","langs":15,"desc_zh":null,"desc_en":"Pycnanthus angolensis is a species of tree in the nutmeg family, Myristicaceae. It is native to tropical Africa. Its English language common names include African nutmeg, false nutmeg, boxboard, and cardboard. In Africa it is widely known as ilomba.","img":"images/1007.jpg","thumb":"images/t/1007.jpg","file":"Pycnanthus angolensis (Welw.) Warb. (GH0209).jpg","ar":0.637,"py":"angelamihuanan aglmhn","cr_by":"Collector(s): Appiah, Amposah Identifier: Gabriel Ameka","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["非洲"]},{"id":1008,"seq":29,"zh":"Degeneria vitiensis","en":"Degeneria vitiensis","sci":"Degeneria vitiensis","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Degeneriaceae","family_zh":"单室木兰科","iucn":"LC","langs":9,"desc_zh":null,"desc_en":"Degeneria vitiensis is a flowering tree found on Viti Levu in Fiji. It is known as masiratu and vāvāloa in Fijian, although the latter is also used for Litsea magnifolia. It is a relatively common plant and is used as timber.","img":"images/1008.png","thumb":"images/t/1008.png","file":"Degeneria vitiensis.png","ar":0.9,"py":"","cr_by":"Е.С. Тахтаджян, П.А. Жиличкин","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":null},{"id":1009,"seq":30,"zh":"Eupomatia laurina","en":"Eupomatia laurina","sci":"Eupomatia laurina","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Eupomatiaceae","family_zh":"帽花木科","iucn":"LC","langs":9,"desc_zh":null,"desc_en":"Eupomatia laurina, commonly named bolwarra, native guava or copper laurel, is a species of plant in the primitive flowering-plant family Eupomatiaceae endemic to Australia and New Guinea.","img":"images/1009.jpg","thumb":"images/t/1009.jpg","file":"Euplaur2.jpg","ar":1.501,"py":"","cr_by":"Steve Fitzgerald","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["大洋洲"]},{"id":1010,"seq":31,"zh":"Galbulimima belgraveana","en":"Galbulimima belgraveana","sci":"Galbulimima belgraveana","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Himantandraceae","family_zh":"瓣蕊花科","iucn":"LC","langs":10,"desc_zh":null,"desc_en":"Galbulimima belgraveana is a tropical forest tree with hallucinogenic properties. Its common names include agara, white magnolia and pigeonberry ash. It is native to Queensland, the Bismarck Archipelago, New Guinea, and the Solomon Islands.","img":"images/1010.jpg","thumb":"images/t/1010.jpg","file":"Galbulimima baccata RBG Sydney.JPG","ar":1.333,"py":"","cr_by":"Poyt448 Peter Woodard","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["大洋洲"]},{"id":28,"seq":32,"zh":"鳄梨","en":"Persea americana","sci":"Persea americana","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":145,"desc_zh":"鳄梨（学名：Persea americana，港澳称为牛油果，台湾称为酪梨，又称油梨或樟梨），是樟科鳄梨属的常绿乔木，果实可食用。鳄梨原产于中美洲，从墨西哥中部的高地森林到哥伦比亚西北部的雨林均有其自然分布地。考古证据显示，早在约一万年前（公元前8000–7000年），墨西哥等地的中美洲原住民就已开始食用本种，而出现时间更晚的一些遗址（距今6000 - 4800年）中发现的鳄梨种子则体积更大，表明当时的人类可能已经开始人工选择鳄梨。","desc_en":"The avocado, alligator pear or avocado pear (Persea americana) is an evergreen tree in the laurel family (Lauraceae). It is native to the Americas, with archaeological evidence of early human avocado use dating back thousands of years across various regions of…","img":"images/28.jpg","thumb":"images/t/28.jpg","file":"Persea americana fruit 2.JPG","ar":0.8,"py":"eli el","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["南美洲"]},{"id":29,"seq":33,"zh":"月桂","en":"Laurus nobilis","sci":"Laurus nobilis","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":86,"desc_zh":"月桂（学名：Laurus nobilis），又称月桂树、桂冠树、甜月桂、月桂冠，是调味料月桂叶的来源。原产于地中海沿岸及小亚细亚一带灌木岩石区，现已遍布世界各地。 叶片深绿色，椭圆形，革质，味苦，清香。干燥后，苦味减少，香气增强，可以用作调料，即“香叶”。 古代希腊人用月桂的小枝条编织成桂冠，授予皮提亚运动会的胜利者，象征荣耀与胜利。","desc_en":"Laurus nobilis is an aromatic evergreen tree or large shrub with green, glabrous (smooth) leaves. It is in the flowering plant family Lauraceae. According to Muer, Jahn, & Sauerbier, the stem can be 1 metre in diameter and the tree can be as high as 20 metres.","img":"images/29.jpg","thumb":"images/t/29.jpg","file":"Laurier.jpg","ar":1.333,"py":"yuegui yg","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲"],"illus_img":"images/i/29.jpg","illus_thumb":"images/i/t/29.jpg","illus_file":"Laurus nobilis (Köhler).jpg","illus_ar":0.75,"illus_by":"Franz Eugen Köhler & Walther Müller","illus_lic":"CC BY 2.5","illus_licurl":"https://creativecommons.org/licenses/by/2.5"},{"id":30,"seq":34,"zh":"樟树","en":"Cinnamomum camphora","sci":"Cinnamomum camphora","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":72,"desc_zh":"樟树（学名：Camphora officinarum）是樟科常绿大乔木，别名香樟、本樟、乌樟、栳樟、樟仔，以往为制造樟脑的经济树种，因天然熬樟已没落而改用化工合成樟油，目前只作景观园林或防风树种。 “樟”的由来有两种说法：一是李时珍《本草纲目》记载，「其木理多纹章，故谓之樟」；二是其有香味，类似发散香气的动物「獐」而得名。","desc_en":"Camphora officinarum is a species of evergreen tree indigenous to warm temperate to subtropical regions of East Asia, including countries such as China, Taiwan, Vietnam, Korea, Japan and India.","img":"images/30.jpg","thumb":"images/t/30.jpg","file":"Cinnamomum camphora20050314.jpg","ar":1.267,"py":"zhangshu zs","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/30.jpg","illus_thumb":"images/i/t/30.jpg","illus_file":"Cinnamomum camphora (Köhler).jpg","illus_ar":0.667,"illus_by":"Hermann Adolf Köhler (1834 - 1879)","illus_lic":"Public domain","illus_licurl":null},{"id":31,"seq":35,"zh":"锡兰肉桂","en":"Cinnamomum verum","sci":"Cinnamomum verum","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"VU","langs":63,"desc_zh":"锡兰肉桂（学名：Cinnamomum verum）是樟科肉桂属植物，原产斯里兰卡，在中国广东、海南、广西、台湾均有栽培。其树皮，亦称锡兰肉桂。 在欧美，英文所称 Cinnamon 多指此类。","desc_en":"Cinnamomum verum (synonym Cinnamomum zeylanicum), also known as true cinnamon or Ceylon cinnamon, is a small evergreen tree belonging to the family Lauraceae, native to Sri Lanka.","img":"images/31.jpg","thumb":"images/t/31.jpg","file":"Cinnamomum verum1.jpg","ar":1.548,"py":"xilanrougui xlrg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"],"illus_img":"images/i/31.jpg","illus_thumb":"images/i/t/31.jpg","illus_file":"Cinnamomum verum - Köhler–s Medizinal-Pflanzen-182.jpg","illus_ar":0.78,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":32,"seq":36,"zh":"肉桂","en":"Cinnamomum cassia","sci":"Cinnamomum cassia","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":null,"langs":47,"desc_zh":"肉桂（学名：Cinnamomum cassia，英语：Cinnamon），又称作官桂、桂心、简桂、玉桂、牡桂，为樟科常绿乔木。还有另一品种锡兰肉桂。两种皆含有微量香豆素，摄取过多肉桂，可能引发副作用。","desc_en":"Cinnamomum cassia, called Chinese cassia, cassia cinnamon, or Chinese cinnamon, is an evergreen tree originating in southern China and widely cultivated there and elsewhere in South and Southeast Asia.","img":"images/32.jpg","thumb":"images/t/32.jpg","file":"Cinnamomum aromaticum - Köhler–s Medizinal-Pflanzen-039 cropped.jpg","ar":0.844,"py":"rougui rg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"],"illus_img":"images/i/32.jpg","illus_thumb":"images/i/t/32.jpg","illus_file":"Cinnamomum cassia (Köhler).jpg","illus_ar":0.75,"illus_by":"Franz Eugen Köhler & Walther Müller","illus_lic":"CC BY 2.5","illus_licurl":"https://creativecommons.org/licenses/by/2.5"},{"id":33,"seq":37,"zh":"柴桂","en":"Cinnamomum tamala","sci":"Cinnamomum tamala","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":30,"desc_zh":"柴桂（学名：Cinnamomum tamala）是樟科肉桂属的植物。分布在不丹、尼泊尔、印度以及中国大陆的云南等地，生长于海拔1,180米至1,930米的地区，多生于山坡、谷地的常绿阔叶林中或水边。","desc_en":"Cinnamomum tamala, Indian bay leaf, also known as tejpat, tejapatta, Malabar leaf, Indian bark, Indian cassia, or malabathrum, is a tree in the family Lauraceae that is native to northern India (Assam and the Western Himalayas), Bangladesh, Nepal, Myanmar, Lao…","img":"images/33.jpg","thumb":"images/t/33.jpg","file":"Indian bay leaf - tejpatta - indisches Lorbeerblatt.jpg","ar":1.333,"py":"chaigui cg","cr_by":"Sonja Pauen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"],"illus_img":"images/i/33.jpg","illus_thumb":"images/i/t/33.jpg","illus_file":"Cinnamomum tamala illustration.jpg","illus_ar":0.781,"illus_by":"Friedrich Gottlob Hayne (book author)","illus_lic":"Public domain","illus_licurl":null},{"id":34,"seq":38,"zh":"亚速尔月桂","en":"Laurus azorica","sci":"Laurus azorica","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":25,"desc_zh":null,"desc_en":"Laurus azorica, the Azores laurel or Macaronesian laurel, is a small, evergreen tree in the laurel family (Lauraceae), found only on the Azores island group in the North Atlantic.","img":"images/34.jpg","thumb":"images/t/34.jpg","file":"Laurus azorica (Flowers).jpg","ar":1.333,"py":"yasueryuegui yseyg","cr_by":"Ixitixel","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null},{"id":35,"seq":39,"zh":"北美檫树","en":"Sassafras albidum","sci":"Sassafras albidum","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":25,"desc_zh":"北美檫树（学名：Sassafras albidum）或称美国檫树、美洲檫木、白檫、红檫、黄樟等，为樟科檫树属，原产于北美洲东部，以美国缅因州、加拿大安大略省为北界，南至佛罗里达州，西至爱荷华州及德克萨斯州东部，常见于海拔1500公尺左右的落叶林中，北美檫树原本曾是威斯康辛州的原生植物，但现今此树种已于该地区消失。","desc_en":"Sassafras albidum (sassafras, white sassafras, red sassafras, or silky sassafras) is a species of Sassafras native to eastern North America. It has a number of culinary and other uses.","img":"images/35.jpg","thumb":"images/t/35.jpg","file":"Sassafras7.jpg","ar":0.75,"py":"beimeichashu bmcs","cr_by":"Wowbobwow12 at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"],"illus_img":"images/i/35.jpg","illus_thumb":"images/i/t/35.jpg","illus_file":"Sassafras albidum - Köhler–s Medizinal-Pflanzen-260.jpg","illus_ar":0.79,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":39,"seq":40,"zh":"蜡梅","en":"Chimonanthus praecox","sci":"Chimonanthus praecox","order_en":"Laurales","order_zh":"樟目","family_en":"Calycanthaceae","family_zh":"蜡梅科","iucn":"LC","langs":22,"desc_zh":"蜡梅（学名：Chimonanthus praecox）是蜡梅科蜡梅属的植物。原产地中国，生长于海拔300米至700米的地区，常生于山地林中。","desc_en":"Chimonanthus praecox, also known as wintersweet and Japanese allspice, is a species of flowering plant in the genus Chimonanthus of the family Calycanthaceae. The plant is native to China and is known as làméi (蠟梅) in Chinese.","img":"images/39.jpg","thumb":"images/t/39.jpg","file":"Frutti Chimonanthus praecox.jpg","ar":1.333,"py":"lamei lm","cr_by":"Luigi Chiesa","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲"]},{"id":40,"seq":41,"zh":"奇子树","en":"Idiospermum australiense","sci":"Idiospermum australiense","order_en":"Laurales","order_zh":"樟目","family_en":"Calycanthaceae","family_zh":"蜡梅科","iucn":null,"langs":20,"desc_zh":"奇子树是奇子树属（又名澳樟属）中的唯一种，生长在澳大利亚昆士兰州热带雨林中，一般为10-100株一起聚居在雨林中低洼潮湿区域，是1亿2千万年前出现的原始被子植物。 奇子树是常绿乔木，一般为20-30米高；单叶对生或3-4个螺旋排列，12-25厘米长，5-9厘米宽；花的直径为4-5厘米，花萼红色，虫媒，两性，但有半数的花没有雌蕊；果实为核果，直径8厘米，分为3-4瓣，有毒。","desc_en":"Idiospermum is a monotypic genus (that is, a genus that contains only one species) in the family Calycanthaceae. The sole included species is Idiospermum australiense − commonly known as ribbonwood, dinosaur tree, or the misnomer idiotfruit − which is found on…","img":"images/40.jpg","thumb":"images/t/40.jpg","file":"CSIRO ScienceImage 1104 Idiospermum australiense.jpg","ar":0.915,"py":"qizishu qzs","cr_by":"division, CSIRO","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["大洋洲"]},{"id":1011,"seq":42,"zh":"智利桂","en":"Laurelia sempervirens","sci":"Laurelia sempervirens","order_en":"Laurales","order_zh":"樟目","family_en":"Atherospermataceae","family_zh":"香皮茶科","iucn":"NT","langs":14,"desc_zh":"智利桂是香皮茶科中的一个物种，原生于智利南纬34至41度之间的地区。","desc_en":"Laurelia sempervirens is a species of evergreen tree in the family Atherospermataceae (formerly Monimiaceae). Common names include Peruvian nutmeg, tihue or trihue (from the Mapuche language), and Chilean laurel or Chilean sassafras.","img":"images/1011.jpg","thumb":"images/t/1011.jpg","file":"Laurelia sempirverens-hojas.JPG","ar":1.135,"py":"zhiligui zlg","cr_by":"Lin linao","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["南美洲"]},{"id":1012,"seq":43,"zh":"纽西兰桂","en":"Laurelia novae-zelandiae","sci":"Laurelia novae-zelandiae","order_en":"Laurales","order_zh":"樟目","family_en":"Atherospermataceae","family_zh":"香皮茶科","iucn":null,"langs":13,"desc_zh":"纽西兰桂是一种常青树，原生于纽西兰的森林中。","desc_en":"Laurelia novae-zelandiae, commonly known as pukatea, is a large evergreen tree, endemic to the forests of New Zealand. Pukatea has 'toothed' leaves and produces small flowers.","img":"images/1012.jpg","thumb":"images/t/1012.jpg","file":"Laurelia novae-zelandiae kz03.jpg","ar":1.501,"py":"niuxilangui nxlg","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["大洋洲"]},{"id":1013,"seq":44,"zh":"奎乐果","en":"Gomortega keule","sci":"Gomortega keule","order_en":"Laurales","order_zh":"樟目","family_en":"Gomortegaceae","family_zh":"腺蕊花科","iucn":"EN","langs":26,"desc_zh":"奎乐果（学名：Gomortega keule）是奎乐果科（Gomortegaceae）奎乐果属（Gomortega）的唯一物种，也叫葵乐果、腺蕊花、油籽树或直接音译为“哥摩木”，是生长在智利的一种乔木，花小，果实为黄色核果，果肉可以食用。几种分类法都把它列入樟目。","desc_en":"Gomortega keule (syn. G. nitida; Spanish names keule, queule, and hualhual) is a species of tree endemic to Chile. It is the sole species of the genus Gomortega and, according to the APG IV system of 2016 (unchanged from the APG systems of 2009, 2003 and 1998)…","img":"images/1013.jpg","thumb":"images/t/1013.jpg","file":"Queule Tomé 01.jpg","ar":0.75,"py":"kuileguo klg","cr_by":"Diego Alarcón","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["南美洲"]},{"id":1014,"seq":45,"zh":"莲叶桐","en":"Hernandia nymphaeifolia","sci":"Hernandia nymphaeifolia","order_en":"Laurales","order_zh":"樟目","family_en":"Hernandiaceae","family_zh":"莲叶桐科","iucn":"LC","langs":15,"desc_zh":"莲叶桐（学名：Hernandia nymphaeifolia）为莲叶桐科莲叶桐属下的一种常绿乔木。","desc_en":"Hernandia nymphaeifolia is a species of plant in the Hernandiaceae family. Its common name is lantern tree. It is a tree native to Madagascar and the western Indian Ocean islands, the Maldives, Sri Lanka, Indochina, Malesia, Papupasia, northern Australia, and…","img":"images/1014.jpg","thumb":"images/t/1014.jpg","file":"Hernandia nymphaeifolia.jpg","ar":1.274,"py":"lianyetong lyt","cr_by":"Tauʻolunga","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲","非洲","大洋洲"]},{"id":1015,"seq":46,"zh":"解醉茶","en":"árnica","sci":"Peumus boldus","order_en":"Laurales","order_zh":"樟目","family_en":"Monimiaceae","family_zh":"杯轴花科","iucn":"LC","langs":30,"desc_zh":null,"desc_en":"Peumus boldus, commonly known as boldo (from the Mapuche name foḻo), is a species of tree in the family Monimiaceae and the only species in the genus Peumus. It is endemic to the central region of Chile, between 33° and 40° southern latitude.","img":"images/1015.jpg","thumb":"images/t/1015.jpg","file":"Peumus boldus - Köhler–s Medizinal-Pflanzen-104.jpg","ar":0.667,"py":"jiezuicha jzc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"],"illus_img":"images/i/1015.jpg","illus_thumb":"images/i/t/1015.jpg","illus_file":"Peumus boldus - Köhler–s Medizinal-Pflanzen-104.jpg","illus_ar":0.667,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1016,"seq":47,"zh":"Mollinedia lamprophylla","en":"Mollinedia lamprophylla","sci":"Mollinedia lamprophylla","order_en":"Laurales","order_zh":"樟目","family_en":"Monimiaceae","family_zh":"杯轴花科","iucn":"NT","langs":9,"desc_zh":null,"desc_en":"Mollinedia lamprophylla is a species of flowering plant in the Monimiaceae family of the Laurales oeder. It is a tree endemic Rio de Janeiro state in southeastern Brazil.","img":"images/1016.jpg","thumb":"images/t/1016.jpg","file":"Botanische Jahrbücher für Systematik, Pflanzengeschichte und Pflanzengeographie (1900) (19779704054).jpg","ar":0.684,"py":"","cr_by":"Engler, Adolf, 1844-1930","cr_lic":"No restrictions","cr_licurl":"https://www.flickr.com/commons/usage/","habit":"乔木","origin":["南美洲"]},{"id":41,"seq":48,"zh":"胡椒","en":"black pepper","sci":"Piper nigrum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":136,"desc_zh":"胡椒（学名：Piper nigrum），又名黑川，是胡椒属的开花藤本植物，果实在晒干后通常可作为香料和调味料使用，称为黑胡椒。同样的果实还是白胡椒（果实去皮）、红胡椒与绿胡椒（未成熟果实）的制作原料。胡椒原产于南印度，在当地和其他热带地区都有着广泛的种植。胡椒的果实在熟透时会呈现黑红色，并包含一粒种子；果实在晒干后会成为直径5毫米的胡椒子核果。 干燥的“胡椒粉”是欧洲菜的常用香料，自古以来，胡椒就因其在调味与医学上的双重价值而备受珍视。","desc_en":"Black pepper (Piper nigrum) is a flowering vine in the family Piperaceae, cultivated for its fruit (the peppercorn), which is usually dried and used as a spice and seasoning.","img":"images/41.jpg","thumb":"images/t/41.jpg","file":"Piper nigrum - Köhler–s Medizinal-Pflanzen-107.jpg","ar":0.783,"py":"hujiao hj","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲"],"illus_img":"images/i/41.jpg","illus_thumb":"images/i/t/41.jpg","illus_file":"Piper nigrum - Köhler–s Medizinal-Pflanzen-107.jpg","illus_ar":0.783,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":42,"seq":49,"zh":"蒌叶","en":"betel","sci":"Piper betle","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":81,"desc_zh":"蒌叶（学名：Piper betle），又名荖藤，俗称蒌子、蒟子、蒟酱、芙畱、荖叶、荜茇、槟榔叶，是一种胡椒科多年生藤本植物，茎为蔓生，全株无毛，叶子呈椭圆形，花为绿色，有香味。原产地是印尼；中国大陆在南方和台湾均有种植。","desc_en":"Betel (Piper betle) is a species of flowering plant in the pepper family Piperaceae, native to Southeast Asia. It is an evergreen, dioecious vine, with glossy heart-shaped leaves and white catkins.","img":"images/42.jpg","thumb":"images/t/42.jpg","file":"Betel leaves for selling in the market 01.jpg","ar":1.333,"py":"louye ly","cr_by":"Suyash Dwivedi","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"],"illus_img":"images/i/42.jpg","illus_thumb":"images/i/t/42.jpg","illus_file":"Piper betle - Curtis' 59 (N.S. 6) pl. 3132 (1832).jpg","illus_ar":0.546,"illus_by":"Unknown author Unknown author","illus_lic":"Public domain","illus_licurl":null},{"id":43,"seq":50,"zh":"卡瓦胡椒","en":"Piper methysticum","sci":"Piper methysticum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":51,"desc_zh":"卡瓦醉椒（英语：kava 或 kava-kava；学名：Piper methysticum），亦译为卡瓦胡椒、毒椒等，卡瓦的其他名称包括' awa（夏威夷），' waava（萨摩亚），yaqona（斐济），sakau（波纳佩）和 malok 或 malogu（瓦努阿图的部分地区）。为胡椒科灌木，主产于西太平洋地区。从美拉尼西亚至波利尼西亚之间广阔的地域——斐济、汤加、萨摩亚等地均为常见的嗜好品。","desc_en":"Kava or kava kava (Piper methysticum: Latin 'pepper' and Latinized Greek 'intoxicating') is a plant in the pepper family, native to the Pacific Islands. The name kava is from Tongan and Marquesan, meaning 'bitter'.","img":"images/43.jpg","thumb":"images/t/43.jpg","file":"Starr 040318-0058 Piper methysticum.jpg","ar":0.75,"py":"kawahujiao kwhj","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["大洋洲"]},{"id":44,"seq":51,"zh":"荜拔","en":"Piper longum","sci":"Piper longum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":47,"desc_zh":"荜拔（学名：Piper longum）是胡椒科胡椒属的植物。分布在斯里兰卡、马来西亚、印度、尼泊尔、越南以及中国大陆的福建、云南、广西、广东等地，生长于海拔580米的地区，多生在疏荫杂木林中，目前尚未由人工引种栽培。","desc_en":"Long pepper (Piper longum), sometimes called Indian long pepper or pippali, is a flowering vine in the family Piperaceae, cultivated for its fruit, which is usually dried and used as a spice and seasoning.","img":"images/44.jpg","thumb":"images/t/44.jpg","file":"Piper longum.jpg","ar":1.269,"py":"biba bb","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲"]},{"id":45,"seq":52,"zh":"荜澄茄","en":"Piper cubeba","sci":"Piper cubeba","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":45,"desc_zh":"荜澄茄（学名：Piper cubeba），又名尾胡椒（英语：tailed pepper），是胡椒属的一种植物，被栽培以获取其果实与精油。它主要生长于爪哇岛与苏门答腊岛地区，因此有时也被叫做爪哇胡椒。其果实在成熟之前被采集，并被仔细地加以干燥处理。荜澄茄的贸易由其干燥的浆果组成，干浆果在外观上类似于黑胡椒，但比黑胡椒多了梗柄——即“尾胡椒”的“尾巴”。在干燥过程中，果皮会产生褶皱，颜色也会从灰棕色变为黑色。","desc_en":"Piper cubeba, cubeb or tailed pepper is a plant in the genus Piper, cultivated for its fruit and essential oil. It is mostly grown in Java and Sumatra, hence sometimes called Java pepper. The fruits are gathered before they are ripe, and carefully dried.","img":"images/45.jpg","thumb":"images/t/45.jpg","file":"Piper cubeba muda.jpg","ar":0.75,"py":"bichengqie bcq","cr_by":"Kembangraps","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/45.jpg","illus_thumb":"images/i/t/45.jpg","illus_file":"Piper cubeba - Köhler–s Medizinal-Pflanzen-244.jpg","illus_ar":0.805,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":47,"seq":53,"zh":"欧细辛","en":"Asarum europaeum","sci":"Asarum europaeum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Asarum europaeum, known as asarabacca, European wild ginger, hazelwort, and wild spikenard, historically cabarick, is a species of flowering plant in the birthwort family Aristolochiaceae, native to parts of temperate Europe, and also cultivated in gardens.","img":"images/47.jpg","thumb":"images/t/47.jpg","file":"Asarum europaeum 170406.jpg","ar":0.75,"py":"ouxixin oxx","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":["欧洲"],"illus_img":"images/i/47.jpg","illus_thumb":"images/i/t/47.jpg","illus_file":"Asarum europaeum Sturm04046.jpg","illus_ar":0.676,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":48,"seq":54,"zh":"欧洲马兜铃","en":"Aristolochia clematitis","sci":"Aristolochia clematitis","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":42,"desc_zh":"铁线莲状马兜铃（Aristolochia clematitis，又称欧洲催生草）是马兜铃科缠绕草本植物，原产于欧洲。铁线莲状马兜铃叶心形，具淡黄色管状花，通过缠绕其他植物向光生长。","desc_en":"Aristolochia clematitis, or European birthwort, is a twining herbaceous plant in the family Aristolochiaceae, which is native to most of central and southern Europe and parts of western Asia, and naturalised further north in Europe.","img":"images/48.jpg","thumb":"images/t/48.jpg","file":"Aristolochia clematitis 20041007 2546.jpg","ar":0.75,"py":"ouzhoumadouling ozmdl","cr_by":"Georg Slickers","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","欧洲"],"illus_img":"images/i/48.jpg","illus_thumb":"images/i/t/48.jpg","illus_file":"Aristolochia clematitis — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":49,"seq":55,"zh":"非洲白鹭花","en":"Hydnora africana","sci":"Hydnora africana","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":24,"desc_zh":"非洲白鹭花（学名：Hydnora africana）是一种寄生于大戟科根部的植物，，并取其营养维生，分布于非洲南部。全株无叶绿素，长年只在泥中生长，只有散发含硫化物，气味如粪的肉质花会在暴雨后露出地面，以吸引粪金龟和葬甲科甲虫到花中。花内设有「陷阱」去暂时囚禁甲虫，以增加为其传播花粉的机会。果实长于土内，需要两年成熟，果内藏约二万籽，可食用，味道、口感如薯，亦可提炼成鱼网的收敛剂。 其种加词“africana”意为“非洲的”。","desc_en":"Hydnora africana is an achlorophyllous plant in the subfamily Hydnoroideae, native to southern Africa that is parasitic on the roots of members of the family Euphorbiaceae. It is also called jakkalskos or jackal food.","img":"images/49.jpg","thumb":"images/t/49.jpg","file":"HydnoraAfricanaKarasburgDistrictNamibia2002Musselman.jpg","ar":1.331,"py":"feizhoubailuhua fzblh","cr_by":"Lytton John Musselman","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":51,"seq":56,"zh":"鱼腥草","en":"Houttuynia cordata","sci":"Houttuynia cordata","order_en":"Piperales","order_zh":"胡椒目","family_en":"Saururaceae","family_zh":"三白草科","iucn":null,"langs":26,"desc_zh":"鱼腥草（学名：Houttuynia cordata），又名折耳根 、截儿根、猪鼻拱、䔃（zǔ）、蕺菜及臭草、岑草、臭臊草，客家话称之狗贴耳、臭臊草，台语称臭腥草，在分类学上属双子叶植物三白草科蕺菜属，是一种略带鱼腥味的草本植物。","desc_en":"Houttuynia cordata, also known as fish mint, fish leaf, rainbow plant, chameleon plant, heart leaf, fish wort, or Chinese lizard tail, is one of two species in the genus Houttuynia (the other being H. emeiensis).","img":"images/51.jpg","thumb":"images/t/51.jpg","file":"Houttuynia cordata Pstrolistka sercowata 2009-07-11 02.jpg","ar":1.001,"py":"yuxingcao yxc","cr_by":"Agnieszka Kwiecień, Nova","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":52,"seq":57,"zh":"冬木","en":"Drimys winteri","sci":"Drimys winteri","order_en":"Canellales","order_zh":"白樟目","family_en":"Winteraceae","family_zh":"林仙科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Drimys winteri, also known as Winter's bark, foye and canelo, is a slender species of tree in the family Winteraceae, growing up to 20 m (66 ft) tall. It is native to the Magellanic and Valdivian temperate forests of Chile and Argentina, where it is a dominant…","img":"images/52.jpg","thumb":"images/t/52.jpg","file":"Drimys winteri.jpg","ar":1.494,"py":"dongmu dm","cr_by":"Eric Hunt","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["南美洲"]},{"id":1017,"seq":58,"zh":"Takhtajania perrieri","en":"Takhtajania perrieri","sci":"Takhtajania perrieri","order_en":"Canellales","order_zh":"白樟目","family_en":"Winteraceae","family_zh":"林仙科","iucn":"EN","langs":16,"desc_zh":null,"desc_en":"Takhtajania is a genus of flowering plants of the family Winteraceae, which contains a single species, Takhtajania perrieri. It is endemic to Madagascar. Takhtajania is found in a small area of the Madagascar subhumid forests.","img":"images/1017.jpg","thumb":"images/t/1017.jpg","file":"Takhtajania perrieri 1871790.jpg","ar":1.499,"py":"","cr_by":"Romer Rabarijaona","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["非洲"]},{"id":1018,"seq":59,"zh":"Canella winterana","en":"Canella winterana","sci":"Canella winterana","order_en":"Canellales","order_zh":"白樟目","family_en":"Canellaceae","family_zh":"白樟科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Canella is a monospecific genus containing the species Canella winterana, a tree native to the Caribbean, south-eastern Mexico, southern Florida, and Venezuela.","img":"images/1018.jpg","thumb":"images/t/1018.jpg","file":"Canella winterana Guadeloupe.JPG","ar":1.333,"py":"","cr_by":"Pancrat","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲","南美洲"]},{"id":53,"seq":60,"zh":"菖蒲","en":"Acorus calamus","sci":"Acorus calamus","order_en":"Acorales","order_zh":"菖蒲目","family_en":"Acoraceae","family_zh":"菖蒲科","iucn":"LC","langs":94,"desc_zh":"菖蒲（学名：Acorus calamus），也叫做水菖蒲、白菖蒲、藏菖蒲，古名蒖、䒢，是一种菖蒲科的水生草本植物。菖蒲分布很广，整个温带基本都能找到它，中国各地也都有分布。 菖蒲可以提取芳香油；端午节有把菖蒲叶和艾草捆一起插于簷下的习俗；根茎可制香味料。亦称为尧韭。菖蒲油可用于医药、美容、香水、烹饪和家庭用途。","desc_en":"Acorus calamus (also called sweet flag, sway or muskrat root, among many other common names) is a species of flowering plant. It is a tall wetland monocot of the family Acoraceae, in the genus Acorus.","img":"images/53.jpg","thumb":"images/t/53.jpg","file":"Acorus calamus1.jpg","ar":0.75,"py":"changpu cp","cr_by":"J.F. Gaffard, Autoreille, France","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/53.jpg","illus_thumb":"images/i/t/53.jpg","illus_file":"Acorus calamus (Köhler).jpg","illus_ar":0.738,"illus_by":"Hermann Adolf Köhler (1834 - 1879)","illus_lic":"Public domain","illus_licurl":null},{"id":54,"seq":61,"zh":"芋","en":"Colocasia esculenta","sci":"Colocasia esculenta","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":111,"desc_zh":"芋（学名：Colocasia esculenta）或芋艿，俗称「芋头」，为天南星科芋属植物，其球状地下茎（块茎）可食用亦可入药，在大洋洲诸岛是玻里尼西亚人传统主要粮食；全年皆有产，花期在秋季。最早栽种的印度人约于西元前5,000年引入了来自马来西亚湿地的野生芋头，尔后又传到埃及。","desc_en":"Taro (; Colocasia esculenta) is a root vegetable. It is the most widely cultivated species of several plants in the family Araceae that are used as vegetables for their corms, leaves, stems and petioles.","img":"images/54.jpg","thumb":"images/t/54.jpg","file":"(MHNT) Colocasia esculenta - Les Martels, Giroussens Tarn.jpg","ar":1.485,"py":"yu y","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","非洲"]},{"id":55,"seq":62,"zh":"巨花魔芋","en":"Amorphophallus titanum","sci":"Amorphophallus titanum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"EN","langs":57,"desc_zh":"巨花魔芋（学名：Amorphophallus titanum），又名尸花、泰坦魔芋，是天南星科魔芋属植物。 巨花魔芋具有世界上最大的不分支花序；还有世界最高的花，贝叶棕具有世界最大的花序；世界上最大的花朵则为大花草的花。巨花魔芋的印尼文名称叫做「bunga bangkai」，「bunga」意为「花」，「bangkai」意为「尸体」，巨花魔芋在开花的时候会散发一股类似尸臭的味道，因此又有「尸花」的别名。","desc_en":"Amorphophallus titanum, the titan arum, is a flowering plant in the family Araceae. It has a large unbranched inflorescence, a tall single leaf branched like a tree, and a heavy tuber which enables the plant to produce the inflorescence. A.","img":"images/55.jpg","thumb":"images/t/55.jpg","file":"Arum titan au jardin botanique de Nancy, floraison 2025.jpg","ar":0.665,"py":"juhuamoyu jhmy","cr_by":"Le Commissaire","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"]},{"id":56,"seq":63,"zh":"绿萝","en":"Epipremnum aureum","sci":"Epipremnum aureum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":50,"desc_zh":"绿萝（学名：Epipremnum aureum），又名黄金葛，是天南星科、麒麟叶属的一种多年生木质藤本植物，原产于法属波利尼西亚的莫雷阿岛，随着人类引进而在东南亚、南亚、华南、所罗门群岛、非洲、西印度群岛等地的热带及亚热带森林中归化，并在部分地区成为入侵物种，影响一些地方的生态平衡。喜荫蔽潮湿的环境，生命力极强，在黑暗无光的条件下亦能生存。","desc_en":"Epipremnum aureum is a species in the arum family Araceae, native to Mo'orea in the Society Islands of French Polynesia. The species is a popular houseplant in temperate regions, but has also become naturalised in tropical and sub-tropical forests worldwide, i…","img":"images/56.png","thumb":"images/t/56.png","file":"Epipremnum aurem flower.png","ar":0.506,"py":"lluo ll","cr_by":"Chiu-Yueh Hung, Jie Qiu, Ying-Hsuan Sun, Jianjun Chen, Farooqahmed S. Kittur, Richard J. Henny, Gulei Jin, Longjiang Fan","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["大洋洲"]},{"id":57,"seq":64,"zh":"大薸","en":"Pistia stratiotes","sci":"Pistia stratiotes","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":49,"desc_zh":"大薸（学名：Pistia stratiotes），又名大萍、大蕊萍、大莲、水芙蓉，为天南星科大薸属的唯一物种。","desc_en":"Pistia is a genus of aquatic plants in the arum family, Araceae. It is the sole genus in the tribe Pistieae which reflects its systematic isolation within the family.","img":"images/57.jpg","thumb":"images/t/57.jpg","file":"Pistia stratiotes0.jpg","ar":1.333,"py":"dapiao dp","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":58,"seq":65,"zh":"浮萍","en":"Lemna minor","sci":"Lemna minor","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":48,"desc_zh":"浮萍（学名：Lemna minor），别称青萍、水薸 ，是天南星科青萍属水生植物。广布于世界各地，池塘、湖泊内常见。 其种加词“minor”意为“较小的”。","desc_en":"Lemna minor, the common duckweed or lesser duckweed, is a species of aquatic freshwater plant in the subfamily Lemnoideae of the arum family Araceae. L. minor is used as animal fodder, bioremediator, for wastewater nutrient recovery, and other applications.","img":"images/58.jpg","thumb":"images/t/58.jpg","file":"Eendekroos dicht bijeen.JPG","ar":1.333,"py":"fuping fp","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/58.jpg","illus_thumb":"images/i/t/58.jpg","illus_file":"Lemna minor — Flora Batava — Volume v20.jpg","illus_ar":0.727,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":59,"seq":66,"zh":"水芋","en":"Calla palustris","sci":"Calla palustris","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":48,"desc_zh":"水芋（学名：Calla palustris）为天南星科水芋属的唯一种。分布于美洲的北温带和亚北极地区、亚洲、欧洲以及中国大陆的内蒙古、吉林、辽宁、黑龙江等地，生长于海拔200米至1,100米的地区，见于草甸或沼泽等浅水域，目前尚未由人工引种栽培，含有含量非常高的草酸，属于有毒的草酸钙结晶。","desc_en":"Calla is a genus of flowering plant in the family Araceae, containing the single species Calla palustris (bog arum, marsh calla, wild calla, squaw claw, and water-arum). It is the only genus in the tribe Calleae of the subfamily Aroideae.","img":"images/59.jpg","thumb":"images/t/59.jpg","file":"Calla palustris2.jpg","ar":1.333,"py":"shuiyu sy","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/59.jpg","illus_thumb":"images/i/t/59.jpg","illus_file":"Calla palustris — Flora Batava — Volume v11.jpg","illus_ar":1.381,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":60,"seq":67,"zh":"斑叶疆南星","en":"Arum maculatum","sci":"Arum maculatum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":47,"desc_zh":null,"desc_en":"Arum maculatum, commonly known as cuckoopint, jack-in-the-pulpit and other names (see common names), is a woodland flowering plant species in the family Araceae. It is native across most of Europe, as well as Eastern Turkey and the Caucasus.","img":"images/60.jpg","thumb":"images/t/60.jpg","file":"Arum maculatum 0 700.jpg","ar":0.913,"py":"banyejiangnanxing byjnx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/60.jpg","illus_thumb":"images/i/t/60.jpg","illus_file":"Arum maculatum illustration 1794.jpg","illus_ar":0.65,"illus_by":"Johann Samuel Halle 1727-1810","illus_lic":"Public domain","illus_licurl":null},{"id":61,"seq":68,"zh":"龟背竹","en":"Monstera deliciosa","sci":"Monstera deliciosa","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":46,"desc_zh":"龟背芋（学名：Monstera deliciosa），又称为龟背竹、凤梨蕉、蓬莱蕉及电信兰，是天南星科龟背芋属植物。 龟背芋适应性强，性喜温暖，潮湿的环境，但也耐阴、耐阳及有一定的耐旱性，原产于墨西哥南部至危地马拉的热带雨林生境。为著名大型观赏植物。","desc_en":"Monstera deliciosa, the Swiss cheese plant or split-leaf philodendron, is a species of flowering plant. The common name \"Swiss cheese plant\" is also used for the related species from the same genus, Monstera adansonii.","img":"images/61.jpg","thumb":"images/t/61.jpg","file":"Monstera deliciosa2.jpg","ar":0.88,"py":"guibeizhu gbz","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":67,"seq":69,"zh":"泽泻","en":"Alisma plantago-aquatica","sci":"Alisma plantago-aquatica","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Alismataceae","family_zh":"泽泻科","iucn":"LC","langs":49,"desc_zh":"泽泻（学名：Alisma plantago-aquatica），又名藚、水舄。为多年生沼生草木，属泽泻科。其根状茎较短，叶子呈长椭圆形，基生。泽泻夏季开白花，排成大型轮状分枝的圆锥花序；花两性；内外轮花被各三枚，内轮花被片花瓣状，比外轮小。瘦果侧扁，顶端有宿存花柱。野生泽泻一般生长在沼泽地，分布于中国、日本和印度等地。 泽泻的根状茎是传统中药之一。中医理论认为其性寒，具有利水渗湿的功能，主治小便不利、水肿腹满、泄泻、淋浊等症。","desc_en":"Alisma plantago-aquatica, also known as European water-plantain, common water-plantain or mad-dog weed, is a perennial flowering aquatic plant widespread across most of Europe and Asia, and apparently spread elsewhere in both the Old and New World.","img":"images/67.jpg","thumb":"images/t/67.jpg","file":"AlismaPlant1.jpg","ar":0.667,"py":"zexie zx","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/67.jpg","illus_thumb":"images/i/t/67.jpg","illus_file":"Alisma Plantago (modern=Alisma plantago-aquatica) - Pl0247 - DescriptionFR01 - FloraBatava-KB-v04.jpg","illus_ar":0.804,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":68,"seq":70,"zh":"慈姑","en":"Sagittaria sagittifolia","sci":"Sagittaria sagittifolia","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Alismataceae","family_zh":"泽泻科","iucn":"LC","langs":40,"desc_zh":"茨菰（学名：Sagittaria sagittifolia），又称葃菇、燕尾草、白地栗等，俗写做慈姑、慈菇，是泽泻科慈姑属的一种植物，球茎可食用。原产中国华中、华南等。分布于欧洲与亚洲、大洋洲、欧洲以及中国大陆的新疆阿勒泰等地的温带湿地，生长于海拔600米（2,000英尺）的地区，一般生长在水塘静水处、沼泽、湖边及缓流溪沟。","desc_en":"Sagittaria sagittifolia (also called arrowhead because of the shape of its leaves) is an Old World flowering plant in the family Alismataceae.","img":"images/68.jpg","thumb":"images/t/68.jpg","file":"SagittariaSagittifoliaInflorescence2.jpg","ar":0.739,"py":"cigu cg","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/68.jpg","illus_thumb":"images/i/t/68.jpg","illus_file":"Sagittaria sagittifolia Sturm04002.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":1019,"seq":71,"zh":"膜果泽泻","en":"Alisma lanceolatum","sci":"Alisma lanceolatum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Alismataceae","family_zh":"泽泻科","iucn":"LC","langs":27,"desc_zh":"膜果泽泻（学名：Alisma lanceolatum）为泽泻科泽泻属的植物。分布在大洋洲、非洲、中亚、欧洲以及中国的新疆等地，一般生长在静水中和沼泽地，目前尚未由人工引种栽培。","desc_en":"Alisma lanceolatum is a species of aquatic plant in the water plantain family known by the common names lanceleaf water plantain and narrow-leaved water plantain. It is widespread across Europe, North Africa and temperate Asia.","img":"images/1019.jpg","thumb":"images/t/1019.jpg","file":"Alismalanceolatum.jpg","ar":1.503,"py":"moguozexie mgzx","cr_by":"Gordon Leppig & Andrea J. Pickart","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":69,"seq":72,"zh":"水蕴藻","en":"Elodea canadensis","sci":"Elodea canadensis","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Hydrocharitaceae","family_zh":"水鳖科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Elodea canadensis (American waterweed or Canadian waterweed or pondweed) is a perennial aquatic plant, or submergent macrophyte, native to most of North America. It has been introduced widely to regions outside its native range.","img":"images/69.jpg","thumb":"images/t/69.jpg","file":"ElodeaCanadensis.jpg","ar":0.872,"py":"shuiyunzao syz","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["北美洲"]},{"id":70,"seq":73,"zh":"大茨藻","en":"Najas marina","sci":"Najas marina","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Hydrocharitaceae","family_zh":"水鳖科","iucn":"LC","langs":32,"desc_zh":"大茨藻（学名：Najas marina）为水鳖科茨藻属的植物。广泛分布于世界各地，生长于海拔700米至2,300米的地区，常生长在河谷、流水中、静水中、渠边、水中、湖边、湖中以及温泉中，目前尚未由人工引种栽培。","desc_en":"Najas marina is a species of aquatic plant known by the common names spiny water nymph, spiny naiad and holly-leaved naiad. It is an extremely widespread species, reported across Europe, Asia, Africa, Australia, the Americas and many oceanic islands.","img":"images/70.jpg","thumb":"images/t/70.jpg","file":"Najas marina.jpeg","ar":1.333,"py":"dacizao dcz","cr_by":"Kristian Peters -- Fabelfroh 08:57, 11 October 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/70.jpg","illus_thumb":"images/i/t/70.jpg","illus_file":"Illustration Najas marina0.jpg","illus_ar":0.592,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":1020,"seq":74,"zh":"Hydrocharis morsus-ranae","en":"Hydrocharis morsus-ranae","sci":"Hydrocharis morsus-ranae","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Hydrocharitaceae","family_zh":"水鳖科","iucn":"LC","langs":32,"desc_zh":null,"desc_en":"Hydrocharis morsus-ranae L. is a species of the genus Hydrocharis known by the common name European frog-bit. It is a free-floating flowering plant that bears small white flowers.","img":"images/1020.jpg","thumb":"images/t/1020.jpg","file":"HydrocharisMorsus-ranae2.jpg","ar":1.166,"py":"","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/1020.jpg","illus_thumb":"images/i/t/1020.jpg","illus_file":"Hydrocharis morsus-ranae — Flora Batava — Volume v7.jpg","illus_ar":0.679,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":71,"seq":75,"zh":"大叶藻","en":"Zostera marina","sci":"Zostera marina","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Zosteraceae","family_zh":"大叶藻科","iucn":"LC","langs":40,"desc_zh":"大叶藻（学名：Zostera marina），又名鳗草，为大叶藻科大叶藻属下的一种海草，广泛分布于北美洲和欧亚大陆沿海海域。","desc_en":"Zostera marina is a flowering vascular plant species as one of many kinds of seagrass, with this species known primarily by the English name of eelgrass, with seawrack much less used, and refers to the plant after breaking loose from the submerged wetland soil…","img":"images/71.jpg","thumb":"images/t/71.jpg","file":"Zostera marina.jpeg","ar":0.75,"py":"dayezao dyz","cr_by":"Kristian Peters -- Fabelfroh 09:28, 16 September 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","北美洲"],"illus_img":"images/i/71.jpg","illus_thumb":"images/i/t/71.jpg","illus_file":"Zostera marina — Flora Batava — Volume v12.jpg","illus_ar":0.688,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1021,"seq":76,"zh":"长柄水蕹","en":"Aponogeton distachyos","sci":"Aponogeton distachyos","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Aponogetonaceae","family_zh":"水蕹科","iucn":"LC","langs":18,"desc_zh":null,"desc_en":"Aponogeton distachyos or Aponogeton distachyum, also known as waterblommetjie (lit. trans. water-floret), Cape-pondweed, water hawthorn, vleikos and Cape pond weed is an aquatic flowering plant.","img":"images/1021.jpg","thumb":"images/t/1021.jpg","file":"Aponogeton distachyos.jpg","ar":1.333,"py":"changbingshuiweng cbsw","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":1022,"seq":77,"zh":"马达加斯加水蕹","en":"Aponogeton madagascariensis","sci":"Aponogeton madagascariensis","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Aponogetonaceae","family_zh":"水蕹科","iucn":"LC","langs":18,"desc_zh":null,"desc_en":"Aponogeton madagascariensis is commonly known as Madagascar laceleaf, lattice leaf or lace plant. It is an aquatic plant native to Madagascar in the family Aponogetonaceae popularly sold for use in aquariums.","img":"images/1022.jpg","thumb":"images/t/1022.jpg","file":"Aponogeton madagascariensis.jpg","ar":0.85,"py":"madajiasijiashuiweng mdjsjsw","cr_by":"William Jackson Hooker","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["非洲"]},{"id":1023,"seq":78,"zh":"花蔺","en":"Butomus umbellatus","sci":"Butomus umbellatus","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Butomaceae","family_zh":"花蔺科","iucn":"LC","langs":46,"desc_zh":null,"desc_en":"Butomus umbellatus is a Eurasian plant species in the family Butomaceae. It is the only species in the family. Common names include flowering rush or grass rush.","img":"images/1023.jpg","thumb":"images/t/1023.jpg","file":"Butomus umbellatus - harilik luigelill Keilas.jpg","ar":0.667,"py":"hualin hl","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["欧洲"],"illus_img":"images/i/1023.png","illus_thumb":"images/i/t/1023.png","illus_file":"Butomus umbellatus Sturm-04007.png","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":1024,"seq":79,"zh":"小海王星草","en":"Cymodocea nodosa","sci":"Cymodocea nodosa","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Cymodoceaceae","family_zh":"丝粉藻科","iucn":"LC","langs":19,"desc_zh":null,"desc_en":"Cymodocea nodosa is a species of seagrass in the family Cymodoceaceae and is sometimes known as little Neptune grass. As a seagrass, it is restricted to growing underwater and is found in shallow parts of the Mediterranean Sea and certain adjoining areas of th…","img":"images/1024.jpg","thumb":"images/t/1024.jpg","file":"Cymodocea nodosa.jpg","ar":1.331,"py":"xiaohaiwangxingcao xhwxc","cr_by":"Sylvain Le Bris","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["欧洲"]},{"id":1025,"seq":80,"zh":"海韭菜","en":"Triglochin maritima","sci":"Triglochin maritima","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Juncaginaceae","family_zh":"水麦冬科","iucn":"LC","langs":35,"desc_zh":"海韭菜（Triglochin maritima}）是水麦冬科植物。","desc_en":"Triglochin maritima is a species of flowering plant in the arrowgrass family Juncaginaceae. It is found in brackish marshes, freshwater marshes, wet sandy beaches, fens, damp grassland and bogs.","img":"images/1025.jpg","thumb":"images/t/1025.jpg","file":"Stranddreizack.jpg","ar":0.673,"py":"haijiucai hjc","cr_by":"Elke Freese","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null,"illus_img":"images/i/1025.png","illus_thumb":"images/i/t/1025.png","illus_file":"Triglochin maritima, Triglochin palustris Lindman cropped.png","illus_ar":0.646,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":1026,"seq":81,"zh":"水麦冬","en":"Triglochin palustris","sci":"Triglochin palustris","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Juncaginaceae","family_zh":"水麦冬科","iucn":"LC","langs":27,"desc_zh":null,"desc_en":"Triglochin palustris or marsh arrowgrass is a species of flowering plant in the arrowgrass family Juncaginaceae. It is found in damp grassland usually on calcareous soils, fens and meadows.","img":"images/1026.jpg","thumb":"images/t/1026.jpg","file":"Triglochium palustris BotGartBln310505.JPG","ar":0.75,"py":"shuimaidong smd","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/1026.png","illus_thumb":"images/i/t/1026.png","illus_file":"Triglochin maritima, Triglochin palustris Lindman cropped.png","illus_ar":0.646,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":1027,"seq":82,"zh":"波希多尼亚海草","en":"Posidonia oceanica","sci":"Posidonia oceanica","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Posidoniaceae","family_zh":"海神草科","iucn":"LC","langs":31,"desc_zh":"大洋海神草（Posidonia Oceanica）是地中海的一种特有海草。本属中现生只有本种分布于地中海，其余均分布于澳大利亚。本种在浅海软质底形成密集水下草场，是生态系统的构建者。","desc_en":"Posidonia oceanica, commonly known as Neptune grass or Mediterranean tapeweed, is a seagrass species that is endemic to the Mediterranean Sea. The mapping of submerged seagrass meadows in the Mediterranean has recently benefited from advanced artificial intell…","img":"images/1027.jpg","thumb":"images/t/1027.jpg","file":"Posidonia oceanica (L).jpg","ar":1.333,"py":"boxiduoniyahaicao bxdnyhc","cr_by":"Frédéric Ducarme","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["欧洲"]},{"id":1028,"seq":83,"zh":"浮叶眼子菜","en":"Potamogeton natans","sci":"Potamogeton natans","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Potamogetonaceae","family_zh":"眼子菜科","iucn":"LC","langs":36,"desc_zh":"浮叶眼子菜（学名：Potamogeton natans）为眼子菜科眼子菜属下的一个种。","desc_en":"Potamogeton natans, commonly known as broad-leaved pondweed, floating pondweed, or floating-leaf pondweed, is an aquatic species in the genus Potamogeton native to quiet or slow-flowing freshwater habitats throughout the Holarctic Kingdom.","img":"images/1028.jpg","thumb":"images/t/1028.jpg","file":"PotamogetonNatans.jpg","ar":1.49,"py":"fuyeyanzicai fyyzc","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/1028.jpg","illus_thumb":"images/i/t/1028.jpg","illus_file":"Potamogeton natans — Flora Batava — Volume v6.jpg","illus_ar":0.687,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1029,"seq":84,"zh":"角果藻","en":"Zannichellia palustris","sci":"Zannichellia palustris","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Potamogetonaceae","family_zh":"眼子菜科","iucn":"LC","langs":32,"desc_zh":"角果藻（学名：Zannichellia palustris）为茨藻科角果藻属下的一个种。","desc_en":"Zannichellia palustris, the horned pondweed, is a plant found in fresh to brackish waters in the United States (especially in the Chesapeake Bay), Europe, Asia, Australasia, and South America.","img":"images/1029.jpg","thumb":"images/t/1029.jpg","file":"ZannichelliaPalustris3.jpg","ar":1.504,"py":"jiaoguozao jgz","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","北美洲","南美洲"],"illus_img":"images/i/1029.jpg","illus_thumb":"images/i/t/1029.jpg","illus_file":"Zannichellia palustris — Flora Batava — Volume v7.jpg","illus_ar":0.679,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1030,"seq":85,"zh":"川蔓藻","en":"Ruppia maritima","sci":"Ruppia maritima","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Ruppiaceae","family_zh":"川蔓藻科","iucn":"LC","langs":30,"desc_zh":"川蔓藻（学名：Ruppia maritima），又名流苏菜，为眼子菜科川蔓藻属下的一种一年生或多年生植物，遍布全球各地沿海的咸水水域。","desc_en":"Ruppia maritima is an aquatic plant species commonly known as beaked tasselweed, beaked ditchgrass, ditch grass, tassel pondweed and widgeon grass. Despite its scientific name, it is not a marine plant; is perhaps best described as a salt-tolerant freshwater s…","img":"images/1030.jpg","thumb":"images/t/1030.jpg","file":"Ruppiamaritima.jpg","ar":1.889,"py":"chuanmanzao cmz","cr_by":"Gordon Leppig & Andrea J. Pickart","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null,"illus_img":"images/i/1030.jpg","illus_thumb":"images/i/t/1030.jpg","illus_file":"Illustration Ruppia maritima0.jpg","illus_ar":0.582,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":1031,"seq":86,"zh":"芝菜","en":"Scheuchzeria palustris","sci":"Scheuchzeria palustris","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Scheuchzeriaceae","family_zh":"冰沼草科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Scheuchzeria palustris (Rannoch-rush, or pod grass), is a flowering plant in the family Scheuchzeriaceae, in which there is only one species and Scheuchzeria is the only genus. In the APG II system it is placed in the order Alismatales of the monocots.","img":"images/1031.jpg","thumb":"images/t/1031.jpg","file":"Scheuchzeria palustris - flowering.jpg","ar":0.663,"py":"zhicai zc","cr_by":"Bertblok","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null,"illus_img":"images/i/1031.jpg","illus_thumb":"images/i/t/1031.jpg","illus_file":"Scheuchzeria palustris — Flora Batava — Volume v18.jpg","illus_ar":0.739,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1032,"seq":87,"zh":"杯萼岩菖蒲","en":"Tofieldia calyculata","sci":"Tofieldia calyculata","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Tofieldiaceae","family_zh":"岩菖蒲科","iucn":null,"langs":18,"desc_zh":null,"desc_en":"Tofieldia calyculata is a species of flowering plant belonging to the family Tofieldiaceae. Its native range is Gotland to Pyrenees and Ukraine.","img":"images/1032.jpg","thumb":"images/t/1032.jpg","file":"Tofieldia calyculata habit.jpg","ar":1.504,"py":"beieyanchangpu beycp","cr_by":"User:Carstor","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/1032.jpg","illus_thumb":"images/i/t/1032.jpg","illus_file":"Tofieldia calyculata Sturm26.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":72,"seq":88,"zh":"尾濑草","en":"Japanolirion","sci":"Japonolirion osense","order_en":"Petrosaviales","order_zh":"无叶莲目","family_en":"Petrosaviaceae","family_zh":"无叶莲科","iucn":null,"langs":18,"desc_zh":null,"desc_en":"Japonolirion is a genus of plants in the family Petrosaviaceae. There is only one known species, Japonolirion osense, endemic to Japan. It is found in grasslands, wetlands and alpine meadows.","img":"images/72.jpg","thumb":"images/t/72.jpg","file":"Japonolirion osense 1.JPG","ar":1.333,"py":"weilaicao wlc","cr_by":"Qwert1234","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":73,"seq":89,"zh":"黑薯蓣","en":"Dioscorea communis","sci":"Dioscorea communis","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":50,"desc_zh":"黑薯苹（学名：Dioscorea communis或Tamus communis）是薯蓣科薯蓣属的一种开花植物，俗称女爵印章（lady's-seal）或黑旋花（black bindweed）。","desc_en":"Dioscorea communis or Tamus communis is a species of flowering plant in the yam family Dioscoreaceae and is commonly known as black bryony, lady's-seal or black bindweed.","img":"images/73.jpg","thumb":"images/t/73.jpg","file":"Tamus communis.jpg","ar":1.333,"py":"heishuyu hsy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":74,"seq":90,"zh":"参薯","en":"Dioscorea alata","sci":"Dioscorea alata","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":49,"desc_zh":"参薯（学名：Dioscorea alata，台湾作大薯）又名香芋、紫薯、田薯、罐薯、银薯、脚板薯、云饼山药、土栾儿、香参、菜用土圞儿、地栗子、红牙芋，他加禄语及英文名称为 ube ，为薯蓣科薯蓣属的植物。 参薯的块茎内部呈鲜艳的深紫色，富含淀粉，可食用。其与甘薯（D. esculenta；即毛薯）、薯蓣（D. polystachya，即山药）、日本山芋（D. japonica）等同科，未经烹饪的块茎中均含有粘液。","desc_en":"Dioscorea alata – also called ube, ubi, uwhi, purple yam, or greater yam, among many other names – is a species of yam (a tuber). The tubers are usually a vivid violet-purple to bright lavender (hence the common name), but some range from creamy-white to plain…","img":"images/74.jpg","thumb":"images/t/74.jpg","file":"Starr 061106-1435 Dioscorea alata.jpg","ar":0.75,"py":"canshu cs","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":null},{"id":75,"seq":91,"zh":"黄独","en":"Dioscorea bulbifera","sci":"Dioscorea bulbifera","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":39,"desc_zh":"黄独（学名：Dioscorea bulbifera）为薯蓣科薯蓣属的植物。别名黄药、黄药子。","desc_en":"Dioscorea bulbifera (commonly known as the air potato, air yam, bitter yam, cheeky yam, potato yam, aerial yam, and parsnip yam) is a species of true yam in the yam family, Dioscoreaceae. It is native to Africa, Asia and northern Australia.","img":"images/75.jpg","thumb":"images/t/75.jpg","file":"Starr-090623-1534-Dioscorea bulbifera-bulbs and leaves-Nahiku-Maui (24966795025).jpg","ar":0.75,"py":"huangdu hd","cr_by":"Forest and Kim Starr","cr_lic":"CC BY 3.0 us","cr_licurl":"https://creativecommons.org/licenses/by/3.0/us/deed.en","habit":null,"origin":["亚洲","非洲","大洋洲"]},{"id":1033,"seq":92,"zh":"三品一枝花","en":"Burmannia coelestis","sci":"Burmannia coelestis","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Burmanniaceae","family_zh":"水玉簪科","iucn":"LC","langs":12,"desc_zh":"三品一枝花（学名：Burmannia coelestis）是水玉簪科水玉簪属的植物。分布在亚洲热带以及中国大陆的广西、江西、广东、贵州、浙江、云南等地，生长于海拔300米至1,250米的地区，多生长在湿地上，目前尚未由人工引种栽培。","desc_en":"Burmannia coelestis is a partially mycoheterotrophic species of plant in the genus Burmannia. It is widespread, occurring in South to Southeast Asia, New Guinea, Australia, and in Micronesia.","img":"images/1033.jpg","thumb":"images/t/1033.jpg","file":"Burmannia coelestis (5025550362).jpg","ar":1.333,"py":"sanpinyizhihua spyzh","cr_by":"Dinesh Valke from Thane, India","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":null},{"id":1034,"seq":93,"zh":"沼金花","en":"Narthecium ossifragum","sci":"Narthecium ossifragum","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Nartheciaceae","family_zh":"沼金花科","iucn":null,"langs":29,"desc_zh":null,"desc_en":"Narthecium ossifragum, commonly known as bog asphodel, Lancashire asphodel or bastard asphodel, is a species of flowering plant in the family Nartheciaceae.","img":"images/1034.jpg","thumb":"images/t/1034.jpg","file":"Gelbe Moorlilie (Narthecium ossifragum) Naturpark Südheide 20200704 (5).jpg","ar":0.683,"py":"zhaojinhua zjh","cr_by":"Hajotthu","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"],"illus_img":"images/i/1034.jpg","illus_thumb":"images/i/t/1034.jpg","illus_file":"Narthecium ossifragum Sturm41 clean.jpg","illus_ar":0.667,"illus_by":"User:Kilom691","illus_lic":"Public domain","illus_licurl":null},{"id":1035,"seq":94,"zh":"Thismia neptunis","en":"Thismia neptunis","sci":"Thismia neptunis","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Thismiaceae","family_zh":"肉质腐生科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Thismia neptunis is a species of Thismia endemic to Borneo. It was discovered by Italian botanist Odoardo Beccari in 1866, and described in 1878. It was not observed again until 2017, when it was first photographed by a team of biologists from the Czech Republ…","img":"images/1035.png","thumb":"images/t/1035.png","file":"Thismia neptunis only.png","ar":0.699,"py":"","cr_by":"Marianne North and Odoardo Beccari","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":77,"seq":95,"zh":"露兜树","en":"Pandanus tectorius","sci":"Pandanus tectorius","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Pandanaceae","family_zh":"露兜树科","iucn":"LC","langs":41,"desc_zh":"林投（学名：Pandanus tectorius），古作菻荼，别称露兜树、野菠萝、假菠萝、海菠萝等，为露兜树科露兜树属下的一个物种，原产于马来界，澳大利亚东部及太平洋三大岛群。林投具耐风、耐盐的特质，且繁殖容易，是台湾常见的海岸防风定砂植物。兰屿达悟族人称之为「Ango」；达悟族会使用林投的气生根烤或曝晒飞鱼，部分客家人则用林投气根替代麻绳制作草鞋。","desc_en":"Pandanus tectorius is a species of Pandanus (screwpine) that is native to Malesia, Papuasia, eastern Australia, and the Pacific Islands. It grows in the coastal lowlands typically near the edge of the ocean.","img":"images/77.jpg","thumb":"images/t/77.jpg","file":"Pandanus tectorius.jpg","ar":1.333,"py":"ludoushu lds","cr_by":"No machine-readable author provided. Marshman~commonswiki assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["大洋洲"]},{"id":78,"seq":96,"zh":"七叶兰","en":"Pandanus amaryllifolius","sci":"Pandanus amaryllifolius","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Pandanaceae","family_zh":"露兜树科","iucn":null,"langs":38,"desc_zh":"七叶兰（学名：Pandanus amaryllifolius），又名香露兜、香露兜树、斑兰叶（pandan）、香兰叶、香林投、碧血树、芳兰叶，是露兜树科露兜树属热带植物，常作为东南亚料理与糕点制作材料。野生七叶兰较为稀少，其多半为栽培作物。使用时多榨取其绿色汁液，混入面点之中，以增添绿色色泽，亦可用于食物的包装。","desc_en":"Pandanus amaryllifolius is a tropical plant in the Pandanus (screwpine) genus, which is commonly known as pandan (; Malay: [ˈpandan]). It has fragrant leaves that are used widely for flavouring in the cuisines of Southeast Asia.","img":"images/78.jpg","thumb":"images/t/78.jpg","file":"Chottola.jpg","ar":0.75,"py":"qiyelan qyl","cr_by":"Zuhairali","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":1036,"seq":97,"zh":"红刺露兜树","en":"Pandanus utilis","sci":"Pandanus utilis","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Pandanaceae","family_zh":"露兜树科","iucn":null,"langs":26,"desc_zh":"红刺露兜树（学名：Pandanus utilis）为露兜树科露兜树属下的一种常绿乔木。原产于非洲马达加斯加岛等地。因树型优美特殊，许多国家地区都有栽种，是有名的热带观赏树种，同时也是一种经常做为样本的树种。","desc_en":"Pandanus utilis, commonly known as common screwpine or pimento thatch, is a species of monocot in the genus Pandanus, native to the Mascarene Islands of Mauritius, Rodrigues, and Réunion, and naturalised in Madagascar (where it has often been thought native),…","img":"images/1036.jpg","thumb":"images/t/1036.jpg","file":"Bermuda - Pandanus utilis (Screwpine).jpg","ar":0.809,"py":"hongciludoushu hclds","cr_by":"P. Hughes","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"]},{"id":1037,"seq":98,"zh":"巴拿马草","en":"Carludovica palmata","sci":"Carludovica palmata","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Cyclanthaceae","family_zh":"环花草科","iucn":"LC","langs":16,"desc_zh":"巴拿马草（学名：Carludovica palmata）为巴拿马草科巴拿马草属下的一个种。","desc_en":"Carludovica palmata (also known as Panama hat plant, toquilla palm, calá, palmilla, palmero, pojom, jiraca, junco, soyacal, tepejilote, and jipijapa) is a species of flowering plant in the family Cyclanthaceae.","img":"images/1037.jpg","thumb":"images/t/1037.jpg","file":"Starr 030807-0128 Carludovica palmata.jpg","ar":0.75,"py":"banamacao bnmc","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":null},{"id":1038,"seq":99,"zh":"大百部","en":"Stemona tuberosa","sci":"Stemona tuberosa","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Stemonaceae","family_zh":"百部科","iucn":null,"langs":13,"desc_zh":"大百部（学名：Stemona tuberosa）是百部科百部属的植物。分布在菲律宾、印度北部、中南半岛以及中国大陆的长江流域以南各省区等地，生长于海拔370米至2,240米的地区，多生在山坡丛林下、路旁、溪边、山谷及阴湿岩石中，目前尚未由人工引种栽培。","desc_en":"Stemona tuberosa is a species of flowering plant in the family Stemonaceae. Hornets play an important role in seed dispersal by biting off the seed with its elaiosome and then carrying the seed away for about 100 m.","img":"images/1038.jpg","thumb":"images/t/1038.jpg","file":"Stemona tuberosa-5-60 feet bridge-yercaud-salem-India.jpg","ar":0.75,"py":"dabaibu dbb","cr_by":"Yercaud-elango","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":1039,"seq":100,"zh":"Lacandonia schismatica","en":"Lacandonia schismatica","sci":"Lacandonia schismatica","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Triuridaceae","family_zh":"霉草科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Lacandonia schismatica is a species of plant in the Triuridaceae family which has a symbiotic relationship with fungi, known as myco-heterotrophy. It is endemic to Lacandon Jungle in the State of Chiapas in southern Mexico.","img":"images/1039.png","thumb":"images/t/1039.png","file":"Lacandonia.PNG","ar":0.995,"py":"","cr_by":"self-made","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":1040,"seq":101,"zh":"Nanuza plicata","en":"Nanuza plicata","sci":"Nanuza plicata","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Velloziaceae","family_zh":"翡若翠科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Nanuza plicata is a plant species in the family Velloziaceae, endemic to Brazil. Nanuza plicata contains amentoflavone and xerophytolic acid.","img":"images/1040.jpg","thumb":"images/t/1040.jpg","file":"Flickr - BioDivLibrary - n9 w1150 (2).jpg","ar":0.775,"py":"","cr_by":"Biodiversity Heritage Library","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["南美洲"]},{"id":79,"seq":102,"zh":"欧洲百合","en":"Lilium martagon","sci":"Lilium martagon","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":61,"desc_zh":"欧洲百合（学名：Lilium martagon）又名头巾百合，为百合科百合属的多年生草本植物，主要分布在欧洲、蒙古、朝鲜，西伯利亚、斯堪的纳维亚（归化）等地也有分布，是常用庭园花卉之一。欧洲百合的花朵有红、深紫、橙、白色，花瓣上分布有很多斑点，有芳香气味，每株生有数朵。","desc_en":"Lilium martagon, the martagon lily or Turk's cap lily, is a Eurasian species of lily. It has a widespread native region extending from Portugal east through Europe and Asia as far east as Mongolia.","img":"images/79.jpg","thumb":"images/t/79.jpg","file":"Lilium martagon a.jpg","ar":0.664,"py":"ouzhoubaihe ozbh","cr_by":"Schnobby","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/79.jpg","illus_thumb":"images/i/t/79.jpg","illus_file":"Lilium martagon - Les liliacées, vol. 3 - t. 146.jpg","illus_ar":0.64,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":80,"seq":103,"zh":"圣母百合","en":"Lilium candidum","sci":"Lilium candidum","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":46,"desc_zh":"圣母百合（学名：Lilium candidum）是百合科百合属多年生草本植物，又名白百合、白花百合、玛丹娜百合（Madonna Lily）。原产于巴尔干半岛与西亚。种小名candidum是「纯白色」的意思，形容本种花瓣的颜色是纯白色的。纯白色的花被视为是纯洁的象征，中世纪时期的基督徒常拿这种百合花来敬礼圣母玛利亚，因此被称为圣母百合、玛丹娜百合。","desc_en":"Lilium candidum, the Madonna lily or white lily, is a plant in the true lily family. It is native to the Balkans and Middle East, and naturalized in other parts of Europe, including France, Italy, and Ukraine, and in North Africa, the Canary Islands, Mexico, a…","img":"images/80.jpg","thumb":"images/t/80.jpg","file":"Liliaceae - Lilium candidum-1.jpg","ar":0.75,"py":"shengmubaihe smbh","cr_by":"Hectonichus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲","北美洲"],"illus_img":"images/i/80.jpg","illus_thumb":"images/i/t/80.jpg","illus_file":"The American Flora. Vol. 2, 1855 - pl. 25 Lilium candidum (8079581912).jpg","illus_ar":0.719,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":81,"seq":104,"zh":"花格贝母","en":"Fritillaria meleagris","sci":"Fritillaria meleagris","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":41,"desc_zh":"花格贝母（学名：Fritillaria meleagris）是百合科贝母属的植物，又名阿尔泰贝母、小贝母、珠鸡斑贝母、蛇头贝母。","desc_en":"Fritillaria meleagris is a Eurasian species of flowering plant in the lily family Liliaceae. Its common names include snake's head fritillary, snake's head (the original English name), chess flower, frog-cup, guinea-hen flower, guinea flower, leper lily (becau…","img":"images/81.jpg","thumb":"images/t/81.jpg","file":"Fritillaria meleagris LJ barje2.jpg","ar":0.723,"py":"huagebeimu hgbm","cr_by":"Yerpo","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/81.jpg","illus_thumb":"images/i/t/81.jpg","illus_file":"Fritillaria meleagris Sturm32.jpg","illus_ar":0.644,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":82,"seq":105,"zh":"花贝母","en":"Fritillaria imperialis","sci":"Fritillaria imperialis","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":38,"desc_zh":"花贝母（学名：Fritillaria imperialis），又名冠花贝母、皇冠贝母、帝王贝母、王贝母，百合科贝母属植物，种类繁多，分布全球各地，原产土耳其南部。是一种观赏类植物，中国各地种植较多，适用于庭院种植，布置花境或基础种植均可，矮生品种比较适合盆栽，观赏性很强。 其种加词“imperialis”意为“帝王的”。","desc_en":"Fritillaria imperialis, the crown imperial, imperial fritillary or Kaiser's crown, is a species of flowering plant in the lily family Liliaceae, native to a wide stretch of Asia including Turkey, Iran Iraq, Afghanistan, Pakistan, Northern India, and the Himala…","img":"images/82.jpg","thumb":"images/t/82.jpg","file":"Fritillaria imperialis.jpg","ar":0.75,"py":"huabeimu hbm","cr_by":"No machine-readable author provided. Magalhães assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"],"illus_img":"images/i/82.jpg","illus_thumb":"images/i/t/82.jpg","illus_file":"Fritillaria imperialis var. jaune. Redouté, Choix des plus belles fleurs et des plus beaux fruits, t. 2, P.J. (1827).tiff","illus_ar":0.731,"illus_by":"Redouté, P.J.","illus_lic":"Public domain","illus_licurl":null},{"id":83,"seq":106,"zh":"珠芽百合","en":"Lilium bulbiferum","sci":"Lilium bulbiferum","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":38,"desc_zh":"珠芽百合（学名：Lilium bulbiferum）是百合科百合属的一种有地下鳞茎的多年生草本植物。种小名bulbiferum的意思是「具有鳞茎的」，形容它的地上茎具有珠芽。","desc_en":"Lilium bulbiferum, common names orange lily, fire lily, Jimmy's Bane, tiger lily and St. John's Lily, is a herbaceous European lily with underground bulbs, belonging to the Liliaceae.","img":"images/83.jpg","thumb":"images/t/83.jpg","file":"0 Lilium bulbiferum - Samoëns (1).JPG","ar":1.27,"py":"zhuyabaihe zybh","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/83.jpg","illus_thumb":"images/i/t/83.jpg","illus_file":"Lilium bulbiferum — Flora Batava — Volume v16.jpg","illus_ar":0.789,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":84,"seq":107,"zh":"猪牙花","en":"Erythronium dens-canis","sci":"Erythronium dens-canis","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Erythronium dens-canis, the dog's-tooth-violet is a bulbous herbaceous perennial flowering plant in the family Liliaceae. It is native to central and southern Europe from Portugal to Ukraine, and locally naturalised north to Germany, Great Britain, and Ireland…","img":"images/84.jpg","thumb":"images/t/84.jpg","file":"Erythronium dens-canis (47351928761).jpg","ar":1.501,"py":"zhuyahua zyh","cr_by":"xulescu_g","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"草本","origin":["欧洲"]},{"id":88,"seq":108,"zh":"秋水仙","en":"Colchicum autumnale","sci":"Colchicum autumnale","order_en":"Liliales","order_zh":"百合目","family_en":"Colchicaceae","family_zh":"秋水仙科","iucn":"LC","langs":61,"desc_zh":"秋水仙（学名：Colchicum autumnale），属于秋水仙科秋水仙属，生物碱秋水仙素就是因是从本植物首次萃取出而得名。","desc_en":"Colchicum autumnale, commonly known as autumn crocus, meadow saffron, naked boys or naked ladies, is a toxic autumn-blooming flowering plant that resembles the true crocuses, but is a member of the plant family Colchicaceae, unlike the true crocuses, which bel…","img":"images/88.jpg","thumb":"images/t/88.jpg","file":"Colchicum autumnale.jpg","ar":0.948,"py":"qiushuixian qsx","cr_by":"Stemonitis","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/88.jpg","illus_thumb":"images/i/t/88.jpg","illus_file":"Colchicum autumnale - Köhler–s Medizinal-Pflanzen-044.jpg","illus_ar":0.696,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":89,"seq":109,"zh":"嘉兰","en":"Gloriosa superba","sci":"Gloriosa superba","order_en":"Liliales","order_zh":"百合目","family_en":"Colchicaceae","family_zh":"秋水仙科","iucn":"LC","langs":45,"desc_zh":"嘉兰（学名：Gloriosa superba）为百合科嘉兰属下的一个种。","desc_en":"Gloriosa superba is a species of flowering plant in the family Colchicaceae. Common names include flame lily, climbing lily, creeping lily, glory lily, gloriosa lily, tiger claw, and fire lily.","img":"images/89.jpg","thumb":"images/t/89.jpg","file":"Gloriosa rothschildiana 01.jpg","ar":0.75,"py":"jialan jl","cr_by":"Jean-Jacques MILAN","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":null},{"id":1041,"seq":110,"zh":"Colchicum bulbocodium","en":"Colchicum bulbocodium","sci":"Colchicum bulbocodium","order_en":"Liliales","order_zh":"百合目","family_en":"Colchicaceae","family_zh":"秋水仙科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Colchicum bulbocodium, the spring meadow saffron, is a species of alpine bulbous plant native to mountain ranges across Europe from the Pyrenees to the Caucasus (Spain, France, Italy, Switzerland, Austria, Hungary, Romania, the former Yugoslavia, Ukraine and s…","img":"images/1041.jpg","thumb":"images/t/1041.jpg","file":"Bulbocodium.JPG","ar":1.333,"py":"","cr_by":"James Steakley","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":90,"seq":111,"zh":"穗菝葜","en":"Smilax aspera","sci":"Smilax aspera","order_en":"Liliales","order_zh":"百合目","family_en":"Smilacaceae","family_zh":"菝葜科","iucn":null,"langs":34,"desc_zh":"穗菝葜（学名：Smilax aspera）为百合科菝葜属下的一个种。","desc_en":"Smilax aspera, with common names common smilax, rough bindweed, sarsaparille, and Mediterranean smilax, is a species of flowering vine in the greenbriar family.","img":"images/90.jpg","thumb":"images/t/90.jpg","file":"Smilax aspera.jpg","ar":0.75,"py":"suibaqia sbq","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["欧洲"],"illus_img":"images/i/90.jpg","illus_thumb":"images/i/t/90.jpg","illus_file":"53 Smilax aspera par Pierre-Joseph Redouté.jpeg","illus_ar":0.696,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":91,"seq":112,"zh":"菝葜","en":"Smilax china","sci":"Smilax china","order_en":"Liliales","order_zh":"百合目","family_en":"Smilacaceae","family_zh":"菝葜科","iucn":null,"langs":24,"desc_zh":"菝葜（bá qiā）（学名：Smilax china），也称金刚藤，菝葜科菝葜属，多年生藤本落叶攀附植物。生于山坡林下。分布于中国长江以南各地和日本。琉璃蛱蝶幼虫的主要食物之一就是菝葜。若种植可在3月播种。","desc_en":"Smilax china is a climbing plant species in the genus Smilax. It is native to China, Korea, Taiwan, Japan (including Ryukyu and Bonin Islands), Philippines, Vietnam, Thailand, Myanmar, and India.","img":"images/91.jpg","thumb":"images/t/91.jpg","file":"Smilax china (Montage s3).jpg","ar":1,"py":"baqia bq","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":1042,"seq":113,"zh":"墨西哥菝葜","en":"Smilax regelii","sci":"Smilax regelii","order_en":"Liliales","order_zh":"百合目","family_en":"Smilacaceae","family_zh":"菝葜科","iucn":null,"langs":20,"desc_zh":"墨西哥菝葜（学名：Smilax regelii）是菝葜科牛尾菜属（菝葜属）的多年生植物，原产于中美洲热带地区。墨西哥菝葜的英语俗名Sarsaparilla有时亦包括墨西哥菝葜的其他近缘种。有人称其为土茯苓，但正确来说土茯苓其实是指另一个品种光滑菝葜（Smilax glabra Roxb）的根。","desc_en":"Smilax ornata is a perennial trailing vine with prickly stems that is native to Mexico and Central America. Common names include sarsaparilla, Honduran sarsaparilla, and Jamaican sarsaparilla.","img":"images/1042.jpg","thumb":"images/t/1042.jpg","file":"Smilax aristolochiifolia - Köhler–s Medizinal-Pflanzen-130.jpg","ar":0.77,"py":"moxigebaqia mxgbq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["北美洲"]},{"id":92,"seq":114,"zh":"四叶重楼","en":"Paris quadrifolia","sci":"Paris quadrifolia","order_en":"Liliales","order_zh":"百合目","family_en":"Melanthiaceae","family_zh":"藜芦科","iucn":null,"langs":45,"desc_zh":"四叶重楼（学名：Paris quadrifolia）为黑药花科重楼属的植物。其种加词“quadrifolia”意为“四叶的”。分布于亚洲、欧洲以及中国大陆的新疆等地，目前尚未由人工引种栽培。","desc_en":"Paris quadrifolia, the herb Paris or true lover's knot, is a species of flowering plant in the family Melanthiaceae. It occurs in temperate and cool areas throughout Eurasia, from Spain to Yakutia, and from Iceland to Mongolia.","img":"images/92.jpg","thumb":"images/t/92.jpg","file":"Paris quadrifolia 2011 G2.jpg","ar":0.75,"py":"siyezhonglou syzl","cr_by":"George Chernilevsky","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/92.jpg","illus_thumb":"images/i/t/92.jpg","illus_file":"Illustration Paris quadrifolia0 clean.jpg","illus_ar":0.613,"illus_by":"Frédéric 19:26, 9 March 2008 (UTC)","illus_lic":"Public domain","illus_licurl":null},{"id":93,"seq":115,"zh":"白藜芦","en":"Veratrum album","sci":"Veratrum album","order_en":"Liliales","order_zh":"百合目","family_en":"Melanthiaceae","family_zh":"藜芦科","iucn":null,"langs":42,"desc_zh":"白藜芦（学名：Veratrum album）是黑药花科藜芦属多年生草本植物，原产欧洲至西伯利亚。","desc_en":"Veratrum album, the false helleborine, white hellebore, European white hellebore, or white veratrum (syn. Veratrum lobelianum Bernh.) is a poisonous plant in the family Melanthiaceae.","img":"images/93.jpg","thumb":"images/t/93.jpg","file":"Veratrum album en Chartreuse.jpg","ar":0.75,"py":"baililu bll","cr_by":"Patrice78500","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/93.jpg","illus_thumb":"images/i/t/93.jpg","illus_file":"Illustration Veratrum album0.jpg","illus_ar":0.629,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":1043,"seq":116,"zh":"藜芦","en":"Veratrum nigrum","sci":"Veratrum nigrum","order_en":"Liliales","order_zh":"百合目","family_en":"Melanthiaceae","family_zh":"藜芦科","iucn":null,"langs":28,"desc_zh":"藜芦（学名：Veratrum nigrum）为黑药花科藜芦属下的一个种。","desc_en":"Veratrum nigrum, the black false hellebore, is a widespread Eurasian species of perennial flowering plant in the family Melanthiaceae. Despite its common name, V. nigrum is not closely related to the true hellebores, nor does it resemble them.","img":"images/1043.jpg","thumb":"images/t/1043.jpg","file":"Veratrum nigrum Ciemiężyca czarna flowers 01.jpg","ar":0.75,"py":"lilu ll","cr_by":"Agnieszka Kwiecień ( Nova )","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["亚洲"]},{"id":176,"seq":117,"zh":"短叶丝兰","en":"Yucca brevifolia","sci":"Yucca brevifolia","order_en":"Liliales","order_zh":"百合目","family_en":"Agavaceae","family_zh":"龙舌兰科","iucn":"LC","langs":36,"desc_zh":"短叶丝兰（学名：Yucca brevifolia），又名约书亚树，为天门冬科丝兰属下的一个物种，属单子叶树木，分布于美国西南部干燥地区，包括加州、亚利桑那州、犹他州、内华达州至西北墨西哥（下加利福尼亚、南下加利福尼亚州、锡那罗亚与索诺拉沙漠），主要生长于莫哈韦沙漠约书亚树国家公园海拔介于400、1,800米（1,300、5,900英尺）之间的空旷草原（女王山谷与失马山谷）。","desc_en":"Yucca brevifolia (also known as the Joshua tree, yucca palm, tree yucca, and palm tree yucca) is a plant species belonging to the genus Yucca. It is tree-like in appearance, which is reflected in its common names.","img":"images/176.jpg","thumb":"images/t/176.jpg","file":"Joshua Tree NP - Joshua Tree 2.jpg","ar":0.646,"py":"duanyesilan dysl","cr_by":"Jarek Tuszyński","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲"]},{"id":177,"seq":118,"zh":"吊兰","en":"Chlorophytum comosum","sci":"Chlorophytum comosum","order_en":"Liliales","order_zh":"百合目","family_en":"Agavaceae","family_zh":"龙舌兰科","iucn":null,"langs":35,"desc_zh":"吊兰（学名：Chlorophytum comosum）又名钓兰、挂兰、兰草、折鹤兰，欧美国家称蜘蛛草（spider plant），日本称折鹤兰，是相当常见的垂挂式观叶植物，原产于南非。","desc_en":"Chlorophytum comosum, usually called spider plant or common spider plant due to its spider-like look, also known as spider ivy, airplane plant, ribbon plant (a name it shares with Dracaena sanderiana), and hen and chicks, is a species of evergreen perennial fl…","img":"images/177.jpg","thumb":"images/t/177.jpg","file":"Malamadre (Chlorophytum comosum).jpg","ar":1.333,"py":"diaolan dl","cr_by":"Juan Carlos Fonseca Mata","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["非洲","大洋洲"]},{"id":1044,"seq":119,"zh":"金黄六出花","en":"Alstroemeria aurea","sci":"Alstroemeria aurea","order_en":"Liliales","order_zh":"百合目","family_en":"Alstroemeriaceae","family_zh":"六出花科","iucn":null,"langs":15,"desc_zh":null,"desc_en":"Alstroemeria aurea is a species of flowering plant in the family Alstroemeriaceae, native to Chile and Argentina, but naturalised in Australia, New Zealand and the United Kingdom. It is also widely cultivated as an ornamental.","img":"images/1044.jpg","thumb":"images/t/1044.jpg","file":"Alstroemieria aurantiaca0.jpg","ar":0.75,"py":"jinhuangliuchuhua jhlch","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["南美洲","大洋洲"]},{"id":1045,"seq":120,"zh":"Bomarea edulis","en":"Bomarea edulis","sci":"Bomarea edulis","order_en":"Liliales","order_zh":"百合目","family_en":"Alstroemeriaceae","family_zh":"六出花科","iucn":null,"langs":13,"desc_zh":null,"desc_en":"Bomarea edulis, common name salsilla, is a species of flowering plant in the alstroemeria family Alstroemeriaceae, that is native to the tropics of Mexico and the United States. A deciduous climber growing to 2.5 metres (8.","img":"images/1045.jpg","thumb":"images/t/1045.jpg","file":"Bomarea edulis - Basel - 2.jpg","ar":1.333,"py":"","cr_by":"James Steakley","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["北美洲"]},{"id":1046,"seq":121,"zh":"腐蛛草","en":"Arachnitis uniflora","sci":"Arachnitis uniflora","order_en":"Liliales","order_zh":"百合目","family_en":"Corsiaceae","family_zh":"白玉簪科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Arachnitis uniflora, the sole species in the genus Arachnitis, is a non-photosynthetic plant species in the family Corsiaceae. This species is mycoheterotrophic, and it obtains carbon from mycorrhizal fungi of the family Glomeraceae which are associated to its…","img":"images/1046.jpg","thumb":"images/t/1046.jpg","file":"Arachnitis uniflora Phil. (2076079153).jpg","ar":1.332,"py":"fuzhucao fzc","cr_by":"pabloendemico","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["南美洲"]},{"id":1047,"seq":122,"zh":"智利风铃草","en":"Lapageria rosea","sci":"Lapageria rosea","order_en":"Liliales","order_zh":"百合目","family_en":"Philesiaceae","family_zh":"垂花科","iucn":null,"langs":34,"desc_zh":"智利风铃草（学名：Lapageria rosea），又称戈比爱野百合，是垂花科智利风铃草属的植物。原产于智利南部的森林里，是智利的国花。智利风铃草属内只有智利风铃草这一个种。 长绿性的攀缘植物，攀附在其他树木上，植株高度有时可以高达 10 公尺以上。花红色，花被片有六片。果实为浆果，可以食用，内含有许多细小的种子。 智利风铃草的果实在智利称为 pepino（黄瓜），果实的外形像小黄瓜，而味道有点像冷子番荔枝。","desc_en":"Lapageria is a genus of flowering plants with only one known species, Lapageria rosea, commonly known as Chilean bellflower or copihue (Spanish pronunciation: [ko'piwe], from Mapudungun kopiwe).","img":"images/1047.jpg","thumb":"images/t/1047.jpg","file":"Lapageria rosea1.jpg","ar":0.75,"py":"zhilifenglingcao zlflc","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["南美洲"]},{"id":1048,"seq":123,"zh":"Ripogonum scandens","en":"Ripogonum scandens","sci":"Ripogonum scandens","order_en":"Liliales","order_zh":"百合目","family_en":"Ripogonaceae","family_zh":"菝葜藤科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Ripogonum scandens, commonly known as supplejack and kareao, is a species of climbing forest vine in the family Ripogonaceae. It is endemic to New Zealand. Its range mainly covers the North and South Islands but it also occurs on some offshore islands.","img":"images/1048.jpg","thumb":"images/t/1048.jpg","file":"Rhipogonum scandens 11.JPG","ar":1.201,"py":"","cr_by":"Rudolph89","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"藤本","origin":["大洋洲"]},{"id":94,"seq":124,"zh":"杓兰","en":"Cypripedium calceolus","sci":"Cypripedium calceolus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":57,"desc_zh":"杓兰（学名：Cypripedium calceolus）为兰科杓兰属下的一个种。本来在英国广泛存在，但十九世纪时人们疯狂采集兰花，杓兰急剧减少，最后在1917年宣布其灭绝。","desc_en":"Cypripedium calceolus is a lady's-slipper orchid, and the type species of the genus Cypripedium. It is native to Europe and Asia.","img":"images/94.jpg","thumb":"images/t/94.jpg","file":"Cypripedium calceolus 03-09.jpg","ar":1.333,"py":"shaolan sl","cr_by":"No machine-readable author provided. Johan N assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/94.jpg","illus_thumb":"images/i/t/94.jpg","illus_file":"Illustration Cypripedium calceolus0 clean.jpg","illus_ar":0.625,"illus_by":"User:Kilom691","illus_lic":"Public domain","illus_licurl":null},{"id":95,"seq":125,"zh":"香草","en":"Vanilla planifolia","sci":"Vanilla planifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"EN","langs":49,"desc_zh":"香荚兰（学名：Vanilla planifolia），又称香草、香子兰、香草兰、港澳地区音译作云呢拿，是香草 (香料)的一种，常用作甜品的香料。该词也指从本植物中提取的、或者人工合成的同种香料。 香荚兰的香味源自其种荚（香荚兰豆）里名为香草精的化合物。鲜豆荚没有什么香味，需要杀青、发酵、烘干、陈化等加工过程，然后才发出浓郁香气。上一年的11月份收获鲜豆荚，要到次年的5月才能完成加工过程，形成成品上市。","desc_en":"Vanilla planifolia is a species of vanilla orchid native to Mexico, Central America, Colombia, and Brazil. It is one of the primary sources for vanilla flavouring, due to its high vanillin content.","img":"images/95.jpg","thumb":"images/t/95.jpg","file":"Vanilla planifolia 1.jpg","ar":1.238,"py":"xiangcao xc","cr_by":"Everglades National Park","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲","南美洲"],"illus_img":"images/i/95.jpg","illus_thumb":"images/i/t/95.jpg","illus_file":"Vanilla planifolia - Köhler–s Medizinal-Pflanzen-278.jpg","illus_ar":0.902,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":96,"seq":126,"zh":"蜂兰","en":"Ophrys apifera","sci":"Ophrys apifera","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":47,"desc_zh":"蜂兰（学名：Ophrys apifera），是蜂兰属下的一种植物，广泛分布于欧洲、北非和西亚，且是英国英格兰贝德福德郡的郡花。 此外也见于北美洲和东亚。 其种加词的意思是“有蜂的”，用以指代其蜂状的花瓣。 而这种花也会分泌利己素模仿雌蜂的气味，以吸引Tetralonia cressa和Eucera pulveraceae这两种蜂的雄蜂。 蜂兰上最像蜂的花也最有可能吸引到这些蜂，因此就会得到更高的授粉机率。","desc_en":"Ophrys apifera, known in Europe as the bee orchid, is a perennial herbaceous plant of the genus Ophrys, in the family of Orchidaceae. It serves as an example of sexually deceptive pollination and floral mimicry, a highly selective and highly evolved plant–poll…","img":"images/96.jpg","thumb":"images/t/96.jpg","file":"(MHNT) Ophrys apifera - Villeneuve-lès-Bouloc - Flower.jpg","ar":1.214,"py":"fenglan fl","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/96.jpg","illus_thumb":"images/i/t/96.jpg","illus_file":"Ophrys apifera (as Ophrys arachnites) - Curtis' 51 pl. 2516 (1824).jpg","illus_ar":0.582,"illus_by":"J. Curtis del., Weddell sc.","illus_lic":"Public domain","illus_licurl":null},{"id":97,"seq":127,"zh":"强壮红门兰","en":"Orchis mascula","sci":"Orchis mascula","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":45,"desc_zh":null,"desc_en":"Orchis mascula, the early-purple orchid, early spring orchis, is a species of flowering plant in the orchid family, Orchidaceae.","img":"images/97.jpg","thumb":"images/t/97.jpg","file":"Orchis mascula inflorescence - Keila.jpg","ar":0.667,"py":"qiangzhuanghongmenlan qzhml","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/97.png","illus_thumb":"images/i/t/97.png","illus_file":"Orchis mascula (Icones Florae Germanicae et Helveticae 1851, v13 et 14, plate 390) clean, no-frame, no-details.png","illus_ar":0.697,"illus_by":"Reichenbach, L.; Reichenbach, H. G.;","illus_lic":"Public domain","illus_licurl":null},{"id":98,"seq":128,"zh":"齿缘红门兰","en":"Anacamptis morio","sci":"Anacamptis morio","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":45,"desc_zh":"齿缘小红门兰（学名：Ponerorchis crenulata）也称齿缘红门兰，为兰科小红门兰属下的一个种，分布于欧洲和中东。","desc_en":"Anacamptis morio, the green-winged orchid or green-veined orchid (synonym Orchis morio), is a flowering plant of the orchid family, Orchidaceae. It usually has purple flowers, and is found in Europe, Northern Africa and western Asia.","img":"images/98.jpg","thumb":"images/t/98.jpg","file":"Anacamptis morio hampe.jpg","ar":0.633,"py":"chiyuanhongmenlan cyhml","cr_by":"Didier Desouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":99,"seq":129,"zh":"细距舌唇兰","en":"Platanthera bifolia","sci":"Platanthera bifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":43,"desc_zh":"细距舌唇兰（学名：Platanthera bifolia）是舌唇兰属的一种植物，与红门兰属有著一定关系。它以往是被分类在玉凤花属中。它分布在欧洲及摩洛哥。其属名是来自希腊文，意思是「阔大的鹿角」，而种小名则意指「两块叶子」。","desc_en":"Platanthera bifolia, commonly known as the lesser butterfly-orchid, is a species of orchid in the genus Platanthera, having certain relations with the genus Orchis, where it was previously included and also with the genus Habenaria.","img":"images/99.jpg","thumb":"images/t/99.jpg","file":"Platanthera bifolia (flower).jpg","ar":0.75,"py":"xijushechunlan xjscl","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"],"illus_img":"images/i/99.jpg","illus_thumb":"images/i/t/99.jpg","illus_file":"Platanthera bifolia - Köhler–s Medizinal-Pflanzen-245.jpg","illus_ar":0.792,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":100,"seq":130,"zh":"Dactylorhiza maculata","en":"Dactylorhiza maculata","sci":"Dactylorhiza maculata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":41,"desc_zh":null,"desc_en":"Dactylorhiza maculata, known as the heath spotted-orchid or moorland spotted orchid, is a herbaceous perennial plant of the family Orchidaceae. It is widespread in mountainous regions across much of Europe from Portugal and Iceland east to Russia.","img":"images/100.jpg","thumb":"images/t/100.jpg","file":"Dactylorhiza maculata LC0232.jpg","ar":0.667,"py":"","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/100.jpg","illus_thumb":"images/i/t/100.jpg","illus_file":"Dactylorhiza maculata Lindman DESC.JPG","illus_ar":1.403,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":101,"seq":131,"zh":"手参","en":"Gymnadenia conopsea","sci":"Gymnadenia conopsea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":40,"desc_zh":"手参（学名：Gymnadenia conopsea）为兰科手参属下的一个种。","desc_en":"Gymnadenia conopsea, commonly known as the fragrant orchid or chalk fragrant orchid, is a herbaceous plant of the family Orchidaceae native to northern Europe.","img":"images/101.jpg","thumb":"images/t/101.jpg","file":"GymnadeniaConopsea.jpg","ar":0.466,"py":"shoucan sc","cr_by":"The original uploader was (Automated conversion) at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"],"illus_img":"images/i/101.jpg","illus_thumb":"images/i/t/101.jpg","illus_file":"Gymnadenia conopsea Nordens Flora 404.jpg","illus_ar":0.6,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":102,"seq":132,"zh":"裂唇虎舌兰","en":"Epipogium aphyllum","sci":"Epipogium aphyllum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":40,"desc_zh":"裂唇虎舌兰（学名：Epipogium aphyllum）为兰科虎舌兰属下的一个种。","desc_en":"Epipogium aphyllum, the ghost orchid, is a hardy mycoheterotrophic orchid lacking chlorophyll. In much of its range, it is a rare representative of family Orchidaceae.","img":"images/102.jpg","thumb":"images/t/102.jpg","file":"Epipogium aphyllum - Jõhvi- crop.jpg","ar":0.75,"py":"liechunhushelan lchsl","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/102.jpg","illus_thumb":"images/i/t/102.jpg","illus_file":"Epipogium aphyllum (as Epipogium gmelinii, spelled Epipogon gmelini) - Curtis' 80 (Ser. 3 no. 10) pl. 4821 (1854).jpg","illus_ar":0.589,"illus_by":"Walter Hood Fitch (1817-1892) del. et lith., description by William Jackson Hooker (1785—1865)","illus_lic":"Public domain","illus_licurl":null},{"id":103,"seq":133,"zh":"欧洲对叶兰","en":"Neottia ovata","sci":"Neottia ovata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":40,"desc_zh":"欧洲对叶兰 (学名：Neottia ovata，旧称 Listera ovata)，又称卵叶对叶兰（eggleaf twayblade），是一种陆生兰花，广泛分布于欧洲和亚洲的许多地区。","desc_en":"Neottia ovata (formerly Listera ovata), the common twayblade or eggleaf twayblade, is a terrestrial orchid widespread across much of Europe and Asia.","img":"images/103.jpg","thumb":"images/t/103.jpg","file":"Listera ovata 230503.jpg","ar":0.698,"py":"ouzhouduiyelan ozdyl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":104,"seq":134,"zh":"小花火烧兰","en":"Epipactis helleborine","sci":"Epipactis helleborine","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":39,"desc_zh":"火烧兰（学名：Epipactis helleborine）为兰科火烧兰属下的一个种。","desc_en":"Epipactis helleborine, the broad-leaved helleborine, is a terrestrial species of orchid with a broad distribution. It is a long lived herb which varies morphologically with ability to self-pollinate.","img":"images/104.jpg","thumb":"images/t/104.jpg","file":"Epipactis helleborine flowers1 220703.jpg","ar":0.657,"py":"xiaohuahuoshaolan xhhsl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":105,"seq":135,"zh":"头蕊兰","en":"Cephalanthera longifolia","sci":"Cephalanthera longifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":39,"desc_zh":"头蕊兰（学名：Cephalanthera longifolia），为兰科头蕊兰属下的一个植物种。","desc_en":"Cephalanthera longifolia, the narrow-leaved helleborine, sword-leaved helleborine or long-leaved helleborine, is a rhizomatous herbaceous perennial plant in the family Orchidaceae.","img":"images/105.jpg","thumb":"images/t/105.jpg","file":"Cephalanthera longifolia 300508.jpg","ar":0.75,"py":"touruilan trl","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":106,"seq":136,"zh":"Anacamptis pyramidalis","en":"Anacamptis pyramidalis","sci":"Anacamptis pyramidalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":39,"desc_zh":null,"desc_en":"Anacamptis pyramidalis, the pyramidal orchid, is a perennial herbaceous plant belonging to the genus Anacamptis of the family Orchidaceae. The scientific name Anacamptis derives from Greek ανακάμτειν 'anakamptein' meaning 'bend forward', while the Latin name p…","img":"images/106.jpg","thumb":"images/t/106.jpg","file":"(MHNT) Anacamptis pyramidalis - Inflorescence.jpg","ar":0.708,"py":"","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null,"illus_img":"images/i/106.jpg","illus_thumb":"images/i/t/106.jpg","illus_file":"Anacamptis pyramidalis — Flora Batava — Volume v14.jpg","illus_ar":0.76,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":107,"seq":137,"zh":"新疆火烧兰","en":"Epipactis palustris","sci":"Epipactis palustris","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":38,"desc_zh":"新疆火烧兰（学名：Epipactis palustris）为兰科火烧兰属下的一个种。","desc_en":"Epipactis palustris, the marsh helleborine, is a species of orchid native to Europe and Asia.","img":"images/107.jpg","thumb":"images/t/107.jpg","file":"Epipactis palustris 230705.jpg","ar":0.639,"py":"xinjianghuoshaolan xjhsl","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/107.jpg","illus_thumb":"images/i/t/107.jpg","illus_file":"Epipactis palustris Nordens Flora 413.jpg","illus_ar":0.571,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":108,"seq":138,"zh":"四裂红门兰","en":"Orchis militaris","sci":"Orchis militaris","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":38,"desc_zh":"四裂红门兰（学名：Orchis militaris）为兰科红门兰属下的一个种，分布于欧洲，花期为4至6月。","desc_en":"Orchis militaris, the military orchid, is a species of orchid native to Europe. It is the type species of the genus Orchis.","img":"images/108.jpg","thumb":"images/t/108.jpg","file":"Hall käpp - Orchis militaris.jpg","ar":0.749,"py":"siliehongmenlan slhml","cr_by":"Kristian Pikner","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/108.jpg","illus_thumb":"images/i/t/108.jpg","illus_file":"Orchis militaris - Köhler–s Medizinal-Pflanzen-231.jpg","illus_ar":0.803,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":109,"seq":139,"zh":"二叶舌唇兰","en":"Platanthera chlorantha","sci":"Platanthera chlorantha","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":37,"desc_zh":"二叶舌唇兰（学名：Platanthera chlorantha），为兰科舌唇兰属下的一个植物种。","desc_en":"Platanthera chlorantha, commonly known as greater butterfly-orchid, is a species of orchid in the genus Platanthera. It can be found throughout Europe and Morocco.","img":"images/109.jpg","thumb":"images/t/109.jpg","file":"Platanthera chlorantha LC0225.jpg","ar":0.677,"py":"eryeshechunlan eyscl","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/109.jpg","illus_thumb":"images/i/t/109.jpg","illus_file":"Platanthera chlorantha — Flora Batava — Volume v20.jpg","illus_ar":0.706,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":110,"seq":140,"zh":"Neottia nidus-avis","en":"Neottia nidus-avis","sci":"Neottia nidus-avis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":37,"desc_zh":null,"desc_en":"Neottia nidus-avis, the bird's-nest orchid, is a non-photosynthetic orchid, native to Europe, Russia, with sporadic presence in North-Africa, and some parts of the Middle East.","img":"images/110.jpg","thumb":"images/t/110.jpg","file":"Neottia nidus-avis plants.jpg","ar":0.613,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/110.jpg","illus_thumb":"images/i/t/110.jpg","illus_file":"Neottia nidus-avis Lindman DESC.JPG","illus_ar":1.347,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":111,"seq":141,"zh":"Orchis simia","en":"Orchis simia","sci":"Orchis simia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Orchis simia, commonly known as the monkey orchid, is a greyish pink to reddish species of the genus Orchis. It gets its common name from its lobed lip which mimics the general shape of a monkey's body.","img":"images/111.jpg","thumb":"images/t/111.jpg","file":"Orchis simia ( άγρια ορχιδέα).jpg","ar":0.667,"py":"","cr_by":"Μεταξία Φωτίου","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/111.jpg","illus_thumb":"images/i/t/111.jpg","illus_file":"Orchis simia (as Orchis tephrosanthos, var. densifolius) - Curtis' 62 (N.S. 9) pl. 3426 (1835).jpg","illus_ar":0.617,"illus_by":"Drawing probably by William Jackson Hooker (1785—1865), editor of the New Series) , Swan sc.","illus_lic":"Public domain","illus_licurl":null},{"id":112,"seq":142,"zh":"紫斑掌裂兰","en":"Common spotted orchid","sci":"Dactylorhiza fuchsii","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":35,"desc_zh":"紫斑掌裂兰（学名：Dactylorhiza fuchsii）为兰科掌裂兰属下的一个种。","desc_en":"Dactylorhiza fuchsii, the common spotted orchid, is a species of flowering plant in the orchid family Orchidaceae. It is one of Europe's most common wild orchids, and is widespread across much of Europe, with the range extending eastward into Siberia, Mongolia…","img":"images/112.jpg","thumb":"images/t/112.jpg","file":"Dactylorhiza fuchsii Mariazell 01.JPG","ar":0.667,"py":"zibanzhanglielan zbzll","cr_by":"Uoaei1","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":113,"seq":143,"zh":"珊瑚兰","en":"Corallorhiza trifida","sci":"Corallorhiza trifida","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":35,"desc_zh":"珊瑚兰（学名：Corallorhiza trifida）为兰科珊瑚兰属下的一个种。虽然有叶绿素，但属部分菌异营，即取真菌之营养助维生。","desc_en":"Corallorhiza trifida, commonly known as early coralroot, northern coralroot, or yellow coralroot, is a coralroot orchid native to North America and Eurasia, with a circumboreal distribution.","img":"images/113.jpg","thumb":"images/t/113.jpg","file":"Corallorrhiza trifida 05 mg-k.jpg","ar":0.642,"py":"shanhulan shl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","北美洲"],"illus_img":"images/i/113.jpg","illus_thumb":"images/i/t/113.jpg","illus_file":"Corallorhiza trifida Lindman DESC.JPG","illus_ar":1.858,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":114,"seq":144,"zh":"丛宝兰","en":"Limodorum abortivum","sci":"Limodorum abortivum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":35,"desc_zh":null,"desc_en":"Limodorum abortivum, also known as violet limodore or violet bird's-nest orchid, is a species of myco-heterotrophic, achlorophyllous orchid and is native to mainland Europe, western Asia and the Mediterranean area.","img":"images/114.jpg","thumb":"images/t/114.jpg","file":"Недоразвит лимодорум Limodorum abortivum.jpg","ar":1.333,"py":"congbaolan cbl","cr_by":"ABesheva","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/114.jpg","illus_thumb":"images/i/t/114.jpg","illus_file":"Illustration Limodorum abortivum0.jpg","illus_ar":0.611,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":115,"seq":145,"zh":"绿花凹舌兰","en":"Dactylorhiza viridis","sci":"Dactylorhiza viridis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":"绿花凹舌兰（学名：Coeloglossum viride）为兰科凹舌兰属下的一个种。","desc_en":"Dactylorhiza viridis, the frog orchid, is a species of flowering plant in the orchid family Orchidaceae. It has also been treated as the only species Coeloglossum viride of the monotypic genus Coeloglossum.","img":"images/115.jpg","thumb":"images/t/115.jpg","file":"Coeloglossum viride 04 mg-k.jpg","ar":0.776,"py":"lhuaaoshelan lhasl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":116,"seq":146,"zh":"欧亚绶草","en":"Spiranthes spiralis","sci":"Spiranthes spiralis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Spiranthes spiralis, commonly known as autumn lady's-tresses, is an orchid that grows in Europe and adjacent North Africa and Asia. It is a small grey-green plant. It forms a rosette of four to five pointed, sessile, ovate leaves about 3 cm (1.2 in) in length.","img":"images/116.jpg","thumb":"images/t/116.jpg","file":"Spiranthes spiralis 120807.jpg","ar":0.428,"py":"ouyashoucao oysc","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/116.jpg","illus_thumb":"images/i/t/116.jpg","illus_file":"Illustration Spiranthes spiralis0.jpg","illus_ar":0.59,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":117,"seq":147,"zh":"Cephalanthera rubra","en":"Cephalanthera rubra","sci":"Cephalanthera rubra","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Cephalanthera rubra, known as red helleborine, is an orchid found in Europe, North Africa and southwest Asia. Although reasonably common in parts of its range, this Cephalanthera has always been one of the rarest orchids in Britain.","img":"images/117.jpg","thumb":"images/t/117.jpg","file":"Cephalanthera rubra 02 Luxemburg.jpg","ar":0.666,"py":"","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/117.jpg","illus_thumb":"images/i/t/117.jpg","illus_file":"Illustration Cephalanthera rubra1.jpg","illus_ar":0.639,"illus_by":"Prof. Dr. Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":118,"seq":148,"zh":"Neotinea ustulata","en":"Neotinea ustulata","sci":"Neotinea ustulata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Neotinea ustulata (syn. Orchis ustulata), the burnt orchid or burnt-tip orchid, is a European terrestrial orchid native to mountains in central and southern Europe, growing at up to 2,400 m (7,900 ft) elevation.","img":"images/118.jpg","thumb":"images/t/118.jpg","file":"Orchis ustulata wiki mg-k02.jpg","ar":0.622,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":119,"seq":149,"zh":"Ophrys insectifera","en":"Ophrys insectifera","sci":"Ophrys insectifera","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":34,"desc_zh":null,"desc_en":"Ophrys insectifera, the fly orchid, is a species of orchid and the type species of the genus Ophrys. It is remarkable as an example of the use of sexually deceptive pollination and floral mimicry, as well as a highly selective and highly evolved plant–pollinat…","img":"images/119.jpg","thumb":"images/t/119.jpg","file":"Ophrys insectifera flower.jpg","ar":0.797,"py":"","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/119.jpg","illus_thumb":"images/i/t/119.jpg","illus_file":"Ophrys insectifera - Moggridge - Flora of Mentone pl. 45 (1871).jpg","illus_ar":0.585,"illus_by":"John Traherne Moggridge (1842-1874)","illus_lic":"Public domain","illus_licurl":null},{"id":120,"seq":150,"zh":"Orchis purpurea","en":"Orchis purpurea","sci":"Orchis purpurea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Orchis purpurea, the lady orchid, is a herbaceous plant belonging to the genus Orchis of the family Orchidaceae.","img":"images/120.jpg","thumb":"images/t/120.jpg","file":"Orchis purpurea6.jpg","ar":1.309,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/120.jpg","illus_thumb":"images/i/t/120.jpg","illus_file":"Illustration Orchis purpurea0.jpg","illus_ar":0.646,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":121,"seq":151,"zh":"南投斑叶兰","en":"Goodyera repens","sci":"Goodyera repens","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":33,"desc_zh":"南投斑叶兰（学名：Goodyera repens）为兰科斑叶兰属下的一个种。","desc_en":"Goodyera repens, a small forest orchid in the genus Goodyera. It is known by the common name creeping lady's-tresses in Anglophone Europe and dwarf rattlesnake plantain or lesser rattlesnake plantain in North America.","img":"images/121.jpg","thumb":"images/t/121.jpg","file":"Goodyera repens (habitus).jpg","ar":0.697,"py":"nantoubanyelan ntbyl","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲","北美洲"],"illus_img":"images/i/121.jpg","illus_thumb":"images/i/t/121.jpg","illus_file":"Goodyera repens — Flora Batava — Volume v17.jpg","illus_ar":0.782,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":122,"seq":152,"zh":"大花头蕊兰","en":"Cephalanthera damasonium","sci":"Cephalanthera damasonium","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":33,"desc_zh":"大花头蕊兰（学名：Cephalanthera damasonium）为兰科头蕊兰属下的一个种。","desc_en":"Cephalanthera damasonium, the white helleborine, is a species of orchid. It is widespread across much of Europe and Asia. Cephalanthera damasonium is the type species of the genus Cephalanthera.","img":"images/122.jpg","thumb":"images/t/122.jpg","file":"Cephalanthera damasonium 050606.jpg","ar":0.651,"py":"dahuatouruilan dhtrl","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/122.jpg","illus_thumb":"images/i/t/122.jpg","illus_file":"Cephalanthera damasonium Lindman DESC.JPG","illus_ar":1.456,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":146,"seq":153,"zh":"番红花","en":"Crocus sativus","sci":"Crocus sativus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":62,"desc_zh":"番红花（学名：Crocus sativus），也叫藏红花、西红花、彼岸花，古称郁金、郁金香、撒馥兰、撒䭱兰，鸢尾科番红花属的一种多年生草本植物。其干燥的雌蕊柱头为料理和医药中常用的番红花香料。 番红花广泛分布于地中海地区、北非、南欧、伊朗高原、阿拉伯半岛、青藏高原、蒙古高原和北美洲，植物在全球多地皆可繁盛生长，但因为其能利用的部份只有雌蕊的柱头部分，所以产量很低，商业化种植及采收需要耗费大量人力物力。","desc_en":"Crocus sativus, commonly known as saffron crocus or autumn crocus, is a species of flowering plant in the iris family Iridaceae. A cormous autumn-flowering cultivated perennial, unknown in the wild, it is best known for the culinary use of its floral stigmas a…","img":"images/146.jpg","thumb":"images/t/146.jpg","file":"Saffran crocus sativus moist.jpg","ar":0.75,"py":"fanhonghua fhh","cr_by":"HeiWu","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/146.jpg","illus_thumb":"images/i/t/146.jpg","illus_file":"Crocus sativus - Köhler–s Medizinal-Pflanzen-194.jpg","illus_ar":0.745,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":147,"seq":154,"zh":"黄菖蒲","en":"Iris pseudacorus","sci":"Iris pseudacorus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":"LC","langs":62,"desc_zh":"黄菖蒲（学名：Iris pseudacorus）是鸢尾科鸢尾属的植物。分布在欧洲以及中国等地，目前已由人工引种栽培。","desc_en":"Iris pseudacorus, the yellow flag, yellow iris, or water flag, is a species of flowering plant in the family Iridaceae. It is native to Europe, western Asia and northwest Africa.","img":"images/147.jpg","thumb":"images/t/147.jpg","file":"Iris pseudacorus 001.jpg","ar":1.333,"py":"huangchangpu hcp","cr_by":"Jean-Jacques MILAN","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/147.jpg","illus_thumb":"images/i/t/147.jpg","illus_file":"Iris pseudacorus — Flora Batava — Volume v5.jpg","illus_ar":0.738,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":148,"seq":155,"zh":"德国鸢尾","en":"Iris x germanica","sci":"Iris × germanica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":46,"desc_zh":"德国鸢尾（学名：Iris germanica）是鸢尾科鸢尾属的植物。分布于欧洲以及中国大陆的青岛、江苏、湖北等地，目前已由人工引种栽培。","desc_en":"Iris × germanica is the accepted name for a species of flowering plants in the family Iridaceae commonly known as the bearded iris or the German bearded iris. It is of hybrid origin. Varieties include I. × g. var. florentina.","img":"images/148.jpg","thumb":"images/t/148.jpg","file":"00 1238 Deutsche Schwertlilie (Iris × germanica).jpg","ar":0.667,"py":"deguoyuanwei dgyw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/148.jpg","illus_thumb":"images/i/t/148.jpg","illus_file":"Iris × germanica - Köhler–s Medizinal-Pflanzen-211.jpg","illus_ar":0.737,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":149,"seq":156,"zh":"春番红花","en":"Crocus vernus","sci":"Crocus vernus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":39,"desc_zh":"春番红花（学名：Crocus vernus）是鸢尾科番红花属多年生草本植物，原产阿尔卑斯山以及西巴尔干。","desc_en":"Crocus vernus (spring crocus, giant crocus) is a species of flowering plant in the family Iridaceae, native to the Alps, the Pyrenees, and the Balkans. Its cultivars and those of Crocus flavus (Dutch crocus) are used as ornamental plants.","img":"images/149.jpg","thumb":"images/t/149.jpg","file":"20140213Crocus tommasinianus2.jpg","ar":1.333,"py":"chunfanhonghua cfhh","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲"],"illus_img":"images/i/149.jpg","illus_thumb":"images/i/t/149.jpg","illus_file":"Crocus vernus Botanical Magazine 45.jpg","illus_ar":0.53,"illus_by":"Sydenham Edwards","illus_lic":"Public domain","illus_licurl":null},{"id":150,"seq":157,"zh":"西伯利亚鸢尾","en":"Iris sibirica","sci":"Iris sibirica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":38,"desc_zh":"西伯利亚鸢尾（学名：Iris sibirica）是鸢尾科鸢尾属的植物。其种加词“sibirica”意为“西伯利亚的”。分布于欧洲以及中国大陆的江苏、湖北、江西等地，目前已由人工引种栽培。","desc_en":"Iris sibirica, commonly known as Siberian iris or Siberian flag, is a species of flowering plant in the family Iridaceae. It is a rhizomatous herbaceous perennial, from Europe (including France, Italy, Switzerland, Austria, Czech Republic, Slovakia, Germany, H…","img":"images/150.jpg","thumb":"images/t/150.jpg","file":".00 3385 Sibirische Schwertlilie (Iris sibirica).jpg","ar":0.749,"py":"xiboliyayuanwei xblyyw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":151,"seq":158,"zh":"射干","en":"Iris domestica","sci":"Iris domestica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":29,"desc_zh":"射干（拼音：yè gān，注音：ㄧㄝˋ ㄍㄢ，学名：Iris domestica）为鸢尾科鸢尾属多年生草本植物。《本草经集注·草木下品》云：“此即是乌翣根，庭台多种之，黄色，亦治毒肿。方多作‘夜干’字，今‘射’亦作‘夜’音……又别有射干，相似而花白茎长，似射人之执竿者。”这里的“射人”为古代官名。《本草图经·草部下品之上卷第八》云：“今观射干之形，其茎梗疏长，正如长竿状，得名由此耳。","desc_en":"Iris domestica, commonly known as leopard lily, blackberry lily, and leopard flower, is an ornamental plant in the family Iridaceae. In 2005, based on molecular DNA sequence evidence, Belamcanda chinensis, the sole species in the genus Belamcanda, was transfer…","img":"images/151.jpg","thumb":"images/t/151.jpg","file":"Belamcanda chinensis 2007.jpg","ar":1.501,"py":"shegan sg","cr_by":"Tom Murphy VII","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null},{"id":152,"seq":159,"zh":"香根鸢尾","en":"Iris pallida","sci":"Iris pallida","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":28,"desc_zh":"香根鸢尾（学名：Iris pallida）是鸢尾科鸢尾属的植物。其种加词“pallida ”意为“淡色的”。分布于欧洲以及中国等地，目前已由人工引种栽培。 香根鸢尾的根称为鸢尾根，是西方草药学中的一种重要的草药，现在已成为香水的一种定香剂以及基本香型，也是很多金酒品牌的配料。 香根鸢尾是法国的国花。","desc_en":"Iris pallida, the Dalmatian iris or sweet iris, is a hardy flowering perennial plant of the genus Iris, family Iridaceae. It is native to the Dalmatian coast (Croatia) but widely naturalised elsewhere.","img":"images/152.jpg","thumb":"images/t/152.jpg","file":"Dettaglio - Iridaceae Iris pallida Link. Erbario Frizzi Perugia n. 2407.jpg","ar":0.589,"py":"xianggenyuanwei xgyw","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/152.jpg","illus_thumb":"images/i/t/152.jpg","illus_file":"Iris pallida - Köhler–s Medizinal-Pflanzen-079.jpg","illus_ar":0.734,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":156,"seq":160,"zh":"洋葱","en":"onion","sci":"Allium cepa","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":199,"desc_zh":"洋葱（学名：Allium cepa），又称圆葱、葱头、洋蒜，新疆地区又称皮芽子，是一种常见的石蒜科葱属植物。 洋葱在全世界广泛栽培，主要用途为食用，既可生食也可烹熟后食用，还可腌渍或制成调味品，多搭配咸味菜肴。生洋葱气味较为辛辣刺鼻，可能会刺激眼睛。 与洋葱同属的常见近缘物种包括大蒜、韭菜、葱、藠头等。红葱头属于洋葱的一个栽培型。","desc_en":"The onion (Allium cepa L.Tooltip Carl Linnaeus, from Latin cepa), also known as the bulb onion or common onion, is a vegetable that is the most widely cultivated species of the genus Allium.","img":"images/156.jpg","thumb":"images/t/156.jpg","file":"Allium cepa, Amol.jpg","ar":1.333,"py":"yangcong yc","cr_by":"Mehdi","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null,"illus_img":"images/i/156.jpg","illus_thumb":"images/i/t/156.jpg","illus_file":"Illustration Allium schoenoprasum and Allium cepa0 clean.jpg","illus_ar":0.638,"illus_by":"Prof. Dr. Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":157,"seq":161,"zh":"蒜","en":"Allium sativum","sci":"Allium sativum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":186,"desc_zh":"蒜（学名：Allium sativum）是石蒜科葱属的一种植物，亦名大蒜，因原产于中亚及西亚（即中国古代所称的西域），得古名「胡蒜」。蒜有两个自然亚种，人工培育的品种多达上百个。其地下鳞茎味道辛辣，有刺激性气味，称为蒜头，可作调味，亦可入药，为佛教中的五辛之一。蒜叶称为青蒜或蒜苗，花苔称为蒜薹，均可作菜蔬食用。 蒜在世界多地被人类食用、药用的历史长达数千年，栽培广泛，尤其在古埃及、地中海地区及亚洲多地有着深远的文化影响。","desc_en":"Garlic (Allium sativum) is a species of bulbous flowering plants in the genus Allium. Its close relatives include the onion, shallot, leek, chives, Welsh onion, and Chinese onion.","img":"images/157.jpg","thumb":"images/t/157.jpg","file":"Garlic bulbs and cloves.jpg","ar":1.501,"py":"suan s","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"]},{"id":158,"seq":162,"zh":"虾夷葱","en":"Allium schoenoprasum","sci":"Allium schoenoprasum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":"LC","langs":89,"desc_zh":"虾夷葱（学名：Allium schoenoprasum），又称细香葱、虾夷葱，是葱属植物的一员。其细长管状叶常同葱一样用为调味料，为常用辛香料，也可用作草药。虾夷葱和洋葱或大蒜相比气味较淡。其英文名称亦称为「chives」，而且一定会加s的复数形，原因是因为它们总是长成一丛而非单独生长。","desc_en":"Chives, scientific name Allium schoenoprasum, is a species of flowering plant in the family Amaryllidaceae. A perennial plant, A. schoenoprasum is widespread in nature across much of Eurasia and North America.","img":"images/158.jpg","thumb":"images/t/158.jpg","file":"Allium schoenoprasum 001.JPG","ar":1.333,"py":"xiayicong xyc","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null,"illus_img":"images/i/158.png","illus_thumb":"images/i/t/158.png","illus_file":"Allium schoenoprasum sibiricum drawing.png","illus_ar":0.797,"illus_by":"Britton, N.L., and A. Brown. 1913. Illustrated flora of the northern states and Canada. Vol. 1: 497. Courtesy of Kentuck","illus_lic":"Public domain","illus_licurl":null},{"id":159,"seq":163,"zh":"熊葱","en":"Allium ursinum","sci":"Allium ursinum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":86,"desc_zh":"熊葱（学名：Allium ursinum），又名野韭菜、熊果大蒜、熊蒜（bear's garlic）、野蒜菜及林地蒜，是石蒜科葱属的多年生草本植物，学名种加词意为“熊”，因欧洲民间故事中认为熊从冬眠中苏醒后会食用本种植物而得名。食用时味道如同韭菜，但气味相对并不强烈。多生长于林地树荫。春季刚发出的第一至第五叶味道鲜嫩，适于食用，开花后口感下降。","desc_en":"Allium ursinum, known as wild garlic, ramsons, cowleekes, cows's leek, cowleek, buckrams, broad-leaved garlic, wood garlic, bear leek, Eurasian wild garlic, onion grass, or bear's garlic, is a bulbous perennial flowering plant in the amaryllis family, Amarylli…","img":"images/159.jpg","thumb":"images/t/159.jpg","file":"Illustration Allium ursinum1.jpg","ar":0.689,"py":"xiongcong xc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"],"illus_img":"images/i/159.jpg","illus_thumb":"images/i/t/159.jpg","illus_file":"Allium ursinum Sturm36 - clean.jpg","illus_ar":0.667,"illus_by":"Jacob Sturm","illus_lic":"Public domain","illus_licurl":null},{"id":160,"seq":164,"zh":"火葱","en":"Allium ascalonicum","sci":"Allium ascalonicum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":73,"desc_zh":"火葱（学名：Allium cepa var. aggregatum），又名分葱、红葱头、四季葱、大头葱、珠葱、油葱、朱葱、绵葱、干葱。为石蒜科葱属的多年生草本鳞茎植物。鳞茎表面有紫红色薄膜，肉浅紫白色。原产于西亚，后传播到南亚、东南亚，在中国南方、北非及南欧皆有分布，多生于村边，目前已由人工引种广泛栽培，在亚洲各地广泛作为调味料用蔬菜。火葱原认为是自有的一个物种（Allium ascalonicum），但现已并入洋葱处置。","desc_en":"The shallot or is a cultivar group of the onion. Until 2010, the (French red) shallot was classified as a separate species, Allium ascalonicum. The taxon was synonymized with Allium cepa (the common onion) in 2010, as the difference was too small to justify a…","img":"images/160.jpg","thumb":"images/t/160.jpg","file":"Shallots - sliced and whole.jpg","ar":1.546,"py":"huocong hc","cr_by":"No machine-readable author provided. Charles P. assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":161,"seq":165,"zh":"葱","en":"Welsh onion","sci":"Allium fistulosum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":63,"desc_zh":"葱（学名：Allium fistulosum），别名青葱、大葱、叶葱、胡葱、冬葱、汉葱、木葱、葱仔、菜伯、水葱、和事草，为多年生草本植物。叶子圆筒形，中间空，脆弱易折，呈青色。在东亚国家以及各处亚裔地区中，葱常作为一种很普遍的香料调味品或蔬菜食用，在东方烹调中占有重要的角色。葱在佛教、道教被归类为为五辛之一，对修行有负面影响，因此佛教徒和道教徒禁止进食含有葱的食品。","desc_en":"Allium fistulosum, the Welsh onion, also commonly called bunching onion, long green onion, Japanese bunching onion, stone leek, rock onion and spring onion, is a species of perennial plant, often considered to be a kind of scallion.","img":"images/161.jpg","thumb":"images/t/161.jpg","file":"Allium fistulosum Ypey26.jpg","ar":0.552,"py":"cong c","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":162,"seq":166,"zh":"雪钟花","en":"Galanthus nivalis","sci":"Galanthus nivalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":"NT","langs":59,"desc_zh":"雪滴花（学名：Galanthus nivalis），是雪花莲属是二十个物种中最著名且分布最广的。雪滴花是春季最早开花的鳞茎，可以在自然的区域形成美丽的白色地毯。较容易与雪片莲属和秋雪片莲属混淆。","desc_en":"Galanthus nivalis, the snowdrop or common snowdrop, is the best-known and most widespread of the 20 species in its genus, Galanthus. Snowdrops are among the first bulbs to bloom in spring and can form impressive carpets of white in areas where they are native…","img":"images/162.jpg","thumb":"images/t/162.jpg","file":"Snowdrops in Lothersdale Churchyard.jpg","ar":1.499,"py":"xuezhonghua xzh","cr_by":"Tim Green","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":null,"illus_img":"images/i/162.png","illus_thumb":"images/i/t/162.png","illus_file":"Galanthus nivalis drawing.png","illus_ar":0.33,"illus_by":"Dwergenpaartje","illus_lic":"CC BY-SA 3.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/3.0"},{"id":163,"seq":167,"zh":"喇叭水仙","en":"Narcissus pseudonarcissus","sci":"Narcissus pseudonarcissus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":47,"desc_zh":"黄水仙（学名：Narcissus pseudonarcissus），又名洋水仙、喇叭水仙，是石蒜科水仙属的植物。分布在欧洲等地，目前已由人工引种栽培。多年生草本，鳞茎最大者长0.45米，宽0.1米，花瓣淡黄色，中心副冠是深黄色的喇叭形，边缘不规则褶皱，叶绿色，略带灰色，基生，宽线形，先端钝，顶生1花，花期3－4月。","desc_en":"Narcissus pseudonarcissus, commonly named the wild daffodil or Lent lily (Welsh: Cennin Pedr), is a perennial flowering plant. This species has pale yellow tepals, with a darker central trumpet.","img":"images/163.jpg","thumb":"images/t/163.jpg","file":"- Narcissus pseudonarcissus 03 -.jpg","ar":1.501,"py":"labashuixian lbsx","cr_by":"User:Nino Barbieri","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":null},{"id":167,"seq":168,"zh":"芦笋","en":"Asparagus officinalis","sci":"Asparagus officinalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":112,"desc_zh":"芦笋（学名：Asparagus officinalis）又名石刁柏，为天门冬科天门冬属 多年生开花草本植物。像它的表兄弟韭、葱、蒜，它一度被归入百合科。 芦笋原产于欧洲大部分地区，以及北非和西亚，是被广泛种植的蔬菜作物。绿芦笋和白芦笋只是有无照到阳光的区别。","desc_en":"Asparagus (Asparagus officinalis) or garden asparagus is a perennial flowering plant species in the genus Asparagus native to Eurasia. Widely cultivated as a vegetable crop, its young shoots are used as a spring vegetable.","img":"images/167.jpg","thumb":"images/t/167.jpg","file":"Asparagus plants - geograph.org.uk - 552470.jpg","ar":0.75,"py":"lusun ls","cr_by":"Evelyn Simak","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/167.jpg","illus_thumb":"images/i/t/167.jpg","illus_file":"Asparagus officinalis - Prof. Dr. Thome Flora von Deutschland (Pl. 131).jpg","illus_ar":0.678,"illus_by":"Migula, Walter; Thomé, Otto W.","illus_lic":"Public domain","illus_licurl":null},{"id":168,"seq":169,"zh":"铃兰","en":"Convallaria majalis","sci":"Convallaria majalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":98,"desc_zh":"铃兰（学名：Convallaria majalis，英语：Lily of the Valley，法语：Muguet de mai），也称山谷百合、风铃草、君影草，是铃兰属中的唯一种，味甜，高毒性。原产北半球温带，欧、亚及北美洲和中国的东北、华北地区海拔850-2,500处均有野生分布。经典法语歌曲《le temps du muguet》即是指铃兰花。","desc_en":"Lily-of-the-valley (Convallaria majalis), also written as lily of the valley, is a woodland flowering plant with sweetly scented, pendent, bell-shaped white flowers borne in sprays in spring. It is native to Europe, Western Asia and Northern Asia.","img":"images/168.jpg","thumb":"images/t/168.jpg","file":"Convallaria majalis inflorescence - Keila.jpg","ar":0.667,"py":"linglan ll","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/168.jpg","illus_thumb":"images/i/t/168.jpg","illus_file":"Convallaria majalis - Köhler–s Medizinal-Pflanzen-045.jpg","illus_ar":0.769,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":169,"seq":170,"zh":"剑麻","en":"sisal","sci":"Agave sisalana","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":66,"desc_zh":"剑麻（学名：Agave sisalana）又名菠萝麻、琼麻、衿麻，是天门冬科龙舌兰亚科龙舌兰属的一种纤维作物，原产墨西哥南部。1901年由美国领事达文生自夏威夷间接引进至台湾。剑麻常与同亚科的凤尾兰（学名：Yucca gloriosa）混淆。","desc_en":"Sisal (, Spanish: [siˈsal]; Agave sisalana) is a species of flowering plant native to southern Mexico, but widely cultivated and naturalized in many other countries. It yields a stiff leaf fiber used in making rope and various other products.","img":"images/169.jpg","thumb":"images/t/169.jpg","file":"Plantsisal.jpg","ar":0.8,"py":"jianma jm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":170,"seq":171,"zh":"龙舌兰","en":"Agave americana","sci":"Agave americana","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":54,"desc_zh":"龙舌兰（学名：Agave americana）是一种天门冬科龙舌兰亚科龙舌兰属植物，其鳞根的汁液可以提炼成龙舌兰糖浆并酿制成普逵酒的，但另一种龙舌兰酒特基拉酒（Tequila）所采用的的是龙舌兰属中另外一个种蓝色龙舌兰作为原料，而并非由本种制作而成。","desc_en":"Agave americana, commonly known as the century plant, maguey, or American aloe, is a flowering plant species belonging to the family Asparagaceae. It is native to Mexico and the United States, specifically Texas.","img":"images/170.jpg","thumb":"images/t/170.jpg","file":"14 November 2016, Century plant or Maguey (Agave Americana), Mosqueira.JPG","ar":0.75,"py":"longshelan lsl","cr_by":"Kolforn ( Kolforn ) I'd appreciate if you could mail me (Kolforn@gmail.com) if you want to use this picture out of the W","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"],"illus_img":"images/i/170.jpg","illus_thumb":"images/i/t/170.jpg","illus_file":"Agave americana - Revue horticole - 1862 - vol. 34.jpg","illus_ar":0.635,"illus_by":"J. A. Barral","illus_lic":"Public domain","illus_licurl":null},{"id":171,"seq":172,"zh":"晚香玉","en":"Agave amica","sci":"Agave amica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":53,"desc_zh":"晚香玉（学名：Polianthes tuberosa），别名月下香，是天门冬科（龙舌兰亚科）晚香玉属的一种多年生球根开花植物。 多年生草本，根状茎块状；线形叶子丛生，先端尖；花茎较长，上部呈总状花序，夏秋开白色花，有浓香味，晚上香味更浓。 晚香玉花在晚上开花，在印度东部地区，被人们称作“Ratkirani”，意思就是“夜晚的女王”。","desc_en":"Polianthes tuberosa, the tuberose, is a perennial plant in the family Asparagaceae, subfamily Agavoideae, extracts of which are used as a note in perfumery. Now widely grown as an ornamental plant, the species is native to Mexico.","img":"images/171.jpg","thumb":"images/t/171.jpg","file":"Polianthes tuberosa, Burdwan, West Bengal, India 25 10 2012.jpg","ar":0.722,"py":"wanxiangyu wxy","cr_by":"JDP90 (Joydeep)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["北美洲"]},{"id":172,"seq":173,"zh":"海葱","en":"Drimia maritima","sci":"Drimia maritima","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":43,"desc_zh":"海葱(Urginea maritima)是天门冬科绵枣儿亚科的多年生鳞茎植物。","desc_en":"Drimia maritima (syn. Urginea maritima) is a species of flowering plant in the family Asparagaceae, subfamily Scilloideae (formerly the family Hyacinthaceae).","img":"images/172.jpg","thumb":"images/t/172.jpg","file":"Drimia maritima - Köhler–s Medizinal-Pflanzen-277.jpg","ar":0.747,"py":"haicong hc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/172.jpg","illus_thumb":"images/i/t/172.jpg","illus_file":"Drimia maritima - Köhler–s Medizinal-Pflanzen-277.jpg","illus_ar":0.747,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":173,"seq":174,"zh":"风信子","en":"Hyacinthus orientalis","sci":"Hyacinthus orientalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":38,"desc_zh":"风信子（学名：Hyacinthus orientalis）是天门冬科风信子属的植物。其种加词“orientalis”意为“东方的”。原产于亚洲西南部、土耳其南部和中部、叙利亚西北部、黎巴嫩和以色列北部，在16世纪引种到欧洲。","desc_en":"Hyacinthus orientalis, the common hyacinth, garden hyacinth or Dutch hyacinth, is a species of flowering plant in the family Asparagaceae, subfamily Scilloideae. It is native to western Asia, from southern Turkey, through Syria and Lebanon to northern Israel.","img":"images/173.jpg","thumb":"images/t/173.jpg","file":"Hyacinth bloem.jpg","ar":0.744,"py":"fengxinzi fxz","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"],"illus_img":"images/i/173.jpg","illus_thumb":"images/i/t/173.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 48 Hyacinthus orientalis (6022342730).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":174,"seq":175,"zh":"蓝铃花","en":"Hyacinthoides non-scripta","sci":"Hyacinthoides non-scripta","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":38,"desc_zh":"蓝铃花（Hyacinthoides non-scripta）是一种鳞茎状的多年生植物，它主要分布在西班牙西北部至英伦三岛的大西洋地区。蓝铃花最早由卡尔·林奈在其1753年的著作《植物种志》中描述。","desc_en":"Hyacinthoides non-scripta (formerly Endymion non-scriptus or Scilla non-scripta) is a bulbous perennial plant found in Atlantic areas from the north-western part of the Iberian Peninsula to the British Isles, and also frequently used as a garden plant.","img":"images/174.jpg","thumb":"images/t/174.jpg","file":"Jacinthes des bois (Hyacinthoides non-scripta).jpg","ar":0.667,"py":"lanlinghua llh","cr_by":"JackyM59","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/174.jpg","illus_thumb":"images/i/t/174.jpg","illus_file":"Hyacinthoides non-scripta Sturm39.jpg","illus_ar":0.675,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":180,"seq":176,"zh":"库拉索芦荟","en":"Aloe vera","sci":"Aloe vera","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":100,"desc_zh":"芦荟（学名：Aloe vera），又名真芦荟、翠叶芦荟、库拉索芦荟或美国芦荟，是芦荟属下的一种多肉植物。芦荟属广泛分布于全世界的热带及亚热带，包含高海拔、海岸、沙漠、草原等地区。能于花圃或盆栽内种植。尽管芦荟的妆用及药用价值存在争议，但仍出现于许多消费产品。 芦荟为无茎或短茎多肉植物，株高约60-100公分，但根据品种的不同还是有蛮大的差距，像是高芦荟、非洲芦荟等等会高达20米，有的则较短小只有10厘米，像是珍珠芦荟。","desc_en":"Aloe vera () is a succulent plant species of the genus Aloe. It is widely distributed, and is considered an invasive species in many world regions. An evergreen perennial, it originates from the Arabian Peninsula, but also grows wild in tropical, semi-tropical…","img":"images/180.jpg","thumb":"images/t/180.jpg","file":"Starr 011104-0040 Aloe vera.jpg","ar":0.75,"py":"kulasuoluhui klslh","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"多肉","origin":["亚洲"],"illus_img":"images/i/180.jpg","illus_thumb":"images/i/t/180.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 15 Aloe vera, Aloe succotrina (6022329218).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":181,"seq":177,"zh":"树丛芦荟","en":"Aloe arborescens","sci":"Aloe arborescens","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":"LC","langs":42,"desc_zh":"树丛芦荟（学名：Aloe arborescens）是阿福花科芦荟属的一种常绿灌木，原产非洲南部的博茨瓦纳、南非、马拉维、莫桑比克、斯威士兰、津巴布韦。也叫大芦荟，日语称木立芦荟（木立アロエ；“木立”在日语中是树丛的意思）。种加词的意思是像树一样。","desc_en":"Aloe arborescens, commonly known as krantz aloe or the candelabra aloe, is a species of flowering succulent perennial plant that belongs to the genus Aloe, which it shares with the well known and studied Aloe vera.","img":"images/181.jpg","thumb":"images/t/181.jpg","file":"Aloe arborescens - Candelabra aloe 01.jpg","ar":1.501,"py":"shucongluhui sclh","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":null},{"id":182,"seq":178,"zh":"萱草","en":"Hemerocallis fulva","sci":"Hemerocallis fulva","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":34,"desc_zh":"萱草（学名：Hemerocallis fulva）是阿福花科萱草属植物，旧的克朗奎斯特分类法中属于百合科（Liliaceae）。另有黄花萱草、忘忧草、橙萱、紫萱、宜男草、疗愁、鹿箭、黄花菜、金针菜等名。原产于中国、西伯利亚、日本和东南亚，台湾于1661年由华南引入。为中国传统的母亲花，常以萱堂代称母亲，与椿庭相对，古称谖草。","desc_en":"Hemerocallis fulva, the orange day-lily, tawny daylily, corn lily, tiger daylily, fulvous daylily, ditch lily or Fourth of July lily (also railroad daylily, roadside daylily, outhouse lily, track lily, and wash-house lily), is a species of daylily native to As…","img":"images/182.jpg","thumb":"images/t/182.jpg","file":"00 6322 Hemerocallis fulva - Gelbroten Taglilie.jpg","ar":1.501,"py":"xuancao xc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"],"illus_img":"images/i/182.jpg","illus_thumb":"images/i/t/182.jpg","illus_file":"Hemerocallis fulva Les liliacees vol. 1 t. 16.jpg","illus_ar":0.674,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":183,"seq":179,"zh":"二歧芦荟","en":"Aloe dichotoma","sci":"Aloe dichotoma","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":31,"desc_zh":"二歧树芦荟（学名：Aloidendron dichotomum）前称二歧芦荟（Aloe dichotoma），是南部非洲特有的一种芦荟，尤其是在南非北开普省及纳米比亚。在尼湖德维（Nieuwoudtville）至洛来斯芳坦（Loeriesfontein）的路上就有一片二歧树芦荟的森林。当地原住的布希曼人会将二歧树芦荟的树干挖空，制成箭筒，故又名箭筒芦荟或箭袋树。","desc_en":"Aloidendron dichotomum, formerly Aloe dichotoma, the quiver tree or kokerboom, is a tall, branching species of succulent plant, indigenous to Southern Africa, specifically in the Northern Cape province of South Africa, and parts of Southern Namibia.","img":"images/183.jpg","thumb":"images/t/183.jpg","file":"Aloe dichotoma -Keetmanshoop, Namibia-21Aug2009-2.jpg","ar":0.75,"py":"erqiluhui eqlh","cr_by":"Le Grand Portage , derivative work: Fletcher6 ( talk )","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"多肉","origin":["非洲"]},{"id":184,"seq":180,"zh":"新西兰麻","en":"Phormium tenax","sci":"Phormium tenax","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Phormium tenax (called flax in New Zealand English; harakeke in Māori; New Zealand flax outside New Zealand; and New Zealand hemp in historical nautical contexts) is an evergreen perennial plant native to New Zealand and Norfolk Island that is an important fib…","img":"images/184.jpg","thumb":"images/t/184.jpg","file":"Phormium tenax Piha02.jpg","ar":0.674,"py":"xinxilanma xxlm","cr_by":"Kahuroa","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["大洋洲"]},{"id":185,"seq":181,"zh":"好望角芦荟","en":"Aloe ferox","sci":"Aloe ferox","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Aloe ferox, commonly known as bitter aloe, is a species of flowering plant in the family Asphodelaceae. This woody aloe is indigenous to southern Africa. It is one of several Aloe species used to make bitter aloes, a purgative medication, and also yields a non…","img":"images/185.jpg","thumb":"images/t/185.jpg","file":"Aloe Ferox between Cofimvaba and Ngcobo.jpg","ar":0.75,"py":"haowangjiaoluhui hwjlh","cr_by":"Gregorydavid","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["非洲"]},{"id":187,"seq":182,"zh":"天蓝百合","en":"Pasithea caerulea","sci":"Pasithea caerulea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Xanthorrhoeaceae","family_zh":"黄脂木科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Pasithea caerulea is a species of herb in the family Asphodelaceae. It is native to Peru and Chile in South America and is the only species in the monotypic genus Pasithea. P.","img":"images/187.jpg","thumb":"images/t/187.jpg","file":"Bluette (3436174277).jpg","ar":1,"py":"tianlanbaihe tlbh","cr_by":"Jason Hollinger","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["南美洲"]},{"id":1049,"seq":183,"zh":"Astelia alpina","en":"Astelia alpina","sci":"Astelia alpina","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asteliaceae","family_zh":"芳香草科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Astelia alpina called pineapple grass, silver astelia, or perching lily is a commonly found species in alpine and subalpine areas of Tasmania and the Australian Alps.","img":"images/1049.jpg","thumb":"images/t/1049.jpg","file":"Astelia alpina - Pineapple Grass.jpg","ar":1.332,"py":"","cr_by":"Ljgua124","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"禾草","origin":["大洋洲"]},{"id":1050,"seq":184,"zh":"Astelia waialealae","en":"Astelia waialealae","sci":"Astelia waialealae","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asteliaceae","family_zh":"芳香草科","iucn":"CR","langs":9,"desc_zh":null,"desc_en":"Astelia waialealae is a rare species of plant in the Asteliaceae family that is endemic to the island of Kauaʻi in Hawaii, United States. It inhabits montane bogs within the vicinity of the Alakaʻi Swamp on the island's central plateau. A.","img":"images/1050.jpg","thumb":"images/t/1050.jpg","file":"Astelia waialealae.jpg","ar":1.532,"py":"","cr_by":"Unknown author Unknown author","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":1051,"seq":185,"zh":"Borya sphaerocephala","en":"Borya sphaerocephala","sci":"Borya sphaerocephala","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Boryaceae","family_zh":"澳韭兰科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Borya sphaerocephala is a perennial herbaceous plant found in southwest Australia. A common name for the species is pincushions. The height is 20–200 millimetres, White flowers appear between August and October.","img":"images/1051.jpg","thumb":"images/t/1051.jpg","file":"Borya sphaerocephala - Flickr - Kevin Thiele.jpg","ar":1.335,"py":"","cr_by":"Kevin Thiele from Perth, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["大洋洲"]},{"id":1052,"seq":186,"zh":"高大矛花","en":"Doryanthes excelsa","sci":"Doryanthes excelsa","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Doryanthaceae","family_zh":"矛花科","iucn":null,"langs":13,"desc_zh":null,"desc_en":"Doryanthes excelsa, commonly known as the gymea lily, is a flowering plant in the family Doryanthaceae that is endemic to coastal areas of New South Wales near Sydney.","img":"images/1052.jpg","thumb":"images/t/1052.jpg","file":"GymeaLily1.jpg","ar":0.534,"py":"gaodamaohua gdmh","cr_by":null,"cr_lic":"CC SA 1.0","cr_licurl":"http://creativecommons.org/licenses/sa/1.0/","habit":null,"origin":null,"illus_img":"images/i/1052.jpg","illus_thumb":"images/i/t/1052.jpg","illus_file":"Doryanthes-excelsa Fitch.jpg","illus_ar":0.667,"illus_by":"Walter Hood Fitch","illus_lic":"Public domain","illus_licurl":null},{"id":1053,"seq":187,"zh":"地中海绵枣儿","en":"Portuguese Squill","sci":"Scilla peruviana","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Hyacinthaceae","family_zh":"风信子科","iucn":null,"langs":19,"desc_zh":"地中海绵枣儿（学名：Scilla peruviana）又名地中海蓝钟花、地金球、野风信子、葡萄牙绵枣儿，是绵枣儿属的一种植物，原产于西地中海地区的伊比利亚半岛、义大利及非洲西北部。也有人根据学名peruviana（秘鲁的），将本种的名称翻译为秘鲁绵枣儿，不过秘鲁并不是本种的原产地，这里所说的秘鲁和南美洲国家秘鲁并没有关系，而是指一艘名为秘鲁（Peru）的船舶，1753年林奈在描述本种性状时所用的标本，就是由这艘船从西班牙运来的。","desc_en":"Scilla peruviana (synonyms including Oncostema peruvianum), the Cuban lily, Peruvian hyacinth or Portuguese squill, is a species of Scilla native to the western Mediterranean region in Iberia, Italy, and northwest Africa.","img":"images/1053.jpg","thumb":"images/t/1053.jpg","file":"Scilla peruviana.jpg","ar":1.354,"py":"dizhonghaimianzaoer dzhmze","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲","非洲"]},{"id":1054,"seq":188,"zh":"仙茅","en":"Curculigo orchioides","sci":"Curculigo orchioides","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Hypoxidaceae","family_zh":"仙茅科","iucn":null,"langs":17,"desc_zh":"仙茅（学名：Curculigo orchioides），又名地棕根、地棕、独茅根、独茅、独脚仙茅、山党参、仙茅参、海南参、婆罗门参、芽瓜子，为石蒜科仙茅属多年生草本植物。分布于印度尼西亚、日本、东南亚、台湾岛以及中国大陆的广西、广东、贵州、福建、云南、浙江、四川、湖南、江西等地，生长于海拔500米至1,600米的地区，一般生长在草地、林中或荒坡上，属中国原产的植物（非从国外引种）。","desc_en":"Curculigo orchioides (commonly called golden eye-grass, xian mao, weevil-wort, कालो मुस्ली (in Nepal) black musli, Kali musli, or Kali Musali) is a flowering plant species in the genus Curculigo.","img":"images/1054.jpg","thumb":"images/t/1054.jpg","file":"Curculigo orchioides.jpg","ar":1.333,"py":"xianmao xm","cr_by":"Viren Vaz (self)","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"禾草","origin":["亚洲"]},{"id":1055,"seq":189,"zh":"Hypoxis hemerocallidea","en":"Hypoxis hemerocallidea","sci":"Hypoxis hemerocallidea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Hypoxidaceae","family_zh":"仙茅科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Hypoxis hemerocallidea, the African star grass or African potato, is a medicinal plant in the Hypoxidaceae family. It is native to southern Africa from South Africa as far north as Mozambique and Zimbabwe. This plant is the best known member of this genus.","img":"images/1055.jpg","thumb":"images/t/1055.jpg","file":"Hypoxis hemerocallidea 5Dsr 1560.jpg","ar":0.667,"py":"","cr_by":"SAplants","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["非洲"]},{"id":1056,"seq":190,"zh":"鸢尾蒜","en":"Ixiolirion tataricum","sci":"Ixiolirion tataricum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Ixioliriaceae","family_zh":"鸢尾蒜科","iucn":null,"langs":19,"desc_zh":"鸢尾蒜（学名：Ixiolirion tataricum），为鸢尾蒜科鸢尾蒜属下的一个种。","desc_en":"Ixiolirion tataricum, commonly known as the Siberian lily or the lavender mountain lily, is native to central and southwest Asia from the Sinai Peninsula to Xinjiang Province of China. Flower color ranges from light blue to dark violet.","img":"images/1056.jpg","thumb":"images/t/1056.jpg","file":"Ixiolirion tataricum - Kudaibergen Amirekul - 266178405.jpeg","ar":1,"py":"yuanweisuan yws","cr_by":"Kudaibergen Amirekul","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":1057,"seq":191,"zh":"毛石蒜科","en":"Lanaria lanata","sci":"Lanaria lanata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Lanariaceae","family_zh":"毛石蒜科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Lanaria is a monotypic genus of flowering plants containing a single species, Lanaria lanata, endemic to the southern coast of South Africa where it is associated with the fynbos belt. Lanaria lanata is commonly known as Cape edelweiss or lambtails.","img":"images/1057.jpg","thumb":"images/t/1057.jpg","file":"Lanaria lanata01.jpg","ar":1.333,"py":"maoshisuanke mssk","cr_by":"Paul venter","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"]},{"id":1058,"seq":192,"zh":"Acanthocarpus preissii","en":"Acanthocarpus preissii","sci":"Acanthocarpus preissii","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Laxmanniaceae","family_zh":"异蕊草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Acanthocarpus preissii is a rhizomatous perennial flowering plant in the family Asparagaceae. It occurs on coastal dunes in Western Australia. White flowers appear between April and May in the species' native range.","img":"images/1058.jpg","thumb":"images/t/1058.jpg","file":"Acanthocarpus preissii.jpg","ar":1.334,"py":"","cr_by":"Ilena","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"草本","origin":["大洋洲"]},{"id":1059,"seq":193,"zh":"美堇莲","en":"Cyanella hyacinthoides","sci":"Cyanella hyacinthoides","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Tecophilaeaceae","family_zh":"蓝星科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Cyanella hyacinthoides (\"lady's hand\" or \"Raaptoluintjie\") is a species of cormous annual or perennial herb native to the western parts of South Africa.","img":"images/1059.jpg","thumb":"images/t/1059.jpg","file":"Cyanella hyacinthoides 1DS-II 1-C3411.jpg","ar":0.667,"py":"meijinlian mjl","cr_by":"SAplants","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["非洲"]},{"id":1060,"seq":194,"zh":"喉齿莲","en":"Odontostomum hartwegii","sci":"Odontostomum hartwegii","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Tecophilaeaceae","family_zh":"蓝星科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Odontostomum is a monotypic genus of flowering plants containing the single species Odontostomum hartwegii, which is known by the common name Hartweg's doll's-lily. In the APG III classification system, it is placed in the family Tecophilaeaceae.","img":"images/1060.jpg","thumb":"images/t/1060.jpg","file":"Odontostomum hartwegii.jpg","ar":0.667,"py":"houchilian hcl","cr_by":"Eric in SF","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"]},{"id":1061,"seq":195,"zh":"Xeronema callistemon","en":"Xeronema callistemon","sci":"Xeronema callistemon","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Xeronemataceae","family_zh":"血剑草科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Xeronema callistemon is a species of flowering plant endemic to the Poor Knights Islands and Taranga Island in the north of New Zealand. It was discovered in 1924 and is also called raupōtaranga (te reo Māori) or Poor Knights lily.","img":"images/1061.jpg","thumb":"images/t/1061.jpg","file":"Xeronema MRD Otari.jpg","ar":0.775,"py":"","cr_by":"Mike Dickison","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["大洋洲"]},{"id":188,"seq":196,"zh":"椰子","en":"Cocos nucifera","sci":"Cocos nucifera","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":155,"desc_zh":"椰（学名：Cocos nucifera），又名椰瓢或可可椰子，是棕榈科椰属的唯一物种。椰子是椰子树的果实，常见于热带地区。椰子树分布广泛的原因之一，是其果实可以在海中随风浪漂流上千公里后在离母树非常远的地方落地生根。一般商业售卖的椰子在收割时仍是绿色的未成熟果实，略呈三角形状，大小接近足球。在泰国南部人们会利用训练过的猕猴来采摘椰子。 一般在原产地以外出售的“椰子”实际上是椰子棕色的核，也叫作「椰仁」，是椰子的种子。","desc_en":"The coconut (Cocos nucifera) is a member of the palm family (Arecaceae) and the only living species of the genus Cocos. The term \"coconut\" (or the archaic \"cocoanut\") can denote the whole coconut palm tree or the large hard fruit.","img":"images/188.jpg","thumb":"images/t/188.jpg","file":"1859-Martinique.web.jpg","ar":0.657,"py":"yezi yz","cr_by":"Patrick Verdier, Free On Line Photos","cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"棕榈","origin":["亚洲"],"illus_img":"images/i/188.jpg","illus_thumb":"images/i/t/188.jpg","illus_file":"Cocos nucifera - Köhler–s Medizinal-Pflanzen-187.jpg","illus_ar":0.668,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":189,"seq":197,"zh":"椰枣","en":"Phoenix dactylifera","sci":"Phoenix dactylifera","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":127,"desc_zh":"椰枣（学名：Phoenix dactylifera），又称枣椰树、海枣、棕栆、波斯枣、伊拉克蜜枣、无漏子、番枣、海棕、仙枣，为棕榈科刺葵属的植物。枣椰树具有耐旱、耐碱、耐热而又喜欢潮湿的特点。 果实产量高，是西亚一些国家的重要出口农作物。枣椰树在阿拉伯神话和伊斯兰教中具有重要地位，沙乌地阿拉伯国徽的上方就是枣椰树。另基督教中之棕树节及犹太教中之住棚节亦与枣椰树有关，可视为中东宗教传统的一大特色。","desc_en":"Phoenix dactylifera, commonly known as the date palm, is a flowering-plant species in the palm family Arecaceae, native to the region from the Gulf States to India. It is cultivated for its edible sweet fruit called dates.","img":"images/189.jpg","thumb":"images/t/189.jpg","file":"Phoenix dactylifera - EJ Burns - 606494286.jpeg","ar":0.75,"py":"yezao yz","cr_by":"EJ Burns","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"棕榈","origin":["亚洲"]},{"id":190,"seq":198,"zh":"槟榔","en":"Areca catechu","sci":"Areca catechu","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":80,"desc_zh":"槟榔（bīng·láng）（学名：Areca catechu）一词可指其植株或嫩果，别名碌树、宾门、螺果、仁频、仁榔、洗瘴丹、仙瘴丹、榔子、台湾口香糖等；闽南语“菁仔”是指未加工的槟榔嫩果。槟榔与椰子同属棕榈科常绿乔木，主干可长至二十米高。“槟榔”一词源于马来语“pinang”。槟榔原产于马来西亚联邦，分布区域涵盖亚洲的斯里兰卡、泰国、印度、非洲东部及大洋洲等热带地区。国际癌症研究机构认定槟榔是第一类致癌物。","desc_en":"Areca catechu is a species of palm native to the Philippines cultivated for areca nuts. It was carried widely through the tropics by the Austronesian migrations and trade since at least 1500 BCE due to its use in betel nut chewing.","img":"images/190.jpg","thumb":"images/t/190.jpg","file":"Beetle palm with nut bunch.jpg","ar":0.958,"py":"binlang bl","cr_by":"Pratheepps","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"棕榈","origin":["亚洲"],"illus_img":"images/i/190.jpg","illus_thumb":"images/i/t/190.jpg","illus_file":"Areca catechu - Köhler–s Medizinal-Pflanzen-014.jpg","illus_ar":0.753,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":191,"seq":199,"zh":"油棕","en":"Elaeis guineensis","sci":"Elaeis guineensis","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":57,"desc_zh":"油棕（学名：Elaeis guineensis）又名非洲油棕、油棕榈、油椰子，是棕榈科油棕属的一种植物，其种加词“guineensis”意为“几内亚的”。原产于非洲热带雨林，从西非、中非至东非，分布范围西自塞内加尔，东抵肯尼亚，南起安哥拉，北至乍得，被引入至马来西亚和印度尼西亚、中美洲及南美洲等地区；属于产油经济作物，主要用于生产棕榈油（果肉榨取）及棕仁油（核仁榨取）。","desc_en":"Elaeis guineensis is a species of palm commonly called oil palm but also sometimes African oil palm or macaw-fat. The first Western person to describe it and bring back seeds was the French naturalist Michel Adanson.","img":"images/191.jpg","thumb":"images/t/191.jpg","file":"De la graine de palme.jpg","ar":1.333,"py":"youzong yz","cr_by":"BeraDigle","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"棕榈","origin":["非洲"],"illus_img":"images/i/191.jpg","illus_thumb":"images/i/t/191.jpg","illus_file":"Elaeis guineensis - Köhler–s Medizinal-Pflanzen-056.jpg","illus_ar":0.701,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":192,"seq":200,"zh":"巴西苺","en":"Euterpe oleracea","sci":"Euterpe oleracea","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":55,"desc_zh":"阿萨伊棕榈（英语：acai palm）或千叶菜棕（学名：Euterpe oleracea）是一种原产于巴西亚马逊地区的棕榈树（棕榈科菜椰属），因其果实（阿萨伊果）、棕榈心（作为蔬菜）、叶子和树干木材而被人种植。该物种原产于亚马逊东部，尤其是巴西，主要分布在沼泽和洪泛平原，树干高大细长，可达25米（82英尺）高，羽状叶可长达3米（9.8英尺）。 阿萨伊果（acai berry，acai）又称巴西莓，外表类似蓝莓，可以食用。","desc_en":"The açaí palm ( ə-SY-ee, Brazilian Portuguese: [asaˈi] ; from Nheengatu asai), Euterpe oleracea, is a species of palm tree (Arecaceae) cultivated for its fruit (açaí berries, or simply açaí), hearts of palm (a vegetable), leaves, and trunk wood.","img":"images/192.jpg","thumb":"images/t/192.jpg","file":"Euterpe oleracea salu.jpg","ar":1.333,"py":"baximei bxm","cr_by":"Vihelik","cr_lic":"Public domain","cr_licurl":null,"habit":"棕榈","origin":["南美洲"]},{"id":193,"seq":201,"zh":"糖棕","en":"Borassus flabellifer","sci":"Borassus flabellifer","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":55,"desc_zh":"糖棕又名扇椰子（学名：Borassus flabellifer）为棕榈科糖棕属下的一个种。","desc_en":"Borassus flabellifer, commonly known as doub palm, palmyra palm, tala, tal palm, toddy palm, lontar palm, wine palm, or ice apple, is a fan palm native to South Asia (especially in Bangladesh, East India, and South India) and Southeast Asia.","img":"images/193.jpg","thumb":"images/t/193.jpg","file":"Borassus flabellifer.jpg","ar":0.667,"py":"tangzong tz","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"棕榈","origin":["亚洲"],"illus_img":"images/i/193.png","illus_thumb":"images/i/t/193.png","illus_file":"Borassus flabellifer Illustration ஐ.png","illus_ar":1.264,"illus_by":"KarunyaBaskar","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":194,"seq":202,"zh":"加拿利海枣","en":"Lá palama aceitosa","sci":"Phoenix canariensis","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":52,"desc_zh":"加拿利海枣（学名：Phoenix canariensis）又名长叶刺葵、加拿利枣椰，是一种多年生的棕榈科刺葵属常绿乔木。原产于非洲西海岸的加那利群岛。","desc_en":"Phoenix canariensis, the Canary Island date palm, is a species of flowering plant in the palm family Arecaceae, native to the Canary Islands off the coast of Northwestern Africa. It is a relative of Phoenix dactylifera, the true date palm.","img":"images/194.jpg","thumb":"images/t/194.jpg","file":"Phoenix canariensis kz01.jpg","ar":0.726,"py":"jianalihaizao jnlhz","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"棕榈","origin":["非洲"]},{"id":195,"seq":203,"zh":"蛇皮果","en":"Salacca zalacca","sci":"Salacca zalacca","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":48,"desc_zh":"蛇皮果（学名：Salacca zalacca）是东南亚地区的水果，属于棕榈科蛇皮果属，原产于印尼的爪哇岛及苏门答腊岛，也有在其他地方种植作食用，包括有：巴厘岛、龙目岛、帝汶岛、马来西亚、马鲁古省及苏拉威西。 树叶柄短，可长达6米长，2米宽，中茎15厘米宽，小叶片无数。以红棕色凸凹不平的果皮花纹得名。果实和无花果大小差不多，但果序丛生，味道酸甜。","desc_en":"Salak (Salacca zalacca) is a species of palm tree (family Arecaceae) native to Java and Sumatra in Indonesia. It is cultivated in other regions of Indonesia as a food crop or snack, and popularly grown in Bali, Lombok, Timor, Maluku, Sulawesi and Papua.","img":"images/195.jpg","thumb":"images/t/195.jpg","file":"Salak Salacca zalacca.jpg","ar":0.666,"py":"shepiguo spg","cr_by":"Cliff","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"棕榈","origin":["亚洲"]},{"id":196,"seq":204,"zh":"丛榈","en":"Chamaerops humilis","sci":"Chamaerops humilis","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":47,"desc_zh":"丛榈（学名：Chamaerops humilis）为棕榈科矮棕属下的一个种。种加名 humilis 意为“矮的”。","desc_en":"Chamaerops is a genus of flowering plants in the family Arecaceae. It contains only one species, Chamaerops humilis, variously called European fan palm or the Mediterranean dwarf palm.","img":"images/196.jpg","thumb":"images/t/196.jpg","file":"Chamaerops humilis (Zingaro)015.jpg","ar":1.333,"py":"congl cl","cr_by":"tato grasso","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"棕榈","origin":["欧洲"],"illus_img":"images/i/196.jpg","illus_thumb":"images/i/t/196.jpg","illus_file":"T7 58 Chamaerops humilis par Pierre Redouté.jpg","illus_ar":0.718,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":197,"seq":205,"zh":"海椰子","en":"Lodoicea maldivica","sci":"Lodoicea maldivica","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"EN","langs":47,"desc_zh":"海椰子（学名：Lodoicea maldivica），又名海底椰、白玉丹、白律丹、绿巨人，是塞舌尔普拉兰岛及屈里厄斯岛的一种特有棕榈。以拥有植物界最大种子著称。过去在不明此一奇特种子原出处时，由于是出现在印度洋以及马尔地夫、印度与斯里兰卡海滩上，所以有「马尔地夫椰子」或「海椰子」之称。「海底椰」一名则更具传奇性，当时人们想像此漂流于海上的核果应是来自于海底植物，成熟脱落后漂浮至海面。 海椰子树高可达30公尺。","desc_en":"Lodoicea, commonly known as the sea coconut, coco de mer, or double coconut, is a monotypic genus in the palm family. The sole species, Lodoicea maldivica, is endemic to the islands of Praslin and Curieuse in the Seychelles, and was historically found on the n…","img":"images/197.jpg","thumb":"images/t/197.jpg","file":"Female coco de mer growth.jpg","ar":0.75,"py":"haiyezi hyz","cr_by":"WL~commonswiki","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"棕榈","origin":null},{"id":1062,"seq":206,"zh":"鼓槌草","en":"Dasypogon bromeliifolius","sci":"Dasypogon bromeliifolius","order_en":"Arecales","order_zh":"棕榈目","family_en":"Dasypogonaceae","family_zh":"鼓槌草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Dasypogon bromeliifolius, commonly known as pineapple bush, is a species of shrub in the family Dasypogonaceae native to Western Australia.","img":"images/1062.jpg","thumb":"images/t/1062.jpg","file":"Dasypogon bromelifolius Walpole 2.jpg","ar":0.747,"py":"guchuicao gcc","cr_by":"MurielBendel","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["大洋洲"]},{"id":203,"seq":207,"zh":"玉米","en":"maize","sci":"Zea mays","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":244,"desc_zh":"玉米（学名：Zea mays）是禾本科玉米属的一年生草本植物，起源于北美洲及由美洲原住民最早种植，后来被引种到世界各地及进行改良，成为全世界总产量最高的重要粮食作物；玉米亦可作饲料使用，还有在生物科技产业作为乙醇燃料的原材料，亦在各个化工领域被大量利用，能做成塑胶等等不同的物品。","desc_en":"Maize (; Zea mays), also known as corn, is a tall stout grass that produces cereal grain. The leafy stalk of the plant gives rise to male inflorescences or tassels which produce pollen, and female inflorescences called ears.","img":"images/203.jpg","thumb":"images/t/203.jpg","file":"Klip kukuruza uzgojen u Međimurju (Croatia).JPG","ar":0.75,"py":"yumi ym","cr_by":"Silverije","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null,"illus_img":"images/i/203.jpg","illus_thumb":"images/i/t/203.jpg","illus_file":"Zea mays - Köhler–s Medizinal-Pflanzen-283.jpg","illus_ar":0.734,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":204,"seq":208,"zh":"大麦","en":"Hordeum vulgare","sci":"Hordeum vulgare","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":174,"desc_zh":"大麦（学名：Hordeum vulgare，英语：barley）是一种禾本科植物，主要的粮食和饲料作物，也可以作为啤酒或某些蒸馏酒的发酵原料。汉语俗称三月黄。大麦是世界上第四大耕作谷物，仅次于玉米、稻和小麦，2014年，大麦收获面积达49万平方公里，年产量约1.44亿吨；到2016年，大麦世界年产量约1.47亿吨。","desc_en":"Barley (Hordeum vulgare), a member of the grass family, is a major cereal grain grown in temperate climates globally. One of the first cultivated grains, it was domesticated in the Fertile Crescent around 9000 BC, giving it nonshattering spikelets and making i…","img":"images/204.jpg","thumb":"images/t/204.jpg","file":"Champ d'Orge carrée (Hordeum vulgare).jpg","ar":1.501,"py":"damai dm","cr_by":"JackyM59","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":null,"illus_img":"images/i/204.png","illus_thumb":"images/i/t/204.png","illus_file":"Hordeum vulgare illustration (01b).png","illus_ar":0.667,"illus_by":"https://www.biodiversitylibrary.org/item/9921#page/142/mode/1up Icones et descriptiones Graminum austriacorum Author: Ho","illus_lic":"Public domain","illus_licurl":null},{"id":205,"seq":209,"zh":"燕麦","en":"Avena sativa","sci":"Avena sativa","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":152,"desc_zh":"燕麦（学名：Avena sativa）一称皮燕麦。为禾本科早熟禾亚科燕麦属植物，是人类的主食之一，常制成燕麦片、大燕麦片贩售，大燕麦片也常作为家畜的饲料。燕麦是高营养成份的食物，定期食用时可以降低血液中的胆固醇。 燕麦中所含的燕麦球蛋白（Avenin，是类似小麦中麦胶蛋白的成份）会让少部份人有乳糜泻症状。而燕麦在制造过程也常会混合到少量含有麸质的谷类，例如小麦及大麦。","desc_en":"The oat (Avena sativa), sometimes called the common oat, is a species of cereal grass (Avena) grown for fodder and for its seed, which is known by the same name (usually in the plural).","img":"images/205.jpg","thumb":"images/t/205.jpg","file":"Illustration Avena sativa0.jpg","ar":0.609,"py":"yanmai ym","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null,"illus_img":"images/i/205.jpg","illus_thumb":"images/i/t/205.jpg","illus_file":"Avena sativa illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":206,"seq":210,"zh":"裸麦","en":"Secale cereale","sci":"Secale cereale","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":147,"desc_zh":"黑麦（学名：Secale cereale）又名裸麦，是一种在温带地区分布很广的谷物。相对于小麦来说裸麦更适应冷和干燥的气候。适合高寒或干旱地区生长。2013年联合国粮食及农业组织估计全世界裸麦产量为1670万吨。裸麦和小麦的杂交产品叫做小黑麦，它结合了两种作物的特性。在中欧和东欧，裸麦主要用来烤面包。","desc_en":"Rye (Secale cereale) is a grass grown extensively as a grain, a cover crop and a forage crop. It is grown principally in an area from Eastern and Northern Europe into Russia.","img":"images/206.jpg","thumb":"images/t/206.jpg","file":"Ear of rye.jpg","ar":1.333,"py":"luomai lm","cr_by":"LSDSL","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"],"illus_img":"images/i/206.jpg","illus_thumb":"images/i/t/206.jpg","illus_file":"Secale cereale illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":207,"seq":211,"zh":"高粱","en":"Sorghum bicolor","sci":"Sorghum bicolor","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":90,"desc_zh":"高粱（学名：Sorghum bicolor）又名二色高粱、蜀黍，禾本科，一年生高大草本植物，喜温、抗旱、耐涝，种子有红、白、褐各种颜色，有黏性变种。二色高粱是驯化后的高粱物种，野生的物种和二色高粱组成了高粱属。原产于非洲，目前主要种植在热带及亚热带地区，用世界不同地区的高粱品种间的基因遗传距离大致推算，高粱从印度传入中国的时间约在950年前的辽朝、宋朝及西夏时期。 种名 bicolor 意为“二色的”。","desc_en":"Sorghum bicolor, commonly called sorghum () and also known as broomcorn, great millet, Indian millet, Guinea corn, jowar, or milo, is a species in the grass genus Sorghum. It is typically an annual, but some cultivars are perennial.","img":"images/207.jpg","thumb":"images/t/207.jpg","file":"Sorghum bicolor03.jpg","ar":0.75,"py":"gaoliang gl","cr_by":"No machine-readable author provided. Pethan assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","非洲"],"illus_img":"images/i/207.jpg","illus_thumb":"images/i/t/207.jpg","illus_file":"Sorghum bicolor illustration (02).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":208,"seq":212,"zh":"水稻","en":"oryza molida","sci":"Oryza sativa","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":88,"desc_zh":"稻（学名：Oryza sativa），其果实为可作为粮食食用部位，称米，是禾本科稻属的一至二年生草本植物，也是稻属中作为粮食的最主要最悠久的一种，又称为亚洲型栽培稻、亚洲稻，简单来说也可以说是“稻”或“稻作”，一般所谓水稻、旱稻也是本种。 依分类学而言，亚洲型栽培稻大致可区分为籼稻（indica）、粳稻（japonica，温带粳稻）与爪哇稻（javanica，热带粳稻）三个亚种。全世界有半数以上人口以水稻为主食。","desc_en":"Oryza sativa, having the common name Asian cultivated rice, is the much more common of the two rice species cultivated as a cereal, the other species being O. glaberrima, African rice.","img":"images/208.jpg","thumb":"images/t/208.jpg","file":"Reis-Rispe.jpg","ar":0.75,"py":"shuidao sd","cr_by":"Leo Michels","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"],"illus_img":"images/i/208.jpg","illus_thumb":"images/i/t/208.jpg","illus_file":"Oryza sativa - Köhler–s Medizinal-Pflanzen-232.jpg","illus_ar":0.764,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":209,"seq":213,"zh":"芦苇","en":"Phragmites australis","sci":"Phragmites australis","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":83,"desc_zh":"芦苇（学名：Phragmites australis）属于禾本科芦竹亚科（Arundinoideae）的芦苇属，是生长于沼泽、河沿、海滩等湿地的一种多年生植物，遍布于全世界温带、亚热带及热带地区。","desc_en":"Phragmites australis, known as the common reed, is a species of flowering plant in the grass family Poaceae. It is a wetland grass that can grow up to 20 feet (6 metres) tall and has a cosmopolitan distribution worldwide.","img":"images/209.jpg","thumb":"images/t/209.jpg","file":"Phragmites australis Schilfrohr.jpg","ar":0.763,"py":"luwei lw","cr_by":"Darkone ( talk · contribs )","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"禾草","origin":null,"illus_img":"images/i/209.jpg","illus_thumb":"images/i/t/209.jpg","illus_file":"Phragmites australis illustration (01).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":210,"seq":214,"zh":"狗牙根","en":"Cynodon dytahilo","sci":"Cynodon dactylon","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":80,"desc_zh":"狗牙根（学名：Cynodon dactylon），亦称绊根草（植物名实图考）、铁线草、爬根草、咸沙草、百慕达草，多年生草本植物。","desc_en":"Cynodon dactylon, commonly known as Bermuda grass or as couch grass in Australia and New Zealand, is a grass found worldwide in warm and tropical climates. It is native to Europe, Africa, Australia, and much of Asia and has been introduced to the Americas.","img":"images/210.jpg","thumb":"images/t/210.jpg","file":"Cynodon dactylon RF.jpg","ar":1.333,"py":"gouyagen gyg","cr_by":"Robert Flogaus-Faust","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["亚洲","欧洲","非洲","大洋洲"],"illus_img":"images/i/210.jpg","illus_thumb":"images/i/t/210.jpg","illus_file":"Cynodon dactylon — Flora Batava — Volume v10 - clean.jpg","illus_ar":0.728,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":211,"seq":215,"zh":"小米","en":"Setaria italica","sci":"Setaria italica","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":79,"desc_zh":"粟（学名：Setaria italica ；英语：foxtail millet），亦称稷、粱、粟米，北方又称谷子，俗称小米、黄小米、小黄米，属禾本科狗尾草属的一种农作物。也有将穗大毛长粒粗的称为粱，而穗小毛短粒细的称为粟；或是大粟为「粱」，小粟为「粟」。是五谷中籽实最小的。 早在新石器时代就已经开始种植，在青海遗址中也有出土。","desc_en":"Foxtail millet, scientific name Setaria italica (synonym Panicum italicum L.), is an annual grass grown for human food. It is the second-most widely planted species of millet and the most grown millet species in Asia.","img":"images/211.jpg","thumb":"images/t/211.jpg","file":"Foxtailmillet.jpg","ar":1.475,"py":"xiaomi xm","cr_by":"No machine-readable author provided. Marknesbitt assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"],"illus_img":"images/i/211.jpg","illus_thumb":"images/i/t/211.jpg","illus_file":"Setaria italica illustration (02).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":212,"seq":216,"zh":"偃麦草","en":"Elymus repens","sci":"Elymus repens","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":75,"desc_zh":"偃麦草（学名：Elymus repens）是一种禾本科植物，原产欧亚大陆和西北非，包括中国甘肃、河北、黑龙江、内蒙古、青海、山东、四川、新疆、西藏、云南等省区。","desc_en":"Elymus repens, commonly known as couch grass , is a very common perennial species of grass native to most of Europe, Asia, the Arctic, and northwest Africa.","img":"images/212.jpg","thumb":"images/t/212.jpg","file":"Kweek Elytrigia repens.jpg","ar":0.757,"py":"yanmaicao ymc","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/212.jpg","illus_thumb":"images/i/t/212.jpg","illus_file":"Elymus repens illustration (03).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":213,"seq":217,"zh":"秀贵甘蔗","en":"Saccharum officinarum","sci":"Saccharum officinarum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":69,"desc_zh":"甘蔗（学名：Saccharum officinarum）又名红甘蔗，为禾本科甘蔗属下的一个种。皮墨红色，茎肉富纤维质多汁液，清甜嫩脆、食而不腻，可削皮后直接食用或搾汁饮用。","desc_en":"Saccharum officinarum is a large, strong-growing species of grass in the sugarcane genus. Its stout stalks are rich in sucrose, a disaccharide sugar which accumulates in the stalk internodes.","img":"images/213.jpg","thumb":"images/t/213.jpg","file":"Saccharum officinarum, Mozambique.jpg","ar":0.781,"py":"xiuguiganzhe xggz","cr_by":"Ton Rulkens","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"禾草","origin":["大洋洲"],"illus_img":"images/i/213.jpg","illus_thumb":"images/i/t/213.jpg","illus_file":"Saccharum officinarum - Köhler–s Medizinal-Pflanzen-125.jpg","illus_ar":0.734,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":214,"seq":218,"zh":"斯佩耳特小麦","en":"Triticum spelta","sci":"Triticum spelta","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":67,"desc_zh":"斯佩耳特小麦（学名：Triticum spelta）是一种小麦。它在青铜时代到中世纪时的部分欧洲地区都是重要的农产品。如今在中欧仍有种植，作为一种健康食品重新在市场中出现。","desc_en":"Spelt (Triticum spelta), also known as dinkel wheat is a species of wheat. It is a relict crop, eaten in Central Europe and northern Spain. It is high in protein. In Australia it is marketed as a health food.","img":"images/214.jpg","thumb":"images/t/214.jpg","file":"202304 7 Tr.spelta color.svg","ar":0.365,"py":"sipeiertexiaomai spetxm","cr_by":"DataBase Center for Life Science (DBCLS)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["欧洲"],"illus_img":"images/i/214.jpg","illus_thumb":"images/i/t/214.jpg","illus_file":"Triticum spelta illustration (02).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":215,"seq":219,"zh":"普通小麦","en":"Triticum aestivum","sci":"Triticum aestivum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":66,"desc_zh":"普通小麦（学名：Triticum aestivum）为禾本科小麦属下的一个种。全世界生产的小麦中约有95%是普通小麦。普通小麦也是全球范围内产量最高的经济作物之一。 普通小麦起源于约8000年前，在外高加索与今伊朗的里海沿岸，二粒小麦偶然与山羊草属的节节麦（Aegilops tauschii）杂交而形成。","desc_en":"Common wheat (Triticum aestivum), also known as bread wheat, is a cultivated wheat species. It originated around 8,000 years ago, from the hybridization of an already existing domesticated variety of wheat and the wild goatgrass in the South Caucasus or southw…","img":"images/215.jpg","thumb":"images/t/215.jpg","file":"Tarweaar.jpg","ar":0.455,"py":"putongxiaomai ptxm","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"],"illus_img":"images/i/215.jpg","illus_thumb":"images/i/t/215.jpg","illus_file":"Triticum aestivum illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":216,"seq":220,"zh":"黍","en":"Panicum miliaceum","sci":"Panicum miliaceum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":65,"desc_zh":"黍（shǔ）（学名：Panicum miliaceum）又名糜子、黍稷、糜黍、稷，古称穄，脱壳后称黄米、稷米、粢米，是禾本科黍属的一年生草本植物，生长期短、耐寒、耐旱、耐贫瘠，全球均有分布。主要种植于印度、中国、尼泊尔、非洲、俄罗斯、乌克兰、白俄罗斯和中东等地区。其种子形小可食用，也常用作鸟食和酿酒。","desc_en":"Panicum miliaceum is a grain crop with many common names, including proso millet, broomcorn millet, common millet, hog millet, Kashfi millet, red millet, and white millet.","img":"images/216.jpg","thumb":"images/t/216.jpg","file":"Panicum miliaceum0.jpg","ar":1.333,"py":"shu s","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"],"illus_img":"images/i/216.jpg","illus_thumb":"images/i/t/216.jpg","illus_file":"Panicum miliaceum illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":217,"seq":221,"zh":"香根草","en":"Chrysopogon zizanioides","sci":"Chrysopogon zizanioides","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":60,"desc_zh":"香根草（学名：Chrysopogon zizanioides），又名培地茅、岩兰草、优尸罗草、忧尸罗草、乌施罗草、嗢尸罗草（梵语：उषीर，罗马化：uṣīra）、茅根香（佛经意译），是禾本科多年生草本植物，原产于印度次大陆与中南半岛，经人工栽种，目前广泛分布于亚洲、非洲、美洲与澳洲热带与亚热带地区。 香根草耐暑、耐涝，可度过寒冬，分蘖丛生，生长快速，茎梗直立有节，抽穗成熟一般高达1.5米（4.","desc_en":"Chrysopogon zizanioides, commonly known as vetiver and khus, is a perennial bunchgrass of the family Poaceae. Vetiver is most closely related to sorghum while sharing many morphological characteristics with other fragrant grasses, such as lemongrass (Cymbopogo…","img":"images/217.jpg","thumb":"images/t/217.jpg","file":"Vetiveria zizanioides0.jpg","ar":1.327,"py":"xianggencao xgc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null},{"id":218,"seq":222,"zh":"白茅","en":"Imperata cylindrica","sci":"Imperata cylindrica","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":59,"desc_zh":"白茅（学名：Imperata cylindrica），又名藗，为禾本科白茅属下的一个种。在中药中食用其根部，称作白茅根，又称作茅根、茅草根、丝茅、茹根，可清热。通常分布于日晒良好的河滩或草原地区。产于中国辽宁、河北、山西、山东、陕西、新疆等北方地区；非洲北部、土耳其、伊拉克、伊朗、中亚、高加索及地中海区域。模式标本采自法国南部。","desc_en":"Imperata cylindrica (commonly known as cogongrass or kunai grass ) is a species of perennial rhizomatous grass native to tropical and subtropical Asia, Micronesia, Melanesia, Australia, Africa, and Southern Europe.","img":"images/218.jpg","thumb":"images/t/218.jpg","file":"JapaneseBloodGrass2.JPG","ar":0.724,"py":"baimao bm","cr_by":"GearedBull at English Wikipedia","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"禾草","origin":["亚洲","欧洲","非洲","大洋洲"],"illus_img":"images/i/218.jpg","illus_thumb":"images/i/t/218.jpg","illus_file":"Imperata cylindrica illustration (01).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":219,"seq":223,"zh":"柠檬草","en":"Cymbopogon citratus","sci":"Cymbopogon citratus","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":55,"desc_zh":"柠檬草（学名：Cymbopogon citratus）又名柠檬香茅，生长在开阔的热带干燥土壤，分布于印度南部及斯里兰卡。全株芳香，丛生的球茎上产生大量叶片及分之的圆锥花序。","desc_en":"Cymbopogon citratus, commonly known as West Indian lemon grass or simply lemon grass, is a tropical plant native to South Asia and Maritime Southeast Asia and introduced to many tropical regions. Cymbopogon citratus is often sold in stem form.","img":"images/219.jpg","thumb":"images/t/219.jpg","file":"YosriNov04Pokok Serai.JPG","ar":0.75,"py":"ningmengcao nmc","cr_by":null,"cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"禾草","origin":["亚洲"]},{"id":220,"seq":224,"zh":"野燕麦","en":"Avena fatua","sci":"Avena fatua","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":54,"desc_zh":"野燕麦（学名：Avena fatua）为禾本科燕麦属下的一种植物，为一种常见的杂草。","desc_en":"Avena fatua is a species of grass in the oat genus. It is known as the common wild oat. Like fellow wild oat species A. sterilis, it bears 42 chromosomes, and its seeds shatter at maturity for yearly seeding.","img":"images/220.jpg","thumb":"images/t/220.jpg","file":"OTRS2009032010019662 HEOS4488.jpg","ar":0.667,"py":"yeyanmai yym","cr_by":"Helge Oskarsen","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["亚洲","欧洲"],"illus_img":"images/i/220.jpg","illus_thumb":"images/i/t/220.jpg","illus_file":"Avena fatua — Flora Batava — Volume v8.jpg","illus_ar":0.728,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":221,"seq":225,"zh":"硬粒小麦","en":"Triticum durum","sci":"Triticum durum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":53,"desc_zh":"硬粒小麦又名杜兰小麦（学名：Triticum durum or Triticum turgidum var. durum）为禾本科小麦属，曾经被归为圆锥小麦的亚种。 基因组学研究表明：50万年前，二倍体的小麦属乌拉尔图小麦（Triticum urartu）与山羊草属的拟山羊草（Aegilops speltoides）杂交，形成了圆锥小麦（T. turgidum）与提莫非维小麦（T.timopheevii），这两种均为四倍体。","desc_en":"Durum (), also called pasta wheat or macaroni wheat (Triticum durum or Triticum turgidum subsp. durum), is a tetraploid species of wheat. It is the second-most cultivated species of wheat after common wheat, although it represents only 5 to 8% of global wheat…","img":"images/221.jpg","thumb":"images/t/221.jpg","file":"Triticum-durum-ear.JPG","ar":1.352,"py":"yinglixiaomai ylxm","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"],"illus_img":"images/i/221.jpg","illus_thumb":"images/i/t/221.jpg","illus_file":"Triticum durum illustration (03).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":222,"seq":226,"zh":"鸭茅","en":"Dactylis glomerata","sci":"Dactylis glomerata","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":53,"desc_zh":"鸭茅（学名：Dactylis glomerata）也叫做鸡脚草、果园草，是一种禾本科草本植物。在中国，这种草主要分布于西南部和西北部，是一种喂牛喂马的牧草，一般都是在春天或者秋天的时候播的种。","desc_en":"Dactylis glomerata is a species of flowering plant in the grass family Poaceae, known as cock's-foot, also colloquially as orchard grass, or cat grass (due to its popularity for use with domestic cats).","img":"images/222.jpg","thumb":"images/t/222.jpg","file":"00 2785 Gewöhnliche Knäuelgras (Dactylis glomerata).jpg","ar":0.667,"py":"yamao ym","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/222.jpg","illus_thumb":"images/i/t/222.jpg","illus_file":"Dactylis glomerata illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":223,"seq":227,"zh":"御谷","en":"Cenchrus americanus","sci":"Cenchrus americanus","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":53,"desc_zh":"御谷（学名：Pennisetum glaucum），又名蜡烛稗、珍珠粟，为禾本科狼尾草属的植物。","desc_en":"Pearl millet (Cenchrus americanus, commonly known as the synonym Pennisetum glaucum) is the most widely grown type of millet. It has been grown in Africa and the Indian subcontinent since prehistoric times.","img":"images/223.jpg","thumb":"images/t/223.jpg","file":"Grain millet, early grain fill, Tifton, 7-3-02.jpg","ar":1.333,"py":"yugu yg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","非洲"]},{"id":224,"seq":228,"zh":"芦荻","en":"Arundo donax","sci":"Arundo donax","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":51,"desc_zh":"芦荻又名芦竹（学名：Arundo donax），是多年生挺水高大宿根草本，形如芦苇。地下茎短缩、粗壮，多分枝，叶片广披针形，圆锥花序顶生，穗状呈扫帚状，9-12月为花果期。为主要水边观景植物。 分布于热带、亚热带，中国华东、华南和西南等地。被国际自然保护联盟物种存续委员会的入侵物种专家小组（ISSG）列入世界百大外来入侵种。","desc_en":"Arundo donax is a tall perennial cane. It is one of several so-called reed species. It has several common names including giant cane, elephant grass, carrizo, arundo, Spanish cane, Colorado river reed, wild cane, and giant reed.","img":"images/224.jpg","thumb":"images/t/224.jpg","file":"Illustration Arundo donax0.jpg","ar":0.566,"py":"ludi ld","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"],"illus_img":"images/i/224.jpg","illus_thumb":"images/i/t/224.jpg","illus_file":"Arundo donax illustration (01).jpg","illus_ar":0.704,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":241,"seq":229,"zh":"纸莎草","en":"Cyperus papyrus","sci":"Cyperus papyrus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":68,"desc_zh":"纸莎（suō）草（学名：Cyperus papyrus，英语：papyrus），又称纸草、埃及莎草、埃及纸草、蒲草（bulrush）、埃及蒲草、印度丛草（Indian matting plant）等。属于莎草科莎草属。是北非洲原产的一种多年生草本植物。","desc_en":"Cyperus papyrus, better known by the common names papyrus sedge, papyrus, paper reed, Indian matting plant, or Nile grass, is a species of aquatic flowering plant belonging to the sedge family Cyperaceae.","img":"images/241.jpg","thumb":"images/t/241.jpg","file":"Papyrus (Cyperus papyrus) (7079191471).jpg","ar":1.333,"py":"zhisuocao zsc","cr_by":"Bernard DUPONT from FRANCE","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"禾草","origin":["欧洲","非洲"],"illus_img":"images/i/241.jpg","illus_thumb":"images/i/t/241.jpg","illus_file":"James Bruce - Cyperus papyrus L (Papyrus Sedge), finished drawing of inflorescence - B1977.14.9119 - Yale Center for British Art.jpg","illus_ar":0.689,"illus_by":"James Bruce","illus_lic":"CC0","illus_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en"},{"id":242,"seq":230,"zh":"香附子","en":"Cyperus rotundus","sci":"Cyperus rotundus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":66,"desc_zh":"香附子（学名：Cyperus rotundus），别名莎草、大香附、香头草、土香草、土香（台湾和闽南一带）、水香棱、地藾草，为莎草科的多年生草本植物，茎直立，三棱形，高40厘米；叶近基生出，细长，呈线形，略比茎短，约20厘米。叶脉平行，中脉明显，春夏开花抽穗，穗状花序做繖房状排列，花序扁状长筒型，红褐色。莎草多生于山坡草地或水边湿地上，在中国广大地区都有分布。","desc_en":"Cyperus rotundus (coco-grass, Java grass, nut grass, purple nut sedge or purple nutsedge, red nut sedge, Khmer kravanh chruk) is a species of sedge (Cyperaceae) native to Africa, southern and central Europe (north to France and Austria), and southern Asia.","img":"images/242.jpg","thumb":"images/t/242.jpg","file":"Nutgrass Cyperus rotundus02.jpg","ar":0.638,"py":"xiangfuzi xfz","cr_by":"No machine-readable author provided. Rickjpelleg assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":243,"seq":231,"zh":"荸荠","en":"Eleocharis dulcis","sci":"Eleocharis dulcis","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":53,"desc_zh":"荸（bí）荠（qí）（学名：Eleocharis dulcis；英文：Chinese water chestnut），又名马荠、马蹄、地栗、凫茈（cí）、茈骨、乌芋、菩荠、地梨、芍（sháo）、马薯、铺李子，是莎草科荸荠属一种。","desc_en":"Eleocharis dulcis, the Chinese water chestnut or water chestnut, is a grass-like sedge native to Asia, tropical Africa, and Oceania. It is grown in many countries for its edible corms, but if eaten uncooked, the surface of the plants may transmit fasciolopsias…","img":"images/243.jpg","thumb":"images/t/243.jpg","file":"Eleocharis dulcis Blanco1.15.jpg","ar":0.668,"py":"biqi bq","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","非洲"]},{"id":244,"seq":232,"zh":"油莎草","en":"Cyperus esculentus","sci":"Cyperus esculentus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":46,"desc_zh":"油莎草（学名：Cyperus esculentus），又名油莎豆、铁荸荠、黄土香，英文俗名为Chufa Sedge、Yellow Nutsedge、Tigernut Sedge或Earthalmond。其块茎在英文中称作tigernut，在西班牙文中称作chufa。油莎草是莎草科莎草属植物。","desc_en":"Cyperus esculentus (also called chufa, tiger nut, atadwe, yellow nutsedge, earth almond, and in Chishona, pfende) is a species of plant in the sedge family widespread across much of the world.","img":"images/244.jpg","thumb":"images/t/244.jpg","file":"Cyperus esculentus L. (AM AK301430-1), white background.jpg","ar":0.723,"py":"yousuocao ysc","cr_by":"Wilcox, Mike","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/244.jpg","illus_thumb":"images/i/t/244.jpg","illus_file":"Cyperus esculentus illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":245,"seq":233,"zh":"东方羊胡子草","en":"Eriophorum angustifolium","sci":"Eriophorum angustifolium","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":39,"desc_zh":"东方羊胡子草（学名：Eriophorum angustifolium）为莎草科羊胡子草属下的一个种。 为多年生草本植物，可高达60厘米。其种子成熟后分裂出状如棉絮的白色细丝，可以随风飞散，以利于传播种子。","desc_en":"Eriophorum angustifolium, commonly known as common cottongrass or common cottonsedge, is a species of flowering plant in the sedge family, Cyperaceae. Native to North America, North Asia, and Europe, it grows on peat or acidic soils, in open wetland, heath or…","img":"images/245.jpg","thumb":"images/t/245.jpg","file":"00 3892 Schmalblättrige Wollgras (Eriophorum angustifolium).jpg","ar":0.667,"py":"dongfangyanghuzicao dfyhzc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/245.jpg","illus_thumb":"images/i/t/245.jpg","illus_file":"Eriophorum angustifolium illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":246,"seq":234,"zh":"海滨三棱草","en":"Bolboschoenus maritimus","sci":"Bolboschoenus maritimus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":37,"desc_zh":"海滨三棱草（学名：Bolboschoenus maritimus），是莎草科三棱草属多年生草本植物，广布于温带、亚热带地区；在中国分布于新疆；台湾可能有分布。","desc_en":"Bolboschoenus maritimus is a species of flowering plant from family Cyperaceae. Common names for this species include sea clubrush, cosmopolitan bulrush, alkali bulrush, saltmarsh bulrush, and bayonet grass.","img":"images/246.jpg","thumb":"images/t/246.jpg","file":"Bolboschoenus maritimus syn Cyperus maritimus.jpg","ar":0.402,"py":"haibinsanlengcao hbslc","cr_by":"Johann Georg Sturm (Painter: Jacob Sturm )","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null,"illus_img":"images/i/246.jpg","illus_thumb":"images/i/t/246.jpg","illus_file":"Bolboschoenus maritimus illustration (01).jpg","illus_ar":0.692,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":247,"seq":235,"zh":"Carex arenaria","en":"Carex arenaria","sci":"Carex arenaria","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Carex arenaria, or sand sedge, is a species of perennial sedge of the genus Carex which is commonly found growing in dunes and other sandy habitats, as the species epithet suggests (Latin arenarius, \"sandy\"). It grows by long stolons under the soil surface.","img":"images/247.jpg","thumb":"images/t/247.jpg","file":"CarexArenaria.jpg","ar":0.687,"py":"","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null,"illus_img":"images/i/247.jpg","illus_thumb":"images/i/t/247.jpg","illus_file":"Carex arenaria - Köhler–s Medizinal-Pflanzen-153.jpg","illus_ar":0.797,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":251,"seq":236,"zh":"菠萝","en":"Ananas comosus","sci":"Ananas comosus","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":154,"desc_zh":"菠萝（学名：Ananas comosus，星马称黄梨，台湾称凤梨）是一种原产于南美洲的热带水果，为禾本目凤梨科凤梨属植物，因多汁酸甜受到喜爱，有解暑之效，是凤梨科中最具经济价值的种类。其食用部位并非果实，而是肥大的肉质花序轴。南美洲种植凤梨已有许多世纪，在17世纪传入欧洲，于1820年代开始在温室与热带地区开始商业种植。","desc_en":"The pineapple (Ananas comosus) is a tropical plant with an edible fruit; it is the most economically significant plant in the family Bromeliaceae. The pineapple is native to South America, where it has been cultivated for many centuries.","img":"images/251.jpg","thumb":"images/t/251.jpg","file":"Nanas variegata cheche.jpg","ar":1.333,"py":"boluo bl","cr_by":"VpuipV ,pemegang hak cipta","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["南美洲"]},{"id":252,"seq":237,"zh":"松萝菠萝","en":"Tillandsia usneoides","sci":"Tillandsia usneoides","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":"LC","langs":37,"desc_zh":"松萝凤梨（学名：Tillandsia usneoides）为菠萝科空气凤梨属下的一个种，英文俗称“西班牙藓”（Spanish moss），在法属波利尼西亚俗称“老人须”（grandpa's beard）。","desc_en":"Spanish moss (Tillandsia usneoides) is an epiphytic flowering plant that often grows upon large trees in tropical and subtropical climates. It is native to much of Mexico, Bermuda, the Bahamas, Central America, South America (as far south as northern Patagonia…","img":"images/252.jpg","thumb":"images/t/252.jpg","file":"Flickr - ggallice - Spanish moss flower.jpg","ar":0.685,"py":"songluoboluo slbl","cr_by":"Geoff Gallice from Gainesville, FL, USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["欧洲","北美洲","南美洲"]},{"id":253,"seq":238,"zh":"莴氏普亚凤梨","en":"Puya Raymondi violadora","sci":"Puya raimondii","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":"EN","langs":28,"desc_zh":"莴氏普亚凤梨（学名Puya raimondii），又名安地斯皇后，是玻利维亚及秘鲁特有的一种凤梨科植物，生长在海拔3200-4800米处。它们是由法国科学家阿尔西德·道比尼（Alcide d'Orbigny）于1830年在玻利维亚科恰班巴省海拔3960米处发现。取此名是为纪念在秘鲁进行多年研究的义大利植物学家安东尼奥·莱蒙廸（Antonio Raimondi）。道比尼后来在秘鲁查文德万塔尔也发现此种植物。 莴氏普亚凤梨的花序巨大。","desc_en":"Puya raimondii, also known as the Queen of the Andes (English), titanka and ilakuash (Quechua) or puya de Raimondi (Spanish), is the largest species of bromeliad, its inflorescences reaching up to 15 m (50 ft) in height.","img":"images/253.jpg","thumb":"images/t/253.jpg","file":"Puya raimondii hábito.jpg","ar":0.75,"py":"woshipuyafengli wspyfl","cr_by":"Pepe Roque","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["南美洲"]},{"id":254,"seq":239,"zh":"蜻蜓菠萝","en":"Aechmea fasciata","sci":"Aechmea fasciata","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":25,"desc_zh":"蜻蜓菠萝（学名：Aechmea fasciata），又叫蜻蜓凤梨、斑粉菠萝、美叶光萼荷，为凤梨科萼凤梨属附生草本植物，或菠萝科蜻蜓菠萝属下的一个种。原产于巴西，附生在雨林树干上。喜半阴、温暖和潮湿环境。生长适温为15—25℃，越冬温度约为10℃。对环境适应力强，既耐阴也耐旱。栽培3、4年后开花。","desc_en":"Aechmea fasciata is a species of flowering plant in the Bromeliaceae family. It is commonly called the silver vase or urn plant and is native to Brazil. This plant is probably the best known species in this genus, and it is often grown as a houseplant in tempe…","img":"images/254.jpg","thumb":"images/t/254.jpg","file":"Aechmea fasciata2.jpg","ar":1.333,"py":"qingtingboluo qtbl","cr_by":"Paul & Aline Burland","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["南美洲"]},{"id":255,"seq":240,"zh":"食蚁凤梨","en":"Brocchinia reducta","sci":"Brocchinia reducta","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":19,"desc_zh":null,"desc_en":"Brocchinia reducta is a carnivorous plant in the bromeliad family. It is native to southern Venezuela, Brazil, Colombia, and Guyana, and is found in areas with nutrient-poor, high moisture soil. B.","img":"images/255.jpg","thumb":"images/t/255.jpg","file":"Brocchinia reducta (Roraima tepui).jpg","ar":1.504,"py":"shiyifengli syfl","cr_by":"Christian Hummert","cr_lic":"CC BY-SA 2.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0/de/deed.en","habit":null,"origin":["南美洲"]},{"id":256,"seq":241,"zh":"贝尔特罗嘉宝凤梨","en":"Catopsis berteroniana","sci":"Catopsis berteroniana","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":16,"desc_zh":"贝尔特罗嘉宝凤梨（学名：Catopsis berteroniana；标音：kətɒpsɪs bɚtəɹəʊniːɑːnə）为著生的凤梨科植物，被认为可能是食肉植物，类似瘦缩布洛凤梨，通常也称作著生食虫凤梨，尽管有迹象显示这仍是有疑问的。原产佛罗里达南部到巴西南部一带。一般生长在树上无遮荫的细枝，而且似乎能比其它可媲美本种大小的积水凤梨捕捉到更多的虫子在它积水槽。本属另有许多其它种类， 然而都没有被认定是食肉植物。","desc_en":"Catopsis berteroniana , commonly known as the powdery strap airplant or the lantern of the forest, is an epiphytic bromeliad thought to be a possible carnivorous plant, similar to Brocchinia reducta, although the evidence is equivocal.","img":"images/256.jpg","thumb":"images/t/256.jpg","file":"CatopsisBerteroniana AtSierraDeLema4836.jpg","ar":0.648,"py":"beierteluojiabaofengli betljbfl","cr_by":"BotBln","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲","南美洲"]},{"id":260,"seq":242,"zh":"灯心草","en":"Juncus effusus","sci":"Juncus effusus","order_en":"Poales","order_zh":"禾本目","family_en":"Juncaceae","family_zh":"灯心草科","iucn":"LC","langs":40,"desc_zh":"灯心草（学名：Juncus effusus），又名圆蔺（lìn）、灯芯草、水灯花、水灯心、蔺草、灯草、龙须草、野席草、马棕根、野马棕，是灯心草属多年生草本植物，分布于全球温暖地区，生长于海拔200－3,400米的地区。其种加词“Effusus”意为“散乱的”。","desc_en":"Juncus effusus is a perennial herbaceous flowering plant species in the rush family Juncaceae, with the common names common rush or soft rush.","img":"images/260.jpg","thumb":"images/t/260.jpg","file":"Juncus effuses.jpg","ar":1.333,"py":"dengxincao dxc","cr_by":"The original uploader was Meggar at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null,"illus_img":"images/i/260.jpg","illus_thumb":"images/i/t/260.jpg","illus_file":"Juncus effusus — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":261,"seq":243,"zh":"地杨梅","en":"Luzula campestris","sci":"Luzula campestris","order_en":"Poales","order_zh":"禾本目","family_en":"Juncaceae","family_zh":"灯心草科","iucn":null,"langs":32,"desc_zh":"地杨梅（学名：Luzula campestris）为灯心草科地杨梅属下的一个种。","desc_en":"Luzula campestris, commonly known as field wood-rush or Good Friday grass is a flowering plant in the rush family Juncaceae. It is also one of the plants known as chimney sweeps or sweep's broom because of the brush-like appearance of their flowers.","img":"images/261.jpg","thumb":"images/t/261.jpg","file":"Luzula campestris IP0605002.jpg","ar":0.699,"py":"diyangmei dym","cr_by":"Leo Michels User:Der Michels","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","欧洲"],"illus_img":"images/i/261.png","illus_thumb":"images/i/t/261.png","illus_file":"Luzula campestris drawing.png","illus_ar":0.555,"illus_by":"Dwergenpaartje","illus_lic":"CC BY-SA 3.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/3.0"},{"id":1063,"seq":244,"zh":"小灯心草","en":"Juncus bufonius","sci":"Juncus bufonius","order_en":"Poales","order_zh":"禾本目","family_en":"Juncaceae","family_zh":"灯心草科","iucn":"LC","langs":30,"desc_zh":"小灯心草（学名：Juncus bufonius）是灯心草科灯心草属的植物。分布在美洲、俄罗斯、日本、朝鲜、欧洲以及中国大陆的东北、西南、华东、华北、西北等地，生长于海拔160米至3,200米的地区，多生于河边、湖岸、湿草地以及沼泽地，目前尚未由人工引种栽培。","desc_en":"Juncus bufonius, known commonly as toad rush, is a widespread flowering plant species complex in the rush family Juncaceae.","img":"images/1063.jpg","thumb":"images/t/1063.jpg","file":"Juncus bufonius.jpeg","ar":1.333,"py":"xiaodengxincao xdxc","cr_by":"Kristian Peters -- Fabelfroh 11:49, 16 June 2007 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null,"illus_img":"images/i/1063.jpg","illus_thumb":"images/i/t/1063.jpg","illus_file":"Juncus bufonius — Flora Batava — Volume v13.jpg","illus_ar":0.749,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":262,"seq":245,"zh":"宽叶香蒲","en":"Typha latifolia","sci":"Typha latifolia","order_en":"Poales","order_zh":"禾本目","family_en":"Typhaceae","family_zh":"香蒲科","iucn":"LC","langs":60,"desc_zh":"宽叶香蒲（学名：Typha latifolia），别名香蒲、蒲黄，为香蒲科香蒲属的植物，广泛分布于南北美、欧洲、亚洲和非洲，环境适应能力很强。高可达三米。 香蒲可当做水生蔬菜。可作蔬菜的部分有假茎基部（蒲菜）、地下幼嫩的匍匐茎和芽（象牙菜），炒食或烩菜，也可做汤。印第安人也有食用它的习惯。","desc_en":"Typha latifolia is a perennial herbaceous wetland plant in the genus Typha. It is known in English as bulrush (sometimes as common bulrush to distinguish from other species of Typha), and in North America as broadleaf cattail.","img":"images/262.jpg","thumb":"images/t/262.jpg","file":"Lisdodde.jpg","ar":0.75,"py":"kuanyexiangpu kyxp","cr_by":"Andrawaag","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["北美洲"],"illus_img":"images/i/262.jpg","illus_thumb":"images/i/t/262.jpg","illus_file":"Typha latifolia — Flora Batava — Volume v10 clean no-description.jpg","illus_ar":0.816,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1064,"seq":246,"zh":"狭叶香蒲","en":"Typha angustifolia","sci":"Typha angustifolia","order_en":"Poales","order_zh":"禾本目","family_en":"Typhaceae","family_zh":"香蒲科","iucn":"LC","langs":49,"desc_zh":"水烛（学名：Typha angustifolia）又称蒲草、狭叶香蒲、草蒲黄，是香蒲科香蒲属的植物。分布于印度、俄罗斯、尼泊尔、巴基斯坦、美洲及大洋洲、台湾、欧洲、日本以及中国大陆的吉林、河北、山东、内蒙古、江苏、黑龙江、陕西、甘肃、辽宁、河南、新疆、云南、湖北等地，生长于海拔50米至2,800米的地区，常生长在水边、沼泽中。","desc_en":"Typha angustifolia is a perennial herbaceous plant in the genus Typha, native throughout most of Eurasia and locally in northwest Africa; it also occurs widely in North America, where its native status is disputed.","img":"images/1064.jpg","thumb":"images/t/1064.jpg","file":"00 1628 Schmalblättrige Rohrkolben (Typha angustifolia).jpg","ar":0.667,"py":"xiayexiangpu xyxp","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":null,"illus_img":"images/i/1064.jpg","illus_thumb":"images/i/t/1064.jpg","illus_file":"Typha angustifolia — Flora Batava — Volume v4.jpg","illus_ar":0.735,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":263,"seq":247,"zh":"Syngonanthus nitens","en":"Syngonanthus nitens","sci":"Syngonanthus nitens","order_en":"Poales","order_zh":"禾本目","family_en":"Eriocaulaceae","family_zh":"谷精草科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Syngonanthus nitens is a grass-like species of Eriocaulaceae which exists in the region of Jalapão, state of Tocantins, Brazil - the region is part of the Brazilian cerrado.","img":"images/263.jpg","thumb":"images/t/263.jpg","file":"Capim Dourado.JPG","ar":1.506,"py":"","cr_by":"Daniel.zilenovski","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["南美洲"]},{"id":1065,"seq":248,"zh":"凤梨食虫谷精","en":"Paepalanthus bromelioides","sci":"Paepalanthus bromelioides","order_en":"Poales","order_zh":"禾本目","family_en":"Eriocaulaceae","family_zh":"谷精草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Paepalanthus bromelioides is a species in the flowering plant family Eriocaulaceae. It is a perennial native to Minas Gerais state in southeastern Brazil. Family Eriocaulaceae is placed in the Poales, close to the Bromeliaceae, whose morphology this genus shar…","img":"images/1065.jpg","thumb":"images/t/1065.jpg","file":"Paepalanthus, Eriocaulaceae.JPG","ar":1.333,"py":"fenglishichonggujing flscgj","cr_by":"UNiesert","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["南美洲"]},{"id":1066,"seq":249,"zh":"Anarthria scabra","en":"Anarthria scabra","sci":"Anarthria scabra","order_en":"Poales","order_zh":"禾本目","family_en":"Anarthriaceae","family_zh":"苞穗草科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Anarthria scabra is an herbaceous plant found in Southwest Australia.","img":"images/1066.jpg","thumb":"images/t/1066.jpg","file":"Anarthria scabra - Flickr - Kevin Thiele (1).jpg","ar":0.258,"py":"","cr_by":"Kevin Thiele from Perth, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["大洋洲"]},{"id":1067,"seq":250,"zh":"Gaimardia setacea","en":"Gaimardia setacea","sci":"Gaimardia setacea","order_en":"Poales","order_zh":"禾本目","family_en":"Centrolepidaceae","family_zh":"刺鳞草科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Gaimardia setacea is a species of plant of the Restionaceae family. It is found in New Zealand (on the South Island and the Stewart Islands), New Guinea and Tasmania.","img":"images/1067.jpg","thumb":"images/t/1067.jpg","file":"Gaimardia setacea in the Waitaki District.jpg","ar":1.333,"py":"","cr_by":"pdbellbutler","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":["大洋洲"]},{"id":1068,"seq":251,"zh":"Ecdeiocolea monostachya","en":"Ecdeiocolea monostachya","sci":"Ecdeiocolea monostachya","order_en":"Poales","order_zh":"禾本目","family_en":"Ecdeiocoleaceae","family_zh":"二柱草科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Ecdeiocolea monostachya is a species of grass-like plant in the family Ecdeiocoleaceae native to Western Australia. It was first described by Mueller in 1874. It is a perennial herb which grows in tufts 0.4 to 1 m (1.3 to 3.3 ft) high and 1 m (3.3 ft) wide.","img":"images/1068.jpg","thumb":"images/t/1068.jpg","file":"Ecdeiocolea monostachya - Flickr - Kevin Thiele.jpg","ar":0.655,"py":"","cr_by":"Kevin Thiele from Perth, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"禾草","origin":["大洋洲"]},{"id":1069,"seq":252,"zh":"须叶藤","en":"Flagellaria indica","sci":"Flagellaria indica","order_en":"Poales","order_zh":"禾本目","family_en":"Flagellariaceae","family_zh":"须叶藤科","iucn":null,"langs":17,"desc_zh":"印度鞭藤（学名：Flagellaria indica），又名角仔藤、芦竹藤、须叶藤，台湾话亦称藤竹仔（台罗：tîn-tik-á），为须叶藤科须叶藤属下的一种木质藤本植物，可长到15米长。 种名indica意为印度的。","desc_en":"Flagellaria indica is a climbing plant found in many of the tropical and subtropical regions of the Old World, in India, Bangladesh, Southeast Asia, Polynesia, and Australia.","img":"images/1069.jpg","thumb":"images/t/1069.jpg","file":"印度鞭藤 Flagellaria indica 20210527105931 08.jpg","ar":1.333,"py":"xuyeteng xyt","cr_by":"Ping an Chang","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","大洋洲"]},{"id":1070,"seq":253,"zh":"Joinvillea plicata","en":"Joinvillea plicata","sci":"Joinvillea plicata","order_en":"Poales","order_zh":"禾本目","family_en":"Joinvilleaceae","family_zh":"拟苇科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Joinvillea plicata is a flowering plant species, one of four in the genus Joinvillea. It is found in New Caledonia and is considered a common plant by the natives.","img":"images/1070.jpg","thumb":"images/t/1070.jpg","file":"Joinvillea plicata 1 (scott.zona).jpg","ar":0.678,"py":"","cr_by":"Scott Zona from USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["大洋洲"]},{"id":1071,"seq":254,"zh":"花水藓","en":"Mayaca fluviatilis","sci":"Mayaca fluviatilis","order_en":"Poales","order_zh":"禾本目","family_en":"Mayacaceae","family_zh":"花水藓科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Mayaca fluviatilis, also known as bog moss, is a perennial herbaceous submerged plant in the monogeneric family Mayacaceae. It is native to Central and South America, the Caribbean, and the United States where it is often sold as an aquarium plant.","img":"images/1071.jpg","thumb":"images/t/1071.jpg","file":"Mayaca fluviatilis flower.jpg","ar":1.333,"py":"huashuixian hsx","cr_by":"João Medeiros","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["北美洲","南美洲"]},{"id":1072,"seq":255,"zh":"Schoenocephalium teretifolium","en":"Schoenocephalium teretifolium","sci":"Schoenocephalium teretifolium","order_en":"Poales","order_zh":"禾本目","family_en":"Rapateaceae","family_zh":"偏穗草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Schoenocephalium teretifolium or Summertime Inírida flower (from the Spanish: Flor de Inírida de verano) is a monocot which is an endemic plant in the area between the Colombian rivers of Guainia and Inírida.","img":"images/1072.jpg","thumb":"images/t/1072.jpg","file":"Schoenocephalium teretifolium2.jpg","ar":1.501,"py":"","cr_by":"Mateo FERNÁNDEZ LUCERO Dep Ciencias Biológicas - Universidad de los Andes Bogotá","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":1073,"seq":256,"zh":"Apodasmia similis","en":"Apodasmia similis","sci":"Apodasmia similis","order_en":"Poales","order_zh":"禾本目","family_en":"Restionaceae","family_zh":"帚灯草科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Apodasmia similis, also known as oioi or jointed wire rush, is a plant that is endemic to New Zealand. It is a coastal plant but is also found around peat bogs and hot springs. It flowers from October to December and bears fruit from December to March.","img":"images/1073.jpg","thumb":"images/t/1073.jpg","file":"Apodasmia similis11.JPG","ar":1.156,"py":"","cr_by":"Rudolph89","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"禾草","origin":["大洋洲"]},{"id":1074,"seq":257,"zh":"Centrolepis pallida","en":"Centrolepis pallida","sci":"Centrolepis pallida","order_en":"Poales","order_zh":"禾本目","family_en":"Restionaceae","family_zh":"帚灯草科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Centrolepis pallida is a species of plant of the family Restionaceae. It is found in New Zealand, found both in the North and South Islands, and in the sub-Antarctic: Auckland Islands and Campbell Island).","img":"images/1074.jpg","thumb":"images/t/1074.jpg","file":"Centrolepis pallida 244354646.jpg","ar":1.333,"py":"","cr_by":"naturewatchwidow","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":["大洋洲"]},{"id":1075,"seq":258,"zh":"Sparganium gramineum","en":"Sparganium gramineum","sci":"Sparganium gramineum","order_en":"Poales","order_zh":"禾本目","family_en":"Sparganiaceae","family_zh":"黑三棱科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Sparganium gramineum is a species of flowering plant belonging to the family Typhaceae. Its native range is Norway to Japan.","img":"images/1075.jpg","thumb":"images/t/1075.jpg","file":"Sparganium gramineum 03fi.jpg","ar":0.75,"py":"","cr_by":"Höyhens","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":1076,"seq":259,"zh":"Prionium serratum","en":"Prionium serratum","sci":"Prionium serratum","order_en":"Poales","order_zh":"禾本目","family_en":"Thurniaceae","family_zh":"梭子草科","iucn":"LC","langs":15,"desc_zh":null,"desc_en":"Prionium serratum, the palmiet, is a robust, evergreen, semiaquatic, rhizomatous flowering plant growing to 2 m (6 ft 7 in) in height. It is the only species in the genus Prionium, and is endemic to South Africa (Cape Province and KwaZulu-Natal).","img":"images/1076.jpg","thumb":"images/t/1076.jpg","file":"Prionium serratum.jpg","ar":1.254,"py":"","cr_by":"Serban Proches","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["非洲"]},{"id":1077,"seq":260,"zh":"硬叶葱草","en":"Xyris complanata","sci":"Xyris complanata","order_en":"Poales","order_zh":"禾本目","family_en":"Xyridaceae","family_zh":"黄眼草科","iucn":"LC","langs":11,"desc_zh":"硬叶葱草（学名：Xyris complanata）为黄眼草科黄眼草属下的一个种，广泛分布于东南亚、南亚至澳洲。","desc_en":"Xyris complanata, known as the feathered yellow-eye is a tufted herb in the Xyridaceae family. It is native to southern China, India, Sri Lanka, Thailand, Cambodia, Laos, Vietnam, Malaysia, Indonesia (Java, Sulawesi, Kalimantan, Sumatra), the Philippines, New…","img":"images/1077.jpg","thumb":"images/t/1077.jpg","file":"N Xyrc D9741.JPG","ar":1.333,"py":"yingyecongcao yycc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","大洋洲"]},{"id":1078,"seq":261,"zh":"Xyris brevifolia","en":"Xyris brevifolia","sci":"Xyris brevifolia","order_en":"Poales","order_zh":"禾本目","family_en":"Xyridaceae","family_zh":"黄眼草科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Xyris brevifolia, the shortleaf yelloweyed grass, is a North American species of flowering plant in the yellow-eyed-grass family. It is native to Brazil, the West Indies, and the southeastern United States (Florida, Alabama, Georgia, and the Carolinas).","img":"images/1078.jpg","thumb":"images/t/1078.jpg","file":"Xyris brevifolia (Shortleaf Yellow eyed Grass).jpg","ar":1.509,"py":"","cr_by":"Bobyellow","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["北美洲","南美洲"]},{"id":264,"seq":262,"zh":"鸭跖草","en":"Commelina communis","sci":"Commelina communis","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":30,"desc_zh":"鸭跖草（学名：Commelina communis），古名鼻斫草，又名鸡舌草、淡竹叶、竹叶菜、碧蝉花，为鸭跖草科鸭跖草属一年生草本植物。原生于中国大陆的四川、云南、甘肃以东的区域、台湾、朝鲜、俄罗斯远东地区、日本、越南，也引入到了欧洲中部和东南部以及北美东部的部分地区，成为一种有害的杂草，模式标本采自北美。常见于路边阴凉处，花由两个较大的蓝色花瓣和一个较小的白色花瓣组成。","desc_en":"Commelina communis the Asiatic dayflower, is an herbaceous annual plant in the dayflower family. It gets its name because the blooms last for only one day. It is native throughout much of East Asia and northern parts of Southeast Asia.","img":"images/264.jpg","thumb":"images/t/264.jpg","file":"C.communis after rain.jpg","ar":1.202,"py":"yazhicao yzc","cr_by":"EHM02667","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":265,"seq":263,"zh":"吊竹梅","en":"Tradescantia zebrina","sci":"Tradescantia zebrina","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":30,"desc_zh":"吊竹梅（学名：Tradescantia zebrina），又名吊竹草、水龟草，鸭跖草科紫万年青属下多年生常绿蔓生草本植物。原生于墨西哥与中美地带，如今在亚洲、非洲、澳洲、南美洲等地都已普及。台湾于1909年引进，全岛各地普遍栽培，并驯化成野生；喜生于溪边，路旁阴湿地。吊竹梅因适宜吊盆栽植，因而得名。","desc_en":"Tradescantia zebrina, formerly known as Zebrina pendula, is a species of creeping plant in the Tradescantia genus. Common names include silver inch plant and wandering Jew. The latter name is controversial, and some now use the alternative wandering dude.","img":"images/265.jpg","thumb":"images/t/265.jpg","file":"Zebrina pendula 20060521 2 closer.jpg","ar":1.286,"py":"diaozhumei dzm","cr_by":"Ruestz (upload 13:54, 11 January 2008)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":266,"seq":264,"zh":"紫背万年青","en":"Tradescantia spathacea","sci":"Tradescantia spathacea","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":28,"desc_zh":"紫背万年青（学名：Tradescantia spathacea），又称青红兰、蚌兰、荷包兰、蚌花、小蚌花，为药食两用植物。多年生草本植物，高20～50厘米。茎多分枝，带肉质，紫红色，下部匍匐状，节上常生须根，上部近于直立。叶互生，披针形。原产于墨西哥。","desc_en":"Tradescantia spathacea, also called the oyster plant, boatlily or 'Moses-in-the-cradle', is an herb in the Commelinaceae family which was first described in 1788. It is native to Central America.","img":"images/266.jpg","thumb":"images/t/266.jpg","file":"Tradescantia spathacea-Yucatan.jpg","ar":1.093,"py":"zibeiwannianqing zbwnq","cr_by":"Jim Conrad","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["北美洲"]},{"id":267,"seq":265,"zh":"淡色紫露草","en":"Tradescantia pallida","sci":"Tradescantia pallida","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":28,"desc_zh":"淡色紫露草（学名：Tradescantia pallida）是鸭跖草科紫露草属多年生草本植物，其种加词pallida 意为“淡色的”。原产墨西哥。其紫叶品种称为紫竹梅、紫锦草（Tradescantia pallida 'Purpurea'），是一种常见的观赏植物。","desc_en":"Tradescantia pallida is a species of spiderwort native to the Gulf Coast region of eastern Mexico. It is a perennial herbaceous species with a trailing habit. The cultivar T.","img":"images/267.jpg","thumb":"images/t/267.jpg","file":"Tradescantia pallida-IMG 20180707 120135.jpg","ar":1.333,"py":"dansezilucao dszlc","cr_by":"Sun Jiao (Interaccoonale)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["北美洲"]},{"id":269,"seq":266,"zh":"水葫芦","en":"Eichhornia crassipes","sci":"Eichhornia crassipes","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Pontederiaceae","family_zh":"雨久花科","iucn":null,"langs":53,"desc_zh":"凤眼蓝（学名：Pontederia crassipes），或称凤眼莲、军舰莲、水葫芦，是一种原产于南美洲亚马逊河流域属于雨久花科梭鱼草属的一种漂浮性水生植物。凤眼蓝曾一度被很多国家引进，广泛分布与世界各地，亦被列入世界百大外来入侵种之一。","desc_en":"Pontederia crassipes (formerly Eichhornia crassipes), commonly known as common water hyacinth, is an aquatic plant native to South America, naturalized throughout the world, and often invasive outside its native range.","img":"images/269.jpg","thumb":"images/t/269.jpg","file":"Pontederia crassipes in native habitat, Transpantaneira, Poconé, Mato Grosso, Brazil.jpg","ar":1.658,"py":"shuihulu shl","cr_by":"Bernard DUPONT","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["南美洲"]},{"id":1079,"seq":267,"zh":"长药袋鼠爪","en":"Anigozanthos manglesii","sci":"Anigozanthos manglesii","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Haemodoraceae","family_zh":"血皮草科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Anigozanthos manglesii, commonly known as the red-and-green kangaroo paw, Mangles' kangaroo paw, or Nyungar: kurulbrang, is a plant species endemic to Western Australia, and the floral emblem of that state. The flower has become symbolic of the region.","img":"images/1079.jpg","thumb":"images/t/1079.jpg","file":"Anigozanthos manglesii, Eaton.JPG","ar":1.401,"py":"changyaodaishuzhua cydsz","cr_by":"Public domain Public domain false false This work has been released into the public domain by its author, Cygnis insigni","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["大洋洲"]},{"id":1080,"seq":268,"zh":"田葱","en":"Philydrum lanuginosum","sci":"Philydrum lanuginosum","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Philydraceae","family_zh":"田葱科","iucn":null,"langs":11,"desc_zh":"田葱（学名：Philydrum lanuginosum）为田葱科田葱属下的一个种。","desc_en":"Philydrum is a genus of tufted, herbaceous, aquatic macrophyte plants, one of three genera constituting the plant family Philydraceae. Philydrum lanuginosum is the sole known species. They are commonly known as frogsmouths and woolly waterlilies.","img":"images/1080.jpg","thumb":"images/t/1080.jpg","file":"Philydrum lanuginosum.jpg","ar":0.571,"py":"tiancong tc","cr_by":"John Sims","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":270,"seq":269,"zh":"姜","en":"ginger","sci":"Zingiber officinale","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":165,"desc_zh":"姜（学名：Zingiber officinale），为姜科姜属的植物，原产于海洋东南亚，最早由南岛民族培植。姜开有黄绿色的花和辣味的根茎。根茎鲜品或干品可以作为调味品。姜经过泡制作为中药药材之一，也可以冲泡为草本茶。姜耕种起源于亚洲并拥有悠久历史，目前在印度、东南亚、西非和加勒比地区生产也见增长。","desc_en":"Ginger (Zingiber officinale) is a flowering plant whose rhizome, ginger root or ginger, is widely used as a spice and a folk medicine. It is an herbaceous perennial that grows annual pseudostems (false stems made of the rolled bases of leaves) about one meter…","img":"images/270.jpg","thumb":"images/t/270.jpg","file":"Koeh-146-no text.jpg","ar":0.768,"py":"jiang j","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"],"illus_img":"images/i/270.jpg","illus_thumb":"images/i/t/270.jpg","illus_file":"Zingiber officinale - Köhler–s Medizinal-Pflanzen-146.jpg","illus_ar":0.726,"illus_by":"Franz Eugen Köhler","illus_lic":"Public domain","illus_licurl":null},{"id":271,"seq":270,"zh":"姜黄","en":"Curcuma longa","sci":"Curcuma longa","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":127,"desc_zh":"姜黄（学名：Curcuma longa），又称宝鼎香，为姜科姜黄属植物，在一些亚洲国家称作turmeric或kunyit。其根茎所磨成的深黄色粉末为咖哩的主要成份之一，也用在南洋料理，尝起来味苦而辛，带点土味。主成分姜黄素（curcumin）具有一些医疗保健的效果，因此姜黄也出现在中医药材中。","desc_en":"Turmeric (), or Curcuma longa (), is a flowering plant in the ginger family Zingiberaceae. It is a perennial, rhizomatous, herbaceous plant native to the Indian subcontinent and Southeast Asia that requires temperatures between 20 and 30 °C (68 and 86 °F) and…","img":"images/271.jpg","thumb":"images/t/271.jpg","file":"Curcuma longa roots.jpg","ar":2.429,"py":"jianghuang jh","cr_by":"Simon A. Eugster","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/271.jpg","illus_thumb":"images/i/t/271.jpg","illus_file":"Curcuma longa - Köhler–s Medizinal-Pflanzen-199.jpg","illus_ar":0.818,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":272,"seq":271,"zh":"小豆蔻","en":"Elettaria cardamomum","sci":"Elettaria cardamomum","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":null,"langs":68,"desc_zh":"小豆蔻（学名：Elettaria cardamomum；英语：true cardamom），又名印度小豆蔻、细豆蔻、绿豆蔻、苏泣迷罗、素泣谜罗香（梵语：सूक्ष्मैला，罗马化：sūkṣmailā），香港坊间香料舖称之为青砂仁，是一种姜科多年生的草本植物。喜欢生长在山坡边阴凉潮湿的地方。小豆蔻是一种烹调香料、种子可以做中药。 多年生草本。根茎粗壮，棕红色。叶两列，叶片狭长披针状，叶鞘具棕黄色柔毛。穗状花序由茎基部抽出。","desc_en":"Elettaria cardamomum, commonly known as green cardamom or true cardamom, is a herbaceous, perennial plant in the ginger family, native to southern India. It is the most common of the species whose seeds are used as a spice called cardamom that has a strong aro…","img":"images/272.jpg","thumb":"images/t/272.jpg","file":"ElettariaCardamomum.jpg","ar":1.333,"py":"xiaodoukou xdk","cr_by":"Chhe ( talk )","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"],"illus_img":"images/i/272.jpg","illus_thumb":"images/i/t/272.jpg","illus_file":"Elettaria cardamomum - Köhler–s Medizinal-Pflanzen-057.jpg","illus_ar":0.773,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":273,"seq":272,"zh":"白莪术","en":"Curcuma zedoaria","sci":"Curcuma zedoaria","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":44,"desc_zh":"白莪术（zhú）（学名：Curcuma zedoaria）为姜科姜黄属多年生草本植物，原产南亚，东亚不产。中国栽培的莪术（学名：Curcuma phaeocaulis）过去常误作本种。","desc_en":"Curcuma zedoaria (zedoary , white turmeric, or temu putih) is a perennial herb and member of the genus Curcuma, family Zingiberaceae. The plant is native to South Asia and Southeast Asia but is now naturalized in other places including the US state of Florida.","img":"images/273.jpg","thumb":"images/t/273.jpg","file":"Curcuma zedoaria - Köhler–s Medizinal-Pflanzen-048.jpg","ar":0.731,"py":"baieshu bes","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","北美洲"],"illus_img":"images/i/273.jpg","illus_thumb":"images/i/t/273.jpg","illus_file":"Curcuma zedoaria - Köhler–s Medizinal-Pflanzen-048.jpg","illus_ar":0.731,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":274,"seq":273,"zh":"大高良姜","en":"Alpinia galanga","sci":"Alpinia galanga","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":null,"langs":44,"desc_zh":"大高良姜（学名：Alpinia galanga），别称高良姜、大良姜、南姜、 山姜、廉姜、良姜、良姜子、红豆蔻、红豆扣、红扣、红蔻、番郁金、诺卡及郭哈等 ，在粤菜烹饪的专业术语中称潮汕姜 ，为姜科山姜属植物。","desc_en":"Alpinia galanga, a plant in the ginger family, bears a rhizome used largely as an herb in Unani medicine and as a spice in Southeast Asian cookery. It is one of four plants known as \"galangal\".","img":"images/274.jpg","thumb":"images/t/274.jpg","file":"Alpinia officinarum - Köhler–s Medizinal-Pflanzen-156.jpg","ar":0.747,"py":"dagaoliangjiang dglj","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":275,"seq":274,"zh":"山柰","en":"Kaempferia galanga","sci":"Kaempferia galanga","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":39,"desc_zh":"山柰（学名：Kaempferia galanga）亦称三柰、沙姜、番郁金、三藾、山辣、土麝香、埔姜花，是一种姜科山柰属的植物。","desc_en":"Kaempferia galanga, commonly known as kencur, aromatic ginger, sand ginger, cutcherry, is a monocotyledonous plant in the ginger family, and one of four plants called galangal.","img":"images/275.jpg","thumb":"images/t/275.jpg","file":"Galangal.web.jpg","ar":0.623,"py":"shannai sn","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":277,"seq":275,"zh":"马尼拉麻蕉","en":"Musa textilis","sci":"Musa textilis","order_en":"Zingiberales","order_zh":"姜目","family_en":"Musaceae","family_zh":"芭蕉科","iucn":"NT","langs":54,"desc_zh":"马尼拉麻蕉（学名：Musa textilis），又称马尼拉麻，属芭蕉科（Musaceae），原产菲律宾，广泛生长在婆罗洲和苏门答腊岛。至今，菲律宾仍是世界是最大的蕉麻生产国。本植物虽然称为马尼拉蕉麻，但属于芭蕉科植物，与真麻无亲缘关系。 多年生草本，形似芭蕉，茎直立柔软，由粗厚的叶鞘包迭而成柱状；叶很大，钜圆形，螺旋排列；穗状花序，单性花。浆果似香蕉。从根茎可生长出多至25个不含有纤维的肉质枝茎，丛生成环形。","desc_en":"Abacá ( ah-bə-KAH; Filipino: abaka [ɐbɐˈka]), also known as Manila hemp, is a species of banana, Musa textilis, endemic to the Philippines. The plant grows to 13–22 feet (4.0–6.","img":"images/277.jpg","thumb":"images/t/277.jpg","file":"Abaca Tree.jpg","ar":1.501,"py":"manilamajiao mnlmj","cr_by":"MarvinBikolano","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":278,"seq":276,"zh":"小果野蕉","en":"Musa acuminata","sci":"Musa acuminata","order_en":"Zingiberales","order_zh":"姜目","family_en":"Musaceae","family_zh":"芭蕉科","iucn":"LC","langs":36,"desc_zh":"小果野蕉（学名：Musa acuminata）又名尖蕉、香蕉，为芭蕉科芭蕉属的植物。分布在越南、泰国、缅甸、马来西亚、菲律宾、印度以及中国大陆的云南、广西等地，生长于海拔1,000米至1,200米的地区，多生长于沼泽、半沼泽、阴湿的沟谷或坡地上。 本种也是杂交种香蕉（M. x paradisiaca）的亲本之一，香蕉另一亲本则为野蕉（M. balbisiana）。","desc_en":"Musa acuminata is a species of banana native to Southern Asia, its range comprising the Indian subcontinent and Southeast Asia. Many of the modern edible dessert bananas are derived from this species, although some are hybrids with Musa balbisiana.","img":"images/278.jpg","thumb":"images/t/278.jpg","file":"Bananapao.JPG","ar":1.36,"py":"xiaoguoyejiao xgyj","cr_by":"Jorgemach7","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":1081,"seq":277,"zh":"大蕉","en":"Musa × paradisiaca","sci":"Musa × paradisiaca","order_en":"Zingiberales","order_zh":"姜目","family_en":"Musaceae","family_zh":"芭蕉科","iucn":null,"langs":36,"desc_zh":"香蕉（学名：Musa × paradisiaca），又名甘蕉、芎蕉、芽蕉，弓蕉（闽南语：king-tsio/kin-tsio；客家话：Khiûng-tsiâu），泛指芭蕉科芭蕉属小果野蕉（M. acuminata）及野蕉（M. balbisiana）之间自然或人工杂交的任何栽培种，广泛栽种于热带、亚热带地区。","desc_en":"Musa × paradisiaca is a species as well as a cultivar, originating as the hybrid between Musa acuminata and Musa balbisiana, cultivated and domesticated by humans very early.","img":"images/1081.jpg","thumb":"images/t/1081.jpg","file":"2018 06 TropicalIslands IMG 2170.jpg","ar":0.918,"py":"dajiao dj","cr_by":"Daniela Kloth","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":null,"origin":null},{"id":279,"seq":278,"zh":"美人蕉","en":"Canna indica","sci":"Canna indica","order_en":"Zingiberales","order_zh":"姜目","family_en":"Cannaceae","family_zh":"美人蕉科","iucn":null,"langs":46,"desc_zh":"美人蕉（学名：Canna indica）是美人蕉科美人蕉属的植物。原产于西印度群岛，墨西哥和美国东南部（佛罗里达州，得克萨斯州，路易斯安那州和南卡罗来纳州）。地下根茎富含淀粉，可食。几千年来一直是美洲原住民种植的一种小型粮食作物。它也在撒哈拉以南非洲的大部分地区及东南亚和大洋洲归化。分布于印度以及中国大陆的南部和西南部等地，生长于海拔800米的地区，目前已由人工引种栽培，作为传统旱藕的替代品，制作粉丝。种名indica意为印度的。","desc_en":"Canna indica, commonly known as Indian shot, African arrowroot, edible canna, purple arrowroot, Sierra Leone arrowroot, is a plant species in the family Cannaceae. It is native to the Americas and naturalized elsewhere.","img":"images/279.jpg","thumb":"images/t/279.jpg","file":"00 3890 Indisches Blumenrohr (Canna indica).jpg","ar":0.667,"py":"meirenjiao mrj","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/279.png","illus_thumb":"images/i/t/279.png","illus_file":"Himalayan Canna. Canna indica. Thornton, R.J., New illustration of the sexual system of Carolus von Linnaeus and the temple of Flora, or garden of nature, t. (1807) (14464577467).png","illus_ar":0.734,"illus_by":"Swallowtail Garden Seeds from Santa Rosa, California, United States","illus_lic":"Public domain","illus_licurl":null},{"id":280,"seq":279,"zh":"旅人蕉","en":"Ravenala madagascariensis","sci":"Ravenala madagascariensis","order_en":"Zingiberales","order_zh":"姜目","family_en":"Strelitziaceae","family_zh":"鹤望兰科","iucn":"LC","langs":51,"desc_zh":"旅人蕉 （学名：Ravenala madagascariensis ），别称旅人木、散尾葵、扁芭槿、扇芭蕉、水木等，属姜目鹤望兰科，为旅人蕉属下的单属种 植物，原产于马达加斯加。由于叶鞘呈杯状能贮存大量水液，其树液亦可饮用，供旱漠旅人提供紧急的水源，故而得名旅人蕉。 其种加词“madagascariensis”意为“马达加斯加的”。马达加斯加国徽有旅人蕉的叶片图案。","desc_en":"Ravenala madagascariensis, commonly known as the traveller's tree, fan palm, traveller's palm or East-West palm, is a species of monocotyledonous flowering plant found in Madagascar. It is not a true palm but a member of the family Strelitziaceae.","img":"images/280.jpg","thumb":"images/t/280.jpg","file":"Ravenala madagascariensis, Atsinanana, Madagascar 1.jpg","ar":0.667,"py":"lrenjiao lrj","cr_by":"kristofz","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["非洲"]},{"id":281,"seq":280,"zh":"斑叶竹芋","en":"Maranta arundinacea","sci":"Maranta arundinacea","order_en":"Zingiberales","order_zh":"姜目","family_en":"Marantaceae","family_zh":"竹芋科","iucn":null,"langs":43,"desc_zh":"葛郁金（学名：Maranta arundinacea），又称竹芋、竹薯、粉薯、太白薯、太白笋、美人蕉、藕仔薯或金笋，为一多年生植物，常见于热带雨林。葛郁金所制成的淀粉常在餐饮烹饪上用于勾芡等用途，其使用最早可追溯至西元前8200年的南美洲北部。","desc_en":"Maranta arundinacea, also known as arrowroot, maranta, West Indian arrowroot, obedience plant or Bermuda arrowroot is a large, perennial herb found in rainforest habitats of the Americas, but cultivated in tropical regions worldwide.","img":"images/281.jpg","thumb":"images/t/281.jpg","file":"Forraçao2.jpg","ar":1.333,"py":"banyezhuyu byzy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":282,"seq":281,"zh":"翅果竹芋","en":"Thaumatococcus daniellii","sci":"Thaumatococcus daniellii","order_en":"Zingiberales","order_zh":"姜目","family_en":"Marantaceae","family_zh":"竹芋科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Thaumatococcus daniellii, also known as miracle fruit, is a plant species from tropical Africa of the Marantaceae (arrowroot and prayer plant) family. It is a large, rhizomatous, flowering herb native to the rainforests of western Africa in Sierra Leone, south…","img":"images/282.jpg","thumb":"images/t/282.jpg","file":"Moimoi.JPG","ar":1.333,"py":"chiguozhuyu cgzy","cr_by":"Zz411 at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["非洲"]},{"id":1082,"seq":282,"zh":"豹纹竹芋","en":"Maranta leuconeura","sci":"Maranta leuconeura","order_en":"Zingiberales","order_zh":"姜目","family_en":"Marantaceae","family_zh":"竹芋科","iucn":null,"langs":19,"desc_zh":"豹纹竹芋（学名：Maranta leuconeura）为竹芋科竹芋属下一个多年生草本观叶植物。原生于南美。英文亦名Prayer plant/祈祷植物。中文别称不少如祈祷花、豹斑竹芋、绿脉竹芋等等。豹纹竹芋的叶片斑块形似豹纹因而得名。","desc_en":"Maranta leuconeura, widely known as the prayer plant due to its daily sunlight-dependent movements (which are said to resemble hands \"in-prayer\"), is a species of flowering plant in the family Marantaceae native to the Brazilian tropical forests.","img":"images/1082.jpg","thumb":"images/t/1082.jpg","file":"Maranta leuconeura3.jpg","ar":1.333,"py":"baowenzhuyu bwzy","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["南美洲"]},{"id":1083,"seq":283,"zh":"闭鞘姜","en":"Cheilocostus speciosus","sci":"Cheilocostus speciosus","order_en":"Zingiberales","order_zh":"姜目","family_en":"Costaceae","family_zh":"闭鞘姜科","iucn":"LC","langs":31,"desc_zh":"闭鞘姜（学名：Costus speciosus），又称绢毛鸢尾，为闭鞘姜科闭鞘姜属下的一个种。它是闭鞘姜属最常见的一个种植种，原产于东南亚和周边的印度、中国及昆士兰地区，后来又引种到了西印度群岛等世界其他地区。闭鞘姜科(Costaceae)下的植物过去与姜(Zingiber officinale Roscoe)及姜黄(Curcuma longa L.","desc_en":"Hellenia speciosa, or crêpe ginger, is a species of flowering plant in the family Costaceae. It is a herbaceous perennial rhizomatous geophyte which is also known by Cheilocostus speciosus and other botanical names.","img":"images/1083.jpg","thumb":"images/t/1083.jpg","file":"Cheilocostus speciosus.jpg","ar":0.75,"py":"biqiaojiang bqj","cr_by":"( Hans Hillewaert )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","大洋洲"]},{"id":1084,"seq":284,"zh":"金鸟赫蕉","en":"Heliconia rostrata","sci":"Heliconia rostrata","order_en":"Zingiberales","order_zh":"姜目","family_en":"Heliconiaceae","family_zh":"赫蕉科","iucn":null,"langs":21,"desc_zh":"金鸟赫蕉（学名：Heliconia rostrata），为赫蕉科赫蕉属下的一种多年生宿跟草本植物。原生于南美洲亚马逊河流域当中，现今世界热带地区均有广泛栽培。因花序形态又名垂花赫蕉、垂花蝎尾蕉、金嘴蝎尾蕉。","desc_en":"Heliconia rostrata, the hanging lobster claw or false bird of paradise, is a herbaceous perennial plant native to El Salvador, Peru, Bolivia, Colombia, Venezuela, Costa Rica, and Ecuador, and naturalized in Puerto Rico.","img":"images/1084.jpg","thumb":"images/t/1084.jpg","file":"Heliconia rostrata 2.jpg","ar":1.333,"py":"jinniaohejiao jnhj","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["南美洲"]},{"id":283,"seq":285,"zh":"金鱼藻","en":"Ceratophyllum demersum","sci":"Ceratophyllum demersum","order_en":"Ceratophyllales","order_zh":"金鱼藻目","family_en":"Ceratophyllaceae","family_zh":"金鱼藻科","iucn":"LC","langs":35,"desc_zh":"金鱼藻（学名：Ceratophyllum demersum），又称作松藻、鱼草、细草、软草，有时根据英文名coontail直译为浣熊尾巴草，为金鱼藻科金鱼藻属底下的一物种。其生活型态可为沉水型，亦可为浮水型。除南极洲外，世界各大陆都有其原生分布。对纽西兰而言，金鱼藻是一种有害的外来水藻。同时，其为一种广受欢迎的水生植物。","desc_en":"Ceratophyllum demersum, commonly known as hornwort (a common name shared with the unrelated Anthocerotophyta), rigid hornwort, coontail, or coon's tail, is a species of flowering plant in the genus Ceratophyllum.","img":"images/283.jpg","thumb":"images/t/283.jpg","file":"Ceratophyllum demersum 2010-8-14 RioMontoro SierraMadrona.jpg","ar":1.333,"py":"jinyuzao jyz","cr_by":"Javier martin","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/283.jpg","illus_thumb":"images/i/t/283.jpg","illus_file":"Illustration Ceratophyllum demersum0.jpg","illus_ar":0.593,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":284,"seq":286,"zh":"家黑种草","en":"Nigella sativa","sci":"Nigella sativa","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":83,"desc_zh":"家黑种草（学名：Nigella sativa；属名是拉丁语“黑色”niger的指小词，种加词意思是“栽培的”），古称草豉（《本草拾遗》）、少尼子（《回回药方》；阿拉伯语：شونيز，罗马化：shūnīz/shawnīz）、香黑子（《回回药方》），也叫黑葛缕、黑孜然、茴香花、瘤果黑种草，是毛茛科黑种草属一年生草本植物，原产西亚，在欧洲、北非、南亚、中亚亦常见栽培。其种子可炼成黑籽油。","desc_en":"Nigella sativa (common names, black caraway, black cumin, nigella, charnushka, or kalonji) is an annual flowering plant in the family Ranunculaceae, native to western Asia (the Levant, Cyprus, Turkey, Iran and Iraq), and eastern Europe (Bulgaria and Romania).","img":"images/284.jpg","thumb":"images/t/284.jpg","file":"Nigella sativa - Köhler–s Medizinal-Pflanzen-227.jpg","ar":0.825,"py":"jiaheizhongcao jhzc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/284.jpg","illus_thumb":"images/i/t/284.jpg","illus_file":"Nigella sativa - Köhler–s Medizinal-Pflanzen-227.jpg","illus_ar":0.825,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":285,"seq":287,"zh":"驴蹄草","en":"Caltha palustris","sci":"Caltha palustris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":"LC","langs":61,"desc_zh":"驴蹄草（学名：Trollius paluster）是一种属于毛茛科驴蹄草属的多年生草本植物，又名驴蹄菜、沼泽金盏花（Marsh Marigold）、立金花。原产于北半球的温带地区，包括欧洲的冰岛与俄罗斯北极地区，亚洲温带与北极地区及北美洲。","desc_en":"Caltha palustris, known as marsh-marigold and kingcup, is a small to medium sized perennial herbaceous plant of the buttercup family, native to marshes, fens, ditches and wet woodland in temperate regions of the Northern Hemisphere.","img":"images/285.jpg","thumb":"images/t/285.jpg","file":".00 1402 Sumpfdotterblume - (Caltha palustris).jpg","ar":1.506,"py":"lticao ltc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null,"illus_img":"images/i/285.jpg","illus_thumb":"images/i/t/285.jpg","illus_file":"Illustration Caltha palustris1.jpg","illus_ar":0.621,"illus_by":"Prof. Dr. Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":286,"seq":288,"zh":"高毛茛","en":"Ranunculus acris","sci":"Ranunculus acris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":61,"desc_zh":"草甸毛茛（学名：Ranunculus acris），又称为高毛茛、普通毛茛，是毛茛科毛茛属的一种植物，原产于欧洲与欧亚大陆温带地区。","desc_en":"Ranunculus acris is a species of flowering plant in the family Ranunculaceae, and is one of the more common buttercups across Europe and temperate Eurasia. Common names include meadow buttercup, tall buttercup, common buttercup and giant buttercup.","img":"images/286.jpg","thumb":"images/t/286.jpg","file":"Ranunculus acris niittyleinikki.jpg","ar":0.551,"py":"gaomaogen gmg","cr_by":"Alinja","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/286.jpg","illus_thumb":"images/i/t/286.jpg","illus_file":"Ranunculus acris illustration 1794.jpg","illus_ar":0.63,"illus_by":"Johann Samuel Halle 1727-1810","illus_lic":"Public domain","illus_licurl":null},{"id":287,"seq":289,"zh":"匍枝毛茛","en":"Ranunculus repens","sci":"Ranunculus repens","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":57,"desc_zh":"匍枝毛茛（学名：Ranunculus repens）为毛茛科毛茛属下的一个种。","desc_en":"Ranunculus repens, the creeping buttercup, is a flowering plant in the buttercup family Ranunculaceae, native to Europe, Asia and northwestern Africa. It is also called creeping crowfoot and (along with restharrow) sitfast.","img":"images/287.jpg","thumb":"images/t/287.jpg","file":"Creeping butercup close 800.jpg","ar":1.187,"py":"puzhimaogen pzmg","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/287.jpg","illus_thumb":"images/i/t/287.jpg","illus_file":"Ranunculus repens Lindman DESC.JPG","illus_ar":1.734,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":288,"seq":290,"zh":"欧洲乌头","en":"Aconitum napellus","sci":"Aconitum napellus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":"LC","langs":56,"desc_zh":"欧洲乌头（学名：Aconitum napellus）为毛莨科乌头属的多年生植物。分布于欧洲，生长在遮阴潮湿的土壤。为耐寒多年生草本，叶互生叶片深裂，为多叶茎，总状花序高长且密集，由淡紫色的盔形小花组成，于初夏开放。全株有毒，其块根的根节是植物中最强的神经毒素之一。","desc_en":"Aconitum napellus, monkshood, aconite, Venus' chariot or wolfsbane, is a species of highly toxic flowering plants in the genus Aconitum of the family Ranunculaceae, native and endemic to western and central Europe.","img":"images/288.jpg","thumb":"images/t/288.jpg","file":"Aconitum napellus 230705.jpg","ar":0.554,"py":"ouzhouwutou ozwt","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/288.jpg","illus_thumb":"images/i/t/288.jpg","illus_file":"Aconitum napellus - Köhler–s Medizinal-Pflanzen-151.jpg","illus_ar":0.722,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":289,"seq":291,"zh":"栎林银莲花","en":"Anemone nemorosa","sci":"Anemone nemorosa","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":54,"desc_zh":"丛林银莲花（学名：Anemonoides nemorosa）是毛茛科西南银莲花属的一种植物，原产于欧洲。","desc_en":"Anemonoides nemorosa (syn. Anemone nemorosa), the wood anemone, also historically known as windflower because of William Turner's interpretation of its Latin name anemone in his 1551 New Herball, is an early spring flowering plant in the buttercup family Ranun…","img":"images/289.jpg","thumb":"images/t/289.jpg","file":".00 2814 Blüte des Buschwindröschen (Anemone nemorosa).jpg","ar":0.75,"py":"lilinyinlianhua llylh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/289.jpg","illus_thumb":"images/i/t/289.jpg","illus_file":"Illustration Anemone nemorosa0.jpg","illus_ar":0.605,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":290,"seq":292,"zh":"葡萄叶铁线莲","en":"Clematis vitalba","sci":"Clematis vitalba","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":53,"desc_zh":"白藤铁线莲（学名：Clematis vitalba），常误译为葡萄叶铁线莲，是一种富有韧性的多年生的木质藤本植物，拥有木质茎，能攀爬至 20 至 30 公尺的高处。它在原生地通常见于白垩和石灰岩区，但经引进后，能在多种环境中茁壮，包括林地、森林边缘、开阔地区，甚至能在柳树丛生的河岸、废弃地和沿海及低地一带扎根。白藤铁线莲的快速蔓延会阻塞并破坏原始森林，导致原生植物消失。这种生态危害多发生在大量外来植物入侵或牲畜破坏栖地后。","desc_en":"Clematis vitalba (also known as old man's beard and traveller's joy) is a shrub in the genus Clematis of the family Ranunculaceae. It is native to Europe and western Asia.","img":"images/290.jpg","thumb":"images/t/290.jpg","file":"Clematis-vitalba-Waldrebe(Samenstand).jpg","ar":1.233,"py":"putaoyetiexianlian ptytxl","cr_by":"Michael Gasperl ( Migas )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/290.jpg","illus_thumb":"images/i/t/290.jpg","illus_file":"Illustration Clematis vitalba0.jpg","illus_ar":1.624,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":291,"seq":293,"zh":"日本獐耳细辛","en":"Hepatica nobilis","sci":"Hepatica nobilis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":52,"desc_zh":"三角草（学名：Hepatica nobilis），为毛茛科獐耳细辛属下的一个植物。","desc_en":"Anemone hepatica (syn. Hepatica nobilis), the common hepatica, liverwort, liverleaf, kidneywort, or pennywort, is a species of flowering plant in the buttercup family Ranunculaceae, native to woodland in temperate regions of the Northern Hemisphere.","img":"images/291.jpg","thumb":"images/t/291.jpg","file":"Hepatica nobilis plant.JPG","ar":1.333,"py":"ribenzhangerxixin rbzexx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/291.jpg","illus_thumb":"images/i/t/291.jpg","illus_file":"Hepatica nobilis Sturm05044.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":292,"seq":294,"zh":"榕叶毛茛","en":"Ficaria verna","sci":"Ficaria verna","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":50,"desc_zh":"榕叶毛茛（学名：Ficaria verna，原名Ranunculus ficaria），又称为小白屈菜，是毛茛科榕毛茛属的一种多年生植物，原产于欧洲与西亚。叶片深绿色有光泽，呈心形，花朵则为亮黄色。在引入北美后，榕叶毛茛被认为是一种会威胁当地生物多样性的入侵物种。 英国浪漫主义诗人威廉·华兹华斯尤为喜爱榕叶毛茛，他曾为其写过《致小白屈菜》（To the Small Celandine）等三首诗（以下为《致小白屈菜》摘录）：","desc_en":"Ficaria verna (formerly Ranunculus ficaria L.), commonly known as lesser celandine or pilewort, is a low-growing, hairless perennial flowering plant in the buttercup family Ranunculaceae.","img":"images/292.jpg","thumb":"images/t/292.jpg","file":"20150324Ficaria verna4.jpg","ar":1.333,"py":"rongyemaogen rymg","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":293,"seq":295,"zh":"春侧金盏花","en":"Adonis vernalis","sci":"Adonis vernalis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":47,"desc_zh":"春侧金盏花（学名：Adonis vernalis），又名春福寿草，是一种多年生的开花植物，生长在欧亚大陆的干旱草原及沙地。它们主要在潘诺尼亚平原及西西伯利亚平原，由西班牙至中欧及南欧，北至瑞典都有个别的群落。它们与其他欧洲的侧金盏花属不同，是在春天开花的，花朵直径长8厘米及有多达20枝鲜黄色的花瓣。 春侧金盏花存在极少量的毒性原理。但它吸收不良，因此中毒不太可能。含有刺激心脏的化合物，包括：阿多尼丁及乌头酸。它们也作为观赏植物。","desc_en":"Adonis vernalis, known variously as pheasant's eye, spring pheasant's eye, yellow pheasant's eye and false hellebore, is a perennial flowering plant in the buttercup family Ranunculaceae. It is found in dry meadows and steppes in Eurasia.","img":"images/293.jpg","thumb":"images/t/293.jpg","file":"Adonis vernalis gonsenheim.jpg","ar":1.275,"py":"chuncejinzhanhua ccjzh","cr_by":"Martin Bahmann","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"],"illus_img":"images/i/293.jpg","illus_thumb":"images/i/t/293.jpg","illus_file":"Adonis vernalis - Köhler–s Medizinal-Pflanzen-152.jpg","illus_ar":0.713,"illus_by":"Walther Müller, Carl Friedrich Schmidt (*1812), Published in Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":299,"seq":296,"zh":"罂粟","en":"Papaver somniferum","sci":"Papaver somniferum","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":95,"desc_zh":"罂粟（学名：Papaver somniferum），也叫罂子粟、御米、米囊、莺粟、鸦片罂粟、大烟，是罂粟科罂粟属一年生草本植物，是制取鸦片的主要原料，同时其提取物也是多种镇痛剂的来源，例如吗啡、蒂巴因、可待因、罂粟碱、那可汀。学名“somniferum”的意思是“催眠”，反映出它有麻醉性。罂粟的种子罂粟籽是重要的食物，其中含有对健康有益的油脂，可用于面包、饼干中烘焙，或制成酱料，使用于沙律中，也可制成罂粟籽油。","desc_en":"Papaver somniferum, commonly known as the opium poppy or breadseed poppy, is a species of flowering plant in the family Papaveraceae. It is the species of plant from which both opium and poppy seeds are derived and is also a valuable ornamental plant grown in…","img":"images/299.jpg","thumb":"images/t/299.jpg","file":"Papaver somniferum flowers.jpg","ar":1.172,"py":"yingsu ys","cr_by":"tanja niggendijker from apeldoorn, the netherlands","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/299.jpg","illus_thumb":"images/i/t/299.jpg","illus_file":"Papaver somniferum - Köhler–s Medizinal-Pflanzen-102.jpg","illus_ar":0.785,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":300,"seq":297,"zh":"虞美人","en":"Papaver rhoeas","sci":"Papaver rhoeas","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":89,"desc_zh":"虞美人（学名：Papaver rhoeas），又名丽春花、赛牡丹、满园春、仙女蒿、御仙花、雏芥子、雏罂粟、小种罂粟花、蝴蝶满园春，罂粟科罂粟属草本植物，花期夏季，花色有红、白、紫、蓝等颜色，浓艳华美。原产于亚欧温带大陆，在古代中国即有大量栽培，现已引种至新西兰、澳大利亚和北美。","desc_en":"Papaver rhoeas, with common names including common poppy, corn poppy, corn rose, field poppy, Flanders poppy, red poppy, and Odai, is an annual herbaceous species of flowering plant in the poppy family Papaveraceae.","img":"images/300.jpg","thumb":"images/t/300.jpg","file":"Papaver rhoeas LC0050.jpg","ar":0.659,"py":"yumeiren ymr","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","非洲"],"illus_img":"images/i/300.jpg","illus_thumb":"images/i/t/300.jpg","illus_file":"Papaver rhoeas - Köhler–s Medizinal-Pflanzen-101.jpg","illus_ar":0.696,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":301,"seq":298,"zh":"白屈菜","en":"Chelidonium majus","sci":"Chelidonium majus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":62,"desc_zh":"白屈菜（学名：Chelidonium majus）为罂粟科白屈菜属下的一个种。在中国大部分省区均有分布，沂源、博山山区有分布，以鲁山较为集中，生于山谷湿润地带。生于海拔500—2200米的山坡、山谷林缘草地或路旁、石缝。朝鲜半岛、日本、俄罗斯及欧洲也有分布。","desc_en":"Chelidonium majus, the greater celandine, is a perennial herbaceous flowering plant in the poppy family Papaveraceae. One of two species in the genus Chelidonium, it is native to Europe and western Asia and introduced widely in North America.","img":"images/301.jpg","thumb":"images/t/301.jpg","file":"Chelidonium majus bgiu.jpg","ar":1.333,"py":"baiqucai bqc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/301.jpg","illus_thumb":"images/i/t/301.jpg","illus_file":"Chelidonium majus (Köhler).jpg","illus_ar":0.749,"illus_by":"Hermann Adolf Köhler (1834 - 1879)","illus_lic":"Public domain","illus_licurl":null},{"id":302,"seq":299,"zh":"球果紫菫","en":"Fumaria officinalis","sci":"Fumaria officinalis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":52,"desc_zh":"球果紫菫（学名：Fumaria officinalis）为紫菫科烟堇属 下的一个种。","desc_en":"Fumaria officinalis, the common fumitory, drug fumitory or earth smoke, is a herbaceous annual flowering plant in the poppy family Papaveraceae. It is the most common species of the genus Fumaria in Western and Central Europe.","img":"images/302.jpg","thumb":"images/t/302.jpg","file":"(MHNT) Fumaria officinalis - Habit.jpg","ar":0.731,"py":"qiuguozijin qgzj","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/302.jpg","illus_thumb":"images/i/t/302.jpg","illus_file":"Illustration Fumaria officinalis0.jpg","illus_ar":0.666,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":303,"seq":300,"zh":"蓟罂粟","en":"Argemone mexicana","sci":"Argemone mexicana","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":47,"desc_zh":"蓟罂粟（学名：Argemone mexicana）为罂粟科蓟罂粟属下的一个种。其种加词“mexicana”意为“墨西哥的”。","desc_en":"Argemone mexicana, also known by the common names Mexican poppy, Mexican prickly poppy, flowering thistle, cardo, and cardosanto, is a species of poppy found in Mexico and now widely naturalized in many parts of the world.","img":"images/303.jpg","thumb":"images/t/303.jpg","file":"Argemone mexicana flower 2.jpg","ar":1.499,"py":"jiyingsu jys","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"],"illus_img":"images/i/303.jpg","illus_thumb":"images/i/t/303.jpg","illus_file":"The American Flora. Vol. 4, 1855 - pl. 28 Argemone mexicana (14781113534).jpg","illus_ar":0.7,"illus_by":"David William Moody","illus_lic":"Public domain","illus_licurl":null},{"id":304,"seq":301,"zh":"花菱草","en":"Eschscholzia californica","sci":"Eschscholzia californica","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":38,"desc_zh":"花菱草（学名：Eschscholzia californica，通俗名：加州罂粟、金英花），是罂粟科花菱草属的一种草本植物。其种加词“californica”意为“加利福尼亚的”。原产于美国西部及墨西哥，分布在美国的加州，向外延伸至俄勒冈州、华盛顿州、内华达州、亚利桑那州及新墨西哥州等地，在墨西哥则分布在索诺拉州及下加利福尼亚州西北部。生长在海拔零至二千公尺的草地及开阔地区。 花菱草是美国加州的州花，加州指定每年的四月六日为花菱草日。","desc_en":"Eschscholzia californica, the California poppy, golden poppy, Mexican poppy, California sunlight or cup of gold, is a species of flowering plant in the family Papaveraceae, native to the United States and Mexico.","img":"images/304.jpg","thumb":"images/t/304.jpg","file":"California poppy.jpg","ar":1.333,"py":"hualingcao hlc","cr_by":"Artslave","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["北美洲"],"illus_img":"images/i/304.jpg","illus_thumb":"images/i/t/304.jpg","illus_file":"Eschscholzia californica illustration valentien.jpg","illus_ar":0.64,"illus_by":"Albert Robert Valentien","illus_lic":"Public domain","illus_licurl":null},{"id":306,"seq":302,"zh":"刺小檗","en":"Berberis vulgaris","sci":"Berberis vulgaris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":64,"desc_zh":"刺檗（学名：Berberis vulgaris）是小檗科小檗属的植物。原产于欧洲中部和南部、北非和西亚等地区，落叶灌木，高达4米。叶长圆状匙形或倒卵形，长2-5厘米，宽1-2厘米。 果实可以食用，富含维生素C，但味道很酸，而且因刺多不易收获，所以在多数地区都未作为食物供人食用。通常是做成食品添加剂、果酱或果干。在伊朗有较大归模的种植，当地也常使用刺檗果干入菜，波斯语将这种果干称作Zereshk (زرشک)。伊朗也是刺檗果干的最大产地。","desc_en":"Berberis vulgaris, also known as common barberry, European barberry or simply barberry, is a shrub in the genus Berberis native to the Old World. It produces edible but sharply acidic berries, which people in many countries eat as a tart and refreshing fruit.","img":"images/306.jpg","thumb":"images/t/306.jpg","file":"Berberis vulgaris berries. - Flickr - gailhampshire.jpg","ar":1.778,"py":"cixiaobo cxb","cr_by":"gailhampshire from Cradley, Malvern, U.K","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":null,"illus_img":"images/i/306.jpg","illus_thumb":"images/i/t/306.jpg","illus_file":"Illustration Berberis vulgaris0.jpg","illus_ar":0.602,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":307,"seq":303,"zh":"俄勒冈十大功劳","en":"Mahonia aquifolium","sci":"Mahonia aquifolium","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":36,"desc_zh":"北美十大功劳（学名：Mahonia aquifolium）是一种常绿小灌木，为十大功劳属的模式种。","desc_en":"Berberis aquifolium, the Oregon grape, holly-leaved barberry, or Mahonia, is a North American species of flowering plant in the family Berberidaceae. It is an evergreen shrub growing up to 3 metres (10 ft) tall and 1.5 m (5 ft) wide.","img":"images/307.jpg","thumb":"images/t/307.jpg","file":"Mahonia aquifolium.jpg","ar":1.473,"py":"elegangshidagonglao elgsdgl","cr_by":"The original uploader was Meggar at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["北美洲"]},{"id":308,"seq":304,"zh":"日本小檗","en":"Berberis thunbergii","sci":"Berberis thunbergii","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":32,"desc_zh":"日本小檗（学名：Berberis thunbergii），为小檗科小檗属的植物。分布于日本以及中国大陆的大部分省区等地，目前广泛采用为园林植物，是小檗属中载培最广泛的种之一。 花期4-6月，果期7-10月。","desc_en":"Berberis thunbergii, the Japanese barberry, Thunberg's barberry, or red barberry, is a species of flowering plant in the barberry family Berberidaceae, native to Japan and eastern Asia, though widely naturalized in China and North America, where it has become…","img":"images/308.jpg","thumb":"images/t/308.jpg","file":"Berberis thunbergii (tree).jpg","ar":1.388,"py":"ribenxiaobo rbxb","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲","北美洲"]},{"id":309,"seq":305,"zh":"麦哲伦小檗","en":"Berberis microphylla","sci":"Berberis microphylla","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Berberis microphylla, common name box-leaved barberry and Magellan barberry, in Spanish calafate and michay and other names, is an evergreen shrub, with simple, shiny box-like leaves.","img":"images/309.jpg","thumb":"images/t/309.jpg","file":"Berberis microphylla - Flickr - Dick Culbert.jpg","ar":1.494,"py":"maizhelunxiaobo mzlxb","cr_by":"Dick Culbert from Gibsons, B.C., Canada","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["亚洲","南美洲"]},{"id":311,"seq":306,"zh":"Tinospora cordifolia","en":"Tinospora cordifolia","sci":"Tinospora cordifolia","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Menispermaceae","family_zh":"防己科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Tinospora cordifolia, guruchi, guduchi, amrita, or the heart-leaved moonseed, is a herbaceous vine of the family Menispermaceae native to South and Southeast Asia. It has been used in Ayurveda in an attempt to treat various disorders.","img":"images/311.jpg","thumb":"images/t/311.jpg","file":"Tinospora cordifolia fruits.jpg","ar":0.749,"py":"","cr_by":"Sanu N","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":312,"seq":307,"zh":"印防己实","en":"Anamirta cocculus","sci":"Anamirta cocculus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Menispermaceae","family_zh":"防己科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Anamirta cocculus (Marathi: काकमारी) is a Southeast Asian and Indian climbing plant. It is the source of picrotoxin, a poisonous compound with stimulant properties. The plant is large-stemmed (up to 10 cm in diameter); the bark is \"corky gray\" with white wood.","img":"images/312.jpg","thumb":"images/t/312.jpg","file":"Anamirta cocculus - Köhler–s Medizinal-Pflanzen-157.jpg","ar":0.769,"py":"yinfangjishi yfjs","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲"],"illus_img":"images/i/312.jpg","illus_thumb":"images/i/t/312.jpg","illus_file":"Anamirta cocculus - Köhler–s Medizinal-Pflanzen-157.jpg","illus_ar":0.769,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1085,"seq":308,"zh":"锡生藤","en":"Cissampelos pareira","sci":"Cissampelos pareira","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Menispermaceae","family_zh":"防己科","iucn":null,"langs":18,"desc_zh":"锡生藤（学名：Cissampelos pareira）为防己科锡生藤属下的一个种。","desc_en":"Cissampelos pareira (velvetleaf) is a species of flowering plant in the family Menispermaceae.","img":"images/1085.jpg","thumb":"images/t/1085.jpg","file":"Cissampelos pareira Blanco2.432-cropped.jpg","ar":0.649,"py":"xishengteng xst","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":1086,"seq":309,"zh":"星叶草","en":"Circaeaster agrestis","sci":"Circaeaster agrestis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Circaeasteraceae","family_zh":"星叶草科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Circaeaster agrestis is a flowering plant species and one of only one to two species in its family, the Circaeasteraceae. The plant is a small, glabrous herb found in temperate zones from the northwest Himalaya to northwest China.","img":"images/1086.jpg","thumb":"images/t/1086.jpg","file":"Circaeaster agrestis 7 Yunnan, China Photo Magnus Lidén.jpg","ar":0.965,"py":"xingyecao xyc","cr_by":"http://angio.bergianska.se/Bilder/Ranunculales/Circaeasteraceae/Circaeaster/Circaeaster%20agrestis%207%20Yunnan,%20China","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"]},{"id":1087,"seq":310,"zh":"Euptelea polyandra","en":"Euptelea polyandra","sci":"Euptelea polyandra","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Eupteleaceae","family_zh":"领春木科","iucn":"LC","langs":11,"desc_zh":null,"desc_en":"Euptelea polyandra is a species of flowering plant in the family Eupteleaceae, native to wet areas of central and southern Japan. A suckering small tree, occasionally a many-stemmed shrub, it is used as a street tree in a number of European cities.","img":"images/1087.jpg","thumb":"images/t/1087.jpg","file":"Euptelea polyandra 03.jpg","ar":1.501,"py":"","cr_by":"Σ64","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲"]},{"id":1088,"seq":311,"zh":"五叶木通","en":"Akebia quinata","sci":"Akebia quinata","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Lardizabalaceae","family_zh":"木通科","iucn":null,"langs":34,"desc_zh":"五叶木通（学名：Akebia quinata），种中文名木通。是木通科木通属的灌木。其木质茎一般被作为中药使用。果实被称为阿科比。","desc_en":"Akebia quinata –commonly known as akebi (木通), chocolate vine, five-leaf chocolate vine, or five-leaf akebia– is a vine that is native to Japan, China and Korea, commonly used as an ornamental or edible plant in the United States and Europe.","img":"images/1088.jpg","thumb":"images/t/1088.jpg","file":"Akebia quinata02.jpg","ar":0.721,"py":"wuyemutong wymt","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲","欧洲","北美洲"]},{"id":313,"seq":312,"zh":"银桦","en":"Grevillea robusta","sci":"Grevillea robusta","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":38,"desc_zh":"银桦（学名：Grevillea robusta），为山龙眼科银桦属下的一个植物种。原产地为澳洲，现于台湾是常见的树种。","desc_en":"Grevillea robusta, commonly known as the southern silky oak, silk oak or silky oak, silver oak or Australian silver oak, is a species of flowering plant in the family Proteaceae.","img":"images/313.jpg","thumb":"images/t/313.jpg","file":"Grevillearobusta40181608300 6dbb4fe9b0 o.jpg","ar":1.333,"py":"yinhua yh","cr_by":"MargaretRDonald","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["大洋洲"]},{"id":314,"seq":313,"zh":"蓟花山龙眼","en":"Protea cynaroides","sci":"Protea cynaroides","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":29,"desc_zh":"国王海神花（学名：Protea cynaroides），又称帝王花（king protea），是海神花属的一种植物，广泛分布于南非凡波斯一带，并为该国国花。本种花的花蜜可吸引橘胸太阳鸟、南方双领花蜜鸟、孔雀石色花蜜鸟与卡佛食蜜鸟等鸟类取食，这些鸟类啄食花蜜时会沾黏花粉于脸部与喙上，进而协助花朵传粉。此外本种花的花蜜亦可吸引多种昆虫，但牠们协助传粉的重要性仍不清楚。","desc_en":"Protea cynaroides, also called the king protea (from Afrikaans: koningsprotea, Xhosa: isiQwane sobukumkani), is a flowering plant. It is a distinctive member of Protea, having the largest flower head in the genus.","img":"images/314.jpg","thumb":"images/t/314.jpg","file":"Protéa royale à Stellenbosch (Afrique du Sud).jpg","ar":1.076,"py":"jihuashanlongyan jhsly","cr_by":"© Pierre André","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["非洲"]},{"id":315,"seq":314,"zh":"Banksia serrata","en":"Banksia serrata","sci":"Banksia serrata","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Banksia serrata, commonly known as the saw banksia, the old man banksia, the saw-tooth banksia or the red honeysuckle and as wiriyagan by the Cadigal people, is a species of woody shrub or tree of the genus Banksia, in the family Proteaceae.","img":"images/315.jpg","thumb":"images/t/315.jpg","file":"Banksia serrata Henry Hd email.jpg","ar":0.667,"py":"","cr_by":"Cas Liber","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["大洋洲"]},{"id":316,"seq":315,"zh":"智利榛","en":"Gevuina avellana","sci":"Gevuina avellana","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":20,"desc_zh":null,"desc_en":"Gevuina avellana, commonly known as the Chilean hazelnut (avellano chileno in Spanish) or Gevuina hazelnut, is an evergreen tree growing up to 20 meters (65 feet) tall. It is the only species currently classified in the genus Gevuina.","img":"images/316.jpg","thumb":"images/t/316.jpg","file":"Gevuina avellana 2.jpg","ar":1.375,"py":"zhilizhen zlz","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["南美洲"]},{"id":317,"seq":316,"zh":"澳洲坚果","en":"Macadamia integrifolia","sci":"Macadamia integrifolia","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"VU","langs":20,"desc_zh":"澳洲坚果（学名：Macadamia integrifolia）为山龙眼科澳洲坚果属下的一个种。","desc_en":"Macadamia integrifolia is a small to medium-sized tree native to Australian rainforests. Common names include macadamia, smooth-shelled macadamia, bush nut, Queensland nut, Bauple nut and nut oak.","img":"images/317.jpg","thumb":"images/t/317.jpg","file":"Starr 070112-3410 Macadamia integrifolia.jpg","ar":1.333,"py":"aozhoujianguo azjg","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["大洋洲"]},{"id":318,"seq":317,"zh":"Protea afra","en":"Protea afra","sci":"Protea afra","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":20,"desc_zh":null,"desc_en":"Protea afra (sometimes called the common protea), native to Africa, inhabiting from South Africa to Kenya, is a small tree or shrub which occurs in subtropical open or wooded grassland, usually on rocky ridges. Its leaves are leathery and hairless.","img":"images/318.jpg","thumb":"images/t/318.jpg","file":"Protea caffra IMG 2758.JPG","ar":0.667,"py":"","cr_by":"Marco Schmidt [1]","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["非洲"]},{"id":320,"seq":318,"zh":"莲","en":"Nelumbo nucifera","sci":"Nelumbo nucifera","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Nelumbonaceae","family_zh":"莲科","iucn":null,"langs":103,"desc_zh":"莲（学名：Nelumbo nucifera；英语：lotus）是莲科莲属多年生草本出水植物，又称荷、荷花、莲花，古称芙蓉、菡萏、芙蕖，梵名迦摩罗（梵语：कमल，罗马化：kamala）、钵头摩/钵特摩/波头摩/波昙/波昙摩/钵昙摩（尤指红莲，梵语：पद्म，罗马化：padma）、分陀利/分陀利迦/芬陀利/芬陀利迦/奔荼利/奔荼利迦（尤指白莲，梵语：पुण्डरीक，罗马化：puṇḍarīka）。花一般盛开于夏季，莲花也因而成为夏日之风物。","desc_en":"Nelumbo nucifera, also known as Padma (Sanskrit: पद्म, romanized: Padma, lit. 'Lotus') or Kamala (Sanskrit: कमल, lit. 'Lotus'), sacred lotus, pink lotus, Indian lotus, or simply lotus, is one of two extant species of aquatic plant in the family Nelumbonaceae.","img":"images/320.jpg","thumb":"images/t/320.jpg","file":"Sacred lotus Nelumbo nucifera.jpg","ar":1.091,"py":"lian l","cr_by":"T.Voekler","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"],"illus_img":"images/i/320.jpg","illus_thumb":"images/i/t/320.jpg","illus_file":"The American Flora. Vol. 4, 1855 - pl. 12 Nelumbo nucifera (14760462266).jpg","illus_ar":0.7,"illus_by":"David William Moody","illus_lic":"Public domain","illus_licurl":null},{"id":321,"seq":319,"zh":"法桐","en":"Plantanus orientalis","sci":"Platanus orientalis","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Platanaceae","family_zh":"悬铃木科","iucn":"DD","langs":55,"desc_zh":"法桐（学名：Platanus orientalis）又称三球悬铃木，是悬铃木科植物。由于二球悬铃木（英桐）最早由法国人在法租界霞飞路一带引入，因此中文中法国梧桐多指英桐而非法桐。法桐与梧桐没有亲属关系。 其种加词“orientalis”意为“东方的”。","desc_en":"Platanus orientalis, the Oriental plane, is a large, deciduous tree in the family Platanaceae, growing to 30 m (98 ft) or more, and known for its longevity and spreading crown. In autumn, its deep green leaves may change to blood red, amber, and yellow.","img":"images/321.jpg","thumb":"images/t/321.jpg","file":"Fruits of Platanus orientalis.jpg","ar":0.75,"py":"fatong ft","cr_by":"Samuli Lintula","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null,"illus_img":"images/i/321.jpg","illus_thumb":"images/i/t/321.jpg","illus_file":"T2 01 Platanus orientalis par Pierre-Joseph Redouté.jpeg","illus_ar":0.713,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1089,"seq":320,"zh":"单叶泡花树","en":"Meliosma simplicifolia","sci":"Meliosma simplicifolia","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Sabiaceae","family_zh":"清风藤科","iucn":null,"langs":8,"desc_zh":"单叶泡花树（学名：Meliosma simplicifolia）为清风藤科泡花树属下的一个种。","desc_en":"Meliosma simplicifolia is a species of plant in the family Sabiaceae. It is widely distributed in Asia from India through south-east Asia.","img":"images/1089.jpg","thumb":"images/t/1089.jpg","file":"Meliosma simplicifolia ssp. simplicifolia(1).jpg","ar":0.785,"py":"danyepaohuashu dyphs","cr_by":"Vinayaraj","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":322,"seq":321,"zh":"锦熟黄杨","en":"Buxus sempervirens","sci":"Buxus sempervirens","order_en":"Buxales","order_zh":"黄杨目","family_en":"Buxaceae","family_zh":"黄杨科","iucn":"LC","langs":62,"desc_zh":"锦熟黄杨（学名：Buxus sempervirens）是黄杨科黄杨属的一种植物，原产于西欧、南欧、西北非及西亚，北起英国南部、南至摩洛哥北部、东达土耳其。原产于西高加索的科尔基斯黄杨（Buxus colchica）与原产于伊朗北部与东高加索的希尔卡尼亚黄杨（Buxus hyrcana）与锦熟黄杨亲缘关系非常近，常被认为是锦熟黄杨的异名。","desc_en":"Buxus sempervirens, the common box, European box, or boxwood, is a species of flowering plant in the genus Buxus, native to western and southern Europe, northwest Africa, and southwest Asia, from southern England south to northern Morocco, and east through the…","img":"images/322.jpg","thumb":"images/t/322.jpg","file":"Buxus sempervirens.jpg","ar":0.633,"py":"jinshuhuangyang jshy","cr_by":"No machine-readable author provided. MPF assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/322.jpg","illus_thumb":"images/i/t/322.jpg","illus_file":"23 Buxus sempervirens par Pierre-Joseph Redouté.jpeg","illus_ar":0.7,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":323,"seq":322,"zh":"顶花板凳果","en":"Pachysandra terminalis","sci":"Pachysandra terminalis","order_en":"Buxales","order_zh":"黄杨目","family_en":"Buxaceae","family_zh":"黄杨科","iucn":null,"langs":19,"desc_zh":"顶花板凳果（学名：Pachysandra terminalis）是黄杨科板凳果属的植物。分布于日本以及中国大陆的四川、湖北、浙江、陕西、甘肃等地，生长于海拔1,000米至2,600米的地区，常生于山区林下阴湿地，已由人工引种栽培，用于药材或园艺。","desc_en":"Pachysandra terminalis, the Japanese pachysandra, carpet box or Japanese spurge, is a species of flowering plant in the boxwood family Buxaceae, native to Japan, Korea and China and introduced to eastern North America.","img":"images/323.jpg","thumb":"images/t/323.jpg","file":"Pachysandra terminalis0.jpg","ar":1.333,"py":"dinghuabandengguo dhbdg","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"]},{"id":1090,"seq":323,"zh":"黄杨","en":"Buxus microphylla","sci":"Buxus microphylla","order_en":"Buxales","order_zh":"黄杨目","family_en":"Buxaceae","family_zh":"黄杨科","iucn":"LC","langs":17,"desc_zh":null,"desc_en":"Buxus microphylla, the Japanese box or littleleaf box, is a species of flowering plant in the box family found in Japan and Taiwan. It is a dwarf evergreen shrub or small tree growing to 1 m (3.3 ft) tall and wide.","img":"images/1090.jpg","thumb":"images/t/1090.jpg","file":"Buxus microphylla HabitusLeaves BotGardBln0906.JPG","ar":0.75,"py":"huangyang hy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":324,"seq":324,"zh":"昆栏树","en":"Trochodendron aralioides","sci":"Trochodendron aralioides","order_en":"Trochodendrales","order_zh":"昆栏树目","family_en":"Trochodendraceae","family_zh":"昆栏树科","iucn":null,"langs":14,"desc_zh":"昆栏树（学名：Trochodendron aralioides）为昆栏树科昆栏树属下的唯一一种。 昆栏树分布于日本、南韩及台湾，生长在日本的针阔叶混合林及常绿阔叶林，以及台湾中央山脉及北部山区的常绿阔叶林中。","desc_en":"Trochodendron aralioides, sometimes colloquially called wheel tree, is a flowering plant and the sole living species in the genus Trochodendron, which also includes several extinct species.","img":"images/324.jpg","thumb":"images/t/324.jpg","file":"Trochodendron aralioides 2.jpg","ar":1.506,"py":"kunlanshu kls","cr_by":"Eric in SF","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":325,"seq":325,"zh":"长萼大叶草","en":"Gunnera manicata","sci":"Gunnera manicata","order_en":"Gunnerales","order_zh":"洋二仙草目","family_en":"Gunneraceae","family_zh":"洋二仙草科","iucn":null,"langs":23,"desc_zh":"大叶蚁塔（Gunnera manicata），又名长萼大叶草，俗称巨人大黄（源自英语：Brazilian giant-rhubarb/giant rhubarb），是洋二仙草属的一种植物，原产于巴西马尔山脉附近地区。它是一种有著巨大叶子的常绿草本植物，高可达2.5米（8.2英尺）至4米（13英尺），叶子直径可达4英尺（120厘米），植株整体覆盖面积达9平方米（97平方英尺）。叶子底部和茎上有刺，开红绿色小花，结的果子也很小。","desc_en":"Gunnera manicata, known as Brazilian giant-rhubarb, giant rhubarb, or dinosaur food is a species of flowering plant in the family Gunneraceae from the coastal Serra do Mar Mountains of Santa Catarina, Parana and Rio Grande do Sul States, Brazil.","img":"images/325.jpg","thumb":"images/t/325.jpg","file":"Gunnera manicata3.JPG","ar":1.333,"py":"changedayecao cedyc","cr_by":"Required attribution is: Photo by Tom Oates. The original uploader was Nabokov at English Wikipedia . (a.k.a. Tom Oates)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["南美洲"]},{"id":1091,"seq":326,"zh":"Myrothamnus flabellifolius","en":"Myrothamnus flabellifolius","sci":"Myrothamnus flabellifolius","order_en":"Gunnerales","order_zh":"大叶草目","family_en":"Myrothamnaceae","family_zh":"香灌木科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Myrothamnus flabellifolius is a species of flowering plant in the family Myrothamnaceae native to central and southern Africa. It is also called the resurrection plant for the appearance of dead leaves reviving during rain (see poikilohydry).","img":"images/1091.jpg","thumb":"images/t/1091.jpg","file":"Myrothamnus flabellifolius Myrothamanaceae.jpg","ar":1,"py":"","cr_by":"Nko","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["非洲"]},{"id":326,"seq":327,"zh":"落地生根","en":"Kalanchoe pinnata","sci":"Kalanchoe pinnata","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":55,"desc_zh":"落地生根（学名：Kalanchoe pinnata）又称叶生根、土三七、天灯笼、古仔灯、大还魂、倒地莲、倒吊莲、打不死、番鬼牡丹，原产地为热带非洲，是景天科伽蓝菜属的多肉植物。由于若将其叶放在泥土上，叶边的一点即能发芽生长，不必依赖种子繁殖，故名落地生根。若将它屈折或打断，其叶著地即能生长，故亦有「打不死」之名。具有止血、消炎、止痛、消肿解毒之功效。但脾胃虚寒者慎服。此外也可做切花、盆栽、花坛和庭园露地栽培。花语：坚忍，有毅力。","desc_en":"Kalanchoe pinnata, commonly known as cathedral bells, air plant, life plant, miracle leaf, and love bush, is a succulent plant native to Madagascar. It is a popular houseplant and has become naturalized in tropical and subtropical areas.","img":"images/326.jpg","thumb":"images/t/326.jpg","file":"Kalanchoe pinnata kz1.JPG","ar":0.667,"py":"luodishenggen ldsg","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["非洲"]},{"id":327,"seq":328,"zh":"蔷薇红景天","en":"Rhodiola rosea","sci":"Rhodiola rosea","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":51,"desc_zh":"红景天（学名：Rhodiola rosea）是景天科红景天属的植物。分布于日本、朝鲜、俄罗斯、蒙古以及吉林、河北、山西、新疆等地，生长于海拔1,800米至2,700米的地区，多生长于山坡林下或草坡上，目前尚未由人工引种栽培。","desc_en":"Rhodiola rosea (commonly golden root, rose root, roseroot, Aaron's rod, Arctic root, king's crown, lignum rhodium, orpin rose) is a perennial flowering plant in the family Crassulaceae.","img":"images/327.jpg","thumb":"images/t/327.jpg","file":"Rhodiola rosea (Montage s3).jpg","ar":1,"py":"qiangweihongjingtian qwhjt","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":328,"seq":329,"zh":"苔景天","en":"Sedum acre","sci":"Sedum acre","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":50,"desc_zh":"苔景天（学名：Sedum acre）是景天科景天属下的一个种，也叫苦味景天、欧洲万年草。种加词acre的意思是刺激的苦辛味。有中文资料将其误译为锐叶景天，但实际上苔景天的叶尖钝圆，而非锐尖。","desc_en":"Sedum acre, commonly known as the goldmoss stonecrop, mossy stonecrop, goldmoss sedum, biting stonecrop, and wallpepper, is a perennial flowering plant in the family Crassulaceae.","img":"images/328.jpg","thumb":"images/t/328.jpg","file":"Sedum acre single - Niitvälja.jpg","ar":0.714,"py":"taijingtian tjt","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","北美洲","南美洲","大洋洲"],"illus_img":"images/i/328.jpg","illus_thumb":"images/i/t/328.jpg","illus_file":"Sedum acre — Flora Batava — Volume v1.jpg","illus_ar":0.759,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":329,"seq":330,"zh":"长生草","en":"Sempervivum tectorum","sci":"Sempervivum tectorum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Sempervivum tectorum, the common houseleek, is a species of flowering plant in the family Crassulaceae, native to the mountains of southern Europe, cultivated in the whole of Europe for its appearance and a Roman-era tradition claiming that it protects buildin…","img":"images/329.jpg","thumb":"images/t/329.jpg","file":"Matafoc flor 8 agost06 050.jpg","ar":1.333,"py":"changshengcao csc","cr_by":"Victor M. Vicente Selvas","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"],"illus_img":"images/i/329.jpg","illus_thumb":"images/i/t/329.jpg","illus_file":"Sempervivum tectorum Sturm45.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":330,"seq":331,"zh":"翡翠木","en":"Crassula ovata","sci":"Crassula ovata","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":41,"desc_zh":"翡翠木（学名：Crassula ovata）又称发财树、玉树、燕子掌，原生于南非。为景天科青锁龙属多肉质亚灌木植物。","desc_en":"Crassula ovata, commonly known as jade plant, lucky plant, money plant or money tree, is a succulent plant with small pink or white flowers that is native to the KwaZulu-Natal and Eastern Cape provinces of South Africa, and Mozambique; it is common as a housep…","img":"images/330.jpg","thumb":"images/t/330.jpg","file":"2016-10-03 Crassula ovata, Camdeboo NP, Eastern Cape (31803933474).jpg","ar":1.487,"py":"feicuimu fcm","cr_by":"Bernard DUPONT from FRANCE","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"多肉","origin":["非洲"]},{"id":331,"seq":332,"zh":"长寿花","en":"Kalanchoe blossfeldiana","sci":"Kalanchoe blossfeldiana","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":37,"desc_zh":"长寿花（学名：Kalanchoe blossfeldiana）又称家乐花、燕子海棠、圣诞伽蓝菜、寿星花、布洛斯费尔德高凉菜，属景天科伽蓝菜属，原产于非洲的马达加斯加。长寿花是常见的观赏花卉。","desc_en":"Kalanchoe blossfeldiana is a commonly cultivated evergreen house plant of the genus Kalanchoe native to Madagascar. It is known by the English common names flaming Katy, Christmas kalanchoe, florist kalanchoe and Madagascar widow's-thrill.","img":"images/331.jpg","thumb":"images/t/331.jpg","file":"Kalanchoe.blossfeldiana.jpg","ar":1.023,"py":"changshouhua csh","cr_by":"Cdpanic at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":332,"seq":333,"zh":"白景天","en":"Sedum album","sci":"Sedum album","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Sedum album, the white stonecrop, is a flowering plant of the genus Sedum in the family Crassulaceae. It is found in the northern temperate regions of the world, often growing in crevices or free-draining rocky soil.","img":"images/332.jpg","thumb":"images/t/332.jpg","file":"Sedum album.jpg","ar":0.941,"py":"baijingtian bjt","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/332.jpg","illus_thumb":"images/i/t/332.jpg","illus_file":"Sedum album — Flora Batava — Volume v3.jpg","illus_ar":0.693,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":333,"seq":334,"zh":"紫八宝","en":"Hylotelephium telephium","sci":"Hylotelephium telephium","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":35,"desc_zh":"紫八宝（学名：Hylotelephium purpureum）又称紫景天，为景天科八宝属的植物。分布于远东地区、日本、欧洲、北美洲以及中国大陆的新疆、黑龙江、吉林、辽宁等地，生长于海拔420米至1,550米的地区，多生长于山坡草原上或林下阴湿山沟边，目前尚未由人工引种栽培。","desc_en":"Hylotelephium telephium (synonym Sedum telephium), known as orpine, livelong, frog's-stomach, harping Johnny, life-everlasting, live-forever, midsummer-men, Orphan John, witch's moneybags, and garden stonecrop is a succulent perennial plant of the family Crass…","img":"images/333.jpg","thumb":"images/t/333.jpg","file":"(MHNT) Hylotelephium telephium - Habitus.jpg","ar":1.501,"py":"zibabao zbb","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["亚洲"],"illus_img":"images/i/333.jpg","illus_thumb":"images/i/t/333.jpg","illus_file":"Hylotelephium telephium Sturm43.jpg","illus_ar":0.687,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":337,"seq":335,"zh":"厚叶岩白菜","en":"Bergenia crassifolia","sci":"Bergenia crassifolia","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":36,"desc_zh":"厚叶岩白菜（Bergenia crassifolia），又名西伯利亚茶、蒙古茶、巴丹茶、白菜皮、冬白菜等，是岩白菜属的一个种。青海白菜高约 30 cm，叶子呈匙羮形。 厚叶岩白菜含有多种多酚类化合物，例如：熊果苷和单宁。","desc_en":"Bergenia crassifolia is a species of flowering plant of the genus Bergenia in the family Saxifragaceae. Common names for the species include heart-leaved bergenia, heartleaf bergenia, leather bergenia, winter-blooming bergenia, elephant-ears, elephant's ears,…","img":"images/337.jpg","thumb":"images/t/337.jpg","file":"Bergenia crassifolia a1.jpg","ar":1.325,"py":"houyeyanbaicai hyybc","cr_by":"Jerzy Opioła","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":338,"seq":336,"zh":"小鳞茎虎耳草","en":"Saxifraga granulata","sci":"Saxifraga granulata","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Saxifraga granulata, commonly called meadow saxifrage, is a species of flowering plant in the family Saxifragaceae. It is native to most of Europe and Morocco.","img":"images/338.jpg","thumb":"images/t/338.jpg","file":"Saxifraga granulata 140505.jpg","ar":0.75,"py":"xiaolinjinghuercao xljhec","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"],"illus_img":"images/i/338.jpg","illus_thumb":"images/i/t/338.jpg","illus_file":"Saxifraga granulata Sturm60.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":339,"seq":337,"zh":"挪威虎耳草","en":"Saxifraga oppositifolia","sci":"Saxifraga oppositifolia","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":32,"desc_zh":"挪威虎耳草（学名：Saxifraga oppositifolia）为虎耳草科虎耳草属下的一个种。","desc_en":"Saxifraga oppositifolia, the purple saxifrage or purple mountain saxifrage, is a species of plant that is very common in the high Arctic and also some high mountainous areas further south, including northern Britain, the Alps and the Rocky Mountains.","img":"images/339.jpg","thumb":"images/t/339.jpg","file":"Purpsaxifrage2.jpg","ar":0.75,"py":"nuoweihuercao nwhec","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲","北美洲"],"illus_img":"images/i/339.jpg","illus_thumb":"images/i/t/339.jpg","illus_file":"Saxifraga oppositifolia Sturm54.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":340,"seq":338,"zh":"Saxifraga aizoides","en":"Saxifraga aizoides","sci":"Saxifraga aizoides","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Saxifraga aizoides, yellow mountain saxifrage or yellow saxifrage, is a flowering alpine plant of the genus Saxifraga.","img":"images/340.jpg","thumb":"images/t/340.jpg","file":"Saxifraga aizoides (flowers).jpg","ar":1.333,"py":"","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/340.jpg","illus_thumb":"images/i/t/340.jpg","illus_file":"Saxifraga aizoides Sturm55.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":342,"seq":339,"zh":"鹅莓","en":"Ribes uva-crispa","sci":"Ribes uva-crispa","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Grossulariaceae","family_zh":"醋栗科","iucn":null,"langs":100,"desc_zh":"鹅莓（学名：Ribes uva-crispa），又称醋栗或欧洲醋栗，是茶藨子科醋栗属草本植物的一种。","desc_en":"Ribes uva-crispa, commonly known as the gooseberry or European gooseberry, is a species of flowering shrub native to Europe, northwestern Africa, and southwestern Asia. It belongs to the family Grossulariaceae, which includes currants and gooseberries.","img":"images/342.jpg","thumb":"images/t/342.jpg","file":"Stachelbeeren.jpg","ar":0.75,"py":"emei em","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/342.jpg","illus_thumb":"images/i/t/342.jpg","illus_file":"Illustration Ribes uva-crispa0.jpg","illus_ar":0.621,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":343,"seq":340,"zh":"黑加仑","en":"Ribes nigrum","sci":"Ribes nigrum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Grossulariaceae","family_zh":"醋栗科","iucn":null,"langs":90,"desc_zh":"黑加仑（学名：Ribes nigrum），又名黑醋栗、黑加伦子、黑豆果、黑茶藨子、黑穗醋栗，为虎耳草目茶藨子科小型灌木，其成熟果实为黑色小浆果，可以食用，也可以加工成果汁、果酱等食品，果实外观近似葡萄，但实为不同目的植物。","desc_en":"The blackcurrant (Ribes nigrum), black currant or cassis is a deciduous shrub in the family Grossulariaceae grown for its edible berries. It is native to temperate parts of central and northern Europe and northern Asia, where it prefers damp fertile soils.","img":"images/343.jpg","thumb":"images/t/343.jpg","file":"Schwarzejohannisbeere.jpg","ar":1.357,"py":"heijialun hjl","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/343.jpg","illus_thumb":"images/i/t/343.jpg","illus_file":"Ribes nigrum — Flora Batava — Volume v12.jpg","illus_ar":0.708,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1092,"seq":341,"zh":"红加仑","en":"Ribes rubrum","sci":"Ribes rubrum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Grossulariaceae","family_zh":"醋栗科","iucn":null,"langs":83,"desc_zh":"红加仑（学名：Ribes rubrum），又称红醋栗、红茶藨子，是醋栗科的小型灌木，原产于法国至波兰之间，现因人工栽植遍布全欧洲。其成熟果实为红色或白色透亮之小浆果，内富含维生素C、花青素。果实可生食，红色品种的酸味较白色品种强。果实亦可加工做果汁、果酱、果冻、果酒等。人工栽种的红加仑可采用扦插繁殖。","desc_en":"The redcurrant or red currant (Ribes rubrum) is a member of the genus Ribes in the family Grossulariaceae. It is native to western Europe. The species is widely cultivated and has escaped into the wild in many regions.","img":"images/1092.jpg","thumb":"images/t/1092.jpg","file":"Ribes rubrum 1.jpg","ar":1.099,"py":"hongjialun hjl","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"],"illus_img":"images/i/1092.jpg","illus_thumb":"images/i/t/1092.jpg","illus_file":"Ribes rubrum Sturm07050.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":344,"seq":342,"zh":"荷兰芍药","en":"Paeonia officinalis","sci":"Paeonia officinalis","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Paeoniaceae","family_zh":"芍药科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Paeonia officinalis, the common peony, or garden peony, is a species of flowering plant in the family Paeoniaceae, native to mainly mountainous areas of Southern Europe and introduced in Central and Western Europe and North America.","img":"images/344.jpg","thumb":"images/t/344.jpg","file":"PAEONIA OFFICINALIS - MONTSEC - IB-200 (Peònia de muntanya).jpg","ar":1.333,"py":"helanshaoyao hlsy","cr_by":"Isidre blanc","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲","北美洲"],"illus_img":"images/i/344.jpg","illus_thumb":"images/i/t/344.jpg","illus_file":"Paeonia officinalis Anemoniflora Bot. Mag. 59. 3175. 1832.jpg","illus_ar":0.548,"illus_by":"W.J. Hooker","illus_lic":"Public domain","illus_licurl":null},{"id":345,"seq":343,"zh":"牡丹","en":"Paeonia × suffruticosa","sci":"Paeonia suffruticosa","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Paeoniaceae","family_zh":"芍药科","iucn":null,"langs":31,"desc_zh":"牡丹（学名：Paeonia × suffruticosa）为芍药科芍药属的一种落叶小灌木，拥有非常巨大且多层的花朵，是起源于中国的一个杂交栽培种，高1～1.5米；二回三出复叶，小叶常3－5裂。初夏开白色、红色或紫色花，花单生大型，雌蕊生于肉质花盘上，密被细毛。常见于和中国文化有关之工艺品中，例如唐朝和清朝的女子头饰、工笔画、汉服纹样等。","desc_en":"Paeonia × suffruticosa is a group of tree peony cultivars that are the result of hybridization with peony species exclusively belonging to the subsection Vaginatae. The common name used in China is mǔdān (Chinese: 牡丹) or Moutan peony.","img":"images/345.jpg","thumb":"images/t/345.jpg","file":"Strauchpfingstrose - Botanischer Garten in Wien.JPG","ar":0.75,"py":"mudan md","cr_by":"C.Stadler/Bwag","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":null,"illus_img":"images/i/345.jpg","illus_thumb":"images/i/t/345.jpg","illus_file":"Paeonia suffruticosa illustration Henry Andrews.jpg","illus_ar":1.533,"illus_by":"Henry Cranke Andrews (1770-1830)","illus_lic":"Public domain","illus_licurl":null},{"id":1093,"seq":344,"zh":"芍药","en":"Paeonia lactiflora","sci":"Paeonia lactiflora","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Paeoniaceae","family_zh":"芍药科","iucn":null,"langs":31,"desc_zh":"芍药（学名：Paeonia lactiflora），又称作娇客，余容，留夷，殿春花，没骨花，婪尾春，白芍、杭白芍、金芍药、将离，是芍药科芍药属的多年生宿根草本植物。 种名lactiflora意为“乳白色花的”。","desc_en":"Paeonia lactiflora (Chinese peony, Chinese herbaceous peony, or common garden peony) is a species of herbaceous perennial flowering plant in the family Paeoniaceae, native to central and eastern Asia from eastern Tibet across northern China to eastern Siberia.","img":"images/1093.jpg","thumb":"images/t/1093.jpg","file":"Lactiflora1b.UME.jpg","ar":0.75,"py":"shaoyao sy","cr_by":"Ulf Eliasson","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/1093.jpg","illus_thumb":"images/i/t/1093.jpg","illus_file":"Paeonia lactiflora (P. albiflora) Bot. Mag, 42. 1756. 1815.jpg","illus_ar":0.584,"illus_by":"Sims","illus_lic":"Public domain","illus_licurl":null},{"id":346,"seq":345,"zh":"波斯铁木","en":"Parrotia persica","sci":"Parrotia persica","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Hamamelidaceae","family_zh":"金缕梅科","iucn":null,"langs":32,"desc_zh":null,"desc_en":"Parrotia persica, the Persian ironwood, is a deciduous tree in the family Hamamelidaceae, closely related to the witch-hazel genus Hamamelis. It is native to the Caspian region of northern Iran (where it is called انجیلی anjili) and southeastern Azerbaijan (wh…","img":"images/346.jpg","thumb":"images/t/346.jpg","file":"برگ درخت انجیلی در اردیبهشت ماه.jpg","ar":0.81,"py":"bositiemu bstm","cr_by":"Waheed butt","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":347,"seq":346,"zh":"北美金缕梅","en":"Hamamelis virginiana","sci":"Hamamelis virginiana","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Hamamelidaceae","family_zh":"金缕梅科","iucn":"LC","langs":31,"desc_zh":"北美金缕梅（学名：Hamamelis virginiana），又名维吉尼亚金缕梅，是金缕梅属的一种落叶灌木。原产于北美洲东部，由加拿大的新斯科舍省向西至美国的明尼苏达州，向南至佛罗里达州中部与德克萨斯州东部。","desc_en":"Hamamelis virginiana, known as witch-hazel, common witch-hazel, American witch-hazel and beadwood, is a species of flowering shrub native to eastern North America, from Nova Scotia west to Minnesota, and south to central Florida to eastern Texas.","img":"images/347.jpg","thumb":"images/t/347.jpg","file":"Hamamelis virginiana - Köhler–s Medizinal-Pflanzen-070.jpg","ar":0.734,"py":"beimeijinlmei bmjlm","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["北美洲"],"illus_img":"images/i/347.jpg","illus_thumb":"images/i/t/347.jpg","illus_file":"Hamamelis virginiana - Köhler–s Medizinal-Pflanzen-070.jpg","illus_ar":0.734,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1094,"seq":347,"zh":"金缕梅","en":"Hamamelis mollis","sci":"Hamamelis mollis","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Hamamelidaceae","family_zh":"金缕梅科","iucn":"LC","langs":20,"desc_zh":"金缕梅（学名：Hamamelis mollis）为金缕梅科金缕梅属下的一种落叶灌木或小乔木，原产于中国东部，其种加词mollis的意思是“柔软的”，指的是其叶子。","desc_en":"Hamamelis mollis, also known as Chinese witch hazel, is a species of flowering plant in the witch hazel family Hamamelidaceae, native to central and eastern China, in Anhui, Guangxi, Hubei, Hunan, Jiangxi, Sichuan, and Zhejiang.","img":"images/1094.jpg","thumb":"images/t/1094.jpg","file":"Hamamelis mollis0.jpg","ar":1.333,"py":"jinlmei jlm","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":1095,"seq":348,"zh":"北美枫香树","en":"Liquidambar styraciflua","sci":"Liquidambar styraciflua","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Altingiaceae","family_zh":"蕈树科","iucn":"LC","langs":35,"desc_zh":"北美枫香树 (Liquidambar styraciflua)，又称 美国苏合香，褐松树， 红糖香树（redgum），缎胡桃树，星叶香树，钝吻鳄树（alligatorwood）， 或简称为枫香树。 北美枫香树是枫香树属的落叶植物，起源于暖温带地区的东北美洲和热带高山地区的墨西哥和中美洲。枫香树是美国东南部的一种主要经济作物，并且是温带气候区中一种很受欢迎的观赏植物，其树叶多为五角形，果实坚硬且带刺。","desc_en":"Liquidambar styraciflua, commonly known as the American sweetgum among other names, is a deciduous tree in the genus Liquidambar native to warm temperate areas of eastern North America and tropical montane regions of Mexico and Central America.","img":"images/1095.jpg","thumb":"images/t/1095.jpg","file":"Liquidambar-otonno-20071028-1.jpg","ar":1.388,"py":"beimeifengxiangshu bmfxs","cr_by":"Luis Fernández García","cr_lic":"CC BY-SA 2.5 es","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5/es/deed.en","habit":"乔木","origin":["北美洲"],"illus_img":"images/i/1095.jpg","illus_thumb":"images/i/t/1095.jpg","illus_file":"T2 10 Liquidambar styraciflua par Pierre-Joseph Redouté.jpeg","illus_ar":0.714,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1096,"seq":349,"zh":"Aphanopetalum resinosum","en":"Aphanopetalum resinosum","sci":"Aphanopetalum resinosum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Aphanopetalaceae","family_zh":"胶藤科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Aphanopetalum resinosum, known as the gum vine, is a rambling vine growing in rainforest or eucalyptus woodland in eastern Australia. In Victoria it is listed as \"vulnerable\", being known only from a single collection near Mallacoota.","img":"images/1096.jpg","thumb":"images/t/1096.jpg","file":"Aphanopetalum resinosum IMG 20190908 153202.jpg","ar":1.333,"py":"","cr_by":"Margaret Donald","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"藤本","origin":["大洋洲"]},{"id":1097,"seq":350,"zh":"连香树","en":"Cercidiphyllum japonicum","sci":"Cercidiphyllum japonicum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Cercidiphyllaceae","family_zh":"连香树科","iucn":"LC","langs":30,"desc_zh":"连香树（学名：Cercidiphyllum japonicum）是连香树科连香树属落叶乔木。属第三纪孑遗植物、东亚植物区系特有种。其种加词“japonicum”意为“日本的”。中国和日本的间断分布种。","desc_en":"Cercidiphyllum japonicum, known as the Katsura (from its Japanese name カツラ, 桂), is a species of flowering tree in the family Cercidiphyllaceae native to China and Japan. It is sometimes called caramel tree for the light caramel smell it emits during leaf fall.","img":"images/1097.jpg","thumb":"images/t/1097.jpg","file":"Great katsura of wachi01s3000.jpg","ar":0.667,"py":"lianxiangshu lxs","cr_by":"663highland","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲"]},{"id":1098,"seq":351,"zh":"交让木","en":"Daphniphyllum macropodum","sci":"Daphniphyllum macropodum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Daphniphyllaceae","family_zh":"虎皮楠科","iucn":"LC","langs":13,"desc_zh":"交让木（学名：Daphniphyllum macropodum）为虎皮楠科虎皮楠属下的一个种。","desc_en":"Daphniphyllum macropodum is a shrub or small tree found in China, Japan and Korea. Small populations are also located in the southern Kuril Islands. Like all species in the genus Daphniphyllum, D.","img":"images/1098.jpg","thumb":"images/t/1098.jpg","file":"Daphniphyllum macropodum 120502-1.jpg","ar":1.259,"py":"jiaorangmu jrm","cr_by":"Peter coxhead","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"]},{"id":1099,"seq":352,"zh":"聚藻","en":"Myriophyllum spicatum","sci":"Myriophyllum spicatum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Haloragaceae","family_zh":"小二仙草科","iucn":"LC","langs":32,"desc_zh":"聚藻（学名：Myriophyllum spicatum），又名穗状狐尾藻、泥茜。为小二仙草科狐尾藻属下的一个种，除了澳洲之外，其他大陆均有分布，在20世纪1940年代首次引入北美，在某些地区成入侵物种。","desc_en":"Myriophyllum spicatum (Eurasian watermilfoil or spiked water-milfoil) is a submerged perennial aquatic plant which grows in still or slow-moving water. Eurasian watermilfoil is native to Europe, Asia, and North Africa, but has a wide geographic and climatic di…","img":"images/1099.jpg","thumb":"images/t/1099.jpg","file":"Cleaned-Illustration Myriophyllum spicatum.jpg","ar":0.567,"py":"juzao jz","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","非洲","北美洲"],"illus_img":"images/i/1099.jpg","illus_thumb":"images/i/t/1099.jpg","illus_file":"Myriophyllum spicatum — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1100,"seq":353,"zh":"鞣木","en":"Itea virginica","sci":"Itea virginica","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Iteaceae","family_zh":"鼠刺科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Itea virginica, commonly known as Virginia willow or Virginia sweetspire, is a small North American flowering shrub that grows in low-lying woods and wetland margins.","img":"images/1100.jpg","thumb":"images/t/1100.jpg","file":"Itea virginica flowers 001.JPG","ar":1.501,"py":"roumu rm","cr_by":"User:SB_Johnny","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["北美洲"]},{"id":1101,"seq":354,"zh":"扯根菜","en":"Penthorum chinense","sci":"Penthorum chinense","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Penthoraceae","family_zh":"扯根菜科","iucn":null,"langs":8,"desc_zh":"扯根菜（学名：Penthorum chinense）为虎耳草科扯根菜属下的一个种。其地上干燥部份可入药，称为赶黄草。","desc_en":"Penthorum chinense, commonly known as Oriental penthorum, is a plant species native to much of East Asia. It has been reported from China, Korea, Japan, Mongolia, Russia, Vietnam, Laos and Thailand.","img":"images/1101.jpg","thumb":"images/t/1101.jpg","file":"Penthorum chinense2.jpg","ar":0.75,"py":"chegencai cgc","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","北美洲"]},{"id":1102,"seq":355,"zh":"Soyauxia velutina","en":"Soyauxia velutina","sci":"Soyauxia velutina","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Peridiscaceae","family_zh":"围盘树科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Soyauxia velutina is a species of flowering plant from the family Peridiscaceae.","img":"images/1102.jpg","thumb":"images/t/1102.jpg","file":"Soyauxia velutina 30926403.jpg","ar":1.333,"py":"","cr_by":"Ben P","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":null},{"id":348,"seq":356,"zh":"酿酒葡萄","en":"Vitis vinifera","sci":"Vitis vinifera","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":"LC","langs":86,"desc_zh":"葡萄（学名：Vitis vinifera），是一种主要用来酿造酒的葡萄，葡萄科葡萄属的开花植物。目前有 5,000 到 10,000 个品种，但只有少数品种对生产具有商业意义。 野生葡萄一般归类为野生亚种（V. v. subsp. sylvestris），而培植种则是指名亚种（V. v. subsp. vinifera）。驯化的葡萄树是有雌雄同体的花，而野生亚种的是雌雄异花的（雄花和雌花在不同的植物上），需要授粉来结果。","desc_en":"Vitis vinifera, the common grape vine, is a species of flowering plant, native to the Mediterranean region, Central Europe, and southwestern Asia, from Morocco and Portugal north to southern Germany and east to northern Iran.","img":"images/348.jpg","thumb":"images/t/348.jpg","file":"Vitis vinifera - Köhler–s Medizinal-Pflanzen-145.jpg","ar":0.816,"py":"niangjiuputao njpt","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲","欧洲"],"illus_img":"images/i/348.jpg","illus_thumb":"images/i/t/348.jpg","illus_file":"Vitis vinifera - Köhler–s Medizinal-Pflanzen-145.jpg","illus_ar":0.816,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":349,"seq":357,"zh":"五叶地锦","en":"Parthenocissus quinquefolia","sci":"Parthenocissus quinquefolia","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":"LC","langs":46,"desc_zh":"五叶地锦（学名：Parthenocissus quinquefolia）为葡萄科地锦属的植物。分布于北美以及中国大陆的华北、东北等地，目前已由人工引种栽培。","desc_en":"Parthenocissus quinquefolia, commonly known as Virginia creeper, woodbine, five-leaved ivy, or five-finger, is a species of flowering vine in the grape family Vitaceae.","img":"images/349.jpg","thumb":"images/t/349.jpg","file":"Klimop detail 2.JPG","ar":0.75,"py":"wuyedijin wydj","cr_by":"Tasja","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["北美洲"]},{"id":350,"seq":358,"zh":"美洲葡萄","en":"Vitis labrusca","sci":"Vitis labrusca","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":null,"langs":35,"desc_zh":"美洲葡萄（学名：Vitis labrusca）为葡萄科葡萄属下的一个种。","desc_en":"Vitis labrusca, the fox grape, is a species of grapevines belonging to the Vitis genus in the flowering plant family Vitaceae. The vines are native to eastern North America and are the source of many grape cultivars, including Catawba, Concord, Delaware, Isabe…","img":"images/350.jpg","thumb":"images/t/350.jpg","file":"ConcordGrapes.jpg","ar":0.935,"py":"meizhouputao mzpt","cr_by":"Unknown Unknown ; cropped, cleaned up, and levels adjustment by Howcheng","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["北美洲"]},{"id":351,"seq":359,"zh":"爬墙虎","en":"Parthenocissus tricuspidata","sci":"Parthenocissus tricuspidata","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":null,"langs":32,"desc_zh":"爬墙虎（学名：Parthenocissus tricuspidata）又名爬山虎、地锦、土鼓藤、红葡萄藤，属葡萄科地锦属。原产朝鲜半岛、日本及中国华北和东北地区。","desc_en":"Parthenocissus tricuspidata is a species of flowering plant in the grape family (Vitaceae) native to eastern Asia (Korea, Japan, and northern and eastern China), where it thrives in floodplain bushes, riverside woodland and moist mountain mixed forests.","img":"images/351.jpg","thumb":"images/t/351.jpg","file":"姫路モノレール跡-06.jpg","ar":0.667,"py":"paqianghu pqh","cr_by":"Gohachiyasu1214","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":353,"seq":360,"zh":"大豆","en":"soybean","sci":"Glycine max","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":149,"desc_zh":"大豆（学名：Glycine max，英语：soybean）古称菽（shū），是豆科大豆属植物，其种子含有丰富的蛋白质，此名词一般都指其种子而言。一年生草本植物，高30-90厘米。 大豆是东亚的原生种植物，果实呈椭圆形、球形。因品系不同，而种皮颜色有黄色、淡绿色、黑色、棕色，所以又别名为黄豆（黄大豆）、青豆（是指青大豆，不是指豌豆）、黑豆（黑大豆）；此外，另有茶大豆。。其中，以黄豆最常见。","desc_en":"The soybean, soy bean, or soya bean (Glycine max) is a species of legume native to East Asia, widely grown for its edible bean. Soy is a staple crop, the world's most grown legume, and an important animal feed.","img":"images/353.jpg","thumb":"images/t/353.jpg","file":"Soybean.USDA.jpg","ar":0.673,"py":"dadou dd","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":354,"seq":361,"zh":"豌豆","en":"Pisum sativum","sci":"Pisum sativum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":145,"desc_zh":"豌豆（学名：Pisum sativum）为豆科豌豆属一年生或二年生攀缘草本植物，是重要的粮食和蔬菜，别称胡豆、麦豆、寒豆、小寒豆、淮豆、麻豆、青小豆、青斑豆、留豆、金豆、回回豆、麦豌豆、雪豆、毕豆、麻累、国豆、马豆等。","desc_en":"Pea is a pulse or fodder crop, but the word often refers to the seed or sometimes the pod of this flowering plant species. Peas are eaten as a vegetable. Carl Linnaeus gave the species the scientific name Pisum sativum in 1753 (meaning cultivated pea).","img":"images/354.jpg","thumb":"images/t/354.jpg","file":"NCI peas in pod.jpg","ar":1.975,"py":"wandou wd","cr_by":"Renee Comet (photographer) AV Number: AV-9400-4164","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/354.jpg","illus_thumb":"images/i/t/354.jpg","illus_file":"Illustration Pisum sativum0.jpg","illus_ar":0.629,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":355,"seq":362,"zh":"花生","en":"peanut","sci":"Arachis hypogaea","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":131,"desc_zh":"花生（学名：Arachis hypogaea）是豆科落花生属的一种植物。其果仁广泛用作食品。花生原产于南美洲，为热带及亚热带作物。","desc_en":"The peanut (Arachis hypogaea), also known as the groundnut, goober (US, via Kikongo), goober pea, pindar (US, via Kikongo) or monkey nut (UK), is a legume crop grown mainly for its edible seeds, contained in underground pods.","img":"images/355.jpg","thumb":"images/t/355.jpg","file":"Groundnuts in container.jpg","ar":0.75,"py":"huasheng hs","cr_by":"Ibn Dagara","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["南美洲"],"illus_img":"images/i/355.jpg","illus_thumb":"images/i/t/355.jpg","illus_file":"Arachis hypogaea - Köhler–s Medizinal-Pflanzen-163.jpg","illus_ar":0.673,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":356,"seq":363,"zh":"酸豆","en":"Tamarindus indica","sci":"Tamarindus indica","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":118,"desc_zh":"酸豆（学名：Tamarindus indica），别名罗望子、酸角、酸果、酸子、亚参、九层皮、泰国甜角、酸梅树、亚森果，是豆科酸豆属唯一的种，是热带乔木，原产于东部非洲，包括马达加斯加落叶林，但已被引种到亚洲热带地区、拉丁美洲和加勒比地区。英文Tamarindus由Tarmar和indus组成，Tarmar的意思为熟枣的，indus是指印度。罗望子是中国海南省三亚市的市树。","desc_en":"Tamarind (Tamarindus indica) is a leguminous tree bearing edible fruit that is indigenous to tropical Africa and naturalized in Asia. The genus Tamarindus is monotypic, meaning that it contains only this species. It belongs to the family Fabaceae.","img":"images/356.jpg","thumb":"images/t/356.jpg","file":"Tamarindus indica pods.JPG","ar":0.75,"py":"suandou sd","cr_by":"B.navez","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","非洲"],"illus_img":"images/i/356.jpg","illus_thumb":"images/i/t/356.jpg","illus_file":"Tamarindus indica - Köhler–s Medizinal-Pflanzen-134.jpg","illus_ar":0.768,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":357,"seq":364,"zh":"鹰嘴豆","en":"Cicer arietinum","sci":"Cicer arietinum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":117,"desc_zh":"鹰嘴豆（学名：Cicer arietinum）又名马豆、桃尔豆、鸡心豆、鸡豆、雪莲子等，原产自东南土耳其，逐渐驯化扩展至黎凡特地区，目前是地中海、中东、印度菜系的主要成分；而于 2019 年，印度占全球鹰嘴豆产量的 70%。在欧洲食用鹰嘴豆也十分普遍，此食材时常出现在小说里面，也是维吾尔医常用药材。因其形状奇特，尖如鹰嘴，故得鹰嘴豆之名。 鹰嘴豆的淀粉具有板栗香味。白色的品种在口感和外型上都与莲子相似。","desc_en":"The chickpea or chick pea (Cicer arietinum) is an annual legume of the family Fabaceae, subfamily Faboideae, cultivated for its edible seeds. Its different types are variously known as gram, Bengal gram, chana (চানা), garbanzo, garbanzo bean, or Egyptian pea.","img":"images/357.jpg","thumb":"images/t/357.jpg","file":"Cicer arietinum HabitusFruits BotGardBln0906a.jpg","ar":0.857,"py":"yingzuidou yzd","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":358,"seq":365,"zh":"菜豆","en":"Phaseolus vulgaris","sci":"Phaseolus vulgaris","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":117,"desc_zh":"菜豆（英语：common bean，学名：Phaseolus vulgaris）也叫云藊豆、芸豆（亦作芸豆）、架豆、刀豆、肾豆等，是一种一年生草本植物，因其干种子或绿色未成熟豆荚可食用，而在世界各地种植。菜豆的豆角称为四季豆或芸豆角。菜豆原产于美洲大陆，属豆科菜豆属植物，为北美洲三谷之一，后传入亚欧大陆并成为世界性的餐桌上常见蔬菜。","desc_en":"Phaseolus vulgaris, the common bean, is a herbaceous annual plant. Its botanical classification, along with other Phaseolus species, is as a member of the legume family, Fabaceae. It forms a green-leaved vine which produces beans inside of pods.","img":"images/358.jpg","thumb":"images/t/358.jpg","file":"Snijboon peulen Phaseolus vulgaris.jpg","ar":0.75,"py":"caidou cd","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":null},{"id":359,"seq":366,"zh":"小扁豆","en":"Lens culinaris","sci":"Lens culinaris","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":107,"desc_zh":"小扁豆（学名：Lens culinaris，英语：lentil）又称兵豆，是豆科蝶形花亚科小扁豆属（兵豆属）一年生或越年生草本植物，果实为荚果，种子呈扁平状，可作食用，故名。每株约40厘米（16英寸）高。 小扁豆有许多其他中文名，如：滨豆、小金扁豆、「鸡豆」、鸡豌豆、「鸡眼豆」。","desc_en":"The lentil (Vicia lens or Lens culinaris) is an annual legume grown for its lens-shaped edible seeds or pulses, also called lentils. It is about 40 cm (16 in) tall, and the seeds grow in pods, usually with two seeds in each.","img":"images/359.jpg","thumb":"images/t/359.jpg","file":"Lens culinaris Sturm8.jpg","ar":0.689,"py":"xiaobiandou xbd","cr_by":"Johann Georg Sturm (Painter: Jacob Sturm )","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/359.jpg","illus_thumb":"images/i/t/359.jpg","illus_file":"Lens culinaris Sturm8.jpg","illus_ar":0.689,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":360,"seq":367,"zh":"光果甘草","en":"liquorice","sci":"Glycyrrhiza glabra","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":106,"desc_zh":"光果甘草（学名：Glycyrrhiza glabra，英语：Liquorice），又名洋甘草，多年生豆科甘草属植物，原产于西亚和南欧，散见于全欧与地中海周边。尽管风味类似，但与茴芹，八角或茴香无植物学上的联系。被用作糖果和烟草的调味剂，尤见于部份欧洲和西亚国家。","desc_en":"Liquorice (Commonwealth English) or licorice (American English; see spelling differences; IPA: LIK-ər-ish, -⁠iss) is the common name of Glycyrrhiza glabra, a flowering plant of the bean family Fabaceae, from the root of which a sweet, aromatic flavouring is ex…","img":"images/360.jpg","thumb":"images/t/360.jpg","file":"Illustration Glycyrrhiza glabra0.jpg","ar":0.621,"py":"guangguogancao gggc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/360.jpg","illus_thumb":"images/i/t/360.jpg","illus_file":"Glycyrrhiza glabra - Köhler–s Medizinal-Pflanzen-207.jpg","illus_ar":0.815,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":361,"seq":368,"zh":"蚕豆","en":"Broad Bean","sci":"Vicia faba","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":105,"desc_zh":"蚕豆（学名：Vicia faba）是一年生或越年生豆科草本植物，又名胡豆、佛豆、川豆、倭豆、罗汉豆、豌豆（湖北湖南部分地区称谓），原产亚洲西南部和非洲北部。相传西汉张骞出使西域时期传入中国，8世纪左右从中国传入日本。据说为菩提僊那渡日后交给行基种植于兵库县的武库村。","desc_en":"Vicia faba, commonly known as the broad bean, fava bean, or faba bean, is a species of vetch, a flowering plant in the pea and bean family Fabaceae. It is widely cultivated as a crop for human consumption, and also as a cover crop.","img":"images/361.jpg","thumb":"images/t/361.jpg","file":"Illustration Vicia faba1.jpg","ar":0.627,"py":"candou cd","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/361.jpg","illus_thumb":"images/i/t/361.jpg","illus_file":"Illustration Vicia faba1.jpg","illus_ar":0.627,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":362,"seq":369,"zh":"胡芦巴","en":"Trigonella foenum-graecum","sci":"Trigonella foenum-graecum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":93,"desc_zh":"胡芦巴（学名：Trigonella foenum-graecum），又称云香草、香草、苦草、苦豆、苦朵菜、香苜蓿或香豆子等，为一年生豆科蝶形花亚科胡芦巴属的一种植物，其种子是调味料和中药；不仅是一种蔬菜，也是一种药材。 原产地中海地区，中国在四川、河南、甘肃、安徽等省也有栽培。 胡芦巴为一年生草本植物，株高35至85厘米，全株有香气。茎直立多丛生。三出羽状复叶互生，小叶长卵形或卵状披针形。","desc_en":"Fenugreek (; Trigonella foenum-graecum) is an annual plant in the family Fabaceae, with leaves consisting of three small obovate to oblong leaflets. It is cultivated worldwide as a semiarid crop.","img":"images/362.jpg","thumb":"images/t/362.jpg","file":"Junger Bockshornklee.jpg","ar":0.853,"py":"huluba hlb","cr_by":"Yak","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/362.jpg","illus_thumb":"images/i/t/362.jpg","illus_file":"Trigonella foenum-graecum - Köhler–s Medizinal-Pflanzen-273.jpg","illus_ar":0.816,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":363,"seq":370,"zh":"紫花苜蓿","en":"Medicago sativa","sci":"Medicago sativa","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":93,"desc_zh":"紫花苜蓿（学名：Medicago sativa， 阿拉伯语：البرسيم الحجازي），又叫做紫苜蓿、牧蓿、苜蓿、路蒸，属豆科植物。","desc_en":"Medicago sativa, commonly known as alfalfa () in North America and lucerne () in the United Kingdom, South Africa, Australia, and New Zealand, is a perennial flowering plant in the legume family, Fabaceae.","img":"images/363.jpg","thumb":"images/t/363.jpg","file":"75 Medicago sativa L.jpg","ar":0.676,"py":"zihuamuxu zhmx","cr_by":"Amédée Masclef","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/363.jpg","illus_thumb":"images/i/t/363.jpg","illus_file":"Illustration Medicago sativa1.jpg","illus_ar":0.606,"illus_by":"Prof. Dr. Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":364,"seq":371,"zh":"含羞草","en":"Mimosa pudica","sci":"Mimosa pudica","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":88,"desc_zh":"含羞草（学名：Mimosa pudica），由于其独特的生理习性有着众多的别名昵称，如喝呼草、知羞草、怕丑草等。含羞草原产于美洲热带的巴西，是豆科含羞草属的一种多年生草本植物。由于这种植物生长力顽强，所以在不少国家，含羞草都被当成是一种野草 。花语：敏锐，细腻的感触，纤细的感情。花色有粉红和紫红。花期为6月至9月。","desc_en":"Mimosa pudica (also called sensitive plant, sleepy grass, sleepy plant, action plant, humble plant, touch-me-not, touch-and-die, shame plant or shy plant) is a creeping annual or perennial flowering plant of the pea/legume family Fabaceae.","img":"images/364.jpg","thumb":"images/t/364.jpg","file":"Mimosa-pudica-SF25124.jpg","ar":1.333,"py":"hanxiucao hxc","cr_by":"Steve Fitzgerald","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":365,"seq":372,"zh":"绿豆","en":"Vigna radiata","sci":"Vigna radiata","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":86,"desc_zh":"绿豆（学名：Vigna radiata (L.) R. Wilczek）是一种豆科、蝶形花亚科豇豆属植物。别名“青小豆”、“植豆”、“交豆”、“文豆”、“八重生”、“菉豆”。","desc_en":"The mung bean or green gram (Vigna radiata) is a plant species in the legume family. It is mainly cultivated in East, Southeast, and in South Asia and used as an ingredient in both savoury and sweet dishes.","img":"images/365.jpg","thumb":"images/t/365.jpg","file":"Mung beans (Vigna radiata).jpg","ar":1.501,"py":"ldou ld","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":366,"seq":373,"zh":"长角豆","en":"Ceratonia siliqua","sci":"Ceratonia siliqua","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":81,"desc_zh":"长角豆（学名：Ceratonia siliqua）是豆科长角豆属的植物，原产于地中海东部。目前已由人工引种栽培。由于这种子的重量一致（重量多在200毫克左右），所以早期钻石的重量用这种植物的种子称量。直至1907年国际商定为宝石计量单位「克拉」开始沿用至今。","desc_en":"The carob ( KARR-əb; Ceratonia siliqua) is a flowering evergreen tree or shrub in the Caesalpinioideae subfamily of the legume family, Fabaceae. The carob tree is native to the Mediterranean region and the Middle East.","img":"images/366.jpg","thumb":"images/t/366.jpg","file":"Algarrobo múltiple.jpg","ar":1.333,"py":"changjiaodou cjd","cr_by":"Eduardo Milla","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/366.jpg","illus_thumb":"images/i/t/366.jpg","illus_file":"58 Ceratonia siliqua par Pierre-Joseph Redouté.jpeg","illus_ar":0.707,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":367,"seq":374,"zh":"木豆","en":"Cajanus cajan","sci":"Cajanus cajan","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":76,"desc_zh":"木豆（学名：Cajanus cajan），又名蒲姜豆、木豆、米豆、树荳、柳豆、白树豆、花螺树豆、观音豆、番仔豆、山豆根，为豆科木豆属下的一个种，台湾一般称为树豆，阿美语称 fata'an，泰雅语称 singut，大武垅语称 taluvawvaw,布农语称“qalidang”，可采集食用，又也可作榨油用。最多生长于印度东部和埃及，在台湾也很常见为人所栽培，为许多台湾原住民族的重要粮食之一，阿美族人将这种树豆视为吉祥物。","desc_en":"The pigeon pea (Cajanus cajan) is a perennial legume from the family Fabaceae native to the Eastern Hemisphere. The pigeon pea is widely cultivated in tropical and semitropical regions around the world, being commonly consumed in the Indian Subcontinent, South…","img":"images/367.jpg","thumb":"images/t/367.jpg","file":"Guandu.jpg","ar":0.541,"py":"mudou md","cr_by":"Lígia Prado","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":368,"seq":375,"zh":"刺槐","en":"Robinia pseudoacacia","sci":"Robinia pseudoacacia","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":73,"desc_zh":"刺槐又名洋槐，是原生于北美洲的一个树种，但现在被广泛引种到亚洲、欧洲等地。汉语名称取自其与同属蝶形花亚科的槐属的相似度（刺槐族仅在美洲存在分布）；拉丁学名中的种名“pseudoacacia”是假金合欢或假相思树之意，尽管两属同属苏木亚科与洋槐关系甚远。","desc_en":"Robinia pseudoacacia, commonly known as black locust, is a medium-sized hardwood deciduous tree, belonging to the tribe Robinieae of the legume family. Another common name is false acacia, a literal translation of the specific name (pseudo [Greek ψευδο-] meani…","img":"images/368.jpg","thumb":"images/t/368.jpg","file":"Korina 2011-05-20 Robinia pseudoacacia 3.jpg","ar":0.75,"py":"cihuai ch","cr_by":"Annabell Hormann / korina.info","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲","非洲","北美洲"],"illus_img":"images/i/368.jpg","illus_thumb":"images/i/t/368.jpg","illus_file":"T2 16 Robinia pseudoacacia par Pierre-Joseph Redouté.jpeg","illus_ar":0.717,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":369,"seq":376,"zh":"红菽草","en":"Trifolium pratense","sci":"Trifolium pratense","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":66,"desc_zh":"红菽草（学名：Trifolium pratense），又名红车轴草、红花苜宿、红三叶草、红花三叶草，为豆科三叶草属下的一种多年生草本植物，高20—80 cm（8—31英寸），耐旱，可以作为牧草。它原产于地中海附近地区，每年5月到10月开粉红色花。在引入北美之后成为入侵物种。","desc_en":"Trifolium pratense (from Latin prātum, meaning meadow), red clover, is a herbaceous species of flowering plant in the bean family, Fabaceae. It is native to the Old World, but planted and naturalised in many other regions.","img":"images/369.jpg","thumb":"images/t/369.jpg","file":"Trifolium pratense - Keila2.jpg","ar":0.75,"py":"hongshucao hsc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null,"illus_img":"images/i/369.jpg","illus_thumb":"images/i/t/369.jpg","illus_file":"Illustration Trifolium pratense0.jpg","illus_ar":0.605,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":370,"seq":377,"zh":"鸡母珠","en":"Abrus precatorius","sci":"Abrus precatorius","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":65,"desc_zh":"鸡母珠（学名：Abrus precatorius），又名相思子、美人豆、亦被称作红豆，是豆科相思子属的一种有毒植物，泛热带分布。","desc_en":"Abrus precatorius, commonly known as jequirity bean or rosary pea, is a herbaceous flowering plant in the bean family Fabaceae. It is a slender, perennial climber with long, pinnate-leafleted leaves that twines around trees, shrubs, and hedges.","img":"images/370.jpg","thumb":"images/t/370.jpg","file":"Abrus precatorius (L.) Fabaceae (21617028808).jpg","ar":1.378,"py":"jimuzhu jmz","cr_by":"Len Worthington","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"藤本","origin":["亚洲","大洋洲"],"illus_img":"images/i/370.jpg","illus_thumb":"images/i/t/370.jpg","illus_file":"Abrus precatorius - Köhler–s Medizinal-Pflanzen-002.jpg","illus_ar":0.747,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":371,"seq":378,"zh":"白车轴草","en":"Trifolium repens","sci":"Trifolium repens","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":63,"desc_zh":"白三叶草（学名：Trifolium repens），又名白花三叶草、白三叶、菽草、白车轴草或白花苜蓿，是一种产自欧洲、北非及西亚的三叶草。它们广泛的引进世界各地，尤其是北美洲的草地甚为普遍，中国南北各地均有分布。","desc_en":"Trifolium repens, the white clover, is a herbaceous perennial plant in the bean family, Fabaceae (also known as Leguminosae). The species is native to Eurasia and is one of the most widely cultivated types of clover.","img":"images/371.jpg","thumb":"images/t/371.jpg","file":"Illustration Trifolium repens1.jpg","ar":0.623,"py":"baichezhoucao bczc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"],"illus_img":"images/i/371.jpg","illus_thumb":"images/i/t/371.jpg","illus_file":"Illustration Trifolium repens1.jpg","illus_ar":0.623,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":372,"seq":379,"zh":"凤凰木","en":"Delonix regia","sci":"Delonix regia","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":60,"desc_zh":"凤凰木（学名：Delonix regia，英语：Poinciana）又名影树、凤凰树、凤凰花、金凤、火凤凰、洋楹、红花楹（广州）、火树、红火楹、火焰木、森之炎、攀霞拿等，为豆科凤凰木属的植物。在香港，凤凰木的花期约为五月至七月，而在台湾则在初夏左右开花。有趣的是，这种树开花的时间，通常也会在学校的毕业季节前后。 凤凰木的特征就是华丽的花朵，以及外观如蕨类植物般的绿叶。它主要生长在世界上许多热带或亚热带地区，作为装饰用树和遮蔽太阳的树木。","desc_en":"Delonix regia is a species of flowering plant in the bean family Fabaceae, subfamily Caesalpinioideae native to Madagascar. It is noted for its fern-like leaves and flamboyant display of orange-red flowers over summer.","img":"images/372.jpg","thumb":"images/t/372.jpg","file":"Royal Poinciana.jpg","ar":1.333,"py":"fenghuangmu fhm","cr_by":"Averette","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["非洲"]},{"id":373,"seq":380,"zh":"阿勒勃","en":"Cassia fistula","sci":"Cassia fistula","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":59,"desc_zh":"阿勒勃（学名：Cassia fistula），讹作阿勃勒（台湾通称），又称波斯皂荚、婆罗门皂荚、腊肠树（中国大陆通称）、猪肠豆（香港通称）、南蛮皂荚（日本通称）、长果子树、牛角树、雨兰松、黄金雨、金急雨（英语：golden shower），是一种豆科苏木亚科的植物。原产于南亚南部，从巴基斯坦南部往东直到印度及缅甸，往南直到斯里兰卡。阿勒勃常被误称为金链花，但金链花其实是毒豆，一种原产欧洲的有毒植物。","desc_en":"Cassia fistula, also known as golden shower, purging cassia, Indian laburnum, kani konna, or pudding-pipe tree, is a flowering plant in the family Fabaceae. The species is native to the Indian subcontinent and adjacent regions of Southeast Asia.","img":"images/373.jpg","thumb":"images/t/373.jpg","file":"Cassia fistula (1).JPG","ar":1.501,"py":"alebo alb","cr_by":"Delonix","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/373.jpg","illus_thumb":"images/i/t/373.jpg","illus_file":"James Bruce - Cassia Fistula (Purging cassia), finished drawing of leafy shoot with flowers - B1977.14.9091 - Yale Center for British Art.jpg","illus_ar":0.713,"illus_by":"James Bruce","illus_lic":"CC0","illus_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en"},{"id":374,"seq":381,"zh":"蝶豆","en":"Clitoria ternatea","sci":"Clitoria ternatea","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":59,"desc_zh":"蝶豆（学名：Clitoria ternatea），是豆科蝶豆属的植物。由于蝶豆的花外观类似人类女性外生殖器，因此它的拉丁语属名被命名为「Clitoria」（蝶豆属），词源为「阴蒂」（Clitoris）。 根及种子有毒，可造成恶心、呕吐、腹泻。","desc_en":"Clitoria ternatea, commonly known as Shankhupushpam (conch-shaped flower), Asian pigeonwings, bluebellvine, blue pea, butterfly pea, cordofan pea, or Darwin pea, is a plant species belonging to the family Fabaceae and native to the Indonesian island of Ternate…","img":"images/374.jpg","thumb":"images/t/374.jpg","file":"Clitoria ternatea - Asian pigeonwings in Bhopal, India September 2025.jpg","ar":0.562,"py":"diedou dd","cr_by":"Suyash.dwivedi","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":375,"seq":382,"zh":"豇豆","en":"Vigna unguiculata","sci":"Vigna unguiculata","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":59,"desc_zh":"豇（jiāng）豆（学名：Vigna unguiculata）是一种豆科豇豆属的植物。豆荚稍肉质且柔软，外观呈长条状圆柱形，长度大约30—50公分，直径约0.6—1.0公分；内有种子多颗，种子长椭圆形或圆柱形或稍肾形，长 0.6—1.2 公分，黄白色、暗红色或其他颜色。 豇豆是最重要的食品豆科作物之一，涵盖亚洲、非洲、欧洲南部、中美洲和南美洲等半干旱热带地区。","desc_en":"The cowpea (Vigna unguiculata) is an annual herbaceous legume from the genus Vigna. It can be erect, semierect (trailing), or climbing. A high level of morphological diversity is found within the species with large variations in the size, shape, and structure…","img":"images/375.jpg","thumb":"images/t/375.jpg","file":"BlackeyeBean.jpg","ar":1.331,"py":"jiangdou jd","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["非洲"]},{"id":391,"seq":383,"zh":"Polygala vulgaris","en":"Polygala vulgaris","sci":"Polygala vulgaris","order_en":"Fabales","order_zh":"豆目","family_en":"Polygalaceae","family_zh":"远志科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Polygala vulgaris, known as the common milkwort, is a herbaceous perennial plant of the genus Polygala in the family Polygalaceae. It grows in Northwen Europe, Western Russia, and Turkey, and has been introduced to parts of the U.S.","img":"images/391.jpg","thumb":"images/t/391.jpg","file":"Polygala vulgaris 290504.jpg","ar":0.845,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"],"illus_img":"images/i/391.jpg","illus_thumb":"images/i/t/391.jpg","illus_file":"Illustration Polygala vulgaris0.jpg","illus_ar":0.558,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":392,"seq":384,"zh":"Polygala amarella","en":"Polygala amarella","sci":"Polygala amarella","order_en":"Fabales","order_zh":"豆目","family_en":"Polygalaceae","family_zh":"远志科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Polygala amarella (or P. amara), commonly known as dwarf milkwort or Kentish milkwort, is a plant of the family Polygalaceae. A European native, it grows on chalky grass land and limestone mountain pastures.","img":"images/392.jpg","thumb":"images/t/392.jpg","file":"Polygala amarella1a.jpg","ar":0.692,"py":"","cr_by":"Algirdas","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"],"illus_img":"images/i/392.jpg","illus_thumb":"images/i/t/392.jpg","illus_file":"Polygala amarella illustration (04).jpg","illus_ar":0.602,"illus_by":"Nees von Esenbeck, T.F.L., Wijhe (Weyhe), M.F., Plantae medicinales (1828-1833) Pl. Medicin.","illus_lic":"Public domain","illus_licurl":null},{"id":1103,"seq":385,"zh":"Polygala serpyllifolia","en":"Polygala serpyllifolia","sci":"Polygala serpyllifolia","order_en":"Fabales","order_zh":"豆目","family_en":"Polygalaceae","family_zh":"远志科","iucn":null,"langs":23,"desc_zh":null,"desc_en":"Polygala serpyllifolia, the heath milkwort, is a European native perennial of heaths and grassy places.","img":"images/1103.jpg","thumb":"images/t/1103.jpg","file":"Polygala serpyllifolia.jpg","ar":1.333,"py":"","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"]},{"id":393,"seq":386,"zh":"桃","en":"Prunus persica","sci":"Prunus persica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":159,"desc_zh":"桃（学名：Prunus persica）是源自中国，蔷薇科李属的一种植物，花可以观赏，果实多汁，作为水果，可以生食或制桃脯、罐头等，核仁也可以食用。 桃品种众多，口感分脆桃和软桃，果肉有白色和黄色的，通常颜色略带粉红，一般在日本最受欢迎的品种多为白色果肉，香甜多汁；欧洲、澳洲和北美洲的人则在历史上较为喜欢黄色果肉而味道偏酸的品种。在原产国中国则百花齐放，由于南北方差异巨大，桃子种类丰富，脆桃、蜜桃、油桃等都深受人们喜爱。","desc_en":"The peach (Prunus persica) is a deciduous tree that bears edible juicy fruits with various characteristics. Most are simply called peaches, while the glossy-skinned, non-fuzzy varieties are called nectarines.","img":"images/393.jpg","thumb":"images/t/393.jpg","file":"Peaches at Applecrest Farm Orchards - 20108462909.jpg","ar":1.501,"py":"tao t","cr_by":"Allagash Brewing","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":null,"illus_img":"images/i/393.jpg","illus_thumb":"images/i/t/393.jpg","illus_file":"Illustration Prunus persica0.jpg","illus_ar":0.618,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":394,"seq":387,"zh":"草莓","en":"strawberry","sci":"Fragaria × ananassa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":135,"desc_zh":"草莓（学名：Fragaria × ananassa；英语：strawberry），中国大陆和台湾称草莓，在香港常叫为士多啤梨，为草莓属中最常见的杂交栽培种，有时为与其它草莓属物种相区分也称花园草莓。草莓是多年生草本植物，植株寿命一般为3年左右。 人们所食用的“果实”部份实为假果，植物学定义上真正的果实是布满草莓表面的众多小点状物，果实类型为瘦果。不同于大多数水果由子房发育而成，草莓的食用部份是由花托在授粉后发育变大而成。","desc_en":"The garden strawberry (or simply strawberry; Fragaria × ananassa) is a widely grown hybrid plant cultivated worldwide for its fruit. The genus Fragaria, the strawberries, is in the rose family, Rosaceae.","img":"images/394.jpg","thumb":"images/t/394.jpg","file":"Strawberries.JPG","ar":1.333,"py":"caomei cm","cr_by":null,"cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":null},{"id":395,"seq":388,"zh":"扁桃","en":"Prunus amygdalus","sci":"Prunus amygdalus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":134,"desc_zh":"扁桃（学名：Prunus amygdalus，英语：almond）是蔷薇科李属的一个种，原产于波斯，唐朝的《酉阳杂俎》和《岭表录异》对“偏桃木”有所记载。其果核内的种子是常见的零嘴，香港、台湾、星马等中国大陆以外的中文地区所一般称的「杏仁」其实是扁桃仁。扁桃分为甜味扁桃(英文:Sweet Almond)和苦味扁桃(英文:Bitter Almond)两种，其中甜扁桃可以食用，也就是一般食用的扁桃，苦扁桃则毒性过高无法食用。","desc_en":"The almond (Prunus amygdalus, syn. Prunus dulcis (Mill.) D.A.Webb, nom. illeg. non Prunus dulcis Rouchy) is a species of tree from the genus Prunus. Along with the peach, it is classified in the subgenus Amygdalus, distinguished from the other subgenera by cor…","img":"images/395.jpg","thumb":"images/t/395.jpg","file":"Almonds - in shell, shell cracked open, shelled, blanched.jpg","ar":1.501,"py":"biantao bt","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/395.jpg","illus_thumb":"images/i/t/395.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 43 Prunus amygdalus, Oxalis acetosella (6022340342).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":396,"seq":389,"zh":"杏","en":"Prunus armeniaca","sci":"Prunus armeniaca","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"DD","langs":129,"desc_zh":"普通杏（学名：Prunus armeniaca）或杏，是李属李亚属植物，为最常见的栽培杏种；其果实又称杏子、杏实、杏桃，其果肉、果仁均可食用。","desc_en":"Prunus armeniaca is the most commonly cultivated apricot species. The native range is somewhat uncertain due to its extensive prehistoric cultivation. Genetic studies indicate Central Asia is the center of origin.","img":"images/396.jpg","thumb":"images/t/396.jpg","file":"Apricots.jpg","ar":1.325,"py":"xing x","cr_by":"Fir0002","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"],"illus_img":"images/i/396.jpg","illus_thumb":"images/i/t/396.jpg","illus_file":"Prunus armeniaca Sturm08061.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":397,"seq":390,"zh":"榅桲","en":"Cydonia oblonga","sci":"Cydonia oblonga","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":115,"desc_zh":"榅桲（拉丁学名：Cydonia oblonga），又名木梨，是榅桲属中唯一物种。 落叶小乔木或灌木，一般为5～8米高；卵形或长椭圆形叶子，背面密生白色软毛，单叶互生，叶长60～110公厘；晚春或初夏开花，花白色或粉红色，有5瓣，直径约50公厘，花梗和花萼也有毛；果实秋季成熟，梨形或苹果形，未成熟时青色，有白毛，成熟后金黄色，直径有70～110公厘，味甘酸。 原生于中亚和高加索山区；现被引种到世界各地，成为重要的水果品种。","desc_en":"The quince (; Cydonia oblonga) is the sole member of the genus Cydonia in the Malinae subtribe (which contains apples, pears, and other fruits) of the Rosaceae family.","img":"images/397.jpg","thumb":"images/t/397.jpg","file":"Cydonia.jpg","ar":1.333,"py":"wenbo wb","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null,"illus_img":"images/i/397.jpg","illus_thumb":"images/i/t/397.jpg","illus_file":"Cydonia oblonga - Köhler–s Medizinal-Pflanzen-049.jpg","illus_ar":0.731,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":398,"seq":391,"zh":"甜樱桃","en":"Prunus avium","sci":"Prunus avium","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":103,"desc_zh":"欧洲甜樱桃（学名：Prunus avium）又名甜樱桃、大樱桃、甜车厘子、车厘子，为蔷薇科李属的植物，是最主要的鲜食樱桃物种。原生于欧洲、非洲西北部和亚洲西部，分布从不列颠群岛南至摩洛哥和突尼西亚，东至瑞典南部、波兰、乌克兰、高加索、伊朗和阿富汗。","desc_en":"Prunus avium, commonly called wild cherry, sweet cherry or gean, is a species of cherry, a flowering plant in the rose family, Rosaceae. It is native to western Eurasia and naturalized elsewhere. It is an ancestor of P. cerasus (sour cherry).","img":"images/398.jpg","thumb":"images/t/398.jpg","file":"Prunus avium fruit.jpg","ar":0.995,"py":"tianyingtao tyt","cr_by":"MPF","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/398.jpg","illus_thumb":"images/i/t/398.jpg","illus_file":"Illustration Prunus avium0 clean.jpg","illus_ar":0.583,"illus_by":"File:Illustration Prunus avium0.jpg : PLEASE COMPLETE AUTHOR INFORMATION derivative work: Kenraiz","illus_lic":"Public domain","illus_licurl":null},{"id":399,"seq":392,"zh":"绒毛悬钩子","en":"Rubus idaeus","sci":"Rubus idaeus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":97,"desc_zh":"覆盆子（学名：Rubus idaeus）是蔷薇科悬钩子属的木本植物，其果实味道酸甜，植株的枝干上长有倒钩刺。","desc_en":"Rubus idaeus (raspberry, also called red raspberry or occasionally European red raspberry to distinguish it from other raspberry species) is a red-fruited species of Rubus native to Eurasia and commonly cultivated in other temperate regions.","img":"images/399.jpg","thumb":"images/t/399.jpg","file":"Raspberry - whole (Rubus idaeus).jpg","ar":1.502,"py":"rongmaoxuangouzi rmxgz","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"],"illus_img":"images/i/399.jpg","illus_thumb":"images/i/t/399.jpg","illus_file":"Rubus idaeus - Köhler–s Medizinal-Pflanzen-124.jpg","illus_ar":0.807,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":400,"seq":393,"zh":"欧洲李","en":"Prunus domestica","sci":"Prunus domestica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"DD","langs":95,"desc_zh":"欧洲李（学名：Prunus domestica）是蔷薇科李属的一个栽培种。欧洲李与樱桃李亲缘关系较近，可能从樱桃李驯化而来，也可能源于樱桃李和黑刺李的杂交。","desc_en":"Prunus domestica is a species of flowering plant in the family Rosaceae. A deciduous tree, it includes many varieties of the fruit trees known as plums in English, though not all plums belong to this species.","img":"images/400.jpg","thumb":"images/t/400.jpg","file":"Fruits Prunus domestica.jpg","ar":1.333,"py":"ouzhouli ozl","cr_by":"YAMAMAYA","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null,"illus_img":"images/i/400.jpg","illus_thumb":"images/i/t/400.jpg","illus_file":"Prunus domestica Sturm08063.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":401,"seq":394,"zh":"黑刺李","en":"Prunus spinosa","sci":"Prunus spinosa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":91,"desc_zh":"黑刺李（学名：Prunus spinosa），别名刺李，为蔷薇科李属的植物。分布于西亚、欧洲、北非以及中国陕西等地，生长于海拔800米至1,200米的地区，常生于林中旷地、森林草原地带、林缘以及河谷旁。","desc_en":"Prunus spinosa, called blackthorn or sloe, is a species of flowering plant in the rose family, Rosaceae. It is native to Europe and West Asia, and has been naturalised in parts of North America.","img":"images/401.jpg","thumb":"images/t/401.jpg","file":"Closeup of blackthorn aka sloe aka prunus spinosa sweden 20050924.jpg","ar":1.333,"py":"heicili hcl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/401.jpg","illus_thumb":"images/i/t/401.jpg","illus_file":"Prunus spinosa Sturm62.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":402,"seq":395,"zh":"欧洲酸樱桃","en":"Prunus cerasus","sci":"Prunus cerasus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":89,"desc_zh":"欧洲酸樱桃（学名：Prunus cerasus）又名酸樱桃、酸车厘子，是蔷薇科李属的植物。分布在欧洲、西亚以及中国大陆的新疆等地。可用来酿酒。","desc_en":"Prunus cerasus (sour cherry, tart cherry, or dwarf cherry) is an Old World species of Prunus in the subgenus Cerasus (cherries). It has two main groups of cultivars: the dark-red Morello cherry and the lighter-red Amarelle cherry. The sour pulp is edible.","img":"images/402.jpg","thumb":"images/t/402.jpg","file":"Prunus cerasus - Köhler–s Medizinal-Pflanzen-113.jpg","ar":0.779,"py":"ouzhousuanyingtao ozsyt","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/402.jpg","illus_thumb":"images/i/t/402.jpg","illus_file":"Prunus cerasus - Köhler–s Medizinal-Pflanzen-113.jpg","illus_ar":0.779,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":403,"seq":396,"zh":"犬蔷薇","en":"Rosa canina","sci":"Rosa canina","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":86,"desc_zh":"犬蔷薇（学名：Rosa canina；英语：dog rose）是蔷薇科蔷薇属落叶灌木，也叫狗蔷薇、狗牙蔷薇，原产于欧洲、非洲西北部以及亚洲西部，是罗马尼亚的国花，也是英格兰汉普郡的郡花。","desc_en":"Rosa canina, the dog rose, is a variable climbing, wild rose species native to Europe, northwest Africa, and western Asia.","img":"images/403.jpg","thumb":"images/t/403.jpg","file":"Divlja ruza cvijet 270508.jpg","ar":0.75,"py":"quanqiangwei qqw","cr_by":"Roberta F.","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/403.jpg","illus_thumb":"images/i/t/403.jpg","illus_file":"Illustration Rosa canina1.jpg","illus_ar":0.567,"illus_by":"Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":404,"seq":397,"zh":"枇杷","en":"Eriobotrya japonica","sci":"Eriobotrya japonica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":86,"desc_zh":"枇杷（学名：Eriobotrya japonica），古名卢橘，又名金丸、芦枝、小芒果、琵琶果，是蔷薇科中的枇杷属的一种植物。枇杷原产中国东南部，因果子形状似乐器琵琶而名。","desc_en":"The loquat (Eriobotrya japonica, Chinese: 枇杷; Pinyin: pípá) is a large evergreen shrub or tree grown commercially for its orange coloured fruits. It is also cultivated as an ornamental plant.","img":"images/404.jpg","thumb":"images/t/404.jpg","file":"Portugal - Algarve - Barao de Sao Joao - Ann scrumping loquats (25187478424).jpg","ar":0.75,"py":"pipa pp","cr_by":"muffinn from Worcester, UK","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["亚洲"]},{"id":405,"seq":398,"zh":"欧洲花楸","en":"Sorbus aucuparia","sci":"Sorbus aucuparia","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":79,"desc_zh":"北欧花楸（学名：Sorbus aucuparia），也叫欧洲花楸，是蔷薇科花楸属的一种植物。广泛分布于欧亚大陆及非洲北部部分地区。其果实可以食用，叶子可以入药。山梨糖醇和山梨酸最早是从其中提取出来的。","desc_en":"Sorbus aucuparia, commonly called rowan (, also UK: ) and mountain-ash, is a species of deciduous tree or shrub in the rose family. The tree has a slender trunk with smooth bark, a loose and roundish crown, and its leaves are pinnate in pairs of leaflets on a…","img":"images/405.jpg","thumb":"images/t/405.jpg","file":"Rowan berries.JPG","ar":1.501,"py":"ouzhouhuaqiu ozhq","cr_by":"Thomas Bjørkan","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/405.jpg","illus_thumb":"images/i/t/405.jpg","illus_file":"Sorbus aucuparia — Flora Batava — Volume v4.jpg","illus_ar":0.731,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":406,"seq":399,"zh":"稠李","en":"Prunus padus","sci":"Prunus padus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":79,"desc_zh":"稠李（学名：Prunus padus），又名臭耳子（甘肃）、臭李子（东北），是蔷薇科李属的植物，原生于欧洲至东亚一带。","desc_en":"Prunus padus, known as bird cherry, hackberry (unrelated to the genus Celtis), hagberry, or Mayday tree, is a flowering plant in the rose family. It is a deciduous small tree or large shrub up to 16 metres (52 ft) tall, the type species of the subgenus Padus,…","img":"images/406.jpg","thumb":"images/t/406.jpg","file":"Bird cherry tree 1.jpg","ar":1.333,"py":"chouli cl","cr_by":"Игоревич","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/406.jpg","illus_thumb":"images/i/t/406.jpg","illus_file":"Prunus padus — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":416,"seq":400,"zh":"无花果","en":"Ficus carica","sci":"Ficus carica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":"LC","langs":152,"desc_zh":"无花果（学名：Ficus carica）是桑科榕属的一种落叶小乔木，果实呈球根状，无花果尾部有一个小孔，花则生长于果内，在近小孔处长有雄花，远离小孔的顶部长有雌花，另外生有不育花（瘿花），花粉由榕小蜂传播。无花果非常好繁殖，最简单的方法就是扦插，无花果就是一种水果。 无花果原产于中东和西亚地区，栽培历史已超过五千多年。因外观见果不见花而得名，另有映日果、优昙钵、阿驵、底珍树、蜜果和阿驵（《酉阳杂俎》、译自波斯语：anjir）等别名。","desc_en":"The fig is the edible fruit of Ficus carica (the common fig), a species of tree or shrub in the flowering plant family Moraceae, native to the Mediterranean region, and to western and southern Asia.","img":"images/416.jpg","thumb":"images/t/416.jpg","file":"Illustration Ficus carica0.jpg","ar":0.634,"py":"wuhuaguo whg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/416.jpg","illus_thumb":"images/i/t/416.jpg","illus_file":"Illustration Ficus carica0.jpg","illus_ar":0.634,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":417,"seq":401,"zh":"菠萝蜜","en":"Artocarpus heterophyllus","sci":"Artocarpus heterophyllus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":115,"desc_zh":"波罗蜜（学名：Artocarpus heterophyllus），是桑科波罗蜜属常绿乔木，另外还有一种名称相似的植物小波罗蜜。","desc_en":"The jackfruit, jakfruit or nangka (Artocarpus heterophyllus) is a species of tree in the fig, mulberry, and breadfruit family (Moraceae). The jackfruit is the largest tree fruit, reaching as much as 55 kg (120 pounds) in weight, 90 cm (35 inches) in length, an…","img":"images/417.jpg","thumb":"images/t/417.jpg","file":"Artocarpus heterophyllus 3.jpg","ar":1.45,"py":"boluomi blm","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null,"illus_img":"images/i/417.png","illus_thumb":"images/i/t/417.png","illus_file":"Artocarpus heterophyllus Illustration ப.png","illus_ar":1.251,"illus_by":"KarunyaBaskar","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":418,"seq":402,"zh":"面包树","en":"breadfruit","sci":"Artocarpus altilis","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":98,"desc_zh":"太平洋面包树（学名：Artocarpus altilis），旧称面包树，又称面包果、罗蜜树、马槟榔、面磅树，夏威夷当地人称为 Ulu，属桑科桂木属。桂木属又名「波罗蜜属」，太平洋面包树的果实很像「菠萝蜜」水果，但是体积较「菠萝蜜」小，大约是一个手掌大小。 太平洋面包树原产于新几内亚以及马来群岛，如今因人类传播而分布波利尼西亚，印度南部，加勒比地区等热带地区。","desc_en":"Breadfruit (Artocarpus altilis) is a species of flowering tree in the mulberry and jackfruit family (Moraceae). Its name is derived from the texture of the moderately ripe fruit when cooked, similar to freshly baked bread and having a potato-like flavor.","img":"images/418.jpg","thumb":"images/t/418.jpg","file":"Artocarpus altilis (fruit).jpg","ar":0.75,"py":"mianbaoshu mbs","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null,"illus_img":"images/i/418.jpg","illus_thumb":"images/i/t/418.jpg","illus_file":"The American Flora. Vol. 2, 1855 - pl. 35 Artocarpus altilis (8079584892).jpg","illus_ar":0.719,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":419,"seq":403,"zh":"菩提树","en":"Ficus religiosa","sci":"Ficus religiosa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":"LC","langs":71,"desc_zh":"菩提树（学名：Ficus religiosa），又称毕钵罗树、菩提榕，是一种桑科榕属（又称无花果属）植物。原产于印度也是印度的国树，在中国西南部、以及中南半岛也有。菩提树的别名有：神圣之树、思维树、天竺菩提树、印度菩提树、佛树、觉树、道树、道场树。是佛教三大圣树之一，另外两个是：无忧树、娑罗双树。","desc_en":"Ficus religiosa or sacred fig is a species of fig native to the Indian subcontinent and Indochina that belongs to Moraceae, the fig or mulberry family. It is also known as the bodhi tree, bo tree, peepul tree, peepal tree, pipala tree or ashvattha tree (in Ban…","img":"images/419.jpg","thumb":"images/t/419.jpg","file":"Bodhi Baum (Ficus religiosa).jpg","ar":1.775,"py":"putishu pts","cr_by":"Burkhard Mücke","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":420,"seq":404,"zh":"白桑","en":"Morus alba","sci":"Morus alba","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":68,"desc_zh":"白桑（Morus alba）是桑属的一种小型到中型的落叶乔木，高度约10–20 米。白桑原生于中国北部，并广于世界各地种植。由于白桑是养蚕业的重要饲料，很早就在中国培育，果实称为桑椹，初生白色，成熟后成为紫黑色。花为雌雄异株，雄花为柔荑花序，雌花为穗状花序。根皮（桑白皮）、桑椹、桑叶都可以作为中药使用。此外桑椹可以酿酒，树皮可以造纸，造出的纸称为“桑皮纸”。 其种加词“alba”意为“白色的”。","desc_en":"Morus alba, known as white mulberry, common mulberry and silkworm mulberry, is a fast-growing, small to medium-sized mulberry tree which grows to 10–20 m (33–66 ft) tall. It is native to China and is widely cultivated and naturalized elsewhere.","img":"images/420.jpg","thumb":"images/t/420.jpg","file":"Morus-alba.jpg","ar":1.333,"py":"baisang bs","cr_by":"GerardM","cr_lic":"CC BY-SA 2.1 es","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.1/es/deed.en","habit":"乔木","origin":["亚洲"]},{"id":421,"seq":405,"zh":"黑桑","en":"Morus nigra","sci":"Morus nigra","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":67,"desc_zh":"黑桑（学名：Morus nigra）为桑科桑属的植物。起源于亚美尼亚高原，分布在亚洲以及中国大陆的新疆等地，目前已由人工引种栽培。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Morus nigra, or the black mulberry, is a species of flowering plant in the family Moraceae that is native to southwestern Asia, where it has been cultivated for so long that its precise natural range is unknown.","img":"images/421.jpg","thumb":"images/t/421.jpg","file":"Illustration Morus nigra0.jpg","ar":0.67,"py":"heisang hs","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"],"illus_img":"images/i/421.jpg","illus_thumb":"images/i/t/421.jpg","illus_file":"Morus nigra Sturm04039.jpg","illus_ar":0.685,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":423,"seq":406,"zh":"异株荨麻","en":"Urtica dioica","sci":"Urtica dioica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":"LC","langs":88,"desc_zh":"异株荨麻（学名：Urtica dioica）是荨麻科荨麻属的植物。分布在喜马拉雅西部、北非、亚洲、欧洲、北美以及中国大陆的西藏、新疆、青海等地，生长于海拔3,300米至3,900米的地区，常生长在山坡阴湿处。茎叶表面遍布毒刺，碰触时会注入许多化学物质，造成刺痛。","desc_en":"Urtica dioica, often known as common nettle, burn nettle, stinging nettle, nettle leaf, or just a nettle or stinger, is a herbaceous perennial flowering plant in the family Urticaceae.","img":"images/423.jpg","thumb":"images/t/423.jpg","file":"Brennnessel 1.JPG","ar":1.228,"py":"yizhuqianma yzqm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/423.jpg","illus_thumb":"images/i/t/423.jpg","illus_file":"Illustration Urtica dioica0.jpg","illus_ar":0.622,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":424,"seq":407,"zh":"苎麻","en":"Boehmeria nivea","sci":"Boehmeria nivea","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":null,"langs":55,"desc_zh":"苎麻（学名：Boehmeria nivea）为荨麻科苎麻属的一种。原生于东亚，包括中国及中印半岛等地区。作为农作物而被引入到世界各地。","desc_en":"Boehmeria nivea, commonly known as ramie, Chinese grass or Chinese silk plant, is a monoecious shrub or subshrub in the family Urticaceae commonly found in China.","img":"images/424.jpg","thumb":"images/t/424.jpg","file":"Boehmeria nivea 1.jpg","ar":1.333,"py":"zhuma zm","cr_by":"Sphl","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"]},{"id":425,"seq":408,"zh":"欧荨麻","en":"Urtica urens","sci":"Urtica urens","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":null,"langs":50,"desc_zh":"欧荨麻（学名：Urtica urens）为荨麻科荨麻属的植物。分布在西伯利亚、亚洲、非洲、欧洲、高加索以及中国大陆的西藏、青海、辽宁、新疆等地，生长于海拔2,800米至2,900米的地区，多生长于林缘路边及住宅旁，目前尚未由人工引种栽培。","desc_en":"Urtica urens, commonly known as annual nettle, dwarf nettle, small nettle, dog nettle, burning nettle, or bush nettle is a herbaceous annual flowering plant species in the nettle family Urticaceae.","img":"images/425.jpg","thumb":"images/t/425.jpg","file":"Urtica urens 002.JPG","ar":0.75,"py":"ouqianma oqm","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","非洲","北美洲","大洋洲"],"illus_img":"images/i/425.jpg","illus_thumb":"images/i/t/425.jpg","illus_file":"Urtica urens — Flora Batava — Volume v5.jpg","illus_ar":0.673,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":427,"seq":409,"zh":"枣树","en":"Ziziphus jujuba","sci":"Ziziphus jujuba","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":86,"desc_zh":"枣（学名：Ziziphus jujuba），俗称红枣、黑枣、大枣，生长在温带地区的小乔木，原产于中国大陆中部与南部、朝鲜半岛、黎巴嫩、伊朗、巴基斯坦、印度、孟加拉，在中国大陆的南北各地都有分布。因其经济价值，被移植到日本、欧洲南部、北美洲。花朵小多蜜，是一种蜜源植物。果实为枣，长圆形，未成熟时呈黄绿色，类似缩小版翠绿色印度枣，成熟后呈褐红色。可鲜食也可制成果干或蜜饯果脯等。营养丰富，富含铁元素和维生素。","desc_en":"Jujube (UK ; US or ), sometimes jujuba, scientific name Ziziphus jujuba, and also called red date, Chinese date, and Chinese jujube, is a species in the genus Ziziphus in the buckthorn family Rhamnaceae.","img":"images/427.jpg","thumb":"images/t/427.jpg","file":"Jujube n.jpg","ar":1.639,"py":"zaoshu zs","cr_by":"Rémi Tournebize","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲"],"illus_img":"images/i/427.jpg","illus_thumb":"images/i/t/427.jpg","illus_file":"Ziziphus jujuba line drawing.jpg","illus_ar":1.5,"illus_by":"L.H. @ USDA-NRCS PLANTS Database","illus_lic":"Public domain","illus_licurl":null},{"id":428,"seq":410,"zh":"欧鼠李","en":"Frangula alnus","sci":"Frangula alnus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":56,"desc_zh":"欧鼠李（学名：Frangula alnus），为鼠李科裸芽鼠李属下的一个植物种。","desc_en":"Frangula alnus, commonly known as alder buckthorn, glossy buckthorn, or breaking buckthorn, is a tall deciduous shrub in the family Rhamnaceae. Unlike other \"buckthorns\", alder buckthorn does not have thorns.","img":"images/428.jpg","thumb":"images/t/428.jpg","file":"Frangula alnus sl7.jpg","ar":1.333,"py":"oushuli osl","cr_by":"Stefan.lefnaer","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/428.jpg","illus_thumb":"images/i/t/428.jpg","illus_file":"Frangula alnus Sturm07025.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":429,"seq":411,"zh":"药鼠李","en":"Rhamnus cathartica","sci":"Rhamnus cathartica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":56,"desc_zh":"药鼠李（学名：Rhamnus cathartica）为鼠李科鼠李属下的一个种。","desc_en":"Rhamnus cathartica, the European buckthorn, common buckthorn, purging buckthorn, or just buckthorn, is a species of small tree in the flowering plant family Rhamnaceae.","img":"images/429.jpg","thumb":"images/t/429.jpg","file":"Rhamnus cathartica 1.jpg","ar":1.501,"py":"yaoshuli ysl","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/429.jpg","illus_thumb":"images/i/t/429.jpg","illus_file":"Rhamnus cathartica - Köhler–s Medizinal-Pflanzen-255.jpg","illus_ar":0.827,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":430,"seq":412,"zh":"滇刺枣","en":"Ziziphus mauritiana","sci":"Ziziphus mauritiana","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":47,"desc_zh":"印度枣（学名：Ziziphus mauritiana）是鼠李科枣属植物，原产中国云南、四川、广西、广东以及南亚、东南亚、非洲。","desc_en":"Ziziphus mauritiana, also known as Indian jujube, Indian plum, Chinee apple, ber (Hindi: बेर) and dunks, is a tropical, spiny, evergreen shrub or small tree in the buckthorn family Rhamnaceae. It is often confused with the closely related Chinese jujube (Z.","img":"images/430.jpg","thumb":"images/t/430.jpg","file":"Ziziphus mauritiana fruit 2.jpg","ar":1.028,"py":"diancizao dcz","cr_by":"Ethel Aardvark","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲"]},{"id":432,"seq":413,"zh":"欧洲野榆","en":"Ulmus minor","sci":"Ulmus minor","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Ulmaceae","family_zh":"榆科","iucn":"DD","langs":57,"desc_zh":"欧洲野榆（学名：Ulmus minor；英语：European field elm）是欧洲的三种榆属植物之一。和欧洲白榆、欧洲山榆一样，欧洲野榆也易感荷兰榆树病，但欧洲野榆的抗性稍高。 欧洲野榆形态变化很大，叶形倒披针形、倒卵形、椭圆形或近圆形，叶片上表面光滑或粗糙，叶片下表面无毛或有毛，嫩枝无毛至密被柔毛。","desc_en":"Ulmus minor Mill., the field elm, is by far the most polymorphic of the European species, although its taxonomy remains a matter of contention. Its natural range is predominantly south European, extending to Asia Minor and Iran; its northern outposts are the B…","img":"images/432.jpg","thumb":"images/t/432.jpg","file":"Illustration Ulmus carpinifolia0.jpg","ar":0.645,"py":"ouzhouyeyu ozyy","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["欧洲"]},{"id":433,"seq":414,"zh":"欧洲山榆","en":"Ulmus glabra","sci":"Ulmus glabra","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Ulmaceae","family_zh":"榆科","iucn":"DD","langs":57,"desc_zh":"欧洲山榆（学名：Ulmus glabra，英语：European mountain elm或wych elm），又名光榆、无毛榆、欧洲光皮榆、阔叶榆（英语：broadleaf elm）、苏格兰榆（英语：Scottish elm, Scotch elm, Scots elm），是榆属下的一种大型落叶乔木，高度可达40米，分布于爱尔兰到乌拉尔山脉的广大欧洲山区，向北分布范围可达北纬67度，是欧洲三种榆树中分布最广的一种（另外两种为欧洲野榆和…","desc_en":"Ulmus glabra, the wych elm or Scots elm, has the widest range of the European elm species, from Ireland eastwards to the Ural Mountains, and from the Arctic Circle south to the mountains of the Peloponnese and Sicily, where the species reaches its southern lim…","img":"images/433.jpg","thumb":"images/t/433.jpg","file":"RN Ulmus glabra (alnarp sweden).jpg","ar":0.75,"py":"ouzhoushanyu ozsy","cr_by":"Ronnie Nijboer","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/433.jpg","illus_thumb":"images/i/t/433.jpg","illus_file":"Ulmus campestris (modern=Ulmus glabra) - Pl0242 - DescriptionNL01 - FloraBatava-KB-v04.jpg","illus_ar":0.788,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1104,"seq":415,"zh":"欧洲白榆","en":"Ulmus laevis","sci":"Ulmus laevis","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Ulmaceae","family_zh":"榆科","iucn":"DD","langs":44,"desc_zh":"欧洲白榆（学名：Ulmus laevis）是榆科榆属的植物，是原产欧洲的三种榆树之一，在北京、新疆、东北、安徽、江苏、山东等地有栽培。和欧洲野榆、欧洲山榆一样，欧洲白榆也易感荷兰榆树病。","desc_en":"Ulmus laevis Pall., variously known as the European white elm, fluttering elm, spreading elm, stately elm and, in the United States, the Russian elm, is a large deciduous tree native to Europe, from France northeast to southern Finland, east beyond the Urals i…","img":"images/1104.jpg","thumb":"images/t/1104.jpg","file":"Ulme Obertheres, 2.jpg","ar":0.75,"py":"ouzhoubaiyu ozby","cr_by":"Rainer Lippert","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/1104.jpg","illus_thumb":"images/i/t/1104.jpg","illus_file":"Ulmus laevis bud illustration.jpg","illus_ar":0.347,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":434,"seq":416,"zh":"大麻","en":"Cannabis sativa","sci":"Cannabis sativa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Cannabaceae","family_zh":"大麻科","iucn":null,"langs":89,"desc_zh":"大麻（学名：Cannabis sativa）是大麻科大麻属植物的物种之一，可能是大麻属的唯一物种，中国古称麻、枲、苴、汉麻、火麻或黄麻，又称为大麻草、寻常大麻、苜蓿大麻。大麻使用者惯称Sativa（与indica（印度大麻）相对比）。 本种外表高大瘦长、叶子长而狭窄，因为含有大麻素成份，可作为医疗与娱乐性药物使用，但在许多国家则被视为毒品禁止。","desc_en":"Cannabis sativa is an annual herbaceous flowering plant. The species was first classified by Carl Linnaeus in 1753. The specific epithet sativa means 'cultivated'.","img":"images/434.jpg","thumb":"images/t/434.jpg","file":"Cannabis sativa 2.jpg","ar":0.751,"py":"dama dm","cr_by":"Thayne Tuason","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/434.jpg","illus_thumb":"images/i/t/434.jpg","illus_file":"Cannabis sativa (Köhler).jpg","illus_ar":0.834,"illus_by":"Hermann Adolph Köhler (1834 - 1879)","illus_lic":"Public domain","illus_licurl":null},{"id":435,"seq":417,"zh":"蛇麻","en":"Humulus lupulus","sci":"Humulus lupulus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Cannabaceae","family_zh":"大麻科","iucn":null,"langs":86,"desc_zh":"蛇麻（学名：Humulus lupulus），又音译作忽布（英语hops），是大麻科葎草属的植物物种，因其花序用于酿造啤酒，因此又称作啤酒花。","desc_en":"Humulus lupulus, the common hop or hops, is a species of flowering plant in the hemp family, Cannabaceae. It is a perennial, herbaceous climbing plant which sends up new shoots in early spring and dies back to a cold-hardy rhizome in autumn.","img":"images/435.jpg","thumb":"images/t/435.jpg","file":"Hop mannelijke plant Humulus lupulus male plant.jpg","ar":0.75,"py":"shema sm","cr_by":"No machine-readable author provided. Rasbak assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/435.jpg","illus_thumb":"images/i/t/435.jpg","illus_file":"Humulus lupulus - Köhler–s Medizinal-Pflanzen-072.jpg","illus_ar":0.845,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":436,"seq":418,"zh":"沙棘","en":"Hippophae rhamnoides","sci":"Hippophae rhamnoides","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Elaeagnaceae","family_zh":"胡颓子科","iucn":"LC","langs":64,"desc_zh":"沙棘（学名：Hippophae rhamnoides），或作海沙棘，是沙棘属的一种带有棘刺的落叶多年生小乔木或灌木。其种加词“rhamnoides”源于希腊语，意为“像鼠李的”。原产于亚洲和欧洲的温带、寒温带地区。沙棘可防风固沙，其果实可以食用或用来制作饮料，此外沙棘果在美容和药用上也有价值。","desc_en":"Sea-buckthorn (Hippophae rhamnoides), also known as sea buckthorn, sandthorn, sallowthorn or seaberry, is a species of flowering plant in the family Elaeagnaceae, native to cold-temperate regions of Eurasia. It is a spiny deciduous shrub.","img":"images/436.jpg","thumb":"images/t/436.jpg","file":"Hippophae (Novogrudinina).jpg","ar":0.75,"py":"shaji sj","cr_by":"Виталий Уайлд","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲"],"illus_img":"images/i/436.jpg","illus_thumb":"images/i/t/436.jpg","illus_file":"Hippophae rhamnoides Sturm41.jpg","illus_ar":0.682,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":437,"seq":419,"zh":"沙枣","en":"Elaeagnus angustifolia","sci":"Elaeagnus angustifolia","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Elaeagnaceae","family_zh":"胡颓子科","iucn":"LC","langs":49,"desc_zh":"沙枣（学名：Elaeagnus angustifolia）也称银柳、香柳、桂香柳。常生长在沙漠地区。果实像枣，可食用，故名沙枣。用于水土保持、防沙护林。","desc_en":"Elaeagnus angustifolia, commonly called Russian olive, silver berry, oleaster, or wild olive, is a species of Elaeagnus, native to Asia and limited areas of eastern Europe. It is widely established in North America as an introduced species.","img":"images/437.jpg","thumb":"images/t/437.jpg","file":"Elaeagnus angustifolia 20050608 852.jpg","ar":0.75,"py":"shazao sz","cr_by":"Georg Slickers","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/437.jpg","illus_thumb":"images/i/t/437.jpg","illus_file":"T2 26 Elaeagnus angustifolia par Pierre-Joseph Redouté.jpeg","illus_ar":0.693,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1105,"seq":420,"zh":"牛奶子","en":"Elaeagnus umbellata","sci":"Elaeagnus umbellata","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Elaeagnaceae","family_zh":"胡颓子科","iucn":"LC","langs":27,"desc_zh":"牛奶子（学名：Elaeagnus umbellata）又名小叶胡颓子、夏茱萸、唐茱萸、秋茱萸、甜枣、剪子果、秋胡颓子，为胡颓子科胡颓子属下的一种落叶灌木，高度可达4米，果实可以食用，也可作为观赏植物栽培，分布于东亚及印度。","desc_en":"Elaeagnus umbellata is a species of flowering plant known as Japanese silverberry, umbellata oleaster, autumn olive, autumn elaeagnus, spreading oleaster, autumnberry, or autumn berry.","img":"images/1105.jpg","thumb":"images/t/1105.jpg","file":"Elaeagnus umbellata1.jpg","ar":0.75,"py":"niunaizi nnz","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":438,"seq":421,"zh":"夏栎","en":"Quercus robur","sci":"Quercus robur","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":84,"desc_zh":"夏栎（学名：Quercus robur），也常称作欧洲有柄橡木、长柄栎、夏橡、欧洲白栎、英国栎、英国橡。原生于欧洲、安那托利亚至高加索地区，北非部分地区和中国青岛亦有分布。","desc_en":"Quercus robur, pedunculate oak, European oak, or English oak, is a species of flowering plant in the beech and oak family, Fagaceae. It is a large tree, native to Europe and western Asia, and is widely cultivated in other temperate regions.","img":"images/438.jpg","thumb":"images/t/438.jpg","file":"Paprastasis azuolas.JPG","ar":1.332,"py":"xiali xl","cr_by":"Algirdas at Lithuanian Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/438.jpg","illus_thumb":"images/i/t/438.jpg","illus_file":"Quercus robur - Flora medica, oder, Abbildung der wichtigsten officinellen Pflanzen (Pl. 106) - clean.jpg","illus_ar":0.759,"illus_by":"Dietrich, David Nathanael Friedrich","illus_lic":"Public domain","illus_licurl":null},{"id":439,"seq":422,"zh":"欧洲山毛榉","en":"Fagus sylvatica","sci":"Fagus sylvatica","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":78,"desc_zh":"欧洲山毛榉（学名：Fagus sylvatica），又名欧洲水青冈，是壳斗科山毛榉属的一种落叶植物。","desc_en":"Fagus sylvatica, the European beech or common beech, and a mutation known has copper beech (Fagus sylvatica purpurea), is a large deciduous tree in the beech family with smooth silvery-grey bark, large leaf area, and a short trunk with low branches.","img":"images/439.jpg","thumb":"images/t/439.jpg","file":"Grib skov.jpg","ar":1.065,"py":"ouzhoushanmaoju ozsmj","cr_by":"Malene Thyssen","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲"],"illus_img":"images/i/439.jpg","illus_thumb":"images/i/t/439.jpg","illus_file":"Fagus sylvatica - Köhler–s Medizinal-Pflanzen-060.jpg","illus_ar":0.785,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":440,"seq":423,"zh":"欧洲栗","en":"Castanea sativa","sci":"Castanea sativa","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":77,"desc_zh":"欧洲栗（学名：Castanea sativa），又称西洋栗、甜栗、甘栗，属于被子植物中的山毛榉科。原产于欧洲东南部与小亚细亚，现已广泛种植于欧洲各地。欧洲栗的果树耐寒且长寿，它的果实「栗子」则常被用作食材。 欧洲栗中最粗的一棵即“百骑大栗树”，位于意大利西西里岛埃特纳火山，也是最粗的树木及植物之一。它是欧洲的乡土树种，非洲北部和亚洲西部也有分布。","desc_en":"The sweet chestnut (Castanea sativa), also known as the Spanish chestnut or European chestnut, is a species of tree in the family Fagaceae, native to Southern Europe and Anatolia, and widely cultivated in Western and Central Europe.","img":"images/440.jpg","thumb":"images/t/440.jpg","file":"Romagne 86 Châtaignes 2008.jpg","ar":1.504,"py":"ouzhouli ozl","cr_by":"JLPC","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/440.jpg","illus_thumb":"images/i/t/440.jpg","illus_file":"Castanea sativa - Köhler–s Medizinal-Pflanzen-173.jpg","illus_ar":0.736,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":441,"seq":424,"zh":"西班牙栓皮栎","en":"Quercus suber","sci":"Quercus suber","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":75,"desc_zh":"西班牙栓皮栎（学名：Quercus suber）为壳斗科栎属下的一个种。是一种中型常绿橡树，原产于西北亚和西南欧。常被用来制作软木塞，因此又被称为软木橡树或木塞橡树。 软木橡树最高可生长到20公尺，但在一般自然环境却少有如此高大。叶长约4~7厘米边缘微裂或有锯齿状，叶面暗绿色叶背则呈现泛白色，叶于支末端呈自然垂落状。种子约2~3公分长，与一般橡树子不同在于壳斗呈现流苏杯状。","desc_en":"Quercus suber, commonly called the cork oak, is a medium-sized, evergreen oak tree in the section Quercus sect. Cerris. It is the primary source of cork for wine bottle stoppers and other uses, such as cork flooring and as the cores of cricket balls.","img":"images/441.jpg","thumb":"images/t/441.jpg","file":"Quercus suber JPG1.jpg","ar":1.502,"py":"xibanyashuanpili xbyspl","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["欧洲","非洲"],"illus_img":"images/i/441.jpg","illus_thumb":"images/i/t/441.jpg","illus_file":"Quercus suber - Köhler–s Medizinal-Pflanzen-254.jpg","illus_ar":0.771,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":442,"seq":425,"zh":"无梗花栎","en":"Quercus petraea","sci":"Quercus petraea","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":69,"desc_zh":"无梗花栎（学名：Quercus petraea），又称岩生栎，分布于欧洲及安纳托利亚。 无梗花栎是爱尔兰的国树，也是威尔士非官方的代表标志，因此在威尔士亦称威尔士橡树（Welsh Oak），同时也被认为是康沃尔郡的郡树，因此亦称康沃尔橡树（Cornish Oak）。","desc_en":"Quercus petraea, commonly known as the sessile oak, Welsh oak, Cornish oak, Irish oak or durmast oak, is a species of deciduous oak tree native to most of Europe and into Anatolia and Iran.","img":"images/442.jpg","thumb":"images/t/442.jpg","file":"Quercus petraea 02.jpg","ar":1.333,"py":"wugenghuali wghl","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/442.jpg","illus_thumb":"images/i/t/442.jpg","illus_file":"Quercus petraea - Köhler–s Medizinal-Pflanzen-118.jpg","illus_ar":0.783,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":443,"seq":426,"zh":"冬青栎","en":"Quercus ilex","sci":"Quercus ilex","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":65,"desc_zh":"冬青栎（学名：Quercus ilex）是一种来自于地中海地区的常绿大型栎属树木。它和栓皮栎一样属于栎属中的白栎，它们可以在一个夏季里就成熟。16世纪它被引入英国，今天这些最老的英国冬青栎还活着。在意大利西西里岛上有一棵冬青栎据传有700年的树龄了。在马耳他有一片树林里的树木据说有500至1000年的树龄。冬青栎是马耳他的国树。在迦太基占据马耳他岛之前它是岛上的主流树木。","desc_en":"The holm oak (Quercus ilex), also called the holly oak, is a large evergreen oak native to the Mediterranean region. It is a member of the section Ilex of the genus, with acorns that mature in a single summer.","img":"images/443.jpg","thumb":"images/t/443.jpg","file":"Frouzet fg02.jpg","ar":1.333,"py":"dongqingli dql","cr_by":"Fritz Geller-Grimm","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/443.jpg","illus_thumb":"images/i/t/443.jpg","illus_file":"Quercus ilex leaf illustration.jpg","illus_ar":0.789,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":444,"seq":427,"zh":"北美红橡","en":"Quercus rubra","sci":"Quercus rubra","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":51,"desc_zh":"北美红橡（学名：Quercus rubra）为北美洲原生植物，为与南方红橡（Quercus falcata）区别亦称北方红橡。分布区域北至五大湖区，南至乔治亚州、密西西比州、阿拉巴马州和路易斯安那州，东至新斯科细亚省，西至奥克拉荷马州、堪萨斯州、内布拉斯加州和明尼苏达州的美国东部和中部以及加拿大东南部和中南部地区。北美红橡现今已被引入西欧的小部份地区，作为花园和公园中的观赏树种种植。它也是新泽西州的州树和爱德华王子岛省的省树。","desc_en":"Quercus rubra, the northern red oak or common red oak, is an oak tree in the red oak group (Quercus section Lobatae). It is a native of North America, in the eastern and central United States and southeast and south-central Canada.","img":"images/444.jpg","thumb":"images/t/444.jpg","file":"Twin Sisters Trail (14) (14092717698).jpg","ar":0.667,"py":"beimeihongxiang bmhx","cr_by":"Nicholas A. Tonelli from Northeast Pennsylvania, USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["北美洲"]},{"id":448,"seq":428,"zh":"欧榛","en":"Corylus avellana","sci":"Corylus avellana","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":91,"desc_zh":"欧榛（学名：Corylus avellana）也称欧洲榛，落叶灌木，春天长出下垂的柔荑花序，秋天结出成串坚果。是一种原生在欧洲与亚洲西部的榛属植物。南至不列颠群岛、希腊、伊比利半岛、土耳其与赛普勒斯，北至斯堪地纳维亚中部、东至乌拉山中部、高加索与伊朗的西北方都有分布。","desc_en":"Corylus avellana, the common hazel, is a species of flowering plant in the birch family Betulaceae. The shrubs usually grow 3–8 metres (10–26 feet) tall. The nut is round, in contrast to the longer filbert nut.","img":"images/448.jpg","thumb":"images/t/448.jpg","file":"Corylus avellana shrub.jpg","ar":1.333,"py":"ouzhen oz","cr_by":"MPF","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/448.jpg","illus_thumb":"images/i/t/448.jpg","illus_file":"Illustration Corylus avellana0 clean.jpg","illus_ar":0.615,"illus_by":"User:Kilom691","illus_lic":"Public domain","illus_licurl":null},{"id":449,"seq":429,"zh":"欧洲桤木","en":"Alnus glutinosa","sci":"Alnus glutinosa","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":76,"desc_zh":"普通赤杨（学名：Alnus glutinosa）是桦木科赤杨属的落叶乔木，主要分布于欧洲、亚洲西南部和非洲北部。普通赤杨喜潮湿，在存在Frankia alni细菌的情况下可在贫瘠的土壤中生长。它是中等大小、生命短暂的树木，大约能长到30米（98英尺）。","desc_en":"Alnus glutinosa, the common alder, black alder, European alder, European black alder, or just alder, is a species of tree in the family Betulaceae, native to most of Europe, southwest Asia and northern Africa.","img":"images/449.jpg","thumb":"images/t/449.jpg","file":"Alnus glutinosa 011.jpg","ar":1.333,"py":"ouzhouqimu ozqm","cr_by":"Willow","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/449.jpg","illus_thumb":"images/i/t/449.jpg","illus_file":"Alnus glutinosa cone illustration.jpg","illus_ar":0.799,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":450,"seq":430,"zh":"垂枝桦","en":"Betula pendula","sci":"Betula pendula","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":71,"desc_zh":"垂枝桦（学名：Betula pendula），也称欧洲银桦、疣枝桦、疣皮桦、阿尔泰桦等，为桦木科桦木属的植物。分布于欧洲、西西伯利亚以及中国大陆的新疆等地，生长于海拔500米至2,000米的地区，多生在河滩、山谷、山脚湿润地带和向阳的石山坡，目前尚未由人工引种栽培。 垂枝桦为芬兰的国树。","desc_en":"Betula pendula, commonly known as silver birch, warty birch, European white birch, or East Asian white birch, is a species of tree in the family Betulaceae, native to Europe and parts of Asia, though in southern Europe, it is only found at higher altitudes.","img":"images/450.jpg","thumb":"images/t/450.jpg","file":"Betula pendula Finland.jpg","ar":1.333,"py":"chuizhihua czh","cr_by":"Percita at Flickr","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/450.jpg","illus_thumb":"images/i/t/450.jpg","illus_file":"Betula pendula leaf illustration.jpg","illus_ar":0.903,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":451,"seq":431,"zh":"欧洲角树","en":"Carpinus betulus","sci":"Carpinus betulus","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":61,"desc_zh":"欧洲角树（学名：Carpinus betulus）是桦树桦木科的一种，原产于西亚和中欧、东欧和南欧，包括英格兰南部。它需要温暖的气候才能良好地生长，并且只生长在海拔高达一千米的地方。它生长在与橡树的混合林中，或在山毛榉的某些地区。","desc_en":"Carpinus betulus, the European or common hornbeam, is a species of tree in the birch family Betulaceae, native to Western Asia and central, eastern, and southern Europe, including southern England.","img":"images/451.jpg","thumb":"images/t/451.jpg","file":"Brohmer-Berge-Rothemühl-24-10-2009-30.jpg","ar":0.75,"py":"ouzhoujiaoshu ozjs","cr_by":"Botaurus","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/451.jpg","illus_thumb":"images/i/t/451.jpg","illus_file":"T2 58 Carpinus betulus par Pierre-Joseph Redouté.jpeg","illus_ar":0.713,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":453,"seq":432,"zh":"普通胡桃","en":"Juglans regia","sci":"Juglans regia","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"LC","langs":92,"desc_zh":"普通胡桃（学名：Juglans regia）又名波斯胡桃、英国胡桃、胡桃、核桃，是胡桃科胡桃属的植物，亦是最常见的胡桃的一种。在南北半球的温带地区广泛栽培。由于长期的人为栽培，其自然分布范围不详，据推测原产于巴尔干半岛到中国之间的区域。","desc_en":"Juglans regia, known by various common names including the common walnut, English walnut, or Persian walnut amongst other names, is a species of walnut. It is native to Eurasia in at least southwest and central Asia and southeast Europe, but its exact natural…","img":"images/453.jpg","thumb":"images/t/453.jpg","file":"Juglans regia Echte Walnussfrucht 1.jpg","ar":0.75,"py":"putonghutao ptht","cr_by":"Böhringer Friedrich","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/453.jpg","illus_thumb":"images/i/t/453.jpg","illus_file":"Juglans regia - Köhler–s Medizinal-Pflanzen-081.jpg","illus_ar":0.76,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":454,"seq":433,"zh":"长山核桃","en":"Carya illinoinensis","sci":"Carya illinoinensis","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"LC","langs":54,"desc_zh":"长山核桃（学名：Carya illinoinensis）是胡桃科山核桃属的一种植物。又称碧根果、美国山核桃、薄壳山核桃、胡桃。种子可食用。","desc_en":"The pecan ( pih-KAN, also US: pih-KAHN, PEE-kan, UK: PEE-kən; Carya illinoinensis) is a species of hickory native to the Southern United States and northern Mexico in the region of the Mississippi River. Originally native to the south-central U.S.","img":"images/454.jpg","thumb":"images/t/454.jpg","file":"Carya illinoinensis (pecan tree) 1 (24790682337).jpg","ar":0.775,"py":"changshanhetao csht","cr_by":"James St. John","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["北美洲"],"illus_img":"images/i/454.jpg","illus_thumb":"images/i/t/454.jpg","illus_file":"Carya illinoinensis line drawing.tif","illus_ar":0.74,"illus_by":"Britton, N.L., and A. Brown, 1913, An illustrated flora of the northern United States, Canada and the British Possession","illus_lic":"Public domain","illus_licurl":null},{"id":455,"seq":434,"zh":"黑胡桃","en":"Juglans nigra","sci":"Juglans nigra","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"LC","langs":43,"desc_zh":null,"desc_en":"Juglans nigra, the eastern American black walnut, is a species of deciduous tree in the walnut family, Juglandaceae, native to central and eastern North America, growing mostly in riparian zones.","img":"images/455.jpg","thumb":"images/t/455.jpg","file":"Black Walnut Juglans nigra Nut 2400px.jpg","ar":1.2,"py":"heihutao hht","cr_by":"Photo by and (c)2007 Derek Ramsey ( Ram-Man ). Location credit to the Chanticleer Garden.","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["北美洲"],"illus_img":"images/i/455.png","illus_thumb":"images/i/t/455.png","illus_file":"Juglans nigra illustration.png","illus_ar":0.757,"illus_by":"USDA-NRCS PLANTS Database / Britton, N.L., and A. Brown. 1913. An illustrated flora of the northern United States, Canad","illus_lic":"Public domain","illus_licurl":null},{"id":457,"seq":435,"zh":"香杨梅","en":"Myrica gale","sci":"Myrica gale","order_en":"Fagales","order_zh":"壳斗目","family_en":"Myricaceae","family_zh":"杨梅科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Myrica gale is a species of flowering plant in the family Myricaceae native to cool temperate regions of Eurasia and North America. Common names include bog-myrtle, sweet gale, Dutch myrtle, and sweetgale.","img":"images/457.jpg","thumb":"images/t/457.jpg","file":"Gagelstrauch(Myrica gale)female.JPG","ar":1.333,"py":"xiangyangmei xym","cr_by":"Hajotthu","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲","北美洲"],"illus_img":"images/i/457.jpg","illus_thumb":"images/i/t/457.jpg","illus_file":"Myrica gale — Flora Batava — Volume v7.jpg","illus_ar":0.679,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":458,"seq":436,"zh":"木麻黄","en":"Casuarina equisetifolia","sci":"Casuarina equisetifolia","order_en":"Fagales","order_zh":"壳斗目","family_en":"Casuarinaceae","family_zh":"木麻黄科","iucn":"LC","langs":44,"desc_zh":"木麻黄（学名：Casuarina equisetifolia L.）为木麻黄科木麻黄属的植物。","desc_en":"Casuarina equisetifolia, commonly known as coastal she-oak, horsetail she-oak, ironwood, beach sheoak, beach casuarina, whistling tree or Australian pine is a species of flowering plant in the family Casuarinaceae and is native to Australia, New Guinea, Southe…","img":"images/458.jpg","thumb":"images/t/458.jpg","file":"Casuarina equesitifolia tree.jpg","ar":1.332,"py":"mumahuang mmh","cr_by":"Ethel Aardvark","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":459,"seq":437,"zh":"黄瓜","en":"Cucumis sativus","sci":"Cucumis sativus","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":180,"desc_zh":"黄瓜（学名：Cucumis sativus）也称胡瓜、青瓜、刺瓜、瓜仔哖，属葫芦科黄瓜属植物。原生于亚洲中部，于3000年前在印度驯化，现在分布于全球各地，并且广泛分布于中国各地，是中国夏季主要蔬菜，且为温室产品之一。","desc_en":"The cucumber (Cucumis sativus) is a widely-cultivated creeping vine plant in the family Cucurbitaceae that bears cylindrical to spherical fruits, used as culinary vegetables.","img":"images/459.jpg","thumb":"images/t/459.jpg","file":"Cucumis sativus 0001.JPG","ar":1.333,"py":"huanggua hg","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲"],"illus_img":"images/i/459.jpg","illus_thumb":"images/i/t/459.jpg","illus_file":"Illustration Cucumis sativus0.jpg","illus_ar":0.634,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":460,"seq":438,"zh":"西瓜","en":"watermelon","sci":"Citrullus lanatus","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":176,"desc_zh":"西瓜 （学名：Citrullus lanatus），古亦称寒瓜，是葫芦科西瓜属的一种植物或其果实，原产于非洲，现世界多地有栽培。其植株为一年生匍匐蔓藤，叶形状裂为掌状。 西瓜的果实在植物学形态分类上属于一种特化的浆果，称为瓠果。其外皮光滑，呈绿色或黄色，且有深绿色的花纹，果瓤多汁，为红色或黄色，有黑色籽。","desc_en":"The watermelon (Citrullus lanatus) is a species of flowering plant in the family Cucurbitaceae, that has a large, edible fruit. It is a scrambling and trailing vine-like plant, and is widely cultivated worldwide, with more than 1,000 varieties.","img":"images/460.jpg","thumb":"images/t/460.jpg","file":"Watermelon-garden.jpg","ar":1.496,"py":"xigua xg","cr_by":"Kumon","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"藤本","origin":["非洲"]},{"id":461,"seq":439,"zh":"甜瓜","en":"Cucumis melo","sci":"Cucumis melo","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":118,"desc_zh":"甜瓜（学名：Cucumis melo）为葫芦科黄瓜属一年生平卧或攀援草本植物，果实为瓠果。甜瓜的起源地不明，亚洲中西部和非洲都曾被认为是甜瓜的主要遗传多样性中心。","desc_en":"Cucumis melo, also known as melon or true melon, is a species of Cucumis that has been developed into many cultivated varieties. The fruit is a pepo. The flesh is either sweet or bland, with or without an aroma, and the rind can be smooth (such as honeydew), r…","img":"images/461.jpg","thumb":"images/t/461.jpg","file":"Canteloupe and cross section.jpg","ar":1.844,"py":"tiangua tg","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Sigma 150mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":null,"origin":["亚洲","非洲"]},{"id":462,"seq":440,"zh":"苦瓜","en":"Momordica charantia","sci":"Momordica charantia","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":96,"desc_zh":"苦瓜（学名：Momordica charantia）又名凉瓜、半生瓜、癞葡萄、锦荔枝等，是葫芦科的热带和亚热带藤本植物。苦瓜原产于非洲。野生或半驯化的变种在史前时期遍布亚洲，很可能在东南亚被完全驯化。","desc_en":"Momordica charantia (commonly called bitter melon, gouya, cerassee, goya, bitter apple, bitter gourd, bitter squash, balsam-pear, karela, karavila and many more names listed below) is a tropical and subtropical vine of the family Cucurbitaceae, widely grown in…","img":"images/462.jpg","thumb":"images/t/462.jpg","file":"Feuilles de Margôzy.jpg","ar":0.75,"py":"kugua kg","cr_by":"Morenga01","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","非洲"]},{"id":463,"seq":441,"zh":"葫芦","en":"Lagenaria siceraria","sci":"Lagenaria siceraria","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":93,"desc_zh":"葫芦（学名：Lagenaria siceraria），别称壶芦、扁蒲、蒲瓜、瓠子、匏仔、瓢箪、瓠瓜、匏、蒲子、长瓜、蒲仔、夜开花、葫芦蒲、地蒲、葫芦瓜等，是属于葫芦目葫芦科葫芦属的一种植物，它是爬藤植物，其果实也被称为葫芦。","desc_en":"Calabash (; Lagenaria siceraria), also known as bottle gourd, white-flowered gourd, long melon, birdhouse gourd, New Guinea bean, New Guinea butter bean, Tasmania bean, zucca melon and opo squash, is a vine which is grown for its fruit.","img":"images/463.jpg","thumb":"images/t/463.jpg","file":"Courge encore verte.jpg","ar":1.333,"py":"hulu hl","cr_by":"撮影者はカールおじさんです。","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["非洲"]},{"id":464,"seq":442,"zh":"佛手瓜","en":"Sicyos edulis","sci":"Sicyos edulis","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":73,"desc_zh":"佛手瓜（学名：Sicyos edulis）是一种葫芦科刺果瓜属植物，又称菜肴梨（英语：chayote, vegetable pear）、合手瓜、合掌瓜、佛手、隼人瓜、拳头瓜、梨瓜等。原产于墨西哥、中美洲和西印度群岛，1915年传入中国，在江南一带有种植，以云南、浙江、福建、广东最多。台湾于1935年自日本引进种植。其藤尖称为龙须菜。 本种曾被归类于佛手瓜属（Sechium），但现已知佛手瓜属是刺果瓜属的异名。","desc_en":"Chayote (; previously placed in the obsolete genus Sechium, now in the genus Sicyos, as Sicyos edulis), also known as christophine, mirliton, güisquil, and choko, is an edible plant belonging to the gourd family, Cucurbitaceae.","img":"images/464.jpg","thumb":"images/t/464.jpg","file":"Sechium edule dsc07767.jpg","ar":1.333,"py":"foshougua fsg","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":468,"seq":443,"zh":"竹节秋海棠","en":"Begonia maculata","sci":"Begonia maculata","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":16,"desc_zh":null,"desc_en":"Begonia maculata (maculata meaning \"spotted\"), the polka dot begonia, is a species of begonia native to southeast Brazil. It grows naturally in the understory of the Atlantic rainforest, with occurrences confirmed in the Brazilian states of Espírito Santo and…","img":"images/468.jpg","thumb":"images/t/468.jpg","file":"Begonia maculata3073316230.jpg","ar":0.666,"py":"zhujieqiuhaitang zjqht","cr_by":"Cliff from I now live in Arlington, VA (Outside Washington DC), USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["南美洲"]},{"id":469,"seq":444,"zh":"蟆叶秋海棠","en":"Begonia rex","sci":"Begonia rex","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":16,"desc_zh":"尖蕊秋海棠（学名：Begonia rex）或紫叶秋海棠，为秋海棠科秋海棠属的植物。分布于印度、喜马拉雅山区、越南以及中国大陆的广西、贵州、云南等地，生长于海拔990米至1,100米的地区，一般生长在山沟岩石上和山沟密林中，目前已由人工引种栽培。","desc_en":"Begonia rex, the king begonia, fancy-leaf begonia, or painted-leaf begonia is a species of flowering plant in the family Begoniaceae. It's a rhizomatous begonia first brought to England from Assam, and documented in 1857.","img":"images/469.jpg","thumb":"images/t/469.jpg","file":"Begonia rex.jpg","ar":0.571,"py":"mayeqiuhaitang myqht","cr_by":"W.J. Hooker","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"],"illus_img":"images/i/469.jpg","illus_thumb":"images/i/t/469.jpg","illus_file":"Painted Leaved Begonia. Begonia rex Putz. Flore des serres et des jardins de l'Europe v.12 (1857).jpg","illus_ar":0.617,"illus_by":"Swallowtail Garden Seeds","illus_lic":"Public domain","illus_licurl":null},{"id":470,"seq":445,"zh":"秋海棠","en":"Begonia grandis","sci":"Begonia grandis","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":15,"desc_zh":"秋海棠（学名：Begonia grandis），又名八香、无名断肠草、无名相思草（本草拾遗）、相思草、断肠花、八月春，是秋海棠科秋海棠属的植物。","desc_en":"Begonia grandis, the hardy begonia, is a species of flowering plant in the family Begoniaceae. This herbaceous perennial has alternate, simple leaves on arching stems.","img":"images/470.jpg","thumb":"images/t/470.jpg","file":"Begonia grandis 001.JPG","ar":1.333,"py":"qiuhaitang qht","cr_by":"User:SB_Johnny","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲"]},{"id":471,"seq":446,"zh":"豹耳秋海棠","en":"Begonia bowerae","sci":"Begonia bowerae","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Begonia bowerae, the eyelash begonia, is a species of flowering plant in the family Begoniaceae, native to Oaxaca and Chiapas states of Mexico. A popular houseplant, a number of cultivars are available.","img":"images/471.jpg","thumb":"images/t/471.jpg","file":"Begonia bowerae.JPG","ar":1.333,"py":"baoerqiuhaitang beqht","cr_by":"No machine-readable author provided. Mininain assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":1106,"seq":447,"zh":"Anisophyllea cinnamomoides","en":"Anisophyllea cinnamomoides","sci":"Anisophyllea cinnamomoides","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Anisophylleaceae","family_zh":"四柱木科","iucn":"VU","langs":8,"desc_zh":null,"desc_en":"Anisophyllea cinnamomoides is a species of plant in the family Anisophylleaceae. It is endemic to Sri Lanka.","img":"images/1106.jpg","thumb":"images/t/1106.jpg","file":"Anisophyllea cinnamomoides Govindoo.jpg","ar":0.742,"py":"","cr_by":"Govindoo","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":1107,"seq":448,"zh":"欧马桑","en":"Coriaria myrtifolia","sci":"Coriaria myrtifolia","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Coriariaceae","family_zh":"马桑科","iucn":null,"langs":15,"desc_zh":null,"desc_en":"Coriaria myrtifolia, called in English redoul, is a shrub that grows to 2–3 m tall. Myrtifolia means myrtle-like leaves. The fruit is a fleshy black berry achene slightly similar to a blackberry but toxic.","img":"images/1107.jpg","thumb":"images/t/1107.jpg","file":"Roldor0032.JPG","ar":1.333,"py":"oumasang oms","cr_by":"No machine-readable author provided. Victor M. Vicente Selvas assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":null},{"id":1108,"seq":449,"zh":"野麻","en":"Datisca cannabina","sci":"Datisca cannabina","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Datiscaceae","family_zh":"野麻科","iucn":null,"langs":13,"desc_zh":null,"desc_en":"Datisca cannabina, called false hemp, is a species of flowering plant in the genus Datisca, family Datiscaceae, native to the Aegean Islands, Crete, Cyprus, Anatolia, the Levant, the Transcaucasus, Iraq, Iran, Central Asia, Afghanistan, Pakistan, the western H…","img":"images/1108.jpg","thumb":"images/t/1108.jpg","file":"Datisca cannabina along Seasonal Walk, NYBG (20973362060).jpg","ar":0.667,"py":"yema ym","cr_by":"Kristine Paulus from New York, United States","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["亚洲"]},{"id":473,"seq":450,"zh":"巧茶","en":"Catha edulis","sci":"Catha edulis","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":"LC","langs":63,"desc_zh":"巧茶（学名：Catha edulis）为卫矛科巧茶属的植物，又名阿比西尼亚茶（Abyssinian tea）、埃塞俄比亚茶（Ethiopian tea）、索马里茶（Somali tea）、阿拉伯茶（Arabian tea）、也门茶、布希曼茶（Bushman's tea）、迷拉（miraa）、东非罂粟，或音译作卡塔叶、卡特草、加德树（khat/qat）或恰特草（chat），分布在热带非洲、埃塞俄比亚、阿拉伯半岛以及中国大陆的海南、广西等地…","desc_en":"Khat or qat (Catha edulis), also known as Bushman's tea, especially in South Africa, is a species of flowering plant in the family Celastraceae, and the sole species in genus Catha.","img":"images/473.jpg","thumb":"images/t/473.jpg","file":"Catha edulis.jpg","ar":1.333,"py":"qiaocha qc","cr_by":"User:Katpatuka","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","非洲"]},{"id":474,"seq":451,"zh":"欧洲卫矛","en":"Euonymus europaeus","sci":"Euonymus europaeus","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":"LC","langs":47,"desc_zh":"欧洲卫矛（学名：Euonymus europaeus）是卫矛属的一种落叶灌木或小乔木，原产于欧洲，后作为观赏植物引入世界其他地区。 其种加词“europaeus ”意为“欧洲的”。","desc_en":"Euonymus europaeus, the spindle, European spindle, or common spindle, is a species of flowering plant in the family Celastraceae, native to much of Europe, where it inhabits the edges of forest, hedges and gentle slopes, tending to thrive on nutrient-rich, cha…","img":"images/474.jpg","thumb":"images/t/474.jpg","file":"20131018Euonymus europaeus4.jpg","ar":1.333,"py":"ouzhouweimao ozwm","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"灌木","origin":["欧洲"],"illus_img":"images/i/474.jpg","illus_thumb":"images/i/t/474.jpg","illus_file":"Euonymus europaeus Sturm20.jpg","illus_ar":0.673,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":475,"seq":452,"zh":"梅花草","en":"Grass-of-Parnassus","sci":"Parnassia palustris","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":"LC","langs":47,"desc_zh":"梅花草（学名：Parnassia palustris）为卫矛科梅花草属下的一个种。与梅树外观相似得名。","desc_en":"Parnassia palustris, the marsh grass of Parnassus, northern grass-of-Parnassus, or just grass-of-Parnassus, and bog star, is a flowering plant in the staff-vine family Celastraceae. It is the county flower of Cumberland in England, and appears on its flag.","img":"images/475.jpg","thumb":"images/t/475.jpg","file":"Dettaglio - Droseraceae Parnassia palustris Lin. Erbario Frizzi Perugia n. 1964.jpg","ar":0.75,"py":"meihuacao mhc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["欧洲"],"illus_img":"images/i/475.jpg","illus_thumb":"images/i/t/475.jpg","illus_file":"Illustration Parnassia palustris0.jpg","illus_ar":0.569,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":477,"seq":453,"zh":"阳桃","en":"Averrhoa carambola","sci":"Averrhoa carambola","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Oxalidaceae","family_zh":"酢浆草科","iucn":"DD","langs":86,"desc_zh":"杨桃（学名：Averrhoa carambola）又称阳桃、洋桃、五敛子，古名苌楚、铫芅、刘杙。是酢浆草科洋桃属的常绿灌木或小乔木。原产于热带印度、印尼和斯里兰卡一带热带亚洲。闽人称为杨桃，因经大洋而来，广东人包括香港，亦称为洋桃。其果实大小约直径6-8厘米，可作食用，以水果或当料理的食材来吃，如沙拉、西式咸菜、蜜饯等，味道像梨。","desc_en":"Averrhoa carambola is a species of tree in the family Oxalidaceae native to tropical Southeast Asia; it has a number of common names, including carambola, star fruit and five-corner.","img":"images/477.jpg","thumb":"images/t/477.jpg","file":"Averrhoa carambola flowers.jpg","ar":1.333,"py":"yangtao yt","cr_by":"Tauʻolunga","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":478,"seq":454,"zh":"三敛","en":"Averrhoa bilimbi","sci":"Averrhoa bilimbi","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Oxalidaceae","family_zh":"酢浆草科","iucn":null,"langs":65,"desc_zh":"三敛（学名：Averrhoa bilimbi）为酢浆草科阳桃属的植物。分布于热带亚洲包括马来西亚、印度以及广东、广西、台湾等地，生长于海拔120米至1,200米的地区，目前已由人工引种栽培。","desc_en":"Averrhoa bilimbi (commonly known as bilimbi, orkkaappuli, cucumber tree, or tree sorrel) is a fruit-bearing tree of the genus Averrhoa, family Oxalidaceae. It is native to the Maluku Islands and Sulawesi in Indonesia, and has become naturalised and is common t…","img":"images/478.jpg","thumb":"images/t/478.jpg","file":"Averrhoa bilimbi dsc03692.jpg","ar":0.75,"py":"sanlian sl","cr_by":"David Monniaux","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":1109,"seq":455,"zh":"白花酢浆草","en":"Oxalis acetosella","sci":"Oxalis acetosella","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Oxalidaceae","family_zh":"酢浆草科","iucn":null,"langs":59,"desc_zh":"白花酢浆草（学名：Oxalis acetosella subsp. acetosella）为酢浆草科酢浆草属下的一种。","desc_en":"Oxalis acetosella, also known as wood-sorrel or common wood-sorrel, is a herbaceous rhizomatous flowering plant in the family Oxalidaceae. The specific epithet acetosella refers to its sour taste.","img":"images/1109.jpg","thumb":"images/t/1109.jpg","file":"Oxalis acetosella LC0190.jpg","ar":1.372,"py":"baihuacujiangcao bhcjc","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"草本","origin":null,"illus_img":"images/i/1109.jpg","illus_thumb":"images/i/t/1109.jpg","illus_file":"Illustration Oxalis acetosella0.jpg","illus_ar":0.614,"illus_by":"Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":1110,"seq":456,"zh":"Brunellia comocladifolia","en":"Brunellia comocladifolia","sci":"Brunellia comocladifolia","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Brunelliaceae","family_zh":"瓣裂果科","iucn":"LC","langs":7,"desc_zh":null,"desc_en":"Brunellia comocladifolia, commonly known as the West Indian sumac, is a species of tree in the family Brunelliaceae. It is native to Central America, the West Indies, and northern South America.","img":"images/1110.jpg","thumb":"images/t/1110.jpg","file":"Brunellia comocladifolia 2.JPG","ar":1.494,"py":"","cr_by":"Yolanda Leon","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["北美洲","南美洲"]},{"id":1111,"seq":457,"zh":"Cnestis ferruginea","en":"Cnestis ferruginea","sci":"Cnestis ferruginea","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Connaraceae","family_zh":"牛栓藤科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"The shrub Cnestis ferruginea is native to Africa. It is best known for its uses in herbal medicine.","img":"images/1111.jpg","thumb":"images/t/1111.jpg","file":"Cnestis ferruginea MS6798.jpg","ar":1.501,"py":"","cr_by":"Marco Schmidt [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["非洲"]},{"id":1112,"seq":458,"zh":"银香茶","en":"Eucryphia cordifolia","sci":"Eucryphia cordifolia","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Cunoniaceae","family_zh":"合椿梅科","iucn":"NT","langs":15,"desc_zh":null,"desc_en":"Eucryphia cordifolia, the ulmo, is a species of tree in the family Cunoniaceae. It is found in Chile and Argentina. It is threatened by logging and habitat loss.","img":"images/1112.jpg","thumb":"images/t/1112.jpg","file":"Eucryphia cordifolia.jpg","ar":0.636,"py":"yinxiangcha yxc","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["南美洲"],"illus_img":"images/i/1112.jpg","illus_thumb":"images/i/t/1112.jpg","illus_file":"Eucryphia cordifolia drawing.jpg","illus_ar":0.598,"illus_by":"Matilda Smith","illus_lic":"Public domain","illus_licurl":null},{"id":1113,"seq":459,"zh":"圆果杜英","en":"Elaeocarpus angustifolius","sci":"Elaeocarpus angustifolius","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Elaeocarpaceae","family_zh":"杜英科","iucn":"LC","langs":23,"desc_zh":"圆果杜英（学名：Elaeocarpus sphaericus）为杜英科杜英属下的一种开花植物，分布于印度、新喀里多尼亚和澳洲北部。常见的同义词是E. ganitrus和E. sphaericus。它是一种常绿大树，通常有板状根，叶子有波浪锯齿，乳白色的花和或多或少呈球形的亮蓝色核果。在英语中，该树在印度被称为utrasum bean树。在斯里兰卡，记录的名称是woodbegar和Indian bead tree。","desc_en":"Elaeocarpus angustifolius is a species of flowering plant in the family Elaeocarpaceae that occurs from India to New Caledonia and northern Australia. Common synonyms are E. ganitrus and E. sphaericus.","img":"images/1113.jpg","thumb":"images/t/1113.jpg","file":"Elaeocarpus grandis (Blue Quandong) flowers sapling.jpg","ar":0.75,"py":"yuanguoduying ygdy","cr_by":"Mark Marathon","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":1114,"seq":460,"zh":"Afrostyrax lepidophyllus","en":"Afrostyrax lepidophyllus","sci":"Afrostyrax lepidophyllus","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Huaceae","family_zh":"蒜树科","iucn":"LC","langs":10,"desc_zh":null,"desc_en":"Afrostyrax lepidophyllus is a species of plant in the Huaceae family. It is found in Cameroon, Gabon, and Ghana. It is threatened by habitat loss. Bark extract of Afrostyrax lepidophyllus has shown pesticidal activity against nematodes and arthropods, includin…","img":"images/1114.jpg","thumb":"images/t/1114.jpg","file":"Afrostyrax lepidophyllus - Arbre.jpg","ar":0.75,"py":"","cr_by":"Hiobson","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":479,"seq":461,"zh":"木薯","en":"cassava","sci":"Manihot esculenta","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":117,"desc_zh":"木薯（学名：Manihot esculenta），又称树薯，是一种大戟科木薯属植物，原产于南美洲。广泛种植于尼日利亚、泰国、巴西、印度尼西亚等100多个国家或地区, 是全球第六大粮食作物, 也是第三大能量来源。","desc_en":"Manihot esculenta, commonly called cassava, manioc, or yuca (among numerous regional names), is a woody shrub of the spurge family, Euphorbiaceae, native to South America, from Brazil, Paraguay and parts of the Andes.","img":"images/479.jpg","thumb":"images/t/479.jpg","file":"Manihot esculenta dsc07325.jpg","ar":1.333,"py":"mushu ms","cr_by":"David Monniaux","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["南美洲"],"illus_img":"images/i/479.jpg","illus_thumb":"images/i/t/479.jpg","illus_file":"Manihot esculenta - Köhler–s Medizinal-Pflanzen-090.jpg","illus_ar":0.774,"illus_by":"Franz Eugen Köhler, Köhlers Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":480,"seq":462,"zh":"蓖麻","en":"Ricinus communis","sci":"Ricinus communis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":102,"desc_zh":"蓖麻（学名：Ricinus communis；英语：castor oil plant）是一种大戟科植物，是蓖麻属（Ricinus）下的唯一物种。","desc_en":"Ricinus communis, the castor bean or castor oil plant, is a species of perennial flowering plant in the spurge family, Euphorbiaceae. It is the sole species in the monotypic genus, Ricinus, and subtribe, Ricininae.","img":"images/480.jpg","thumb":"images/t/480.jpg","file":"Casterplant 03.jpg","ar":0.75,"py":"bima bm","cr_by":"Dvellakat","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/480.jpg","illus_thumb":"images/i/t/480.jpg","illus_file":"Ricinus communis - Köhler–s Medizinal-Pflanzen-257.jpg","illus_ar":0.771,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":481,"seq":463,"zh":"一品红","en":"Euphorbia pulcherrima","sci":"Euphorbia pulcherrima","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":81,"desc_zh":"一品红（学名：Euphorbia pulcherrima），又名为圣诞红、圣诞花，大戟科大戟属植物，在圣诞节用来摆设的著名红色花卉。大红大绿的叶片相间，外观色彩充满圣诞节的应景气氛，因而称为圣诞红。 那些被人认为是花朵的红色部份其实是苞叶，而真正的花是在叶束中间的部份。被栽培的品系的叶通常会被制成橙色、浅绿色、奶油色及大理石花纹，要达到这效果，在十月至圣诞节时，它们不可以在晚上被灯光照射。即使是少量灯光照亦会阻止其开「花」。","desc_en":"The poinsettia (; Euphorbia pulcherrima) is a commercially important flowering plant species of the diverse spurge family Euphorbiaceae. Indigenous to Mexico and Central America, the poinsettia was first described by Europeans in 1834.","img":"images/481.jpg","thumb":"images/t/481.jpg","file":"Euphorbia pulcherrima (Barlovento) 04.jpg","ar":1.333,"py":"yipinhong yph","cr_by":"Frank Vincentz","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲","北美洲"]},{"id":482,"seq":464,"zh":"橡胶树","en":"Hevea brasiliensis","sci":"Hevea brasiliensis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":65,"desc_zh":"橡胶树（学名：Hevea brasiliensis），又称为巴西橡胶树、巴西护谟树、帕拉橡胶树或三叶橡胶树，是大戟科橡胶树属的一种乔木，其树汁是天然橡胶主要的原材料，其木材亦可制作家具。 原产于南美洲亚马逊森林，印第安人称橡胶树为“cahuchu”或“caoutchou”，意为“流泪之树”。在已知的产胶植物中，橡胶树产胶量最高, 品质最好，当前全球99%以上的天然橡胶均来源于该树。","desc_en":"Hevea brasiliensis, the Pará rubber tree, sharinga tree, seringueira, or, most commonly, rubber tree or rubber plant, is a flowering plant belonging to the spurge family, Euphorbiaceae.","img":"images/482.jpg","thumb":"images/t/482.jpg","file":"Hevea brasiliensis - Köhler–s Medizinal-Pflanzen-071.jpg","ar":0.722,"py":"xiangjiaoshu xjs","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"],"illus_img":"images/i/482.jpg","illus_thumb":"images/i/t/482.jpg","illus_file":"Hevea brasiliensis - Köhler–s Medizinal-Pflanzen-071.jpg","illus_ar":0.722,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":483,"seq":465,"zh":"麻疯树","en":"Barbados nut","sci":"Jatropha curcas","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":50,"desc_zh":"桐油树（学名：Jatropha curcas），又名麻风树、痲疯树、南洋油桐、黄肿树、假白榄等，为大戟科落叶灌木。其发源地在加勒比海的岛上，但葡萄牙商人把它引进了非洲和亚洲各地，现已分布在全世界的热带和亚热带地区。 桐油树的种仁含油率很高，达到40%以上，经过加工适用于生产生物柴油。在印度，桐油树被选为出产生物柴油的主要原料之一。 桐油树可生长在南北纬30度之间，在许多非洲国家被大量种植（如马里）。","desc_en":"Jatropha curcas is a species of flowering plant in the spurge family, Euphorbiaceae, that is native to the American tropics: Mexico, the Caribbean and Central and South America.","img":"images/483.jpg","thumb":"images/t/483.jpg","file":"Jatropha curcas1 henning.jpg","ar":0.786,"py":"mafengshu mfs","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["北美洲","南美洲"]},{"id":484,"seq":466,"zh":"泽漆","en":"Euphorbia helioscopia","sci":"Euphorbia helioscopia","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":48,"desc_zh":"泽漆（学名：Euphorbia helioscopia）为大戟科大戟属的植物。","desc_en":"Euphorbia helioscopia, the sun spurge or madwoman's milk, is a species of flowering plant in the spurge family Euphorbiaceae. It is a herbaceous annual plant, native to most of Europe, northern Africa, and eastward through most of Asia.","img":"images/484.jpg","thumb":"images/t/484.jpg","file":"Euphorbia helioscopia –IMG 6077 01.jpg","ar":1,"py":"zeqi zq","cr_by":"Kızıl","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/484.jpg","illus_thumb":"images/i/t/484.jpg","illus_file":"Euphorbia helioscopia — Flora Batava — Volume v4.jpg","illus_ar":0.745,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":485,"seq":467,"zh":"铁海棠","en":"Euphorbia milii","sci":"Euphorbia milii","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":47,"desc_zh":"虎刺梅（学名：Euphorbia milii），又名麒麟花、铁海棠、万年刺，属大戟科大戟属，原产于马达加斯加。","desc_en":"Euphorbia milii, the crown-of-thorns, Christ plant or Christ's thorn, is a species of flowering plant in the spurge family, Euphorbiaceae, native to Madagascar.","img":"images/485.jpg","thumb":"images/t/485.jpg","file":"Euphorbia Milii flowers.jpg","ar":1.501,"py":"tiehaitang tht","cr_by":"Ezra Katz","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"],"illus_img":"images/i/485.jpg","illus_thumb":"images/i/t/485.jpg","illus_file":"Euphorbia milii var. splendens Bot. Mag. 56. t. 2902. 1829.jpg","illus_ar":0.554,"illus_by":"Hooker","illus_lic":"Public domain","illus_licurl":null},{"id":486,"seq":468,"zh":"飞扬草","en":"Euphorbia hirta","sci":"Euphorbia hirta","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":44,"desc_zh":"飞扬草（学名：Euphorbia hirta L.）为大戟科大戟属的植物。一年生草本，植株高10-40公分，全株具有乳汁，被毛。茎斜生或直立，被毛，淡红色至紫色。单叶对生，叶卵形至椭圆形，歪基，叶缘锯齿，被毛。大戟花序聚繖状排列，总苞宽钟状，单性花，雄花多数，无花被片，雌花1枚，柱头3裂，子房3室。蒴果。","desc_en":"Euphorbia hirta (sometimes called asthma-plant) is a pantropical weed, originating from the tropical regions of the Americas. It is a hairy herb that grows in open grasslands, roadsides and pathways.","img":"images/486.jpg","thumb":"images/t/486.jpg","file":"Hierba de la golondrina (Euphorbia hirta) I.jpg","ar":1,"py":"feiyangcao fyc","cr_by":"Juan Carlos Fonseca Mata","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":492,"seq":469,"zh":"欧洲山杨","en":"Populus tremula","sci":"Populus tremula","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":93,"desc_zh":"欧洲山杨（学名：Populus tremula）是杨柳科杨属的植物。分布于欧洲、高加索、西伯利亚及中国的新疆等地，生长于海拔700米至2,300米的地区，一般生长在河谷和针叶林林缘。花期4月，果期5月。","desc_en":"Populus tremula (commonly called aspen, common aspen, Eurasian aspen, European aspen, or quaking aspen) is a species of poplar native to cool temperate regions of the Old World.","img":"images/492.jpg","thumb":"images/t/492.jpg","file":"Ospeholt i Hurdal.JPG","ar":0.667,"py":"ouzhoushanyang ozsy","cr_by":"Øyvind Holmstad","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/492.jpg","illus_thumb":"images/i/t/492.jpg","illus_file":"Populus tremula tree illustration.jpg","illus_ar":0.482,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":493,"seq":470,"zh":"白柳","en":"Salix alba","sci":"Salix alba","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":83,"desc_zh":"白柳（学名：Salix alba）为杨柳科柳属的植物。原产于欧洲和亚洲中西部，后来移种到世界其他地区，生长于海拔40米至3,100米的地区，多生长在沿河生长。 其种加词“alba”意为“白色的”。","desc_en":"Salix alba, the white willow, is a species of willow native to Europe and western and Central Asia. The name derives from the white tone to the undersides of the leaves.","img":"images/493.jpg","thumb":"images/t/493.jpg","file":"2015-05-08 Büdingen Naturdenkmal 440.221 Silber-Weide - 0919.jpg","ar":0.667,"py":"bailiu bl","cr_by":"Sven Teschke","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/493.jpg","illus_thumb":"images/i/t/493.jpg","illus_file":"Illustration Salix alba0.jpg","illus_ar":0.605,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":494,"seq":471,"zh":"黑杨","en":"Populus nigra","sci":"Populus nigra","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"DD","langs":70,"desc_zh":"黑杨（学名：Populus nigra）是杨柳科杨属的植物。分布在西亚、欧洲、中亚、高加索、巴尔干以及中国大陆的新疆等地，生长于海拔50米至3,685米的地区，目前尚未由人工引种栽培。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Populus nigra, the black poplar, is a species of cottonwood poplar, the type species of section Aigeiros of the genus Populus, native to Europe, southwest and central Asia, and northwest Africa.","img":"images/494.jpg","thumb":"images/t/494.jpg","file":"Populus nigra.Italica.01.jpg","ar":0.75,"py":"heiyang hy","cr_by":"No machine-readable author provided. JoJan assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/494.jpg","illus_thumb":"images/i/t/494.jpg","illus_file":"Populus nigra - Köhler–s Medizinal-Pflanzen-112.jpg","illus_ar":0.781,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":495,"seq":472,"zh":"银白杨","en":"Populus alba","sci":"Populus alba","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":69,"desc_zh":"银白杨（学名：Populus alba）通称白杨，为杨柳科杨属的植物。喜光，根系发达，木材轻软，可供观赏。 其种加词“alba”意为“白色的”。","desc_en":"Populus alba, commonly called silver poplar, silverleaf poplar, white poplar, or abele is a species of poplar, most closely related to the aspens (Populus sect. Populus).","img":"images/495.jpg","thumb":"images/t/495.jpg","file":"Populus alba, Czajecice, 20060812 1358.jpg","ar":0.75,"py":"yinbaiyang yby","cr_by":"Jakub Hałun","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/495.jpg","illus_thumb":"images/i/t/495.jpg","illus_file":"T2 52 Populus alba par Pierre-Joseph Redouté.jpeg","illus_ar":0.7,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":496,"seq":473,"zh":"黄花柳","en":"Salix caprea","sci":"Salix caprea","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":67,"desc_zh":"黄花柳（学名：Salix caprea）是杨柳科柳属的植物。分布于欧洲、俄罗斯以及中国大陆的新疆等地，生长于海拔500米至3,100米的地区，多生长在山坡和林中，目前尚未由人工引种栽培。 白银色种（Salix caprea pendula）民间又名「银柳」，亦是经常用于插花。","desc_en":"Salix caprea, known as goat willow, pussy willow or great sallow, is a common species of willow native to Europe and western and central Asia.","img":"images/496.jpg","thumb":"images/t/496.jpg","file":"Salix caprea8.jpg","ar":1.333,"py":"huanghualiu hhl","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/496.jpg","illus_thumb":"images/i/t/496.jpg","illus_file":"Salix caprea Sturm04028.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":498,"seq":474,"zh":"香堇菜","en":"Viola odorata","sci":"Viola odorata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":66,"desc_zh":"香堇菜（学名：Viola odorata）是堇菜科堇菜属的植物，原产于欧洲、北非和西亚。","desc_en":"Viola odorata is a species of flowering plant in the family Violaceae. The small hardy herbaceous perennial is commonly known as wood violet, sweet violet, English violet, common violet, florist's violet, or garden violet. The plant is native to Eurasia.","img":"images/498.jpg","thumb":"images/t/498.jpg","file":"20130407Viola odorata1.jpg","ar":0.75,"py":"xiangjincai xjc","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲"],"illus_img":"images/i/498.jpg","illus_thumb":"images/i/t/498.jpg","illus_file":"Viola odorata — Flora Batava — Volume v6.jpg","illus_ar":0.687,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":499,"seq":475,"zh":"三色堇","en":"Viola tricolor","sci":"Viola tricolor","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":66,"desc_zh":"三色菫（学名：Viola tricolor；英语：wild pansy）是堇菜科堇菜属的一年生或短期多年生草本植物，又名三色堇菜（中国植物图鉴）、蝴蝶花、三色紫罗兰、人脸花、阿拉叶－尼勒－其其格（蒙语），在欧洲是常见的野花，也常栽培于公园中，是一种常见的园艺植物。三色菫也被引进北美，并在当地广泛繁衍。 三色菫以露天栽种为宜，无论花坛、庭园、盆栽皆适合。","desc_en":"Viola tricolor is a common European wild flower, growing as an annual or short-lived perennial. The species is also known as wild pansy, Johnny Jump up (though this name is also applied to similar species such as the yellow pansy), heartsease, heart's ease, he…","img":"images/499.jpg","thumb":"images/t/499.jpg","file":"20180612Viola tricolor2.jpg","ar":0.75,"py":"sansejin ssj","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["欧洲"],"illus_img":"images/i/499.jpg","illus_thumb":"images/i/t/499.jpg","illus_file":"Viola tricolor - Köhler–s Medizinal-Pflanzen-280 0289-caps.jpg","illus_ar":0.762,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":500,"seq":476,"zh":"大花三色堇","en":"Viola × wittrockiana","sci":"Viola ×wittrockiana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":46,"desc_zh":"大花三色堇（学名：Viola ×wittrockiana）是堇菜科堇菜属的一个园艺栽培种，由三色堇与阿尔泰堇菜、黄堇菜杂交而得。大花三色堇诞生于1800年代的北欧，1820年代之后快速得到普及，成为主要园艺花卉之一。大花三色堇较为耐寒，主要在冬春开花。大花三色堇也是思想自由的象征之一。 大花三色堇染色体数是2n = 44–52，通常为2n = 48。","desc_en":"The garden pansy (Viola × wittrockiana) is a type of polychromatic large-flowered hybrid plant cultivated as a garden flower. It is derived by hybridization from several species in the section Melanium (\"the pansies\") of the genus Viola, particularly V.","img":"images/500.jpg","thumb":"images/t/500.jpg","file":"Pansy Viola x wittrockiana Red Cultivar Flower 2000px.jpg","ar":0.818,"py":"dahuasansejin dhssj","cr_by":"Photo by and (c)2008 Derek Ramsey ( Ram-Man )","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":null,"origin":["亚洲","欧洲"]},{"id":501,"seq":477,"zh":"野生堇菜","en":"Viola arvensis","sci":"Viola arvensis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":43,"desc_zh":"野生堇菜（学名：Viola arvensis）为菫菜科堇菜属下的一个种。","desc_en":"Viola arvensis is a species of violet known by the common name field pansy. It is native to Europe, western Asia, and North Africa, and it is known on other continents as an introduced species and a weed of disturbed and cultivated areas.","img":"images/501.jpg","thumb":"images/t/501.jpg","file":"(MHNT) Viola arvensis - White flower.jpg","ar":1.201,"py":"yeshengjincai ysjc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/501.jpg","illus_thumb":"images/i/t/501.jpg","illus_file":"Viola arvensis — Flora Batava — Volume v5.jpg","illus_ar":0.673,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":503,"seq":478,"zh":"百香果","en":"Passiflora edulis","sci":"Passiflora edulis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":81,"desc_zh":"西番莲（学名：Passiflora edulis），又名百香果、热情果、鸡蛋果、时计果，产于美洲的热带及亚热带地区。原产于巴西，巴拉圭，1610年间传入欧洲。西番莲的果汁常被用作香料，加在其他果汁中。","desc_en":"Passiflora edulis, commonly known as passion fruit, is a vine species of passion flower native to southern Brazil, through Paraguay, and northern Argentina.","img":"images/503.jpg","thumb":"images/t/503.jpg","file":"Markisa madu manis seperti kamu.jpg","ar":1.333,"py":"baixiangguo bxg","cr_by":"Rarani","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["南美洲"]},{"id":504,"seq":479,"zh":"蓝花西番莲","en":"Blue Passionflower","sci":"Passiflora caerulea","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":44,"desc_zh":"蓝花西番莲（学名：Passiflora caerulea），别名巴西耐寒西番莲，原产于巴西，是多年生草本藤本植物，比其他种类的西番莲有更高的耐寒性。本种因花色艳而成为园艺植物，各茎节上均长有卷须以作攀爬，是十分受欢迎的观花园艺植物。","desc_en":"Passiflora caerulea, the blue passionflower, bluecrown passionflower or common passion flower, is a species of flowering plant in the family Passifloraceae. It is native to South America and has been introduced elsewhere.","img":"images/504.jpg","thumb":"images/t/504.jpg","file":"Blue passion flower (Passiflora caerulea).jpg","ar":1.333,"py":"lanhuaxifanlian lhxfl","cr_by":"K. Chaikovska (Kate Chkv)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"藤本","origin":["南美洲"],"illus_img":"images/i/504.jpg","illus_thumb":"images/i/t/504.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 42 Passiflora caerulea, Mentha spicata (6022340096).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":505,"seq":480,"zh":"毛西番莲","en":"Passiflora foetida","sci":"Passiflora foetida","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":37,"desc_zh":"毛西番莲（学名：Passiflora foetida）又称为野百香果、龙珠果、小时计果，为二年生蔓性草本植物，常见于广西、广东、云南和台湾。常逸生于海拔120-500米草坡、灌丛中，为泛热带杂草。全株密生长毛，因而得其有「毛」之名，常藉卷须攀附其他作物上，为危害农地作物的杂草。其具有食虫习性，苞片被证实可以捕猎小型昆虫并将其消化吸收用于果实发育，但鉴于其食虫目的更倾向于保护果实，故也有学者将其归为捕虫植物。","desc_en":"Passiflora foetida (common names: stinking passionflower, wild maracuja, bush passion fruit, wild water lemon, stoneflower, love-in-a-mist, or running pop) is a species of passion flower that is native to the southwestern United States (southern Texas and Ariz…","img":"images/505.jpg","thumb":"images/t/505.jpg","file":"Passiflora foetida fruits.JPG","ar":1.499,"py":"maoxifanlian mxfl","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["北美洲","南美洲"]},{"id":507,"seq":481,"zh":"山竹","en":"Garcinia mangostana","sci":"Garcinia mangostana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":null,"langs":84,"desc_zh":"山竹（学名：Garcinia mangostana），又名莽吉柿、芒翕、山竺、山竹子、倒捻子、凤果，热带常绿乔木，为藤黄科藤黄属下的一个种。原产于马来群岛中的巽他群岛和摩鹿加群岛，由于盛产于南洋热带地区，有“热带果后”之称。在马来西亚、新加坡和泰国，榴梿和山竹被视为“夫妻果”，故此相对于称为「果王」的榴梿而言，山竹就是「果后」。","desc_en":"Mangosteen (Garcinia mangostana), also called mangostan or purple mangosteen, is a tropical evergreen tree with edible fruit native to the Malay Peninsula and Borneo. It has been cultivated extensively in tropical Asia since ancient times.","img":"images/507.jpg","thumb":"images/t/507.jpg","file":"Berthe Hoola van Nooten48.jpg","ar":0.668,"py":"shanzhu sz","cr_by":"Berthe Hoola van Nooten (1817-1892), Pieter De Pannemaeker (lithographer)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":508,"seq":482,"zh":"藤黄果","en":"Garcinia indica","sci":"Garcinia indica","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":"VU","langs":32,"desc_zh":null,"desc_en":"Garcinia indica, a plant in the mangosteen family (Clusiaceae), commonly known as kokum, is a fruit-bearing tree that has culinary, pharmaceutical, and industrial uses.","img":"images/508.jpg","thumb":"images/t/508.jpg","file":"Garcinia indica - fruits, seeds, pulp and rinds.jpg","ar":1.336,"py":"tenghuangguo thg","cr_by":"Subray Hegde","cr_lic":"CC BY 1.0","cr_licurl":"https://creativecommons.org/licenses/by/1.0","habit":"乔木","origin":null},{"id":509,"seq":483,"zh":"藤黄果","en":"Garcinia gummi-gutta","sci":"Garcinia gummi-gutta","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":"LC","langs":28,"desc_zh":null,"desc_en":"Garcinia gummi-gutta is a tropical species of Garcinia native to India. Common names include Garcinia cambogia (a former scientific name), as well as brindle berry, and Malabar tamarind. It is a tree which grows up to 20 metres tall.","img":"images/509.jpg","thumb":"images/t/509.jpg","file":"കുടപ്പുളി.JPG","ar":1.12,"py":"tenghuangguo thg","cr_by":"Vssun at ml.wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":511,"seq":484,"zh":"贯叶连翘","en":"Hypericum perforatum","sci":"Hypericum perforatum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Hypericaceae","family_zh":"金丝桃科","iucn":null,"langs":78,"desc_zh":"贯叶连翘（学名：Hypericum perforatum）， 又名贯叶金丝桃、圣约翰草（St John's wort），金丝桃科金丝桃属植物，是欧美的常用草药。主要用于妇女调经，亦有宁神、平衡情绪的作用。临床上发现对抑郁症患者有疗效，对癌症无效，，也一般不推荐用于调经。","desc_en":"Hypericum perforatum, commonly known as St. John's wort (sometimes perforate St. John's wort or common St. John's wort), is a flowering plant in the family Hypericaceae.","img":"images/511.jpg","thumb":"images/t/511.jpg","file":"(MHNT) Hypericum perforatum flower and buttons.jpg","ar":0.734,"py":"guanyelianqiao gylq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/511.jpg","illus_thumb":"images/i/t/511.jpg","illus_file":"Hypericum perforatum Sturm06060.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":512,"seq":485,"zh":"Hypericum maculatum","en":"Hypericum maculatum","sci":"Hypericum maculatum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Hypericaceae","family_zh":"金丝桃科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Hypericum maculatum, commonly known as imperforate St John's-wort, or spotted St. Johnswort, is a species of perennial herbaceous flowering plant in the family Hypericaceae. It is native to Europe and Western Asia where it grows in moist meadows.","img":"images/512.jpg","thumb":"images/t/512.jpg","file":"Geflecktes Johanniskraut.jpg","ar":0.75,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲"]},{"id":1115,"seq":486,"zh":"铺地金丝桃","en":"Hypericum humifusum","sci":"Hypericum humifusum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Hypericaceae","family_zh":"金丝桃科","iucn":null,"langs":25,"desc_zh":null,"desc_en":"Hypericum humifusum is a prostrate flowering plant in the St. John's wort family Hypericaceae commonly known as trailing St John's-wort. It is found in Western Europe.","img":"images/1115.jpg","thumb":"images/t/1115.jpg","file":"Hypericum humifusum W.jpg","ar":1.292,"py":"pudijinsitao pdjst","cr_by":"Fornax","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/1115.jpg","illus_thumb":"images/i/t/1115.jpg","illus_file":"Hypericum humifusum — Flora Batava — Volume v7.jpg","illus_ar":0.679,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":513,"seq":487,"zh":"红茄苳","en":"Rhizophora mucronata","sci":"Rhizophora mucronata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Rhizophoraceae","family_zh":"红树科","iucn":"LC","langs":32,"desc_zh":"红茄苳（学名：Rhizophora mucronata），为红树科红树属下的一个种。","desc_en":"Rhizophora mucronata (loop-root mangrove, red mangrove or Asiatic mangrove) is a species of mangrove found on coasts and river banks in East Africa and the Indo-Pacific region.","img":"images/513.jpg","thumb":"images/t/513.jpg","file":"Rhizophora mucronata Propagules.jpg","ar":0.75,"py":"hongqiedong hqd","cr_by":"self","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","非洲"]},{"id":1116,"seq":488,"zh":"印尼黑果","en":"Pangium edule","sci":"Pangium edule","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Achariaceae","family_zh":"青钟麻科","iucn":"LC","langs":25,"desc_zh":null,"desc_en":"Pangium is a genus in the family Achariaceae containing the sole species Pangium edule, a tall tree native to the mangrove swamps of Southeast Asia (Indonesia and Papua New Guinea).","img":"images/1116.jpg","thumb":"images/t/1116.jpg","file":"Pangium edule Blanco2.391.jpg","ar":0.694,"py":"yinniheiguo ynhg","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","大洋洲"]},{"id":1117,"seq":489,"zh":"Balanops australiana","en":"Balanops australiana","sci":"Balanops australiana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Balanopaceae","family_zh":"橡子木科","iucn":"LC","langs":7,"desc_zh":null,"desc_en":"Balanops australiana, commonly known as pimplebark, is a plant in the family Balanopaceae found only in the coastal regions of northern and central Queensland, Australia.","img":"images/1117.jpg","thumb":"images/t/1117.jpg","file":"Balanops australiana (13813866135).jpg","ar":1.333,"py":"","cr_by":"Keith Townsend from Townsville, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["大洋洲"]},{"id":1118,"seq":490,"zh":"红厚壳","en":"Calophyllum inophyllum","sci":"Calophyllum inophyllum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Calophyllaceae","family_zh":"红厚壳科","iucn":"LC","langs":41,"desc_zh":"红厚壳（学名：Calophyllum inophyllum），又名琼崖海棠，为胡桐科红厚壳属的植物。因为能在海滨沙石地生长粗大，南岛民族栽种作为木材来源，特别是用于造船。","desc_en":"Calophyllum inophyllum is a large evergreen plant, commonly called tamanu, oil-nut, mastwood, beach calophyllum or beautyleaf. It is native to the Old World Tropics, from Africa through Asia to Australia and Polynesia.","img":"images/1118.jpg","thumb":"images/t/1118.jpg","file":"Starr 010309-0546 Calophyllum inophyllum.jpg","ar":1.333,"py":"honghouke hhk","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲","非洲","大洋洲"]},{"id":1119,"seq":491,"zh":"巴西油桃木果","en":"Caryocar brasiliense","sci":"Caryocar brasiliense","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Caryocaraceae","family_zh":"油桃木科","iucn":"LC","langs":27,"desc_zh":"巴西油桃木（学名：Caryocar brasiliense）是一种可食用的果实，在巴西的一些地区，尤其是在巴西中西部地区很受欢迎。","desc_en":"Caryocar brasiliense, known as pequi (Portuguese pronunciation: [peˈki]) or souari nut, is an edible fruit popular in some areas of Brazil, especially in central-west Brazil.","img":"images/1119.jpg","thumb":"images/t/1119.jpg","file":"Pequi01.JPG","ar":1.333,"py":"baxiyoutaomuguo bxytmg","cr_by":"No machine-readable author provided. Conrado assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["南美洲"]},{"id":1120,"seq":492,"zh":"Bhesa ceylanica","en":"Bhesa ceylanica","sci":"Bhesa ceylanica","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Centroplacaceae","family_zh":"安神木科","iucn":"VU","langs":6,"desc_zh":null,"desc_en":"Bhesa ceylanica is a species of plant in the family Centroplacaceae. It is endemic to Sri Lanka.","img":"images/1120.jpg","thumb":"images/t/1120.jpg","file":"Bhesa ceylanica.jpg","ar":1.501,"py":"","cr_by":"AntanO","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":1121,"seq":493,"zh":"一口可梅","en":"Chrysobalanus icaco","sci":"Chrysobalanus icaco","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Chrysobalanaceae","family_zh":"可可李科","iucn":"LC","langs":24,"desc_zh":"一口可梅（学名：Chrysobalanus icaco）为蔷薇科可口梅属下的一个种。","desc_en":"Chrysobalanus icaco, the cocoplum, paradise plum, abajeru or icaco is a low shrub or bushy tree found near sea beaches and inland throughout tropical Africa, tropical Americas and the Caribbean, and in southern Florida and the Bahamas.","img":"images/1121.jpg","thumb":"images/t/1121.jpg","file":"Chrysobalanus icaco (inflorescense).jpg","ar":0.75,"py":"yikoukemei ykkm","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["非洲","北美洲"]},{"id":1122,"seq":494,"zh":"毒鼠子","en":"Dichapetalum gelonioides","sci":"Dichapetalum gelonioides","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Dichapetalaceae","family_zh":"毒鼠子科","iucn":"LC","langs":9,"desc_zh":"毒鼠子（学名：Dichapetalum gelonioides）为毒鼠子科毒鼠子属下的一个种。","desc_en":"Dichapetalum gelonioides, the gelonium poison-leaf, is a large shrub or small semi-evergreen tree, up to 5 m tall, originally described from Indo-Malaysian region.","img":"images/1122.jpg","thumb":"images/t/1122.jpg","file":"Dichapetalum gelonioides 09756.jpg","ar":1.501,"py":"dushuzi dsz","cr_by":"Vengolis","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":1123,"seq":495,"zh":"三蕊沟繁缕","en":"Elatine triandra","sci":"Elatine triandra","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Elatinaceae","family_zh":"沟繁缕科","iucn":"LC","langs":23,"desc_zh":"短柄花沟繁缕（学名：Elatine triandra）又名三蕊沟繁缕，为沟繁缕科沟繁缕属下的一个种。","desc_en":"Elatine triandra is a species of flowering plant belonging to the family Elatinaceae. It is known by the common name longstem waterwort. Its native range is Temperate and Subtropical Old World to Western Malesia.","img":"images/1123.jpg","thumb":"images/t/1123.jpg","file":"Elatine triandra flower.jpg","ar":0.814,"py":"sanruigoufanl srgfl","cr_by":"Loasa","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/1123.jpg","illus_thumb":"images/i/t/1123.jpg","illus_file":"Elatine triandra illustration (01).jpg","illus_ar":0.667,"illus_by":"Britton, N.L., and A. Brown, 1913, An illustrated flora of the northern United States, Canada and the British Possession","illus_lic":"Public domain","illus_licurl":null},{"id":1124,"seq":496,"zh":"古柯","en":"Erythroxylum coca","sci":"Erythroxylum coca","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Erythroxylaceae","family_zh":"古柯科","iucn":null,"langs":64,"desc_zh":"古柯树（英语：Coca，学名：Erythroxylum coca），又名药古柯，一种灌木，原生于南美洲的西北部秘鲁一带，叶中含有古柯碱，可用于提取可卡因，作为麻醉药，也可作为毒品，在当地原住民的传统文化中曾起过很重要的作用。 古柯树是被称为古柯的两种植物之一，目前在南美洲的秘鲁、哥伦比亚、玻利维亚、亚洲的斯里兰卡和印度尼西亚等地广为栽培，形成许多亚种，如秘鲁古柯（E.truxillense）、爪哇古柯（E.","desc_en":"Erythroxylum coca is a species of flowering plant in the family Erythroxylaceae. It is one of the two species of cultivated coca.","img":"images/1124.jpg","thumb":"images/t/1124.jpg","file":"Erythroxylum coca - Köhler–s Medizinal-Pflanzen-204.jpg","ar":0.848,"py":"guke gk","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/1124.jpg","illus_thumb":"images/i/t/1124.jpg","illus_file":"Erythroxylum coca - Köhler–s Medizinal-Pflanzen-204.jpg","illus_ar":0.848,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1125,"seq":497,"zh":"圭巴卫矛","en":"Goupia glabra","sci":"Goupia glabra","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Goupiaceae","family_zh":"尾瓣桂科","iucn":"LC","langs":10,"desc_zh":"圭巴卫矛（Goupia glabra）是毛药树科（以前被归入卫矛科）的一种开花植物。它原产于南美洲热带地区，在巴西北部、哥伦比亚、法属圭亚那、圭亚那、苏里南和委内瑞拉均有分布。 该物种的其他名称包括Saino、Sapino（哥伦比亚）、Kopi（苏里南）、Kabukalli（圭亚那）、Goupi、bois-caca（法属圭亚那）、Pasisi（Wayampi语）、Pasis（Palikur语言）、Kopi（Businenge语）、Cup…","desc_en":"Goupia glabra (goupie or kabukalli; syn. G. paraensis, G. tomentosa) is a species of flowering plant in the family Goupiaceae (formerly treated in the family Celastraceae).","img":"images/1125.jpg","thumb":"images/t/1125.jpg","file":"13534-Goupia glabra-Caura.jpg","ar":1.432,"py":"guibaweimao gbwm","cr_by":"Vojtěch Zavadil","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":1126,"seq":498,"zh":"马来假杧果","en":"Irvingia malayana","sci":"Irvingia malayana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Irvingiaceae","family_zh":"包芽树科","iucn":"LC","langs":10,"desc_zh":null,"desc_en":"Irvingia malayana, also known as wild almond (Vietnamese: Kơ nia, Thai: กระบก, Khmer: ចំបក់) or barking deer's mango, is a tropical evergreen tree species in the family Irvingiaceae. The specific epithet malayana is from the Latin meaning \"of Malaya\".","img":"images/1126.jpg","thumb":"images/t/1126.jpg","file":"Konia tree.jpg","ar":0.728,"py":"malaijiamangguo mljmg","cr_by":"DXLINH","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":1127,"seq":499,"zh":"粘木","en":"Ixonanthes reticulata","sci":"Ixonanthes reticulata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Ixonanthaceae","family_zh":"黏木科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Ixonanthes reticulata is a species of plant in the Ixonanthaceae family. It is native to an area from China to India (Assam and Meghalaya) to mainland and maritime Southeast Asia. It is a broadleaf evergreen.","img":"images/1127.jpg","thumb":"images/t/1127.jpg","file":"Ixonanthes reticulata.jpg","ar":0.75,"py":"nianmu nm","cr_by":"Patrice78500","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":1128,"seq":500,"zh":"Lacistema robustum","en":"Lacistema robustum","sci":"Lacistema robustum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Lacistemataceae","family_zh":"裂药花科","iucn":"NT","langs":8,"desc_zh":null,"desc_en":"Lacistema robustum is a species of plant in the Lacistemataceae family. It is endemic to Brazil.","img":"images/1128.jpg","thumb":"images/t/1128.jpg","file":"Lacistema robustum.jpg","ar":0.677,"py":"","cr_by":"Carl Friedrich Philipp von Martius","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"]},{"id":1129,"seq":501,"zh":"亚麻","en":"Linum usitatissimum","sci":"Linum usitatissimum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Linaceae","family_zh":"亚麻科","iucn":null,"langs":113,"desc_zh":"亚麻（英语：Flax，学名：Linum usitatissimum），又名胡麻，是亚麻科亚麻属一年生草本优质油料和纺织原料植物。是在全球各地广泛栽培的植物，可能原产于西亚。","desc_en":"Flax, also known as common flax or line, is a flowering plant, Linum usitatissimum, in the family Linaceae. It is cultivated as a food and fiber crop in regions of the world with temperate climates.","img":"images/1129.jpg","thumb":"images/t/1129.jpg","file":"Linum usitatissimum 001.JPG","ar":1.333,"py":"yama ym","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/1129.jpg","illus_thumb":"images/i/t/1129.jpg","illus_file":"Linum usitatissimum - Köhler–s Medizinal-Pflanzen-088.jpg","illus_ar":0.743,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":1130,"seq":502,"zh":"卡披木","en":"Banisteriopsis caapi","sci":"Banisteriopsis caapi","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Malpighiaceae","family_zh":"金虎尾科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Banisteriopsis caapi, also known as, caapi, soul vine, yagé (yage), or ayahuasca (the latter of which also refers to the psychedelic decoction made with the vine and a plant source of dimethyltryptamine) is a South American liana of the family Malpighiaceae.","img":"images/1130.jpg","thumb":"images/t/1130.jpg","file":"Ejemplar de Banisteriopsis caapi en el jardín botánico del Centro Takiwasi.jpg","ar":1.5,"py":"kapimu kpm","cr_by":"François Delonnay/Archivo Centro Takiwasi","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["南美洲"]},{"id":1131,"seq":503,"zh":"Lophira alata","en":"Lophira alata","sci":"Lophira alata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Ochnaceae","family_zh":"金莲木科","iucn":"VU","langs":21,"desc_zh":null,"desc_en":"Lophira alata, commonly known as azobé, ekki or the red ironwood tree, is a species of plant in the family Ochnaceae. It is found in Cameroon, the Republic of the Congo, the Democratic Republic of the Congo, Ivory Coast, Equatorial Guinea, Gabon, Ghana, Liberi…","img":"images/1131.jpg","thumb":"images/t/1131.jpg","file":"Lophira alata 157880343.jpg","ar":1.333,"py":"","cr_by":"Ajit Ampalakkad","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲","非洲"],"illus_img":"images/i/1131.jpg","illus_thumb":"images/i/t/1131.jpg","illus_file":"Lophira alata illustration.jpg","illus_ar":0.594,"illus_by":"Talbot","illus_lic":"Public domain","illus_licurl":null},{"id":1132,"seq":504,"zh":"Panda oleosa","en":"Panda oleosa","sci":"Panda oleosa","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Pandaceae","family_zh":"小盘木科","iucn":"LC","langs":12,"desc_zh":null,"desc_en":"Panda is a plant genus of the family Pandaceae. It contains only one known species, Panda oleosa, native to western and central Africa (Liberia, Ghana, Guinea, Ivory Coast, Nigeria, Cabinda, Gabon, Central African Republic, Congo-Brazzaville, Cameroon, Zaire).","img":"images/1132.png","thumb":"images/t/1132.png","file":"Pandaceae Panda oleosa.png","ar":0.725,"py":"","cr_by":"Adolf Engler","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲","非洲"]},{"id":1133,"seq":505,"zh":"Clutia pulchella","en":"Clutia pulchella","sci":"Clutia pulchella","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Peraceae","family_zh":"蚌壳木科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Clutia pulchella, the lightning bush, is a southern African dioecious shrub of the family Peraceae. It occurs at middle altitudes in Namibia, Mozambique, Zimbabwe, Eswatini, Botswana, Lesotho and South Africa.","img":"images/1133.jpg","thumb":"images/t/1133.jpg","file":"Clutia pulchella, habitus, Seringveld.jpg","ar":1.333,"py":"","cr_by":"JMK","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["非洲"]},{"id":1134,"seq":506,"zh":"余甘子","en":"Phyllanthus emblica","sci":"Phyllanthus emblica","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Phyllanthaceae","family_zh":"叶下珠科","iucn":"LC","langs":68,"desc_zh":"余甘子（学名：Phyllanthus emblica），另称油甘/柑（子）、橄榄、滇橄榄、久如拉、昂荆旦、麻甘腮、牛甘子、牛甘果、喉甘子、鱼木果、橄榄子、木波、望果、米含等，为叶下珠科叶下珠属的一种木本植物。 余甘子自然分布于南亚及东南亚，包括印度、斯里兰卡、中南半岛、印尼、菲律宾、台湾、香港、华南，美洲巴拿马地区有引入。自然生境多位于海拔200米至2300的地区，多见于山地疏林、灌丛、荒地或山沟向阳处，现有人工种植。","desc_en":"Phyllanthus emblica, commonly known as emblic, Indian gooseberry, amalaki, amloki, or amla, is a deciduous tree of the family Phyllanthaceae. Its native range is tropical and southern Asia.","img":"images/1134.jpg","thumb":"images/t/1134.jpg","file":"Indian Gooseberry.jpg","ar":0.562,"py":"yuganzi ygz","cr_by":"In Transit","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":1135,"seq":507,"zh":"Petalostigma pubescens","en":"Petalostigma pubescens","sci":"Petalostigma pubescens","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Picrodendraceae","family_zh":"苦胡桃科","iucn":"LC","langs":9,"desc_zh":null,"desc_en":"Petalostigma pubescens, known as the quinine bush is a rainforest tree native to Papua New Guinea, Queensland, Northern Territory, New South Wales, Western Australia. It was first described by the botanist Karel Domin in 1927.","img":"images/1135.jpg","thumb":"images/t/1135.jpg","file":"Petalostigma pubescens foliage and flowers.jpg","ar":1.097,"py":"","cr_by":"Ethel Aardvark","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["大洋洲"]},{"id":1136,"seq":508,"zh":"Rhyncholacis clavigera","en":"Rhyncholacis clavigera","sci":"Rhyncholacis clavigera","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Podostemaceae","family_zh":"川苔草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Rhyncholacis clavigera is a species of aquatic plant in the family Podostemaceae. It is found in the Caño Cristales river in Colombia.","img":"images/1136.jpg","thumb":"images/t/1136.jpg","file":"PLANTA ACUÁTICA ROJA MACARENIA CLAVIGERA.jpg","ar":1.502,"py":"","cr_by":"Mario Carvajal","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":1137,"seq":509,"zh":"Drypetes sepiaria","en":"Drypetes sepiaria","sci":"Drypetes sepiaria","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Putranjivaceae","family_zh":"核果木科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Drypetes sepiaria is a species of small tree in the family Putranjivaceae. This tree is very common in India and Sri Lanka. It is known by many local names, including vellakasavu, veeramaram in Malayalam, vellilambu, veerai (வீரை), aadumilukkan, kaayalakkamara…","img":"images/1137.jpg","thumb":"images/t/1137.jpg","file":"Drypetes sepiaria (fruit).jpg","ar":1.501,"py":"","cr_by":"AntanO","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":1138,"seq":510,"zh":"阿诺尔特大花草","en":"Rafflesia arnoldi","sci":"Rafflesia arnoldi","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Rafflesiaceae","family_zh":"大花草科","iucn":null,"langs":52,"desc_zh":"阿诺尔特大花草（学名：Rafflesia arnoldii），又称霸王花、大王花，属金虎尾目大花草科大花草属的一种，产于印度尼西亚共和国苏门达腊岛南端与婆罗洲。阿诺尔特大花草为世界上最大的花，花的直径长达一米，重11千克。其种名“arnoldii”是为了纪念发现此植物的科学探险队的率领者——英国自然学家约瑟夫·阿诺尔特（Joseph Arnold）；则贝叶棕具有世界最大的花序；巨花魔芋是具有世界上最大的不分支花序。","desc_en":"Rafflesia arnoldii is a species of flowering plant in the parasitic genus Rafflesia within the family Rafflesiaceae. It is native to the rainforests of Sumatra and Borneo. It is commonly known as the corpse flower or giant padma.","img":"images/1138.jpg","thumb":"images/t/1138.jpg","file":"Rafflesia Arnoldii Batang Palupuah Indonesia.jpg","ar":0.662,"py":"anuoertedahuacao anetdhc","cr_by":"Maizal Chaniago","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":1139,"seq":511,"zh":"Mathurina penduliflora","en":"Mathurina penduliflora","sci":"Mathurina penduliflora","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Turneraceae","family_zh":"时钟花科","iucn":null,"langs":6,"desc_zh":null,"desc_en":"Mathurina penduliflora is the sole member of the monotypic genus Mathurina, of flowering plants.","img":"images/1139.jpg","thumb":"images/t/1139.jpg","file":"Mathurina penduliflora - Grande Montagne 3.jpg","ar":0.755,"py":"","cr_by":"S Molteno","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":514,"seq":512,"zh":"芹叶牻牛儿苗","en":"Erodium cicutarium","sci":"Erodium cicutarium","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":54,"desc_zh":"芹叶牻牛儿苗（学名：Erodium cicutarium）为牻牛儿苗科牻牛儿苗属下的一个种。","desc_en":"Erodium cicutarium, also known as common stork's-bill, redstem filaree, redstem stork's bill or pinweed, is a herbaceous annual – or in warm climates, biennial – member of the family Geraniaceae of flowering plants.","img":"images/514.jpg","thumb":"images/t/514.jpg","file":"Erodium cicutarium flowers - Keila.jpg","ar":1.501,"py":"qinyemangniuermiao qymnem","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","非洲","北美洲"],"illus_img":"images/i/514.jpg","illus_thumb":"images/i/t/514.jpg","illus_file":"Erodium cicutarium Sturm8.jpg","illus_ar":0.69,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":515,"seq":513,"zh":"汉荭鱼腥草","en":"Geranium robertianum","sci":"Geranium robertianum","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":53,"desc_zh":"汉荭鱼腥草（学名：Geranium robertianum）为牻牛儿苗科老鹳草属的植物。分布于朝鲜、日本、地中海、中亚、西伯利亚、欧洲、台湾以及中国大陆的西南、华东、华中等地，生长于海拔900米至3,200米的地区，常生于山地林下、沟坡、岩壁和路旁。","desc_en":"Geranium robertianum, commonly known as herb-robert or, in North America, as Robert's geranium, is a species of cranesbill that is widespread throughout the northern hemisphere and introduced to some countries in the southern.","img":"images/515.jpg","thumb":"images/t/515.jpg","file":"(MHNT) Geranium robertianum - blossom and bud.jpg","ar":0.918,"py":"hanhongyuxingcao hhyxc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["北美洲"],"illus_img":"images/i/515.jpg","illus_thumb":"images/i/t/515.jpg","illus_file":"Geranium robertianum Sturm7.jpg","illus_ar":0.684,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":516,"seq":514,"zh":"森林老鹳草","en":"Geranium sylvaticum","sci":"Geranium sylvaticum","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Geranium sylvaticum, the wood cranesbill or woodland geranium, is a species of hardy flowering plant in the family Geraniaceae, native to Europe and northern Turkey.","img":"images/516.jpg","thumb":"images/t/516.jpg","file":"Geranium sylvaticum (1).JPG","ar":0.8,"py":"senlinlaoguancao sllgc","cr_by":"Philipp Weigell","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/516.jpg","illus_thumb":"images/i/t/516.jpg","illus_file":"Geranium sylvaticum Lindman DESC.JPG","illus_ar":1.493,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":517,"seq":515,"zh":"血红老鹳草","en":"Geranium sanguineum","sci":"Geranium sanguineum","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":39,"desc_zh":null,"desc_en":"Geranium sanguineum, common name bloody crane's-bill or bloody geranium, is a species of hardy flowering herbaceous perennial plant in the cranesbill family Geraniaceae. It is the county flower of Northumberland.","img":"images/517.jpg","thumb":"images/t/517.jpg","file":"(MHNT) Geranium sanguineum - Flower and leaf - Les Martels, Giroussens Tarn.jpg","ar":1.49,"py":"xuehonglaoguancao xhlgc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null,"illus_img":"images/i/517.jpg","illus_thumb":"images/i/t/517.jpg","illus_file":"The American Flora. Vol. 3, 1855 - pl. 17 Geranium sanguineum (10172322036).jpg","illus_ar":0.71,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":1140,"seq":516,"zh":"娑羽树","en":"Bersama abyssinica","sci":"Bersama abyssinica","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Francoaceae","family_zh":"新妇花科","iucn":"LC","langs":14,"desc_zh":null,"desc_en":"Bersama abyssinica is a species of medium-sized evergreen tree in the family Francoaceae. The leaves are pinnately divided with a strongly winged rachis (hence the common name winged bersama). The inflorescence is a spike.","img":"images/1140.jpg","thumb":"images/t/1140.jpg","file":"Bersama abyssinica 1DS-II 3026.jpg","ar":1.501,"py":"suoyushu sys","cr_by":"SAplants","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["非洲"]},{"id":519,"seq":517,"zh":"丁香","en":"clove","sci":"Syzygium aromaticum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":null,"langs":128,"desc_zh":"丁子香或丁香（学名：Syzygium aromaticum）是桃金娘科蒲桃属的一个种，也叫鸡舌香、鸡舌。Clove来自拉丁文「CLAVUS」，代表「钉子」的意思，因外型像小钉。原产于印度尼西亚的摩鹿加群岛（MOLUCCAS），摩鹿加又被称为香料岛(SPICE ISLAND)。当地传统习俗在婴儿诞生时，栽种一棵丁香树苗，母亲们由丁香树成长荣枯，最为其子女命运的前兆。","desc_en":"Cloves are the aromatic flower buds of a tree in the family Myrtaceae, Syzygium aromaticum (). They are native to the Maluku Islands, or Moluccas, in Indonesia, and are commonly used as a spice, flavoring, or fragrance in consumer products, such as toothpaste,…","img":"images/519.jpg","thumb":"images/t/519.jpg","file":"Cengkih.jpg","ar":0.75,"py":"dingxiang dx","cr_by":"Bayu Nugroho","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/519.jpg","illus_thumb":"images/i/t/519.jpg","illus_file":"Syzygium aromaticum - Köhler–s Medizinal-Pflanzen-030.jpg","illus_ar":0.768,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":520,"seq":518,"zh":"番石榴","en":"Psidium guajava","sci":"Psidium guajava","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":87,"desc_zh":"番石榴（学名：Psidium guajava），是桃金娘科番石榴属的常绿灌木或小乔木植物。因多籽类似石榴而得名，在台湾又俗称为芭乐，源自台湾话的林菝仔；客家语则称朳仔；中山、顺德一带、澳门粤语又称花稔等。番石榴原产于加勒比地区、中美洲和南美洲，因适应性良好而广泛栽培于热带及亚热带地区。可用播种、扦插、空中压条及嫁接等方法繁殖。各国因种植、加工和出口番石榴的果实而形成规模庞大的果树产业。2023年番石榴全球总产量达到79.","desc_en":"Psidium guajava, the common guava, yellow guava, lemon guava, or apple guava is an evergreen shrub or small tree native to South America. It is pollinated by insects. When cultivated, it is pollinated mainly by the common honey bee, Apis mellifera.","img":"images/520.jpg","thumb":"images/t/520.jpg","file":"Apple Guava.jpg","ar":1.333,"py":"fanshiliu fsl","cr_by":"Fuadsyazwan ( talk )","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"]},{"id":521,"seq":519,"zh":"阎浮树","en":"Syzygium cumini","sci":"Syzygium cumini","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":76,"desc_zh":"阎浮树（学名：Syzygium cumini；梵语：जम्बूफलम् (Jambu)），为桃金娘科蒲桃属，又名肯氏蒲桃、海南蒲桃（广州植物志、海南植物志）、堇宝莲、乌墨、鸟木、乌楣、印度蓝莓、印度黑莓等，分布于南亚及东南亚。","desc_en":"Syzygium cumini, also known as Java plum, Malabar plum, jambolan, black plum, jamun, jambul, is an evergreen tropical tree in the flowering plant family Myrtaceae, and favored for its fruit, timber, and ornamental value.","img":"images/521.jpg","thumb":"images/t/521.jpg","file":"Syzygium cumini plant.jpg","ar":0.562,"py":"yanfushu yfs","cr_by":"কামরুল ইসলাম শাহীন","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":522,"seq":520,"zh":"多香果","en":"Pimenta dioica","sci":"Pimenta dioica","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":56,"desc_zh":"多香果又名全香子、众香子、牙买加胡椒，是桃金娘科多香果属的一种植物，原产于美洲的热带地区。干燥未成熟的果实与叶子可以做为香料使用，由于果实具有丁香、胡椒、肉桂、肉荳蔻等多种香料的味道，所以被称为多香果。","desc_en":"Allspice, also known as Jamaica pepper, myrtle pepper, pimenta, or pimento, is the dried unripe berry of Pimenta dioica, a midcanopy tree native to the Greater Antilles, southern Mexico, and Central America, now cultivated in many warm parts of the world.","img":"images/522.jpg","thumb":"images/t/522.jpg","file":"Piment Flower.jpg","ar":1.333,"py":"duoxiangguo dxg","cr_by":"Christian Blue","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["北美洲"],"illus_img":"images/i/522.jpg","illus_thumb":"images/i/t/522.jpg","illus_file":"Pimenta dioica - Köhler–s Medizinal-Pflanzen-239.jpg","illus_ar":0.77,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":523,"seq":521,"zh":"香桃木","en":"common myrtle","sci":"Myrtus communis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":54,"desc_zh":"香桃木（学名：Myrtus communis），别名为香桃金娘、甜香桃木，原生于南欧至地中海沿岸一带，为桃金娘科香桃木属下的一个种。常绿灌木，分布于中南半岛、菲律宾、日本、印度、斯里兰卡、马来西亚、印度尼西亚、台湾以及中国的福建、广东、广西、云南、贵州、湖南，生长于海拨50－900米的地区，常见于丘陵坡地，是一种酸性土壤指示植物。","desc_en":"Myrtus communis, the common myrtle or true myrtle, is a species of flowering plant in the myrtle family Myrtaceae. It is an evergreen shrub native to southern Europe, North Africa, Western Asia, Macaronesia, and the Indian subcontinent, and also cultivated.","img":"images/523.jpg","thumb":"images/t/523.jpg","file":"Illustration Myrtus communis0.jpg","ar":0.597,"py":"xiangtaomu xtm","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/523.jpg","illus_thumb":"images/i/t/523.jpg","illus_file":"43 Myrtus communis romana par Pierre-Joseph Redouté.jpeg","illus_ar":0.705,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":524,"seq":522,"zh":"拟爱神木","en":"Plinia cauliflora","sci":"Plinia cauliflora","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":52,"desc_zh":"拟爱神木（英语：Jabuticaba，学名：Plinia cauliflora，旧学名：Myrciaria cauliflora）为热带、亚热带水果，原产地为南美洲巴西米纳斯吉拉斯。抗虫害和适应环境力强，其果实也叫木葡萄、树葡萄，成熟的外表为紫色，果肉呈白色略透明状，内有种籽一粒，不坚硬，容易咬碎。果肉味道清甜、果皮味酸。可以连籽一同食用。其含有较丰富的维生素C等营养物质及磷、镁等微量元素。","desc_en":"A jaboticaba () or jabuticaba (Portuguese: [ʒabutʃiˈkabɐ]) is a round, edible fruit produced by a jaboticaba tree (Plinia cauliflora), also known as Brazilian grapetree.","img":"images/524.jpg","thumb":"images/t/524.jpg","file":"Flor de jaboticaba (Myrciaria cauliflora) CASA de mamâ, Sao Paulo.jpg","ar":1.333,"py":"niaishenmu nasm","cr_by":"mauroguanandi","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["南美洲"]},{"id":525,"seq":523,"zh":"蓝桉","en":"Eucalyptus globulus","sci":"Eucalyptus globulus","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":49,"desc_zh":"蓝桉（学名：Eucalyptus globulus，英语：Blue gum）为桃金娘科桉属下的一个种，又名蓝胶尤加利，是一种高大常绿乔木，为澳大利亚东南边的特有种，也是澳大利亚栽培最广泛的树种之一。一般可长到30—50米（98—164英尺）。历史记录中最高可达101米（331英尺）。自然分布范围包括塔斯马尼亚和维多利亚州南部。在金岛和弗林德斯岛上也有孤立的蓝桉。","desc_en":"Eucalyptus globulus, commonly known as southern blue gum or blue gum, is a species of flowering plant in the family Myrtaceae. It is a tall, evergreen tree endemic to southeastern Australia.","img":"images/525.jpg","thumb":"images/t/525.jpg","file":"Eucalyptus globulus globulus buds.jpg","ar":1.51,"py":"lanan la","cr_by":"Murray Fagg","cr_lic":"CC BY 3.0 au","cr_licurl":"https://creativecommons.org/licenses/by/3.0/au/deed.en","habit":"乔木","origin":["大洋洲"],"illus_img":"images/i/525.jpg","illus_thumb":"images/i/t/525.jpg","illus_file":"Eucalyptus globulus - Köhler–s Medizinal-Pflanzen-147.jpg","illus_ar":0.738,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":526,"seq":524,"zh":"南美棯","en":"Feijoa sellowiana","sci":"Feijoa sellowiana","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":49,"desc_zh":"费约果（Feijoa）、凤梨番石榴、非油果、菠萝番石榴。原产地在中南美洲哥伦比亚、 乌拉圭和阿根廷北部，盛产于纽西兰，外皮深绿色，内部类似芭乐。含丰富维他命C。其常用名“斐济果”为早期缺乏正式中文译名期间，民间根据其发音类似“斐济”而产生的俗说讹传。费约果得名于葡萄牙植物学家若昂·达·席尔瓦·费约（João da Silva Feijó）。","desc_en":"Feijoa sellowiana, also known as Acca sellowiana (O.Berg) Burret, is a species of flowering plant in the myrtle family, Myrtaceae. It is the only species in the genus Feijoa.","img":"images/526.jpg","thumb":"images/t/526.jpg","file":"Acca sellowiana Fruit MHNT Fronton.jpg","ar":1.316,"py":"nanmeiren nmr","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["南美洲"]},{"id":532,"seq":525,"zh":"野牡丹","en":"Melastoma malabathricum","sci":"Melastoma malabathricum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":23,"desc_zh":"野牡丹（学名：Melastoma candidum，英文名称：Common Melastoma），为野牡丹科野牡丹属的植物，又名山石榴（台湾）、大金香炉、猪古稔（广东）、豹牙兰（云南）、豹牙郎木、倒罐草、九螺子花、高脚稔、罐罐草、地茄、金石榴、老虎杆、埔笔仔、痢疾罐、毛张口、小毛香、王不留行、王不留。原产于巴西，分布于台湾、印度以及中国大陆的广东、福建、广西、云南等地，生长于海拔120米的地区，多生长于山坡松林下和开朗的灌草丛中。","desc_en":"Melastoma malabathricum, known also as Malabar melastome, Indian rhododendron, Singapore rhododendron, planter's rhododendron and senduduk, is a flowering plant in the family Melastomataceae native to Seychelles, tropical and subtropical Asia to Australia and…","img":"images/532.jpg","thumb":"images/t/532.jpg","file":"Khloongkhleeng.jpg","ar":1.333,"py":"yemudan ymd","cr_by":"User:Loma","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","大洋洲"]},{"id":533,"seq":526,"zh":"粉苞酸脚杆","en":"Medinilla magnifica","sci":"Medinilla magnifica","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":21,"desc_zh":null,"desc_en":"Medinilla magnifica, the showy medinilla or rose grape, is a species of epiphytic flowering plant, of the family Melastomataceae, native to the Philippines.","img":"images/533.jpg","thumb":"images/t/533.jpg","file":"Medinilla magnifica flor.jpg","ar":1.333,"py":"fenbaosuanjiaogan fbsjg","cr_by":"No machine-readable author provided. Alberto Salguero assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"],"illus_img":"images/i/533.jpg","illus_thumb":"images/i/t/533.jpg","illus_file":"Medinilla magnifica Paxton 12.jpg","illus_ar":0.735,"illus_by":"John Lindley and Joseph Paxton , drawing by L. A. L. Constans","illus_lic":"Public domain","illus_licurl":null},{"id":534,"seq":527,"zh":"米氏野牡丹","en":"Miconia calvescens","sci":"Miconia calvescens","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":"LC","langs":17,"desc_zh":"米氏野牡丹（学名：Miconia calvescens）是大叶野牡丹属下的一个种，原产于墨西哥到南美洲。 并且入侵到了包括夏威夷在内的世界各地，同时也是世界百大外来入侵种之一。 米氏野牡丹一年数次开花，同时结果。大型圆锥花絮。花呈白色到粉色不等，其花香会吸引许多鸟类和动物前来觅食。紫色果实直接约半厘米，一颗米氏野牡丹的两朵花一个结果季可产出二十万颗种子。","desc_en":"Miconia calvescens, the velvet tree, miconia, or bush currant, is a species of flowering plant in the family Melastomataceae. It is native to Mexico and Central and South America and it has become one of the world's most invasive species.","img":"images/534.jpg","thumb":"images/t/534.jpg","file":"Starr Miconia calvescens0.jpg","ar":0.75,"py":"mishiyemudan msymd","cr_by":null,"cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"灌木","origin":["北美洲","南美洲"]},{"id":535,"seq":528,"zh":"毛野牡丹藤","en":"Siete cueros","sci":"Clidemia hirta","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":16,"desc_zh":"毛野牡丹藤（学名：Clidemia hirta）为野牡丹科毛野牡丹属下的一个种。国际自然保护联盟物种存续委员会的入侵物种专家小组（ISSG）列为世界百大外来入侵种。","desc_en":"Miconia crenata, commonly called Koster's curse, is a species of plant in the family Melastomataceae. It is a perennial shrub native to Central and South America, including the Caribbean, and it has been introduced to tropical parts of the Indian Ocean, Asia,…","img":"images/535.jpg","thumb":"images/t/535.jpg","file":"Starr 030729-0107 Clidemia hirta.jpg","ar":1.333,"py":"maoyemudanteng mymdt","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"灌木","origin":["亚洲","北美洲","南美洲","大洋洲"]},{"id":536,"seq":529,"zh":"Medinilla speciosa","en":"Medinilla speciosa","sci":"Medinilla speciosa","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Medinilla speciosa is a perennial epiphytic plant in the genus Medinilla of the family Melastomataceae.","img":"images/536.jpg","thumb":"images/t/536.jpg","file":"Medinilla speciosa - par Mickael Schauli.jpg","ar":0.665,"py":"","cr_by":"Mickaël Schauli","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":538,"seq":530,"zh":"柳兰","en":"Chamaenerion angustifolium","sci":"Chamaenerion angustifolium","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":null,"langs":61,"desc_zh":"柳兰（学名：Epilobium angustifolium ssp. angustifolium）为柳叶菜科柳叶菜属下的一个亚种。它原产于整个北半球温带地区，包括大部分北方针叶林。","desc_en":"Chamaenerion angustifolium is a perennial herbaceous flowering plant in the willowherb family, Onagraceae. It is known in North America as fireweed and in the British Isles as both fireweed and rosebay willowherb.","img":"images/538.jpg","thumb":"images/t/538.jpg","file":"Chamerion angustifolium - Fireweed 01.jpg","ar":0.668,"py":"liulan ll","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲","北美洲"],"illus_img":"images/i/538.jpg","illus_thumb":"images/i/t/538.jpg","illus_file":"Epilobium angustifolium (modern=Chamaenerion angustifolium) - Pl0007 - FloraBatava-KB-v01.jpg","illus_ar":0.764,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":539,"seq":531,"zh":"月见草","en":"Oenothera biennis","sci":"Oenothera biennis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":null,"langs":43,"desc_zh":"月见草（学名：Oenothera biennis）为柳叶菜科月见草属下的一个种。原产于北美洲的东部和中部，分布范围从纽芬兰岛西部到艾伯塔省，东南到佛罗里达州，西南到德克萨斯州，并且在其他温带和亚热带地区广泛归化。","desc_en":"Oenothera biennis, the common evening-primrose, is a species of flowering plant in the family Onagraceae, native to eastern and central North America, from Newfoundland west to Alberta, southeast to Florida, and southwest to Texas, and widely naturalized elsew…","img":"images/539.jpg","thumb":"images/t/539.jpg","file":"Dettaglio - Onagrarieae Oenothera biennis Lam. Erbario Frizzi Perugia n. 1995.jpg","ar":0.471,"py":"yuejiancao yjc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"],"illus_img":"images/i/539.jpg","illus_thumb":"images/i/t/539.jpg","illus_file":"Oenothera biennis — Flora Batava — Volume v10.jpg","illus_ar":0.8,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":540,"seq":532,"zh":"柳叶菜","en":"Epilobium hirsutum","sci":"Epilobium hirsutum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":"LC","langs":39,"desc_zh":"柳叶菜（学名：Epilobium hirsutum）也称鸡脚参、水朝阳花，为柳叶菜科柳叶菜属下的一个种。","desc_en":"Epilobium hirsutum is a flowering plant belonging to the willowherb genus Epilobium in the family Onagraceae. It is commonly known as the great willowherb, great hairy willowherb or hairy willowherb.","img":"images/540.jpg","thumb":"images/t/540.jpg","file":"Dettaglio - Onagrarieae Epilobium hirsutum Lin. Erbario Frizzi Perugia n. 1179.jpg","ar":0.549,"py":"liuyecai lyc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/540.jpg","illus_thumb":"images/i/t/540.jpg","illus_file":"Epilobium hirsutum — Flora Batava — Volume v10.jpg","illus_ar":0.789,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":542,"seq":533,"zh":"石榴","en":"pomegranate","sci":"Punica granatum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":135,"desc_zh":"石榴（学名：Punica granatum），或称安石榴，千屈菜科灌木。","desc_en":"The pomegranate (Punica granatum) is a fruit-bearing, deciduous shrub in the family Lythraceae, subfamily Punicoideae, that grows to between 1.5–5 metres (5–16 ft) tall.","img":"images/542.jpg","thumb":"images/t/542.jpg","file":"Punica granatum 004.JPG","ar":1.333,"py":"shiliu sl","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","欧洲","非洲","北美洲","南美洲"],"illus_img":"images/i/542.jpg","illus_thumb":"images/i/t/542.jpg","illus_file":"Punica granatum - Köhler–s Medizinal-Pflanzen-116.jpg","illus_ar":0.805,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":543,"seq":534,"zh":"散沫花","en":"Lawsonia inermis","sci":"Lawsonia inermis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":72,"desc_zh":"散沫花（学名：Lawsonia inermis），又名指甲花、海蒳，是千屈菜科散沫花属下唯一一个种。原产于非洲、南亚及澳大拉西亚的热带与亚热带地区，在澳大拉西亚主要分布于北部的半干旱地带。 植株为大灌木或小乔木，株高约二至六公尺。叶对生，无毛，近无柄，叶缘全缘，叶形为椭圆形至宽披针形，叶长1.5-5.0公分，叶宽0.5-2公分，叶先端为渐尖形。","desc_en":"Lawsonia inermis, also known as hina, the henna tree, the mignonette tree, and the Egyptian privet, is a flowering plant and one of the only two species of the genus Lawsonia, with the other being Lawsonia odorata. It is used as a traditional medicinal plant.","img":"images/543.jpg","thumb":"images/t/543.jpg","file":"Lawsonia inermis (3709419835).jpg","ar":1.333,"py":"sanmohua smh","cr_by":"Dinesh Valke from Thane, India","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":null,"illus_img":"images/i/543.jpg","illus_thumb":"images/i/t/543.jpg","illus_file":"James Bruce - Lawsonia inermis L (Henna), finished drawing of a flowering leafy shoot - B1977.14.9124 - Yale Center for British Art.jpg","illus_ar":0.707,"illus_by":"James Bruce","illus_lic":"CC0","illus_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en"},{"id":544,"seq":535,"zh":"千屈菜","en":"Lythrum salicaria","sci":"Lythrum salicaria","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":50,"desc_zh":"千屈菜（学名：Lythrum salicaria），为千屈菜科千屈菜属下的一个植物种，又名「千禧花」。被列入「世界百大外来入侵种」之一。","desc_en":"Lythrum salicaria or purple-loosestrife is a flowering plant belonging to the family Lythraceae. It should not be confused with other plants sharing the name loosestrife that are members of the genus Lysimachia in the family Primulaceae.","img":"images/544.jpg","thumb":"images/t/544.jpg","file":"00 1804 Gewöhnlicher Blutweiderich - Lythrum.jpg","ar":0.667,"py":"qianqucai qqc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"],"illus_img":"images/i/544.jpg","illus_thumb":"images/i/t/544.jpg","illus_file":"Illustration Lythrum salicaria0.jpg","illus_ar":0.582,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":546,"seq":536,"zh":"榄仁树","en":"Terminalia catappa","sci":"Terminalia catappa","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Combretaceae","family_zh":"使君子科","iucn":"LC","langs":53,"desc_zh":"榄仁树（学名：Terminalia catappa ）别称大叶榄仁树、凉扇树、枇杷树、山枇杷树、法国枇杷、楠仁树、雨伞树、岛朴及古巴梯斯树等，为使君子科榄仁树属植物。","desc_en":"Terminalia catappa is a large tropical tree in the leadwood tree family, Combretaceae, native to Asia, Australia, the Pacific, Madagascar and Seychelles. Common names in English include country almond, Indian almond, Malabar almond, sea almond, tropical almond…","img":"images/546.jpg","thumb":"images/t/546.jpg","file":"01423jfCapalangan Sulipan Apalit Pampanga Peters Trees Shrinesfvf 20.JPG","ar":1.333,"py":"lanrenshu lrs","cr_by":"Judgefloro","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","非洲","大洋洲"],"illus_img":"images/i/546.jpg","illus_thumb":"images/i/t/546.jpg","illus_file":"Terminalia catappa illustration.jpg","illus_ar":0.822,"illus_by":"W.J. Hooker","illus_lic":"Public domain","illus_licurl":null},{"id":547,"seq":537,"zh":"使君子","en":"Combretum indicum","sci":"Combretum indicum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Combretaceae","family_zh":"使君子科","iucn":null,"langs":43,"desc_zh":"使君子（学名：Combretum indicum）为使君子科使君子属植物。本种为古今中外著名的驱虫药，于治疗小儿病患上至少已有1600多年历史。 其种加词“indicum”意为“印度的”。","desc_en":"Combretum indicum, commonly known as the Rangoon creeper or Burma creeper, is a vine with red flower clusters which is native to tropical Asia and grows in thickets, primary and secondary forest, and along river banks in the Indian subcontinent, Malaysia and t…","img":"images/547.jpg","thumb":"images/t/547.jpg","file":"Combretum indicum 01.JPG","ar":1.508,"py":"shijunzi sjz","cr_by":"Prenn","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲"]},{"id":1141,"seq":538,"zh":"诃子","en":"Terminalia chebula","sci":"Terminalia chebula","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Combretaceae","family_zh":"使君子科","iucn":"LC","langs":42,"desc_zh":"诃子（学名：Terminalia chebula）为使君子科诃子属的植物。","desc_en":"Terminalia chebula, commonly known as black- or chebulic myrobalan, is a species of Terminalia, native to South Asia from India, Pakistan and Nepal east to southwest China (Yunnan), and south to Sri Lanka, Malaysia, and Vietnam.","img":"images/1141.jpg","thumb":"images/t/1141.jpg","file":"Terminalia chebula - South China Botanical Garden 2013.11.02 11-07-25.jpg","ar":1.501,"py":"hezi hz","cr_by":"Zhangzhugang","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":1142,"seq":539,"zh":"双翼果科","en":"Alzatea verticillata","sci":"Alzatea verticillata","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Alzateaceae","family_zh":"双翼果科","iucn":"LC","langs":15,"desc_zh":null,"desc_en":"Alzatea verticillata is a small flowering tree, native to the Neotropics. It inhabits moist submontane forests from Costa Rica and Panama in Central America south to Peru and Bolivia in tropical South America.","img":"images/1142.jpg","thumb":"images/t/1142.jpg","file":"Alzatea verticillata imported from iNaturalist photo 173522367 on 27 January 2022.jpg","ar":0.75,"py":"shuangyiguoke sygk","cr_by":"(c) Ashwin Srinivasan, some rights reserved (CC BY)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":null},{"id":1143,"seq":540,"zh":"Olinia ventosa","en":"Olinia ventosa","sci":"Olinia ventosa","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Oliniaceae","family_zh":"方枝树科","iucn":"LC","langs":10,"desc_zh":null,"desc_en":"Olinia ventosa, commonly known as the hard-pear. is a large, evergreen forest tree indigenous to South Africa.","img":"images/1143.jpg","thumb":"images/t/1143.jpg","file":"Berries of Olinia ventosa IMG 12951304.jpg","ar":2.215,"py":"","cr_by":"JonRichfield","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["非洲"]},{"id":1144,"seq":541,"zh":"喙萼花","en":"Rhynchocalyx lawsonioides","sci":"Rhynchocalyx lawsonioides","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Penaeaceae","family_zh":"管萼科","iucn":"NT","langs":12,"desc_zh":null,"desc_en":"Rhynchocalyx lawsonioides, the false-waterberry, is a small flowering tree, the sole species of the genus Rhynchocalyx. It had also previously been regarded as the only species in the monogeneric family Rhynchocalycaceae but is now included in the expanded Pen…","img":"images/1144.gif","thumb":"images/t/1144.gif","file":"Rhynchocalyx lawsonioides00.gif","ar":0.574,"py":"huiehua heh","cr_by":"Matilda Smith (1854–1926)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["非洲"]},{"id":1145,"seq":542,"zh":"裸木","en":"Psiloxylon mauritianum","sci":"Psiloxylon mauritianum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Psiloxylaceae","family_zh":"裸木科","iucn":null,"langs":16,"desc_zh":"裸木（学名：Psiloxylon mauricianum）又名亮皮树，属桃金娘目桃金娘科，是裸木属的唯一物种。","desc_en":"Psiloxylon mauritianum (known locally as \"bois bigaignon\") is a species of flowering plant, the sole species of the genus Psiloxylon. It is endemic to the Mascarene Islands (Mauritius and Réunion) in the Indian Ocean.","img":"images/1145.jpg","thumb":"images/t/1145.jpg","file":"Bois Bigaignon - Psiloxylon mauritianum - Ferney Mauritius 2.jpg","ar":0.75,"py":"luomu lm","cr_by":"S Molteno","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"]},{"id":1146,"seq":543,"zh":"Qualea parviflora","en":"Qualea parviflora","sci":"Qualea parviflora","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Vochysiaceae","family_zh":"蜡烛树科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Qualea parviflora, known as pau-terra in Portuguese, is a deciduous tree indigenous to Bolivia, Brazil, and Paraguay. The tree favors dry climates like the tropical savanna of the cerrado.","img":"images/1146.jpg","thumb":"images/t/1146.jpg","file":"Flickr - BioDivLibrary - n81 w1150.jpg","ar":0.739,"py":"","cr_by":"Biodiversity Heritage Library","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["南美洲"]},{"id":548,"seq":544,"zh":"羽叶省沽油","en":"Staphylea pinnata","sci":"Staphylea pinnata","order_en":"Crossosomatales","order_zh":"燥木目","family_en":"Staphyleaceae","family_zh":"省沽油科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Staphylea pinnata, the European bladdernut, is a species of bladdernut native to Europe and naturalized in Britain.","img":"images/548.jpg","thumb":"images/t/548.jpg","file":"20130817Staphylea pinnata1.jpg","ar":0.75,"py":"yuyeshengguyou yysgy","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲"],"illus_img":"images/i/548.jpg","illus_thumb":"images/i/t/548.jpg","illus_file":"Staphylea pinnata Sturm19.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":1147,"seq":545,"zh":"Crossosoma bigelovii","en":"Crossosoma bigelovii","sci":"Crossosoma bigelovii","order_en":"Crossosomatales","order_zh":"缨子木目","family_en":"Crossosomataceae","family_zh":"燧体木科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Crossosoma bigelovii, known by the common name ragged rockflower, is one of only a few species in the flowering plant family Crossosomataceae. It is native to the Mojave, Chihuahuan, and Sonoran Deserts of North America.","img":"images/1147.jpg","thumb":"images/t/1147.jpg","file":"Ragged Rockflower - Flickr - treegrow (2).jpg","ar":1.333,"py":"","cr_by":"Katja Schulz from Washington, D. C., USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["北美洲"]},{"id":1148,"seq":546,"zh":"四棱果","en":"Geissoloma marginatum","sci":"Geissoloma marginatum","order_en":"Crossosomatales","order_zh":"缨子木目","family_en":"Geissolomataceae","family_zh":"四棱果科","iucn":null,"langs":14,"desc_zh":"四棱果科（学名：Geissoloma marginatum）又名缨缘科，是四棱果科（Geissolomataceae；又名缨缘科）及四棱果属（又名缨缘属）的唯一物种，只生长在南非好望角一带，是当地的特有种。","desc_en":"Geissoloma is a genus of flowering plants in the monotypic family Geissolomataceae, native to the Cape Province of South Africa. Geissoloma marginatum is the only species in the family. It is sometimes called guyalone in English.","img":"images/1148.jpg","thumb":"images/t/1148.jpg","file":"Geissoloma Rebelo 2.jpg","ar":0.664,"py":"silengguo slg","cr_by":"Tony Rebelo","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"]},{"id":1149,"seq":547,"zh":"中国旌节花","en":"Stachyurus chinensis","sci":"Stachyurus chinensis","order_en":"Crossosomatales","order_zh":"缨子木目","family_en":"Stachyuraceae","family_zh":"旌节花科","iucn":null,"langs":12,"desc_zh":"中国旌节花（学名：Stachyurus chinensis），又名短穗旌节花，为旌节花科旌节花属下的一种落叶灌木，高二至四米。叶互生，呈卵形，纸质。穗状花序腋生，在长出叶子之前开放，花黄色，果实圆球形。花期3-4月，果期5-7月。","desc_en":"Stachyurus chinensis (中国旌节花), Chinese stachyurus, is a species of flowering plant in the family Stachyuraceae, native to China and Taiwan. It is a spreading deciduous shrub growing to 2.5 m (8 ft) tall by 4 m (13 ft) wide.","img":"images/1149.jpg","thumb":"images/t/1149.jpg","file":"(MHNT) Stachyurus chinensis 'Joy Forever' Les Martels, Giroussens Tarn.jpg","ar":1.501,"py":"zhongguojingjiehua zgjjh","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲"]},{"id":549,"seq":548,"zh":"柠檬","en":"Citrus × limon","sci":"Citrus × limon","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":184,"desc_zh":"柠檬（学名：Citrus × limon）为芸香科柑橘属的一种，是原产于亚洲的常绿小乔木，其果实为黄色椭圆状。","desc_en":"The lemon (Citrus × limon) is a species of small evergreen tree in the Citrus genus of the flowering plant family Rutaceae. A true lemon is a hybrid of the citron and the bitter orange.","img":"images/549.jpg","thumb":"images/t/549.jpg","file":"Citrus x limon - Köhler–s Medizinal-Pflanzen-041.jpg","ar":0.805,"py":"ningmeng nm","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":550,"seq":549,"zh":"橘","en":"Citrus reticulata","sci":"Citrus reticulata","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":112,"desc_zh":"橘子（学名：Citrus reticulata），或写作桔子，芸香科柑橘属的一种水果，原产自中国南方、中南半岛、缅甸等地。在福州话称为橘，而闽南语称橘为柑仔，西南官话区的各方言中呼为“柑子”或“柑儿”，也有一些方言称之为“橘柑”。其种加词“reticuluma”意为“网纹的”。中华人民共和国国家标准称之为“柑橘”（citrus）。","desc_en":"A mandarin orange (Citrus reticulata), often simply called mandarin, is a small, rounded citrus tree fruit. Treated as a distinct species of orange, it is usually eaten plain or in fruit salads.","img":"images/550.jpg","thumb":"images/t/550.jpg","file":"Mandarin Oranges (Citrus Reticulata).jpg","ar":1.501,"py":"ju j","cr_by":"Joe Ravi","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":551,"seq":550,"zh":"柚子","en":"pomelo","sci":"Citrus maxima","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":"LC","langs":108,"desc_zh":"柚（学名：Citrus maxima）是芸香科柑橘属果树，其特征与柑橘相同。柚的果实称为柚子或文旦，又称香栾、朱栾、内紫、条、雷柚、碌柚、胡柑、臭橙、抛、苞、脬、枹、花柚子，广泛分布于中国河南、长江以南等地及东南亚，生长于海拔600－1400米的地区，多见于河谷、丘陵、山坡、民居附近，常用于栽培。该种栽培种数量众多，如玉环文旦、文旦柚、坪山柚、沙田柚、暹罗柚、蜜柚、胡柚、四季柚等。一般在中秋节前采收、作为中秋拜月、餽赠亲友的礼品。。","desc_en":"The pomelo ( POM-il-oh, PUM-; or pummelo, Citrus maxima), also known as a shaddock, is the largest citrus fruit. It is an ancestor of several cultivated citrus species, including the bitter orange and the grapefruit.","img":"images/551.jpg","thumb":"images/t/551.jpg","file":"Pomelo fruit.jpg","ar":1.333,"py":"youzi yz","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":552,"seq":551,"zh":"葡萄柚","en":"Citrus paradisi","sci":"Citrus paradisi","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":101,"desc_zh":"葡萄柚（学名：Citrus × paradisi，港澳又称西柚），是芸香科柑橘属的一种亚热带植物。为常见的水果之一。起源于17世纪的巴巴多斯，为当地从亚洲引入种植橙（Citrus sinensis）及柚子（Citrus maxima）后而出现的杂交种，当地人发现时，一度戏称此果为“禁果”。","desc_en":"The grapefruit (Citrus × paradisi) is a subtropical citrus tree known for its relatively large, sour to semi-sweet, somewhat bitter fruit. The flesh of the fruit is segmented and varies in color from pale yellow to dark red.","img":"images/552.jpg","thumb":"images/t/552.jpg","file":"Citrus x paradisi (Macfad.) Pompelino Grapefruit 002.jpg","ar":1.506,"py":"putaoyou pty","cr_by":"Amada44","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":null},{"id":553,"seq":552,"zh":"橙","en":"Citrus sinensis","sci":"Citrus ×sinensis","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":97,"desc_zh":"柳橙（学名：Citrus sinensis）又名甜橙、黄果、金环，是芸香科柑橘属的物种。其种加词“sinensis”意为“中华的”。 甜橙是柑果，也是人类种植了很久的混合品种──本来是柚子（Citrus maxima）与橘子（Citrus reticulata）的杂交品种，起源于中国；考古证据显示，早在公元前2500年，中国已开始种植橙子。1493年哥伦布第二次造访新大陆时，橙子登上了美洲大陆。","desc_en":"Citrus × sinensis (sometimes written Citrus sinensis), the sweet orange, is a broadleaf evergreen hybrid between pomelo (Citrus maxima) and mandarin (Citrus reticulata).","img":"images/553.jpg","thumb":"images/t/553.jpg","file":"OrangeBloss wb.jpg","ar":1.136,"py":"cheng c","cr_by":"Ellen Levy Finch ( Elf )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":554,"seq":553,"zh":"苦橙","en":"Citrus × aurantium","sci":"Citrus × aurantium","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":84,"desc_zh":"酸橙（学名：Citrus × aurantium）又名苦橙、南庄橙、来母、金柚葡萄柚、胡柚、常山胡柚、塞维亚柑橘，是柚（Citrus maxima）与橘（Citrus reticulata）的杂交种，属芸香科柑橘属植物。 栽培品种玳玳花（Citrus × aurantium Amara）开白花，香气浓郁。","desc_en":"The bitter orange, sour orange, Seville orange, bigarade orange, or marmalade orange is the hybrid citrus tree species Citrus × aurantium, and its fruit. It is native to Southeast Asia and has been spread by humans to many parts of the world.","img":"images/554.jpg","thumb":"images/t/554.jpg","file":"Turunç - Citrus aurantium 02.JPG","ar":0.688,"py":"kucheng kc","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/554.jpg","illus_thumb":"images/i/t/554.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 11 Citrus × aurantium (6022327482).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":555,"seq":554,"zh":"枸橼","en":"Citrus medica","sci":"Citrus medica","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":"LC","langs":79,"desc_zh":"枸橼（学名：Citrus medica ，拼音：jǔ yuán，注音：ㄐㄩˇ ㄩㄢˊ），又称香橼、香水柠檬、枸橼子、香泡，是芸香科柑橘属的一种植物；和青柠的外观上相似。枸橼是犹太人庆祝住棚节必备的植物之一。 枸橼和苦橙杂交的后代就是现今各种的柠檬。","desc_en":"The citron (Citrus medica) is a large fragrant citrus fruit with a thick, coarse rind. It resembles a lemon, but is larger. It is one of the original citrus fruits from which all other citrus types developed through natural hybrid speciation or artificial hybr…","img":"images/555.jpg","thumb":"images/t/555.jpg","file":"Chinesische Zedrat Zitrone.jpg","ar":1.405,"py":"gouyuan gy","cr_by":"Johann Werfring","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":559,"seq":555,"zh":"荔枝","en":"Litchi chinensis","sci":"Litchi chinensis","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":null,"langs":105,"desc_zh":"荔枝（学名：Litchi chinensis）又名荔支、离枝、丹荔、丽枝、贵妃香、火山荔、勒荔、荔果，是中国南部原产的一种果树，广泛栽培于东南亚至新几内亚等亚热带地区，是无患子目无患子科荔枝属的唯一物种。其果树与果实状似同科不同属的龙眼。 荔枝是中国华南的重要水果农作物，每年产量逾百万吨，因其果实对保鲜的要求相当高，一般采用低温运输。 生荔枝和荔枝核含有毒物亚甲基环丙基乙酸，食用过量会导致低血糖和急性癫痫发作。","desc_en":"Lychees ( LIE-chee, US also LEE-chee) are the fruit of the tree Litchi chinensis, the sole member of the genus Litchi, part of the soapberry family, Sapindaceae.","img":"images/559.jpg","thumb":"images/t/559.jpg","file":"Lychee.jpg","ar":1.508,"py":"lizhi lz","cr_by":"Barry Fitzgerald, USDA","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":560,"seq":556,"zh":"红毛丹","en":"Nephelium lappaceum","sci":"Nephelium lappaceum","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":88,"desc_zh":"红毛丹（学名：Nephelium lappaceum，马来语：Rambutan），为东南亚原产之无患子科韶子属大型热带乔木，马来文称之“rambutan”，意为“毛茸茸之物”。成熟的红毛丹果通常是红色的，也有黄色果子的变种。有的红毛丹的核的大小近似于芝麻。","desc_en":"Rambutan (; Nephelium lappaceum) is a medium-sized tropical tree in the family Sapindaceae. The name also refers to the edible fruit produced by this tree. The rambutan is native to Southeast Asia.","img":"images/560.jpg","thumb":"images/t/560.jpg","file":"Rambutan white background alt.jpg","ar":1.628,"py":"hongmaodan hmd","cr_by":"Muhammad Mahdi Karim","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"乔木","origin":["亚洲"]},{"id":561,"seq":557,"zh":"欧亚槭","en":"Acer pseudoplatanus","sci":"Acer pseudoplatanus","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":75,"desc_zh":"岩槭（学名：Acer pseudoplatanus），也称为岩槭、白槭、假挪威槭、欧亚槭，是枫属的一种被子植物、落叶植物，属于阔叶树，抗风能力好。它原产于中欧和西亚，从法国开始东至乌克兰、土耳其北和高加索地区，南至意大利和西班牙北部的山丘地带。","desc_en":"Acer pseudoplatanus, known as the sycamore in the British Isles and as the sycamore maple in the United States, is a species of maple native to Central Europe and Western Asia. It is a large deciduous, broad-leaved tree, tolerant of wind and coastal exposure.","img":"images/561.jpg","thumb":"images/t/561.jpg","file":"ID 1211 Bergahorn 0011.jpg","ar":0.667,"py":"ouyaqi oyq","cr_by":"Christian Pirkl","cr_lic":"CC BY-SA 3.0 at","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/at/deed.en","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/561.jpg","illus_thumb":"images/i/t/561.jpg","illus_file":"Acer pseudoplatanus tree illustration.jpg","illus_ar":0.704,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":562,"seq":558,"zh":"欧洲七叶树","en":"Aesculus hippocastanum","sci":"Aesculus hippocastanum","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"VU","langs":73,"desc_zh":"欧洲七叶树（学名：Aesculus hippocastanum），果实又称马栗（Horse Chestnut），是无患子科七叶树属的植物。分布于希腊、马其顿、保加利亚和阿尔巴尼亚，作为行道树广泛栽植于世界各地。","desc_en":"Aesculus hippocastanum, the horse chestnut, is a species of flowering plant in the maple, soapberry and lychee family Sapindaceae. It is a large, deciduous, synoecious (hermaphroditic-flowered) tree.","img":"images/562.jpg","thumb":"images/t/562.jpg","file":"ND 678.N.59 Hofers Kastanien in Wettringen.jpg","ar":1.275,"py":"ouzhouqiyeshu ozqys","cr_by":"Stephan van Helden","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["欧洲"],"illus_img":"images/i/562.png","illus_thumb":"images/i/t/562.png","illus_file":"Aesculus hippocastanum drawing.png","illus_ar":0.778,"illus_by":"USDA-NRCS PLANTS Database / Britton, N.L., and A. Brown. 1913. Illustrated flora of the northern states and Canada. Vol.","illus_lic":"Public domain","illus_licurl":null},{"id":563,"seq":559,"zh":"龙眼","en":"Dimocarpus longan","sci":"Dimocarpus longan","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"DD","langs":68,"desc_zh":"龙眼（学名：Dimocarpus longan），又称桂圆、福圆、荔枝奴、亚荔枝、燕卵、牛眼，为水果，寿命最长可达400多年。","desc_en":"Longan (; Dimocarpus longan), also called lungan or dragon's eye, is a tropical tree species that produces edible fruit. It is one of the better-known tropical members of the soapberry family Sapindaceae, to which the lychee and rambutan also belong.","img":"images/563.jpg","thumb":"images/t/563.jpg","file":"Dimocarpus longan fruits.jpg","ar":0.656,"py":"longyan ly","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"],"illus_img":"images/i/563.jpg","illus_thumb":"images/i/t/563.jpg","illus_file":"Dimocarpus longan Curtis's Bot Mag-1.jpg","illus_ar":0.846,"illus_by":"W.H. Fitch, Curtis's Botanical Magazine, vol 70, 1844","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":564,"seq":560,"zh":"挪威枫","en":"Acer platanoides","sci":"Acer platanoides","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":65,"desc_zh":"挪威枫，枫属落叶乔木，原产于欧洲中东部，树龄最多约为250年。","desc_en":"Acer platanoides, commonly known as the Norway maple, is a species of maple native to eastern and central Europe and western Asia, from Spain east to Russia, north to southern Scandinavia and southeast to northern Iran.","img":"images/564.jpg","thumb":"images/t/564.jpg","file":"2020 year. Herbarium. Acer platanoides. img-012.jpg","ar":1.108,"py":"nuoweifeng nwf","cr_by":"Dmitry Makeev","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/564.jpg","illus_thumb":"images/i/t/564.jpg","illus_file":"Illustration Acer platanoides1 clean.jpg","illus_ar":0.655,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":568,"seq":561,"zh":"腰果","en":"Cashew","sci":"Anacardium occidentale","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"LC","langs":115,"desc_zh":"腰果（学名：Anacardium occidentale）是一种肾形核果，原产于南美洲，属无患子目漆树科腰果属。又名树花生、槚如树、鸡腰果、介寿果、腰子豆等，带有附果。","desc_en":"Cashew is the common name of a tropical evergreen tree Anacardium occidentale, in the family Anacardiaceae. It is the source of the cashew nut and the cashew apple. The tree can grow as tall as 14 meters (46 feet). Cashews are native to tropical South America.","img":"images/568.jpg","thumb":"images/t/568.jpg","file":"Anacardium occidentale - Köhler–s Medizinal-Pflanzen-010.jpg","ar":0.722,"py":"yaoguo yg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"],"illus_img":"images/i/568.jpg","illus_thumb":"images/i/t/568.jpg","illus_file":"Anacardium occidentale - Köhler–s Medizinal-Pflanzen-010.jpg","illus_ar":0.722,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":569,"seq":562,"zh":"芒果树","en":"Mangifera indica","sci":"Mangifera indica","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"DD","langs":89,"desc_zh":"芒果树（学名：Mangifera indica）也作檬果树、杧果树，是芒果属的一种植物，果实为芒果，原产南亚东北部和中南半岛，在梵语中叫作āmra，音译为“庵罗”，性喜高温、干燥的天气，营养生长期（根、茎、叶）最适合温度为24－30℃，气温降到18℃以下时生长缓慢，10℃以下停止生长，生殖生长期（花、果）需较高温度，以排水良好且含腐植质的砂质土壤最适宜，pH值5.5－7.5为佳。","desc_en":"Mangifera indica, commonly known as the mango after its fruit, is an evergreen species of flowering plant in the family Anacardiaceae. It is a large fruit tree, capable of growing to a height and width of 30 m (100 ft).","img":"images/569.jpg","thumb":"images/t/569.jpg","file":"The Botanical Magazine. Mango.jpg","ar":0.836,"py":"mangguoshu mgs","cr_by":"Walter Hood Fitch (1817-1892) del. et lith. Description by John Smith (1798 - 1888)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":570,"seq":563,"zh":"阿月浑子","en":"Pistacia vera","sci":"Pistacia vera","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"NT","langs":87,"desc_zh":"阿月浑子（学名：Pistacia vera，英语：pistachio），又称胡榛子，是漆树科黄连木属的植物，其果实常称开心果，是一种常见干果。开心果营养丰富，味道可口，是很受欢迎的零食。最早的汉语商品名是开口笑，形容其硬壳裂开如笑容之状，但迅速被更口语化的开心果取代。富含维生素A、维生素E。","desc_en":"The pistachio (, UK also ; Pistacia vera) is a small to medium-sized tree of the cashew family. The tree produces seeds that are widely consumed as food. Pistachios can be used as an ingredient in desserts, chocolate, candy, ice cream, and as a paste or butter…","img":"images/570.jpg","thumb":"images/t/570.jpg","file":"Pistacia vera Kerman.jpg","ar":1.361,"py":"ayuehunzi ayhz","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":571,"seq":564,"zh":"乳香黄连木","en":"Pistacia lentiscus","sci":"Pistacia lentiscus","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"LC","langs":59,"desc_zh":"乳香黄连木（学名：Pistacia lentiscus）是漆树科黄连木属常绿灌木，也叫洋乳香树、黏胶乳香树，原产于地中海区域。其树脂洋乳香是一种名贵香料。","desc_en":"Pistacia lentiscus (also lentisk or mastic) is a dioecious evergreen shrub or small tree of the genus Pistacia native to the Mediterranean Basin. It grows up to 4 m (13 ft) tall and is cultivated for its aromatic resin, mainly on the Greek island of Chios, aro…","img":"images/571.jpg","thumb":"images/t/571.jpg","file":"Dettaglio - Anacardiaceae Pistacia lentiscus Lin. Erbario Frizzi Perugia n. 3752.jpg","ar":0.75,"py":"ruxianghuanglianmu rxhlm","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["欧洲"],"illus_img":"images/i/571.jpg","illus_thumb":"images/i/t/571.jpg","illus_file":"Pistacia lentiscus - Köhler–s Medizinal-Pflanzen-110.jpg","illus_ar":0.774,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":572,"seq":565,"zh":"象李","en":"Sclerocarya birrea","sci":"Sclerocarya birrea","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"LC","langs":49,"desc_zh":"马鲁拉（学名：Sclerocarya birrea），又名非洲漆树，是漆树科象李属的物种。本物种以常绿乔木仔或灌木的形式存在。","desc_en":"Sclerocarya birrea (Ancient Greek: σκληρός ⟨sklērós⟩, meaning \"hard\", and κάρυον ⟨káryon⟩, \"nut\", in reference to the stone inside the fleshy fruit), commonly known as the marula, is a medium-sized deciduous fruit-bearing tree, indigenous to the miombo woodlan…","img":"images/572.jpg","thumb":"images/t/572.jpg","file":"Marula02.jpg","ar":1.506,"py":"xiangli xl","cr_by":"Rotational","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["非洲"]},{"id":574,"seq":566,"zh":"印度苦楝树","en":"Azadirachta indica","sci":"Azadirachta indica","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":"LC","langs":91,"desc_zh":"印度苦楝树（学名：Azadirachta indica），又称印度楝树、印度蒜楝、印度假苦楝、宁树（英语：Neem）、印度紫丁香（Indian lilac），楝科蒜楝属植物，分布于印度、缅甸、孟加拉、斯里兰卡、马来西亚与巴基斯坦等亚洲亚热带、热带气候地区。其种加词“indica”意为“印度的”。 它生长快速，可以达到15-20公尺高，少数甚至可以达到35-40公尺高。它是常青树，但在严重干旱时，叶子会大部份或全部掉落。","desc_en":"Azadirachta indica, commonly known as neem, margosa, nimtree or Indian lilac, is a tree in the mahogany family Meliaceae. It is one of the two species in the genus Azadirachta.","img":"images/574.jpg","thumb":"images/t/574.jpg","file":"Neem (Azadirachta indica) in Hyderabad W IMG 6976.jpg","ar":1.137,"py":"yindukulianshu ydkls","cr_by":"J.M.Garg","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲"]},{"id":575,"seq":567,"zh":"苦楝","en":"Melia azedarach","sci":"Melia azedarach","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":"LC","langs":61,"desc_zh":"苦楝（学名：Melia azedarach，英文名称：Beadtree、 Bead Tree、Cape Lilac、Chinaberry、China-berry、China Berry、Chinaberry-tree、China-berry Tree、Melia、Persian Lilac、Pride-of-India, Melia、white cedar,），别称苦苓、楝、楝树、楝子 、森树、翠树、楝枣树、紫花树、紫花木、花心树、双白…","desc_en":"Melia azedarach, commonly known as the chinaberry tree, pride of India, bead-tree, Cape lilac, syringa berrytree, Persian lilac, Indian lilac, or white cedar, is a species of deciduous tree in the mahogany family, Meliaceae, that is native to Indomalaya and Au…","img":"images/575.jpg","thumb":"images/t/575.jpg","file":"Chinaberry1216.JPG","ar":0.75,"py":"kulian kl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":576,"seq":568,"zh":"兰撒","en":"Lansium domesticum","sci":"Lansium domesticum","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":null,"langs":51,"desc_zh":"兰撒（学名：Lansium domesticum；马来语：langsat）又译作冷刹、芦菇或杜古（马来语：duku）、龙贡或龙宫果，为楝科㭴木属的一种。","desc_en":"Lansium domesticum, commonly known as langsat () or lanzones, ,--) is a species of tree in the family Meliaceae with commercially cultivated edible fruits. The species is native to Southeast Asia, from peninsular Thailand and Malaysia to Indonesia and the Phil…","img":"images/576.jpg","thumb":"images/t/576.jpg","file":"Lanzones.jpg","ar":1.333,"py":"lansa ls","cr_by":"Mike Gonzalez ( TheCoffee )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":578,"seq":569,"zh":"阿拉伯乳香树","en":"Boswellia sacra","sci":"Boswellia sacra","order_en":"Sapindales","order_zh":"无患子目","family_en":"Burseraceae","family_zh":"橄榄科","iucn":"NT","langs":33,"desc_zh":"乳香树（学名：Boswellia sacra，学名的意思是神圣乳香）为乳香属下的一种植物，其树脂凝固后便成乳香。 一些学者认为Boswellia sacra只代表阿拉伯乳香树，而索马里的种群属于索马里乳香树（学名：Boswellia carteri），但这种区分缺少植物学依据。","desc_en":"Boswellia sacra, also known as Boswellia carteri and others, and commonly called the frankincense tree or the olibanum tree, is a tree in the genus Boswellia, in the Burseraceae family, from which frankincense, a resinous dried sap, is harvested.","img":"images/578.jpg","thumb":"images/t/578.jpg","file":"Boswellia sacra.jpg","ar":1.333,"py":"alaboruxiangshu albrxs","cr_by":"Scott Zona from USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["亚洲","非洲"],"illus_img":"images/i/578.jpg","illus_thumb":"images/i/t/578.jpg","illus_file":"Boswellia sacra - Köhler–s Medizinal-Pflanzen-022.jpg","illus_ar":0.781,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":579,"seq":570,"zh":"没药树","en":"Commiphora myrrha","sci":"Commiphora myrrha","order_en":"Sapindales","order_zh":"无患子目","family_en":"Burseraceae","family_zh":"橄榄科","iucn":null,"langs":32,"desc_zh":"没药树（学名：Commiphora myrrha）又名哈地丁树、地丁树，橄榄科常绿乔木，原产于索马利亚和衣索比亚。","desc_en":"Commiphora myrrha, called myrrh, Somali myrrh, herabol myrrh, common myrrh, is a tree in the family Burseraceae. It is one of the primary trees used in the production of myrrh, a resin made from dried tree sap.","img":"images/579.jpg","thumb":"images/t/579.jpg","file":"Commiphora myrrha - Köhler–s Medizinal-Pflanzen-019.jpg","ar":0.743,"py":"moyaoshu mys","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","非洲"],"illus_img":"images/i/579.jpg","illus_thumb":"images/i/t/579.jpg","illus_file":"Commiphora myrrha - Köhler–s Medizinal-Pflanzen-019.jpg","illus_ar":0.743,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1150,"seq":571,"zh":"齿叶乳香树","en":"Boswellia serrata","sci":"Boswellia serrata","order_en":"Sapindales","order_zh":"无患子目","family_en":"Burseraceae","family_zh":"橄榄科","iucn":null,"langs":28,"desc_zh":"齿叶乳香树（学名：Boswellia serrata），也叫印度乳香，为乳香属下的一种植物，分布于印度及巴基斯坦旁遮普地区。齿叶乳香树是印度原产的两种乳香树属植物之一（另一种是卵叶乳香树），它所产出的乳香是阿育吠陀中使用的一种传统药物，可用来治疗关节炎。","desc_en":"Boswellia serrata is a plant that produces Indian frankincense. The plant is native to much of India and the Punjab region that extends into Pakistan.","img":"images/1150.jpg","thumb":"images/t/1150.jpg","file":"Boswellia serrata (Salai) in Kinnarsani WS, AP W IMG 5844.jpg","ar":1.111,"py":"chiyeruxiangshu cyrxs","cr_by":"J.M.Garg","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":580,"seq":572,"zh":"臭椿","en":"Ailanthus altissima","sci":"Ailanthus altissima","order_en":"Sapindales","order_zh":"无患子目","family_en":"Simaroubaceae","family_zh":"苦木科","iucn":null,"langs":62,"desc_zh":"臭椿（学名：Ailanthus altissima ）原名樗（拼音：chū，注音：ㄕㄨ），又名大眼桐、姑姑翅、臭桐，属于苦木科，是一种落叶树。它原产于东亚北部与中部。与臭椿属其他成员不同，它生长在气候温和的地带而不是热带地区。这种树木生长迅速，适应环境能力强，可以在25年内达到15米（50英尺）的高度。然而此物种寿命较短，极少生存超过50年。 在中国，臭椿历史悠久且分布广泛。尔雅、说文解字、急救篇等古老字书均有记载。","desc_en":"Ailanthus altissima ( ay-LAN-thəss al-TIH-sim-ə), commonly known as tree of heaven or ailanthus tree, is a deciduous tree in the quassia family. It is native to northeast, central China, and Taiwan.","img":"images/580.jpg","thumb":"images/t/580.jpg","file":"Götterbaum (Ailanthus altissima).jpg","ar":0.74,"py":"chouchun cc","cr_by":"Darkone ( talk · contribs )","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/580.jpg","illus_thumb":"images/i/t/580.jpg","illus_file":"35 Ailanthus altissima par Pierre-Joseph Redouté.jpeg","illus_ar":0.692,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1151,"seq":573,"zh":"骆驼蓬","en":"Peganum harmala","sci":"Peganum harmala","order_en":"Sapindales","order_zh":"无患子目","family_en":"Nitrariaceae","family_zh":"白刺科","iucn":null,"langs":45,"desc_zh":"骆驼蓬（学名：Peganum harmala），又名野芸香，臭古朵。是骆驼蓬属下的一个有着木本地下茎的多年生草本植物物种。骆驼蓬属旧属蒺藜科，今属白刺科。其种子可入药，是为骆驼蓬子，有致幻效果，是台湾的相思汤的两种成份之一。","desc_en":"Peganum harmala, commonly called wild rue, Syrian rue, African rue, esfand or espand, or harmel (among other similar pronunciations and spellings), is a perennial, herbaceous plant, with a woody underground rootstock, of the family Nitrariaceae, usually growin…","img":"images/1151.jpg","thumb":"images/t/1151.jpg","file":"Peganum harmala Baikonur 04.jpg","ar":1.333,"py":"luotuopeng ltp","cr_by":"Yuriy75","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲","北美洲"]},{"id":581,"seq":574,"zh":"可可树","en":"cacao","sci":"Theobroma cacao","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":116,"desc_zh":"可可（学名：Theobroma cacao）是热带常绿植物，原产于南美，现在广泛在非洲、东南亚和拉丁美洲种植。用种子、枝条或树苗栽培。可可树最高可达15米，叶片宽阔，花直接簇生于枝干上，白色，花萼为粉色，直径约1厘米。果实成熟期为4到6个月，每年成熟两次，主要收获期为10月到12月。果实为荚状，长15至30厘米，外为绿色，内有20至100粒种子。收获后需发酵数日，使其内部变为红棕色，并产生浓郁的香味，然后剔开果肉，取出可可豆。","desc_en":"Theobroma cacao (cacao tree or cocoa tree) is a small (6–12 m (20–39 ft) tall) evergreen tree in the Malvaceae family. Its seeds—cocoa beans when dried and fermented—are used to make chocolate liquor, cocoa powder, cocoa butter and chocolate.","img":"images/581.jpg","thumb":"images/t/581.jpg","file":"Theobroma cacao - Köhler–s Medizinal-Pflanzen-136.jpg","ar":0.687,"py":"kekeshu kks","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null,"illus_img":"images/i/581.jpg","illus_thumb":"images/i/t/581.jpg","illus_file":"Theobroma cacao - Köhler–s Medizinal-Pflanzen-136.jpg","illus_ar":0.687,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":582,"seq":575,"zh":"秋葵","en":"Abelmoschus esculentus","sci":"Abelmoschus esculentus","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":114,"desc_zh":"秋葵（学名：Abelmoschus esculentus），一种锦葵科、秋葵属的一年或多年生草本植物，是人类通过选择性育种改良而成的栽培植物，又称黄秋葵、咖啡黄葵、糊麻、补肾草、羊角椒、毛茄，其果实常被称作羊角豆或潺茄。秋葵的确切起源尚不清楚，通常认为原产于非洲西部至埃塞俄比亚一带。现已广泛种植于全球的热带、亚热带和暖温带地区，性喜温暖，耐高温和干旱。","desc_en":"Okra (US: , UK: ), Abelmoschus esculentus, known in some English-speaking countries as lady's fingers, is a flowering plant in the mallow family native to East Africa.","img":"images/582.jpg","thumb":"images/t/582.jpg","file":"Abelmoschus esculentus (1).jpg","ar":0.75,"py":"qiukui qk","cr_by":"Kristine Paulus from New York, United States","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["非洲"]},{"id":583,"seq":576,"zh":"猴面包树","en":"Adansonia digitata","sci":"Adansonia digitata","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":82,"desc_zh":"猴面包树（学名：Adansonia digitata），又名猢狲树、非洲猴面包树、酸瓠树、猴树、旅人树、死老鼠树，是一种锦葵科猴面包树属的大型落叶乔木，原产于热带非洲以及阿拉伯半岛，现今中国大陆南部以及台湾皆有人工引种栽培。 猴面包树会开出巨大的白花。华丽的花朵下垂，带有很多雄蕊，富含腐肉的气味，研究人员认为狐蝠科是它们主要授粉者。果实充满果肉，干燥变硬后会碎成块状，看起来就像是干了的面包块。","desc_en":"Adansonia digitata, the African baobab, is the most widespread tree species of the genus Adansonia, the baobabs, and is native to the African continent and the southern Arabian Peninsula (Yemen, Oman).","img":"images/583.jpg","thumb":"images/t/583.jpg","file":"Baobab and elephant, Tanzania.jpg","ar":1.501,"py":"houmianbaoshu hmbs","cr_by":"Ferdinand Reus from Arnhem, Holland","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["亚洲","非洲"]},{"id":584,"seq":577,"zh":"朱槿","en":"Hibiscus × rosa-sinensis","sci":"Hibiscus × rosa-sinensis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":74,"desc_zh":"朱槿（学名：Hibiscus rosa-sinensis）是一种属于锦葵科木槿属的常绿灌木或小乔木，又称赤槿、日及、佛桑、烈红花、红扶桑、红木槿、桑槿、火红花、照殿红、宋槿、二红花、花上花、土红花、假牡丹、灯篮仔花，因原产于中国南部，欧洲各语系依循其拉丁学名皆称朱槿为中国蔷薇（英文：Rose of China、China rose）。由于早期花色大多为红色，中国岭南一带将之称为大红花。 其种加词“sinensis”意为“中华的”。","desc_en":"Hibiscus × rosa-sinensis (known colloquially as Chinese hibiscus, China rose, Hawaiian hibiscus, rose mallow and shoeblack plant) is a cultigen of tropical hibiscus, a flowering plant in the Hibiscus genus and Hibisceae tribe of the family Malvaceae.","img":"images/584.jpg","thumb":"images/t/584.jpg","file":"Hibiscus Brilliant.jpg","ar":1.366,"py":"zhujin zj","cr_by":"Andy / Andrew Fogg from near Cambridge, UK","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["大洋洲"]},{"id":585,"seq":578,"zh":"吉贝","en":"Ceiba pentandra","sci":"Ceiba pentandra","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":"LC","langs":73,"desc_zh":"美洲木棉（学名：Ceiba pentandra），又名吉贝、吉贝木棉、爪哇木棉，为锦葵科木棉亚科美洲木棉属的植物。属名源于泰诺语俗名seiba，种加词意思是五枚雄蕊的。","desc_en":"Ceiba pentandra is a tropical tree of the order Malvales and the family Malvaceae (previously placed in the family Bombacaceae), native to Central America, the Caribbean, and the northern half of South America; some authors also consider it native in western a…","img":"images/585.jpg","thumb":"images/t/585.jpg","file":"Ceiba pentandra in Cuba.jpg","ar":0.561,"py":"jibei jb","cr_by":"Burkhard Mücke","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","非洲","北美洲","南美洲"]},{"id":586,"seq":579,"zh":"药葵","en":"Althaea officinalis","sci":"Althaea officinalis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":69,"desc_zh":"药蜀葵（学名：Althaea officinalis）为锦葵科蜀葵属下的一个种。是欧洲、西亚和北非原生的多年生植物，亦产于中国大陆新疆塔城县依灭勒河沿岸。","desc_en":"Althaea officinalis, the marsh mallow or marshmallow, is a species of flowering plant indigenous to Europe, Western Asia and North Africa, which is used in herbalism and as an ornamental plant.","img":"images/586.jpg","thumb":"images/t/586.jpg","file":"Althea officinalis flor.jpg","ar":1.333,"py":"yaokui yk","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/586.jpg","illus_thumb":"images/i/t/586.jpg","illus_file":"Althaea officinalis (Köhler).jpg","illus_ar":0.664,"illus_by":"Hermann Adolf Köhler (1834 - 1879)","illus_lic":"Public domain","illus_licurl":null},{"id":587,"seq":580,"zh":"小叶椴","en":"Tilia cordata","sci":"Tilia cordata","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":"LC","langs":62,"desc_zh":"小叶椴（Tilia cordata）分布在中国北方等地，也是一种在欧洲非常普遍的树。 种名cordata意为心形的。 小叶椴树高可达20到35米，干粗可达直径1到1.5米，树叶圆状或三角-椭圆状，4到8厘米长和宽，一般无毛（阔叶椴相反一般叶上有毛），只有在叶脉中轴上有少许棕色的毛。初夏开花，花小，黄绿色，有很浓的气味，易招引蜂。 小叶椴和阔叶椴的杂交品种是西洋椴。","desc_en":"Tilia cordata, the small-leaved lime or small-leaved linden, is a species of tree in the family Malvaceae, native to much of Europe. Its other common names include little-leaf or littleleaf linden, or traditionally in South East England, pry or pry tree.","img":"images/587.jpg","thumb":"images/t/587.jpg","file":"Tilia cordata, Lipa2009.jpg","ar":0.666,"py":"xiaoyeduan xyd","cr_by":"ImreKiss","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["欧洲"],"illus_img":"images/i/587.jpg","illus_thumb":"images/i/t/587.jpg","illus_file":"Tilia cordata - Köhler–s Medizinal-Pflanzen-139.jpg","illus_ar":0.801,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":588,"seq":581,"zh":"欧锦葵","en":"Malva sylvestris","sci":"Malva sylvestris","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":58,"desc_zh":"欧锦葵（学名：Malva sylvestris）是一种锦葵科锦葵属的多年生草本植物，原产于欧洲、北非和西亚等地区。其植株高度可达 60 至 100 公分，叶片呈现掌状，而花朵多为带有深色条纹的紫色或粉红色，开花时间通常在每年 4 月至 10 月。除了观赏用途外，欧锦葵的花朵与叶片也常作为天然草药，具有润肺止咳、清热解毒的功效 。","desc_en":"Malva sylvestris is a species of the mallow genus Malva, of which it the type species. Known as common mallow to English-speaking Europeans, it acquired the common names of cheeses, high mallow and tall mallow (mauve des bois by the French) as it migrated from…","img":"images/588.jpg","thumb":"images/t/588.jpg","file":"Dettaglio - Malvaceae Malva sylvestris Lin. Erbario Frizzi Perugia n. 299.jpg","ar":0.466,"py":"oujinkui ojk","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/588.jpg","illus_thumb":"images/i/t/588.jpg","illus_file":"Malva sylvestris - Köhler–s Medizinal-Pflanzen-222.jpg","illus_ar":0.8,"illus_by":"Köhler, F. E. (Franz Eugen)","illus_lic":"Public domain","illus_licurl":null},{"id":594,"seq":582,"zh":"欧洲瑞香","en":"Daphne mezereum","sci":"Daphne mezereum","order_en":"Malvales","order_zh":"锦葵目","family_en":"Thymelaeaceae","family_zh":"瑞香科","iucn":null,"langs":60,"desc_zh":"二月瑞香（学名：Daphne mezereum）是瑞香科瑞香属的一种植物，原产于欧洲与西亚大部分地区，北至斯堪的纳维亚北部与俄罗斯。在欧洲南部，二月瑞香主要生长于中高海拔与亚高山带。而在欧洲北部，则可生长于海平面附近。石灰岩地区较常见。","desc_en":"Daphne mezereum, the mezereon, is a species of Daphne in the flowering plant family Thymelaeaceae, native to most of Europe and Western Asia, north to northern Scandinavia and Russia.","img":"images/594.jpg","thumb":"images/t/594.jpg","file":"Daphne mezereum flowers - Keila.jpg","ar":0.7,"py":"ouzhouruixiang ozrx","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/594.jpg","illus_thumb":"images/i/t/594.jpg","illus_file":"Daphne mezereum - Köhler–s Medizinal-Pflanzen-050.jpg","illus_ar":0.741,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":595,"seq":583,"zh":"洋瑞香","en":"Daphne laureola","sci":"Daphne laureola","order_en":"Malvales","order_zh":"锦葵目","family_en":"Thymelaeaceae","family_zh":"瑞香科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Daphne laureola, commonly called spurge-laurel, is a woodland shrub in the flowering plant family Thymelaeaceae. Its native range covers much of western and southern Europe and extends to Algeria, Morocco and the Azores.","img":"images/595.jpg","thumb":"images/t/595.jpg","file":"Daphne laureola.jpg","ar":0.75,"py":"yangruixiang yrx","cr_by":"User:Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["欧洲"],"illus_img":"images/i/595.jpg","illus_thumb":"images/i/t/595.jpg","illus_file":"09 Daphne laureola par Pierre-Joseph Redouté.jpg","illus_ar":0.699,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1152,"seq":584,"zh":"马来沉香","en":"Aquilaria malaccensis","sci":"Aquilaria malaccensis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Thymelaeaceae","family_zh":"瑞香科","iucn":"CR","langs":31,"desc_zh":"沉香又可称沉香树（学名：Aquilaria malaccensis），属于瑞香科沉香属下的一种，分布于孟加拉、不丹、印度、印尼、寮国、马来西亚、缅甸、菲律宾、新加坡、泰国及香港，沉香目前受到失去栖息地的威胁，与土沉香（Aquilaria sinensis）亲缘甚近，但不完全相同，由于土沉香产量少，故亦以土沉香较为矜贵，但野生的沉香采收风险大，危险性也大，产量小无法供应市场，所以现在都是人工培植较多。","desc_en":"Aquilaria malaccensis (Hindi: अगर, agaru; Assamese: সাঁচিগছ, sānci; Arabic: عود هندي, transl. Indian oud) or agar is a species of lign-aloe tree in the family Thymelaeaceae.","img":"images/1152.jpg","thumb":"images/t/1152.jpg","file":"Aquilaria malaccensis - Agar Wood, Eaglewood - Indian Aloewood at Munnar (4).jpg","ar":1.333,"py":"malaichenxiang mlcx","cr_by":"Vinayaraj","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":596,"seq":585,"zh":"娑罗树","en":"Shorea robusta","sci":"Shorea robusta","order_en":"Malvales","order_zh":"锦葵目","family_en":"Dipterocarpaceae","family_zh":"龙脑香科","iucn":"NT","langs":48,"desc_zh":"娑罗树（学名：Shorea robusta），又名沙罗双树、钵罗叉树、波罗叉树，摩诃娑罗树、沙罗树、鹤林、鹄树、无忧树，为龙脑香科娑罗属植物，产于印度及马来半岛等南亚雨林之中。属多年生乔木。树身高大，叶为长卵形而尖，表面光滑，花淡黄色，萼及花瓣外有灰色刚毛。因为气味芳香，木材坚固，可以用来制作家具或建材，又可供作药用或香料。佛教视之为圣树之一。","desc_en":"Shorea robusta, the sal tree (Devanagari: साल ; IAST: sāla), shala, sakhua, or sarai, is a species of tree in the family Dipterocarpaceae. The tree is native to India, Bangladesh, Nepal, Tibet and across the Himalayan regions.","img":"images/596.jpg","thumb":"images/t/596.jpg","file":"Shorea robusta.jpg","ar":0.726,"py":"suoluoshu sls","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":597,"seq":586,"zh":"龙脑香","en":"Dryobalanops aromatica","sci":"Dryobalanops aromatica","order_en":"Malvales","order_zh":"锦葵目","family_en":"Dipterocarpaceae","family_zh":"龙脑香科","iucn":"VU","langs":22,"desc_zh":null,"desc_en":"Dryobalanops aromatica, commonly known as Borneo camphor, camphor tree, Malay camphor, or Sumatran camphor, is a species of plant in the family Dipterocarpaceae.","img":"images/597.jpg","thumb":"images/t/597.jpg","file":"Dryobalanops Aromatica canopy.jpg","ar":1.333,"py":"longnaoxiang lnx","cr_by":"Patrice78500","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":1153,"seq":587,"zh":"香坡垒树","en":"Hopea odorata","sci":"Hopea odorata","order_en":"Malvales","order_zh":"锦葵目","family_en":"Dipterocarpaceae","family_zh":"龙脑香科","iucn":"VU","langs":21,"desc_zh":"香坡垒树，是龙脑香科坡垒属下的榭种，分布于孟加拉国、印度、缅甸、泰国、老挝、柬埔寨、马来西亚、越南。 它可生长至45米高、树干的底部直径可达到4.5米。它生长在森林中，偏好在河流附近，海拔0-600米高的地方。在西孟加拉邦和安达曼群岛等地方，它常常种植为遮荫树。因其木材价值，在其自然栖息地它是一个受威胁的物种。 自2025年「台风康芮」被除名后，台风委员会决定用本植物名称代替。","desc_en":"Hopea odorata is a species of tree in the plant family Dipterocarpaceae. It is found in Bangladesh, Cambodia, India, Laos, Malaysia, Singapore, Myanmar, Thailand, and Vietnam.","img":"images/1153.jpg","thumb":"images/t/1153.jpg","file":"Leaves of Hopea odorata.jpg","ar":0.75,"py":"xiangpoleishu xpls","cr_by":"Silviculture at Vietnamese Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/1153.jpg","illus_thumb":"images/i/t/1153.jpg","illus_file":"Hopea odorata Roxb. from Pl. Coromandel 3, t. 210.jpg","illus_ar":0.736,"illus_by":"Unknown author Unknown author","illus_lic":"Public domain","illus_licurl":null},{"id":598,"seq":588,"zh":"铺地半日花","en":"Helianthemum nummularium","sci":"Helianthemum nummularium","order_en":"Malvales","order_zh":"锦葵目","family_en":"Cistaceae","family_zh":"半日花科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Helianthemum nummularium (known as common rock-rose) is a species of rock-rose (Cistaceae), native to most of Europe.","img":"images/598.jpg","thumb":"images/t/598.jpg","file":"Helianthemum nummularium1.jpg","ar":0.75,"py":"pudibanrihua pdbrh","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"],"illus_img":"images/i/598.jpg","illus_thumb":"images/i/t/598.jpg","illus_file":"Helianthemum nummularium Lindman DESC.jpeg","illus_ar":1.5,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":599,"seq":589,"zh":"鼠尾草叶岩蔷薇","en":"Cistus salviifolius","sci":"Cistus salviifolius","order_en":"Malvales","order_zh":"锦葵目","family_en":"Cistaceae","family_zh":"半日花科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Cistus salviifolius, common names sage-leaved rock-rose, salvia cistus or Gallipoli rose, is a shrub of the family Cistaceae.","img":"images/599.jpg","thumb":"images/t/599.jpg","file":"00 3288 Cistus salviifolius - Salbeiblättrige Zistrose.jpg","ar":1.531,"py":"shuweicaoyeyanqiangwei swcyyqw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":null},{"id":1154,"seq":590,"zh":"白毛岩蔷薇","en":"Cistus albidus","sci":"Cistus albidus","order_en":"Malvales","order_zh":"锦葵目","family_en":"Cistaceae","family_zh":"半日花科","iucn":null,"langs":28,"desc_zh":null,"desc_en":"Cistus albidus, the grey-leaved cistus, is a shrubby species of flowering plant in the family Cistaceae, with pink to purple flowers, native to south-western Europe and western north Africa.","img":"images/1154.jpg","thumb":"images/t/1154.jpg","file":"Cistus albidus flowers.jpg","ar":1.333,"py":"baimaoyanqiangwei bmyqw","cr_by":"Júlio Reis","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲","非洲"]},{"id":1155,"seq":591,"zh":"红木","en":"Bixa orellana","sci":"Bixa orellana","order_en":"Malvales","order_zh":"锦葵目","family_en":"Bixaceae","family_zh":"红木科","iucn":"LC","langs":64,"desc_zh":"红木（Achiote，学名：Bixa orellana）又称胭脂树、臙脂树、胭脂木（云南金平）、红色树，是热带红木科红木属唯一一种的植物。其种皮红色，可生产浅红色或黄色粉末状染料胭脂树红，用于食品（黄油、乳酪、人造黄油）及纺织品、化妆品的着色剂。","desc_en":"Bixa orellana, also known as achiote, is a shrub or small tree native to Mexico and Central and South America. Bixa orellana is grown in many countries worldwide.","img":"images/1155.jpg","thumb":"images/t/1155.jpg","file":"Bixa.jpg","ar":1.333,"py":"hongmu hm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["北美洲","南美洲"]},{"id":1156,"seq":592,"zh":"岩寄生","en":"Cytinus hypocistis","sci":"Cytinus hypocistis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Cytinaceae","family_zh":"簇花草科","iucn":null,"langs":24,"desc_zh":null,"desc_en":"Cytinus hypocistis is an ant-pollinated species of obligate parasitic plant in the family Cytinaceae having four subspecies, which is parasitic on Cistus (rock-rose) species.","img":"images/1156.jpg","thumb":"images/t/1156.jpg","file":"Cytinus hypocistis06052003 1.JPG","ar":1.252,"py":"yanjisheng yjs","cr_by":"Henry Brisse (upload by user:Abalg )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"],"illus_img":"images/i/1156.jpg","illus_thumb":"images/i/t/1156.jpg","illus_file":"Illustration Cytinus hypocistis0.jpg","illus_ar":0.584,"illus_by":"Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":1157,"seq":593,"zh":"文定果","en":"Muntingia calabura","sci":"Muntingia calabura","order_en":"Malvales","order_zh":"锦葵目","family_en":"Muntingiaceae","family_zh":"文定果科","iucn":null,"langs":37,"desc_zh":"文定果属（学名：Muntingia）是文定果科下的一个单型属，即本属仅包括一种植物文定果（Muntingia calabura L.）。 原产于热带美洲低海拔地区，由于果实可食，现于各热带地区广泛栽培。","desc_en":"Muntingia is a genus of plants in the family Muntingiaceae, comprising only one species, Muntingia calabura, named in honour of Abraham Munting. It is native from Mexico south to Bolivia and Argentina.","img":"images/1157.jpg","thumb":"images/t/1157.jpg","file":"0001jfFlowers, fruits and seeds of Alatres trees in the Philippinesfvf 02.jpg","ar":1.333,"py":"wendingguo wdg","cr_by":"Judgefloro","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["北美洲","南美洲"]},{"id":1158,"seq":594,"zh":"Grielum humifusum","en":"Grielum humifusum","sci":"Grielum humifusum","order_en":"Malvales","order_zh":"锦葵目","family_en":"Neuradaceae","family_zh":"沙莓科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Grielum humifusum is a species of flowering plant in the family Neuradaceae.","img":"images/1158.jpg","thumb":"images/t/1158.jpg","file":"Grielum humifusum1.jpg","ar":1.333,"py":"","cr_by":"Winfried Bruenken ( Amrum )","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null},{"id":1159,"seq":595,"zh":"Sarcolaena oblongifolia","en":"Sarcolaena oblongifolia","sci":"Sarcolaena oblongifolia","order_en":"Malvales","order_zh":"锦葵目","family_en":"Sarcolaenaceae","family_zh":"旋花树科","iucn":"LC","langs":9,"desc_zh":null,"desc_en":"Sarcolaena oblongifolia is a species of plant in the Sarcolaenaceae family. It is endemic to Madagascar. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist shrubland. It is threatened by habitat loss.","img":"images/1159.jpg","thumb":"images/t/1159.jpg","file":"Sarcolaena oblongifolia 2.JPG","ar":1.35,"py":"","cr_by":"Wilfried Bauer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"]},{"id":1160,"seq":596,"zh":"梨蒴珠藓","en":"Bartramia pomiformis","sci":"Bartramia pomiformis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Tiliaceae","family_zh":"椴树科","iucn":null,"langs":15,"desc_zh":"梨蒴珠藓（学名：Bartramia pomiformis）为珠藓科珠藓属下的一个种。","desc_en":"Bartramia pomiformis, the common apple-moss, is a species of moss in the Bartramiaceae family. It is typically green or glaucous in hue, although sometimes it can appear yellowish.","img":"images/1160.jpg","thumb":"images/t/1160.jpg","file":"Bartramia.pomiformis.jpg","ar":1.506,"py":"lishuozhuxian lszx","cr_by":"James K. Lindsey","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":600,"seq":597,"zh":"萝卜","en":"Raphanus sativus","sci":"Raphanus sativus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":134,"desc_zh":"萝卜（bo）（学名：Raphanus raphanistrum subsp. sativus），别名莱菔、芦菔、菈𦿚（音同“拉沓”），在中国福建下路地区、潮汕地区、四县与台湾俗称菜头（台罗：tshài-thâu），为十字花科萝卜属草本植物，是野萝卜的亚种。 萝卜的根部是最常见的蔬菜之一，但实际上整株植物均可食用。目前有专门食用叶子的品种，称为“叶萝卜”。种子称为莱菔子，是常用的中药。 萝卜分为白萝卜、青萝卜和樱桃萝卜三种。","desc_en":"The radish (Raphanus sativus or Raphanus raphanistrum subsp. sativus) is a flowering plant in the mustard family, Brassicaceae. Its large taproot is commonly used as a root vegetable, although the entire plant is edible and its leaves are sometimes used as a l…","img":"images/600.jpg","thumb":"images/t/600.jpg","file":"Radish 3371103037 4ab07db0bf o.jpg","ar":0.75,"py":"luobo lb","cr_by":"Self, en:User:Jengod","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":601,"seq":598,"zh":"甘蓝","en":"Brassica oleracea","sci":"Brassica oleracea","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"DD","langs":114,"desc_zh":"甘蓝（学名：Brassica oleracea）是十字花科植物，具多个变种，依食用部位概略分为：花用甘蓝（花椰菜、西兰花）、叶用甘蓝（高丽菜、叶用不结球甘蓝、芥蓝）、茎用甘蓝（苤蓝）等，是被人类广泛食用的蔬菜。","desc_en":"Brassica oleracea, also known as wild cabbage in its uncultivated form, is a plant of the family Brassicaceae. The species originated from feral populations of related plants in the Eastern Mediterranean, where it was most likely first cultivated.","img":"images/601.jpg","thumb":"images/t/601.jpg","file":"Brassica oleracea - Royal Botanical Garden, Madrid.JPG","ar":0.75,"py":"ganlan gl","cr_by":"Daderot","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"]},{"id":602,"seq":599,"zh":"欧洲油菜","en":"Brassica napus","sci":"Brassica napus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":93,"desc_zh":"西洋油菜（学名：Brassica napus）又名甘蓝型油菜、大油菜，是十字花科草本植物，主要用途是油料经济作物。油菜籽的种籽粒可制油脂，它分为冬油菜和春油菜两种。 油菜籽含芥酸、芥子碱、单宁等化学物质，含毒性。","desc_en":"Rapeseed (Brassica napus subsp. napus), also known as rape and oilseed rape and canola, is a yellow-flowered member of the Brassicaceae family. The plant is cultivated primarily for its oil-rich seed, which naturally contains mildly toxic erucic acid.","img":"images/602.jpg","thumb":"images/t/602.jpg","file":"(MHNT) Brassica napus - Habit.jpg","ar":0.983,"py":"ouzhouyoucai ozyc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/602.jpg","illus_thumb":"images/i/t/602.jpg","illus_file":"Brassica napus - Köhler–s Medizinal-Pflanzen-169.jpg","illus_ar":0.813,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":603,"seq":600,"zh":"辣根","en":"Armoracia rusticana","sci":"Armoracia rusticana","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"LC","langs":81,"desc_zh":"辣根（学名：Armoracia rusticana），又称西洋山嵛菜、马萝卜、山萝卜、粉山葵、西洋山葵，原产东南欧，是十字花科辣根属多年生宿根耐寒植物。可以作为蔬菜使用，具有刺激鼻窦的香辣味道。辣根用于欧洲国家的烤牛肉等菜肴的佐料以外，因削皮后是白的，加入食用色素后可作为仿制山葵调料的材料。","desc_en":"Horseradish (Armoracia rusticana, syn. Cochlearia armoracia) is a perennial plant of the family Brassicaceae (which also includes mustard, wasabi, broccoli, cabbage, and radish).","img":"images/603.jpg","thumb":"images/t/603.jpg","file":"Armoracia rusticana.jpg","ar":0.75,"py":"lagen lg","cr_by":"Pethan","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/603.jpg","illus_thumb":"images/i/t/603.jpg","illus_file":"Armoracia rusticana illustration.jpg","illus_ar":0.667,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":604,"seq":601,"zh":"水芹","en":"Lepidium sativum","sci":"Lepidium sativum","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":78,"desc_zh":"家独行菜（学名：Lepidium sativum）是十字花科独行菜属的植物，有时讹称水芹，与伞形科的真水芹相混淆。","desc_en":"Cress (Lepidium sativum), sometimes referred to as garden cress (or curly cress) to distinguish it from similar plants also referred to as cress (from Old English cresse), is a fast-growing, edible herb.","img":"images/604.jpg","thumb":"images/t/604.jpg","file":"Img 0717 garden cress.jpg","ar":1.506,"py":"shuiqin sq","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":605,"seq":602,"zh":"西洋菜","en":"Nasturtium officinale","sci":"Nasturtium officinale","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"LC","langs":76,"desc_zh":"西洋菜（学名：Nasturtium officinale），别名豆瓣菜、水田芥、水芥菜、荷兰芥菜、水蔊菜等，是十字花科西洋菜属的一种植物。其为牛羊肝吸虫的第二中间宿主（病媒），因此作为食物食用的西洋菜需煮熟，以防感染。 西洋菜速生，原产于欧洲和亚洲，是已知最早被人类食用的叶菜之一。西洋菜和其近亲水芹、芥菜、萝卜、山葵等都有明显的辣味。 西洋菜的茎中空，使其可以漂浮在水面。白色丛生的花容易吸引食蚜蝇科的昆虫。","desc_en":"Watercress or yellowcress (Nasturtium officinale) is a species of aquatic flowering plant in the cabbage family, Brassicaceae. Watercress is a rapidly growing perennial plant native to Eurasia. It is one of the oldest known leaf vegetables consumed by humans.","img":"images/605.jpg","thumb":"images/t/605.jpg","file":"Cresson 02.jpg","ar":0.75,"py":"xiyangcai xyc","cr_by":"Chirocca77","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/605.jpg","illus_thumb":"images/i/t/605.jpg","illus_file":"Illustration Nasturtium officinale0.jpg","illus_ar":0.651,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":606,"seq":603,"zh":"芸苔","en":"Brassica rapa","sci":"Brassica rapa","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":72,"desc_zh":"芸薹（学名：Brassica rapa），是芸薹属的一种植物，可作为叶菜（如小白菜、大白菜、菜心）、根用植物（如芜菁）和作为植物油（又称白菜型油菜注意，此并非更常见的甘蓝型油菜，详见油菜）食用。 在十八世纪时，卡尔·林奈视芜菁和油用的变种（即白菜型油菜）为不同的品种并分别命名为 B. rapa 和 B. campestris。然而二十世纪的分类学家发现这些植物是异体受精，因此认为是相同的物种。","desc_en":"Brassica rapa is an annual to biennial plant species native to Eurasia that is from the Brassicaceae family. The B. rapa subspecies oleifera is an oilseed commonly known as turnip rape, field mustard, bird's rape, and keblock.","img":"images/606.jpg","thumb":"images/t/606.jpg","file":"Malselvneper.JPG","ar":1.494,"py":"yuntai yt","cr_by":"Osopolar","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":607,"seq":604,"zh":"山葵","en":"Eutrema japonicum","sci":"Eutrema japonicum","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":66,"desc_zh":"山葵（学名：Eutrema japonicum；日语：山葵／わさび／ワサビ，罗马化：wasabi），音译为哇沙米 （台罗：ua-sá-bih）、哇沙比，又称为山萮菜，是一种属于十字花科山萮菜属的绿色植物，味道极其强烈。山葵的辛辣跟辣椒不同，辣椒的辣味刺激舌头，而山葵的辣味却刺激鼻窦。山葵常见于日本山谷河流旁边生长，其他品种包括W. koreana及W. tetsuigi；市面上普遍出售的两种山葵是W.","desc_en":"Wasabi (Japanese: ワサビ, わさび, or 山葵, pronounced [waꜜsabi]) or Japanese horseradish (Eutrema japonicum syn. Wasabia japonica) is a plant of the family Brassicaceae, which also includes horseradish and mustard in other genera.","img":"images/607.jpg","thumb":"images/t/607.jpg","file":"Fresh wasabi rhizomes.jpg","ar":1.333,"py":"shankui sk","cr_by":"Sabigirl at English Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":613,"seq":605,"zh":"番木瓜","en":"Carica papaya","sci":"Carica papaya","order_en":"Brassicales","order_zh":"十字花目","family_en":"Caricaceae","family_zh":"番木瓜科","iucn":"DD","langs":163,"desc_zh":"番木瓜（学名：Carica papaya）又名木瓜、万寿果，热带和亚热带大型草本，叶大掌状，大多为雌雄异株，花黄色，果实长圆形，果肉厚味甜。木瓜的乳汁含木瓜蛋白酶，是制作松肉粉的主要成分。 中国古代即有“木瓜”，《诗经·卫风·木瓜》所称之“木瓜”是贴梗海棠的果实，而番木瓜约在17世纪引进中国大陆，约在清朝末年再引入台湾。","desc_en":"The papaya (, US: ) is the plant species Carica papaya, one of the 21 accepted species in the genus Carica of the family Caricaceae. It was first domesticated in Mesoamerica, within modern-day southern Mexico and Central America.","img":"images/613.jpg","thumb":"images/t/613.jpg","file":"Carica papaya - Köhler–s Medizinal-Pflanzen-029.jpg","ar":0.708,"py":"fanmugua fmg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"],"illus_img":"images/i/613.jpg","illus_thumb":"images/i/t/613.jpg","illus_file":"Carica papaya - Köhler–s Medizinal-Pflanzen-029.jpg","illus_ar":0.708,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":614,"seq":606,"zh":"旱金莲","en":"Tropaeolum majus","sci":"Tropaeolum majus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Tropaeolaceae","family_zh":"旱金莲科","iucn":null,"langs":54,"desc_zh":"旱金莲（学名：Tropaeolum majus）又名金莲花，十字花目旱金莲科旱金莲属植物，与另一个同名的金莲花（Trollius chinensis，毛茛目毛茛科金莲花属）不同。 在台湾俗称的金莲花，实际上是旱金莲。","desc_en":"Tropaeolum majus, the garden nasturtium, nasturtium, Indian cress or monk's cress, is a species of flowering plant in the family Tropaeolaceae. An annual or a short-lived perennial with disc-shaped leaves and brilliant yellow, orange or red flowers, it is of c…","img":"images/614.jpg","thumb":"images/t/614.jpg","file":"Tropaeolum majus 2005 G1.jpg","ar":1.094,"py":"hanjinlian hjl","cr_by":"George Chernilevsky","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"],"illus_img":"images/i/614.jpg","illus_thumb":"images/i/t/614.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 23 Tropaeolum majus (6021776775).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":615,"seq":607,"zh":"刺山柑","en":"Capparis spinosa","sci":"Capparis spinosa","order_en":"Brassicales","order_zh":"十字花目","family_en":"Capparaceae","family_zh":"山柑科","iucn":"LC","langs":79,"desc_zh":"刺山柑（学名：Capparis spinosa），又名马槟榔、棘风蝶木、西洋风蝶木、酸豆、水瓜柳、水瓜榴或是水瓜钮，是一种多年生的有刺半蔓性灌木，属于山柑科山柑属。刺山柑在台湾常被称为续随子，但真正的续随子是大戟属植物。刺山柑的叶厚身、对生、呈鹅卵形，有大大的白色到粉白色的花朵。原产于地中海的刺山柑，会在石墙或岩岸生长。当地人会把植物的果实腌制，可作调味用途。花蕾及果实可食用，但一般都会先腌制。","desc_en":"Capparis spinosa, the caper bush, also called Flinders rose, is a perennial plant that bears rounded, fleshy leaves and large white to pinkish-white flowers. The taxonomic status of the species is controversial and unsettled.","img":"images/615.jpg","thumb":"images/t/615.jpg","file":"Capparis zoharyi 4.jpg","ar":1.254,"py":"cishangan csg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["欧洲"],"illus_img":"images/i/615.jpg","illus_thumb":"images/i/t/615.jpg","illus_file":"34 Capparis spinosa par Pierre-Joseph Redouté.jpeg","illus_ar":0.7,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1161,"seq":608,"zh":"Akania bidwillii","en":"Akania bidwillii","sci":"Akania bidwillii","order_en":"Brassicales","order_zh":"十字花目","family_en":"Akaniaceae","family_zh":"叠珠树科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Akania is a monotypic genus in the family Akaniaceae. The single species, Akania bidwillii (turnipwood), is a tree that is native to subtropical and warm-temperate coastal rainforests in New South Wales and Queensland in Australia.","img":"images/1161.jpg","thumb":"images/t/1161.jpg","file":"Akania bidwillii leaves.jpg","ar":0.751,"py":"","cr_by":"Poyt448 Peter Woodard","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["大洋洲"]},{"id":1162,"seq":609,"zh":"白楔","en":"Batis maritima","sci":"Batis maritima","order_en":"Brassicales","order_zh":"十字花目","family_en":"Bataceae","family_zh":"藜木科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Batis maritima, the saltwort or beachwort (also known as turtleweed, pickleweed, barilla, planta de sal, camphire, herbe-à-crâbes, and akulikuli-kai), is a halophyte. It is a C3-plant, long-lived perennial, dioecious, succulent shrub.","img":"images/1162.jpg","thumb":"images/t/1162.jpg","file":"Batis maritima male.jpg","ar":0.75,"py":"baixie bx","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":null},{"id":1163,"seq":610,"zh":"白花菜","en":"Cleome gynandra","sci":"Cleome gynandra","order_en":"Brassicales","order_zh":"十字花目","family_en":"Cleomaceae","family_zh":"白花菜科","iucn":null,"langs":23,"desc_zh":"白花菜（学名：Cleome gynandra）为醉蝶花科醉蝶花属下的一个种。","desc_en":"Cleome gynandra is a species of Cleome that is used as a leaf vegetable. It is known by many common names including Shona cabbage, African cabbage, spiderwisp, cat's whiskers, and stinkweed.","img":"images/1163.jpg","thumb":"images/t/1163.jpg","file":"Cat’s whiskers or African Cabbage - Sheikh Zain al-din - 19 1927 2 52.jpg","ar":0.675,"py":"baihuacai bhc","cr_by":"Sheikh Zainuddin","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["非洲"]},{"id":1164,"seq":611,"zh":"澳远志","en":"Emblingia calceoliflora","sci":"Emblingia calceoliflora","order_en":"Brassicales","order_zh":"十字花目","family_en":"Emblingiaceae","family_zh":"澳远志科","iucn":null,"langs":21,"desc_zh":"澳远志（学名：Emblingia calceoliflora）又名龙柱花，是澳远志科（Emblingiaceae）及澳远志属的唯一物种，属于真双子叶植物十字花目，只生长在澳大利亚的西海岸，是当地的特有种。 本种植物是多年生亚灌木，单叶对生，有多个托叶；花大，花冠朝下，花瓣5，不等大，有两片最大；果实为蒴果。","desc_en":"Emblingia is a monospecific plant genus containing the species Emblingia calceoliflora, a herbaceous prostrate subshrub endemic to Western Australia. It has no close relatives, and is now generally placed alone in family Emblingiaceae.","img":"images/1164.jpg","thumb":"images/t/1164.jpg","file":"Emblingia calceoliflora.jpg","ar":0.575,"py":"aoyuanzhi ayz","cr_by":"Ferdinand Jacob H . Mueller","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["大洋洲"]},{"id":1165,"seq":612,"zh":"Gyrostemon ramulosus","en":"Gyrostemon ramulosus","sci":"Gyrostemon ramulosus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Gyrostemonaceae","family_zh":"环蕊科","iucn":"LC","langs":7,"desc_zh":null,"desc_en":"Gyrostemon ramulosus is a plant in the family Gyrostemonaceae. It was first described by René Louiche Desfontaines in 1820. It is native to dry zones in Western and South of Australia.","img":"images/1165.jpg","thumb":"images/t/1165.jpg","file":"Gyrostemon ramulosus.jpg","ar":0.54,"py":"","cr_by":"Pierre Jean François Turpin","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["大洋洲"]},{"id":1166,"seq":613,"zh":"耶稣刺","en":"Koeberlinia spinosa","sci":"Koeberlinia spinosa","order_en":"Brassicales","order_zh":"十字花目","family_en":"Koeberliniaceae","family_zh":"刺枝树科","iucn":"LC","langs":14,"desc_zh":null,"desc_en":"Koeberlinia spinosa is a species of flowering plant native to the southwestern United States and northern Mexico known by several common names, including crown of thorns, allthorn, smokebush, and crucifixion thorn.","img":"images/1166.jpg","thumb":"images/t/1166.jpg","file":"Koeberlinia spinosa WikiPlant.jpg","ar":1.333,"py":"yesuci ysc","cr_by":"Florian Siebeck","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":1167,"seq":614,"zh":"沼花","en":"Limnanthes douglasii","sci":"Limnanthes douglasii","order_en":"Brassicales","order_zh":"十字花目","family_en":"Limnanthaceae","family_zh":"池花科","iucn":null,"langs":13,"desc_zh":null,"desc_en":"Limnanthes douglasii is a species of annual flowering plant in the family Limnanthaceae (meadowfoam) commonly known as Douglas' meadowfoam or poached egg plant.","img":"images/1167.jpg","thumb":"images/t/1167.jpg","file":"Limnanthes douglasii1.jpg","ar":1.333,"py":"zhaohua zh","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲"]},{"id":1168,"seq":615,"zh":"辣木","en":"moringa","sci":"Moringa oleifera","order_en":"Brassicales","order_zh":"十字花目","family_en":"Moringaceae","family_zh":"辣木科","iucn":"LC","langs":86,"desc_zh":"辣木（学名：Moringa oleifera）别名鼓槌树，为辣木科辣木属下的一个种，原产于南亚热带和亚热带地区，抗旱且快速增长。因此在一些非原生地亦是具侵略性的入侵物种。","desc_en":"Moringa oleifera is a short-lived, fast-growing, drought-resistant tree of the family Moringaceae, native to northern India and used extensively in South and Southeast Asia.","img":"images/1168.jpg","thumb":"images/t/1168.jpg","file":"Brèdes morôngo-ananambo.jpg","ar":0.75,"py":"lamu lm","cr_by":"Chirocca77","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"]},{"id":1169,"seq":616,"zh":"Pentadiplandra brazzeana","en":"Pentadiplandra brazzeana","sci":"Pentadiplandra brazzeana","order_en":"Brassicales","order_zh":"十字花目","family_en":"Pentadiplandraceae","family_zh":"瘤药树科","iucn":null,"langs":21,"desc_zh":null,"desc_en":"Pentadiplandra brazzeana, also known as oubli, is an evergreen shrub or liana that is the only species assigned to the genus Pentadiplandra, and has been placed in a family of its own called Pentadiplandraceae.","img":"images/1169.jpg","thumb":"images/t/1169.jpg","file":"Pentadiplandra etching 1909.jpg","ar":0.71,"py":"","cr_by":"Wildeman, E. de, died 24 July 1947 see Wildeman, E. de (Emile) 1866-1947","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":null},{"id":1170,"seq":617,"zh":"黄木樨草","en":"Reseda lutea","sci":"Reseda lutea","order_en":"Brassicales","order_zh":"十字花目","family_en":"Resedaceae","family_zh":"木樨草科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Reseda lutea, the yellow mignonette or wild mignonette, is a species of fragrant herbaceous flowering plant. Its leaves and flowers have been used to make a yellow dye called \"weld\" since the first millennium BC, although the related plant Reseda luteola was m…","img":"images/1170.jpg","thumb":"images/t/1170.jpg","file":"ResedaLutea-overz-kl.jpg","ar":1.332,"py":"huangmuxicao hmxc","cr_by":"TeunSpaans at Dutch Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","非洲"],"illus_img":"images/i/1170.jpg","illus_thumb":"images/i/t/1170.jpg","illus_file":"Reseda lutea — Flora Batava — Volume v9.jpg","illus_ar":0.758,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1171,"seq":618,"zh":"牙刷树","en":"Salvadora persica","sci":"Salvadora persica","order_en":"Brassicales","order_zh":"十字花目","family_en":"Salvadoraceae","family_zh":"刺茉莉科","iucn":"LC","langs":40,"desc_zh":"牙刷树（学名：Salvadora persica）是一种小型常绿乔木，原产于中东、非洲和印度。其树枝称做米斯瓦克，传统上被用作天然牙刷，世界卫生组织提到它能让口腔保持干净。 牙刷树另有别名阿拉克树（Arak Tree） 、Jhak、Pīlu和Mustard tree。","desc_en":"Salvadora persica or the arak, is a small evergreen tree. Other common names include jhal, toothbrush tree, mustard tree, and peelu. Its roots and twigs called miswak are traditionally used for chewing as a toothbrush.","img":"images/1171.jpg","thumb":"images/t/1171.jpg","file":"Salvadora persica.jpg","ar":0.684,"py":"yashuashu yss","cr_by":"William Roxburgh (1751-1815), Joseph Banks (1774-1820)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":616,"seq":619,"zh":"檀香","en":"Santalum album","sci":"Santalum album","order_en":"Santalales","order_zh":"檀香目","family_en":"Santalaceae","family_zh":"檀香科","iucn":null,"langs":65,"desc_zh":"檀香树（学名：Santalum album；梵语：चन्दन，IAST：candana），又名真檀（《本草纲目》）、栴檀、旃檀、白旃檀（《楞严经》）、白檀、檀香，是檀香科檀香属的一种半寄生性植物。原产地为马来西亚半岛等东南亚地区，再经由海上贸易传播到印度，澳洲，再经由随佛教来到中国。品质纯正的檀香是一味中药材，分为檀香片和檀香粉，放在专用的檀香炉中燃烧，它独特的安抚作用可以使人清心、凝神、排除杂念，是修生养性的辅助工具。","desc_en":"Santalum album is a small tropical tree, and the traditional source of sandalwood oil. It is native to Indonesia (Java and the Lesser Sunda Islands), the Philippines, and Western Australia. It is commonly known as the white sandalwood or Indian sandalwood.","img":"images/616.jpg","thumb":"images/t/616.jpg","file":"Santalum album - Köhler–s Medizinal-Pflanzen-128.jpg","ar":0.734,"py":"tanxiang tx","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","大洋洲"],"illus_img":"images/i/616.jpg","illus_thumb":"images/i/t/616.jpg","illus_file":"Santalum album - Köhler–s Medizinal-Pflanzen-128.jpg","illus_ar":0.734,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":617,"seq":620,"zh":"槲寄生","en":"Viscum album","sci":"Viscum album","order_en":"Santalales","order_zh":"檀香目","family_en":"Santalaceae","family_zh":"檀香科","iucn":null,"langs":61,"desc_zh":"白果槲寄生（学名：Viscum album）又名欧洲槲寄生，是檀香科、槲寄生属的一种半寄生植物，从寄主树体获取水分与养分，原生于西亚、南亚和欧洲，在欧洲神话、传说与民俗中具有重要地位。现代西方仍将白果槲寄生作为圣诞节相关的装饰及象征物使用。 在北美，其文化角色通常由外形相近的本土种北美肉穗寄生所替代。","desc_en":"Viscum album is a species of mistletoe in the family Santalaceae, commonly called European mistletoe, common mistletoe, or simply mistletoe (Old English mistle). It is native to Europe, as well as western and southern Asia. V.","img":"images/617.jpg","thumb":"images/t/617.jpg","file":"Viscum album 2026 G1.jpg","ar":1,"py":"hujisheng hjs","cr_by":"George Chernilevsky","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/617.jpg","illus_thumb":"images/i/t/617.jpg","illus_file":"Viscum album - Köhler–s Medizinal-Pflanzen-281.jpg","illus_ar":0.855,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":1172,"seq":621,"zh":"框东","en":"Santalum acuminatum","sci":"Santalum acuminatum","order_en":"Santalales","order_zh":"檀香目","family_en":"Santalaceae","family_zh":"檀香科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Santalum acuminatum, the desert quandong, is an evergreen, hemiparasitic tree in the sandalwood family, Santalaceae, which is widely dispersed throughout the central deserts and southern areas of Australia.","img":"images/1172.jpg","thumb":"images/t/1172.jpg","file":"Santalum acuminatum - Flickr - Kevin Thiele.jpg","ar":0.736,"py":"kuangdong kd","cr_by":"Kevin Thiele from Perth, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["大洋洲"]},{"id":618,"seq":622,"zh":"澳洲圣诞树","en":"Nuytsia floribunda","sci":"Nuytsia floribunda","order_en":"Santalales","order_zh":"檀香目","family_en":"Loranthaceae","family_zh":"桑寄生科","iucn":"LC","langs":17,"desc_zh":"多花金焰檀（学名：Nuytsia floribunda）是分布在西澳洲的大型寄生植物，因花期在圣诞节前后而又名澳洲圣诞树，是金焰檀属现存唯一物种。","desc_en":"Nuytsia floribunda is a hemiparasitic tree found in Western Australia. The species is known locally as moodjar and, more recently, the Christmas tree or Western Australian Christmas tree.","img":"images/618.jpg","thumb":"images/t/618.jpg","file":"Christmas tree 02 gnangarra.jpg","ar":1.333,"py":"aozhoushengdanshu azsds","cr_by":"Gnangarra","cr_lic":"CC BY 2.5 au","cr_licurl":"https://creativecommons.org/licenses/by/2.5/au/deed.en","habit":"乔木","origin":["大洋洲"]},{"id":619,"seq":623,"zh":"小叶钝果寄生","en":"Taxillus kaempferi","sci":"Taxillus kaempferi","order_en":"Santalales","order_zh":"檀香目","family_en":"Loranthaceae","family_zh":"桑寄生科","iucn":null,"langs":13,"desc_zh":"小叶钝果寄生（学名：Taxillus kaempferi），为桑寄生科钝果寄生属下的一个植物种。","desc_en":"Taxillus kaempferi (Chinese: 小叶钝果寄生; pinyin: xiao ye dun guo ji sheng) is a parasitic plant species in the genus Taxillus found in China (Anhui, Fujian, W Hubei, S Jiangxi, Sichuan, S Zhejiang), Bhutan and Japan. Its host is Pinus thunbergii.","img":"images/619.jpg","thumb":"images/t/619.jpg","file":"Taxillus kaempferi matugumi01.jpg","ar":1.333,"py":"xiaoyedunguojisheng xydgjs","cr_by":"Keisotyo","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":1173,"seq":624,"zh":"Plicosepalus acaciae","en":"Plicosepalus acaciae","sci":"Plicosepalus acaciae","order_en":"Santalales","order_zh":"檀香目","family_en":"Loranthaceae","family_zh":"桑寄生科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Plicosepalus acaciae (syn. Loranthus acaciae), the acacia strap flower, is a species of hemiparasitic flowering plant in the family Loranthaceae. It is native to northeastern Africa, the Levant, and the Arabian Peninsula.","img":"images/1173.jpg","thumb":"images/t/1173.jpg","file":"Loranthus acaciae.jpg","ar":1.471,"py":"","cr_by":"איתן פרמן","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","非洲"]},{"id":1174,"seq":625,"zh":"Anacolosa densiflora","en":"Anacolosa densiflora","sci":"Anacolosa densiflora","order_en":"Santalales","order_zh":"檀香目","family_en":"Aptandraceae","family_zh":"兜帽果科","iucn":"EN","langs":10,"desc_zh":null,"desc_en":"Anacolosa densiflora is a species of plant in the Olacaceae family. Currently, it is an endangered species that is endemic to India.","img":"images/1174.jpg","thumb":"images/t/1174.jpg","file":"Anacolosa densiflora Govindoo.jpg","ar":0.757,"py":"","cr_by":"Govindoo","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":1175,"seq":626,"zh":"蛇菰","en":"Balanophora fungosa","sci":"Balanophora fungosa","order_en":"Santalales","order_zh":"檀香目","family_en":"Balanophoraceae","family_zh":"蛇菰科","iucn":null,"langs":13,"desc_zh":"蛇菰（学名：Balanophora fungosa），是一种开花植物，属于蛇菰科，分布于南亚、东南亚、澳大利亚和一些太平洋岛屿。它是一种专性寄生植物，生长在雨林树木的根部。开花结构的形状像一个马勃，但实际上是由一个覆盖着数千朵小雌花的球体组成的。地体的底部被数量少得多的雄花包围。在开花时，这种植物会散发出一种类似于老鼠的气味。","desc_en":"Balanophora fungosa, sometimes known as fungus root, is a flowering plant in the family Balanophoraceae and occurs in South Asia, Southeast Asia, Australia and some Pacific islands. It is a parasite growing on the roots of rainforest trees.","img":"images/1175.jpg","thumb":"images/t/1175.jpg","file":"Balanophora fungosa 24169269.jpg","ar":1.502,"py":"shegu sg","cr_by":"coenobita","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["亚洲","大洋洲"],"illus_img":"images/i/1175.jpg","illus_thumb":"images/i/t/1175.jpg","illus_file":"Balanophora fungosa in Hooker 1856 plate 8.jpg","illus_ar":0.76,"illus_by":"Joseph Dalton Hooker (1817–1911) del., W. Fitch lith.","illus_lic":"Public domain","illus_licurl":null},{"id":1176,"seq":627,"zh":"海檀木","en":"Ximenia americana","sci":"Ximenia americana","order_en":"Santalales","order_zh":"檀香目","family_en":"Olacaceae","family_zh":"铁青树科","iucn":"LC","langs":25,"desc_zh":"海檀木（学名：Ximenia americana）为铁青树科海檀木属下的一个种。","desc_en":"Ximenia americana, commonly known as tallow wood, hog plum, yellow plum, sea lemon, or pi'ut (Chamorro), is bush-forming shrub/small tree; a species from the Ximenia genus in the Olacaceae family.","img":"images/1176.jpg","thumb":"images/t/1176.jpg","file":"Ximenia americana leaves & fruit at Chilkur near Hyderabad, AP W2 IMG 7288.jpg","ar":1.336,"py":"haitanmu htm","cr_by":"J.M.Garg","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","非洲","北美洲","南美洲","大洋洲"]},{"id":1177,"seq":628,"zh":"巴西西柚木","en":"Agonandra brasiliensis","sci":"Agonandra brasiliensis","order_en":"Santalales","order_zh":"檀香目","family_en":"Opiliaceae","family_zh":"山柚子科","iucn":"LC","langs":10,"desc_zh":null,"desc_en":"Agonandra brasiliensis (Portuguese common name: pau-marfim) is a timber tree native to Amazon rainforest and Cerrado vegetation in Brazil. This plant is Brazilian wood export, and it is often used for flooring and furniture, specially chair production.","img":"images/1177.jpg","thumb":"images/t/1177.jpg","file":"Agonandra brasiliensis 2.jpg","ar":1.333,"py":"baxixiyoumu bxxym","cr_by":"João Medeiros","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["南美洲"]},{"id":1178,"seq":629,"zh":"Quinchamalium chilense","en":"Quinchamalium chilense","sci":"Quinchamalium chilense","order_en":"Santalales","order_zh":"檀香目","family_en":"Schoepfiaceae","family_zh":"青皮木科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Quinchamalium is a genus of flowering plant in the family Schoepfiaceae, with a single species Quinchamalium chilense, native to Chile, Argentina, Peru and Bolivia. Depending on the latitude, it can be found from sea level to 3,800 m in elevation.","img":"images/1178.jpg","thumb":"images/t/1178.jpg","file":"Quinchamalium chilense Molina.(pabloendemico).jpg","ar":1.333,"py":"","cr_by":"pabloendemico","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["南美洲"]},{"id":1179,"seq":630,"zh":"Viscum minimum","en":"Viscum minimum","sci":"Viscum minimum","order_en":"Santalales","order_zh":"檀香目","family_en":"Viscaceae","family_zh":"槲寄生科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Viscum minimum is a species of mistletoe in the family Santalaceae. It is a parasitic plant native to South Africa.","img":"images/1179.jpg","thumb":"images/t/1179.jpg","file":"Viscum minimum2 ies.jpg","ar":1.143,"py":"","cr_by":"Frank Vincentz","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":620,"seq":631,"zh":"梨果仙人掌","en":"Opuntia ficus-indica","sci":"Opuntia ficus-indica","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"DD","langs":64,"desc_zh":"梨果仙人掌又名食用仙人掌（学名：Opuntia ficus-indica）为仙人掌科仙人掌属的植物。分布于吉海及红海沿岸、澳洲大陆全境、毛里求斯、南非、东非、夏威夷以及台湾、云南、广东、四川、福建、贵州、浙江、广西等地，生长于海拔600米至2,900米的地区，多生在热河谷，目前尚未由人工引种栽培。","desc_en":"Opuntia ficus-indica, the Indian fig opuntia, fig opuntia, or prickly pear, is a species of cactus that has long been a domesticated crop plant grown in agricultural economies throughout arid and semiarid parts of the world. O.","img":"images/620.jpg","thumb":"images/t/620.jpg","file":"Dikenli İncir (Opuntia ficus-indica) Gaziantep Turkey.IMG 1104.jpg","ar":0.75,"py":"liguoxianrenzhang lgxrz","cr_by":"YG01","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"多肉","origin":["亚洲"],"illus_img":"images/i/620.jpg","illus_thumb":"images/i/t/620.jpg","illus_file":"Opuntia ficus-indica - Flora von Deutschland (Pl. 355).jpg","illus_ar":0.703,"illus_by":"Migula, Walter; Thomé, Otto W.","illus_lic":"Public domain","illus_licurl":null},{"id":621,"seq":632,"zh":"巨人柱","en":"Carnegiea gigantea","sci":"Carnegiea gigantea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":55,"desc_zh":"巨人柱（学名：Carnegiea gigantea）是仙人掌科巨人柱属（Carnegiea）的唯一物种，也是世界最高的仙人掌品种之一，高度可超过12公尺。原产于墨西哥的索诺拉州、美国亚利桑那州的索诺拉沙漠以及加利福尼亚州的惠普尔山脉和帝国郡。巨人柱的花为亚利桑那州的州花。其学名是为了纪念美国企业家暨慈善家安德鲁·卡内基而起。1994年，巨人柱国家公园于亚利桑那州土桑设立，致力于保育巨人柱以及其栖地。","desc_en":"The saguaro ( sə-(G)WAR-oh, Spanish: [saˈɣwaɾo]; Carnegiea gigantea) is a tree-like cactus species in the monotypic genus Carnegiea that can grow to be over 12 meters (40 feet) tall.","img":"images/621.jpg","thumb":"images/t/621.jpg","file":"CarnegieaGigantea.jpg","ar":0.75,"py":"jurenzhu jrz","cr_by":"RoFra","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"多肉","origin":["北美洲"]},{"id":622,"seq":633,"zh":"乌羽玉","en":"Lophophora williamsii","sci":"Lophophora williamsii","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":55,"desc_zh":"乌羽玉（学名：Lophophora williamsii），音译配有特（英语：Peyote），又称作威廉斯氏仙人球，俗称无刺的仙人掌，是一种细小及无刺的仙人掌。它们原产于美国德克萨斯州西南部至墨西哥，主要在奇瓦瓦沙漠、塔毛利帕斯州及圣路易斯波托西州生长。 乌羽玉及其同属的银冠玉均含有精神生物碱，如麦司卡林（三甲氧苯乙胺）等，会使人产生幻觉。故被用在宗教致幻剂及多种宗教超越上，包括冥想及迷幻药治疗法等。","desc_en":"Peyote, also known as Lophophora williamsii, is a small, spineless cactus which contains psychoactive alkaloids, particularly mescaline. Peyote is a Spanish word derived from the Nahuatl peyōtl, meaning \"caterpillar cocoon\", from a root peyōni, \"to glisten\".","img":"images/622.jpg","thumb":"images/t/622.jpg","file":"Peyote Cactus.jpg","ar":1.506,"py":"wuyuyu wyy","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":["北美洲"]},{"id":623,"seq":634,"zh":"金琥","en":"Kroenleinia grusonii","sci":"Kroenleinia grusonii","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":null,"langs":32,"desc_zh":"金鯱（学名：Echinocactus grusonii），又称象牙球、金鯱仙人球，是强刺球类仙人掌的代表，原产墨西哥中部圣路易波托西至伊达尔戈干燥炎热的沙漠地带。金鯱虽然在观赏植物市场中很普遍，但野生的金鯱却是濒危的稀有植物。 本种是仙人掌类中最具魅力的一类植物。它拥有浑圆碧绿的球体及钢硬的金黄色硬刺。球体的直径可达1米左右，球体顶部密生一圈金黄色的绒毛。金鯱顶部有21-27个棱脊高耸的直棱(一般仙人球只有棱12-14个)。","desc_en":"Kroenleinia grusonii, popularly known as the golden barrel cactus, golden ball, \"mother-in-law's cushion\" or \"mother-in-law's chair\", is a species of barrel cactus which is endemic to east-central Mexico.","img":"images/623.jpg","thumb":"images/t/623.jpg","file":"Echinocactus grusonii (aka).jpg","ar":1.08,"py":"jinhu jh","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"多肉","origin":["北美洲"]},{"id":624,"seq":635,"zh":"昙花","en":"Epiphyllum oxypetalum","sci":"Epiphyllum oxypetalum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":29,"desc_zh":"昙花（学名：Epiphyllum oxypetalum）也叫月下美人，是仙人掌科昙花属的一个种，原产墨西哥南部和中美洲。","desc_en":"Epiphyllum oxypetalum, the Dutchman's pipe cactus, princess of the night or queen of the night, is a species of cactus with a native range from Mexico to Nicaragua. It blooms nocturnally, and its flowers wilt before dawn.","img":"images/624.jpg","thumb":"images/t/624.jpg","file":"Nightblooming cereum.JPG","ar":1.501,"py":"tanhua th","cr_by":"Bobjgalindo","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["北美洲"]},{"id":625,"seq":636,"zh":"量天尺","en":"Selenicereus undatus","sci":"Selenicereus undatus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":null,"langs":28,"desc_zh":"量天尺（学名：Selenicereus undatus；异名：Hylocereus undatus），是仙人掌科蛇鞭柱属（旧属量天尺属）的植物。原产墨西哥南部及中美洲，现已在全球热带及亚热带地区广泛栽培，在澳大利亚、夏威夷、中国大陆（福建、广东、海南、广西）以及台湾等地归化，以气根攀缘于树干、岩石或墙壁上。","desc_en":"Selenicereus undatus, the white-fleshed pitahaya, is a species of the genus Selenicereus (formerly Hylocereus) in the family Cactaceae and is the most cultivated species in the genus.","img":"images/625.jpg","thumb":"images/t/625.jpg","file":"Selenicereus undatus 173646842.jpeg","ar":0.563,"py":"liangtianchi ltc","cr_by":"Tiago Lubiana","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"多肉","origin":null},{"id":626,"seq":637,"zh":"星叶球","en":"Astrophytum asterias","sci":"Astrophytum asterias","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":26,"desc_zh":"星球（学名：Astrophytum asterias），又称星红仙人球、星叶球或兜，是一种无针的仙人掌，属于仙人掌科有星属。它们细小，直径长5-15厘米，高2-5厘米。在野外生长的，整个夏天都会开花。 星红仙人球的成熟期很长，并被列为易危。它们的衰落是因过度采集所致，城市化及除草剂的使用也有影响。幸运的是它们可以种子传播，虽然在野外已很稀少，但仍可靠种植来保存。它们现已有多个的栽培种，其中包括有很多斑点的「超兜」。","desc_en":"Astrophytum asterias is a species of cactus in the genus Astrophytum, and is native to small parts of Texas in the United States and Mexico. Common names include sand dollar cactus, sea urchin cactus, star cactus and star peyote.","img":"images/626.jpg","thumb":"images/t/626.jpg","file":"Astrophytum asterias11.jpg","ar":1.333,"py":"xingyeqiu xyq","cr_by":"GaleoC","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":["北美洲"]},{"id":627,"seq":638,"zh":"蛇鞭柱","en":"Selenicereus grandiflorus","sci":"Selenicereus grandiflorus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":26,"desc_zh":"蛇鞭柱（学名：Selenicereus grandiflorus）是仙人掌科蛇鞭柱属的模式种，也叫大花蛇鞭柱（其种加词grandiflorus意为“大花的”），原产墨西哥、中美洲和加勒比地区。蛇鞭柱和昙花一样只在夜晚开花。","desc_en":"Selenicereus grandiflorus is a cactus species originating from the Antilles, Mexico and Central America. The species is commonly referred to as queen of the night, night-blooming cereus (though these two terms are also used for other species), large-flowered c…","img":"images/627.jpg","thumb":"images/t/627.jpg","file":"Johann Jacob Haid Cereus.jpg","ar":0.689,"py":"shebianzhu sbz","cr_by":"Johann Jakob Haid","cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":["北美洲"],"illus_img":"images/i/627.jpg","illus_thumb":"images/i/t/627.jpg","illus_file":"Selenicereus grandiflorus. Norton, E.H., Brazilian flowers, drawn from nature in the years 1880-1882 in the neighbourhood of Rio de Janeiro, t. 38 (1893).tiff","illus_ar":0.749,"illus_by":"E. H. Norton","illus_lic":"Public domain","illus_licurl":null},{"id":628,"seq":639,"zh":"蟹爪兰","en":"Schlumbergera truncata","sci":"Schlumbergera truncata","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":25,"desc_zh":"蟹爪兰（学名：Schlumbergera truncata）又称螃蟹兰、感恩节仙人掌（英语：Thanksgiving cactus），是一种附生性小灌木，属双子叶植物石竹目仙人掌科仙人指属植物。其节径连接形状如螃蟹的副爪，故名蟹爪兰，但并非兰科物种。","desc_en":"Schlumbergera truncata, the false Christmas cactus, is a species of plant in the family Cactaceae. It is endemic to a small area of the coastal mountains of south-eastern Brazil where its natural habitats are subtropical or tropical moist forests.","img":"images/628.jpg","thumb":"images/t/628.jpg","file":"Schlumbergera Truncata.jpg","ar":1.333,"py":"xiezhualan xzl","cr_by":"JennTM","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["南美洲"]},{"id":629,"seq":640,"zh":"圣佩德罗仙人掌","en":"Echinopsis pachanoi","sci":"Echinopsis pachanoi","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":24,"desc_zh":null,"desc_en":"Echinopsis pachanoi, synonyms including Trichocereus pachanoi and Trichocereus macrogonus var. pachanoi, is a fast-growing columnar cactus found in the Andes at 2,000–3,000 m (6,600–9,800 ft) in altitude.","img":"images/629.jpg","thumb":"images/t/629.jpg","file":"Starr 070320-5799 Echinopsis pachanoi.jpg","ar":0.75,"py":"shengpeideluoxianrenzhang spdlxrz","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"多肉","origin":["欧洲","非洲","南美洲"]},{"id":635,"seq":641,"zh":"康乃馨","en":"Dianthus caryophyllus","sci":"Dianthus caryophyllus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":78,"desc_zh":"香石竹（学名：Dianthus caryophyllus）又称剪绒花、洛阳花、康乃馨、狮头石竹、麝香石竹、大花石竹、荷兰石竹，为石竹科石竹属的植物，分布于欧洲温带以及中国大陆的福建、湖北等地，原产于地中海地区，是目前世界上应用最普遍的花卉之一。康乃馨包括许多变种与杂交种，在温室里几乎可以连续不断开花。1907年起，开始以粉红色康乃馨作为母亲节的象征，故今常被作为献给母亲的花。","desc_en":"Dianthus caryophyllus ( dy-AN-thəs KAIR-ee-ə-FIL-əs), commonly known as carnation or clove pink, is a species of Dianthus native to the Mediterranean region.","img":"images/635.jpg","thumb":"images/t/635.jpg","file":"Gartennelke 1.jpg","ar":0.772,"py":"kangnaixin knx","cr_by":"Darkone ( talk · contribs )","cr_lic":"CC BY-SA 1.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/1.0","habit":null,"origin":["欧洲"]},{"id":636,"seq":642,"zh":"繁缕","en":"Stellaria media","sci":"Stellaria media","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":66,"desc_zh":"繁缕（学名：Stellaria media）属石竹科繁缕属植物，为原野杂草。其种加词“media”意为“中间的”。","desc_en":"Stellaria media, chickweed, is an annual flowering plant in the family Caryophyllaceae. It is native to Eurasia and naturalized throughout the world, where it is a weed of waste ground, farmland and gardens.","img":"images/636.jpg","thumb":"images/t/636.jpg","file":"Chickweed (aka).jpg","ar":0.856,"py":"fanl fl","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲"],"illus_img":"images/i/636.jpg","illus_thumb":"images/i/t/636.jpg","illus_file":"Stellaria media - Billeder af nordens flora (1917) (19750123373).jpg","illus_ar":0.702,"illus_by":"Mentz, August","illus_lic":"Public domain","illus_licurl":null},{"id":637,"seq":643,"zh":"麦仙翁","en":"Agrostemma githago","sci":"Agrostemma githago","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":60,"desc_zh":"麦仙翁（学名：Agrostemma githago）是石竹科麦仙翁属的植物。分布于亚洲、非洲、欧洲、北美以及中国大陆的内蒙古、吉林、新疆、黑龙江等地，生长于海拔100米至500米的地区，多生长在麦田中及路旁草地，目前已经做为观赏植物栽培。","desc_en":"Agrostemma githago, the common corn-cockle (also written \"corncockle\"), is a herbaceous annual flowering plant a member of Caryophyllaceae, also called the pink family or the carnation family of plants.","img":"images/637.jpg","thumb":"images/t/637.jpg","file":"Agrostemma githago 120605.jpg","ar":1.157,"py":"maixianweng mxw","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":null,"illus_img":"images/i/637.jpg","illus_thumb":"images/i/t/637.jpg","illus_file":"Agrostemma githago Sturm17.jpg","illus_ar":0.659,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":638,"seq":644,"zh":"白玉草","en":"Silene vulgaris","sci":"Silene vulgaris","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":"LC","langs":60,"desc_zh":"白玉草（学名：Silene vulgaris）是石竹科蝇子草属的植物。分布于欧洲、蒙古、伊朗、土耳其、非洲、印度、尼泊尔以及中国大陆的黑龙江、西藏、内蒙古、新疆等地，生长于海拔150米至2,700米的地区，一般生于草甸、林下多砾石的草地、灌丛中及撂荒地，目前尚未由人工引种栽培。","desc_en":"Silene vulgaris, the bladder campion or maidenstears, is a plant species of the genus Silene within the family Caryophyllaceae. Native to the Old World, the plant has been naturalized elsewhere, including North America. The young shoots and leaves are edible.","img":"images/638.jpg","thumb":"images/t/638.jpg","file":"SileneVulgaris-bloem.jpg","ar":1.333,"py":"baiyucao byc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":639,"seq":645,"zh":"肥皂草","en":"Saponaria officinalis","sci":"Saponaria officinalis","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":52,"desc_zh":"肥皂草（学名：Saponaria officinalis）为石竹科肥皂草属的一种草本植物，广泛分布于欧亚大陆。 肥皂草在地中海沿岸有野生，我国北方栽培较多，在部分地区已逸生。开花时，其根中的皂素含量可达20%。","desc_en":"Saponaria officinalis is a common perennial plant from the family Caryophyllaceae. This plant has many common names, including common soapwort, bouncing-bet, crow soap, and soapweed. There are about 20 species of soapworts altogether.","img":"images/639.jpg","thumb":"images/t/639.jpg","file":"Saponaria-officinalis-flower.jpg","ar":1.333,"py":"feizaocao fzc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"],"illus_img":"images/i/639.jpg","illus_thumb":"images/i/t/639.jpg","illus_file":"Saponaria officinalis — Flora Batava — Volume v10.jpg","illus_ar":0.801,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":640,"seq":646,"zh":"须苞石竹","en":"Dianthus barbatus","sci":"Dianthus barbatus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":46,"desc_zh":"须苞石竹（学名：Dianthus barbatus）也叫美国石竹（华北经济植物志要）、十样锦（江苏南部种子植物手册）、五彩石竹（北京植物志），为石竹科石竹属的植物，原产欧洲（原变种）、东北亚（头石竹）。","desc_en":"Dianthus barbatus, the sweet William, is a species of flowering plant in the family Caryophyllaceae, native to southern Europe and parts of Asia. It has become a popular ornamental garden plant.","img":"images/640.jpg","thumb":"images/t/640.jpg","file":"Dianthus barbatus PID1688-4.jpg","ar":0.75,"py":"xubaoshizhu xbsz","cr_by":"Benjamin Zwittnig","cr_lic":"CC BY 2.5 si","cr_licurl":"https://creativecommons.org/licenses/by/2.5/si/deed.en","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/640.jpg","illus_thumb":"images/i/t/640.jpg","illus_file":"Dianthus barbatus — Flora Batava — Volume v12.jpg","illus_ar":0.708,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":644,"seq":647,"zh":"菠菜","en":"Spinacia oleracea","sci":"Spinacia oleracea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":134,"desc_zh":"菠菜（学名：Spinacia oleracea），又称菠薐、波斯草、赤根菜，是苋科菠菜属的一年生或二年生草本植物。是一种重要的绿叶蔬菜，在全球范围内广泛栽培和食用。菠菜的叶片柔嫩多汁，富含维生素、矿物质和抗氧化物，具有很高的营养价值和药用潜力。","desc_en":"Spinach (Spinacia oleracea) is a leafy green flowering plant native to Central and Western Asia. It is of the order Caryophyllales, family Amaranthaceae, subfamily Chenopodioideae.","img":"images/644.jpg","thumb":"images/t/644.jpg","file":"Spinacia oleracea Spinazie bloeiend.jpg","ar":0.767,"py":"bocai bc","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"],"illus_img":"images/i/644.jpg","illus_thumb":"images/i/t/644.jpg","illus_file":"Illustration Spinacia oleracea1.jpg","illus_ar":0.623,"illus_by":"Otto Wilhelm Thom&eacute","illus_lic":"Public domain","illus_licurl":null},{"id":645,"seq":648,"zh":"甜菜","en":"Beta vulgaris","sci":"Beta vulgaris","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":98,"desc_zh":"甜菜（学名：Beta vulgaris；英语：beetroot）又名菾菜或红菜，为苋科甜菜属下的一个种。原产于欧洲西部和南部沿海，从瑞典直到西班牙，是热带甘蔗以外的一个主要糖来源。叶子也是一种蔬菜。","desc_en":"Beta vulgaris (beet) is a species of flowering plant in the subfamily Betoideae of the family Amaranthaceae. It is a perennial plant usually growing up to 120 centimetres (4 ft) tall. Three subspecies are typically recognised.","img":"images/645.jpg","thumb":"images/t/645.jpg","file":"Beta vulgaris - Köhler–s Medizinal-Pflanzen-167.jpg","ar":0.803,"py":"tiancai tc","cr_by":"Walther Otto Müller","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/645.jpg","illus_thumb":"images/i/t/645.jpg","illus_file":"Beta vulgaris (Köhler).jpg","illus_ar":0.75,"illus_by":"Franz Eugen Köhler","illus_lic":"CC BY 2.5","illus_licurl":"https://creativecommons.org/licenses/by/2.5"},{"id":646,"seq":649,"zh":"藜麦","en":"Chenopodium quinoa","sci":"Chenopodium quinoa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":75,"desc_zh":"藜（lí）麦（学名：Chenopodium quinoa，又称昆诺阿藜、奎奴亚藜、奎藜，俗称印地安麦、灰米或小小米，是苋科藜属植物，与小麦无关且不属于谷物类，为南美洲高地特有的一年生植物。 作为人类主要粮食的谷物大多属于禾本科，而藜麦则属于苋科，所以被称作「准谷物」。在藜麦中完全成熟并散发出艳红光泽的可称为红藜麦，为一种代替谷物的健康食品。","desc_en":"Quinoa (Chenopodium quinoa; , from Quechua kinwa or kinuwa) is a flowering plant in the amaranth family. It is an herbaceous annual plant grown as a crop primarily for its edible seeds; the seeds are high in protein, dietary fiber, B vitamins and dietary miner…","img":"images/646.jpg","thumb":"images/t/646.jpg","file":"Quinua.JPG","ar":1.533,"py":"limai lm","cr_by":"Maurice Chédel","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["南美洲"]},{"id":647,"seq":650,"zh":"藜","en":"Chenopodium album","sci":"Chenopodium album","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":75,"desc_zh":"藜（学名：Chenopodium album）为苋科藜属的植物。分布于全球温带及热带各地，生长于海拔50米至4,200米的地区，见于路旁、荒地及田间。","desc_en":"Chenopodium album is a fast-growing annual plant in the flowering plant family Amaranthaceae. Though cultivated in some regions, the plant is elsewhere considered a weed.","img":"images/647.jpg","thumb":"images/t/647.jpg","file":"Melganzenvoet bloeiwijze Chenopodium album.jpg","ar":0.664,"py":"li l","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/647.jpg","illus_thumb":"images/i/t/647.jpg","illus_file":"Chenopodium album Lindman DESC.jpg","illus_ar":1.51,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":648,"seq":651,"zh":"青葙","en":"Celosia argentea","sci":"Celosia argentea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":"LC","langs":52,"desc_zh":"青葙（学名：Celosia argentea）是苋科青葙属的一种植物。青葙为中药药材，名为青葙子的种子有清肝明目的作用。全株可做，饲料。幼嫩茎叶浸去苦味后，可作野菜食用。种子炒熟亦可加工制作各种糖食。此外，青葙花序宿存经久不凋，可供观赏。","desc_en":"Celosia argentea, commonly known as the plumed cockscomb or silver cock's comb, is a herbaceous plant of tropical origin in the family Amaranthaceae from tropical Africa. The plant is known for its very bright colors.","img":"images/648.jpg","thumb":"images/t/648.jpg","file":"Celosia argentea (Silver cockscomb) W IMG 0985.jpg","ar":0.823,"py":"qingxiang qx","cr_by":"J.M.Garg","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["非洲"]},{"id":649,"seq":652,"zh":"土荆芥","en":"Dysphania ambrosioides","sci":"Dysphania ambrosioides","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":48,"desc_zh":"土荆芥（学名：Dysphania ambrosioides），又名臭杏、臭草、杀虫芥、鸭脚草。是苋科刺藜属的植物。","desc_en":"Dysphania ambrosioides, formerly Chenopodium ambrosioides, known as epazote, Jesuit's tea, Mexican tea or wormseed, is an annual or short-lived perennial herb native to the Americas.","img":"images/649.jpg","thumb":"images/t/649.jpg","file":"Dysphania ambrosioides Blanco1.69.jpg","ar":0.701,"py":"tujingjie tjj","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":653,"seq":653,"zh":"荞麦","en":"Fagopyrum esculentum","sci":"Fagopyrum esculentum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":104,"desc_zh":"荞麦（学名：Fagopyrum esculentum，英语：buckwheat）亦作普通荞麦（common buckwheat）以跟其他同属物种区别，是蓼科荞麦属的植物，也有人将其分入蓼属，它是一种双子叶植物。 普通荞麦和同属的苦荞麦（F. tataricum Gaertn）、金荞麦（F. dibotrys H.Hara），在汉语与英语均称「麦」（wheat），且都可作粮食，但与其他粮食作物不同的是，它们不属于禾本科。","desc_en":"Buckwheat (Fagopyrum esculentum) or common buckwheat is a flowering plant in the knotweed family Polygonaceae cultivated for its grain-like seeds and as a cover crop.","img":"images/653.jpg","thumb":"images/t/653.jpg","file":"Illustration Fagopyrum esculentum0.jpg","ar":0.606,"py":"qiaomai qm","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"],"illus_img":"images/i/653.jpg","illus_thumb":"images/i/t/653.jpg","illus_file":"Illustration Fagopyrum esculentum0.jpg","illus_ar":0.606,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":654,"seq":654,"zh":"酸模","en":"Rumex acetosa","sci":"Rumex acetosa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":83,"desc_zh":"酸模（学名：Rumex acetosa），又名蕦、薞芜，蓼科多年生草本植物，欧洲和西亚大多数的草原均可见到其踪迹。酸模含有丰富的维他命A、维他命C及草酸，草酸导致此植物尝起来有酸溜口味，常作料理调味用。酸模亦具药用价值，有利尿、发汗、行血等功效。","desc_en":"Sorrel (Rumex acetosa) is a perennial herbaceous plant in the family Polygonaceae. It is also called common sorrel, meadow sorrel, green sorrel, sour dock, spinach dock and narrow-leaved dock (\"dock\" often used for the genus).","img":"images/654.jpg","thumb":"images/t/654.jpg","file":"20150423Rumex acetosa4.jpg","ar":0.75,"py":"suanmo sm","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲"],"illus_img":"images/i/654.png","illus_thumb":"images/i/t/654.png","illus_file":"Rumex acetosa (Reichenbach 1909, vol.24 0339) clean, no-description, squared.png","illus_ar":1,"illus_by":"Reichenbach, Heinrich Gottlieb Ludwig; Reichenbach, Heinrich Gustav;","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":655,"seq":655,"zh":"萹蓄","en":"Polygonum aviculare","sci":"Polygonum aviculare","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":64,"desc_zh":"萹蓄（学名：Polygonum aviculare），又名𦺇（音同“毒”），为蓼科萹蓄属下的一种一年生草本植物，高10—40 cm（3.9—15.7英寸），原产于北半球温带地区，后来也引入南半球。它可以入中药，《神农本草经》记载它“味苦，平”。","desc_en":"Polygonum aviculare or common knotgrass is a plant related to buckwheat and dock. It is also called prostrate knotweed, birdweed, pigweed and lowgrass. It is an annual found in fields and wasteland, with white flowers from June to October.","img":"images/655.jpg","thumb":"images/t/655.jpg","file":"Polygonum aviculare 4.JPG","ar":0.667,"py":"bianxu bx","cr_by":"Dalgial","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/655.jpg","illus_thumb":"images/i/t/655.jpg","illus_file":"Polygonum aviculare — Flora Batava — Volume v3.jpg","illus_ar":0.693,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":656,"seq":656,"zh":"水蓼","en":"Persicaria hydropiper","sci":"Persicaria hydropiper","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":"LC","langs":56,"desc_zh":"水蓼（学名：Persicaria hydropiper；同义词：Polygonum hydropiper）是一种蓼科春蓼属植物，也称辣蓼。","desc_en":"Persicaria hydropiper (syn. Polygonum hydropiper), also known as water pepper, marshpepper knotweed, arse smart or tade, is a plant of the family Polygonaceae.","img":"images/656.jpg","thumb":"images/t/656.jpg","file":"Polygonum hydropiper1.jpg","ar":0.75,"py":"shuiliao sl","cr_by":"No machine-readable author provided. Aroche assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","北美洲","大洋洲"]},{"id":657,"seq":657,"zh":"春蓼","en":"Persicaria maculosa","sci":"Persicaria maculosa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":"LC","langs":56,"desc_zh":"春蓼（学名：Persicaria maculosa 或 Polygonum persicaria），为蓼科春蓼属下的一个种。","desc_en":"Persicaria maculosa (syn. Polygonum persicaria) is an annual plant in the buckwheat family, Polygonaceae. Common names include lady's thumb, spotted lady's thumb, Jesusplant, and redshank.","img":"images/657.jpg","thumb":"images/t/657.jpg","file":"PolygonumPersicara-plant-sm.jpg","ar":1.333,"py":"chunliao cl","cr_by":"TeunSpaans at Dutch Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"],"illus_img":"images/i/657.jpg","illus_thumb":"images/i/t/657.jpg","illus_file":"Polygonum persicaria (modern=Persicaria maculosa) - Pl0124 - FloraBatava-KB-v02.jpg","illus_ar":0.799,"illus_by":"Georgius Jacobus Johannes van Os","illus_lic":"Public domain","illus_licurl":null},{"id":659,"seq":658,"zh":"番杏","en":"Tetragonia tetragonoides","sci":"Tetragonia tetragonoides","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":33,"desc_zh":"番杏（学名：Tetragonia tetragonioides (Pall.) Kuntze）是番杏科番杏属的植物，又名法国菠菜、新西兰菠菜、洋菠菜、夏菠菜、滨莴苣、蔓菜、白番杏、白红菜。耐盐性强，在海水灌溉下仍然可以正常完成生活史。","desc_en":"Tetragonia tetragonioides, commonly called New Zealand spinach, warrigal greens or by its Māori name of Kōkihi, is a flowering plant in the fig-marigold family (Aizoaceae). It is often cultivated as a leafy vegetable.","img":"images/659.jpg","thumb":"images/t/659.jpg","file":"Tetragonia tetragonioides (Flower).jpg","ar":0.75,"py":"fanxing fx","cr_by":"Ixitixel","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","大洋洲"]},{"id":660,"seq":659,"zh":"莫邪菊","en":"Carpobrotus edulis","sci":"Carpobrotus edulis","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":30,"desc_zh":"食用日中花（学名：Carpobrotus edule）为番杏科莫邪菊属下的一个种。叶和果可食用。 本物种原产于南非，且为黑鼠的花朵，因此借着黑鼠食用后随同其粪便的传播，目前已透过人类扩散至世界多处，主要为地中海地区、澳大利亚及纽西兰等气候相近的地区，且被视为入侵物种。","desc_en":"Carpobrotus edulis is a creeping plant with succulent leaves in the fig-marigold family Aizoaceae, native to South Africa. Its common names include hottentot-fig, sour fig, ice plant, highway ice plant, or vygie.","img":"images/660.jpg","thumb":"images/t/660.jpg","file":"Carpobrutus edulis b.JPG","ar":1.333,"py":"moxieju mxj","cr_by":"Taken by Carsten Niehaus ( user:Lumbar ).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"多肉","origin":["非洲"]},{"id":661,"seq":660,"zh":"冰叶日中花","en":"Mesembryanthemum crystallinum","sci":"Mesembryanthemum crystallinum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":27,"desc_zh":"冰叶日中花（学名：Mesembryanthemum crystallinum），又名冰花、冰草、水晶冰菜、冰菜或冰叶菜，为番杏科日中花属下的一个物种，是一种常为一年生的匍匐型多肉植物。原生于非洲大陆、西奈半岛及欧洲南部，而北美洲、南美洲及澳大利亚则有野外归化居群。 冰叶日中花的植株表面覆盖著大而闪亮的透明囊状细胞，形如冰晶，因而得名。","desc_en":"Mesembryanthemum crystallinum (the common, 'crystalline' or 'crystallinum' iceplant, or simply 'iceplant') is a species of annual/perennial, succulent flowering plant in the Mesembryanthemum genus of the Aizoaceae family.","img":"images/661.jpg","thumb":"images/t/661.jpg","file":"Unk desert flower 2.jpg","ar":1.333,"py":"bingyerizhonghua byrzh","cr_by":"Yummifruitbat","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["亚洲","欧洲","非洲"]},{"id":662,"seq":661,"zh":"海马齿","en":"Sesuvium portulacastrum","sci":"Sesuvium portulacastrum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":"LC","langs":26,"desc_zh":"海马齿（学名：Sesuvium portulacastrum）为番杏科海马齿属的植物。分布于全球热带和亚热带海岸、台湾岛以及中国大陆的广东、东沙岛、福建、海南等地，一般生于近海岸的沙地上。","desc_en":"Sesuvium portulacastrum is a sprawling perennial herb in the family Aizoaceae that grows in coastal and mangrove areas throughout much of the world. It grows in sandy clay, coastal limestone and sandstone, tidal flats and salt marshes, throughout much of the w…","img":"images/662.jpg","thumb":"images/t/662.jpg","file":"Sesuvium p.jpg","ar":1.204,"py":"haimachi hmc","cr_by":"by Eric Guinther ( Marshman at en.wikipedia )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","非洲","北美洲","南美洲","大洋洲"]},{"id":663,"seq":662,"zh":"心叶日中花","en":"Mesembryanthemum cordifolium","sci":"Mesembryanthemum cordifolium","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":23,"desc_zh":"心叶日中花（学名：Mesembryanthemum cordifolium），又名心叶日中花、太阳玫瑰，为番杏科露草属下的一种多年生常绿草本。原产非洲南部。","desc_en":"Mesembryanthemum cordifolium, formerly known as Aptenia cordifolia, is a species of succulent plant in the family Aizoaceae. It is a creeping plant that forms a carpet of flat-growing perennial herbs in groups on the ground from a base.","img":"images/663.jpg","thumb":"images/t/663.jpg","file":"Растения в Седово 109.JPG","ar":1.333,"py":"xinyerizhonghua xyrzh","cr_by":"Andrey Butko","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":null},{"id":665,"seq":663,"zh":"紫茉莉","en":"Mirabilis jalapa","sci":"Mirabilis jalapa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Nyctaginaceae","family_zh":"紫茉莉科","iucn":null,"langs":62,"desc_zh":"紫茉莉（学名：Mirabilis jalapa）别名地雷花、粉豆花、烟粉豆、粉果花、茉莲子、草茉莉、夜娇娇、夜晚花、夜来香、胭脂花、胭粉豆、洗澡花、煮饭花、做饭花、晚饭花、烧汤花、白粉花、潮来花、素香、五点红、喇叭花、老爷儿没、状元花等，属紫茉莉科植物。","desc_en":"Mirabilis jalapa, the marvel of Peru or four o'clock flower, is the most commonly grown ornamental species of Mirabilis plant, and is available in a range of colors.","img":"images/665.jpg","thumb":"images/t/665.jpg","file":"2006-10-18Mirabilis jalapa06.jpg","ar":1.343,"py":"zimoli zml","cr_by":"Wildfeuer","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["北美洲","南美洲"]},{"id":666,"seq":664,"zh":"光叶子花","en":"Bougainvillea glabra","sci":"Bougainvillea glabra","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Nyctaginaceae","family_zh":"紫茉莉科","iucn":"LC","langs":25,"desc_zh":"光叶子花（学名：Bougainvillea glabra）又名小叶九重葛、簕杜鹃、宝巾、三角梅、紫三角、紫亚兰、三角花等，为紫茉莉科叶子花属下的一个物种，是中国深圳、厦门和珠海的市花以及海南省的省花。","desc_en":"Bougainvillea glabra, the lesser bougainvillea or paperflower, is the most common species of bougainvillea used for bonsai. The epithet 'glabra' comes from Latin and means \"bald\".","img":"images/666.jpg","thumb":"images/t/666.jpg","file":"Flor de Santa Rita (Bougainvillea glabra) una especie de planta trepadora de la familia de las Nyctaginaceae (sobre Ruta Provincial 7, municipio de Ruiz de Montoya, Provincia de Misiones, República Argentina).jpg","ar":1.778,"py":"guangyezihua gyzh","cr_by":"Horacio Cambeiro","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":null},{"id":1180,"seq":665,"zh":"黄细心","en":"Boerhavia diffusa","sci":"Boerhavia diffusa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Nyctaginaceae","family_zh":"紫茉莉科","iucn":null,"langs":25,"desc_zh":"黄细心（学名：Boerhavia diffusa）为紫茉莉科黄细心属下的一个种。其分布十分广泛，包括印度、太平洋诸岛和美国南部都能找到其踪迹，在印度它被称为punarnava，被认为有使人年轻的力量。","desc_en":"Boerhavia diffusa is a species of flowering plant in the four o'clock family which is commonly known as punarnava (meaning that which rejuvenates or renews the body in Ayurveda), red spiderling, spreading hogweed, or tarvine.","img":"images/1180.jpg","thumb":"images/t/1180.jpg","file":"Boerhaavia diffusa.jpg","ar":1.168,"py":"huangxixin hxx","cr_by":"Neha.Vindhya","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":667,"seq":666,"zh":"捕蝇草","en":"Dionaea muscipula","sci":"Dionaea muscipula","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Droseraceae","family_zh":"茅膏菜科","iucn":"VU","langs":71,"desc_zh":"捕蝇草（学名：Dionaea muscipula）是原产于北美洲的一种多年生草本植物。据说因为叶片边缘会有规则的刺毛，那种感觉就像维纳斯的睫毛一般，所以英文名称为Venus Flytrap，意思是「维纳斯的捕蝇陷阱」。中文及日文对捕蝇草还有「苍蝇的地狱」（ハエジゴク）这个别名。其主要特征就是能够迅速的关闭叶片捕食昆虫，这是种和其远亲猪笼草一样的食肉植物之一，在茅膏菜科捕蝇草属中仅此一种。捕蝇草于生态系中属生产者及消费者。","desc_en":"The Venus flytrap (Dionaea muscipula) is a carnivorous plant native to the temperate and subtropical wetlands of North Carolina and South Carolina, on the East Coast of the United States. Although various modern hybrids have been created in cultivation, D.","img":"images/667.jpg","thumb":"images/t/667.jpg","file":"Venus Flytrap Dionaea muscipula (26455092815).jpg","ar":0.78,"py":"buyingcao byc","cr_by":"Len Worthington","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["北美洲"]},{"id":668,"seq":667,"zh":"圆叶茅膏菜","en":"Drosera rotundifolia","sci":"Drosera rotundifolia","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Droseraceae","family_zh":"茅膏菜科","iucn":"LC","langs":56,"desc_zh":"圆叶茅膏菜（学名：Drosera rotundifolia），又及圆叶毛毡苔，是肉食性茅膏菜的一种，一般会在泥沼、沼泽及潮湿地方可以见到。圆叶茅膏菜是最广泛分布的茅膏菜之一，主要是环北带的植物，在整个欧洲北部、西伯利亚大部份地区、北美洲北部、韩国、日本、甚至新畿内亚都可以见到它们。","desc_en":"Drosera rotundifolia, the round-leaved sundew, roundleaf sundew, or common sundew, is a species of carnivorous flowering plant that grows in bogs, marshes and fens.","img":"images/668.jpg","thumb":"images/t/668.jpg","file":"Drosera rotondifolia.JPG","ar":1.333,"py":"yuanyemaogaocai yymgc","cr_by":"association AMV","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","北美洲","大洋洲"],"illus_img":"images/i/668.jpg","illus_thumb":"images/i/t/668.jpg","illus_file":"Drosera rotundifolia chromolithograph.jpg","illus_ar":0.57,"illus_by":"Botanical Fine Art Weekly","illus_lic":"Public domain","illus_licurl":null},{"id":1181,"seq":668,"zh":"英国茅膏菜","en":"Drosera anglica","sci":"Drosera anglica","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Droseraceae","family_zh":"茅膏菜科","iucn":null,"langs":38,"desc_zh":null,"desc_en":"Drosera anglica, commonly known as the English sundew or great sundew, is a carnivorous flowering plant species belonging to the sundew family Droseraceae. It is a temperate species with a circumboreal range, although it does occur as far south as Japan, south…","img":"images/1181.jpg","thumb":"images/t/1181.jpg","file":"Drosera anglica ne1.JPG","ar":1.066,"py":"yingguomaogaocai ygmgc","cr_by":"No machine-readable author provided. NoahElhardt assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":669,"seq":669,"zh":"马齿苋","en":"Portulaca oleracea","sci":"Portulaca oleracea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Portulacaceae","family_zh":"马齿苋科","iucn":"LC","langs":92,"desc_zh":"马齿苋（学名：Portulaca oleracea），又名马生菜、马齿菜、马屎苋、五行草、酸苋、猪母乳、马勺菜、地马菜、马蛇子菜、长寿菜、老鼠耳、宝钏菜、蚂蚱菜，是马齿苋科马齿苋属植物。","desc_en":"Portulaca oleracea (common purslane, also known as little hogweed, or pursley) is a succulent plant in the family Portulacaceae. All parts of the plant are edible raw or cooked.","img":"images/669.jpg","thumb":"images/t/669.jpg","file":"Portulaca oleracea.JPG","ar":1.4,"py":"machixian mcx","cr_by":"ZooFari","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":null,"illus_img":"images/i/669.jpg","illus_thumb":"images/i/t/669.jpg","illus_file":"Illustration Portulaca oleracea0.jpg","illus_ar":0.63,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":670,"seq":670,"zh":"海石竹","en":"Armeria maritima","sci":"Armeria maritima","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Plumbaginaceae","family_zh":"白花丹科","iucn":null,"langs":38,"desc_zh":"海石竹（学名：Armeria maritima）为蓝雪科海石竹属下的一个种。","desc_en":"Armeria maritima, the thrift, sea thrift or sea pink, is a species of flowering plant in the family Plumbaginaceae. It is a compact evergreen perennial which grows in low clumps and sends up long stems that support globes of bright pink flowers.","img":"images/670.jpg","thumb":"images/t/670.jpg","file":"Zawciag nadmorski Ameria maritima maritima.jpg","ar":0.75,"py":"haishizhu hsz","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":671,"seq":671,"zh":"蓝花丹","en":"Plumbago auriculata","sci":"Plumbago auriculata","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Plumbaginaceae","family_zh":"白花丹科","iucn":null,"langs":33,"desc_zh":"蓝花丹（学名：Plumbago auriculata），又名蓝花矶松、花绣球、蓝茉莉，为蓝雪科半灌木。原产于非洲南部，在世界各地被广泛地作为观赏植物而栽种。种名auriculata意为耳形的，指代上部叶的叶柄基部常有小形半圆至长圆形的耳。园艺中，蓝花丹常与蓝雪花（Ceratostigma plumbaginoides）混淆。 蓝花丹为常绿柔弱半灌木，上端蔓状或极开散，高约1米或更长，除花序外无毛，被有细小的钙质颗粒。","desc_en":"Plumbago auriculata, the Cape leadwort, blue plumbago or Cape plumbago, is a species of flowering plant in the family Plumbaginaceae, native to South Africa and Mozambique.","img":"images/671.jpg","thumb":"images/t/671.jpg","file":"Plumbago.jpg","ar":1.333,"py":"lanhuadan lhd","cr_by":"No machine-readable author provided. Calvin Teo assumed (based on copyright claims).","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["非洲"]},{"id":1182,"seq":672,"zh":"乌面马","en":"Plumbago zeylanica","sci":"Plumbago zeylanica","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Plumbaginaceae","family_zh":"白花丹科","iucn":null,"langs":22,"desc_zh":"乌面马（学名：Plumbago zeylanica）为蓝雪科蓝雪属下的一个种。种名zeylanica意为斯里兰卡的。","desc_en":"Plumbago zeylanica, commonly known as Ceylon leadwort, doctorbush or wild leadwort, is a species of plumbago with a pantropical distribution. Carl Linnaeus described the paleotropical P. zeylanica and Neotropical P.","img":"images/1182.jpg","thumb":"images/t/1182.jpg","file":"Plumbago zeylanica1MTFL.jpg","ar":1.333,"py":"wumianma wmm","cr_by":"Bernard Loison","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null},{"id":1183,"seq":673,"zh":"Phaulothamnus spinescens","en":"Phaulothamnus spinescens","sci":"Phaulothamnus spinescens","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Achatocarpaceae","family_zh":"玛瑙果科","iucn":"LC","langs":8,"desc_zh":null,"desc_en":"Phaulothamnus is a genus of plants formerly included in the family Phytolaccaceae but now considered a part of the Achatocarpaceae. Only one species is recognized: Phaulothamnus spinescens A.","img":"images/1183.jpg","thumb":"images/t/1183.jpg","file":"Phaulothamnus spinescens (homeredwardprice) 001.jpg","ar":0.752,"py":"","cr_by":"homeredwardprice","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["北美洲"]},{"id":1184,"seq":674,"zh":"回欢草","en":"Anacampseros arachnoides","sci":"Anacampseros arachnoides","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Anacampserotaceae","family_zh":"回欢草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Anacampseros arachnoides is a species of succulent plant native to the Little Karoo region of South Africa.","img":"images/1184.jpg","thumb":"images/t/1184.jpg","file":"Anacampseros arachnoides - Zoo Plzeň, 1.jpg","ar":0.79,"py":"huihuancao hhc","cr_by":"Alex Hauner","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["非洲"],"illus_img":"images/i/1184.jpg","illus_thumb":"images/i/t/1184.jpg","illus_file":"Anacampseros arachnoides Curtis’s Botanical Magazine Plate 1368 Detail.jpg","illus_ar":0.39,"illus_by":"Sydenham Teast Edwards (1768–1819)","illus_lic":"Public domain","illus_licurl":null},{"id":1185,"seq":675,"zh":"海尼钩枝藤","en":"Ancistrocladus heyneanus","sci":"Ancistrocladus heyneanus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Ancistrocladaceae","family_zh":"钩枝藤科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Ancistrocladus heyneanus or kardal is a liana endemic to the Western Ghats of southwestern India. Leaves are alternate, oblong in shape, 10–25 cm long, margins are entire.","img":"images/1185.jpg","thumb":"images/t/1185.jpg","file":"Ancistrocladus heyneanus.jpg","ar":0.719,"py":"hainigouzhiteng hngzt","cr_by":"Vinayaraj","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲"]},{"id":1186,"seq":676,"zh":"Asteropeia labatii","en":"Asteropeia labatii","sci":"Asteropeia labatii","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Asteropeiaceae","family_zh":"翼萼茶科","iucn":"VU","langs":7,"desc_zh":null,"desc_en":"Asteropeia labatii is a species of plant in the Asteropeiaceae family. It is endemic to Madagascar. Its natural habitat is subtropical or tropical high-altitude shrubland. It is threatened by habitat loss.","img":"images/1186.jpg","thumb":"images/t/1186.jpg","file":"Asteropeia labatii 49433393.jpg","ar":1.499,"py":"","cr_by":"lallen","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["非洲"]},{"id":1187,"seq":677,"zh":"落葵","en":"Basella alba","sci":"Basella alba","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Basellaceae","family_zh":"落葵科","iucn":null,"langs":46,"desc_zh":"落葵（学名：Basella alba、Basella rubra）是落葵科落葵属的一年生藤蔓植物，其种加词“alba”意为“白色的”。是一种可供食用的蔬菜。《本草纲目》记载：「落葵三月种之，嫩苗可食。五月蔓延，其叶似杏叶而肥厚软滑，作蔬和肉皆宜。」传说为泰国皇宫指定为御用的菜肴，因此亦称皇宫菜，其他名称亦有：健康菜、紫角叶、胭脂菜、胭脂豆、蚕菜、木耳菜、天葵、胡臙脂、牛皮冻、𫊻公菜、𫊻管菜、𫊻菜、猬菜、软筋菜、软姜仔、藤菜、藤葵、…","desc_en":"Basella alba is a perennial vine in the family Basellaceae. It is also known by common names including Malabar spinach, vine spinach, Ceylon spinach, alugbati and Indian spinach.","img":"images/1187.jpg","thumb":"images/t/1187.jpg","file":"Arya.Basela Alba 1.Pilang.2019.jpg","ar":0.75,"py":"luokui lk","cr_by":"Aris riyanto","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"藤本","origin":["亚洲","大洋洲"]},{"id":1188,"seq":678,"zh":"树马齿苋","en":"Portulacaria afra","sci":"Portulacaria afra","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Didiereaceae","family_zh":"龙树科","iucn":"LC","langs":23,"desc_zh":"树马齿苋（学名：Portulacaria afra），又名马齿苋树、银杏木、金枝玉叶、小叶燕子掌、幸运树，是龙树科马齿苋树属植物，原产于南非。","desc_en":"Portulacaria afra (known as elephant bush, porkbush, purslane tree, dwarf jade and spekboom in Afrikaans) is a small-leaved succulent plant found in South Africa.","img":"images/1188.jpg","thumb":"images/t/1188.jpg","file":"Portulacaria afra 02.JPG","ar":1.333,"py":"shumachixian smcx","cr_by":"Dinkum","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"多肉","origin":["非洲"]},{"id":1189,"seq":679,"zh":"露松藤","en":"Triphyophyllum peltatum","sci":"Triphyophyllum peltatum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Dioncophyllaceae","family_zh":"双钩叶科","iucn":null,"langs":20,"desc_zh":"穗叶藤属（拉丁语：Triphyophyllum；标音：tɹɪfɪəʊfɪləm/ 或是 /tɹɪfɪɒfɪləm）为单型的植物属，相当于唯一的种类──盾籽穗叶藤（学名：Triphyophyllum peltatum）。本种原产于热带非洲西部、塞拉利昂以及赖比瑞亚，生长在热带雨林中。 现在仅3处植物园有栽培盾籽穗叶藤：阿必尚、波恩以及维尔茨堡。这个品种在私人收集中并不常见。","desc_en":"Triphyophyllum peltatum is a facultatively carnivorous, up to 60 m (200 ft) tall vine in the monotypic genus Triphyophyllum in the family Dioncophyllaceae native to tropical western Africa, in Guinea, Ivory Coast, Liberia, and Sierra Leone where it grows in tr…","img":"images/1189.jpg","thumb":"images/t/1189.jpg","file":"Triphyophyllum peltatum.jpg","ar":1.205,"py":"lusongteng lst","cr_by":"No machine-readable author provided. Denis Barthel assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["欧洲","非洲"]},{"id":1190,"seq":680,"zh":"瓣鳞花","en":"Frankenia pulverulenta","sci":"Frankenia pulverulenta","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Frankeniaceae","family_zh":"瓣鳞花科","iucn":null,"langs":15,"desc_zh":null,"desc_en":"Frankenia pulverulenta, the European seaheath, is a species of annual herb in the family Frankeniaceae. They have a self-supporting growth form and simple, broad leaves. Individuals can grow to 5 cm tall.","img":"images/1190.jpg","thumb":"images/t/1190.jpg","file":"Frankenia pulverulenta kz2.jpg","ar":1.501,"py":"banlinhua blh","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":1191,"seq":681,"zh":"非洲麻粟草","en":"Limeum africanum","sci":"Limeum africanum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Limeaceae","family_zh":"灯粟草科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Limeum africanum is a species of flowering plant in the genus Limeum. It is endemic to Southern Africa. It is also known by the names common lizardfoot and koggelmandervoet; Afrikaans for the foot of a lizard from the genus Agama.","img":"images/1191.jpg","thumb":"images/t/1191.jpg","file":"Limeum africanum.jpg","ar":1.405,"py":"feizhoumasucao fzmsc","cr_by":"Malcolm Manners","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["非洲"]},{"id":1192,"seq":682,"zh":"韦草","en":"Corrigiola litoralis","sci":"Corrigiola litoralis","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Molluginaceae","family_zh":"粟米草科","iucn":"LC","langs":19,"desc_zh":null,"desc_en":"Corrigiola litoralis is a species of flowering plant known by the common name strapwort. It can be found as a native species in Europe and Africa, and has been introduced to Australia and North America.","img":"images/1192.jpg","thumb":"images/t/1192.jpg","file":"Corrigiola littoralis 2.jpg","ar":0.904,"py":"weicao wc","cr_by":"Aroche","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/1192.jpg","illus_thumb":"images/i/t/1192.jpg","illus_file":"Illustration Corrigiola litoralis0.jpg","illus_ar":0.615,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":1193,"seq":683,"zh":"Montia fontana","en":"Montia fontana","sci":"Montia fontana","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Montiaceae","family_zh":"水卷耳科","iucn":"LC","langs":28,"desc_zh":null,"desc_en":"Montia fontana, blinks is a herbaceous annual to perennial plant that grows in freshwater springs in upland regions, and in seasonally damp acid grassland in the lowlands. It is widespread throughout the world, except in southern Asia.","img":"images/1193.jpg","thumb":"images/t/1193.jpg","file":"Montia fontana (mezenc, 43, France)2.JPG","ar":1.501,"py":"","cr_by":"Abalg","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null,"illus_img":"images/i/1193.png","illus_thumb":"images/i/t/1193.png","illus_file":"Montia fontana cleanedSturm.png","illus_ar":1.333,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm ) cleaned by uploader","illus_lic":"Public domain","illus_licurl":null},{"id":1194,"seq":684,"zh":"马来王猪笼草","en":"Nepenthes rajah","sci":"Nepenthes rajah","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Nepenthaceae","family_zh":"猪笼草科","iucn":"EN","langs":33,"desc_zh":"马来王猪笼草（学名：Nepenthes rajah），又名王侯猪笼草、拉贾猪笼草及猪王猪笼草，是婆罗洲马来西亚沙巴担布尤贡山附近及基纳巴卢山特有的热带食虫植物。马来王猪笼草仅生长于蛇纹石土壤基质中，特别是有地下水渗出、土壤松散且长期湿润的地区。其海拔分布范围为1500米至2650米，因此马来王猪笼草被认为是高山或亚高山植物。由于其分布局限，马来王猪笼草已被世界自然保护联盟评估为濒危物种，列于《濒危野生动植物种国际贸易公约》附录一中。","desc_en":"Nepenthes rajah is a carnivorous pitcher plant species of the family Nepenthaceae. It is endemic to Mount Kinabalu and neighbouring Mount Tambuyukon in Sabah, Malaysian Borneo.","img":"images/1194.png","thumb":"images/t/1194.png","file":"Nepenthes rajah.png","ar":0.75,"py":"malaiwangzhulongcao mlwzlc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"],"illus_img":"images/i/1194.jpg","illus_thumb":"images/i/t/1194.jpg","illus_file":"Nepenthes rajah - Curtis’s Botanical Magazine (1905).jpg","illus_ar":0.777,"illus_by":"M. Smith","illus_lic":"Public domain","illus_licurl":null},{"id":1195,"seq":685,"zh":"垂序商陆","en":"Phytolacca americana","sci":"Phytolacca americana","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Phytolaccaceae","family_zh":"商陆科","iucn":null,"langs":41,"desc_zh":"垂序商陆（学名：Phytolacca americana），又名美洲商陆、美商陆、花商陆、野胭脂、白鸡腿，为商陆科商陆属下的一个植物种。 该植物全株有毒，易与山牛蒡或人参混淆，原产于北美洲。","desc_en":"Phytolacca americana, also known as American pokeweed, pokeweed, poke sallet, pokeberry, dragonberries, pigeonberry weed, and inkberry, is a poisonous, herbaceous perennial plant in the pokeweed family Phytolaccaceae.","img":"images/1195.png","thumb":"images/t/1195.png","file":"Pokeberries.png","ar":1.501,"py":"chuixushanglu cxsl","cr_by":"Huw Williams ( Huwmanbeing )","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["北美洲"]},{"id":1196,"seq":686,"zh":"西蒙德木","en":"Simmondsia chinensis","sci":"Simmondsia chinensis","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Simmondsiaceae","family_zh":"油蜡树科","iucn":null,"langs":40,"desc_zh":null,"desc_en":"Jojoba ( ; botanical name: Simmondsia chinensis) – also commonly called goat nut, deer nut, pignut, wild hazel, quinine nut, coffeeberry, and gray box bush – is an evergreen, dioecious shrub native to the Southwestern United States and northern Mexico.","img":"images/1196.jpg","thumb":"images/t/1196.jpg","file":"Simmondsia chinensis male flower.jpg","ar":1.11,"py":"ximengdemu xmdm","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["北美洲"]},{"id":1197,"seq":687,"zh":"棱轴土人参","en":"Talinum fruticosum","sci":"Talinum fruticosum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Talinaceae","family_zh":"土人参科","iucn":null,"langs":21,"desc_zh":"棱轴土人参（学名：Talinum fruticosum），俗称皇宫菜、人参菜、归来参、参仔菜、巴参菜。，一种草本多年生植物，分布于墨西哥、加勒比海、中美洲及南美广泛地区，是一种在热带地区的绿叶蔬菜。","desc_en":"Talinum fruticosum is a herbaceous perennial plant that is native to Mexico, the Caribbean, West Africa, Central America, and much of South America. Common names include Ceylon spinach, waterleaf, cariru, Gbure, Surinam purslane, Philippine spinach, Florida sp…","img":"images/1197.jpg","thumb":"images/t/1197.jpg","file":"Talinum crassifolium 2.jpg","ar":0.83,"py":"lengzhouturenshen lztrs","cr_by":"Sphl","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["非洲","北美洲","南美洲"]},{"id":1198,"seq":688,"zh":"Tamarix gallica","en":"Tamarix gallica","sci":"Tamarix gallica","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Tamaricaceae","family_zh":"柽柳科","iucn":"LC","langs":29,"desc_zh":null,"desc_en":"Tamarix gallica, also known as the French tamarisk, is a deciduous, herbaceous, twiggy shrub or small tree reaching up to about 5 meters high. It is indigenous to Saudi Arabia and the Sinai Peninsula, and very common around the Mediterranean region.","img":"images/1198.jpg","thumb":"images/t/1198.jpg","file":"Tamarix gallica flores ArgamasillaCalatrava.jpg","ar":1.333,"py":"","cr_by":"Javier martinlo","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":672,"seq":689,"zh":"大果山茱萸","en":"Cornus mas","sci":"Cornus mas","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":"LC","langs":73,"desc_zh":"大果山茱萸（学名：Cornus mas，也做欧洲山茱萸）是一种于山茱萸科下的被子植物。于南欧（从法国到俄罗斯南部）、亚美尼亚、阿塞拜疆、乔治亚、伊朗、土耳其、黎巴嫩和叙利亚为原生物种。","desc_en":"Cornelian cherry (Cornus mas), also known as the European cornel, is a species of shrub or small tree in the dogwood family Cornaceae native to Western Europe, Southern Europe, and Southwestern Asia.","img":"images/672.jpg","thumb":"images/t/672.jpg","file":"CornusMas Fruits 01.jpg","ar":1.333,"py":"daguoshanzhuyu dgszy","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/672.jpg","illus_thumb":"images/i/t/672.jpg","illus_file":"Cornus mas - Prof. Dr. Thome-s Flora von Deutschland ... (Pl. 391) clean.jpg","illus_ar":0.689,"illus_by":"Migula, Walter; Thomé, Otto W.","illus_lic":"Public domain","illus_licurl":null},{"id":673,"seq":690,"zh":"欧洲红瑞木","en":"Cornus sanguinea","sci":"Cornus sanguinea","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":null,"langs":54,"desc_zh":"欧洲红瑞木（学名：Swida sanguinea），为山茱萸科梾木属下的一个种。","desc_en":"Cornus sanguinea, the common dogwood or bloody dogwood, is a species of dogwood native to most of Europe and western Asia, from England and central Scotland east to the Caspian Sea. It is widely grown as an ornamental plant.","img":"images/673.jpg","thumb":"images/t/673.jpg","file":"Cornus-sanguinea.JPG","ar":1.333,"py":"ouzhouhongruimu ozhrm","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/673.jpg","illus_thumb":"images/i/t/673.jpg","illus_file":"Cornus sanguinea — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":674,"seq":691,"zh":"红瑞木","en":"Cornus alba","sci":"Cornus alba","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":null,"langs":38,"desc_zh":"红瑞木（学名：Cornus alba）是山茱萸属的一种落叶灌木，原产于西伯利亚、中国和韩国，后来作为观赏植物引入世界其他国家，还培育出了不同的品种 。它的花期在5至6月，开乳白色花，其茎在深秋和冬天变成红色，因而形成一道独特的景观。 其种加词“alba”意为“白色的”，意指所开的花开始为白色的。","desc_en":"Cornus alba, the red-barked, white or Siberian dogwood, is a species of flowering plant in the family Cornaceae, native to Siberia, northern China and Korea. It is a large deciduous surculose (suckering) shrub that can be grown as a small tree.","img":"images/674.jpg","thumb":"images/t/674.jpg","file":"Cornus alba a2.jpg","ar":1.345,"py":"hongruimu hrm","cr_by":"Opioła Jerzy (Poland)","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/674.png","illus_thumb":"images/i/t/674.png","illus_file":"Cornus alba - J. C. Krauss - t. 4 (1802).png","illus_ar":0.795,"illus_by":"J. C. Krauss (1759-1826)","illus_lic":"Public domain","illus_licurl":null},{"id":676,"seq":692,"zh":"绣球花","en":"Hydrangea macrophylla","sci":"Hydrangea macrophylla","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":null,"langs":48,"desc_zh":"绣球花（学名：Hydrangea macrophylla），又名绣球、八仙花、草绣球、紫阳花等，是绣球花科绣球属下的一个植物种。 绣球花原产于日本，是一种常见的园艺装饰花，花色一般包括红、蓝、紫色，会因所在环境的酸碱度引起花色变化，所以也可作为天然的酸碱指示剂，其在酸性的土壤偏向青色、中性至碱性的土壤则偏向红色。夏季开花，花期5-8月。也常用于制作干花。 原生种是「额紫杨花」（Hydrangea macrophylla f.","desc_en":"Hydrangea macrophylla is a species of flowering plant in the family Hydrangeaceae, native and endemic to Japan. It is a deciduous shrub growing to 3 m (10 ft) tall by 2.5 m (8 ft) or more broad with large heads of pink or blue flowers in summer and autumn.","img":"images/676.jpg","thumb":"images/t/676.jpg","file":"(Natural) Hydrangea macrophylla, Iwafune, Isumi, Chiba, Japan 2.jpg","ar":1.347,"py":"xiuqiuhua xqh","cr_by":"belvedere04","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"灌木","origin":["亚洲"],"illus_img":"images/i/676.jpg","illus_thumb":"images/i/t/676.jpg","illus_file":"The American Flora. Vol. 2, 1855 - pl. 04 Hydrangea macrophylla (8079580353).jpg","illus_ar":0.719,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":677,"seq":693,"zh":"西洋山梅花","en":"Philadelphus coronarius","sci":"Philadelphus coronarius","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Philadelphus coronarius (sweet mock orange, English dogwood) is a species of flowering plant in the family Hydrangeaceae, native to the Caucasus and northeastern Turkey.","img":"images/677.jpg","thumb":"images/t/677.jpg","file":"Philadelphus coronarius.jpg","ar":1.333,"py":"xiyangshanmeihua xysmh","cr_by":"No machine-readable author provided. Rainer Bielefeld assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"],"illus_img":"images/i/677.jpg","illus_thumb":"images/i/t/677.jpg","illus_file":"20 Philadelphus coronarius par Pierre-Joseph Redouté.jpeg","illus_ar":0.692,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":678,"seq":694,"zh":"圆锥绣球","en":"Hydrangea paniculata","sci":"Hydrangea paniculata","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":"LC","langs":23,"desc_zh":"水亚木（学名：Hydrangea paniculata），又名糊八仙花、玉粉团、圆锥绣球。为绣球花科绣球属下的一种落叶灌木、小乔木，高度在1—5米（3.3—16.4英尺）之间。。","desc_en":"Hydrangea paniculata, or panicled hydrangea, is a species of flowering plant in the family Hydrangeaceae native to southern and eastern China, Korea, Japan and Russia (Sakhalin). It was first formally described by Philipp Franz von Siebold in 1829.","img":"images/678.jpg","thumb":"images/t/678.jpg","file":"Hydrangea paniculata IMG 6629.JPG","ar":1.501,"py":"yuanzhuixiuqiu yzxq","cr_by":"Hedwig Storch","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":1199,"seq":695,"zh":"Curtisia dentata","en":"Curtisia dentata","sci":"Curtisia dentata","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Curtisiaceae","family_zh":"南非茱萸科","iucn":"LC","langs":21,"desc_zh":null,"desc_en":"Curtisia dentata (commonly known as the Assegai tree or Cape lancewood, Afrikaans: Assegaai, Xhosa: Umgxina, Zulu: Umagunda) is a flowering tree from Southern Africa.","img":"images/1199.jpg","thumb":"images/t/1199.jpg","file":"Curtisia dentata - 2.JPG","ar":1.013,"py":"","cr_by":"en:User:Abu Shawka","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["非洲"],"illus_img":"images/i/1199.jpg","illus_thumb":"images/i/t/1199.jpg","illus_file":"Curtisia dentata, loof, Manie van der Schijff BT, a.jpg","illus_ar":1.184,"illus_by":"JMK","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":1200,"seq":696,"zh":"Hydrostachys imbricata","en":"Hydrostachys imbricata","sci":"Hydrostachys imbricata","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrostachyaceae","family_zh":"水穗草科","iucn":"LC","langs":6,"desc_zh":null,"desc_en":"Hydrostachys imbricata is a species of aquatic flowering plant in the genus Hydrostachys.","img":"images/1200.jpg","thumb":"images/t/1200.jpg","file":"Hydrostachys imbricata.jpg","ar":0.661,"py":"","cr_by":"Jules Paul Benjamin Delessert (1773-1858)","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":1201,"seq":697,"zh":"Cevallia sinuata","en":"Cevallia sinuata","sci":"Cevallia sinuata","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Loasaceae","family_zh":"刺莲花科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Cevallia sinuata or stinging serpent is a species of flowering plant belonging to the family Loasaceae. It is a perennial or subshrub native to northern Mexico and the southern central United States from Arizona to Oklahoma.","img":"images/1201.jpg","thumb":"images/t/1201.jpg","file":"Cevallia sinuata.jpg","ar":0.75,"py":"","cr_by":"CK Kelly","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"灌木","origin":["北美洲"]},{"id":1202,"seq":698,"zh":"珙桐","en":"Davidia involucrata","sci":"Davidia involucrata","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Nyssaceae","family_zh":"蓝果树科","iucn":null,"langs":32,"desc_zh":"珙桐（学名：Davidia involucrata），又称鸽子树、鸽子树、水梨子，是一种孑遗植物，野生种群只分布在中国湖北省和云贵高原北缘秦巴山地等地区。珙桐有两个亚种，两种相似，其一叶面有毛；另一光叶珙桐（Davidia involucrata Baill. var. vilmoriniana (Dode) Wanger.）叶面无毛。 法国传教士谭卫道神父首次发现并命名珙桐。谭卫道也是为麋鹿的命名人。","desc_en":"Davidia involucrata, the dove tree, ghost tree, handkerchief tree, pocket handkerchief tree, or is a medium-sized deciduous tree in the family Nyssaceae. It is the only living species in the genus Davidia.","img":"images/1202.jpg","thumb":"images/t/1202.jpg","file":"Davidia1.jpg","ar":1.545,"py":"gongtong gt","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null},{"id":680,"seq":699,"zh":"黑果越橘","en":"Vaccinium myrtillus","sci":"Vaccinium myrtillus","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":99,"desc_zh":"黑果越橘（学名：Vaccinium myrtillus，英语：bilberry, whortleberry），又称欧洲蓝莓（英语：European blueberry）或是山桑子，是杜鹃花科越橘属的植物。","desc_en":"Vaccinium myrtillus is a holarctic species of shrub with edible fruit of blue color, known by the common names bilberry, blaeberry, and whortleberry. It is more precisely called common bilberry or blue whortleberry to distinguish it from other Vaccinium relati…","img":"images/680.jpg","thumb":"images/t/680.jpg","file":"203 Vaccinum myrtillus L.jpg","ar":0.713,"py":"heiguoyueju hgyj","cr_by":"Amédée Masclef","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":null,"illus_img":"images/i/680.jpg","illus_thumb":"images/i/t/680.jpg","illus_file":"Vaccinium myrtillus Sturm09055.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":681,"seq":700,"zh":"越橘","en":"Vaccinium vitis-idaea","sci":"Vaccinium vitis-idaea","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":97,"desc_zh":"越橘（学名：Vaccinium vitis-idaea），又名红豆（黑龙江）、牙疙瘩（大兴安岭），是杜鹃花科的常绿灌木植物，有“北国红豆”赞誉；性耐寒，味熟时略酸甜，未熟略苦，生长在海拔900－2000米针叶林与阔叶树交混区，红果实可当果酱、鲜食，叶可制成茶叶泡茶，叶含乌苏酸、鞣质成分。中医学认为它“利尿消炎”。喜酸性潮湿土壤。含有丰富的维他命A、维他命C、B族维他命等营养量，野生欧洲越橘大量分布在斯堪的纳维亚半岛（挪威和瑞典）。","desc_en":"Vaccinium vitis-idaea is a small evergreen shrub in the heath family, Ericaceae. It is known colloquially as the lingonberry, partridgeberry, foxberry, mountain cranberry, or cowberry.","img":"images/681.jpg","thumb":"images/t/681.jpg","file":"Vaccinium vitis-idaea 20060824 003.jpg","ar":1.333,"py":"yueju yj","cr_by":"Jonas Bergsten","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":null,"illus_img":"images/i/681.jpg","illus_thumb":"images/i/t/681.jpg","illus_file":"T2 30 Vaccinium vitis-idaea par Pierre-Joseph Redouté.jpeg","illus_ar":0.691,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":682,"seq":701,"zh":"帚石楠","en":"Calluna vulgaris","sci":"Calluna vulgaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":77,"desc_zh":"帚石楠（学名：Calluna vulgaris）是指杜鹃花科帚石楠属的植物，别名「苏格兰石楠」。在欧洲，帚石楠属与其同科近类欧石楠属经常遭到混淆，被互作训解的称号亦有不少（这种情况在汉语领域中更为明显）。虽然它们在生物分类上界线清晰，但在文化理解上却曾造成不少误会。两种花属的主要分别是帚石楠的花萼的裂片遮盖著花瓣，而欧石楠的花瓣则反过来盖著萼片。。","desc_en":"Calluna vulgaris, common heather, ling, or simply heather, is the sole species in the genus Calluna in the flowering plant family Ericaceae. It is a low-growing evergreen shrub growing to 20 to 50 centimetres (8 to 20 in) tall, or rarely to 1 metre (40 in) and…","img":"images/682.jpg","thumb":"images/t/682.jpg","file":"CallunaVulgaris.jpg","ar":1.172,"py":"zhoushinan zsn","cr_by":"Aqwis ( Aqwis )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/682.jpg","illus_thumb":"images/i/t/682.jpg","illus_file":"Illustration Calluna vulgaris0.jpg","illus_ar":0.598,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":683,"seq":702,"zh":"笃斯越橘","en":"bog bilberry","sci":"Vaccinium uliginosum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":75,"desc_zh":"笃斯越橘（满语：ᡩᡠᡴᠰᡳ，穆麟德转写：duksi；拉丁学名：Vaccinium uliginosum），又名笃斯、黑豆树（大兴安岭）、𣛭柿（小兴安岭、伊春）、甸果、地果、龙果、蛤塘果（吉林）、讷日苏（蒙古语：ᠨᠡᠷᠰᠦ(᠊ᠨ)，汉语拼音字母：ners，中蒙通用转写：nersü(n)；达斡尔语：ner）、吉厄特（通古斯语：ǰukte, d/ǰusikte, ǰiksiŋē, t/čuikte）、吾格特（鄂伦春语）、皂李子等，种加词ul…","desc_en":"Vaccinium uliginosum (bog bilberry, bog blueberry, alpine blueberry or western blueberry) is an edible Eurasian and North American flowering plant in the heath family Ericaceae.","img":"images/683.jpg","thumb":"images/t/683.jpg","file":"Vaccinium uliginosum fruit.jpg","ar":1.333,"py":"dusiyueju dsyj","cr_by":"David Gaya","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","北美洲"],"illus_img":"images/i/683.jpg","illus_thumb":"images/i/t/683.jpg","illus_file":"Vaccinium uliginosum — Flora Batava — Volume v14.jpg","illus_ar":0.801,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":684,"seq":703,"zh":"熊果","en":"Arctostaphylos uva-ursi","sci":"Arctostaphylos uva-ursi","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":67,"desc_zh":"熊果又名熊葡萄、熊莓，是杜鹃花科熊果属的一种植物。","desc_en":"Arctostaphylos uva-ursi is a plant species of the genus Arctostaphylos widely distributed across circumboreal regions of the subarctic Northern Hemisphere. Kinnikinnick (from the Unami language for smoking \"mixture\") is a common name in Canada and the United S…","img":"images/684.jpg","thumb":"images/t/684.jpg","file":"Arctostaphylos uva-ursi 25924.JPG","ar":1.333,"py":"xiongguo xg","cr_by":"Walter Siegmund","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null,"illus_img":"images/i/684.jpg","illus_thumb":"images/i/t/684.jpg","illus_file":"Arctostaphylos uva-ursi - Köhler–s Medizinal-Pflanzen-013.jpg","illus_ar":0.799,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":685,"seq":704,"zh":"草莓树","en":"Arbutus unedo","sci":"Arbutus unedo","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":60,"desc_zh":"草莓树（学名：Arbutus unedo）是浆果鹃属下的一种常绿灌木或小树，原产于地中海地区，分布最西可达爱尔兰。在爱尔兰常被称为“爱尔兰草莓树”（Irish strawberry tree）或“基拉尼草莓树”（Killarney strawberry tree）。","desc_en":"Arbutus unedo, commonly known as strawberry tree, also called madrone, is an evergreen shrub or small tree in the family Ericaceae, native to the Mediterranean Basin and Western Europe.","img":"images/685.jpg","thumb":"images/t/685.jpg","file":"Arbouse.jpg","ar":0.812,"py":"caomeishu cms","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["欧洲"],"illus_img":"images/i/685.jpg","illus_thumb":"images/i/t/685.jpg","illus_file":"The American Flora. Vol. 4, 1855 - pl. 18 Arbutus unedo (14760467266).jpg","illus_ar":0.7,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":686,"seq":705,"zh":"白欧石楠","en":"Erica arborea","sci":"Erica arborea","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":46,"desc_zh":"白欧石楠（Erica arborea）是一种常绿灌木，一般高约 1-4 公尺，有标本可达 7 公尺高。花色白，小花，长于酸性土壤。白欧石楠一般生长于环地中海地区的灌木地带，西至葡萄牙及加纳利和马德拉群岛、以至非洲紧连着的地带，例如：埃塞俄比亚高原、鲁文佐里山脉和喀麦隆山脉。 白欧石楠的木非常坚硬，而且抗热能力很强，所以常用于制作烟斗或刀柄。日常生活所讲的「石楠木」，一般都指白欧石楠，但有时亦指其他高身的欧石楠属树木，例如：葡萄牙石楠。","desc_en":"Erica arborea, the tree heath or tree heather, is a species of flowering plant (angiosperms) in the heather family Ericaceae, native to the Mediterranean Basin and Ethiopia, Kenya and Tanzania in East Africa. It is also cultivated as an ornamental.","img":"images/686.jpg","thumb":"images/t/686.jpg","file":"Axlenǧ s uleǧǧig.jpg","ar":1.501,"py":"baioushinan bosn","cr_by":"Zidat","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["欧洲","非洲"],"illus_img":"images/i/686.jpg","illus_thumb":"images/i/t/686.jpg","illus_file":"Erica arborea — Flora Batava — Volume v12.jpg","illus_ar":0.708,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":687,"seq":706,"zh":"岩高兰","en":"Empetrum nigrum","sci":"Empetrum nigrum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":46,"desc_zh":"岩高兰（学名：Empetrum nigrum）为岩高兰科岩高兰属下的一个种。","desc_en":"Empetrum nigrum, the crowberry, black crowberry, mossberry, rockberry, or, in western Alaska, Labrador, etc., blackberry, is a flowering plant species in the heather family Ericaceae with a near circumboreal distribution in the Northern Hemisphere.","img":"images/687.jpg","thumb":"images/t/687.jpg","file":"Empetrum nigrum 12.jpg","ar":1.333,"py":"yangaolan ygl","cr_by":"B.gliwa","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null,"illus_img":"images/i/687.jpg","illus_thumb":"images/i/t/687.jpg","illus_file":"Empetrum nigrum — Flora Batava — Volume v9.jpg","illus_ar":0.738,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":693,"seq":707,"zh":"黄花九轮草","en":"Primula veris","sci":"Primula veris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":63,"desc_zh":"黄花九轮草（学名：Primula veris）是报春花科报春花属多年生草本植物。该物种的原生地在大部份的温带欧洲和西亚地区，虽然在苏格兰西北部的大部分北部地区并没有它的踪迹，但它再次出现在最北端的萨瑟兰和奥克尼群岛以及斯堪的纳维亚半岛。 该物种经常与欧报春杂交形成多花报春（Primula ×polyantha）。多花报春经常与高报春（Primula elatior）混淆。","desc_en":"Primula veris, the cowslip, common cowslip, or cowslip primrose (syn. Primula officinalis Hill), is a herbaceous perennial flowering plant in the primrose family Primulaceae.","img":"images/693.jpg","thumb":"images/t/693.jpg","file":"Common Cowslip.jpg","ar":0.751,"py":"huanghuajiuluncao hhjlc","cr_by":"Avetisyan Ani","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/693.jpg","illus_thumb":"images/i/t/693.jpg","illus_file":"Illustration Primula veris0.jpg","illus_ar":0.626,"illus_by":"Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":694,"seq":708,"zh":"欧洲报春","en":"Primula vulgaris","sci":"Primula vulgaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":57,"desc_zh":"欧报春（学名：Primula vulgaris），又名欧洲报春花、西洋樱草，是报春花属下的一种多年生草本植物，广泛分布于西欧、南欧、北非、西亚，也是一种常见的园艺植物。其种加词的意思就是“普通的”。","desc_en":"Primula vulgaris is a species of flowering plant in the family Primulaceae, native to Eurasia. The common name of this plant is primrose, or occasionally common primrose or English primrose to distinguish it from other Primula species referred to as primroses.","img":"images/694.jpg","thumb":"images/t/694.jpg","file":"Chipping Sodbury MMB 02 primula vulgaris.jpg","ar":1.501,"py":"ouzhoubaochun ozbc","cr_by":"mattbuck ( category )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":695,"seq":709,"zh":"琉璃繁缕","en":"Lysimachia arvensis","sci":"Lysimachia arvensis","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":57,"desc_zh":"琉璃繁缕（学名：Anagallis arvensis），为报春花科琉璃繁缕属下的一个植物物种。","desc_en":"Lysimachia arvensis, syn. Anagallis arvensis, commonly known as scarlet pimpernel, red pimpernel, red chickweed, poor man's barometer, poor man's weather-glass, shepherd's weather glass or shepherd's clock, is a species of low-growing annual plant with brightl…","img":"images/695.jpg","thumb":"images/t/695.jpg","file":"Scarlet Pimpernel (Lysimachia arvensis) - Pollença, Spain 2022-04-15.jpg","ar":1,"py":"liulifanl llfl","cr_by":"Ryan Hodnett","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":696,"seq":710,"zh":"毛黄连花","en":"Lysimachia vulgaris","sci":"Lysimachia vulgaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":"LC","langs":37,"desc_zh":"毛黄连花（学名：Lysimachia vulgaris）为报春花科珍珠菜属的植物。分布在欧洲、高加索、中亚、西伯利亚以及中国大陆的新疆等地，生长于海拔500米至700米的地区，见于沟边芦苇地中，目前尚未由人工引种栽培。","desc_en":"Lysimachia vulgaris, the yellow loosestrife or garden loosestrife, is a species of herbaceous perennial flowering plant in the family Primulaceae. It was transferred to Myrsinoideae based on results of molecular phylogenetic research before being merged into t…","img":"images/696.jpg","thumb":"images/t/696.jpg","file":"Lysimachia vulgaris.jpeg","ar":0.87,"py":"maohuanglianhua mhlh","cr_by":"Kristian Peters -- Fabelfroh 15:11, 26 September 2005 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/696.jpg","illus_thumb":"images/i/t/696.jpg","illus_file":"Lysimachia vulgaris — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":697,"seq":711,"zh":"仙客来","en":"Cyclamen persicum","sci":"Cyclamen persicum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":37,"desc_zh":"仙客来（学名：Cyclamen persicum），别名萝卜海棠、兔耳花、兔子花、一品冠、篝火花、翻瓣莲，是报春花科仙客来属多年生草本植物。仙客来是一种普遍种植的鲜花，适合种植于室内花盆，冬季则需温室种植。仙客来的某些栽培品种有浓郁的香气，而有些香气淡或无香气。 “仙客来”一词来自学名Cyclamen的音译，由于音译巧妙，使得花名有“仙客翩翩而至”的寓意。","desc_en":"Cyclamen persicum, the Persian cyclamen, is a species of flowering herbaceous perennial plant growing from a tuber, native to rocky hillsides, shrubland, and woodland up to 1,200 m (3,900 ft) above sea level, from south-central Turkey to the Levant.","img":"images/697.jpg","thumb":"images/t/697.jpg","file":"Yagur – Nesher, the Green Path – Mount Carmel 016.JPG","ar":0.75,"py":"xiankelai xkl","cr_by":"Hanay","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"],"illus_img":"images/i/697.jpg","illus_thumb":"images/i/t/697.jpg","illus_file":"Cyclamen persicum illustration 1794.jpg","illus_ar":0.644,"illus_by":"Johann Samuel Halle 1727-1810","illus_lic":"Public domain","illus_licurl":null},{"id":699,"seq":712,"zh":"茶树","en":"Camellia sinensis","sci":"Camellia sinensis","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"DD","langs":93,"desc_zh":"茶树（学名：Camellia sinensis）是山茶科山茶属的一种，为多年生常绿木本植物，落叶灌木或乔木。在热带地区也有乔木型茶树高达15－30米，基部树围1.5米以上。栽培茶树往往通过修剪来抑制纵向生长，所以树高多在0.8－1.2米间。 其种加词“sinensis”意为“中华的”。","desc_en":"Camellia sinensis is a species of evergreen shrub or small tree in the flowering plant family Theaceae. Its leaves, leaf buds, and stems are used to produce tea.","img":"images/699.jpg","thumb":"images/t/699.jpg","file":"Csinensis.jpg","ar":1.333,"py":"chashu cs","cr_by":"AxelBoldt at en.wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null,"illus_img":"images/i/699.jpg","illus_thumb":"images/i/t/699.jpg","illus_file":"Camellia sinensis - Köhler–s Medizinal-Pflanzen-025.jpg","illus_ar":0.825,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":700,"seq":713,"zh":"山茶花","en":"Camellia japonica","sci":"Camellia japonica","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"LC","langs":50,"desc_zh":"山茶（学名：Camellia japonica），又名山茶花､ 玉茗花、耐冬､ 椿花，山茶科山茶属植物，是一种常绿灌木或小乔木，古名海石榴｡ 山茶的花大多数为红色或淡红色，亦有白色，多为重瓣。茶花的品种极多，是东亚传统的观赏花卉，在“十大名花”中排名第七。茶花也在全世界多地广泛栽培，用于园艺装饰。种子也可榨油。","desc_en":"Camellia japonica, known as common camellia, or Japanese camellia, is a species of flowering plant from the genus Camellia in the tea family Theaceae. It is native to China and Japan, and grows naturally in forests at altitudes of around 300–1,100 metres (980–…","img":"images/700.jpg","thumb":"images/t/700.jpg","file":"Camellia japonica var. decumbens 3.JPG","ar":1.333,"py":"shanchahua sch","cr_by":"Qwert1234","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"],"illus_img":"images/i/700.jpg","illus_thumb":"images/i/t/700.jpg","illus_file":"The American Flora. Vol. 1, 1855 - pl. 13 Camellia japonica (6021772629).jpg","illus_ar":0.689,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":701,"seq":714,"zh":"富兰克林木","en":"Franklinia alatamaha","sci":"Franklinia alatamaha","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"EW","langs":24,"desc_zh":"洋木荷属（学名：Franklinia）也称富兰克林木属，为山茶科的一个属。","desc_en":"Franklinia is a monotypic genus in the tea family, Theaceae. The sole species in this genus is a flowering tree, Franklinia alatamaha, commonly called Franklinias or the Franklin tree, and native to the Altamaha River valley in Georgia in the southeastern Unit…","img":"images/701.jpg","thumb":"images/t/701.jpg","file":"Franklinia alatamaha.jpg","ar":1.333,"py":"fulankelinmu flklm","cr_by":"Francine Riez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲"]},{"id":702,"seq":715,"zh":"茶梅","en":"Camellia sasanqua","sci":"Camellia sasanqua","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"LC","langs":21,"desc_zh":"茶梅（学名：Camellia sasanqua，日语：サザンカ）是山茶属油茶组的一种常绿灌木或小乔木，原产于日本南部（四国、九州）及琉球群岛。它在东亚拥有悠久的栽培历史，既作为观赏植物，又可用于种子榨油和叶片制茶。","desc_en":"Camellia sasanqua, with common name Sasanqua camellia or Christmas camellia (茶梅, サザンカ), is an evergreen shrub or small tree in the genus Camellia, section Oleifera of the family Theaceae. It is native to southern Japan (Shikoku, Kyushu) and the Ryukyu Islands.","img":"images/702.jpg","thumb":"images/t/702.jpg","file":"Camellia sasanqua1.jpg","ar":1.08,"py":"chamei cm","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":704,"seq":716,"zh":"人心果","en":"Manilkara zapota","sci":"Manilkara zapota","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":"LC","langs":77,"desc_zh":"人心果，别称仁心果、赤铁果、在台湾又称吴凤柿、人参果、台语查某李仔、查某囡仔、英文称Sapodilla、马来文称Basiku或Buah Ciku、印尼文称Sawo、越南称Hồng xiêm、寮国称Lamood或Rarmood。是一种山榄科铁线子属的常绿中乔木。人心果之称来自广东，因纵剖面似人心而得。 人心果树原产于美洲热带，结果时间很长，大概要用一年时间。","desc_en":"Manilkara zapota, commonly known as sapodilla (Spanish: [ˌsapoˈðiʝa]), sapote, chicozapote, chico, chicoo, chicle, naseberry, nispero, or soapapple, among other names, is an evergreen tree native to southern Mexico and Central America.","img":"images/704.jpg","thumb":"images/t/704.jpg","file":"Manilkara Zapota in HK.JPG","ar":1.37,"py":"renxinguo rxg","cr_by":"HK Arun","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲"]},{"id":705,"seq":717,"zh":"摩洛哥坚果","en":"Argania spinosa","sci":"Argania spinosa","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":null,"langs":55,"desc_zh":"摩洛哥坚果（学名：Sideroxylon spinosum），亦有音译阿甘，是一种生长自西地中海的北非地区的碳酸钙半沙漠山谷的山榄科特有种植物，可在摩洛哥西南部的苏斯及阿尔及利亚的廷杜夫合共8280平方公里的联合国教科文组织生物圈保护区内发现。 摩洛哥坚果之所以闻名遐迩是因为这种坚果榨出来的坚果油一种很受欢迎的产品，即可以食用也可以做为美容护肤用品而供人们使用。","desc_en":"Sideroxylon spinosum, known as argan (Tashelhit: ⴰⵔⴳⴰⵏ, romanized: argan), synonym Argania spinosa, is a species of flowering plant. It is a tree native to the calcareous semi-desert Sous valley and to the Chiadma and Haha regions of Morocco, as well as some p…","img":"images/705.jpg","thumb":"images/t/705.jpg","file":"Argania spinosa.jpg","ar":1.333,"py":"moluogejianguo mlgjg","cr_by":"No machine-readable author provided. MPF assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["非洲"]},{"id":706,"seq":718,"zh":"乳油木","en":"Vitellaria paradoxa","sci":"Vitellaria paradoxa","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":"VU","langs":47,"desc_zh":"乳油木（学名：Vitellaria paradoxa，旧名Butyrospermum parkii），又名牛油果、乳木果、雪亚果（Shea nut）或非洲果，是属于山榄科，乳木果属的一种树木。乳油木是非洲特有的植物，原产于马利、喀麦隆、刚果、象牙海岸、迦纳、几内亚、多哥、奈及利亚、塞内加尔、苏丹、布吉纳法索及乌干达等地。乳油木的种子很大，含有丰富的油脂，可以从中提取出乳木果油。","desc_en":"Vitellaria paradoxa (formerly Butyrospermum parkii), commonly known as shea tree, shi tree (, also ), or vitellaria, is a tree of the family Sapotaceae. It is the only species in the genus Vitellaria, and is indigenous to Africa.","img":"images/706.jpg","thumb":"images/t/706.jpg","file":"Vitellaria paradoxa MS4195.JPG","ar":1.333,"py":"ruyoumu rym","cr_by":"Marco Schmidt","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["非洲"]},{"id":708,"seq":719,"zh":"柿树","en":"Diospyros kaki","sci":"Diospyros kaki","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ebenaceae","family_zh":"柿科","iucn":"LC","langs":78,"desc_zh":"柿（学名：Diospyros kaki），是柿树属的一种落叶乔木，是最常见的产柿子的植物，原产于中国长江流域，后来引入日本、美国等世界其他地区。","desc_en":"Diospyros kaki, the Oriental persimmon, Chinese persimmon, Japanese persimmon, kaki persimmon, or Fuyu persimmon, is the most widely cultivated species of the genus Diospyros. Although its first botanical description was not published until 1780, D.","img":"images/708.jpg","thumb":"images/t/708.jpg","file":"Kaki 20041002.jpg","ar":1.333,"py":"shishu ss","cr_by":"Sphl","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":709,"seq":720,"zh":"君迁子","en":"Diospyros lotus","sci":"Diospyros lotus","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ebenaceae","family_zh":"柿科","iucn":"LC","langs":38,"desc_zh":"君迁子（学名：Diospyros lotus），又名黑枣、猴枣、豆柿，为柿科柿属下的一个种。它原产于欧亚大陆，从中国到南欧都有分布。君迁子在古希腊语中称“Dios pyros”，即“诸神之果”，这亦是柿属属名的来源。其果实味道像是樱桃和枣混在一起。","desc_en":"The date-plum (Diospyros lotus), also known by the common names Caucasian persimmon and lilac persimmon, is a widely cultivated species of the genus Diospyros, native to temperate Asia and southeast Europe.","img":"images/709.jpg","thumb":"images/t/709.jpg","file":"Caucasian persimmon - Diospyros lotus 07.jpg","ar":1.419,"py":"junqianzi jqz","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":1203,"seq":721,"zh":"异色柿","en":"Diospyros blancoi","sci":"Diospyros blancoi","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ebenaceae","family_zh":"柿科","iucn":null,"langs":36,"desc_zh":"毛柿（台湾植物志）或异色柿（中国植物志）（学名：Diospyros blancoi；异名：Diospyros discolor, Diospyros philippensis），也叫番柿、台湾黑檀、台湾乌木、菲律宾乌木（英语：kamagong或camagon），是柿树科柿树属下的一个种，原产台湾的兰屿、绿岛、龟山岛、恒春半岛以及菲律宾、婆罗洲，在广州、东南亚、南亚、中美洲等地有栽培。","desc_en":"Diospyros blancoi, (synonym Diospyros discolor), commonly known as velvet apple, velvet persimmon, kamagong, or mabolo tree, is a tree of the genus Diospyros of ebony trees and persimmons.","img":"images/1203.jpg","thumb":"images/t/1203.jpg","file":"Starr 980601-4322 Diospyros discolor.jpg","ar":0.667,"py":"yiseshi yss","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲"]},{"id":710,"seq":722,"zh":"凤仙花","en":"Impatiens balsamina","sci":"Impatiens balsamina","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":null,"langs":50,"desc_zh":"凤仙花（学名：Impatiens balsamina），又名指甲花（台罗：tsíng-kah-hue）、指甲桃、急性子、凤仙透骨草，是凤仙花科凤仙花属的植物。","desc_en":"Impatiens balsamina, commonly known as balsam, garden balsam, rose balsam, touch-me-not or spotted snapweed, is a species of plant native to India and Myanmar. It is an annual plant growing to 20–75 cm tall, with a thick, but soft stem.","img":"images/710.jpg","thumb":"images/t/710.jpg","file":"Antsiranana 08.jpg","ar":0.75,"py":"fengxianhua fxh","cr_by":"Florantsika","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["亚洲"]},{"id":711,"seq":723,"zh":"水金凤","en":"Impatiens noli-tangere","sci":"Impatiens noli-tangere","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":"LC","langs":41,"desc_zh":"水金凤（学名：Impatiens noli-tangere），又名辉菜花，是凤仙花科凤仙花属的植物。分布于俄罗斯、朝鲜、日本以及中国大陆的陕西、河北、湖南、山东、辽宁、浙江、甘肃、湖北、内蒙古、安徽、黑龙江、吉林、山西、河南等地，生长于海拔900米至2,400米的地区，多生长于山坡林下。","desc_en":"Impatiens noli-tangere (touch-me-not balsam; Latin impatiēns 'impatient' or 'not allowing', and nōlī tangere 'do not touch': literally 'be unwilling to touch') is an annual herbaceous plant in the family Balsaminaceae found in damp places in Europe, Asia and N…","img":"images/711.jpg","thumb":"images/t/711.jpg","file":"NoliTangere Pflanze.jpg","ar":0.75,"py":"shuijinfeng sjf","cr_by":"Túrelio","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/711.jpg","illus_thumb":"images/i/t/711.jpg","illus_file":"Impatiens noli-tangere — Flora Batava — Volume v4.jpg","illus_ar":0.708,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":712,"seq":724,"zh":"腺柄凤仙花","en":"Impatiens glandulifera","sci":"Impatiens glandulifera","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Impatiens glandulifera, Himalayan balsam, is a large annual plant native to the Himalayas. Via human introduction it is now present across much of the Northern Hemisphere and is considered an invasive species in many areas.","img":"images/712.jpg","thumb":"images/t/712.jpg","file":"Valley of flowers National Park 04.JPG","ar":1.333,"py":"xianbingfengxianhua xbfxh","cr_by":"Guptaele","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"]},{"id":714,"seq":725,"zh":"花荵","en":"Polemonium caeruleum","sci":"Polemonium caeruleum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Polemoniaceae","family_zh":"花荵科","iucn":null,"langs":33,"desc_zh":"花荵（学名：Polemonium caeruleum）为花荵科花荵属下的一个种。","desc_en":"Polemonium caeruleum, known as Jacob's-ladder or Greek valerian, is a hardy perennial flowering plant. The plant produces cup-shaped, blue or white flowers. It is native to temperate regions of Europe. It is the type species of the phlox family, Polemoniaceae.","img":"images/714.jpg","thumb":"images/t/714.jpg","file":"Polemonium caeruleum nf.jpg","ar":0.606,"py":"huaren hr","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"]},{"id":715,"seq":726,"zh":"天蓝绣球","en":"Phlox paniculata","sci":"Phlox paniculata","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Polemoniaceae","family_zh":"花荵科","iucn":null,"langs":30,"desc_zh":"天蓝绣球（学名：Phlox paniculata）为花荵科天蓝绣球属下的一个种。","desc_en":"Phlox paniculata is a species of flowering plant in the phlox family (Polemoniaceae). It is native to parts of the eastern and central United States. It is extensively cultivated in temperate regions as an ornamental plant and has become established in the wil…","img":"images/715.jpg","thumb":"images/t/715.jpg","file":"(MHNT) Phlox paniculata famous light purple - Les Martels, Giroussens Tarn.jpg","ar":1.411,"py":"tianlanxiuqiu tlxq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["北美洲"]},{"id":1204,"seq":727,"zh":"福禄考","en":"Phlox drummondii","sci":"Phlox drummondii","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Polemoniaceae","family_zh":"花荵科","iucn":null,"langs":22,"desc_zh":"福禄考（学名：Phlox drummondii），别名小天蓝绣球、五色梅、桔梗石竹、福禄花，属于福禄考属。福禄考原产于美国德克萨斯州，但经由公路等交通因素的传播，现已广布在整个美国南方。福禄考开有繁茂的花，常被做为观赏植物。","desc_en":"Phlox drummondii (commonly annual phlox or Drummond's phlox) is a flowering plant in the genus Phlox of the family Polemoniaceae. Native to Texas, it is also widely distributed in the southeastern United States, especially along public highways. P.","img":"images/1204.jpg","thumb":"images/t/1204.jpg","file":"Phlox drummondii - Fl3.jpg","ar":1.171,"py":"fulukao flk","cr_by":"Tim Ross","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["北美洲"],"illus_img":"images/i/1204.jpg","illus_thumb":"images/i/t/1204.jpg","illus_file":"Phlox drummondii-Curtis.jpg","illus_ar":0.623,"illus_by":"S. Curtis","illus_lic":"Public domain","illus_licurl":null},{"id":716,"seq":728,"zh":"软枣猕猴桃","en":"Actinidia arguta","sci":"Actinidia arguta","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Actinidiaceae","family_zh":"猕猴桃科","iucn":null,"langs":34,"desc_zh":"软枣猕猴桃（学名：Actinidia arguta），台湾称之为迷你奇异果或袖珍奇异果，又名奇异莓（英文：Kiwiberry），中国大陆称之为软枣猕猴桃，俗称软枣子（中国东北部分地区写作方言中同音的元枣子），为猕猴桃科猕猴桃属的植物。分布在朝鲜、日本以及中国大陆的辽宁、浙江、山西、山东、安徽、河南、吉林、云南等、河北、黑龙江等地，生长于海拔200米至3,602米的地区，多生长在山坡灌木林中、沟边、山顶杂木林中、山坡杂木林中、山坡灌丛、山…","desc_en":"Actinidia arguta is a perennial vine native to Japan, Korea, Northern China, and the Russian Far East. The fruit is known as kiwiberry or hardy kiwi, which are small kiwifruits without the hair-like fiber covering the outside, unlike most other species of the…","img":"images/716.jpg","thumb":"images/t/716.jpg","file":"Actinidia arguta fruit - hardy kiwi - Kiwibeere 05.jpg","ar":1.307,"py":"ruanzaomihoutao rzmht","cr_by":"Rillke","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"藤本","origin":["亚洲"]},{"id":717,"seq":729,"zh":"眼镜蛇瓶子草","en":"Darlingtonia californica","sci":"Darlingtonia californica","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sarraceniaceae","family_zh":"瓶子草科","iucn":"LC","langs":41,"desc_zh":"眼镜蛇瓶子草（学名：Darlingtonia californica），又称为加州瓶子草（California Pitcher plant）、眼镜蛇百合（Cobra Lily）、眼镜蛇植物（Cobra Plant），为瓶子草科眼镜蛇瓶子草属食虫植物。眼镜蛇瓶子草属为单种属，仅眼镜蛇瓶子草一种。其种加词“californica”意为“美国加利福尼亚的”。其原产于奥勒冈州及加利福尼亚州以北的沼泽及冷水浸润地。","desc_en":"Darlingtonia californica is a species of carnivorous plant in the new world pitcher plant family, Sarraceniaceae. The cobra lily is the sole species within its monotypic genus, Darlingtonia.","img":"images/717.jpg","thumb":"images/t/717.jpg","file":"Cobra lilies with flowers 1 - Darlingtonia SNS Oregon.jpg","ar":1.333,"py":"yanjingshepingzicao yjspzc","cr_by":"Ian Poellet","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"]},{"id":1205,"seq":730,"zh":"甜胡椒","en":"Clethra alnifolia","sci":"Clethra alnifolia","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Clethraceae","family_zh":"桤叶树科","iucn":"LC","langs":15,"desc_zh":null,"desc_en":"Clethra alnifolia, the coastal sweetpepperbush or summer sweet, is a species of flowering plant in the genus Clethra of the family Clethraceae, native to eastern North America from southern Nova Scotia and Maine south to northern Florida, and west to eastern T…","img":"images/1205.jpg","thumb":"images/t/1205.jpg","file":"Clethra-alnifolia-flowers.JPG","ar":1.569,"py":"tianhujiao thj","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["北美洲"],"illus_img":"images/i/1205.jpg","illus_thumb":"images/i/t/1205.jpg","illus_file":"Clethra alnifolia — Flora Batava — Volume v11.jpg","illus_ar":0.646,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1206,"seq":731,"zh":"岩梅","en":"Diapensia lapponica","sci":"Diapensia lapponica","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Diapensiaceae","family_zh":"岩梅科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Diapensia lapponica, the pincushion plant, is a plant in the family Diapensiaceae, the only circumboreal species in the genus Diapensia, the others being mainly in the Himalaya and on mountains in southwestern China.","img":"images/1206.jpg","thumb":"images/t/1206.jpg","file":"Diapensia lapponica plant upernavik.jpg","ar":1.333,"py":"yanmei ym","cr_by":"Kim Hansen","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"],"illus_img":"images/i/1206.jpg","illus_thumb":"images/i/t/1206.jpg","illus_file":"Nordens flora Diapensia lapponica.jpg","illus_ar":0.5,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":1207,"seq":732,"zh":"Androstoma empetrifolia","en":"Androstoma empetrifolia","sci":"Androstoma empetrifolia","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Epacridaceae","family_zh":"尖苞树科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Androstoma empetrifolium, or bog mingimingi, is a species of plant endemic to New Zealand.","img":"images/1207.jpg","thumb":"images/t/1207.jpg","file":"Androstoma empetrifolia Hook.f. (AM AK351346).jpg","ar":0.626,"py":"","cr_by":"A. E. Wright","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":["大洋洲"],"illus_img":"images/i/1207.jpg","illus_thumb":"images/i/t/1207.jpg","illus_file":"Androstoma empetrifolia-Botany of Antarctica-PL030-0065.jpg","illus_ar":0.795,"illus_by":"Walter Hood Fitch","illus_lic":"Public domain","illus_licurl":null},{"id":1208,"seq":733,"zh":"观峰玉","en":"Fouquieria columnaris","sci":"Fouquieria columnaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Fouquieriaceae","family_zh":"福桂树科","iucn":"VU","langs":20,"desc_zh":"观峰玉（学名：Fouquieria columnaris），又名柱状福桂树或柱状福桂花，是福桂花属下的一种树。它们绝大部份都生长在下加利福尼亚半岛，只有少数生长在索诺拉州。其英文名称翻译是「可怕的怪物树」，是由戈弗雷·赛克斯（Godfrey Sykes）根据路易斯·卡罗（Lewis Carroll）的《猎鲨记》所取的。 观峰玉的独特分布令墨西哥植物学家相信它们是被原住的塞里人移植至大陆内。","desc_en":"Fouquieria columnaris, the Boojum tree or cirio (Latin American Spanish: [ˈsiɾjo]) is a tree in the ocotillo family, whose other members include the ocotillos. Some taxonomists place it in the separate genus Idria.","img":"images/1208.jpg","thumb":"images/t/1208.jpg","file":"Cirio columnaris, boojum tree.jpg","ar":0.75,"py":"guanfengyu gfy","cr_by":"Tomas Castelazo","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["北美洲"]},{"id":1209,"seq":734,"zh":"巴西栗","en":"Bertholletia excelsa","sci":"Bertholletia excelsa","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Lecythidaceae","family_zh":"玉蕊科","iucn":"VU","langs":54,"desc_zh":"巴西坚果（英文：Brazil nut，学名：Bertholletia excelsa）是高大的贝尔托莱氏木（Bertholletia excelsa）的可食种子。贝尔托莱氏木是玉蕊科巴西坚果属的植物，巴西坚果属只有巴西坚果一个种，植物名Bertholletia是以法国化学家克劳德·贝托莱的名字命名的。是世界上主要商业坚果和果仁类之一。原产于南美洲的圭亚那、委内瑞拉、巴西、哥伦比亚东部、秘鲁东部、玻利维亚东部。","desc_en":"Brazil nut (Bertholletia excelsa) refers to a South American tree of the monotypic genus Bertholletia in the family Lecythidaceae as well as the tree's commercially-harvested edible seeds.","img":"images/1209.jpg","thumb":"images/t/1209.jpg","file":"Bertholletia excelsa.jpg","ar":0.662,"py":"baxili bxl","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"]},{"id":1210,"seq":735,"zh":"Marcgravia umbellata","en":"Marcgravia umbellata","sci":"Marcgravia umbellata","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Marcgraviaceae","family_zh":"蜜囊花科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Marcgravia umbellata, also called monkey paws, is a species of flowering vine in the family Marcgraviaceae. It is native to the Lesser Antilles islands in the eastern Caribbean and Anguilla.","img":"images/1210.jpg","thumb":"images/t/1210.jpg","file":"Marcgravia umbellata - Berlin Botanical Garden - IMG 8726.JPG","ar":0.75,"py":"","cr_by":"Daderot","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["北美洲"]},{"id":1211,"seq":736,"zh":"假红树科","en":"Pelliciera rhizophorae","sci":"Pelliciera rhizophorae","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Pellicieraceae","family_zh":"假红树科","iucn":"VU","langs":13,"desc_zh":"假红树科只有1属1种，是单种科，假红树只生长在中美洲从哥斯达黎加到厄瓜多尔一带。 本科植物是常绿乔木，枝条丛生；单叶互生，有腺点；花大，花苞长，花瓣5数；果实大，直径达13厘米，类似椰子，皮干燥，但前面有一个尖端突出。 1981年的克朗奎斯特分类法将其列在山茶科中，1998年根据基因亲缘关系分类的APG 分类法认为应该单独分出一个科，2003年经过修订的APG II 分类法认为可以选择性地与四籽树科合并，但2007年5月7日新修订的版本…","desc_en":"Pelliciera rhizophorae, known as the tea mangrove, is a less-common species of mangroves found along the Pacific coast from the Gulf of Nicoya in Costa Rica to the Esmeraldas River in Ecuador, as well as within stands located in Nicaragua, Panama, and Colombia…","img":"images/1211.jpg","thumb":"images/t/1211.jpg","file":"Pelliciera rhizophorae.jpg","ar":1.333,"py":"jiahongshuke jhsk","cr_by":"Fabsiar","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["南美洲"]},{"id":1212,"seq":737,"zh":"红淡比","en":"Cleyera japonica","sci":"Cleyera japonica","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Pentaphylacaceae","family_zh":"五列木科","iucn":null,"langs":24,"desc_zh":"红淡比（学名： Cleyera japonica）为肖柃属常绿乔木。日本称之为榊（さかき）。","desc_en":"Cleyera japonica (sakaki) is a flowering evergreen tree native to warm areas of Japan, Taiwan, China, Myanmar, Nepal, and northern India (Min and Bartholomew 2015). It can reach a height of 10 m (33 ft). The leaves are 6–10 cm (2.4–3.","img":"images/1212.jpg","thumb":"images/t/1212.jpg","file":"W sakaki4061.jpg","ar":1.333,"py":"hongdanbi hdb","cr_by":"‘Uncle Carl’ (カールおじさん).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"],"illus_img":"images/i/1212.jpg","illus_thumb":"images/i/t/1212.jpg","illus_file":"Naturalis Biodiversity Center - RMNH.ART.354-Cleyera japonica-Malus halliana-Camellia japonica-Celtis sinensis-Morus sp.-Castanopsis sieboldii-Yūshi Ishizaki - Cock Blomhoff Collection - pencil drawing-water colour.jpg","illus_ar":0.711,"illus_by":"Ishizaki Yūshi","illus_lic":"Public domain","illus_licurl":null},{"id":1213,"seq":738,"zh":"锯齿捕蝇幌","en":"Roridula dentata","sci":"Roridula dentata","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Roridulaceae","family_zh":"捕蝇幌科","iucn":null,"langs":11,"desc_zh":"锯齿捕蝇幌（学名：Roridula dentata），一般直接称作捕虫树。为前食肉植物，原生于南非。","desc_en":"Roridula dentata (also called the northern dewstick) is a protocarnivorous plant native to the Western Cape province of South Africa. It can be found only in South Africa, in the hotter and more arid inland mountains of Clanwilliam, Tulbagh and Ceres, and can…","img":"images/1213.jpg","thumb":"images/t/1213.jpg","file":"Roridula dentata Helme 2.jpg","ar":0.75,"py":"juchibuyinghuang jcbyh","cr_by":"Nick Helme","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"]},{"id":1214,"seq":739,"zh":"毒药树","en":"Sladenia celastrifolia","sci":"Sladenia celastrifolia","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sladeniaceae","family_zh":"肋果茶科","iucn":null,"langs":8,"desc_zh":"毒药树（学名：Sladenia celastrifolia），为猕猴桃科毒药树属下的一个植物种。","desc_en":"Sladenia celastrifolia is a species of tree in the family Sladeniaceae. It is found in southwestern China (Yunnan and Guizhou), Thailand, and Myanmar.","img":"images/1214.png","thumb":"images/t/1214.png","file":"Sladenia celastrifolia.png","ar":0.58,"py":"duyaoshu dys","cr_by":"William Jackson Hooker","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":1215,"seq":740,"zh":"南欧安息香","en":"Styrax officinalis","sci":"Styrax officinalis","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Styracaceae","family_zh":"安息香科","iucn":"LC","langs":24,"desc_zh":null,"desc_en":"Styrax officinalis is a species of shrub in the family Styracaceae, commonly called the storax tree, or Snowdrop bush.","img":"images/1215.jpg","thumb":"images/t/1215.jpg","file":"Styrax officinalis.jpg","ar":1.297,"py":"nanouanxixiang noaxx","cr_by":"איתן פרמן","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"灌木","origin":null},{"id":1216,"seq":741,"zh":"白檀","en":"Symplocos paniculata","sci":"Symplocos paniculata","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Symplocaceae","family_zh":"山矾科","iucn":null,"langs":14,"desc_zh":"白檀（学名：Symplocos paniculata）为山矾科山矾属下的一个种。","desc_en":"Symplocos paniculata, called Asiatic sweetleaf or sapphire-berry, is a species of tree in the family Symplocaceae. It is native to all of eastern Asia and was introduced to the United States in around 1871.","img":"images/1216.jpg","thumb":"images/t/1216.jpg","file":"灰木.jpg","ar":1.494,"py":"baitan bt","cr_by":"Shih-Shiuan Kao","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["亚洲","北美洲"]},{"id":718,"seq":742,"zh":"杜仲","en":"Eucommia ulmoides","sci":"Eucommia ulmoides","order_en":"Garryales","order_zh":"绞木目","family_en":"Eucommiaceae","family_zh":"杜仲科","iucn":"VU","langs":29,"desc_zh":"杜仲（学名：Eucommia ulmoides），别名木棉、思仙、思仲、思锦树、石思仙、扯丝皮、棉皮、玉丝皮，为杜仲科植物。杜仲的化学成分包括木脂素类、环烯醚萜类、黄酮类、苯丙素类、甾醇类、三萜类、多糖类、抗真菌蛋白和矿物元素等。","desc_en":"Eucommia ulmoides is a species of small tree native to China. It belongs to the monotypic family Eucommiaceae. It is considered vulnerable in the wild, but is widely cultivated in China for its bark and is highly valued in herbology such as traditional Chinese…","img":"images/718.jpg","thumb":"images/t/718.jpg","file":"Eucommia-ulmoides.JPG","ar":1.499,"py":"duzhong dz","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":1217,"seq":743,"zh":"青木","en":"Aucuba japonica","sci":"Aucuba japonica","order_en":"Garryales","order_zh":"丝缨花目","family_en":"Garryaceae","family_zh":"丝缨花科","iucn":null,"langs":30,"desc_zh":"青木（学名：Aucuba japonica）为丝缨花科桃叶珊瑚属的植物。分布在朝鲜、日本及中国浙江等地。","desc_en":"Aucuba japonica, commonly called spotted laurel, Japanese laurel, Japanese aucuba or gold dust plant (U.S.), is a shrub (1–5 m, 3.3–16.4 ft) native to rich forest soils of moist valleys, thickets, by streams and near shaded moist rocks in China, Korea, and Jap…","img":"images/1217.jpg","thumb":"images/t/1217.jpg","file":"Spottedlaurelmale.JPG","ar":0.75,"py":"qingmu qm","cr_by":"Callum1234","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["亚洲"]},{"id":719,"seq":744,"zh":"檄树","en":"Morinda citrifolia","sci":"Morinda citrifolia","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":71,"desc_zh":"檄（xí）树（学名：Morinda citrifolia，又名海滨木巴戟、海巴戟，是茜草科巴戟天属的一种植物，与咖啡同科，灌木至小乔木，高1—5米（3英尺3英寸—16英尺5英寸），属于经济作物，分布于新加坡、马来西亚、印度尼西亚、台湾、海南、云南、西沙群岛、南沙群岛、永兴岛、澳大利亚、法属波利尼西亚、夏威夷等东南亚、太平洋岛屿。","desc_en":"Morinda citrifolia is a fruit-bearing tree in the coffee family, Rubiaceae. It is commonly known as noni or Indian mulberry, among many other names. Native to Southeast Asia and Australasia, the species was spread across the Pacific by Polynesian sailors.","img":"images/719.png","thumb":"images/t/719.png","file":"Morinda citrifolia Blanco1.52.png","ar":0.715,"py":"xishu xs","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","大洋洲"]},{"id":720,"seq":745,"zh":"小粒咖啡","en":"Coffea arabica","sci":"Coffea arabica","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"EN","langs":63,"desc_zh":"小果咖啡（学名：Coffea arabica）亦称阿拉伯咖啡、阿拉比卡咖啡，为茜草科（Rubiaceae）咖啡属的一个物种。小果咖啡原产于东非，属大灌木或小乔木，高度5到8米；叶薄革质，光滑深绿色，卵状披针形，长6—14厘米，宽3.5—5厘米，叶缘全缘成浅波浪状；花冠为白色，花期3～4月；核果椭圆形，成熟时变成红色，长约10～15毫米；常含两枚种子，称作咖啡豆。","desc_en":"Coffea arabica (), also known as the Arabica coffee, is a species of flowering plant in the coffee and madder family Rubiaceae. It is believed to be the first species of coffee to have been cultivated and is the dominant cultivar, representing about 60% of glo…","img":"images/720.jpg","thumb":"images/t/720.jpg","file":"Coffee Flowers.JPG","ar":1.333,"py":"xiaolikafei xlkf","cr_by":"Marcelo Corrêa","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/720.jpg","illus_thumb":"images/i/t/720.jpg","illus_file":"Coffea arabica -Köhler-original.jpg","illus_ar":0.725,"illus_by":"Köhler","illus_lic":"Public domain","illus_licurl":null},{"id":721,"seq":746,"zh":"香猪殃殃","en":"sweet woodruff","sci":"Galium odoratum","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":60,"desc_zh":"香猪殃殃（学名：Galium odoratum）又名香车叶草，是茜草科猪殃殃属的植物，原产于欧洲、西亚及北非。植株具有香味，可以添加在食物及酒内以增加食品的风味。 多年生草本植物，植株长三十至五十公分，常平卧在地面上或攀附在其他植物上。叶为单叶，披针形，光滑无毛，长二至五公分，叶六至九片轮生。花小，花径四至七公厘，白色，每一朵花有四片花瓣，花瓣在基部合生，花序为聚繖花序。","desc_en":"Galium odoratum, the sweet woodruff or sweetscented bedstraw, is a flowering perennial plant in the family Rubiaceae, native to much of Europe. It is widely cultivated for its flowers and its sweet-smelling foliage.","img":"images/721.jpg","thumb":"images/t/721.jpg","file":"Waldmeister.jpg","ar":0.75,"py":"xiangzhuyangyang xzyy","cr_by":"Jopi","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"],"illus_img":"images/i/721.jpg","illus_thumb":"images/i/t/721.jpg","illus_file":"Galium odoratum Sturm47.jpg","illus_ar":0.659,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":722,"seq":747,"zh":"蓬子菜","en":"Galium verum","sci":"Galium verum","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":58,"desc_zh":"蓬子菜（学名：Galium verum）为茜草科拉拉藤属下的一个种。","desc_en":"Galium verum (lady's bedstraw or yellow bedstraw) is a herbaceous perennial flowering plant in the family Rubiaceae. It is widespread across most of Europe, North Africa, and temperate Asia from Israel, Lebanon and Turkey to Japan and Kamchatka.","img":"images/722.jpg","thumb":"images/t/722.jpg","file":"Galium verum 02.jpg","ar":0.75,"py":"pengzicai pzc","cr_by":"Bjoertvedt","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/722.jpg","illus_thumb":"images/i/t/722.jpg","illus_file":"Galium verum Lindman DESC.JPG","illus_ar":1.504,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":723,"seq":748,"zh":"原拉拉藤","en":"Galium aparine","sci":"Galium aparine","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":51,"desc_zh":"原拉拉藤（学名：Galium aparine），或称为欧洲猪殃殃，为茜草科拉拉藤属下的一个种。","desc_en":"Galium aparine, with common names including cleavers, clivers, catchweed, robin-run-the-hedge, goosegrass, and sticky willy, is an annual, herbaceous plant of the family Rubiaceae.","img":"images/723.jpg","thumb":"images/t/723.jpg","file":"Flowers February 2008-4.jpg","ar":0.898,"py":"yuanlalateng yllt","cr_by":"Alvesgaspar","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null,"illus_img":"images/i/723.jpg","illus_thumb":"images/i/t/723.jpg","illus_file":"Illustration Galium aparine0.jpg","illus_ar":0.596,"illus_by":"Prof. Dr. Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":724,"seq":749,"zh":"栀子花","en":"Gardenia jasminoides","sci":"Gardenia jasminoides","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":51,"desc_zh":"栀（zhī）子（zi）（学名：Gardenia jasminoides），又名木丹、鲜支、卮（zhī）子、越桃、白蟾花､ 林兰､ 水横枝、栀子花、支子花、枝子花、山栀花、黄鸡子、黄荑子、黄栀子、黄栀、黄栀花、山黄栀、玉荷花、白婵花、玉堂春，属茜草科栀子属常绿植物。 因栀子的花香清雅甜美，故为中国典型香花植物之一。常与梅、百合、菊、连香树、茉莉花、水仙合称为「七香」。中国两汉时期，种植栀子花，多为染物之用，为珍贵的经济作物之一。","desc_en":"Gardenia jasminoides, commonly known as gardenia and cape jasmine, is an evergreen flowering plant in the coffee family Rubiaceae. It is native to the subtropical and northern tropical parts of the Far East.","img":"images/724.jpg","thumb":"images/t/724.jpg","file":"Gardenia jasminoides in Mount Yagi 2008-06-13.jpg","ar":1.466,"py":"zhizihua zzh","cr_by":"Alpsdake","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null,"illus_img":"images/i/724.jpg","illus_thumb":"images/i/t/724.jpg","illus_file":"The American Flora. Vol. 4, 1855 - pl. 41 Gardenia jasminoides (14596775310).jpg","illus_ar":0.7,"illus_by":"Anonymous Unknown author [illustrator not stated, no signature]","illus_lic":"Public domain","illus_licurl":null},{"id":725,"seq":750,"zh":"染色茜草","en":"Rubia tinctorum","sci":"Rubia tinctorum","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":48,"desc_zh":"染色茜草（学名：Rubia tinctorum），为茜草科茜草属下的一种多年生草本植物，高可达1.5米，土耳其红和茜草玫瑰红是从该植物的根提取出来的，是西方古代较常见的染料，印度摩亨朱-达罗遗址中也发现了使用这种植物染色的棉布。","desc_en":"Rubia tinctorum, the rose madder or common madder or dyer's madder, is a herbaceous perennial plant species belonging to the bedstraw and coffee family Rubiaceae. The type genus of the whole Rubiaceae family of around 80 flowering plants is called Rubia.","img":"images/725.jpg","thumb":"images/t/725.jpg","file":"Rubia tinctorum flowers.jpg","ar":0.918,"py":"ranseqiancao rsqc","cr_by":"Carstor","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null,"illus_img":"images/i/725.jpg","illus_thumb":"images/i/t/725.jpg","illus_file":"Rubia tinctorum - Köhler–s Medizinal-Pflanzen-123.jpg","illus_ar":0.769,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":726,"seq":751,"zh":"中果咖啡","en":"Coffea canephora","sci":"Coffea canephora","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":45,"desc_zh":"中果咖啡（学名：Coffea canephora）又名卡尼弗拉咖啡，异名罗布斯塔咖啡，是世界咖啡生产的第二大种，它在全球咖啡产量中占了大约43%，与小果咖啡达成平衡。 中果咖啡的浆果较小果咖啡大但比大果咖啡小，比小果咖啡抗病害能力强。中果咖啡适合在海拔700公尺以下的热带气候中生长，含咖啡因浓度高，约为2%-4%，但入口有苦、烧橡胶味，主要在印度尼西亚、印度、乌干达及越南等一些热带国家种植，大部分作为即溶咖啡之用。","desc_en":"Coffea canephora (especially C. canephora subvar. robusta, syn. Coffea robusta, or commonly robusta coffee) is a species of coffee plant that has its origins in central and western sub-Saharan Africa. It is a species of flowering plant in the family Rubiaceae.","img":"images/726.jpg","thumb":"images/t/726.jpg","file":"Coffea canephora berries.JPG","ar":1.333,"py":"zhongguokafei zgkf","cr_by":"Ksd5","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["非洲"]},{"id":727,"seq":752,"zh":"大果咖啡","en":"Coffea liberica","sci":"Coffea liberica","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":39,"desc_zh":"大果咖啡（学名：Coffea liberica）又名赖比瑞亚咖啡、利比里卡咖啡，亦称利比里亚种（Liberica），是一种抗虫害、适合高温潮湿气候的物种，其浆果和种子都要比小果咖啡大到近两倍，香味浓郁，但味淡，一般北欧人比较喜欢这种咖啡。主要在非洲利比里亚、科特迪瓦、马达加斯加种植。 高产咖啡现在被认为是大果咖啡的异名","desc_en":"Coffea liberica, commonly known as Liberian coffee, is a species of flowering plant in the family Rubiaceae from which coffee is produced. It is native to western and central Africa (from Liberia to Uganda and Angola), and has become naturalised in areas inclu…","img":"images/727.jpg","thumb":"images/t/727.jpg","file":"Coffee tree chary.jpg","ar":0.734,"py":"daguokafei dgkf","cr_by":"DXLINH","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲","南美洲"]},{"id":728,"seq":753,"zh":"卡痛","en":"Mitragyna speciosa","sci":"Mitragyna speciosa","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":39,"desc_zh":"卡痛树（学名：Mitragyna speciosa）是一种主长于东南亚的热带多年生常绿乔本。卡痛树的叶子，卡痛叶，有类似鸦片的镇定和刺激效果。有历史记载，卡痛叶被用作民间草药和偏方，有体力劳动者会用卡痛叶提神。 2019年，美国药监局警告消费者避免摄入卡痛叶，并申明未曾准许卡痛叶的医疗使用。","desc_en":"Mitragyna speciosa is a tropical evergreen tree of the Rubiaceae family native to Southeast Asia. It is indigenous to Cambodia, Thailand, Indonesia, Malaysia, Myanmar, and Papua New Guinea, where its dark green, glossy leaves, known as kratom, have been used i…","img":"images/728.jpg","thumb":"images/t/728.jpg","file":"Mitragyna speciosa111.JPG","ar":1.333,"py":"katong kt","cr_by":"Uomo vitruviano","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":734,"seq":754,"zh":"夹竹桃","en":"Nerium oleander","sci":"Nerium oleander","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":"LC","langs":99,"desc_zh":"夹竹桃（学名：Nerium oleander），又名洋夹竹桃或欧洲夹竹桃，是龙胆目夹竹桃科夹竹桃属的唯一一种，为常绿灌木或小乔木，原生于地中海盆地，因为茎部像竹，花朵像桃，因而为名，也是具观赏价值的中草药。北非古城沃吕比利斯就是以洋夹竹桃的旧拉丁文名而取名的。","desc_en":"Nerium oleander ( NEER-ee-əm), commonly known as oleander, rose laurel, be-still tree or rosebay, is a shrub or small tree cultivated worldwide in temperate and subtropical areas as an ornamental and landscaping plant.","img":"images/734.jpg","thumb":"images/t/734.jpg","file":"Nerium oleander flowers leaves.jpg","ar":1.369,"py":"jiazhutao jzt","cr_by":"Alvesgaspar","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":null},{"id":735,"seq":755,"zh":"长春花","en":"Catharanthus roseus","sci":"Catharanthus roseus","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":65,"desc_zh":"长春花（学名：Catharanthus roseus），别名日日春、日日草、日日新、三万花（广西、广东）、四时春、时钟花、雁来红（广东）、五瓣梅、王瓣梅、五合梅（潮汕）、长春海棠，是夹竹桃科长春花属植物。","desc_en":"Catharanthus roseus, commonly known as bright eyes, Cape periwinkle, graveyard plant, Madagascar periwinkle, old maid, pink periwinkle, rose periwinkle, is a perennial species of flowering plant in the family Apocynaceae.","img":"images/735.jpg","thumb":"images/t/735.jpg","file":"2019-08-02 Catharanthus roseus, Ifaty, Madagascar 2.jpg","ar":1.333,"py":"changchunhua cch","cr_by":"imbeaul","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["非洲"]},{"id":736,"seq":756,"zh":"小蔓长春花","en":"Vinca minor","sci":"Vinca minor","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":59,"desc_zh":"小蔓长春花（学名：Vinca minor）是夹竹桃科蔓长春花属的植物。分布在欧洲以及中国大陆的江苏等地，目前尚未由人工引种栽培。 其种加词“minor”意为“较小的”。","desc_en":"Vinca minor (common names lesser periwinkle or dwarf periwinkle) is a species of flowering plant in the dogbane family, native to central and southern Europe.","img":"images/736.jpg","thumb":"images/t/736.jpg","file":"20130421Vinca minor1.jpg","ar":1.333,"py":"xiaomanchangchunhua xmcch","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲"],"illus_img":"images/i/736.jpg","illus_thumb":"images/i/t/736.jpg","illus_file":"Illustration Vinca minor0.jpg","illus_ar":0.593,"illus_by":"Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":737,"seq":757,"zh":"黑板树","en":"Alstonia scholaris","sci":"Alstonia scholaris","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":"LC","langs":47,"desc_zh":"黑板树（学名：Alstonia scholaris）又称象皮树、灯架树、糖胶树、乳木、魔神树等，为夹竹桃科鸡骨常山属的模式种。常绿大乔木，其树体高大，为具有明显主干的乔木，株高15~25公尺，树冠伞盖状，树干挺直灰褐色、枝轮生、具白色乳液。叶序为单叶轮生，小叶4~10枚，叶面深绿、叶背浅白色。花是黄白色，花冠径8~12公分。荚果褐色，长30~60公分细长圆柱形，姿态优美，且不易落叶，对环境适应力强，属于快速生长的绿化植物。","desc_en":"Alstonia scholaris, commonly called blackboard tree, scholar tree, milkwood or devil's tree in English, is an evergreen tree in the oleander and frangipani family Apocynaceae. Its natural range is from Pakistan to China, and south to northern Australia.","img":"images/737.jpg","thumb":"images/t/737.jpg","file":"Alstonia scholaris at Sungai Berang valley, Kampung Gunung 20240225 164615.jpg","ar":0.75,"py":"heibanshu hbs","cr_by":"Wiki Farazi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":738,"seq":758,"zh":"蛇根木","en":"Rauvolfia serpentina","sci":"Rauvolfia serpentina","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":47,"desc_zh":"蛇根木（学名：Rauvolfia serpentina）为夹竹桃科萝芙木属的植物。分布在大洋洲、泰国、印度尼西亚、缅甸、斯里兰卡、印度以及中国的云南、广西、广东等地，目前已由人工引种栽培。","desc_en":"Rauvolfia serpentina, the Indian snakeroot, devil pepper, serpentine wood, Sarpagandha (as known locally) or Chandrika, is a species of flower in the milkweed family Apocynaceae. It is native to the Indian subcontinent and East Asia (from India to Indonesia).","img":"images/738.png","thumb":"images/t/738.png","file":"Hortus Cliffortianus Rauvolfia.png","ar":0.603,"py":"shegenmu sgm","cr_by":"Carl von Linné (1707-1778)","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":739,"seq":759,"zh":"牛角瓜","en":"Calotropis gigantea","sci":"Calotropis gigantea","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":45,"desc_zh":"牛角瓜（学名：Calotropis gigantea，英文名称：Akund Calotrope、Bowstring Hemp、Crownplant、Madar、Mudar），别称断肠草（广东）、五狗卧花（广东崖县）、羊浸树（云南、广东）、羊浸渣叶、哮喘树、大麻风药、奶浆包、皇冠花、紫冠花、五狗卧花心、野攀枝花及牛角瓜叶等，为夹竹桃科牛角瓜属植物，本种的模式标本采自于印度。","desc_en":"Calotropis gigantea, the crown flower, is a species of Calotropis native to India, Cambodia, Vietnam, Bangladesh, Indonesia, Malaysia, Philippines,Thailand, Sri Lanka, China, Pakistan, and Nepal. It is a large shrub growing to 4 m (13 ft) tall.","img":"images/739.jpg","thumb":"images/t/739.jpg","file":"(Arya) Calotropis gigantea flower Pilangsari 2019.jpg","ar":1.333,"py":"niujiaogua njg","cr_by":"Aris riyanto","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲"]},{"id":740,"seq":760,"zh":"黄花夹竹桃","en":"Cascabela thevetia","sci":"Cascabela thevetia","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":"LC","langs":41,"desc_zh":"黄花夹竹桃（学名：Thevetia peruviana），亦称黄酒杯花，夹竹桃科黄花夹竹桃属，常见灌木或小乔木。其种加词“peruviana”意为“秘鲁的”。","desc_en":"Cascabela thevetia (syn. Thevetia peruviana) is a species of poisonous plant in the dogbane family Apocynaceae, native throughout Mexico and Central America and cultivated widely as an ornamental.","img":"images/740.jpg","thumb":"images/t/740.jpg","file":"Yellow Oleander (Thevetia peruviana) leaves & flowers in Kolkata W IMG 8008.jpg","ar":1.032,"py":"huanghuajiazhutao hhjzt","cr_by":"J.M.Garg","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"]},{"id":744,"seq":761,"zh":"红色百金花","en":"Centaurium erythraea","sci":"Centaurium erythraea","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":"LC","langs":56,"desc_zh":"日本鬼灯檠（学名：Centaurium erythraea），或称红百金花、苦护胆与矢车菊，是一种植物，常被用来当作药草，晒干之后可以制成药草茶，而日本鬼灯檠制作的药草茶，有著治疗肝及肾方面毛病的妙用，并具有调理血压的效果。除此之外，将磨碎的日本鬼灯檠涂在伤口上，也可以止痛，是一种效用十分广泛的药用植物。","desc_en":"Centaurium erythraea is a species of flowering plant in the gentian family known by the names common centaury and European centaury. It is also commonly known as feverfoullie, gentian or centaury.","img":"images/744.jpg","thumb":"images/t/744.jpg","file":"Centaurium erythraea (flowers).jpg","ar":1.333,"py":"hongsebaijinhua hsbjh","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/744.jpg","illus_thumb":"images/i/t/744.jpg","illus_file":"Centaurium erythraea - Köhler–s Medizinal-Pflanzen-058.jpg","illus_ar":0.753,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":745,"seq":762,"zh":"黄龙胆","en":"Gentiana lutea","sci":"Gentiana lutea","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":null,"langs":52,"desc_zh":"黄龙胆（学名：Gentiana lutea）是原产于中欧和南欧山区的一种龙胆科植物。","desc_en":"Gentiana lutea, the great yellow gentian, is a species of gentian native to the mountains of central and southern Europe, including the Alps, the Carpathians (where scarce), the Pyrenees, the Apennines, and the mountains of the Balkan Peninsula.","img":"images/745.jpg","thumb":"images/t/745.jpg","file":"Gentiana lutea 230705.jpg","ar":0.752,"py":"huanglongdan hld","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"],"illus_img":"images/i/745.jpg","illus_thumb":"images/i/t/745.jpg","illus_file":"Gentiana lutea - Köhler–s Medizinal-Pflanzen-066.jpg","illus_ar":0.769,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":746,"seq":763,"zh":"春花龙胆","en":"Gentiana verna","sci":"Gentiana verna","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":null,"langs":36,"desc_zh":"春花龙胆（Gentiana verna）是龙胆属的一种低矮草本植物，春末夏初开蓝色花，偶尔开粉红或白色花，花朵五瓣，直径1-2厘米。广泛分布于亚洲大陆北部和欧洲大陆、英国和爱尔兰，海拔可达2,600米（8,500英尺）。","desc_en":"Gentiana verna, the spring gentian, is a species of flowering plant in the family Gentianaceae, and one of its smallest members, normally only growing to a height of a few centimetres.","img":"images/746.jpg","thumb":"images/t/746.jpg","file":"Gentiana verna (1).JPG","ar":0.8,"py":"chunhualongdan chld","cr_by":"Philipp Weigell","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":null},{"id":747,"seq":764,"zh":"蓝色龙胆","en":"Gentiana pneumonanthe","sci":"Gentiana pneumonanthe","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Gentiana pneumonanthe, the marsh gentian, is a species of the genus Gentiana. It was the first wildflower announced as flower of the year in Germany in 1980. The species can be found in marshes and moorlands.","img":"images/747.jpg","thumb":"images/t/747.jpg","file":"Gentiana pneumonanthe 130805a.jpg","ar":0.67,"py":"lanselongdan lsld","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null,"illus_img":"images/i/747.jpg","illus_thumb":"images/i/t/747.jpg","illus_file":"Gentiana pneumonanthe — Flora Batava — Volume v5.jpg","illus_ar":0.673,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":749,"seq":765,"zh":"马钱子","en":"Strychnos nux-vomica","sci":"Strychnos nux-vomica","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Loganiaceae","family_zh":"马钱科","iucn":null,"langs":52,"desc_zh":"马钱子（学名：Strychnos nux-vomica）也称番木鳖、苦实把豆儿、火失刻把都、苦实、马前、牛眼、大方八、马钱树，是马钱科马钱属的一种落叶乔木。产于南亚和东南亚等地，喜热带湿润性气候，怕霜冻。模式标本采自斯里兰卡科伦坡。种子有毒，主要含有马钱子碱（strychnine，又名番木鳖碱）等多种生物碱。西医学上用种子提取物作中枢神经兴奋剂。中医学上以种子泡制后入药，有通络散结、消肿止痛之效。","desc_en":"Strychnos nux-vomica, the strychnine tree, also known as nux vomica, poison fruit, semen strychnos, and quaker buttons, is a deciduous tree native to India and to southeast Asia. It is a medium-sized tree in the family Loganiaceae that grows in open habitats.","img":"images/749.jpg","thumb":"images/t/749.jpg","file":"Strychnos nux-vomica - Köhler–s Medizinal-Pflanzen-266.jpg","ar":0.741,"py":"maqianzi mqz","cr_by":"Franz Eugen Köhler","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"],"illus_img":"images/i/749.jpg","illus_thumb":"images/i/t/749.jpg","illus_file":"Strychnos nux-vomica - Köhler–s Medizinal-Pflanzen-266.jpg","illus_ar":0.741,"illus_by":"Franz Eugen Köhler","illus_lic":"Public domain","illus_licurl":null},{"id":1218,"seq":766,"zh":"常绿钩吻藤","en":"Gelsemium sempervirens","sci":"Gelsemium sempervirens","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gelsemiaceae","family_zh":"钩吻科","iucn":null,"langs":19,"desc_zh":null,"desc_en":"Gelsemium sempervirens is a twining vine in the family Gelsemiaceae, native to subtropical and tropical America: Honduras, Guatemala, Belize, Mexico (Chiapas, Oaxaca, Veracruz, Puebla, Hidalgo), and southeastern and south-central United States (from Texas to V…","img":"images/1218.jpg","thumb":"images/t/1218.jpg","file":"Gelsemium sempervirens3.jpg","ar":1.346,"py":"changlgouwenteng clgwt","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["北美洲"],"illus_img":"images/i/1218.jpg","illus_thumb":"images/i/t/1218.jpg","illus_file":"Gelsemium sempervirens - Köhler–s Medizinal-Pflanzen-065.jpg","illus_ar":0.678,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":750,"seq":767,"zh":"琉璃苣","en":"borage","sci":"Borago officinalis","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":80,"desc_zh":"琉璃苣（学名：Borago officinalis）是一种一年生草本植物，原产于叙利亚，目前已经被广泛引种到欧洲、西亚、北非和南美洲等地。 琉璃苣株高一般为60-100厘米，叶互生粗糙，有柄，5-10厘米长，叶和茎上都有毛刺；花的花瓣5裂，通常为蓝色，但也有粉色或白色的变种，为疏散的聚伞花序，同株异花授粉，夏季开花，但在气候温暖适宜的地区可全年开花；果实为小坚果。 琉璃苣的花语：「勇气」。","desc_en":"Borage ( or ; Borago officinalis), also known as starflower, is an annual herb in the flowering plant family Boraginaceae native to the Mediterranean region.","img":"images/750.jpg","thumb":"images/t/750.jpg","file":"00 2100 Borretsch (Borago officinalis).jpg","ar":0.78,"py":"liuliju llj","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/750.jpg","illus_thumb":"images/i/t/750.jpg","illus_file":"Illustration Borago officinalis0.jpg","illus_ar":0.625,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":751,"seq":768,"zh":"聚合草","en":"Symphytum officinale","sci":"Symphytum officinale","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":59,"desc_zh":"聚合草（学名：Symphytum officinale）为紫草科聚合草属的植物。分布在俄罗斯以及中国大陆的 福建省、 四川省、 中国、 湖北省、江苏省等地，目前已由人工引种栽培。 花语为“寂静”。为多年生草本，高60~90公分，有香气。有补血、止泻之效。主治高血压、出血、止痢等，并有防癌、抗癌作用。","desc_en":"Symphytum officinale is a perennial flowering plant in the family Boraginaceae. Along with thirty four other species of Symphytum, it is known as comfrey (from the Latin confervere to 'heal' or literally to 'boil together', referring to uses in ancient traditi…","img":"images/751.jpg","thumb":"images/t/751.jpg","file":"Symphytum officinale 01.jpg","ar":0.75,"py":"juhecao jhc","cr_by":"Agnieszka Kwiecień ( Nova )","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":["欧洲","北美洲"],"illus_img":"images/i/751.jpg","illus_thumb":"images/i/t/751.jpg","illus_file":"Symphytum officinale - Köhler–s Medizinal-Pflanzen-268.jpg","illus_ar":0.86,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":752,"seq":769,"zh":"蓝蓟","en":"Echium vulgare","sci":"Echium vulgare","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":55,"desc_zh":"蓝蓟（学名：Echium vulgare）为紫草科蓝蓟属下的一个种。","desc_en":"Echium vulgare, known as viper's bugloss and blueweed, is a species of flowering plant in the borage family Boraginaceae. It is native to most of Europe and western and central Asia and it occurs as an introduced species in north-eastern North America, south-w…","img":"images/752.jpg","thumb":"images/t/752.jpg","file":"Dettaglio - Borraginaceae Echium vulgare Lin. Erbario Frizzi Perugia n. 731.jpg","ar":0.75,"py":"lanji lj","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","北美洲","南美洲","大洋洲"],"illus_img":"images/i/752.jpg","illus_thumb":"images/i/t/752.jpg","illus_file":"Echium vulgare Sturm11021.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":753,"seq":770,"zh":"沼泽勿忘草","en":"Myosotis scorpioides","sci":"Myosotis scorpioides","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":46,"desc_zh":"沼泽勿忘草（学名：Myosotis scorpioides）是紫草科勿忘草属多年生草本植物，原产欧洲、西亚、中亚、北亚，在美洲部分地区归化，常生于浅水或湿草地。","desc_en":"Myosotis scorpioides (syn. Myosotis palustris), the true forget-me-not or water forget-me-not, is a forget-me-not plant species in the borage family, Boraginaceae.","img":"images/753.jpg","thumb":"images/t/753.jpg","file":"Myosotis scorpioides - Niitvälja bog.jpg","ar":0.8,"py":"zhaozewuwangcao zzwwc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/753.jpg","illus_thumb":"images/i/t/753.jpg","illus_file":"Myosotis scorpioides — Flora Batava — Volume v3.jpg","illus_ar":0.693,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":754,"seq":771,"zh":"蓝花肺草","en":"Pulmonaria officinalis","sci":"Pulmonaria officinalis","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":"LC","langs":46,"desc_zh":null,"desc_en":"Pulmonaria officinalis, common names lungwort, common lungwort, Mary's tears or Our Lady's milk drops, is a herbaceous rhizomatous evergreen perennial plant of the genus Pulmonaria, belonging to the family Boraginaceae.","img":"images/754.jpg","thumb":"images/t/754.jpg","file":"Pulmonaria officinalis 800.jpg","ar":0.844,"py":"lanhuafeicao lhfc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/754.jpg","illus_thumb":"images/i/t/754.jpg","illus_file":"Pulmonaria officinalis Sturm10.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":755,"seq":772,"zh":"森林勿忘草","en":"Myosotis sylvatica","sci":"Myosotis sylvatica","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":44,"desc_zh":"森林勿忘草（学名：Myosotis sylvatica），又名森林勿忘我（英语：wood forget-me-not）、林地勿忘我（英语：woodland forget-me-not）、花园勿忘我（英语：garden forget-me-not），是紫草科勿忘草属二年生或多年生草本植物。","desc_en":"Myosotis sylvatica, the wood forget-me-not or woodland forget-me-not, is a species of flowering plant in the family Boraginaceae, native to Europe. This spring-flowering plant and its cultivars, typically with blue flowers, are the familiar forget-me-nots of g…","img":"images/755.jpg","thumb":"images/t/755.jpg","file":"Myosotis sylvatica (aka).jpg","ar":1.342,"py":"senlinwuwangcao slwwc","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"],"illus_img":"images/i/755.jpg","illus_thumb":"images/i/t/755.jpg","illus_file":"Myosotis sylvatica — Flora Batava — Volume v11.jpg","illus_ar":0.78,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1219,"seq":773,"zh":"Codon royenii","en":"Codon royenii","sci":"Codon royenii","order_en":"Boraginales","order_zh":"紫草目","family_en":"Codonaceae","family_zh":"刺钟花科","iucn":null,"langs":7,"desc_zh":null,"desc_en":"Codon royenii is a species of flowering plant in the genus Codon. It is native to Namibia and the Northern Cape Province of South Africa. It is also known by the names honey bush or white nectarcup, or in Afrikaans as heuningbos and suikerkelk (meaning sugar c…","img":"images/1219.jpg","thumb":"images/t/1219.jpg","file":"Codon royenii 1DS-II 2-2824.jpg","ar":0.667,"py":"","cr_by":"SAplants","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["非洲"]},{"id":1220,"seq":774,"zh":"毛叶破布木","en":"Cordia myxa","sci":"Cordia myxa","order_en":"Boraginales","order_zh":"紫草目","family_en":"Cordiaceae","family_zh":"破布木科","iucn":"LC","langs":24,"desc_zh":"毛叶破布木（学名：Cordia myxa），为紫草科破布木属下的一个植物种。","desc_en":"Cordia myxa, also called sebesten plum, Assyrian plum, Indian cherry, glue berry, lasura, or bambar is a mid-sized, deciduous tree in the family Cordiaceae, native to Asia. It produces small, edible fruit and is found in warmer areas across Africa and Asia.","img":"images/1220.jpg","thumb":"images/t/1220.jpg","file":"Cordia myxa MS 1790.jpg","ar":1.501,"py":"maoyepobumu mypbm","cr_by":"Marco Schmidt [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","非洲"]},{"id":1221,"seq":775,"zh":"基及树","en":"Ehretia microphylla","sci":"Ehretia microphylla","order_en":"Boraginales","order_zh":"紫草目","family_en":"Ehretiaceae","family_zh":"厚壳树科","iucn":null,"langs":21,"desc_zh":"基及树（学名：Ehretia microphylla），又名小叶厚壳树，俗称福建茶或猫仔树，日文名福満木（フクマンギ）为紫草科厚壳树属下的一个种，原生于亚洲东半部、新几内亚、澳洲东北部与索罗门群岛，在夏威夷则是入侵物种。 其种加词microphylla，意为“小叶的”。","desc_en":"Ehretia microphylla is commonly known as the Fukien tea tree or Philippine tea tree, is a species of flowering plant. The genus Ehretia is placed in the family Ehretiaceae.","img":"images/1221.jpg","thumb":"images/t/1221.jpg","file":"Ehretia microphylla flower in Naha, Okinawa.jpg","ar":1.333,"py":"jijishu jjs","cr_by":"M108t","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["亚洲"]},{"id":1222,"seq":776,"zh":"香水草","en":"Heliotropium arborescens","sci":"Heliotropium arborescens","order_en":"Boraginales","order_zh":"紫草目","family_en":"Heliotropiaceae","family_zh":"天芥菜科","iucn":null,"langs":22,"desc_zh":"南美天芥菜（学名：Heliotropium arborescens），又名香水草、洋茉莉，是紫草科天芥菜属的植物。分布于秘鲁以及中国大陆等地，目前已由人工引种栽培。因其花具有浓郁独特之香味，故又名“香水草”，可制成香料。也是切花、花坛、盆栽的很好材料。","desc_en":"Heliotropium arborescens, the garden heliotrope or just heliotrope, is a species of flowering plant in the family Heliotropiaceae, native to Bolivia, Colombia, and Peru. Common names also include cherry pie and common heliotrope.","img":"images/1222.jpg","thumb":"images/t/1222.jpg","file":"Heliotropium arborescens 'Mini Marine' Heliotrope Flower 2500px.jpg","ar":1.563,"py":"xiangshuicao xsc","cr_by":"Photo (c)2006 Derek Ramsey ( Ram-Man )","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["南美洲"]},{"id":1223,"seq":777,"zh":"Wellstedia socotrana","en":"Wellstedia socotrana","sci":"Wellstedia socotrana","order_en":"Boraginales","order_zh":"紫草目","family_en":"Wellstediaceae","family_zh":"蒴紫草科","iucn":"VU","langs":8,"desc_zh":null,"desc_en":"Wellstedia socotrana is a species of flowering plant in the family Wellstediaceae. It is a subshrub native to northeastern Somalia and southern Socotra.","img":"images/1223.jpg","thumb":"images/t/1223.jpg","file":"Transactionsofro311888roy 0859.jpg","ar":0.705,"py":"","cr_by":"Matilda Smith / McFarlane & Erskine Ltd","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["非洲"]},{"id":757,"seq":778,"zh":"番茄","en":"tomato","sci":"Solanum lycopersicum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":208,"desc_zh":"番茄（学名：Solanum lycopersicum）是茄科茄属的一种植物。番茄原产于中美洲和南美洲，现作为食用蔬果已被全球广泛种植，同时具医疗效用，是茄科开花植物的模型生物之一。","desc_en":"The tomato (US: , UK: ; Solanum lycopersicum) is a plant whose fruit is an edible berry that is eaten as a vegetable. The tomato is a member of the nightshade family that includes tobacco, potato, and chili peppers.","img":"images/757.jpg","thumb":"images/t/757.jpg","file":"Bright red tomato and cross section02.jpg","ar":1.499,"py":"fanqie fq","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Sigma 150mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"草本","origin":["北美洲","南美洲"]},{"id":758,"seq":779,"zh":"马铃薯","en":"potato","sci":"Solanum tuberosum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":197,"desc_zh":"马铃薯（学名：Solanum tuberosum），属茄科茄属多年生草本植物，块茎可供食用，是全球第四大重要的粮食作物，仅次于稻米、玉米和小麦。原产于南美洲秘鲁与玻利维亚境内的安地斯山脉。马铃薯的人工栽培最早可追溯到大约公元前8000年到公元前5000年的秘鲁南部地区。大航海时代马铃薯与其他物种被装船带回欧亚大陆的菜单当中，现在是欧美地区许多国家的主食。","desc_en":"The potato () is a starchy tuberous vegetable native to the Americas that is consumed as a staple food in many parts of the world. Potatoes are underground stem tubers of the plant Solanum tuberosum, a perennial in the nightshade family Solanaceae.","img":"images/758.jpg","thumb":"images/t/758.jpg","file":"234 Solanum tuberosum L.jpg","ar":0.666,"py":"malingshu mls","cr_by":"Amédée Masclef","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":759,"seq":780,"zh":"茄","en":"Solanum melongena","sci":"Solanum melongena","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":170,"desc_zh":"茄（学名：Solanum melongena），官话、晋语、湘语多称茄子，粤语多称矮瓜，客语有叫吊菜，吴语、徽语有叫落苏，闽南语有叫红菜，闽东语称作紫菜或茄囝，潮州话叫力苏，新竹人特别称之昭惟。茄子是茄科茄属的一年生草本植物，部分热带品系为多年生，其结出的果实可食用，颜色多为紫色或紫黑色，也有淡绿色或白色品种，形状上也有长条形、圆形、椭圆、梨形等各种。根据品种的不同，食用方法多样。","desc_en":"Eggplant (in North American, Australian, and Philippine English), aubergine (in British, Irish, and New Zealand English), brinjal (in Indian, Bangladeshi, Pakistani, Singapore, Malaysian, South African, and Sri Lankan English), or baigan (in Caribbean English)…","img":"images/759.jpg","thumb":"images/t/759.jpg","file":"Solanum melongena 24 08 2012 (1).JPG","ar":0.916,"py":"qie q","cr_by":"Joydeep","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":760,"seq":781,"zh":"辣椒","en":"Capsicum annuum","sci":"Capsicum annuum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":"LC","langs":91,"desc_zh":"一年生辣椒（学名：Capsicum annuum），即普通辣椒，是一种原产于美洲中部的辣椒属植物物种。该物种是辣椒属五个栽培种之中，被最为广泛种植的辣椒物种。1900万年前，番茄和辣椒有共同的祖先，后驯化栽培成为全球性最大宗也最广泛的经济种。","desc_en":"Capsicum annuum is a flowering plant in the family Solanaceae (nightshades), native to the northern regions of South America and to southwestern North America.","img":"images/760.jpg","thumb":"images/t/760.jpg","file":"Capsicum annuum - Köhler–s Medizinal-Pflanzen-027.jpg","ar":0.808,"py":"lajiao lj","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲","南美洲"],"illus_img":"images/i/760.jpg","illus_thumb":"images/i/t/760.jpg","illus_file":"Capsicum annuum - Köhler–s Medizinal-Pflanzen-027.jpg","illus_ar":0.808,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":761,"seq":782,"zh":"龙葵","en":"Solanum nigrum","sci":"Solanum nigrum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":91,"desc_zh":"龙葵（学名：Solanum nigrum），又称黑珠仔菜、乌甜仔菜、乌籽菜、天茄子、天星星(东北)、烟李、烟李子（临沂）、牛酸浆、乌甜菜、大头根（阿美族语：Tatokem）、Wasiq（泰雅语）、Samechi（排湾语），是茄科茄属植物，因果实成熟时乌黑如龙的眼珠而得名。 外型与光果龙葵非常相似。","desc_en":"Solanum nigrum, the European black nightshade or simply black nightshade or blackberry nightshade, is a species of flowering plant in the family Solanaceae, native to Eurasia and introduced in the Americas, Australasia, and South Africa.","img":"images/761.jpg","thumb":"images/t/761.jpg","file":"Dettaglio - Solanaceae Solanum nigrum Lin. Erbario Frizzi Perugia n. 734.jpg","ar":0.556,"py":"longkui lk","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","非洲"],"illus_img":"images/i/761.jpg","illus_thumb":"images/i/t/761.jpg","illus_file":"Solanum nigrum Lindman DESC.jpeg","illus_ar":1.444,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":762,"seq":783,"zh":"曼陀罗","en":"Datura stramonium","sci":"Datura stramonium","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":88,"desc_zh":"曼陀罗（学名：Datura stramonium；英语：thorn apple）即紫花曼陀罗是茄科类曼陀罗属植物，俗名醉心花、狗核桃、醉仙桃、疯茄儿、南洋金花、山茄子、凤茄花、朝鲜牵牛花。几个世纪以来，曼陀罗被用作中医草药，以缓解哮喘症状和作为手术或接骨止痛剂，也是强力迷幻剂和谵妄剂。","desc_en":"Datura stramonium, known by the common names thornapple, jimsonweed (jimson weed), or devil's trumpet, is a poisonous flowering plant in the Daturae tribe of the nightshade family Solanaceae.","img":"images/762.jpg","thumb":"images/t/762.jpg","file":"Datura stramonium - Köhler–s Medizinal-Pflanzen-051.jpg","ar":0.793,"py":"mantuoluo mtl","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"],"illus_img":"images/i/762.jpg","illus_thumb":"images/i/t/762.jpg","illus_file":"Datura stramonium - Köhler–s Medizinal-Pflanzen-051.jpg","illus_ar":0.793,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":763,"seq":784,"zh":"颠茄","en":"Atropa bella-donna","sci":"Atropa bella-donna","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":84,"desc_zh":"颠茄（学名：Atropa belladonna；英语：belladonna，deadly nightshade）是一种茄科草本植物。 原产于西欧的多年生草本植物，后来移植到北非、西亚、北美等地，中国也有引进栽培。原产地为山地背阴潮湿地带，在富含石灰质的土壤中群生。 初春发芽，全长40-50厘米，最高可达5米。","desc_en":"Atropa bella-donna, commonly known as deadly nightshade or belladonna, is a toxic perennial herbaceous plant in the nightshade family Solanaceae, which also includes tomatoes, potatoes and eggplant.","img":"images/763.jpg","thumb":"images/t/763.jpg","file":"Atropa belladonna 003.JPG","ar":0.75,"py":"dianqie dq","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/763.jpg","illus_thumb":"images/i/t/763.jpg","illus_file":"Atropa bella-donna Sturm10014.jpg","illus_ar":0.671,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":764,"seq":785,"zh":"天仙子","en":"Hyoscyamus niger","sci":"Hyoscyamus niger","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":80,"desc_zh":"天仙子（学名：Hyoscyamus niger）又名莨菪，旧称菲沃斯，为茄科植物。其种加词“niger”意为“黑色的”。","desc_en":"Henbane (Hyoscyamus niger, also black henbane and stinking nightshade) is a poisonous plant belonging to tribe Hyoscyameae of the nightshade family Solanaceae. Henbane is native to temperate Europe and Siberia, and naturalised in Great Britain and Ireland.","img":"images/764.jpg","thumb":"images/t/764.jpg","file":"Henbane1.JPG","ar":1.385,"py":"tianxianzi txz","cr_by":"Chilepine ( talk · contribs )","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/764.jpg","illus_thumb":"images/i/t/764.jpg","illus_file":"Hyoscyamus niger - Köhler–s Medizinal-Pflanzen-073.jpg","illus_ar":0.819,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":770,"seq":786,"zh":"番薯","en":"sweet potato","sci":"Ipomoea batatas","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":"DD","langs":152,"desc_zh":"番薯（学名：Ipomoea batatas），亦称地瓜、甘薯、甜薯、番芋、苕（sháo）等，为旋花科番薯属的一种常见一年生或多年生植物。 番薯原产于南美洲的热带地区，哥伦布大交换后传播到欧洲，又通过殖民等路径传入世界各地。 番薯的地下块根硕大、味甜、富含淀粉，在历史上常扮演救济饥荒、提供粮食安全的角色，是世界主要主食作物之一。“番薯”一词也单指其块根，根据皮、肉颜色可称红薯（红苕、朱薯）、紫薯、白薯等。番薯的嫩茎叶也可作蔬菜食用。","desc_en":"The sweet potato or sweetpotato (Ipomoea batatas) is a dicotyledonous plant in the morning glory family, Convolvulaceae. Its sizeable, starchy, sweet-tasting tuberous roots are used as a root vegetable, which is a staple food in parts of the world.","img":"images/770.jpg","thumb":"images/t/770.jpg","file":"Ipomoea batatas 006.JPG","ar":1.332,"py":"fanshu fs","cr_by":"Llez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["南美洲"]},{"id":771,"seq":787,"zh":"蕹菜","en":"water spinach","sci":"Ipomoea aquatica","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":"LC","langs":76,"desc_zh":"蕹（wèng）菜（学名：Ipomoea aquatica），又称空心菜、空芯菜、通菜、壅（yōng）菜、瓮菜、应菜、藤菜及葛菜，为一年生草本植物，茎蔓性，中空，节上能生不定根。蕹菜原产于东南亚。","desc_en":"Ipomoea aquatica, commonly known as water spinach or kangkung, is a semi-aquatic, tropical plant grown as a vegetable for its tender shoots. I. aquatica is generally believed to have been first domesticated in Southeast Asia.","img":"images/771.jpg","thumb":"images/t/771.jpg","file":"N Ipoa D1600.JPG","ar":1.333,"py":"wengcai wc","cr_by":"Eric Guinther","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":772,"seq":788,"zh":"田旋花","en":"Convolvulus arvensis","sci":"Convolvulus arvensis","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":null,"langs":71,"desc_zh":"田旋花（学名：Convolvulus arvensis）是旋花科旋花属的一个物种，分布在欧洲和亚洲。","desc_en":"Convolvulus arvensis, or field bindweed, is a species of bindweed in the Convolvulaceae native to Europe and Asia. It is a rhizomatous and climbing or creeping herbaceous perennial plant with stems growing to 0.5–2 metres (1.6–6.6 ft) in length.","img":"images/772.jpg","thumb":"images/t/772.jpg","file":"00 2050 Ackerwinde (Convolvulus arvensis).jpg","ar":0.75,"py":"tianxuanhua txh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","欧洲"],"illus_img":"images/i/772.jpg","illus_thumb":"images/i/t/772.jpg","illus_file":"Illustration Convolvulus arvensis0.jpg","illus_ar":0.583,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":773,"seq":789,"zh":"旋花","en":"Calystegia sepium","sci":"Calystegia sepium","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":"LC","langs":54,"desc_zh":"旋花（学名：Calystegia sepium）为旋花科打碗花属的植物。","desc_en":"Calystegia sepium (Rutland beauty, bugle vine, heavenly trumpets, bellbind, granny-pop-out-of-bed and many others) is a species of flowering plant in the family Convolvulaceae.","img":"images/773.jpg","thumb":"images/t/773.jpg","file":"Calystegia sepium - tara-seatapp.jpg","ar":0.667,"py":"xuanhua xh","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":null,"illus_img":"images/i/773.jpg","illus_thumb":"images/i/t/773.jpg","illus_file":"Calystegia sepium Sturm1.jpg","illus_ar":0.628,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":774,"seq":790,"zh":"圆叶牵牛","en":"Ipomoea purpurea","sci":"Ipomoea purpurea","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":null,"langs":41,"desc_zh":"圆叶牵牛（学名：Ipomoea purpurea）是旋花科番薯属的植物。其种加词“purpurea”意为“紫色的”，指的是花为紫色的。分布在世界各地，包括热带美洲以及中国大陆的大部分地区，生长于海拔2,800米的地区，多生长在田边、路边、宅旁和山谷林内，目前已由人工引种栽培。","desc_en":"Ipomoea purpurea, the common morning-glory, tall morning-glory, or purple morning glory, is a species in the genus Ipomoea. It is native to Mexico and Central America, and is naturalized throughout warm temperate and subtropical regions of the world.","img":"images/774.jpg","thumb":"images/t/774.jpg","file":"BlueMorningGlory.jpg","ar":0.816,"py":"yuanyeqianniu yyqn","cr_by":"Original uploader was PiccoloNamek at en.wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":1224,"seq":791,"zh":"Hydrolea ovata","en":"Hydrolea ovata","sci":"Hydrolea ovata","order_en":"Solanales","order_zh":"茄目","family_en":"Hydroleaceae","family_zh":"田基麻科","iucn":null,"langs":6,"desc_zh":null,"desc_en":"Hydrolea ovata is a species of flowering plant known by the common names ovate false fiddleleaf and blue waterleaf. It is native to the southeastern United States. This rhizomatous perennial herb has spiny stems that grow up to 2 feet tall.","img":"images/1224.jpg","thumb":"images/t/1224.jpg","file":"Hydrolea ovata.jpg","ar":1.5,"py":"","cr_by":"Robert H. Mohlenbrock. USDA SCS. 1991. Southern wetland flora: Field office guide to plant species. South National Techn","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["北美洲"]},{"id":1225,"seq":792,"zh":"幌菊","en":"Nemophila menziesii","sci":"Nemophila menziesii","order_en":"Solanales","order_zh":"茄目","family_en":"Hydrophyllaceae","family_zh":"田基麻科","iucn":null,"langs":14,"desc_zh":"粉蝶花（学名：Nemophila menziesii），又称喜林草、琉璃唐草等，是一种一年生草本植物，原产于北美西部。","desc_en":"Nemophila menziesii, known commonly as baby blue eyes or baby's-blue-eyes, is an annual herb, native to western North America. Historically, it was eaten by cows kept by the Kawaiisu.","img":"images/1225.jpg","thumb":"images/t/1225.jpg","file":"Baby Blue Eyes o.jpg","ar":1.333,"py":"huangju hj","cr_by":"Cliff Hutson","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":["北美洲"]},{"id":1226,"seq":793,"zh":"Pholisma sonorae","en":"Pholisma sonorae","sci":"Pholisma sonorae","order_en":"Solanales","order_zh":"茄目","family_en":"Lennoaceae","family_zh":"盖裂寄生科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Pholisma sonorae, commonly known as sandfood, is a rare and unusual species of flowering plant endemic to the Sonoran Deserts to the west of Yuma, Arizona in the California Yuha, Mojave Desert and Colorado Desert, and south in the Yuma Desert, where it is know…","img":"images/1226.jpg","thumb":"images/t/1226.jpg","file":"Pholisma sonorae.jpg","ar":1.333,"py":"","cr_by":"Pacific Southwest Region U.S. Fish and Wildlife Service","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":1227,"seq":794,"zh":"楔瓣花","en":"Sphenoclea zeylanica","sci":"Sphenoclea zeylanica","order_en":"Solanales","order_zh":"茄目","family_en":"Sphenocleaceae","family_zh":"楔瓣花科","iucn":"LC","langs":20,"desc_zh":"尖瓣花（学名：Sphenoclea zeylanica），为密穗桔梗科尖瓣花属(Sphenoclea)下的一个植物种。种名zeylanica意为斯里兰卡的。","desc_en":"Sphenoclea zeylanica, called chickenspike, gooseweed, and wedgewort, is a widespread species of flowering plant in the genus Sphenoclea, native to Africa, Madagascar, tropical and subtropical Asia, and Australia.","img":"images/1227.jpg","thumb":"images/t/1227.jpg","file":"Sphenoclea zeylanica MS 2295.JPG","ar":0.667,"py":"xiebanhua xbh","cr_by":"Marco Schmidt","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","非洲","大洋洲"]},{"id":776,"seq":795,"zh":"罗勒","en":"basil","sci":"Ocimum basilicum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":121,"desc_zh":"罗勒（学名：Ocimum basilicum，俗名金不换、九层塔（台湾）、七层塔（客家语）鱼生菜（香港及潮汕）、香花子（皖北），兰香（华北）、西王母菜）是一种可食用香草的统称。其大多数为一年生植物，少部分为多年生植物，其下包括许多栽培品种，其中于远东较为常见之品种为Thai basil(直译为泰国罗勒，Ocimum basilicum var.","desc_en":"Basil (Ocimum basilicum), also called great basil, is a culinary herb of the family Lamiaceae (mints). It is a tender plant and is used in cuisines worldwide.","img":"images/776.jpg","thumb":"images/t/776.jpg","file":"Basil-Basilico-Ocimum basilicum-albahaca.jpg","ar":1.333,"py":"luole ll","cr_by":"Castielli","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","非洲"]},{"id":777,"seq":796,"zh":"迷迭香","en":"Salvia rosmarinus","sci":"Salvia rosmarinus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":114,"desc_zh":"迷迭香（学名：Salvia rosmarinus）是唇形科、鼠尾草属的一种多年生常绿灌木，原产于地中海盆地，其叶、茎、花富含芳香油，常用作烹饪或精油中的香料。","desc_en":"Salvia rosmarinus, synonym Rosmarinus officinalis, commonly known as rosemary, is a shrub with fragrant, evergreen, needle-like leaves and purple or sometimes white, pink, or blue flowers. It is a member of the mint family, Lamiaceae.","img":"images/777.jpg","thumb":"images/t/777.jpg","file":"P1090247(4x3)-Rosmarinus officinalis (41960388224).jpg","ar":1.333,"py":"midiexiang mdx","cr_by":"Miguel Angel Masegosa Martínez","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["欧洲"]},{"id":778,"seq":797,"zh":"牛至","en":"Origanum vulgare","sci":"Origanum vulgare","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":103,"desc_zh":"牛至（学名：Origanum vulgare），又名滇香薷，欧洲语言中称为“俄勒冈”、“披萨草”或“野马郁兰”（意大利语：origano；英语：oregano、pizza herb、wild marjoram），是唇形科牛至属中的一种植物。 牛至和马郁兰同属牛至属，为近亲。后者在中东也叫“甘牛至”（sweet marjoram）。","desc_en":"Oregano (US: , UK: ; Origanum vulgare) is a species of flowering plant in the mint family, Lamiaceae. It was native to the Mediterranean region, but widely naturalised elsewhere in the temperate Northern Hemisphere.","img":"images/778.jpg","thumb":"images/t/778.jpg","file":"Origanum vulgare inflorescence - Keila.jpg","ar":1.501,"py":"niuzhi nz","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/778.jpg","illus_thumb":"images/i/t/778.jpg","illus_file":"Origanum vulgare Sturm56.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":779,"seq":798,"zh":"墨角兰","en":"marjoram","sci":"Origanum majorana","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":91,"desc_zh":"墨角兰（学名：Origanum majorana），隶属于唇形科牛至属，是一种有点对寒冷敏感的多年生香草，带有甜松和柑橘的香味。墨角兰又名马郁草、马约兰草、甜墨角兰（Sweet Marjoram）、多节墨角兰（Knotted Marjoram）及马乔兰(Marjoram)。叶对生，卵圆形，具顶生伞房花序，开白色或紫色花朵。","desc_en":"Marjoram (, Origanum majorana, syn. Majorana hortensis Moench) is a cold-sensitive perennial herb or undershrub with sweet pine and citrus flavours. In some Middle Eastern countries, marjoram is synonymous with oregano, and there the names sweet marjoram and k…","img":"images/779.jpg","thumb":"images/t/779.jpg","file":"Origanum majorana.jpg","ar":1.333,"py":"mojiaolan mjl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":780,"seq":799,"zh":"香蜂花","en":"Melissa officinalis","sci":"Melissa officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":79,"desc_zh":"香蜂花（学名：Melissa officinalis），又名柠檬香草（英语：lemon balm）、柠檬香蜂草，是唇形科蜜蜂花属的一个种，多年生草本，株高约40～45cm，原产中东温带地区，随后遍及亚洲及地中海国家。目前广泛植于于欧洲、中亚和北美地区。学名中的Melissa在希腊文中为「蜜蜂」之意。古希腊、罗马人认为香蜂花为月亮与狩猎女神阿耳忒弥斯（黛安娜）之化身，将其视为重要植物，栽培于寺庙周围，吸引蜂群制造蜂蜜，作为糖份来源。","desc_en":"Lemon balm (Melissa officinalis) is a perennial herbaceous plant in the mint family. It has lemon-scented leaves, white or pale pink flowers, and contains essential oils and compounds, such as geranial and neral. It grows to a maximum height of 1 m (3+1⁄2 ft).","img":"images/780.jpg","thumb":"images/t/780.jpg","file":"Melissa officinalis Bee Balm,Lemon Balm ბარამბო.JPG","ar":0.664,"py":"xiangfenghua xfh","cr_by":"Lazaregagnidze","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/780.jpg","illus_thumb":"images/i/t/780.jpg","illus_file":"Melissa officinalis - Köhler–s Medizinal-Pflanzen-094.jpg","illus_ar":0.742,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":781,"seq":800,"zh":"柚木","en":"Tectona grandis","sci":"Tectona grandis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"EN","langs":77,"desc_zh":"柚木（学名Tectona grandis）又名胭脂树，是阔叶乔木，属于唇形科（或是马鞭草科）柚木属的植物。一般生长在南亚或东南亚，以缅甸(Burma Teak)出产的最为著名，原产地为缅甸 (Kyun)、印尼(jati)、泰国(Teak)、婆罗洲、爪哇、印度等，因富含油脂及高稳定度而受到广泛利用，在家具用材中，有群木之王的美誉 。","desc_en":"Teak (Tectona grandis) is a tropical hardwood tree species in the family Lamiaceae. It is a large, deciduous tree that occurs in mixed hardwood forests. Tectona grandis has small, fragrant white flowers arranged in dense clusters (panicles) at the end of the b…","img":"images/781.jpg","thumb":"images/t/781.jpg","file":"Starr 010304-0485 Tectona grandis.jpg","ar":1.333,"py":"youmu ym","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲","非洲","北美洲"]},{"id":782,"seq":801,"zh":"鼠尾草","en":"Salvia officinalis","sci":"Salvia officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":77,"desc_zh":"药用鼠尾草（学名：Salvia officinalis），《中国植物志》作「撒尔维亚」，是唇形科鼠尾草属的一种芳香性植物。常绿性小型亚灌木，有木质茎，叶子灰绿色，花蓝色至蓝紫色。原产于欧洲南部与地中海沿岸地区。药用鼠尾草有时也俗称「鼠尾草」，但容易与原产中国和日本的同属植物鼠尾草相混。无论其香草形状，都不像鼠尾。","desc_en":"Salvia officinalis, common sage or sage, is a perennial, evergreen subshrub, with woody stems, grayish leaves, and blue to purplish flowers. It is a member of the mint family (Lamiaceae) and native to the Mediterranean region, though it has been naturalized in…","img":"images/782.jpg","thumb":"images/t/782.jpg","file":"Salvia officinalis L. 3355742911.jpg","ar":0.75,"py":"shuweicao swc","cr_by":"iNaturalist.org (Alina Majcen) (Alina%20Majcen)","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"灌木","origin":["欧洲"],"illus_img":"images/i/782.jpg","illus_thumb":"images/i/t/782.jpg","illus_file":"Salvia officinalis - Köhler–s Medizinal-Pflanzen-126.jpg","illus_ar":0.76,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":783,"seq":802,"zh":"胡椒薄荷","en":"Mentha × piperita","sci":"Mentha ×piperita","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":76,"desc_zh":"[[Category:物种微格式条目|Mentha × piperita]] 辣薄荷（学名：Mentha × piperita，又名胡椒薄荷，英语：Peppermint）唇形科年生草本植物，是一种被广泛种植的混种薄荷，原产于欧洲，可用于食物的调味料。这个薄荷品种是由绿薄荷（Mentha spicata，英语：Spearmint）与水薄荷（Mentha aquatica，英语：Watermint）混种而成的.","desc_en":"Peppermint (Mentha × piperita) is a hybrid species of mint, a cross between watermint and spearmint. Indigenous to Europe and the Middle East, the plant is now widely spread and cultivated in many regions of the world.","img":"images/783.jpg","thumb":"images/t/783.jpg","file":"Pfefferminze natur peppermint.jpg","ar":1.333,"py":"hujiaobohe hjbh","cr_by":null,"cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":784,"seq":803,"zh":"野薄荷","en":"corn mint","sci":"Mentha arvensis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":69,"desc_zh":"田野薄荷（学名：Mentha arvensis；英语：field mint），也称谷薄荷、玉米薄荷（英语：corn mint），是薄荷属下的一种。其范围遍及环北方带，在有湿润土壤的欧洲、西亚、北亚都有分布，东至西喜马拉雅山脉和西伯利亚的东部，以及北美。 它是一种多年生草本植物，高10-60厘米（特殊情况能长到100厘米）。对生叶序，叶片较小，2-6.5厘米长，1-2厘米宽，长毛，边缘为齿状。","desc_en":"Mentha arvensis, the corn mint, field mint, or wild mint, is a species of flowering plant in the mint family Lamiaceae. It has a circumboreal distribution, being native to the temperate regions of Europe and western and central Asia, east to the Himalaya and e…","img":"images/784.jpg","thumb":"images/t/784.jpg","file":"Mentha arvensis 2005.08.28 09.49.00.jpg","ar":0.75,"py":"yebohe ybh","cr_by":"Michael Becker","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/784.png","illus_thumb":"images/i/t/784.png","illus_file":"Mentha arvensis Lindman DESC.png","illus_ar":2.306,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":785,"seq":804,"zh":"圣罗勒","en":"Holy Basil","sci":"Ocimum tenuiflorum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":63,"desc_zh":"圣罗勒（学名：Ocimum tenuiflorum），又名神罗勒、打抛叶、打抛或嘎抛（泰语：กะเพรา，kaphrao），为唇形科罗勒属下的一种多年生草本植物，原生于印度次大陆，其相关栽植种遍及东南亚和热带地区。","desc_en":"Ocimum tenuiflorum, commonly known as tulasi, tulsi, or holy basil, is an aromatic perennial plant in the family Lamiaceae. It is widely cultivated throughout the Southeast Asian tropics.","img":"images/785.jpg","thumb":"images/t/785.jpg","file":"Tulasih.jpg","ar":0.563,"py":"shengluole sll","cr_by":"I Gd Nj Prt","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","大洋洲"]},{"id":786,"seq":805,"zh":"铺地百里香","en":"Thymus serpyllum","sci":"Thymus serpyllum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":61,"desc_zh":"铺地百里香（学名：Thymus serpyllum；英语：creeping thyme），也称铺地香、匍匐百里香、野百里香（英语：wild thyme），是百里香属下的一个种，主要生长在欧洲和北非。它的植株很小，通常为2厘米高的小灌木，带有10厘米长的匍匐茎。叶子为椭圆形常绿叶，长为3-8毫米。花带有浓郁香味，为淡紫色、粉紫色、洋紫色或淡白色，4-6毫米长，簇生。其香味因植株不同而有浓淡之分，从浓重的草药味到淡淡柠檬味都有。","desc_en":"Thymus serpyllum, known by the common names of Breckland thyme, Breckland wild thyme, wild thyme, creeping thyme, or elfin thyme, is a species of flowering plant in the mint family, Lamiaceae.","img":"images/786.jpg","thumb":"images/t/786.jpg","file":"Thymus serpyllum1.jpg","ar":1.333,"py":"pudibailixiang pdblx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["欧洲","非洲"],"illus_img":"images/i/786.jpg","illus_thumb":"images/i/t/786.jpg","illus_file":"Thymus serpyllum - Köhler–s Medizinal-Pflanzen-138.jpg","illus_ar":0.768,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":787,"seq":806,"zh":"短柄野芝麻","en":"Lamium album","sci":"Lamium album","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":61,"desc_zh":"短柄野芝麻又名野芝麻（学名：Lamium album）为唇形科野芝麻属下的一个种。","desc_en":"Lamium album, commonly called white dead-nettle, is a flowering plant in the family Lamiaceae. It is native throughout Europe and Asia, growing in a variety of habitats from open grassland to woodland, generally on moist, fertile soils.","img":"images/787.jpg","thumb":"images/t/787.jpg","file":"Lamium album Sturm39.jpg","ar":0.698,"py":"duanbingyezhima dbyzm","cr_by":"Johann Georg Sturm (Painter: Jacob Sturm )","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/787.jpg","illus_thumb":"images/i/t/787.jpg","illus_file":"Lamium album Sturm39.jpg","illus_ar":0.698,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":795,"seq":807,"zh":"宽叶车前","en":"Plantago major","sci":"Plantago major","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":"LC","langs":77,"desc_zh":"大车前草（学名：Plantago major）又名宽叶车前，是车前科车前属的一种植物。这种植物原产于亚洲北部和欧洲，但现已遍布全球。它在殖民时期被无意中带到美洲。这种植物能够在紧致的土壤生长，包括从前筑路时被夯实的泥土路，所以在英语又名\"roadweed\"，意思就是「路上的野草」。 宽叶车前是一种风媒植物，叶子捣碎后可以用来止血，可食用及入药，但在美国被视为一种野草。","desc_en":"Plantago major, the broadleaf plantain, white man's footprint, waybread, or greater plantain, is a species of flowering plant in the plantain family Plantaginaceae. The plant is native to Eurasia and naturalized to America.","img":"images/795.jpg","thumb":"images/t/795.jpg","file":"Grote weegbree bloeiwijze Plantago major subsp. major.jpg","ar":0.714,"py":"kuanyecheqian kycq","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"],"illus_img":"images/i/795.jpg","illus_thumb":"images/i/t/795.jpg","illus_file":"Otto Brunfels, Plantago major, in \"Herbarum vivae eicones\" Wellcome L0006544.jpg","illus_ar":0.631,"illus_by":null,"illus_lic":"CC BY 4.0","illus_licurl":"https://creativecommons.org/licenses/by/4.0"},{"id":796,"seq":808,"zh":"长叶车前","en":"Plantago lanceolata","sci":"Plantago lanceolata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":69,"desc_zh":"长叶车前（学名：Plantago lanceolata） 又名窄叶车前、欧车前、披针叶车前，为车前属的品种之一，是一种多年生草本植物，株高约5至50厘米，根深可达60厘米左右。在英语世界里普遍被称为 ribwort plantain、English plantain、buckhorn plantain 或narrowleaf plantain。","desc_en":"Plantago lanceolata is a species of flowering plant in the plantain family Plantaginaceae. It is known by the common names ribwort plantain, narrowleaf plantain, English plantain, ribleaf, lamb's tongue, and buckhorn.","img":"images/796.jpg","thumb":"images/t/796.jpg","file":"Ribwort 600.jpg","ar":0.828,"py":"changyecheqian cycq","cr_by":"sannse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/796.png","illus_thumb":"images/i/t/796.png","illus_file":"Plantago lanceolata Sturm DESC.png","illus_ar":2.661,"illus_by":"Johann Georg Sturm","illus_lic":"Public domain","illus_licurl":null},{"id":797,"seq":809,"zh":"毛地黄","en":"Digitalis purpurea","sci":"Digitalis purpurea","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":63,"desc_zh":"毛地黄（学名：Digitalis purpurea；foxglove、common foxglove、purple foxglove、lady's glove）为唇形目车前科毛地黄属下的一个种，其种加词“purpurea”意为“紫色的”。广泛分布于温带欧洲。也见于北美和其他温带部分地区。 本物种为著名的药用有毒植物，全株皆有毒。与同作药用的有毒植物如马醉木等是少数可作为观赏用之有毒却有药用的有毒植物。","desc_en":"Digitalis purpurea, the foxglove or common foxglove, is a toxic species of flowering plant in the plantain family Plantaginaceae, native to and widespread throughout most of temperate Europe.","img":"images/797.jpg","thumb":"images/t/797.jpg","file":"Brdy-stonek zvonku.jpg","ar":0.75,"py":"maodihuang mdh","cr_by":"Honza Groh","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/797.jpg","illus_thumb":"images/i/t/797.jpg","illus_file":"Digitalis purpurea - Köhler–s Medizinal-Pflanzen-053.jpg","illus_ar":0.768,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":798,"seq":810,"zh":"新疆柳穿鱼","en":"Linaria vulgaris","sci":"Linaria vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":48,"desc_zh":"新疆柳穿鱼（学名：Linaria vulgaris sp. acutiloba）为玄参科柳穿鱼属下的一个亚种。","desc_en":"Linaria vulgaris, the common toadflax, is a species of flowering plant in the family Plantaginaceae, native to Europe, and northern, central and eastern Asia. It has also been introduced to North America and is now common there.","img":"images/798.jpg","thumb":"images/t/798.jpg","file":"Linaria vulgaris - harilik käokannus Valingu.jpg","ar":0.667,"py":"xinjiangliuchuanyu xjlcy","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/798.jpg","illus_thumb":"images/i/t/798.jpg","illus_file":"Linaria vulgaris Sturm10027.jpg","illus_ar":0.626,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":799,"seq":811,"zh":"药用水苦荬","en":"Veronica officinalis","sci":"Veronica officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":47,"desc_zh":null,"desc_en":"Veronica officinalis, the heath speedwell, common gypsyweed, common speedwell, or Paul's betony, is a species of flowering plant in the plantain family Plantaginaceae. It is native to Europe and western Asia.","img":"images/799.jpg","thumb":"images/t/799.jpg","file":"Veronica officinalis0.jpg","ar":0.75,"py":"yaoyongshuikumai yyskm","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/799.jpg","illus_thumb":"images/i/t/799.jpg","illus_file":"Veronica officinalis Sturm10040.jpg","illus_ar":0.7,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":801,"seq":812,"zh":"毛蕊花","en":"Verbascum thapsus","sci":"Verbascum thapsus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":55,"desc_zh":"毛蕊花（学名：Verbascum thapsus），为玄参科毛蕊花属下的一个植物种。 这种植物原生于非洲与亚洲北部,后期引进到了美洲和澳大利亚。","desc_en":"Verbascum thapsus, the great mullein, greater mullein or common mullein, is a species of mullein native to Europe, northern Africa, and Asia, and introduced in the Americas, Australia and New Zealand.","img":"images/801.gif","thumb":"images/t/801.gif","file":"00 2262 Kleinblütige Königskerze (Verbascum thapsus).gif","ar":0.752,"py":"maoruihua mrh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"],"illus_img":"images/i/801.jpg","illus_thumb":"images/i/t/801.jpg","illus_file":"Verbascum thapsus — Flora Batava — Volume v3.jpg","illus_ar":0.693,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":802,"seq":813,"zh":"大叶醉鱼草","en":"Buddleja davidii","sci":"Buddleja davidii","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":43,"desc_zh":"大叶醉鱼草（学名：Buddleja davidii），又名绛花醉鱼草（中国树木分类学）、穆坪醉鱼草（中国树木分类学）、兴山醉鱼草（中国树木分类学）、白背叶醉鱼草（云南植物研究）、白壶子（甘肃武都），是玄参科醉鱼草属的植物。","desc_en":"Buddleja davidii (spelling variant Buddleia davidii), also called butterfly-bush, orange eye, or summer lilac, is a species of flowering plant in the family Scrophulariaceae, native to most of China except for the far northeast.","img":"images/802.jpg","thumb":"images/t/802.jpg","file":"BuddlejaDavidiiStrauch.jpg","ar":1.333,"py":"dayezuiyucao dyzyc","cr_by":"-- IKAl 15:22, 23 July 2007 (UTC)","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"灌木","origin":["亚洲"]},{"id":803,"seq":814,"zh":"林地玄参","en":"Scrophularia nodosa","sci":"Scrophularia nodosa","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":39,"desc_zh":null,"desc_en":"Scrophularia nodosa (also called figwort, woodland figwort, and common figwort) is a perennial herbaceous plant found in temperate regions of the Northern Hemisphere except western North America. It grows in moist and cultivated waste ground.","img":"images/803.jpg","thumb":"images/t/803.jpg","file":"Scrophularia nodosa8.jpg","ar":1.333,"py":"lindixuancan ldxc","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲"],"illus_img":"images/i/803.jpg","illus_thumb":"images/i/t/803.jpg","illus_file":"Scrophularia nodosa — Flora Batava — Volume v2.jpg","illus_ar":0.697,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":804,"seq":815,"zh":"毒鱼草","en":"denseflower mullein","sci":"Verbascum densiflorum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":32,"desc_zh":null,"desc_en":"Verbascum densiflorum, also known as denseflower mullein and dense-flowered mullein, is a species of plant in the figwort family Scrophulariaceae.","img":"images/804.jpg","thumb":"images/t/804.jpg","file":"00 2359 Großblütige Königskerze - Verbascum densiflorum.jpg","ar":0.6,"py":"duyucao dyc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/804.jpg","illus_thumb":"images/i/t/804.jpg","illus_file":"Verbascum densiflorum Sturm18.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":806,"seq":816,"zh":"小鼻花","en":"Rhinanthus minor","sci":"Rhinanthus minor","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Rhinanthus minor, known as yellow rattle, is a herbaceous wildflower in the genus Rhinanthus in the broomrape family. It has circumpolar distribution in Europe, Russia, western Asia, and northern North America.","img":"images/806.jpg","thumb":"images/t/806.jpg","file":"Yellow-rattle 700.jpg","ar":0.75,"py":"xiaobihua xbh","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/806.png","illus_thumb":"images/i/t/806.png","illus_file":"Rhinanthus minor (Icones Florae Germanicae et Helveticae 1862, v20, plate 1738, BHL-29363) clean, no-description.png","illus_ar":0.79,"illus_by":"Reichenbach, L.; Reichenbach, H. G.;","illus_lic":"Public domain","illus_licurl":null},{"id":807,"seq":817,"zh":"Euphrasia rostkoviana","en":"Euphrasia rostkoviana","sci":"Euphrasia rostkoviana","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":35,"desc_zh":null,"desc_en":"Euphrasia officinalis, also known as eyebright or eyewort, is a species of plant in the family Orobanchaceae. Euphrasia officinalis herb has been used in the traditional Austrian medicine internally as tea, or externally as compresses, for treatment of disorde…","img":"images/807.jpg","thumb":"images/t/807.jpg","file":"Augentrost.jpg","ar":1.011,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/807.jpg","illus_thumb":"images/i/t/807.jpg","illus_file":"Illustration Euphrasia rostkoviana0 clean.jpg","illus_ar":0.58,"illus_by":"Original book source: Prof. Dr. Otto Wilhelm Thomé Flora von Deutschland, Österreich und der Schweiz 1885, Gera, Germany","illus_lic":"Public domain","illus_licurl":null},{"id":808,"seq":818,"zh":"Lathraea squamaria","en":"Lathraea squamaria","sci":"Lathraea squamaria","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":35,"desc_zh":null,"desc_en":"Lathraea squamaria, the common toothwort, is a species of flowering plant in the family Orobanchaceae. It is widely distributed in Europe and also occurs in Turkey.","img":"images/808.jpg","thumb":"images/t/808.jpg","file":"Lathraea squamaria LC0126.jpg","ar":0.677,"py":"","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 2.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0/de/deed.en","habit":"乔木","origin":["欧洲"],"illus_img":"images/i/808.jpg","illus_thumb":"images/i/t/808.jpg","illus_file":"Lathraea squamaria Sturm59.jpg","illus_ar":0.676,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":810,"seq":819,"zh":"野捕虫堇","en":"Pinguicula vulgaris","sci":"Pinguicula vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lentibulariaceae","family_zh":"狸藻科","iucn":"LC","langs":46,"desc_zh":"野捕虫堇（学名：Pinguicula vulgaris），也称作紫花捕虫堇，是狸藻科多年生的食肉植物，其种加词“vulgaris”源自拉丁语“vulgar ”，意为“一般的、粗野的”。本种植株高3-16公分，顶部带有紫色，偶尔白色，花朵约15毫米或是更大，且呈漏斗状。本种捕虫堇生长在潮湿环绕的环境，诸如泥塘和沼泽，在低海拔或是亚高山带的海拔。本种具有广泛地环北带分布区域，原生于几乎所有的欧洲国家、俄国、中国、加拿大以及美国。","desc_en":"Pinguicula vulgaris, the common butterwort, is a perennial carnivorous plant in the butterwort genus of the family Lentibulariaceae.","img":"images/810.jpg","thumb":"images/t/810.jpg","file":"Pinguicula vulgaris 140505.jpg","ar":0.959,"py":"yebuchongjin ybcj","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/810.jpg","illus_thumb":"images/i/t/810.jpg","illus_file":"Pinguicula vulgaris Sturm62.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":811,"seq":820,"zh":"普通狸藻","en":"Utricularia vulgaris","sci":"Utricularia vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lentibulariaceae","family_zh":"狸藻科","iucn":"LC","langs":32,"desc_zh":"普通狸藻（学名：Utricularia vulgaris）为狸藻属水生食虫植物。其种加词“vulgaris”来源于拉丁文“vulgaris”，意为“普通的”。其分布于欧洲与亚洲，是狸藻属中分布最为广泛的物种。","desc_en":"Utricularia vulgaris (greater bladderwort or common bladderwort) is an aquatic species of bladderwort found in Asia and Europe. The plant is free-floating and does not put down roots.","img":"images/811.jpg","thumb":"images/t/811.jpg","file":"Uk pond bladderwort.jpg","ar":0.81,"py":"putonglizao ptlz","cr_by":"No machine-readable author provided. Veledan~commonswiki assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/811.jpg","illus_thumb":"images/i/t/811.jpg","illus_file":"Utricularia vulgaris Sturm63.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":1228,"seq":821,"zh":"南方狸藻","en":"Utricularia australis","sci":"Utricularia australis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lentibulariaceae","family_zh":"狸藻科","iucn":"LC","langs":32,"desc_zh":"南方狸藻（学名：Utricularia australis），又称鱼刺草，狗尾巴草，为狸藻科狸藻属中型多年生浮水食虫植物。南方狸藻广泛分布于欧洲和亚洲热带及温带，包括东亚的中国和日本，非洲中南部及澳大利亚和纽西兰北岛。其种加词「australis」来源于拉丁文，意为「南方」，指其分布于南部地区。并也反映出该种是1810年在澳大利亚发现的事实。南方狸藻花期为6月至11月，果期7月至12月，花冠黄色，果实球形，植株在夏季强光下也会转为红色。","desc_en":"Utricularia australis is a medium-sized, perennial species of aquatic bladderwort. This species has a vast geographic range, being found throughout Europe, in tropical and temperate Asia including China and Japan in the east, Central and Southern Africa, Austr…","img":"images/1228.jpg","thumb":"images/t/1228.jpg","file":"Utriculariaaustralis.jpg","ar":0.75,"py":"nanfanglizao nflz","cr_by":"No machine-readable author provided. Botanikus~commonswiki assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"],"illus_img":"images/i/1228.png","illus_thumb":"images/i/t/1228.png","illus_file":"Utricularia australis illustration.png","illus_ar":0.69,"illus_by":"Klaus van de Weyer (scientist); Dagmar Wassong (artist)","illus_lic":"CC BY-SA 3.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/3.0"},{"id":812,"seq":822,"zh":"吊灯树","en":"Kigelia africana","sci":"Kigelia africana","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"LC","langs":50,"desc_zh":"吊灯树（学名：Kigelia africana）为紫葳科吊灯树属的植物。分布在马达加斯加、非洲以及云南、福建、广东、海南、台湾等地，目前已由人工引种栽培。 其种加词“africana”意为“非洲的”。 吊灯树的果实虽然不可食用，但在非洲是被用作医治皮肤病的药物。","desc_en":"Kigelia is a genus of flowering plants in the trumpet vine family Bignoniaceae. The genus consists of only one species, Kigelia africana, syn. Kigelia pinnata, which occurs throughout tropical Africa and is cultivated elsewhere in the tropics.","img":"images/812.jpg","thumb":"images/t/812.jpg","file":"Kigelia-Africana-Serengeti.JPG","ar":1.407,"py":"diaodengshu dds","cr_by":"Bjørn Christian Tørrissen","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["非洲"]},{"id":813,"seq":823,"zh":"蓝花楹","en":"Jacaranda mimosifolia","sci":"Jacaranda mimosifolia","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"VU","langs":43,"desc_zh":"蓝花楹（学名：Jacaranda mimosifolia）是紫葳科蓝花楹属的植物。分布在阿根廷、玻利维亚、巴西 、澳大利亚。目前已人工引种栽培到广西、海南、广东、云南、福建等地。","desc_en":"Jacaranda mimosifolia is a sub-tropical tree native to south-central South America that has been widely planted elsewhere because of its attractive and long-lasting violet-colored flowers. It is also known as the jacaranda, blue jacaranda, Nupur or black poui.","img":"images/813.jpg","thumb":"images/t/813.jpg","file":"Jacaranda1212.jpg","ar":1.333,"py":"lanhuaying lhy","cr_by":"Kahuroa","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"],"illus_img":"images/i/813.jpg","illus_thumb":"images/i/t/813.jpg","illus_file":"Jacaranda mimosifolia Bot. Mag. 49. t. 2327 (1822).jpg","illus_ar":0.863,"illus_by":"R.Brown","illus_lic":"Public domain","illus_licurl":null},{"id":814,"seq":824,"zh":"美国梓树","en":"Catalpa bignonioides","sci":"Catalpa bignonioides","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"DD","langs":42,"desc_zh":null,"desc_en":"Catalpa bignonioides is a short-lived species of Catalpa that is native to the southeastern United States in Alabama, Florida, Georgia, Louisiana, and Mississippi.","img":"images/814.jpg","thumb":"images/t/814.jpg","file":"Catalpa bignonioides 05.jpg","ar":1.302,"py":"meiguozishu mgzs","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["北美洲"]},{"id":816,"seq":825,"zh":"马樱丹","en":"Lantana camara","sci":"Lantana camara","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":63,"desc_zh":"马缨丹（学名：Lantana camara），别称五色梅、七色梅、五龙兰、如意草、五彩花、臭草、臭金凤、五雷丹、五色绣球、变色草等，客家人称之为绵鼻公花。原本主要分布于南美洲、西印度群岛，马缨丹属（Lantana）常绿灌木。一般花期大约是在4月中、下旬到隔年的2月中旬左右，不过也因气候与温度的影响，几乎整年都能看到开花，可说是常盛的植物。","desc_en":"Lantana camara (common lantana) is a species of flowering plant in the verbena family (Verbenaceae), native to the tropics of the Americas. It is a very adaptable species, which can inhabit a wide variety of ecosystems; once it has been introduced into a habit…","img":"images/816.jpg","thumb":"images/t/816.jpg","file":"LantanaFlowerLeaves.jpg","ar":1.333,"py":"mayingdan myd","cr_by":"Alvesgaspar","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":817,"seq":826,"zh":"马鞭草","en":"Verbena officinalis","sci":"Verbena officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":55,"desc_zh":"马鞭草（学名：Verbena officinalis）为马鞭草科(Verbenaceae)，马鞭草属(Verbena)植物。 英文名称：European Verbena","desc_en":"Verbena officinalis, the common vervain or common verbena, is a perennial herb native to Europe. It grows up to 70 cm (28 in) high, with an upright habitus. The lobed leaves are toothed, and the delicate spikes hold clusters of two-lipped mauve flowers.","img":"images/817.jpg","thumb":"images/t/817.jpg","file":"Eisenkraut, Passau.JPG","ar":0.75,"py":"mabiancao mbc","cr_by":"Konrad Lackerbeck","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["欧洲"],"illus_img":"images/i/817.jpg","illus_thumb":"images/i/t/817.jpg","illus_file":"Verbena officinalis Sturm22.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm)","illus_lic":"Public domain","illus_licurl":null},{"id":818,"seq":827,"zh":"柠檬龙至木","en":"Aloysia citrodora","sci":"Aloysia citrodora","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":43,"desc_zh":null,"desc_en":"Aloysia citrodora, lemon verbena, is a species of flowering plant in the verbena family Verbenaceae, native to South America. Other common names include lemon beebrush.","img":"images/818.jpg","thumb":"images/t/818.jpg","file":"Aloysia citriodora 002.jpg","ar":0.75,"py":"ningmenglongzhimu nmlzm","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["南美洲"]},{"id":820,"seq":828,"zh":"油橄榄","en":"Olea europaea","sci":"Olea europaea","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":null,"langs":145,"desc_zh":"油橄榄（学名：Olea europaea，其种加词europaea的意思为欧洲），又称木犀榄，古称齐墩、阿列布，是一种木樨科木樨榄属常绿乔木，果实主要用于榨制橄榄油。《圣经》故事中曾用它的树枝作为大地复苏的标志，后来西方国家把它用作和平象征。本种原产于东地中海盆地的沿海地区（临近的东南欧、西亚和北非沿海地区），以及里海南岸的伊朗北部地区。它的果实，也叫做橄榄，它是地中海地区一种主要的农作物，用来生产橄榄油。","desc_en":"The olive (botanical name Olea europaea, \"European olive\") is a species of subtropical evergreen tree in the family Oleaceae. Originating in Asia Minor, it is abundant throughout the Mediterranean Basin, with wild subspecies in Africa and western Asia; modern…","img":"images/820.jpg","thumb":"images/t/820.jpg","file":"El Perelló - Old olive tree.jpg","ar":1.333,"py":"youganlan ygl","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/820.jpg","illus_thumb":"images/i/t/820.jpg","illus_file":"Olea europaea - Köhler–s Medizinal-Pflanzen-229.jpg","illus_ar":0.869,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":821,"seq":829,"zh":"欧洲白蜡树","en":"Fraxinus excelsior","sci":"Fraxinus excelsior","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":"NT","langs":74,"desc_zh":"欧洲白蜡树又名欧洲梣（学名：Fraxinus excelsior）是一种梣属落叶乔木，主要分布在欧洲大陆，除斯堪的纳维亚北部和伊比利亚半岛以外均可生长，在亚洲土耳其北部到高加索山一带也分布。 欧洲白蜡树通高30米，冬季有黑色芽苞。每小枝生有羽状小叶9至13枚，长20至30厘米，叶片呈深绿色，秋季变黄。极为耐寒。","desc_en":"Fraxinus excelsior, known as the ash, or European ash or common ash to distinguish it from other types of ash, is a flowering plant species in the olive family Oleaceae.","img":"images/821.jpg","thumb":"images/t/821.jpg","file":"Fraxinus excelsior 001.jpg","ar":1.333,"py":"ouzhoubailashu ozbls","cr_by":"Willow","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/821.jpg","illus_thumb":"images/i/t/821.jpg","illus_file":"Fraxinus excelsior flower illustration.jpg","illus_ar":0.478,"illus_by":"G.Bernetti/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":822,"seq":830,"zh":"茉莉花","en":"Jasminum sambac","sci":"Jasminum sambac","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":null,"langs":56,"desc_zh":"茉莉花（学名：Jasminum sambac，梵语：मल्लिका，罗马化：Mallikā），又称茉莉，为木犀科素馨属的植物，是一种高约1至3公尺的灌木。茉莉花原产于印度，现时世界各地也很广泛地栽培。","desc_en":"Jasminum sambac (Arabian jasmine or Sambac jasmine or Mogra) is a species of jasmine native to Bhutan and India. It is cultivated in many places, especially West Asia, South Asia and Southeast Asia.","img":"images/822.jpg","thumb":"images/t/822.jpg","file":"JasminumSambac.jpg","ar":1.333,"py":"molihua mlh","cr_by":"Taken by Fanghong","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲"]},{"id":823,"seq":831,"zh":"欧丁香","en":"Syringa vulgaris","sci":"Syringa vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":"LC","langs":56,"desc_zh":"欧丁香（学名：Syringa vulgaris），又称丁香、洋丁香，是木犀科丁香属的一个种，原产东南欧。温带地区广泛栽培，包括中国东北、西北、华北、江苏等地。","desc_en":"Syringa vulgaris, the lilac or common lilac, is a species of flowering plant in the olive family, Oleaceae. Native to the Balkan Peninsula, it is widely cultivated for its scented flowers in Europe (particularly the north and west) and North America.","img":"images/823.png","thumb":"images/t/823.png","file":"Lilac Larousse Extracted.png","ar":1.101,"py":"oudingxiang odx","cr_by":"Arbres d'ornement-1 - ornamental trees in colour- Public domain book illustration (visual explanation, informative drawi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲","北美洲"],"illus_img":"images/i/823.jpg","illus_thumb":"images/i/t/823.jpg","illus_file":"T2 61 Syringa vulgaris par Pierre-Joseph Redouté.jpeg","illus_ar":0.717,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":824,"seq":832,"zh":"花梣","en":"Fraxinus ornus","sci":"Fraxinus ornus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":"LC","langs":54,"desc_zh":"花梣（学名：Fraxinus ornus），又名花白蜡，是原产于南欧与西南亚的梣属植物，其分布范围西起西班牙与意大利，北至奥地利与捷克，向东经巴尔干半岛、土耳其、叙利亚西部延伸至黎巴嫩与亚美尼亚。","desc_en":"Fraxinus ornus, the manna ash or South European flowering ash, is a species of Fraxinus native to Southern Europe and Southwestern Asia, from Spain and Italy north to Austria and the Czech Republic, and east through the Balkans, Turkey, and western Syria to Le…","img":"images/824.jpg","thumb":"images/t/824.jpg","file":"(MHNT) Fraxinus ornus - Flowers - Fronton (Haute-Garonne).jpg","ar":1.084,"py":"huaqin hq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/824.jpg","illus_thumb":"images/i/t/824.jpg","illus_file":"Fraxinus ornus - Köhler–s Medizinal-Pflanzen-062.jpg","illus_ar":0.828,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":826,"seq":833,"zh":"穿心莲","en":"Andrographis paniculata","sci":"Andrographis paniculata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":49,"desc_zh":"穿心莲（学名：Andrographis paniculata）为爵床科一年生草本植物。","desc_en":"Andrographis paniculata, commonly known as creat or green chiretta, is an annual herbaceous plant in the family Acanthaceae, native to India and Sri Lanka. It is widely cultivated in Southern and Southeastern Asia, where it has been believed to be a treatment…","img":"images/826.jpg","thumb":"images/t/826.jpg","file":"Andrographis-paniculata.jpg","ar":1.333,"py":"chuanxinlian cxl","cr_by":"Uwe Thobae","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":827,"seq":834,"zh":"蛤蟆花","en":"Acanthus mollis","sci":"Acanthus mollis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":38,"desc_zh":null,"desc_en":"Acanthus mollis, commonly known as bear's breeches, sea dock, bear's foot plant, sea holly, gator plant or oyster plant, is a species of plant in the family Acanthaceae and is native to the Mediterranean region.","img":"images/827.jpg","thumb":"images/t/827.jpg","file":"Acanthaceae - Acanthus mollis (2).JPG","ar":0.665,"py":"hamahua hmh","cr_by":"Hectonichus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"]},{"id":828,"seq":835,"zh":"鸭嘴花","en":"Justicia adhatoda","sci":"Justicia adhatoda","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Justicia adhatoda commonly known in English as Malabar nut, adulsa, adhatoda, vasa, vasaka, is native to Asia. Adathoda means 'untouched by goats' in Tamil.","img":"images/828.jpg","thumb":"images/t/828.jpg","file":"Justicia adhatoda - Alipore - Kolkata 2013-02-10 4607.JPG","ar":0.665,"py":"yazuihua yzh","cr_by":"Biswarup Ganguly","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲"]},{"id":829,"seq":836,"zh":"翼叶山牵牛","en":"Thunbergia alata","sci":"Thunbergia alata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":30,"desc_zh":"翼叶山牵牛（学名：Thunbergia alata）是爵床科山牵牛属的植物。分布于热带非洲以及中国大陆的广东、福建等地，目前已由人工引种栽培。","desc_en":"Thunbergia alata, commonly called black-eyed Susan vine, is a herbaceous perennial climbing plant species in the family Acanthaceae. It is native to Eastern Africa, and has been naturalized in other parts of the world.","img":"images/829.jpg","thumb":"images/t/829.jpg","file":"ACANTHACEAE Thunbergia alata Bojer ex Sims, INMA (MBML040839).pdf","ar":0.707,"py":"yiyeshanqianniu yysqn","cr_by":"Instituto Nacional da Mata Atlântica - INMA","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["非洲"],"illus_img":"images/i/829.jpg","illus_thumb":"images/i/t/829.jpg","illus_file":"Thunbergia alata illustration.jpg","illus_ar":0.679,"illus_by":"J.L.A. Loiseleur-Deslongchamps","illus_lic":"Public domain","illus_licurl":null},{"id":831,"seq":837,"zh":"大岩桐","en":"Sinningia speciosa","sci":"Sinningia speciosa","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":null,"langs":22,"desc_zh":"大岩桐（学名：Sinningia speciosa），大岩桐为园艺贸易的俗称，是苦苣苔科岩桐属的多年生球根花卉家族成员其种加词“speciosa”意为“外表美丽的”。 长大而鲜艳的花朵，所以常用作园艺植物。生长于南美洲巴西的热带草原。大岩桐通常在春、夏季开花，它的抗寒区为10-12。","desc_en":"Sinningia speciosa, sometimes known in the horticultural trade as gloxinia, is a tuberous member of the flowering plant native to Brazil within the family Gesneriaceae. Originally included in the genus Gloxinia in 1817, it was reclassified to Sinningia.","img":"images/831.jpg","thumb":"images/t/831.jpg","file":"Sinningia speciosa-IMG 0659.JPG","ar":1,"py":"dayantong dyt","cr_by":"Christer T Johansson","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["南美洲"]},{"id":832,"seq":838,"zh":"喜荫花","en":"Episcia cupreata","sci":"Episcia cupreata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":null,"langs":16,"desc_zh":"喜荫花（学名：Episcia cupreata）为苦苣苔科喜荫花属下的一个种。","desc_en":"Episcia cupreata is a species of perennial plant in the family Gesneriaceae that is found in Brazil, Colombia, and Venezuela. Its common name is flame violet, although this name may also refer to other species of the genus Episcia.","img":"images/832.jpg","thumb":"images/t/832.jpg","file":"Arya.episcia cupreata viridiflora.bulak.2019.jpg","ar":0.75,"py":"xiyinhua xyh","cr_by":"Aris riyanto","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["南美洲"]},{"id":833,"seq":839,"zh":"高山欧洲苣苔","en":"Ramonda myconi","sci":"Ramonda myconi","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":"LC","langs":16,"desc_zh":null,"desc_en":"Ramonda myconi, the Pyrenean-violet or rosette mullein, syn. R. pyrenaica, is a species of flowering plant in the family Gesneriaceae, which is a relictual endemite of shady, rocky places in the Pyrenees and north eastern Spain.","img":"images/833.jpg","thumb":"images/t/833.jpg","file":"RAMONDA MYCONI - LA CORRIU - IB-467 (Orella d'ós).JPG","ar":0.75,"py":"gaoshanouzhoujutai gsozjt","cr_by":"Isidre blanc","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":834,"seq":840,"zh":"非洲堇属","en":"Saintpaulia ionantha","sci":"Saintpaulia ionantha","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":"NT","langs":15,"desc_zh":null,"desc_en":"Streptocarpus ionanthus (synonym Saintpaulia ionantha) is a species of Streptocarpus in the section Saintpaulia, commonly known as an African violet. It is native to eastern and southwestern Tanzania.","img":"images/834.jpg","thumb":"images/t/834.jpg","file":"2007-04-20Saintpaulia ionantha04.jpg","ar":1.342,"py":"feizhoujinshu fzjs","cr_by":"Wildfeuer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"],"illus_img":"images/i/834.jpg","illus_thumb":"images/i/t/834.jpg","illus_file":"Streptocarpus ionanthus (as Saintpaulia ionantha) - Curtis' 121 (Ser. 3 no. 51) pl. 7408 (1895).jpg","illus_ar":0.612,"illus_by":"M. S. del. ( = Matilda Smith , 1854-1926), J. N. Fitch lith. ( = John Nugent Fitch , 1840–1927) Description by Joseph Da","illus_lic":"Public domain","illus_licurl":null},{"id":1229,"seq":841,"zh":"布袋花","en":"Calceolaria uniflora","sci":"Calceolaria uniflora","order_en":"Lamiales","order_zh":"唇形目","family_en":"Calceolariaceae","family_zh":"蒲包花科","iucn":null,"langs":19,"desc_zh":null,"desc_en":"Calceolaria uniflora (syn. Calceolaria darwinii, known as Darwin's slipper) is a perennial plant of the genus Calceolaria, known as the slipperworts. It is originally from Tierra del Fuego in the southern part of South America.","img":"images/1229.jpg","thumb":"images/t/1229.jpg","file":"Calceolaria uniflora.JPG","ar":1.333,"py":"budaihua bdh","cr_by":"Thomas Mathis","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["南美洲"]},{"id":1230,"seq":842,"zh":"夏堇","en":"Torenia fournieri","sci":"Torenia fournieri","order_en":"Lamiales","order_zh":"唇形目","family_en":"Linderniaceae","family_zh":"母草科","iucn":null,"langs":14,"desc_zh":"夏堇（学名：Torenia fournieri）又名蓝猪耳、雀仔花，为玄参科蝴蝶草属下的一个种。","desc_en":"Torenia fournieri, the bluewings or wishbone flower, is an annual plant in the Linderniaceae, with blue, white, or pink flowers that have yellow markings. It is typically grown as a landscape annual, reaching 12–15 in. tall.","img":"images/1230.jpg","thumb":"images/t/1230.jpg","file":"Torenia fournieri2.jpg","ar":0.743,"py":"xiajin xj","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":1231,"seq":843,"zh":"羊角麻","en":"Ibicella lutea","sci":"Ibicella lutea","order_en":"Lamiales","order_zh":"唇形目","family_en":"Martyniaceae","family_zh":"角胡麻科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Ibicella lutea (; syn. Martynia lutea, Proboscidea lutea) is a species of flowering plant known by the common name yellow unicorn-plant. It grows in dry conditions, such as those in desert regions.","img":"images/1231.jpg","thumb":"images/t/1231.jpg","file":"Ibicella lutea1.JPG","ar":1.165,"py":"yangjiaoma yjm","cr_by":"Mello T R B","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["非洲","北美洲","南美洲"]},{"id":1232,"seq":844,"zh":"通泉草","en":"Mazus pumilus","sci":"Mazus pumilus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Mazaceae","family_zh":"通泉草科","iucn":null,"langs":10,"desc_zh":"通泉草（学名：Mazus pumilus）是通泉草科通泉草属植物。常生长在较为潮湿的草地；从低海拔的荒地、沟渠旁，都很容易发现它的身影。潮湿之地常常意味著泉水水源在附近，因此可能是「通泉」命名的由来。遍布中国大陆（内蒙古、宁夏、青海及新疆除外）以及台湾、日本（琉球群岛）、越南、俄罗斯、朝鲜、菲律宾、泰国、印度尼西亚、不丹、克什米尔、印度锡金、新几内亚等地。 其种加词“pumilus”意为“矮小的”。","desc_en":"Mazus pumilus, commonly called Japanese mazus, is a species of flowering plant in the Mazaceae family. It is native to south and east Asia, where it is found in Bhutan, China, India, Pakistan, Bangladesh, Indonesia, Japan, Korea, Nepal, New Guinea, the Philipp…","img":"images/1232.jpg","thumb":"images/t/1232.jpg","file":"Mazus pumilus2.jpg","ar":0.739,"py":"tongquancao tqc","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","大洋洲"]},{"id":1233,"seq":845,"zh":"毛泡桐","en":"Paulownia tomentosa","sci":"Paulownia tomentosa","order_en":"Lamiales","order_zh":"唇形目","family_en":"Paulowniaceae","family_zh":"泡桐科","iucn":"LC","langs":42,"desc_zh":"毛泡桐（学名：Paulownia tomentosa）为泡桐科泡桐属的植物。以其花紫色，又名紫花泡桐。分布在北美洲、日本、朝鲜、欧洲以及中国大陆的河北、山西、山东、湖北、江西、辽宁、河南、江苏、安徽等地，生长于海拔500米至1,800米的地区。","desc_en":"Paulownia tomentosa, common names princess tree, empress tree, or foxglove-tree, is a deciduous hardwood tree in the family Paulowniaceae, native to central and eastern China and the Korean Peninsula.","img":"images/1233.jpg","thumb":"images/t/1233.jpg","file":"Paulownia tomentosa JPG2a.jpg","ar":1.501,"py":"maopaotong mpt","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲"]},{"id":1234,"seq":846,"zh":"芝麻","en":"Sesamum indicum","sci":"Sesamum indicum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Pedaliaceae","family_zh":"芝麻科","iucn":null,"langs":126,"desc_zh":"脂麻（学名：Sesamum indicum），俗作芝麻，别名巨胜、苣蕂、油麻、胡麻，是脂麻科脂麻属植物。它遍布世界上的热带地区，在温带地区也有种植。因为它的种子含油率较高并是可食用的，所以它被大量种植。由于品种差异，芝麻有黑、白等不同颜色的区别。芝麻既可食用又可作为油料。","desc_en":"Sesame (; Sesamum indicum) is a plant in the genus Sesamum, also called benne. Numerous wild relatives occur in Africa and a smaller number in India. It is widely naturalized in tropical regions around the world and is cultivated for its edible seeds, which gr…","img":"images/1234.jpg","thumb":"images/t/1234.jpg","file":"Sesamum indicum 2.jpg","ar":0.667,"py":"zhima zm","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","非洲"],"illus_img":"images/i/1234.jpg","illus_thumb":"images/i/t/1234.jpg","illus_file":"Sesamum indicum - Köhler–s Medizinal-Pflanzen-129.jpg","illus_ar":0.687,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1235,"seq":847,"zh":"斑点狗面花","en":"Erythranthe guttata","sci":"Erythranthe guttata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Phrymaceae","family_zh":"透骨草科","iucn":null,"langs":20,"desc_zh":null,"desc_en":"Erythranthe guttata, with the common names seep monkeyflower and common yellow monkeyflower, is a yellow bee-pollinated annual or perennial flowering plant. It was formerly known as Mimulus guttatus.","img":"images/1235.jpg","thumb":"images/t/1235.jpg","file":"Erythranthe guttata or Mimulus, the Monkey Flower.jpg","ar":1.171,"py":"bandiangoumianhua bdgmh","cr_by":"Rosser1954","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":1236,"seq":848,"zh":"Nuxia floribunda","en":"Nuxia floribunda","sci":"Nuxia floribunda","order_en":"Lamiales","order_zh":"唇形目","family_en":"Stilbaceae","family_zh":"密穗草科","iucn":"LC","langs":11,"desc_zh":null,"desc_en":"Nuxia floribunda, the forest elder, forest nuxia or wild elder, is a species of tree in the Stilbaceae family, that is native to moist regions of southern Africa, East Africa and central tropical Africa.","img":"images/1236.jpg","thumb":"images/t/1236.jpg","file":"Nuxia floribunda.jpg","ar":1.333,"py":"","cr_by":"Melburnian","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["非洲"]},{"id":836,"seq":849,"zh":"欧洲冬青","en":"Ilex aquifolium","sci":"Ilex aquifolium","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":"LC","langs":63,"desc_zh":"欧洲冬青（学名Ilex aquifolium）是一种原产于西欧及南欧、西北非洲及西南亚洲的冬青。 欧洲冬青是常绿树，高达10-25米，树干直径40-80厘米阔，树皮呈灰色及光滑。叶子长5-12厘米及阔2-6厘米，形状各有不同。幼树及低枝上的叶子每边有3-5条尖刺，交替指向上下；在较高的树枝上的叶子有很少或没有尖刺。 花朵是雌雄异株的，呈白色及有4瓣，由蜜蜂传播花粉。果实呈红色，直径阔6-10毫米，有4个果核，一般在秋末成熟。","desc_en":"Ilex aquifolium, the holly, common holly, English holly, European holly, or occasionally Christmas holly, is a species of flowering plant in the family Aquifoliaceae, native to western and southern Europe, northwest Africa, and southwest Asia.","img":"images/836.jpg","thumb":"images/t/836.jpg","file":"Illustration Ilex aquifolium0.jpg","ar":0.596,"py":"ouzhoudongqing ozdq","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/836.jpg","illus_thumb":"images/i/t/836.jpg","illus_file":"Illustration Ilex aquifolium0.jpg","illus_ar":0.596,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":837,"seq":850,"zh":"巴拉圭冬青","en":"yerba mate","sci":"Ilex paraguariensis","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":"NT","langs":58,"desc_zh":"巴拉圭冬青（学名：Ilex paraguariensis），为冬青科冬青属植物。原产于南美洲的亚热带地区，包括阿根廷北部、巴拉圭、乌拉圭、巴西南部及玻利维亚。将巴拉圭冬青干燥的叶片浸泡在热水中，所泡出来的茶汤称为玛黛茶（港台译作：玛黛茶；也称巴拉圭茶（Paraguay tea）、巴西茶（Brazilian tea）），含有咖啡因、鞣酸，是一种兴奋饮料，其咖啡因含量比等量的绿茶稍高，收敛性较茶弱。","desc_en":"Yerba mate or yerba maté ( YUR-bə MAH-tay), Ilex paraguariensis, is a plant species of the holly genus native to South America. The leaves of the plant can be steeped in hot water to make a beverage known as mate. Brewed cold, it is used to make tereré.","img":"images/837.jpg","thumb":"images/t/837.jpg","file":"Ilex paraguariensis - Köhler–s Medizinal-Pflanzen-074.jpg","ar":0.691,"py":"balaguidongqing blgdq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"],"illus_img":"images/i/837.jpg","illus_thumb":"images/i/t/837.jpg","illus_file":"Ilex paraguariensis - Köhler–s Medizinal-Pflanzen-074.jpg","illus_ar":0.691,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":838,"seq":851,"zh":"齿叶冬青","en":"Ilex crenata","sci":"Ilex crenata","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":null,"langs":21,"desc_zh":"齿叶冬青（学名：Ilex crenata，又名日本冬青）是冬青科冬青属的植物。分布于日本、欧美、台湾以及中国大陆东部等地，生长于海拔700米至2 100米的地区，常生长在山谷杂木林中、灌丛中、山顶灌丛中或石边。","desc_en":"Ilex crenata, also known as Japanese holly or box-leaved holly, is a species of flowering plant in the family Aquifoliaceae, native to East and Southeast Asia.","img":"images/838.jpg","thumb":"images/t/838.jpg","file":"Ilex Crenata5.jpg","ar":0.791,"py":"chiyedongqing cydq","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":1237,"seq":852,"zh":"青荚叶","en":"Helwingia japonica","sci":"Helwingia japonica","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Helwingiaceae","family_zh":"青荚叶科","iucn":null,"langs":12,"desc_zh":"青荚叶（学名：Helwingia japonica）为青荚叶科青荚叶属下的一个种。","desc_en":"Helwingia japonica, the Japanese helwingia, is a species of flowering plant in the family Helwingiaceae. It is native to South-East Asia.","img":"images/1237.jpg","thumb":"images/t/1237.jpg","file":"Helwingia japonica (Montage s3).jpg","ar":1,"py":"qingjiaye qjy","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":840,"seq":853,"zh":"向日葵","en":"common sunflower","sci":"Helianthus annuus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":138,"desc_zh":"向日葵（学名：Helianthus annuus），别名向阳花、朝阳花、日头花、葵花、文菊，是一种大型菊科向日葵属植物。因用其果实榨取的食用油和果实具备较高经济价值，而被认为是一种经济作物。 向日葵也常被野生鸟类作为食物和牲畜饲料（作为膳食或青贮）。向日葵还常作为一种花园观赏植物被用于园艺种植。该植物最早是在美洲被人类驯化；16世纪，葵花籽从美洲被带到了欧洲，并在欧洲成为一种被广泛使用的烹饪原料。","desc_en":"The common sunflower (Helianthus annuus) is a large annual forb in the daisy family Asteraceae. The domesticated form of common sunflower is harvested for its edible seeds, which come in two types: oil and confectionary seeds.","img":"images/840.jpg","thumb":"images/t/840.jpg","file":"Helianthus annuus exposed 2004-05-22.jpg","ar":0.75,"py":"xiangrikui xrk","cr_by":"Jon Sullivan","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":841,"seq":854,"zh":"莴苣","en":"Lactuca sativa","sci":"Lactuca sativa","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":126,"desc_zh":"莴苣（学名：Lactuca sativa），又名生菜、莴菜、春菜，是菊科莴苣属之一年生或二年生草本植物，原产于地中海一带，因适应性佳而目前普及温带、亚热带地区。","desc_en":"Lettuce (Lactuca sativa) is an annual plant of the family Asteraceae mostly grown as a leaf vegetable. The leaves are most often used raw in green salads, although lettuce is also seen in other kinds of food, such as sandwiches, wraps and soups; it can also be…","img":"images/841.jpg","thumb":"images/t/841.jpg","file":"Iceberg lettuce in SB.jpg","ar":1.333,"py":"woju wj","cr_by":"en:User:Geographer","cr_lic":"CC BY 1.0","cr_licurl":"https://creativecommons.org/licenses/by/1.0","habit":"草本","origin":null},{"id":842,"seq":855,"zh":"药用蒲公英","en":"common dandelion","sci":"Taraxacum officinale","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":97,"desc_zh":"西洋蒲公英（学名：Taraxacum officinale）又名药用蒲公英，菊科蒲公英属植物，因其繁殖能力强而在世界各地均被视为野草，在全球多个平原及温带地区均有其影踪。分布于北美洲、吉尔吉斯斯坦、哈萨克斯坦、欧洲以及中国大陆的新疆等地，生长于海拔700米至2,200米的地区，多生在低山草原、森林草甸以及田间与路边。此外也有人将其视为药草的一种。","desc_en":"Taraxacum officinale, the dandelion or common dandelion, is a herbaceous perennial flowering plant in the daisy family, Asteraceae. The common dandelion is well-known for its yellow flower heads that turn into round balls of many silver-tufted fruit, which dis…","img":"images/842.jpg","thumb":"images/t/842.jpg","file":"Maskros 2.jpg","ar":0.711,"py":"yaoyongpugongying yypgy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"],"illus_img":"images/i/842.jpg","illus_thumb":"images/i/t/842.jpg","illus_file":"Taraxacum officinale - Köhler–s Medizinal-Pflanzen-135.jpg","illus_ar":0.727,"illus_by":"Walther Otto Müller","illus_lic":"Public domain","illus_licurl":null},{"id":843,"seq":856,"zh":"蓍","en":"Achillea millefolium","sci":"Achillea millefolium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":95,"desc_zh":"洋蓍草（学名：Achillea millefolium，拼音：shī ㄕ），又名欧蓍、千叶蓍、锯草、西洋蓍草、羽衣草、魔鬼荨麻，是菊科蓍属的多年生草本植物。分布在蒙古、伊朗、欧洲、俄罗斯、非洲以及中国大陆的东北、内蒙古、新疆等地，生长于海拔200米至2,300米的地区，见于湿草地、荒地和铁路沿线，目前已由人工引种栽培。","desc_en":"Achillea millefolium, commonly known as yarrow () or common yarrow, is a flowering plant in the family Asteraceae. Growing to 1 metre (3+1⁄3 feet) tall, it is characterized by small whitish flowers, a tall stem of fernlike leaves, and a pungent odor.","img":"images/843.jpg","thumb":"images/t/843.jpg","file":"Achillea millefolium vallee-de-grace-amiens 80 22062007 1.jpg","ar":0.669,"py":"shi s","cr_by":"O. Pichard","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","北美洲"],"illus_img":"images/i/843.jpg","illus_thumb":"images/i/t/843.jpg","illus_file":"Achillea millefolium - Köhler–s Medizinal-Pflanzen-149.jpg","illus_ar":0.77,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":844,"seq":857,"zh":"菊苣","en":"Cichorium intybus","sci":"Cichorium intybus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":94,"desc_zh":"菊苣（学名：Cichorium intybus），又称苦苣、苦菜，是一种灌木丛生的多年生草本植物，长出蓝色或薰衣草色的小花。原生于欧洲，但现时已自然生长于北美等地而成为路边物种。经烘焙及磨碎后的根部广泛用作咖啡代用品起源于地中海，但现在在全球，特别是美国南部的新奥尔良地区、印度及东南亚也广受欢迎。与此同时，它也是制作红眼肉汁的主要材料。 常见的菊苣有多个名称，包括blue sailors、succory、coffeeweed等。","desc_en":"Common chicory (Cichorium intybus) is a somewhat woody, perennial herbaceous plant of the family Asteraceae, usually with bright blue flowers, rarely white or pink.","img":"images/844.jpg","thumb":"images/t/844.jpg","file":"Illustration Cichorium intybus0 clean.jpg","ar":0.612,"py":"juju jj","cr_by":"Original book source: Prof. Dr. Otto Wilhelm Thomé Flora von Deutschland, Österreich und der Schweiz 1885, Gera, Germany","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"],"illus_img":"images/i/844.jpg","illus_thumb":"images/i/t/844.jpg","illus_file":"Illustration Cichorium intybus0 clean.jpg","illus_ar":0.612,"illus_by":"Original book source: Prof. Dr. Otto Wilhelm Thomé Flora von Deutschland, Österreich und der Schweiz 1885, Gera, Germany","illus_lic":"Public domain","illus_licurl":null},{"id":845,"seq":858,"zh":"雏菊","en":"Bellis perennis","sci":"Bellis perennis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":94,"desc_zh":"雏菊（学名：Bellis perennis）是菊科雏菊属的一种，别名长命菊、延命菊，原产于欧洲，原种被视为丛生的杂草，开花期在春季。 雏菊在原产地是多年生草本植物，学名的种加词perennis也含有「多年生的」的意思，但在日本由于夏季炎热，雏菊多半活不过夏季，通常被当作秋天播种的一年生植物。雏菊在能够渡夏的寒冷地区可以进行分枝繁殖。","desc_en":"Bellis perennis ( BEL-iss pə-REN-iss), the daisy, is a European species of the family Asteraceae, often considered the archetypal species of the name daisy.","img":"images/845.jpg","thumb":"images/t/845.jpg","file":"Belis peremnis - panoramio.jpg","ar":1.333,"py":"chuju cj","cr_by":"m.dolores paderne sa…","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/845.jpg","illus_thumb":"images/i/t/845.jpg","illus_file":"Bellis perennis Sturm DESC.JPG","illus_ar":1.905,"illus_by":"Johann Georg Sturm","illus_lic":"Public domain","illus_licurl":null},{"id":846,"seq":859,"zh":"中亚苦蒿","en":"Artemisia absinthium","sci":"Artemisia absinthium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":93,"desc_zh":"中亚苦蒿（学名：Artemisia absinthium）为菊科蒿属的植物。分布于欧洲、克什米尔、非洲、阿富汗、伊朗、俄罗斯、北美洲、印度、巴基斯坦以及中国大陆的新疆等地，生长于海拔1,100米至1,500米的地区，多生长于山坡、林缘、野果林、草原及灌丛地等）。是酿造苦艾酒的原料之一。","desc_en":"Artemisia absinthium, otherwise known as common wormwood, is a species of Artemisia native to North Africa and temperate regions of Eurasia, and widely naturalized in Canada and the northern United States.","img":"images/846.jpg","thumb":"images/t/846.jpg","file":"Artemisia absinthium P1210748.jpg","ar":0.75,"py":"zhongyakuhao zykh","cr_by":"David Monniaux","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","非洲","北美洲"],"illus_img":"images/i/846.jpg","illus_thumb":"images/i/t/846.jpg","illus_file":"Artemisia absinthium (Köhler).jpg","illus_ar":0.804,"illus_by":"Hermann Adolf Köhler (1834 - 1879)","illus_lic":"Public domain","illus_licurl":null},{"id":847,"seq":860,"zh":"洋姜","en":"Helianthus tuberosus","sci":"Helianthus tuberosus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":91,"desc_zh":"菊芋（学名：Helianthus tuberosus，英语：Jerusalem artichoke）也称洋姜、鬼子姜、姜不辣、块茎向日葵，是一种菊科向日葵属宿根性草本植物。原产北美洲中部，十七世纪传入欧洲，后传入中国。","desc_en":"The Jerusalem artichoke (Helianthus tuberosus), also called sunroot, sunchoke, wild sunflower, topinambur, or earth apple, is a species of sunflower native to central North America.","img":"images/847.jpg","thumb":"images/t/847.jpg","file":"Sunroot top.jpg","ar":0.75,"py":"yangjiang yj","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲"]},{"id":848,"seq":861,"zh":"款冬","en":"Tussilago farfara","sci":"Tussilago farfara","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":85,"desc_zh":"款冬（学名：Tussilago farfara），别名冬花、款冬蒲公英 多年生草本植物，广卵形至心脏形叶子丛生，边缘有波状疏锯齿，下面密被白色棉毛；冬季花茎先叶出现，顶生头状花序，周围为黄色舌状花，中央为管状花；细小瘦果。 原产于中国、欧洲和非洲北部，日本也有生长。","desc_en":"Tussilago farfara, commonly known as coltsfoot, is a plant in the tribe Senecioneae in the family Asteraceae, native to Europe and parts of western and central Asia.","img":"images/848.jpg","thumb":"images/t/848.jpg","file":"Coltsfoot.jpg","ar":1.321,"py":"kuandong kd","cr_by":"Andreas Trepte","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/848.jpg","illus_thumb":"images/i/t/848.jpg","illus_file":"Tussilago farfara - Köhler–s Medizinal-Pflanzen-142.jpg","illus_ar":0.754,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":849,"seq":862,"zh":"北艾","en":"Artemisia vulgaris","sci":"Artemisia vulgaris","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":85,"desc_zh":"北艾（学名：Artemisia vulgaris）为菊科蒿属的植物。分布在加拿大、蒙古、俄罗斯、北美洲、大西洋、欧洲、美国以及中国大陆的青海、新疆、四川、甘肃、陕西等地，生长于海拔1,500米至2,100米的地区，一般生于谷地、森林草原、亚高山地区的草原、林缘、荒坡和路旁等处，目前尚未由人工引种栽培。","desc_en":"Artemisia vulgaris, commonly known as mugwort, common mugwort, or wormwood, is a species of flowering plant in the daisy family Asteraceae. It is one of several species in the genus Artemisia commonly known as mugwort, although Artemisia vulgaris is the specie…","img":"images/849.jpg","thumb":"images/t/849.jpg","file":"Artemisia vulgaris - Köhler–s Medizinal-Pflanzen-016.jpg","ar":0.728,"py":"beiai ba","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/849.jpg","illus_thumb":"images/i/t/849.jpg","illus_file":"Artemisia vulgaris - Köhler–s Medizinal-Pflanzen-016.jpg","illus_ar":0.728,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":850,"seq":863,"zh":"红花","en":"Carthamus tinctorius","sci":"Carthamus tinctorius","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":81,"desc_zh":"红花（学名：Carthamus tinctorius)，又名红蓝花，属菊科植物。原产于亚洲和非洲地区，在埃及已有四千年栽培历史。如今在全球都有栽培，其中印度栽培规模最大。","desc_en":"Safflower (Carthamus tinctorius), also false saffron, is a highly branched, herbaceous, thistle-like annual plant in the family Asteraceae. It is one of the world's oldest crops; today, it is commercially cultivated for vegetable oil extracted from the seeds.","img":"images/850.jpg","thumb":"images/t/850.jpg","file":"Safflower.jpg","ar":1.131,"py":"honghua hh","cr_by":null,"cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/850.jpg","illus_thumb":"images/i/t/850.jpg","illus_file":"Carthamus tinctorius Sturm21.jpg","illus_ar":0.68,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":851,"seq":864,"zh":"龙蒿","en":"tarragon","sci":"Artemisia dracunculus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":80,"desc_zh":"龙蒿（学名：Artemisia dracunculus）又称香艾菊、狭叶青蒿、蛇蒿、椒蒿、青蒿、他拉根香草，菊科多年生草本植物，原产于西伯利亚和西亚。阿拉伯人统治西班牙时期，才引入欧洲。中文圈里，俗误称为茵陈蒿。","desc_en":"Tarragon (Artemisia dracunculus), also known as estragon, is a species of perennial herb in the family Asteraceae. It is widespread in the wild across much of Eurasia and North America and is cultivated for culinary and medicinal purposes.","img":"images/851.jpg","thumb":"images/t/851.jpg","file":"Artemisia dracunculus1.jpg","ar":0.743,"py":"longhao lh","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"]},{"id":852,"seq":865,"zh":"矢车菊","en":"Centaurea cyanus","sci":"Centaurea cyanus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":80,"desc_zh":"矢车菊（学名：Centaurea cyanus）是菊科矢车菊属植物，又名蓝芙蓉、车轮花，也称矢车草。","desc_en":"Centaurea cyanus, commonly known as cornflower or bachelor's button (among other names), is an annual flowering plant in the family Asteraceae native to Europe.","img":"images/852.jpg","thumb":"images/t/852.jpg","file":"CentaureaCyanus-bloem-kl.jpg","ar":1.333,"py":"shicheju scj","cr_by":"TeunSpaans","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"],"illus_img":"images/i/852.jpg","illus_thumb":"images/i/t/852.jpg","illus_file":"Centaurea cyanus Sturm26.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":853,"seq":866,"zh":"金盏花","en":"Calendula officinalis","sci":"Calendula officinalis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":79,"desc_zh":"金盏花（学名：Calendula officinalis）又名金盏菊，为菊科金盏花属的一种，可能原产南欧，但在古代、近代就已引入世界各地，用于观赏、药用、染料及化妆品。","desc_en":"Calendula officinalis, Mary's gold, common marigold, the pot marigold, Scotch marigold, or ruddles, is a flowering plant in the daisy family, Asteraceae. It is probably native to southern Europe, but its long history of cultivation makes its precise origin unk…","img":"images/853.jpg","thumb":"images/t/853.jpg","file":"Calendula officinalis - Köhler–s Medizinal-Pflanzen-024.jpg","ar":0.706,"py":"jinzhanhua jzh","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"],"illus_img":"images/i/853.jpg","illus_thumb":"images/i/t/853.jpg","illus_file":"Calendula officinalis - Köhler–s Medizinal-Pflanzen-024.jpg","illus_ar":0.706,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":854,"seq":867,"zh":"德国洋甘菊","en":"Matricaria chamomilla","sci":"Matricaria chamomilla","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":79,"desc_zh":"德国洋甘菊又名母菊（学名：Matricaria chamomilla or Matricaria recutita），其气味带著微甜的香辛料味，比罗马洋甘菊的气味柔和。可制作香料和精油。分布于亚洲、欧洲以及新疆等地，目前产地为埃及、法国、德国和摩洛哥。精油以水蒸气蒸馏法制取，外观呈深蓝色，具有浓厚香甜味，挥发度中等，中强度。","desc_en":"Matricaria chamomilla (synonym: Matricaria recutita), commonly known as chamomile (also spelled camomile), German chamomile, Hungarian chamomile (kamilla), wild chamomile, blue chamomile, or scented mayweed, is an annual plant of the composite family Asteracea…","img":"images/854.jpg","thumb":"images/t/854.jpg","file":"Matricaria recutita 0.1 R.jpg","ar":1.333,"py":"deguoyangganju dgygj","cr_by":"Rob Hille","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null,"illus_img":"images/i/854.jpg","illus_thumb":"images/i/t/854.jpg","illus_file":"Description of Matricaria chamomilla in Linnaei Species plantarum 1753 vol 2 p 891.jpg","illus_ar":2.826,"illus_by":"Carl Linnaeus","illus_lic":"Public domain","illus_licurl":null},{"id":855,"seq":868,"zh":"牛蒡","en":"Arctium lappa","sci":"Arctium lappa","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":73,"desc_zh":"牛蒡（学名：Arctium lappa；英语：greater burdock；gobō (日语：牛蒡／ゴボウ)；edible burdock；lappa；beggar's buttons；thorny burr；happy major）是菊科牛蒡属的植物。中国各地普遍分布。","desc_en":"Arctium lappa, commonly called greater burdock, gobō (牛蒡/ゴボウ), edible burdock, lappa, beggar's buttons, thorny burr, or happy major is a Eurasian species of plants in the family Asteraceae.","img":"images/855.jpg","thumb":"images/t/855.jpg","file":"ArctiumLappa1.jpg","ar":0.885,"py":"niubang nb","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","北美洲","大洋洲"],"illus_img":"images/i/855.jpg","illus_thumb":"images/i/t/855.jpg","illus_file":"Arctium lappa botanilac illustration.jpg","illus_ar":0.659,"illus_by":"N. Criddle","illus_lic":"Public domain","illus_licurl":null},{"id":856,"seq":869,"zh":"高山火绒草","en":"edelweiss","sci":"Leontopodium nivale","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":66,"desc_zh":"高山火绒草（学名：Leontopodium alpinum）是菊科，火绒草属植物。又叫做高山薄雪草、雪绒花、小白花等。是欧洲著名的高山花卉。","desc_en":"Leontopodium nivale, commonly called edelweiss (lit. 'noble white') (English: AY-dəl-vyss; German: Edelweiß [ˈeːdl̩vaɪs] or Alpen-Edelweiß), is a mountain flower belonging to the daisy or sunflower family Asteraceae.","img":"images/856.jpg","thumb":"images/t/856.jpg","file":"Alpen Edelweiß, Leontopodium alpinum 2.JPG","ar":1.506,"py":"gaoshanhuorongcao gshrc","cr_by":"Böhringer Friedrich","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"]},{"id":857,"seq":870,"zh":"丝路蓟","en":"Cirsium arvense","sci":"Cirsium arvense","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":62,"desc_zh":"丝路蓟（学名：Cirsium arvense），又名田蓟或加拿大蓟，是一种分布在欧洲及亚洲北部的蓟属，并且广泛引进到其他地方。虽然在北美洲一般称它为加拿大蓟，但是并非来自加拿大。 丝路蓟下有两个变种： Cirsium arvense var. arvense：分布在欧洲大部份地方。叶子下方没有毛。 Cirsium arvense var. incanum：分布在欧洲南部。叶子下方有厚毛。","desc_en":"Cirsium arvense is a perennial species of flowering plant in the family Asteraceae, native throughout Europe and western Asia, northern Africa and widely introduced elsewhere. The standard English name in its native area is creeping thistle.","img":"images/857.jpg","thumb":"images/t/857.jpg","file":"20200701Cirsium arvense1.jpg","ar":1.333,"py":"siluji slj","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/857.jpg","illus_thumb":"images/i/t/857.jpg","illus_file":"Cirsium arvense Sturm08.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":858,"seq":871,"zh":"苦苣菜","en":"Sonchus oleraceus","sci":"Sonchus oleraceus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":60,"desc_zh":"苦菜（学名：Sonchus oleraceus），又名苦苣菜、滇苦荬菜、苦滇菜，为菊科苦苣菜属的植物。原产于欧洲和西亚，后来扩散到全球，生长于海拔170米至3,200米的地区，多生长在林下、山坡、平地田间、空旷处、山谷林缘或近水处。","desc_en":"Sonchus oleraceus is a species of flowering plant in the tribe Cichorieae of the family Asteraceae, native to Europe and Western Asia. It has many common names including common sowthistle, sow thistle, smooth sow thistle, annual sow thistle, puha (in New Zeala…","img":"images/858.jpg","thumb":"images/t/858.jpg","file":"Sónchus oleraceus.jpg","ar":1.331,"py":"kujucai kjc","cr_by":"T.Voekler","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/858.jpg","illus_thumb":"images/i/t/858.jpg","illus_file":"Sonchus oleraceus — Flora Batava — Volume v3.jpg","illus_ar":0.693,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":859,"seq":872,"zh":"法兰西菊","en":"Leucanthemum vulgare","sci":"Leucanthemum vulgare","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":59,"desc_zh":"法国菊（学名：Leucanthemum vulgare），又名法兰西菊、滨菊、春白菊、牛眼菊（英语：oxeye daisy）、玛格丽特（法语：Marguerite commune），是原产于欧洲及亚洲温带的菊科植物。 法国菊是多年生草本植物，在茎的顶端有细小的头状花序（不多于5厘米），由约20支白色舌状花及大量黄色心花所组成。茎多是没有分枝及从根上向侧生长。叶子两面均呈墨绿色。基生叶及中叶有柄，呈倒卵形至匙形，并有锯齿。","desc_en":"Leucanthemum vulgare, commonly known as the ox-eye daisy, oxeye daisy, dog daisy, marguerite (French: Marguerite commune, \"common marguerite\") and other common names, is a widespread flowering plant native to Europe and the temperate regions of Asia, and an in…","img":"images/859.jpg","thumb":"images/t/859.jpg","file":"Leucanthemum vulgare15.06.07.JPG","ar":1.333,"py":"falanxiju flxj","cr_by":"Victor M. Vicente Selvas","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","北美洲","大洋洲"]},{"id":860,"seq":873,"zh":"水飞蓟","en":"Silybum marianum","sci":"Silybum marianum","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":58,"desc_zh":"水飞蓟（学名：Silybum marianum），又名乳蓟，为菊科水飞蓟属下的一个植物种，是种中药材和食材。","desc_en":"Silybum marianum is a species of thistle. It has various common names including milk thistle, blessed milkthistle, Marian thistle, Mary thistle, Saint Mary's thistle, Mediterranean milk thistle, variegated thistle and Scotch thistle (not to be confused with On…","img":"images/860.jpg","thumb":"images/t/860.jpg","file":"Milk thistle.jpg","ar":1.499,"py":"shuifeiji sfj","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Tamron 28-75mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"草本","origin":["欧洲"],"illus_img":"images/i/860.jpg","illus_thumb":"images/i/t/860.jpg","illus_file":"Silybum marianum - Flora Londinensis - vol. 3 - t. 148.jpg","illus_ar":0.598,"illus_by":"William Curtis","illus_lic":"Public domain","illus_licurl":null},{"id":861,"seq":874,"zh":"菊蒿","en":"Tanacetum vulgare","sci":"Tanacetum vulgare","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":58,"desc_zh":"菊蒿（学名：Tanacetum vulgare）为菊科菊蒿属的多年生草本开花植物，原产于温带欧洲和亚洲，生长于海拔250米至2,400米的地区，一般生长在山坡、草地、丘陵地、河滩和桦木林下。 它已被引入世界其他地区，包括北美，并且在某些地区已成为入侵性的。","desc_en":"Tansy (Tanacetum vulgare) is a perennial, herbaceous flowering plant in the genus Tanacetum in the family Asteraceae, native to temperate Europe and Asia. It has been introduced to other parts of the world, including Australia and North and South America, and…","img":"images/861.jpg","thumb":"images/t/861.jpg","file":"Tanacetum vulgare - harilik soolikarohi Keilas2.jpg","ar":0.667,"py":"juhao jh","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/861.jpg","illus_thumb":"images/i/t/861.jpg","illus_file":"Tanacetum vulgare Sturm13047.jpg","illus_ar":0.679,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":862,"seq":875,"zh":"万寿菊","en":"Tagetes erecta","sci":"Tagetes erecta","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":55,"desc_zh":"万寿菊（学名：Tagetes erecta，为菊科万寿菊属的植物。原产墨西哥，在中国各地都有人栽培用于观赏，可生长在海拔1150米至1480米的地区，多生在路边草甸。万寿菊常于春天播种，因其花大、花期长，故常用于花坛布景。 现在万寿菊用来提炼食用色素E161b。","desc_en":"Tagetes erecta, the Aztec marigold, Mexican marigold, big marigold, cempaxochitl or cempasúchil, is a species of flowering plant in the genus Tagetes native to Mexico and Central America.","img":"images/862.jpg","thumb":"images/t/862.jpg","file":"Aztec Marigold Tagetes erecta.jpg","ar":1.059,"py":"wanshouju wsj","cr_by":"HitroMilanese","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲","北美洲"]},{"id":863,"seq":876,"zh":"苦苣","en":"Cichorium endivia","sci":"Cichorium endivia","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":53,"desc_zh":"苦苣（学名：Cichorium endivia），又称苦菊、苦白菜，为菊科菊苣属的植物，是一种栽培菊苣。分布在南欧、北美及亚洲等地，目前已由人工引种栽培，基生叶有苦味，软化后苦味减少而柔软，性喜冷凉气候，初夏抽花茎，可生食凉拌，有抗菌、解热、消炎、明目等作用。","desc_en":"Cichorium endivia is a species of flowering plant belonging to the genus Cichorium. It is widely cultivated as one of the species of similar bitter-leafed vegetables known as endive and escarole. There is considerable confusion between the species and C.","img":"images/863.jpg","thumb":"images/t/863.jpg","file":"Friseesalat1 (fcm).jpg","ar":1.259,"py":"kuju kj","cr_by":"Photograph: Frank C. Müller , Baden-Baden","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":864,"seq":877,"zh":"山金车","en":"Arnica montana","sci":"Arnica montana","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":51,"desc_zh":"山金车（学名：Arnica Montana）是一种源于中欧以及西伯利亚高原地区的的菊科植物，在缓解肌肉和关节疼痛及炎症方面具有悠久历史。近年全球有多项针对山金车疗效的基础医学及临床研究，证实山金车除了有消炎镇痛的疗效外，更具有促进受伤组织痊愈的效能，因而受到科研及医药业界的注视。","desc_en":"Arnica montana, also known as leopard's bane, mountain tobacco and mountain arnica, is a moderately toxic European flowering plant in the daisy family Asteraceae that has a large yellow flower head.","img":"images/864.jpg","thumb":"images/t/864.jpg","file":"00 2245 Echte Arnika (Arnica montana).jpg","ar":1.499,"py":"shanjinche sjc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/864.jpg","illus_thumb":"images/i/t/864.jpg","illus_file":"Arnica montana - Köhler–s Medizinal-Pflanzen-015.jpg","illus_ar":0.779,"illus_by":"Franz Eugen Köhler, Köhlers Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":865,"seq":878,"zh":"翼蓟","en":"Cirsium vulgare","sci":"Cirsium vulgare","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":51,"desc_zh":"翼蓟（学名：Cirsium vulgare）是菊科蓟属的植物，又名欧洲蓟，分布在俄罗斯、欧洲、地中海地区、北非以及中国大陆的新疆等地，并在北美洲作为入侵生物存在，生长于海拔800米至1,800米的地区，多生长于田间或潮湿草地。它是苏格兰的国花。 该植物为传粉者提供了大量的花蜜。 在由英国昆虫传粉者计划支持的AgriLand项目进行的英国植物调查中，它被评为大多数花蜜产量（每年单位单位花蜜量）前十名。","desc_en":"Cirsium vulgare, commonly known as spear thistle, bull thistle, or common thistle, is a species of the Asteraceae genus Cirsium, native throughout most of Europe (north to 66°N, locally 68°N), Western Asia (east to the Yenisei Valley), and northwestern Africa…","img":"images/865.jpg","thumb":"images/t/865.jpg","file":"Cirsium vulgare Harthope.jpg","ar":0.832,"py":"yiji yj","cr_by":"Sciadopitys from UK","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["亚洲","欧洲","非洲","北美洲","大洋洲"],"illus_img":"images/i/865.jpg","illus_thumb":"images/i/t/865.jpg","illus_file":"Cirsium vulgare Sturm DESC.jpg","illus_ar":1.206,"illus_by":"Johann Georg Sturm","illus_lic":"Public domain","illus_licurl":null},{"id":866,"seq":879,"zh":"苣荬菜","en":"Sonchus arvensis","sci":"Sonchus arvensis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":49,"desc_zh":"苣荬菜（学名：Sonchus arvensis）是菊科苦苣菜属的植物。分布在全球以及中国大陆的贵州、湖北、广西、福建、宁夏、新疆、云南、陕西、湖南、四川等地，生长于海拔300米至2,300米的地区，多生长在林间草地、山坡草地、潮湿地和近水旁，目前尚未由人工引种栽培。","desc_en":"Sonchus arvensis, the field milk thistle, field sowthistle, perennial sow-thistle, corn sow thistle, dindle, gutweed, swine thistle, or tree sow thistle, is a species of flowering plant in the family Asteraceae. S.","img":"images/866.jpg","thumb":"images/t/866.jpg","file":"Sonchus arvensis Unterfranken.jpg","ar":0.75,"py":"jumaicai jmc","cr_by":"Fornax","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null,"illus_img":"images/i/866.jpg","illus_thumb":"images/i/t/866.jpg","illus_file":"Sonchus arvensis — Flora Batava — Volume v1.jpg","illus_ar":0.674,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":867,"seq":880,"zh":"苍耳","en":"Xanthium strumarium","sci":"Xanthium strumarium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":48,"desc_zh":"苍耳（学名：Xanthium strumarium）为一年生草本，属于菊科苍耳属。菓实为「苍耳子」，苍耳子又名葈耳实、羊负来、羊带来、道人头、胡寝子、胡苍子。","desc_en":"Xanthium strumarium (rough cocklebur, Noogoora burr, clotbur, common cocklebur, large cocklebur, woolgarie bur, Siberian cocklebur) is a species of annual plants in the flowering plant family Asteraceae.","img":"images/867.jpg","thumb":"images/t/867.jpg","file":"Xanthium strumarium L..jpg","ar":0.687,"py":"canger ce","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/867.jpg","illus_thumb":"images/i/t/867.jpg","illus_file":"Xanthium strumarium — Flora Batava — Volume v18.jpg","illus_ar":0.766,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":868,"seq":881,"zh":"大叶菜蓟","en":"Cynara cardunculus","sci":"Cynara cardunculus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":47,"desc_zh":"刺苞菜蓟（学名：Cynara cardunculus）是菊科菜蓟属的植物，分布于地中海地区以及中国大陆的陕西等地，目前已由人工引种栽培。","desc_en":"The cardoon (Cynara cardunculus ), also called the artichoke thistle, is a thistle in the family Asteraceae. It is a naturally occurring species that also has many cultivated forms, including the globe artichoke.","img":"images/868.jpg","thumb":"images/t/868.jpg","file":"Cynara cardunculus0.jpg","ar":1.333,"py":"dayecaiji dycj","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":891,"seq":882,"zh":"北疆风铃草","en":"Campanula glomerata","sci":"Campanula glomerata","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":38,"desc_zh":"北疆风铃草（Campanula glomerata L.）为桔梗科风铃草属多年生草本植物。","desc_en":"Campanula glomerata, known by the common names clustered bellflower or Dane's blood, is a species of flowering plant in the genus Campanula, belonging to the family Campanulaceae. It is the county flower of Rutland, England.","img":"images/891.jpg","thumb":"images/t/891.jpg","file":"Campanula glomerata.JPG","ar":0.629,"py":"beijiangfenglingcao bjflc","cr_by":"Dag Lindgren","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/891.jpg","illus_thumb":"images/i/t/891.jpg","illus_file":"Campanula glomerata Lindman DESC.jpg","illus_ar":1.14,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":892,"seq":883,"zh":"圆叶风铃草","en":"Campanula rotundifolia","sci":"Campanula rotundifolia","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":38,"desc_zh":"圆叶风铃草（学名：Campanula rotundifolia）为桔梗科风铃草属下的一个种，分布北半球温带，生长在草地及欧石南荒地。多年生草本，高约30公分，珠形纤巧，茎及花梗细长。叶片为暗绿或蓝绿的线形叶，先端渐尖，叶柄小或无，匍匐根著生有心型的基生叶。白色至深蓝色的钟形花有五枚尖端裂瓣，花初生直立，绽放后会弯垂。","desc_en":"Campanula rotundifolia, the harebell or common harebell, Scottish bluebell, or bluebell in Scotland, is a species of flowering plant in the bellflower family Campanulaceae.","img":"images/892.jpg","thumb":"images/t/892.jpg","file":"Campanula rotondifolia.jpg","ar":0.75,"py":"yuanyefenglingcao yyflc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null,"illus_img":"images/i/892.jpg","illus_thumb":"images/i/t/892.jpg","illus_file":"Campanula rotundifolia Lindman DESC.jpg","illus_ar":1.232,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":893,"seq":884,"zh":"长发公主桔梗","en":"rampion bellflower","sci":"Campanula rapunculus","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":38,"desc_zh":null,"desc_en":"Campanula rapunculus, common name rampion bellflower, rampion, rover bellflower, or rapunzel, is a species of bellflower (Campanula) in the family Campanulaceae.","img":"images/893.jpg","thumb":"images/t/893.jpg","file":"Campanula rapunculus - Rampion Bellflower 06.jpg","ar":0.721,"py":"changfagongzhujiegeng cfgzjg","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"],"illus_img":"images/i/893.jpg","illus_thumb":"images/i/t/893.jpg","illus_file":"Campanula rapunculus — Flora Batava — Volume v15.jpg","illus_ar":0.689,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":894,"seq":885,"zh":"宽钟风铃草","en":"Campanula trachelium","sci":"Campanula trachelium","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Campanula trachelium, the nettle-leaved bellflower, is a species of bellflower. It is native to Eurasia and parts of northwestern Africa and the Middle East.","img":"images/894.jpg","thumb":"images/t/894.jpg","file":".00 2908 Nesselblättrige Glockenblume (Campanula trachelium).jpg","ar":0.75,"py":"kuanzhongfenglingcao kzflc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","非洲"],"illus_img":"images/i/894.jpg","illus_thumb":"images/i/t/894.jpg","illus_file":"Campanula trachelium — Flora Batava — Volume v10.jpg","illus_ar":0.747,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":895,"seq":886,"zh":"阔叶风铃草","en":"Campanula latifolia","sci":"Campanula latifolia","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Campanula latifolia, the giant bellflower, is a species of bellflower in the family Campanulaceae. It is also known as the large campanula and the wide-leaved bellflower. It is native to Europe and western Asia and is widely grown as an ornamental plant.","img":"images/895.jpg","thumb":"images/t/895.jpg","file":"Campanula latifolia1.jpg","ar":1.333,"py":"kuoyefenglingcao kyflc","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/895.jpg","illus_thumb":"images/i/t/895.jpg","illus_file":"Campanula latifolia — Flora Batava — Volume v18.jpg","illus_ar":0.781,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":897,"seq":887,"zh":"草海桐","en":"Scaevola taccada","sci":"Scaevola taccada","order_en":"Asterales","order_zh":"菊目","family_en":"Goodeniaceae","family_zh":"草海桐科","iucn":null,"langs":19,"desc_zh":"草海桐（学名：Scaevola taccada）为草海桐科草海桐属下的一种多年生常绿灌木。台湾原生，分布于全岛沿海地带。具耐风、耐潮、耐盐及抗旱特质，即使在海风强大的海边岩石上也能生长，长期以来被视为沿海防风定砂植物。另因草海桐植株优美，已成为全岛各地普受喜爱的园艺观赏植物。草海桐具药用价值，嫩叶与果实亦可食。","desc_en":"Scaevola taccada, also known as beach cabbage, sea lettuce, or beach naupaka, is a flowering plant in the family Goodeniaceae found in mangrove swamps and rocky or sandy coastal locations in the tropical areas of the Indo-Pacific.","img":"images/897.jpg","thumb":"images/t/897.jpg","file":"Starr 010209-0286 Scaevola taccada.jpg","ar":1.333,"py":"caohaitong cht","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"灌木","origin":["亚洲"]},{"id":1238,"seq":888,"zh":"Alseuosmia macrophylla","en":"Alseuosmia macrophylla","sci":"Alseuosmia macrophylla","order_en":"Asterales","order_zh":"菊目","family_en":"Alseuosmiaceae","family_zh":"假海桐科","iucn":null,"langs":8,"desc_zh":null,"desc_en":"Alseuosmia macrophylla, the toropapa or karapapa, is a plant species in the family Alseuosmiaceae. This is a small evergreen shrub which is endemic to New Zealand, along with two closely related species. An example occurrence of A.","img":"images/1238.jpg","thumb":"images/t/1238.jpg","file":"Alseuosmia macrophylla.jpg","ar":0.596,"py":"","cr_by":"Joseph Dalton Hooker","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["大洋洲"]},{"id":1239,"seq":889,"zh":"榅桲叶秋叶果","en":"Corokia cotoneaster","sci":"Corokia cotoneaster","order_en":"Asterales","order_zh":"菊目","family_en":"Argophyllaceae","family_zh":"雪叶科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Corokia cotoneaster is a flowering plant in the family Argophyllaceae was described by Étienne Fiacre Louis Raoul in 1846. This plant is commonly known as the wire-netting bush, korokio, or korokia-tarango. The word \"koriko\" comes from the Māori language.","img":"images/1239.jpg","thumb":"images/t/1239.jpg","file":"Corokia cotoneaster 138-8425.jpg","ar":0.625,"py":"wenboyeqiuyeguo wbyqyg","cr_by":"Matilda Smith / John Nugent Fitch","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":null},{"id":1240,"seq":890,"zh":"Succisella inflexa","en":"Succisella inflexa","sci":"Succisella inflexa","order_en":"Asterales","order_zh":"菊目","family_en":"Dipsacaceae","family_zh":"川续断科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Succisella inflexa is a species of flowering plant belonging to the family Caprifoliaceae. Its native range is Europe.","img":"images/1240.jpg","thumb":"images/t/1240.jpg","file":"ÖBG 2010-09-23 Succisella inflexa 1.jpg","ar":0.748,"py":"","cr_by":"El Grafo","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"]},{"id":1241,"seq":891,"zh":"睡菜","en":"Menyanthes trifoliata","sci":"Menyanthes trifoliata","order_en":"Asterales","order_zh":"菊目","family_en":"Menyanthaceae","family_zh":"睡菜科","iucn":"LC","langs":62,"desc_zh":"睡菜属（学名：Menyanthes）是睡菜科下的一个属，为多年生、沼生草本植物。该属仅有睡菜（Menyanthes trifoliata）一种，其种加词“trifoliata”意为“三叶的”。分布于北温带，中国东北、西南及河北、浙江等地皆有繁殖。 睡菜又名暝菜，为多年生沼生草本植物。其花冠洁白可爱，美观，可进行盆栽，装点庭院。其茎部发达，亦可食用，味甘微苦，无毒，具有润肺、止咳、消肿等效果。食之使人好睡。","desc_en":"Menyanthes is a monotypic genus of flowering plants in the family Menyanthaceae containing the single species Menyanthes trifoliata. The North American form is often referred to as M. trifoliata var. minor Michx.","img":"images/1241.jpg","thumb":"images/t/1241.jpg","file":"(MHNT) Menyanthes trifoliata - Jardin Botanique Henri GAUSSEN.jpg","ar":0.762,"py":"shuicai sc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"],"illus_img":"images/i/1241.jpg","illus_thumb":"images/i/t/1241.jpg","illus_file":"Menyanthes trifoliata - Köhler–s Medizinal-Pflanzen-225.jpg","illus_ar":0.76,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":1242,"seq":892,"zh":"Roussea simplex","en":"Roussea simplex","sci":"Roussea simplex","order_en":"Asterales","order_zh":"菊目","family_en":"Rousseaceae","family_zh":"卢梭木科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Roussea simplex is a woody climber of 4–6 m high, that is endemic to the mountain forest of Mauritius. It is the only species of the genus Roussea, which is assigned to the family Rousseaceae.","img":"images/1242.jpg","thumb":"images/t/1242.jpg","file":"N230 w1150.jpg","ar":0.809,"py":"","cr_by":"Biodiversity Heritage Library","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"藤本","origin":null},{"id":1243,"seq":893,"zh":"Oreostylidium subulatum","en":"Oreostylidium subulatum","sci":"Oreostylidium subulatum","order_en":"Asterales","order_zh":"菊目","family_en":"Stylidiaceae","family_zh":"花柱草科","iucn":null,"langs":11,"desc_zh":null,"desc_en":"Oreostylidium is a genus of flowering plants in the family Stylidiaceae with a single species, Oreostylidium subulatum, that is endemic to New Zealand. O. subulatum is a very small plant with small, white flowers.","img":"images/1243.jpg","thumb":"images/t/1243.jpg","file":"Stylidium graminifolium flower spike.jpg","ar":1.501,"py":"","cr_by":"Mick Stanic from Melbourne, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["大洋洲"]},{"id":1244,"seq":894,"zh":"败酱","en":"Patrinia scabiosaefolia","sci":"Patrinia scabiosifolia","order_en":"Asterales","order_zh":"菊目","family_en":"Valerianaceae","family_zh":"败酱科","iucn":null,"langs":13,"desc_zh":"黄花败酱草（学名：Patrinia scabiosaefolia）为忍冬科败酱属的植物。","desc_en":"Patrinia scabiosifolia, the eastern valerian or golden lace, is a species of flowering plant in the family Caprifoliaceae. It is native to southeastern Siberia, Mongolia, the Russian Far East, most of China, Vietnam, Korea, Japan, and the Ryukyu Islands, and i…","img":"images/1244.jpg","thumb":"images/t/1244.jpg","file":"Patrinia scabiosifolia2.jpg","ar":0.743,"py":"baijiang bj","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":898,"seq":895,"zh":"沙甘松","en":"Eremosyne pectinata","sci":"Eremosyne pectinata","order_en":"Escalloniales","order_zh":"南鼠刺目","family_en":"Escalloniaceae","family_zh":"南鼠刺科","iucn":null,"langs":13,"desc_zh":"寄奴花（学名：Eremosyne pectinata）又名柔毛小花草、旱生草或漠茸草，是寄奴花属的唯一已知物种，属于南鼠刺目南鼠刺科，曾被归类为单型的寄奴花科（Eremosynaceae），只生长在澳大利亚的西南部，是当地的特有种。","desc_en":"Eremosyne pectinata, the sole species in the genus Eremosyne, is an annual herb endemic to the south coast of Western Australia.","img":"images/898.jpg","thumb":"images/t/898.jpg","file":"Eremosyne pectinata - Flickr - Kevin Thiele (1).jpg","ar":0.882,"py":"shagansong sgs","cr_by":"Kevin Thiele from Perth, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["大洋洲"]},{"id":899,"seq":896,"zh":"芫荽","en":"Coriandrum sativum","sci":"Coriandrum sativum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":130,"desc_zh":"芫（yán）荽（suī）（学名：Coriandrum sativum），又名胡荽、香菜、盐须、香茜、臭菜，广东等地为避衰讳也称芫（）茜（）。芫荽属一年生草本植物。在中东、地中海、印度、拉丁美洲、中国和东南亚的烹调中经常出现，亦可作药用。","desc_en":"Coriander (), or Coriandrum sativum, is an annual herb in the family Apiaceae. The leaves are known as cilantro () in the US. Most people perceive the leaves as having a fresh, slightly citrus taste.","img":"images/899.jpg","thumb":"images/t/899.jpg","file":"Coriandrum sativum - Köhler–s Medizinal-Pflanzen-193.jpg","ar":0.794,"py":"yansui ys","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"],"illus_img":"images/i/899.jpg","illus_thumb":"images/i/t/899.jpg","illus_file":"Coriandrum sativum - Köhler–s Medizinal-Pflanzen-193.jpg","illus_ar":0.794,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":900,"seq":897,"zh":"茴香","en":"Foeniculum vulgare","sci":"Foeniculum vulgare","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":123,"desc_zh":"茴香（学名：Foeniculum vulgare，英语：Fennel），也被称为甜茴香，汉药中的「小茴香」，古称蘹香。为伞形科茴香属的开花植物种。原产于地中海沿岸与东南亚的原生种，但目前已广泛被种植在世界许多地方，特别是在海岸附近干燥的土壤。","desc_en":"Fennel (Foeniculum vulgare) is a flowering plant species in the carrot family. It is a hardy, perennial herb with yellow flowers and feathery leaves. It is indigenous to the shores of the Mediterranean but has become widely naturalized in many parts of the wor…","img":"images/900.jpg","thumb":"images/t/900.jpg","file":"Fennel (Foeniculum vulgare) - Parc Natural de s'Albufera, Spain 2022-04-18 (02).jpg","ar":1.25,"py":"huixiang hx","cr_by":"Ryan Hodnett","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"],"illus_img":"images/i/900.jpg","illus_thumb":"images/i/t/900.jpg","illus_file":"Foeniculum vulgare - Köhler–s Medizinal-Pflanzen-148.jpg","illus_ar":0.801,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":901,"seq":898,"zh":"欧芹","en":"parsley","sci":"Petroselinum crispum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":118,"desc_zh":"欧芹（学名：Petroselinum crispum），别称香芹、巴西利、巴西里、洋香菜、洋芫荽、番芫荽、荷兰芹，是伞形科欧芹属的二年生草本植物，原产地中海沿岸，为常见蔬菜和香草，具有清爽的香味和鲜绿色。古罗马时代起用于烹调，也是世界上用的最广的一种香草。对地质和气候的适应性高，栽培也容易，故世界各地都有栽培，但对干燥的适应性差。","desc_en":"Parsley, or garden parsley (Petroselinum crispum), is a species of flowering plant in the family Apiaceae that is native to Greece, the Balkans, Algeria and Morocco.","img":"images/901.jpg","thumb":"images/t/901.jpg","file":"Petroselinum crispum - Köhler–s Medizinal-Pflanzen-103.jpg","ar":0.697,"py":"ouqin oq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"],"illus_img":"images/i/901.jpg","illus_thumb":"images/i/t/901.jpg","illus_file":"Petroselinum crispum - Köhler–s Medizinal-Pflanzen-103.jpg","illus_ar":0.697,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":902,"seq":899,"zh":"莳萝","en":"Anethum graveolens","sci":"Anethum graveolens","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":112,"desc_zh":"莳（shí）萝（学名：Anethum graveolens，英语：dill），是伞形科莳萝属中唯一的一种植物，为一年生草本植物，原生于西亚，后西传至地中海沿岸及欧洲各地，现今地中海和东欧为主要的生产地，外形类似茴香，高度约为一至四英呎高，黄色小花呈伞状分布，叶为针状分针。台湾话称为「茴香仔」。","desc_en":"Dill (Anethum graveolens) is an annual herb in the celery family Apiaceae. Native to North Africa and West Asia, dill is grown widely in Eurasia, where its leaves and seeds are used as a herb or spice for flavouring food.","img":"images/902.jpg","thumb":"images/t/902.jpg","file":"Anethum graveolens 02.jpg","ar":0.75,"py":"shiluo sl","cr_by":"Tepeyac","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","非洲"],"illus_img":"images/i/902.jpg","illus_thumb":"images/i/t/902.jpg","illus_file":"Anethum graveolens Sturm12023.jpg","illus_ar":0.667,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":903,"seq":900,"zh":"茴芹","en":"Pimpinella anisum","sci":"Pimpinella anisum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":107,"desc_zh":"茴芹（学名：Pimpinella anisum，英语：Anise，Aniseed），又称作西洋茴香、洋茴香、欧洲大茴香，是原产于埃及和地中海东部的一种伞形科植物，有着带甜味的果实和类似甘草和茴香的香味，故常用于用于提炼精油、制造糖果和酿酒，也有一定的药用价值，自古便受到珍视。","desc_en":"Anise (; Pimpinella anisum), also called aniseed or rarely anix, is a flowering plant in the family Apiaceae native to the eastern Mediterranean region and Southwest Asia.","img":"images/903.jpg","thumb":"images/t/903.jpg","file":"Koehler1887-PimpinellaAnisum.jpg","ar":0.88,"py":"huiqin hq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"],"illus_img":"images/i/903.jpg","illus_thumb":"images/i/t/903.jpg","illus_file":"Pimpinella anisum - Köhler–s Medizinal-Pflanzen-240.jpg","illus_ar":0.823,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":904,"seq":901,"zh":"葛缕子","en":"Carum carvi","sci":"Carum carvi","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":106,"desc_zh":"葛缕子，伞形科两年生草本植物，原产于欧洲和西亚。其果实是一种香料，可用于烹调，也可以入药。","desc_en":"Caraway (Carum carvi), also known as meridian fennel, is a biennial plant in the family Apiaceae, native to western Asia, Europe, and North Africa.","img":"images/904.jpg","thumb":"images/t/904.jpg","file":"Carum carvi - Köhler–s Medizinal-Pflanzen-172.jpg","ar":0.839,"py":"gelzi glz","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/904.jpg","illus_thumb":"images/i/t/904.jpg","illus_file":"Carum carvi - Köhler–s Medizinal-Pflanzen-172.jpg","illus_ar":0.839,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":905,"seq":902,"zh":"孜然","en":"Cuminum cyminum","sci":"Cuminum cyminum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":105,"desc_zh":"孜然芹（学名：Cuminum cyminum），又名香旱芹，其果实作为香料时简称孜然（英语：cumin），又称阿拉伯茴香、安息茴香、枯茗，伞形科孜然芹属一年生草本植物。原产自中东至南亚一带。 孜然历史悠久。它主要用于调味、提取香精油等，是料理食品常用的上等佐料，口感风味独特且富有油性，气味芳香而浓烈，也是配制咖哩的主要原料之一。","desc_en":"Cumin ( , ; US also ; Cuminum cyminum) is a flowering plant in the family Apiaceae, native to the Irano-Turanian Region. Its seeds – each one contained within a fruit, which is dried – are used in the cuisines of many cultures in both whole and ground form.","img":"images/905.jpg","thumb":"images/t/905.jpg","file":"Cuminum cyminum - Köhler–s Medizinal-Pflanzen-198.jpg","ar":0.757,"py":"ziran zr","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null,"illus_img":"images/i/905.jpg","illus_thumb":"images/i/t/905.jpg","illus_file":"Cuminum cyminum - Köhler–s Medizinal-Pflanzen-198.jpg","illus_ar":0.757,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":906,"seq":903,"zh":"野胡萝卜","en":"Daucus carota","sci":"Daucus carota","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":"LC","langs":88,"desc_zh":"野胡萝卜（学名：Daucus carota），英文另叫（Queen Anne's lace）,为二年生草本植物。主根长，茎的上面有毛，叶为分裂状。花序为散形花序，花的颜色有淡紫色和白色。花心的颜色是紫色，花苞的苞片全裂。其中亚种“Daucus carota subsp. sativus”由于其根部富含胡萝卜素和维生素C，可用来提取咖啡代用品、糖浆和橙色染料。种子可以用来治疗宿醉，精油可以用来调制香水和利口酒。","desc_en":"Daucus carota, whose common names include wild carrot, European wild carrot, bird's nest, bishop's lace, carrot flower, and Queen Anne's lace (North America), is a flowering plant in the family Apiaceae.","img":"images/906.jpg","thumb":"images/t/906.jpg","file":"Daucus carota.jpg","ar":0.75,"py":"yehuluobo yhlb","cr_by":"User:Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null,"illus_img":"images/i/906.jpg","illus_thumb":"images/i/t/906.jpg","illus_file":"Illustration Daucus carota0.jpg","illus_ar":0.62,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":910,"seq":904,"zh":"常春藤","en":"Hedera helix","sci":"Hedera helix","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":null,"langs":75,"desc_zh":"洋常春藤（学名：Hedera helix），又名常春藤、长春藤、土鼓藤、木茑、百角蜈蚣，是常春藤属下的一种常绿攀援植物，在很多地区洋常春藤实际都属于入侵物种。","desc_en":"Hedera helix, simply ivy, or common ivy, English ivy, European ivy, King's choice ivy, is a species of flowering plant in the family Araliaceae. It is native to most of Europe and parts of western Asia.","img":"images/910.jpg","thumb":"images/t/910.jpg","file":"20121002Hedera helix1.jpg","ar":1.333,"py":"changchunteng cct","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"藤本","origin":["亚洲","欧洲"],"illus_img":"images/i/910.jpg","illus_thumb":"images/i/t/910.jpg","illus_file":"Illustration Hedera helix0 correct.jpg","illus_ar":0.6,"illus_by":"kenraiz","illus_lic":"Public domain","illus_licurl":null},{"id":911,"seq":905,"zh":"高丽参","en":"Panax ginseng","sci":"Panax ginseng","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":null,"langs":46,"desc_zh":"人参（学名：Panax ginseng）又称为人参、亚洲参、红参、生晒参、山晒山参、石柱参、朝鲜参、野山参、人衔、鬼盖、土精、神草，中国东北地区土名棒槌，是五加科人参属的一种，具有肉质的根，可药用，主要生长在东亚，特别是寒冷地区。 尽管人参已在传统医学中使用了多个世纪，现代临床研究对其仍有讨论。人参是亚洲常见药材，北中美洲也普遍使用花旗参(西洋参)，许多草药铺和超市都能找到各式人参饮片及萃取物保健产品。","desc_en":"Panax ginseng, ginseng, also known as Asian ginseng, Chinese ginseng or Korean ginseng, is a species of plant whose root is the original source of ginseng. It is a perennial plant that grows in the mountains of East Asia.","img":"images/911.jpg","thumb":"images/t/911.jpg","file":"Ginsengpflanze.jpg","ar":1,"py":"gaolishen gls","cr_by":"FloraFarm GmbH / Katharina Lohrie","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["亚洲"]},{"id":912,"seq":906,"zh":"野天胡荽","en":"Hydrocotyle vulgaris","sci":"Hydrocotyle vulgaris","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":"LC","langs":36,"desc_zh":"野天胡荽（学名：Hydrocotyle vulgaris）为五加科天胡荽属下的一个种。也可称为铜钱草、金钱草、钱币草、圆币草、少脉香菇草、香菇钱、盾叶天胡荽等，外观与南美天胡荽（Hydrocotyle verticillata）非常相近。","desc_en":"Hydrocotyle vulgaris, the marsh pennywort, common pennywort, water naval, money plant, lucky plant, dollarweed or copper coin, is a small creeping aquatic perennial plant native to North Africa, Europe, the Caucasus and parts of the Levant.","img":"images/912.jpg","thumb":"images/t/912.jpg","file":"HydrocotyleVulgaris.jpg","ar":1.449,"py":"yetianhusui yths","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/912.jpg","illus_thumb":"images/i/t/912.jpg","illus_file":"Hydrocotyle vulgaris — Flora Batava — Volume v1.jpg","illus_ar":0.759,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":913,"seq":907,"zh":"刺五加","en":"Eleutherococcus senticosus","sci":"Eleutherococcus senticosus","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":null,"langs":36,"desc_zh":"刺五加（学名：Eleutherococcus senticosus），五加科五加属的一种落叶灌木，又名五加参、俄国参、老虎参、西伯利亚人参，主要分布于亚洲东北部，西伯利亚一带。其根部和根状茎可入药，其主要成分有刺五加苷、新五加苷等。1950年代苏联学者曾对刺五加及刺五加苷进行过一系列研究，并开发了刺五加提取物制成的产品。具有清热解毒、镇痛止痒、消炎杀菌等功效，是中医常用的药材之一。","desc_en":"Eleutherococcus senticosus is a species of small, woody shrub in the family Araliaceae. It is native to Northeastern Asia. It may be colloquially called devil's bush, Siberian ginseng, taiga root, eleuthero, ciwujia, Devil's shrub, shigoka, touch-me-not, wild…","img":"images/913.jpg","thumb":"images/t/913.jpg","file":"Eleutherococcus senticosus.jpg","ar":0.972,"py":"ciwujia cwj","cr_by":"Stanislav Doronenko","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"灌木","origin":["亚洲"]},{"id":1245,"seq":908,"zh":"Delarbrea michieana","en":"Delarbrea michieana","sci":"Delarbrea michieana","order_en":"Apiales","order_zh":"伞形目","family_en":"Myodocarpaceae","family_zh":"裂果红科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Delarbrea michieana, the blue nun, is a species of flowering plant of family Myodocarpaceae. A widespread shrub or small tree, it is found in rainforest between Tully and Cooktown in tropical Queensland, Australia.","img":"images/1245.jpg","thumb":"images/t/1245.jpg","file":"Delarbrea michieana 180766881.jpg","ar":0.75,"py":"","cr_by":"Matthew Borella","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"灌木","origin":["大洋洲"]},{"id":1246,"seq":909,"zh":"三王凯科玛寇木","en":"Pennantia baylisiana","sci":"Pennantia baylisiana","order_en":"Apiales","order_zh":"伞形目","family_en":"Pennantiaceae","family_zh":"彭南特氏木科","iucn":"CR","langs":13,"desc_zh":null,"desc_en":"Pennantia baylisiana, commonly known as Three Kings kaikōmako or kaikōmako manawatāwhi (Māori), is a species of plant in the family Pennantiaceae (Icacinaceae in older classifications).","img":"images/1246.jpg","thumb":"images/t/1246.jpg","file":"Pennantia baylisiana MRD.jpg","ar":0.976,"py":"sanwangkaikemakoumu swkkmkm","cr_by":"Mike Dickison","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":["非洲","大洋洲"]},{"id":1247,"seq":910,"zh":"海桐","en":"Pittosporum tobira","sci":"Pittosporum tobira","order_en":"Apiales","order_zh":"伞形目","family_en":"Pittosporaceae","family_zh":"海桐科","iucn":null,"langs":29,"desc_zh":"海桐（学名：Pittosporum tobira），海桐科海桐属植物，又名海桐花。","desc_en":"Pittosporum tobira is a species of sweet-smelling flowering plant in the pittosporum family Pittosporaceae known by several common names, including Australian laurel, Japanese pittosporum, mock orange and Japanese cheesewood.","img":"images/1247.jpg","thumb":"images/t/1247.jpg","file":"Pittosporum Tobira JPG0.jpg","ar":1.502,"py":"haitong ht","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲"]},{"id":915,"seq":911,"zh":"缬草","en":"Valeriana officinalis","sci":"Valeriana officinalis","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":78,"desc_zh":"缬草（学名：Valeriana officinalis）是一种多年生耐寒开花植物，在北半球每年6月至9月是其花期，会开出芬芳的白色或粉红色花朵。当花朵被放在花瓶里时，其散发出来的香味因过于浓烈，会令人难以忍受。 缬草原产于亚洲部分地区和欧洲，现在已被栽培到北美洲。其茎叶被一些鳞翅目物种（蝴蝶及蛾）的幼虫当作食物。 缬草在药理学和本草疗法中是一种草药，其根部作为膳食补充剂使用。","desc_en":"Valerian (Valeriana officinalis) is an herbaceous perennial flowering plant in the family Caprifoliaceae, native to Europe and southwestern Asia. It is the type species of the genus Valeriana.","img":"images/915.jpg","thumb":"images/t/915.jpg","file":"Valeriana officinalis - Niitvälja.jpg","ar":0.714,"py":"xiecao xc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"],"illus_img":"images/i/915.jpg","illus_thumb":"images/i/t/915.jpg","illus_file":"Valeriana officinalis - Köhler–s Medizinal-Pflanzen-143.jpg","illus_ar":0.764,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":916,"seq":912,"zh":"莴苣缬草","en":"corn salad","sci":"Valerianella locusta","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":50,"desc_zh":"莴苣缬草（学名：Valerianella locusta），又名野苣、羊莴苣，是败酱科新缬草属的一种双子叶一年生或二年生植物，原产于欧洲、北非及西亚。","desc_en":"Valeriana locusta, commonly called mâche, cornsalad, or lamb's lettuce, a small, herbaceous, annual flowering plant in the honeysuckle family Caprifoliaceae. It is native to Europe, western Asia and north Africa, where it is eaten as a leaf vegetable.","img":"images/916.jpg","thumb":"images/t/916.jpg","file":"(MHNT) Valerianella locusta - inflorescences and Leaf.jpg","ar":1.203,"py":"wojuxiecao wjxc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/916.jpg","illus_thumb":"images/i/t/916.jpg","illus_file":"Valerianella locusta drawing.jpg","illus_ar":0.667,"illus_by":"USDA-NRCS PLANTS Database / Britton, N.L., and A. Brown. 1913. Illustrated flora of the northern states and Canada. Vol.","illus_lic":"Public domain","illus_licurl":null},{"id":917,"seq":913,"zh":"田野孀草","en":"field scabious","sci":"Knautia arvensis","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":49,"desc_zh":"田野孀草（学名：Knautia arvensis）是忍冬科孀草属的一种多年生草本植物。","desc_en":"Knautia arvensis, commonly known as field scabious, is a herbaceous perennial species of flowering plant in the honeysuckle family Caprifoliaceae.","img":"images/917.jpg","thumb":"images/t/917.jpg","file":"Knautia arvensis flower (side view) - Keila.jpg","ar":0.667,"py":"tianyeshuangcao tysc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null,"illus_img":"images/i/917.jpg","illus_thumb":"images/i/t/917.jpg","illus_file":"Knautia arvensis Sturm2.jpg","illus_ar":0.675,"illus_by":"Johann Georg Sturm (Painter: Jacob Sturm )","illus_lic":"Public domain","illus_licurl":null},{"id":918,"seq":914,"zh":"羊叶忍冬","en":"Lonicera caprifolium","sci":"Lonicera caprifolium","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":44,"desc_zh":null,"desc_en":"Lonicera caprifolium, the Italian woodbine, perfoliate honeysuckle, goat-leaf honeysuckle, Italian honeysuckle, or perfoliate woodbine, is a species of perennial flowering plants in the genus Lonicera of the family Caprifoliaceae.","img":"images/918.jpg","thumb":"images/t/918.jpg","file":"Dettaglio - Caprifoliaceae Lonicera caprifolium Lin. Erbario Frizzi Perugia n. 3641.jpg","ar":0.734,"py":"yangyerendong yyrd","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲","北美洲"],"illus_img":"images/i/918.jpg","illus_thumb":"images/i/t/918.jpg","illus_file":"Illustration Lonicera caprifolium0.jpg","illus_ar":0.606,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":919,"seq":915,"zh":"金银花","en":"Lonicera japonica","sci":"Lonicera japonica","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":41,"desc_zh":"忍冬（学名：Lonicera japonica），是忍冬科的一种植物，花称为金银花、也叫忍冬藤、金银藤､ 密银花､ 东银花､ 小山花､ 忍冬草､ 鸳鸯草、双花、毛金银花、二宝花、双宝花､ 二花。 “金银花”一名始载于宋代《苏沈内翰良方》，金银花指的是忍冬花朵因成熟度不同由白变黄的特性。而“忍冬”则得名于植物冬天不枯萎的特点。由于忍冬花初开为白色，后转为黄色，因此得名金银花。花芬芳，果实为黑色球形的浆果，直径是3—4毫米（0.12—0.","desc_en":"Lonicera japonica, known as Japanese honeysuckle and golden-and-silver honeysuckle, is a species of honeysuckle native to East Asia, including many parts of China.","img":"images/919.jpg","thumb":"images/t/919.jpg","file":"Honeysuckle 2.jpg","ar":0.75,"py":"jinyinhua jyh","cr_by":"William Rafti of the William Rafti Institute, aka Rafti Institute at en.wikipedia . Original watermark removed by Ms. ha","cr_lic":"Attribution","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":921,"seq":916,"zh":"欧洲荚蒾","en":"Viburnum opulus","sci":"Viburnum opulus","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Adoxaceae","family_zh":"五福花科","iucn":null,"langs":68,"desc_zh":"欧洲荚蒾（学名：Viburnum opulus，别名欧洲琼花、欧洲雪球）为五福花科荚蒾属的一种落叶灌木，高4—5米（13—16英尺），原产于欧洲、北非和中亚，后来作为观赏植物引入世界其他地区。","desc_en":"Viburnum opulus, commonly known as the guelder-rose, or guelder rose (), is an Old World species of flowering plant in the family Adoxaceae.","img":"images/921.jpg","thumb":"images/t/921.jpg","file":"Viburnum opulus bunched.jpg","ar":1.501,"py":"ouzhoujiami ozjm","cr_by":"Waitblock","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null,"illus_img":"images/i/921.jpg","illus_thumb":"images/i/t/921.jpg","illus_file":"Viburnum opulus Sturm.jpg","illus_ar":0.695,"illus_by":"Gotthilf Heinrich von Schubert File:Naturgeschichte des Pflanzenreichs Tafel XVI.jpg : Аимаина хикари","illus_lic":"Public domain","illus_licurl":null},{"id":922,"seq":917,"zh":"黑果绣球","en":"Viburnum lantana","sci":"Viburnum lantana","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Adoxaceae","family_zh":"五福花科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Viburnum lantana, the wayfarer or wayfaring tree, is a species of Viburnum, native to central, southern and western Europe (north to Yorkshire in England), northwest Africa, and southwestern Asia.","img":"images/922.jpg","thumb":"images/t/922.jpg","file":"Viburnum lantana a1.jpg","ar":1.336,"py":"heiguoxiuqiu hgxq","cr_by":"Opioła Jerzy","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"灌木","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/922.jpg","illus_thumb":"images/i/t/922.jpg","illus_file":"Viburnum lantana — Flora Batava — Volume v16.jpg","illus_ar":0.807,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1248,"seq":918,"zh":"地中海荚蒾","en":"Viburnum tinus","sci":"Viburnum tinus","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Adoxaceae","family_zh":"五福花科","iucn":"LC","langs":35,"desc_zh":null,"desc_en":"Viburnum tinus, the laurustinus or laurustine, is a species of flowering plant in the family Viburnaceae, native to the Mediterranean area of Europe and North Africa.","img":"images/1248.jpg","thumb":"images/t/1248.jpg","file":"Dettaglio - Caprifoliaceae Viburnum tinus Lin. Erbario Frizzi Perugia n. 1221.jpg","ar":0.75,"py":"dizhonghaijiami dzhjm","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲","非洲"],"illus_img":"images/i/1248.jpg","illus_thumb":"images/i/t/1248.jpg","illus_file":"T2 37 Viburnum tinus par Pierre-Joseph Redouté.jpeg","illus_ar":0.713,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":1249,"seq":919,"zh":"北极花","en":"Linnaea borealis","sci":"Linnaea borealis","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Linnaeaceae","family_zh":"北极花科","iucn":null,"langs":40,"desc_zh":"北极花（学名：Linnaea borealis）为忍冬科北极花属的植物。生长于海拔750米至2,300米的地区，一般生于树干、针叶林下以及长满苔藓的岩石上，目前尚未由人工引种栽培。","desc_en":"Linnaea borealis is a species of flowering plant in the family Caprifoliaceae (the honeysuckle family). It is the only species in the genus Linnaea. It is a boreal to subarctic woodland subshrub, commonly known as twinflower (sometimes written twin flower).","img":"images/1249.jpg","thumb":"images/t/1249.jpg","file":"Linnaea borealis 8803.JPG","ar":1.501,"py":"beijihua bjh","cr_by":"Walter Siegmund (talk)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":null,"illus_img":"images/i/1249.jpg","illus_thumb":"images/i/t/1249.jpg","illus_file":"Illustration Linnaea borealis1.jpg","illus_ar":0.579,"illus_by":"Prof. Dr. Otto Wilhelm Thomé Flora von Deutschland, Österreich und der Schweiz 1885, Gera, Germany","illus_lic":"Public domain","illus_licurl":null},{"id":1250,"seq":920,"zh":"西洋接骨木","en":"Sambucus nigra","sci":"Sambucus nigra","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Viburnaceae","family_zh":"荚蒾科","iucn":"LC","langs":82,"desc_zh":"西洋接骨木（学名：Sambucus nigra）为五福花科接骨木属的植物。原产于欧洲和北美洲，后来人工引种到世界其他地区。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Sambucus nigra is a temperate species of tree or shrub in the family Viburnaceae native to the Azores, Europe, and the Middle East. Common names include elder, elderberry, black elder, European elder, European elderberry, and European black elderberry.","img":"images/1250.jpg","thumb":"images/t/1250.jpg","file":"Sambucus nigra 004.jpg","ar":1.333,"py":"xiyangjiegumu xyjgm","cr_by":"Willow","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","欧洲"],"illus_img":"images/i/1250.jpg","illus_thumb":"images/i/t/1250.jpg","illus_file":"Sambucus nigra - Köhler–s Medizinal-Pflanzen-127.jpg","illus_ar":0.809,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":923,"seq":921,"zh":"苏铁","en":"Cycas revoluta","sci":"Cycas revoluta","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"LC","langs":48,"desc_zh":"苏铁（学名：Cycas revoluta），又名琉球苏铁，同物异名台东苏铁，俗称铁树、凤尾蕉、凤尾松、避火树，属于苏铁科苏铁属的一种植物。","desc_en":"Cycas revoluta (Sotetsu [Japanese ソテツ], sago cycad, sago palm, king sago, Japanese sago palm) is a species of gymnosperm in the family Cycadaceae, native to southern Japan including the Ryukyu Islands.","img":"images/923.jpg","thumb":"images/t/923.jpg","file":"Cycas inflorescence.jpg","ar":0.75,"py":"sutie st","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":924,"seq":922,"zh":"拳叶苏铁","en":"Cycas circinalis","sci":"Cycas circinalis","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"EN","langs":24,"desc_zh":null,"desc_en":"Cycas circinalis, also known as the queen sago, is a species of cycad known in the wild only from southern India. Cycas circinalis is the only gymnosperm species found among native Sri Lankan flora.","img":"images/924.jpg","thumb":"images/t/924.jpg","file":"Cycas Circinalis - 200 Years Old in Prague - DSC 0068.jpg","ar":0.669,"py":"quanyesutie qyst","cr_by":"myself","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":925,"seq":923,"zh":"华南苏铁","en":"Cycas rumphii","sci":"Cycas rumphii","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"NT","langs":22,"desc_zh":"华南苏铁（学名：Cycas rumphii）为苏铁科苏铁属的植物。分布于印度尼西亚、新几内亚和圣诞岛，多生长于山坡杂木林中，目前尚未由人工引种栽培。","desc_en":"Cycas rumphii, commonly known as queen sago or the queen sago palm, is a dioecious gymnosperm, a species of cycad in the genus Cycas native to Indonesia, New Guinea and Christmas Island. Although palm-like in appearance, it is not a palm.","img":"images/925.jpg","thumb":"images/t/925.jpg","file":"Cycas rumphii-IMG 9702.JPG","ar":1.501,"py":"huanansutie hnst","cr_by":"C T Johansson","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","大洋洲"]},{"id":927,"seq":924,"zh":"伍德苏铁","en":"Encephalartos woodii","sci":"Encephalartos woodii","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"EW","langs":24,"desc_zh":"伍德苏铁（学名Encephalartos woodii）是南非夸祖鲁-纳塔尔省特有的苏铁。它们是世界最稀有的植物之一，现已从野外灭绝，所有现存标本都是模式标本的克隆。 其学名为纪念发现此植物的德班植物园（Durban Botanic Garden）的约翰·梅德利·伍德。","desc_en":"Encephalartos woodii, Wood's cycad, is a rare cycad in the genus Encephalartos, and is endemic to the oNgoye Forest of KwaZulu-Natal, South Africa. It is one of the rarest plants in the world, being extinct in the wild with all specimens being clones of the ty…","img":"images/927.jpg","thumb":"images/t/927.jpg","file":"Encephalartos woodii original stem Durban Botanic Gardens 04 09 2010.JPG","ar":0.75,"py":"wudesutie wdst","cr_by":"Purves, M.","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"]},{"id":928,"seq":925,"zh":"双子苏铁","en":"Dioon edule","sci":"Dioon edule","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"NT","langs":20,"desc_zh":null,"desc_en":"Dioon edule, the chestnut dioon, is a cycad native to Mexico, also known as palma de la virgen. Cycads are among the oldest seed plants and even pre-date the dinosaurs. It belongs to the Zamiaceae plant family within the order Cycadales.","img":"images/928.jpg","thumb":"images/t/928.jpg","file":"Dioon edule05.jpg","ar":1.333,"py":"shuangzisutie szst","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["北美洲"]},{"id":929,"seq":926,"zh":"粉叶非洲铁","en":"Encephalartos horridus","sci":"Encephalartos horridus","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"EN","langs":19,"desc_zh":null,"desc_en":"Encephalartos horridus, commonly known as the Eastern Cape blue cycad, is a small, low-growing cycad up to 0.9 m (3.0 ft) high and 0.9 m (3.0 ft) wide. It is a native of Eastern Cape Province, South Africa, and found in arid shrublands, most commonly on ridges…","img":"images/929.jpg","thumb":"images/t/929.jpg","file":"Encephalartos horridus 03.jpg","ar":1.333,"py":"fenyefeizhoutie fyfzt","cr_by":"A. Barra","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":931,"seq":927,"zh":"银杏","en":"Ginkgo biloba","sci":"Ginkgo biloba","order_en":"Ginkgoales","order_zh":"银杏目","family_en":"Ginkgoaceae","family_zh":"银杏科","iucn":"EN","langs":95,"desc_zh":"银杏（学名：Ginkgo biloba），落叶乔木，寿命可达3000年以上。又名公孙树、鸭掌树、鸭脚树、鸭脚子等，其裸露的种子称为白果，叶称蒲扇。属裸子植物银杏门惟一现存物种，和它同门的其他所有物种都已灭绝，因此被称为植物界的“活化石”。已发现的化石可以追溯到2.7亿年前。银杏原产于中国，现广泛种植于全世界，常作为道路景观树种，并被早期引入人类历史。它有多种用途，可作为传统医学用途和食材。","desc_en":"Ginkgo biloba, commonly known as ginkgo ( GINK-oh, -⁠goh), also known as the maidenhair tree, and often misspelled \"gingko\" (see Taxonomy below) is a species of gymnosperm tree native to East Asia.","img":"images/931.jpg","thumb":"images/t/931.jpg","file":"GINKGOBAUM-2.jpg","ar":0.727,"py":"yinxing yx","cr_by":"EecherplazGinkgo06.jpg : Cayambe derivative work: Ginkgotree ( talk )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":932,"seq":928,"zh":"欧洲赤松","en":"Pinus sylvestris","sci":"Pinus sylvestris","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":88,"desc_zh":"欧洲赤松（学名：Pinus sylvestris）是一种分布在西起大不列颠和伊比利亚半岛，东至东西伯利亚及高加索山脉，北达拉普兰之间，广大范围的树种。在北部，其生长高度为海平面至海拔1000公尺，在南方则以高山植物方式呈现 (1200-2500公尺)。 在英伦三岛中，目前只有苏格兰有原生的欧洲赤松，但最晚到三、四百年前，在英格兰、爱尔兰和威尔斯仍然能发现其踪影—后者由于伐木过度而消失，但近年又重新引进回来。","desc_en":"Pinus sylvestris is a species of tree in the pine family Pinaceae that is native to Eurasia. It is commonly known as the Scots pine in English; it is also known as the Scotch pine in the United States, and occasionally called the Baltic pine or European red pi…","img":"images/932.jpg","thumb":"images/t/932.jpg","file":"Pinus sylvestris Glenmuick.jpg","ar":0.77,"py":"ouzhouchisong ozcs","cr_by":"Hello, I am Bruce on Flickr","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["亚洲"],"illus_img":"images/i/932.jpg","illus_thumb":"images/i/t/932.jpg","illus_file":"Pinus sylvestris - Köhler–s Medizinal-Pflanzen-106.jpg","illus_ar":0.793,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":933,"seq":929,"zh":"欧洲云杉","en":"Picea abies","sci":"Picea abies","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":81,"desc_zh":"欧洲云杉（学名：Picea abies；英语：Norway spruce、European spruce），或译作挪威云杉，是一种大型常绿针叶树，高达35-55公尺，树干直径可达 1-1.5 公尺。2008年，一株由瑞典于默奥大学科学家在瑞典达拉纳省境内的欧洲云杉Old Tjikko经碳-14定年法后核实其树龄高达9550岁，打破了一直以来在美国加利福尼亚州白山找到的一株刺果松4700岁的纪录足足一倍有多，所以是目前世界上已知寿命最长的…","desc_en":"Picea abies, the Norway spruce, Norway fir or European spruce, is a species of spruce native to Northern, Central and Eastern Europe. It has branchlets that typically hang downwards, and the longest cones of any spruce, 9–17 cm long.","img":"images/933.jpg","thumb":"images/t/933.jpg","file":"Kuusk Keila-Paldiski rdt ääres.jpg","ar":0.667,"py":"ouzhouyunshan ozys","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0 ee","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/ee/deed.en","habit":"针叶树","origin":["欧洲"],"illus_img":"images/i/933.jpg","illus_thumb":"images/i/t/933.jpg","illus_file":"Picea abies - Köhler–s Medizinal-Pflanzen-105.jpg","illus_ar":0.761,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":934,"seq":930,"zh":"银冷杉","en":"Abies alba","sci":"Abies alba","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":72,"desc_zh":"银冷杉（学名：Abies alba）为松科冷杉属的一种植物，又称欧洲银冷杉，欧洲冷杉，圣诞树。其种加词“alba”意为“白色的”。其外型呈现漂亮的绿色金字塔状，带略白色的枝枒，常被联想为传统的圣诞树；生于欧洲山区的原生植物，为常绿的松科植物，成树高50至60米，树干直径阔1.5米，树叶为针状，呈墨绿色。","desc_en":"Abies alba, the European silver fir or silver fir, is a fir native to the mountains of Europe, from the Pyrenees north to Normandy, east to the Alps and the Carpathians, Slovakia, Slovenia, Croatia, Bosnia and Herzegovina, Montenegro, Serbia, and south to Ital…","img":"images/934.jpg","thumb":"images/t/934.jpg","file":"Abies alba - Köhler–s Medizinal-Pflanzen-001.jpg","ar":0.783,"py":"yinlengshan yls","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"针叶树","origin":["欧洲"],"illus_img":"images/i/934.jpg","illus_thumb":"images/i/t/934.jpg","illus_file":"Abies alba (Köhler).jpg","illus_ar":0.771,"illus_by":"Franz Eugen Köhler","illus_lic":"Public domain","illus_licurl":null},{"id":935,"seq":931,"zh":"黎巴嫩雪松","en":"Cedrus libani","sci":"Cedrus libani","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"VU","langs":69,"desc_zh":"黎巴嫩雪松（学名：Cedrus libani）是东地中海盆地山区的本土雪松。它是常绿针叶树，可长至40米高。黎巴嫩雪松也是黎巴嫩的国家象征，在该国国旗上可以看见其图案。其在公园、花园等地广泛种植，用作观赏植物。","desc_en":"Cedrus libani, commonly known as cedar of Lebanon, Lebanon cedar, or Lebanese cedar (Arabic: أرز لبناني, romanized: ʾarz lubnāniyy), is a species of large evergreen conifer in the genus Cedrus, which belongs to the pine family and is native to the mountains of…","img":"images/935.jpg","thumb":"images/t/935.jpg","file":"Cèdre du Liban Barouk 2005.jpg","ar":1.333,"py":"libanenxuesong lbnxs","cr_by":"Olivier BEZES","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"针叶树","origin":["欧洲"]},{"id":936,"seq":932,"zh":"喜马拉雅雪松","en":"Cedrus deodara","sci":"Cedrus deodara","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":67,"desc_zh":"喜马拉雅雪松（学名：Cedrus deodara）是雪松的一个物种，为阿富汗东部、巴基斯坦北部（特别是在开伯尔-普赫图赫瓦省境内）、印度（查谟-克什米尔邦、喜马偕尔邦、锡金、大吉岭、北阿坎德邦）、西藏地区西南端以及尼泊尔西部的本土植物，通常出现在海拔1,500—3,200米（4,921—10,499英尺）的地方。","desc_en":"Cedrus deodara, the deodar cedar, Himalayan cedar, or deodar, is a species of cedar native to the Himalayas.","img":"images/936.jpg","thumb":"images/t/936.jpg","file":"Cedrus deodara Manali 2.jpg","ar":0.75,"py":"ximalayaxuesong xmlyxs","cr_by":"Paul Evans from London, United Kingdom","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"针叶树","origin":["亚洲"]},{"id":937,"seq":933,"zh":"意大利笠松","en":"Pinus pinea","sci":"Pinus pinea","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":62,"desc_zh":"笠松（学名：Pinus pinea），也被称为意大利石松、意大利伞松、意大利五针松。原产于地中海地区，分布在南欧，北非和地中海东部。笠松自史前时代已被用于种植食用松子。现代作为观赏树，在世界各地普遍种植在花园和公园。","desc_en":"Pinus pinea, the Italian stone pine or Mediterranean stone pine, is a tree from the pine family, Pinaceae. The tree is native to the Mediterranean region, occurring in Southern Europe and the Levant.","img":"images/937.jpg","thumb":"images/t/937.jpg","file":"Pinus pinea and ruins on Palatine Hill.jpg","ar":0.706,"py":"yidalilisong ydlls","cr_by":"Livioandronico2013","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["亚洲","欧洲"],"illus_img":"images/i/937.jpg","illus_thumb":"images/i/t/937.jpg","illus_file":"Pinus pinea foliage illustration.jpg","illus_ar":1.451,"illus_by":"C.Giordano/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":938,"seq":934,"zh":"欧洲落叶松","en":"Larix decidua","sci":"Larix decidua","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":61,"desc_zh":"欧洲落叶松（Larix decidua）是落叶松属下的一个物种，主要分布在欧洲中部的阿尔卑斯山脉和喀尔巴阡山脉。 欧洲落叶松是一种中型到大型的落叶松柏目树木，高度为25-45米，直径可达1米。幼年期树冠为圆锥形，随着树龄增长，渐渐变得宽阔。主干向上，支干通常下垂，枝平展，树冠呈不规则塔形；小枝平展，枝稍多少上升。树叶为针状，浅绿色，2-4厘米长，秋季变成黄色落下。","desc_en":"Larix decidua, the European larch, is a species of larch native to the mountains of central Europe, in the Alps and Carpathian Mountains, with small disjunct lowland populations in northern Poland.","img":"images/938.jpg","thumb":"images/t/938.jpg","file":"2014-07-03 Larix decidua cone & foliage, Valle di Cogne, Italian Alps.jpg","ar":1.501,"py":"ouzhouluoyesong ozlys","cr_by":"Fulvio Spada from Torino, Italy","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["欧洲"],"illus_img":"images/i/938.jpg","illus_thumb":"images/i/t/938.jpg","illus_file":"Larix decidua - Köhler–s Medizinal-Pflanzen-216.jpg","illus_ar":0.822,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":939,"seq":935,"zh":"欧洲黑松","en":"Pinus nigra","sci":"Pinus nigra","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":58,"desc_zh":"欧洲黑松（学名：Pinus nigra）为松科松属的植物。幼皮暗灰色，老则呈灰褐色，裂成鳞状厚片脱落。分布在小亚细亚半岛、欧洲等地，属中国原产的植物（非从国外引种）。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Pinus nigra, the Austrian pine or black pine, is a moderately variable species of pine, occurring across Southern Europe from the Iberian Peninsula and Lower Austria to the eastern Mediterranean, on the Anatolian peninsula of Turkey, Corsica and Cyprus, as wel…","img":"images/939.jpg","thumb":"images/t/939.jpg","file":"Schwarzkiefer.jpg","ar":1.512,"py":"ouzhouheisong ozhs","cr_by":"Karl Gruber","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/939.jpg","illus_thumb":"images/i/t/939.jpg","illus_file":"Pinus nigra - Köhler–s Medizinal-Pflanzen-242.jpg","illus_ar":0.769,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":943,"seq":936,"zh":"刺柏","en":"Juniperus communis","sci":"Juniperus communis","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"LC","langs":89,"desc_zh":"欧刺柏（学名：Juniperus communis）是一种小灌木，是柏科刺柏属的植物。分布于欧洲、北非、北美以及中国大陆的南京、上海、青岛、杭州等地，目前已由人工引种栽培。和亚洲的桧树亲缘关系较近，属于同一属。本属植物的松球和其他柏科植物不同，无翅并有著近似浆果的肉质，其味苦有清香。 自古以来，欧洲人一直使用欧刺柏种子作为煮肉时的调味料，作为利尿的药物使用，或在啤酒发酵的过程中添加刺柏种子作为苦味的来源。","desc_en":"Juniperus communis, the common juniper, is a species of small tree or shrub in the cypress family Cupressaceae. An evergreen conifer, it has the largest geographical range of any woody plant, with a Holarctic distribution throughout the cool temperate Northern…","img":"images/943.jpg","thumb":"images/t/943.jpg","file":"Juniperus communis fruits - Keila.jpg","ar":0.8,"py":"cibai cb","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":null,"illus_img":"images/i/943.jpg","illus_thumb":"images/i/t/943.jpg","illus_file":"Juniperus communis - Köhler–s Medizinal-Pflanzen-082.jpg","illus_ar":0.791,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":944,"seq":937,"zh":"红杉","en":"Sequoia sempervirens","sci":"Sequoia sempervirens","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"EN","langs":75,"desc_zh":"红杉（学名：Sequoia sempervirens），又称海岸红杉、北美红杉、美国红杉、长叶世界爷、加州红木、咖斗，是世界上最高的针叶树（位于第二高花旗松的变种海滨黄杉以及第三高的北美云杉之上）以及是世界上长的最高的植物之一，能长到115公尺高，主要分布于美国加利福尼亚州。目前已知最老的红杉约有2200岁。 红杉（Sequoia）据信为纪念切罗基文字发明者塞阔雅（Seguoyah）而命名。","desc_en":"Sequoia sempervirens () is the sole living species of the genus Sequoia in the cypress family Cupressaceae (formerly treated in Taxodiaceae). Common names include coast redwood, coastal redwood and California redwood.","img":"images/944.jpg","thumb":"images/t/944.jpg","file":"Sequoia sempervirens Big Basin Redwoods State Park 9.jpg","ar":0.667,"py":"hongshan hs","cr_by":"Allie_Caulfield from Germany","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"针叶树","origin":["北美洲"]},{"id":945,"seq":938,"zh":"巨杉","en":"Sequoiadendron giganteum","sci":"Sequoiadendron giganteum","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"EN","langs":70,"desc_zh":"巨杉（学名：Sequoiadendron giganteum），俗称世界爷，为柏科巨杉属唯一的现生种。主要分布于美国加利福尼亚州内华达山脉西部。阳性树，生长快，而树龄极长。播种繁殖，但幼苗易生病害。巨杉是所有树中最粗大的一种。巨杉不仅是最大的红杉，而且也是地球上最庞大的并且尚存活着的生物。平均可长到50—85米（164—279英尺），直径约5—7米（16—23英尺）。纪录中树高最高可达93.","desc_en":"Sequoiadendron giganteum (also known as the giant sequoia, giant redwood, Sierra redwood or Wellingtonia) is a species of coniferous tree, classified in the family Cupressaceae in the subfamily Sequoioideae.","img":"images/945.jpg","thumb":"images/t/945.jpg","file":"Grizzly Giant Mariposa Grove.jpg","ar":0.541,"py":"jushan js","cr_by":"Mike Murphy ( talk · contribs )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["北美洲"]},{"id":946,"seq":939,"zh":"水杉","en":"Metasequoia glyptostroboides","sci":"Metasequoia glyptostroboides","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"EN","langs":62,"desc_zh":"水杉（学名：Metasequoia glyptostroboides）又名曙杉，落叶乔木，柏科水杉属唯一现存种，中国特产的孑遗珍贵树种，第一批列为中国国家一级保护植物的稀有种类，有植物界“活化石”之称。","desc_en":"Metasequoia glyptostroboides, the dawn redwood, is a fast-growing, endangered deciduous conifer. It is the sole living species of the genus Metasequoia, one of three genera in the subfamily Sequoioideae of the family Cupressaceae.","img":"images/946.jpg","thumb":"images/t/946.jpg","file":"Metasequoia Glyptostroboides2.jpg","ar":0.75,"py":"shuishan ss","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["亚洲"]},{"id":947,"seq":940,"zh":"地中海柏木","en":"Cupressus sempervirens","sci":"Cupressus sempervirens","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"LC","langs":58,"desc_zh":"地中海柏木（学名：Cupressus sempervirens）为柏科柏木属下的一个种。又名丝柏、义大利柏、铅笔柏。","desc_en":"Cupressus sempervirens (also known as the Mediterranean cypress, Italian cypress, Tuscan cypress, or Persian cypress), is a species of cypress native to the eastern Mediterranean region and Iran.","img":"images/947.jpg","thumb":"images/t/947.jpg","file":"Cyprès.jpg","ar":1.333,"py":"dizhonghaibaimu dzhbm","cr_by":"Taoujouti Abdelmouhaïmen","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["亚洲","欧洲"],"illus_img":"images/i/947.jpg","illus_thumb":"images/i/t/947.jpg","illus_file":"T3 01 Cupressus sempervirens par Pierre-Joseph Redouté.jpeg","illus_ar":0.68,"illus_by":"Pierre-Joseph Redouté","illus_lic":"Public domain","illus_licurl":null},{"id":948,"seq":941,"zh":"日本柳杉","en":"Cryptomeria japonica","sci":"Cryptomeria japonica","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"NT","langs":57,"desc_zh":"日本柳杉（学名：Cryptomeria japonica），松柏门柏科植物，原本分类于杉科，也是柳杉属中的唯一一种。是日本的特有种。在日本上直称的スギ（杉或杉木）就是指这个品种。英文则多称此树为 Japanese Cedar （中译日本香柏），但此树其实并不是香柏的一种。日本柳杉林占日本全国12%的土地，也是导致花粉症广泛出现的主要原因。 属名Cryptomeria源于希腊语kryptos（隐藏的）和meros（部分）的合成词。","desc_en":"Cryptomeria (literally \"hidden parts\") is a monotypic genus of conifer in the cypress family Cupressaceae. It includes only one species, Cryptomeria japonica (syn. Cupressus japonica L.f.).","img":"images/948.jpg","thumb":"images/t/948.jpg","file":"Jhomonsugi in Yaku Island Japan 001.JPG","ar":1.333,"py":"ribenliushan rbls","cr_by":"Yosemite","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["亚洲"]},{"id":952,"seq":942,"zh":"桃柘罗汉松","en":"Podocarpus totara","sci":"Podocarpus totara","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"LC","langs":27,"desc_zh":"桃柘罗汉松（学名：Podocarpus totara；毛利语：Tōtara），也称作纽西兰罗汉松，是纽西兰特有的罗汉松。在整个北岛、南岛的东北部的低地、山地及亚高地上生长，最高生长环境可达海拔600米。 桃柘罗汉松常在土壤肥沃且水分充沛的地方中生长。","desc_en":"Podocarpus totara (), commonly known as the tōtara, is a species of podocarp tree endemic to New Zealand. Found across New Zealand, the tree can grow up to a height of 35 m (115 ft), and is known for its longevity.","img":"images/952.jpg","thumb":"images/t/952.jpg","file":"Giant lowland totara.jpg","ar":0.667,"py":"taozheluohansong tzlhs","cr_by":"Tomas Sobek","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["大洋洲"]},{"id":953,"seq":943,"zh":"新西兰陆均松","en":"Dacrydium cupressinum","sci":"Dacrydium cupressinum","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"LC","langs":26,"desc_zh":"纽西兰陆均松（学名：Dacrydium cupressinum）是一种大型的常绿树木，是纽西兰的特有种。过去曾广泛称作red pine（中译红松），但这个名字已慢慢由毛利语所起的名字rimu所取代。","desc_en":"Dacrydium cupressinum, commonly known as rimu, is an evergreen conifer native to New Zealand. A member of the Podocarpaceae, the tree usually reaches 35 metres (100 feet) in height, but may reach up to 60 metres (200 feet) and can have a stout trunk up to 2 m…","img":"images/953.jpg","thumb":"images/t/953.jpg","file":"Rimu-Waitakere.jpg","ar":0.667,"py":"xinxilanlujunsong xxlljs","cr_by":"Kahuroa","cr_lic":"Public domain","cr_licurl":null,"habit":"针叶树","origin":["大洋洲"]},{"id":954,"seq":944,"zh":"智利杉","en":"Saxegothaea conspicua","sci":"Saxegothaea conspicua","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"NT","langs":24,"desc_zh":null,"desc_en":"Saxegothaea is a genus comprising a single species, Saxegothaea conspicua. It is a conifer in the podocarp family Podocarpaceae, native to southern South America.","img":"images/954.jpg","thumb":"images/t/954.jpg","file":"Saxegothea conspicua 3.jpg","ar":1.07,"py":"zhilishan zls","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"针叶树","origin":["南美洲"]},{"id":956,"seq":945,"zh":"智利南洋杉","en":"Araucaria araucana","sci":"Araucaria araucana","order_en":"Pinales","order_zh":"松目","family_en":"Araucariaceae","family_zh":"南洋杉科","iucn":"EN","langs":54,"desc_zh":"智利南洋杉（学名：Araucaria araucana）是最耐寒的南洋杉，原产于智利中部及阿根廷中西部，是常绿树，成年树高50米，树干直径可达2米。其寿命悠长，可达1300年以上。智利南洋杉是南洋杉科少数分布于大洋洲以外的物种，其演化历史相当悠久，故被称为活化石。智利南洋杉是智利的国树。","desc_en":"Araucaria araucana, commonly called the pewen, monkey-puzzle, pehuen or piñonero or Chile pine, is an evergreen tree belonging to the family Araucariaceae and growing to a height of 30–40 m (98–131 ft) and a trunk diameter of 1–1.5 m (3.3–4.9 ft).","img":"images/956.jpg","thumb":"images/t/956.jpg","file":"Araucaria en Parque Nacional Conguillio.jpg","ar":0.667,"py":"zhilinanyangshan zlnys","cr_by":"Vicente Fernández Rioja","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["南美洲"]},{"id":957,"seq":946,"zh":"异叶南洋杉","en":"Araucaria heterophylla","sci":"Araucaria heterophylla","order_en":"Pinales","order_zh":"松目","family_en":"Araucariaceae","family_zh":"南洋杉科","iucn":"VU","langs":51,"desc_zh":"异叶南洋杉（学名：Araucaria heterophylla），又称小叶南洋杉、诺福克松（Norfolk pine）、诺福克岛松（Norfolk Island pine），是南洋杉属下的一个物种，原产澳洲诺福克岛，主要分布地亦有新喀里多尼亚。柱状南洋杉（Araucaria columnaris）在台湾普遍被误认成异叶南洋杉。","desc_en":"Araucaria heterophylla (synonym A. excelsa) is a species of conifer. As its vernacular name Norfolk Island pine (or Norfolk pine) implies, the tree is endemic to Norfolk Island, an external territory of Australia located in the Pacific Ocean between New Zealan…","img":"images/957.jpg","thumb":"images/t/957.jpg","file":"Araucaria heterophylla Norfolk Island 0.jpg","ar":0.667,"py":"yiyenanyangshan yynys","cr_by":"bertknot from scarborough, australia","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["大洋洲"]},{"id":1251,"seq":947,"zh":"瓦勒迈杉","en":"Wollemia nobilis","sci":"Wollemia nobilis","order_en":"Pinales","order_zh":"松目","family_en":"Araucariaceae","family_zh":"南洋杉科","iucn":"CR","langs":47,"desc_zh":"瓦勒迈杉（学名：Wollemia nobilis），又名恐龙杉、沃莱米杉或梧来米松是南洋杉科下瓦勒迈杉属（又称沃莱米杉属）的唯一种，属于孑遗植物，于1994年在澳洲悉尼西北面150公里，新南威尔士的瓦勒迈国家公园温带雨林的狭窄及陡斜的沙岩峡谷中被发现。 瓦勒迈杉又称为梧来米松，但它并非真正的松属植物，且亦不是松科的一员。而它却是与南洋杉科下的贝壳杉属及南洋杉属有所关连。","desc_en":"Wollemia is a genus of coniferous trees in the family Araucariaceae, endemic to Australia. It represents one of only three living genera in the family, alongside Araucaria and Agathis (being more closely related to the latter).","img":"images/1251.jpg","thumb":"images/t/1251.jpg","file":"Wakehurst Place woodland Wollemi pine.jpg","ar":0.667,"py":"walemaishan wlms","cr_by":"AndyScott","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["大洋洲"]},{"id":958,"seq":948,"zh":"欧洲红豆杉","en":"Taxus baccata","sci":"Taxus baccata","order_en":"Pinales","order_zh":"松目","family_en":"Taxaceae","family_zh":"红豆杉科","iucn":"LC","langs":81,"desc_zh":"欧洲红豆杉（学名：Taxus baccata），红豆杉科红豆杉属常绿乔木。植株高10-20m，胸径达2米。叶线形，深绿色，长1-4cm，螺旋状着生，基部扭转排成二列。假种皮肉质、杯状、红色；种子坚果状，位于假种皮中。原产欧洲及北非西部、伊拉克、亚洲西南部。这植物大部分有毒，食用其叶子可致死。欧洲红豆杉是雌雄异株的树，雄树的寿命天生要比雌树长得多，雄树能活5000多年。","desc_en":"Taxus baccata is an Old World species of evergreen tree in the family Taxaceae. It is the tree originally known as yew, though to distinguish it from related species it is sometimes called common yew, European yew, or, in North America, English yew.","img":"images/958.jpg","thumb":"images/t/958.jpg","file":"Taxus baccata tree.jpg","ar":0.75,"py":"ouzhouhongdoushan ozhds","cr_by":"Sitomon","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["欧洲","北美洲"],"illus_img":"images/i/958.jpg","illus_thumb":"images/i/t/958.jpg","illus_file":"Taxus baccata cones illustration.jpg","illus_ar":1.823,"illus_by":"C.Giordano/EUFORGEN","illus_lic":"CC BY-SA 4.0","illus_licurl":"https://creativecommons.org/licenses/by-sa/4.0"},{"id":959,"seq":949,"zh":"东北红豆杉","en":"Taxus cuspidata","sci":"Taxus cuspidata","order_en":"Pinales","order_zh":"松目","family_en":"Taxaceae","family_zh":"红豆杉科","iucn":"LC","langs":30,"desc_zh":"东北红豆杉（学名：Taxus cuspidata），又称紫杉、日本红豆杉、赤柏松、紫柏松、朱树。其木材纹理细致、色泽美丽且具有香味，被视为良好的建筑及家俱用材，比重约为0.51，心材呈红褐色，在古日本被用来作为大官及神职人员的朝笏，因此又名「一位」。东北红豆杉可入药，药名为「紫杉」 ，大量服用会导致心跳停止。","desc_en":"Taxus cuspidata, the Japanese yew or spreading yew, is a member of the genus Taxus, native to Japan, Korea, northeast China and the extreme southeast of Russia.","img":"images/959.jpg","thumb":"images/t/959.jpg","file":"Taxus cuspidata 2.JPG","ar":1.501,"py":"dongbeihongdoushan dbhds","cr_by":"Dalgial","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"针叶树","origin":["亚洲"]},{"id":1252,"seq":950,"zh":"短叶红豆杉","en":"Taxus brevifolia","sci":"Taxus brevifolia","order_en":"Pinales","order_zh":"松目","family_en":"Taxaceae","family_zh":"红豆杉科","iucn":"NT","langs":26,"desc_zh":"短叶红豆杉（学名：Taxus brevifolia），又名太平洋红豆杉（英语：Pacific yew），是红豆杉科红豆杉属的植物，原生于北美洲的太平洋西北地区。其树皮可提炼得到抗癌药物紫杉醇。","desc_en":"Taxus brevifolia, the Pacific yew or western yew, is a species of tree in the yew family Taxaceae native to the Pacific Northwest of North America. It is a small evergreen conifer, thriving in moisture and otherwise tending to take the form of a shrub.","img":"images/1252.jpg","thumb":"images/t/1252.jpg","file":"Taxus brevifolia Blue Mts WA.jpg","ar":0.8,"py":"duanyehongdoushan dyhds","cr_by":"Jason Hollinger","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"针叶树","origin":["北美洲"]},{"id":960,"seq":951,"zh":"日本金松","en":"Sciadopitys verticillata","sci":"Sciadopitys verticillata","order_en":"Pinales","order_zh":"松目","family_en":"Sciadopityaceae","family_zh":"金松科","iucn":"NT","langs":45,"desc_zh":"日本金松（学名：Sciadopitys verticillata），为金松科金松属唯一种，只生长在日本，是当地的特有种，目前已经被引种到世界各地，是一种比较珍贵的观赏植物。","desc_en":"Sciadopitys verticillata, the kōyamaki or Japanese umbrella-pine, is a unique conifer endemic to Japan. It is the sole living member of the family Sciadopityaceae and genus Sciadopitys, a living fossil with no close relatives.","img":"images/960.jpg","thumb":"images/t/960.jpg","file":"Sekiunji Koyamaki, Osaki.jpg","ar":0.75,"py":"ribenjinsong rbjs","cr_by":"Ty19080914","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["亚洲"]},{"id":961,"seq":952,"zh":"灌状买麻藤","en":"Gnetum gnemon","sci":"Gnetum gnemon","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Gnetaceae","family_zh":"买麻藤科","iucn":"LC","langs":34,"desc_zh":"灌状买麻藤（Gnetum gnemon）是裸子植物门买麻藤属下的一种植物，其原产地从印度的米佐拉姆邦和阿萨姆邦向南延伸，经马来半岛、马来群岛及菲律宾群岛直至西太平洋诸岛。","desc_en":"Gnetum gnemon is a gymnosperm species of Gnetum. Its native area spans from Mizoram and Assam in India down south through Malay Peninsula, Malay Archipelago and the Philippines in southeast Asia to the western Pacific islands.","img":"images/961.jpg","thumb":"images/t/961.jpg","file":"Melinjo (Gnetum gnemon) (6863727669).jpg","ar":1.501,"py":"guanzhuangmaimateng gzmmt","cr_by":"gbohne from Berlin, Germany","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["亚洲","大洋洲"]},{"id":962,"seq":953,"zh":"双穗麻黄","en":"Ephedra distachya","sci":"Ephedra distachya","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Ephedraceae","family_zh":"麻黄科","iucn":"LC","langs":30,"desc_zh":null,"desc_en":"Ephedra distachya is a shrub in the family Ephedraceae that stands about 25 cm to 50 cm high. The shrub grows in many parts of the world, including southern and central Europe and western and central Asia. Its local names include somlatha.","img":"images/962.jpg","thumb":"images/t/962.jpg","file":"Ephedra distachya.jpg","ar":0.893,"py":"shuangsuimahuang ssmh","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲","欧洲"],"illus_img":"images/i/962.jpg","illus_thumb":"images/i/t/962.jpg","illus_file":"Illustration Ephedra distachya1.jpg","illus_ar":0.757,"illus_by":"Illustration_Ephedra_distachya0.jpg : Prof. Dr. Otto Wilhelm Thom&eacute derivative work: Bff ( talk )","illus_lic":"Public domain","illus_licurl":null},{"id":963,"seq":954,"zh":"草麻黄","en":"Ephedra sinica","sci":"Ephedra sinica","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Ephedraceae","family_zh":"麻黄科","iucn":"LC","langs":24,"desc_zh":"草麻黄（学名：Ephedra sinica）为麻黄科麻黄属下的一个种。其种加词sinica，意为“中华的”。","desc_en":"Ephedra sinica (also known as Chinese ephedra or ma huang) is a species of Ephedra in the plant family Ephedraceae. Native to Mongolia, northern China, and Russia, it is a shrub found on arid highland slopes, dry river beds, steppes, fields or mountain sides.","img":"images/963.jpg","thumb":"images/t/963.jpg","file":"Ephedra sinica alexlomas.jpg","ar":0.752,"py":"caomahuang cmh","cr_by":"alexlomas on Flickr","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["亚洲"]},{"id":1253,"seq":955,"zh":"Ephedra fragilis","en":"Ephedra fragilis","sci":"Ephedra fragilis","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Ephedraceae","family_zh":"麻黄科","iucn":"LC","langs":19,"desc_zh":null,"desc_en":"Ephedra fragilis, commonly named the joint pine, is a species of Ephedra from the western Mediterranean region of southern Europe (Italy, Spain, and Portugal) and Northern Africa, and from Madeira and the Canary Islands in the Atlantic.","img":"images/1253.jpg","thumb":"images/t/1253.jpg","file":"Ephedra fragilis 3.JPG","ar":1.333,"py":"","cr_by":"User:falconaumanni","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲","非洲"]},{"id":964,"seq":956,"zh":"百岁兰","en":"Welwitschia mirabilis","sci":"Welwitschia mirabilis","order_en":"Welwitschiales","order_zh":"百岁兰目","family_en":"Welwitschiaceae","family_zh":"百岁兰科","iucn":null,"langs":75,"desc_zh":"百岁兰（学名：Welwitschia mirabilis）是单种科百岁兰科百岁兰属的唯一物种。又称为百岁叶、千岁兰、奇想天外、二叶树。最早发现于1859年9月3日，由奥地利探险家Friedrich Martin Joseph Welwitsch发现于非洲安哥拉的沙漠之中。主要分布在安哥拉与纳米布沙漠。茎短，一生只长两片叶。雌雄异株。叶上的气孔会吸收大气中的水气，根极长，可达3米至10米，以吸收地下水。","desc_en":"Welwitschia is a monotypic genus of gnetophytes containing only the species Welwitschia mirabilis. It is named after the Austrian botanist Friedrich Welwitsch, who documented the plant in the 1850s. In common use, it is sometimes referred to as the tree tumbo.","img":"images/964.jpg","thumb":"images/t/964.jpg","file":"Welwitschia mirablis ^ Ragnhild-4657 - Flickr - Ragnhild & Neil Crawford.jpg","ar":1.501,"py":"baisuilan bsl","cr_by":"Ragnhild&Neil Crawford from Sweden","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["非洲"]},{"id":965,"seq":957,"zh":"银叶蕨","en":"Alsophila dealbata","sci":"Alsophila dealbata","order_en":"Cyatheales","order_zh":"桫椤目","family_en":"Cyatheaceae","family_zh":"桫椤科","iucn":null,"langs":32,"desc_zh":"银叶蕨（Cyathea dealbata）是一种生长于纽西兰的蕨类植物。纽西兰是蕨类植物的宝库，许多蕨类植物甚至可以生长为树木大小，银叶蕨就是其中之一。银叶蕨因其叶子为白色而成为毛利人的信仰对象，并且也是纽西兰的象征之一，是纽西兰国徽的组成图案。银叶蕨高度可达10米以上，但通常匍匐生长。其叶子长度可达4米，而背面呈银色，因而得名。","desc_en":"Alsophila dealbata (synonyms Alsophila tricolor and Cyathea dealbata), commonly known as the silver fern or silver tree-fern, or as ponga or punga (from Māori kaponga or ponga), is a species of medium-sized tree fern, endemic to New Zealand.","img":"images/965.jpg","thumb":"images/t/965.jpg","file":"Cyathea dealbata - Jon Sullivan - 1385477.jpeg","ar":0.721,"py":"yinyejue yyj","cr_by":"Jon Sullivan","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"蕨类","origin":["大洋洲"]},{"id":966,"seq":958,"zh":"Sphaeropteris medullaris","en":"Sphaeropteris medullaris","sci":"Sphaeropteris medullaris","order_en":"Cyatheales","order_zh":"桫椤目","family_en":"Cyatheaceae","family_zh":"桫椤科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Sphaeropteris medullaris, synonym Cyathea medullaris, commonly known as mamaku or black tree fern, is a large tree fern up to 20 m (66 ft) tall with a trunk up to 20 cm diameter at breast height.","img":"images/966.jpg","thumb":"images/t/966.jpg","file":"Cyathea medullaris.JPG","ar":0.75,"py":"","cr_by":"wikimedia user gerald.w","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"蕨类","origin":["大洋洲"]},{"id":1254,"seq":959,"zh":"笔筒树","en":"Cyathea lepifera","sci":"Cyathea lepifera","order_en":"Cyatheales","order_zh":"桫椤目","family_en":"Cyatheaceae","family_zh":"桫椤科","iucn":null,"langs":10,"desc_zh":"笔筒树（学名：Cyathea lepifera），又名多鳞白桫椤、蛇木，为桫椤科桫椤属的植物，分布于琉球群岛、菲律宾群岛、新几内亚岛、台湾、福建等华南地区，喜爱潮湿且向阳的开阔环境。","desc_en":"Sphaeropteris lepifera, synonym Cyathea lepifera, the brush pot tree (Chinese: 筆筒樹; pinyin: bǐtǒng shù; Japanese: ヒカゲヘゴ), or flying spider monkey tree fern is an endangered tree fern that grows in the mountains of East and Southeast Asia.","img":"images/1254.jpg","thumb":"images/t/1254.jpg","file":"Cyathea lepifera 2.jpg","ar":1.333,"py":"bitongshu bts","cr_by":"Nakagami at Japanese Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":["亚洲"]},{"id":967,"seq":960,"zh":"欧亚多足蕨","en":"Polypodium vulgare","sci":"Polypodium vulgare","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":45,"desc_zh":"欧亚多足蕨（学名：Polypodium vulgare）为水龙骨科多足蕨属下的一个种。","desc_en":"Polypodium vulgare, the common polypody, is an evergreen fern of the family Polypodiaceae. The name is derived from Greek poly- (\"many\") and pous, podos (\"foot\").","img":"images/967.jpg","thumb":"images/t/967.jpg","file":"Engelsüß HD.JPG","ar":0.75,"py":"ouyaduozujue oydzj","cr_by":"4028mdk09","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null,"illus_img":"images/i/967.jpg","illus_thumb":"images/i/t/967.jpg","illus_file":"Illustration Polypodium vulgare0.jpg","illus_ar":0.652,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":968,"seq":961,"zh":"二歧鹿角蕨","en":"Platycerium bifurcatum","sci":"Platycerium bifurcatum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":21,"desc_zh":"二歧鹿角蕨（学名：Platycerium bifurcatum）为鹿角蕨科鹿角蕨属下的一个种。","desc_en":"Platycerium bifurcatum, commonly known as the elkhorn fern or staghorn fern, is a species of plant in the fern family Polypodiaceae native to Java, Bali, New Guinea,andi in Australia ( New South Wales, Queensland and Lord Howe Island).","img":"images/968.jpg","thumb":"images/t/968.jpg","file":"Platycerium bifurcatum kz01.jpg","ar":1.501,"py":"erqilujiaojue eqljj","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":["大洋洲"]},{"id":969,"seq":962,"zh":"有翅星蕨","en":"Microsorum pteropus","sci":"Microsorum pteropus","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":20,"desc_zh":"有翅星蕨（学名：Microsorum pteropus）又名铁皇冠、三叉叶星蕨，为水龙骨科星蕨属下的一个种。","desc_en":"Leptochilus pteropus (synonym Microsorum pteropus) is a species of aquatic or semi-aquatic fern, commonly known as Java fern (after the Indonesian island of Java). It is predominantly known from Malaysia, Thailand, Northeastern India and parts of South China.","img":"images/969.jpg","thumb":"images/t/969.jpg","file":"Microsorum pteropus.jpg","ar":0.898,"py":"youchixingjue ycxj","cr_by":"Tsunamicarlos at English Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":null},{"id":970,"seq":963,"zh":"Polypodium cambricum","en":"Polypodium cambricum","sci":"Polypodium cambricum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":19,"desc_zh":null,"desc_en":"Polypodium cambricum, the southern polypody, limestone polypody, or Welsh polypody, is a species of fern in the family Polypodiaceae, native to southern and western Europe where it grows on shady rocks, near the coasts of the Mediterranean Basin and in the mou…","img":"images/970.jpg","thumb":"images/t/970.jpg","file":"Polypodium cambricum 001.jpg","ar":1.333,"py":"","cr_by":"Johan N","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["欧洲"]},{"id":971,"seq":964,"zh":"金水龙骨","en":"Phlebodium aureum","sci":"Phlebodium aureum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":17,"desc_zh":null,"desc_en":"Phlebodium aureum (golden polypody, golden serpent fern, cabbage palm fern, gold-foot fern, blue-star fern, hare-foot fern; syn. Polypodium aureum, Polypodium leucotomos) is an epiphytic fern native to tropical and subtropical regions of the Americas.","img":"images/971.jpg","thumb":"images/t/971.jpg","file":"Starr 050107-2831 Phlebodium aureum.jpg","ar":1.336,"py":"jinshuilonggu jslg","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"蕨类","origin":null},{"id":973,"seq":965,"zh":"南方铁线蕨","en":"Adiantum capillus-veneris","sci":"Adiantum capillus-veneris","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":"LC","langs":57,"desc_zh":"铁线蕨（学名：Adiantum capillus-veneris），是凤尾蕨科铁线蕨属的一种植物，又名铁丝草、少女的发丝、铁线草、水猪毛土、银杏蕨、条裂铁线蕨。","desc_en":"Adiantum capillus-veneris, the maidenhair fern, southern maidenhair fern, black maidenhair fern and venus hair fern, is a species of ferns in the genus Adiantum and the family Pteridaceae with a subcosmopolitan worldwide distribution.","img":"images/973.jpg","thumb":"images/t/973.jpg","file":"Adiantum capillus-veneris 2601.jpg","ar":1.333,"py":"nanfangtiexianjue nftxj","cr_by":"Balles2601","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":null,"illus_img":"images/i/973.png","illus_thumb":"images/i/t/973.png","illus_file":"Adiantum capillus-veneris drawing.png","illus_ar":0.85,"illus_by":"Britton, N.L., and A. Brown. 1913. Illustrated flora of the northern states and Canada. Vol. 1: 31.","illus_lic":"Public domain","illus_licurl":null},{"id":974,"seq":966,"zh":"Cryptogramma crispa","en":"Cryptogramma crispa","sci":"Cryptogramma crispa","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Cryptogramma crispa, the parsley fern, is an Arctic–alpine species of fern native to Europe and parts of Asia. It produces separate sterile and fertile fronds, up to 30 cm (12 in) tall, and is a pioneer species on acidic screes.","img":"images/974.jpg","thumb":"images/t/974.jpg","file":"Cryptogramma crispa.jpg","ar":1.333,"py":"","cr_by":"Meneerke bloem","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":["亚洲","欧洲"],"illus_img":"images/i/974.jpg","illus_thumb":"images/i/t/974.jpg","illus_file":"Illustration Cryptogramma crispa0.jpg","illus_ar":0.609,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":975,"seq":967,"zh":"欧洲凤尾蕨","en":"Pteris cretica","sci":"Pteris cretica","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":null,"langs":23,"desc_zh":"欧洲凤尾蕨（学名：Pteris cretica）也称井口边草，为凤尾蕨科凤尾蕨属下的一个植物变种。 别名 白玉凤尾蕨, 井口边草, 石化野鸡尾, 还阳草, 鸡爪凤尾草。","desc_en":"Pteris cretica, the Cretan brake, ribbon fern, or Cretan brake fern, is a species of evergreen fern in the family Pteridaceae, native to Europe, Asia and Africa.","img":"images/975.jpg","thumb":"images/t/975.jpg","file":"Pteris cretica 370560915.jpg","ar":0.75,"py":"ouzhoufengweijue ozfwj","cr_by":"naturewatchwidow","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"]},{"id":976,"seq":968,"zh":"蜈蚣凤尾蕨","en":"Pteris vittata","sci":"Pteris vittata","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":"LC","langs":22,"desc_zh":"鳞盖凤尾蕨（学名：Pteris vittata L.），常见于低海拔温暖潮湿之阔叶林，野外空旷山坡、道路边坡、水沟或砖墙上皆可发现。","desc_en":"Pteris vittata, the Chinese brake, Chinese ladder brake, or simply ladder brake, is a fern species in the Pteridoideae subfamily of the Pteridaceae. It is indigenous to Asia, southern Europe, tropical Africa, and Australia.","img":"images/976.jpg","thumb":"images/t/976.jpg","file":"Pteris vittata.jpg","ar":0.607,"py":"wugongfengweijue wgfwj","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":978,"seq":969,"zh":"欧洲鳞毛蕨","en":"Dryopteris filix-mas","sci":"Dryopteris filix-mas","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":57,"desc_zh":"欧洲鳞毛蕨（学名：Dryopteris filix-mas）为鳞毛蕨科鳞毛蕨属下的一个种。","desc_en":"Dryopteris filix-mas, the male fern, is a common fern of the temperate Northern Hemisphere, native to much of Europe, Asia, and North America. It favours damp shaded areas in the understory of woodlands, but also shady places on hedge-banks, and rocks, and scr…","img":"images/978.jpg","thumb":"images/t/978.jpg","file":"Dryopteris filix mas nf.jpg","ar":0.677,"py":"ouzhoulinmaojue ozlmj","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":["亚洲","欧洲","北美洲"],"illus_img":"images/i/978.jpg","illus_thumb":"images/i/t/978.jpg","illus_file":"Dryopteris filix-mas - Köhler–s Medizinal-Pflanzen-202.jpg","illus_ar":0.773,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":979,"seq":970,"zh":"刺叶鳞毛蕨","en":"Dryopteris carthusiana","sci":"Dryopteris carthusiana","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":30,"desc_zh":"刺叶鳞毛蕨（学名：Dryopteris carthusiana）为鳞毛蕨科鳞毛蕨属下的一个种。","desc_en":"Dryopteris carthusiana is a perennial species of fern native to damp forests throughout the Holarctic Kingdom. It is known as the narrow buckler-fern in the United Kingdom, and as the spinulose woodfern in North America.","img":"images/979.jpg","thumb":"images/t/979.jpg","file":"Dryopteris carthusiana.jpg","ar":1.523,"py":"ciyelinmaojue cylmj","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null,"illus_img":"images/i/979.jpg","illus_thumb":"images/i/t/979.jpg","illus_file":"Dryopteris carthusiana illustration 1.svg","illus_ar":0.714,"illus_by":"USDA Natural Resources Conservation Service","illus_lic":"Public domain","illus_licurl":null},{"id":980,"seq":971,"zh":"欧洲耳蕨","en":"Polystichum aculeatum","sci":"Polystichum aculeatum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":28,"desc_zh":"欧洲耳蕨（学名：Polystichum aculeatum）为鳞毛蕨科耳蕨属下的一个种。","desc_en":"Polystichum aculeatum, the hard shield-fern, is an evergreen fern native to Europe. It is most abundant in upland regions of the British Isles and western France, where it benefits from the combination of mild winters and moist summers, but also occurs more lo…","img":"images/980.jpg","thumb":"images/t/980.jpg","file":"Polystichum aculeatum.jpg","ar":0.75,"py":"ouzhouerjue ozej","cr_by":"MPF","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"蕨类","origin":["欧洲"]},{"id":981,"seq":972,"zh":"矛状耳蕨","en":"Polystichum lonchitis","sci":"Polystichum lonchitis","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":26,"desc_zh":"矛状耳蕨（学名：Polystichum lonchitis），为鳞毛蕨科耳蕨属下的一个种。","desc_en":"Polystichum lonchitis is a species of fern known by the common name northern hollyfern, or simply holly-fern. It is native to much of the Northern Hemisphere from Eurasia to Alaska to Greenland and south into mountainous central North America.","img":"images/981.jpg","thumb":"images/t/981.jpg","file":"Polystichum lonchitis 5579.JPG","ar":1.501,"py":"maozhuangerjue mzej","cr_by":"Walter Siegmund (talk)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["亚洲","北美洲"]},{"id":983,"seq":973,"zh":"欧洲对开蕨","en":"Asplenium scolopendrium","sci":"Asplenium scolopendrium","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":44,"desc_zh":"阿尔泰铁角蕨（学名：Asplenium altajense）为铁角蕨科铁角蕨属下的一个种，分布于北半球。模式标本产地为俄罗斯阿尔泰山。","desc_en":"Asplenium scolopendrium, commonly known as the hart's-tongue fern, is an evergreen fern in the family Aspleniaceae native to the Northern Hemisphere.","img":"images/983.jpg","thumb":"images/t/983.jpg","file":"Asplenium scolopendrium ssp. scolopendrium 20150705 110346 (18816757464).jpg","ar":1.333,"py":"ouzhouduikaijue ozdkj","cr_by":"Erwin Gruber from Frohnleiten, Österreich, Steiermark","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"蕨类","origin":null,"illus_img":"images/i/983.jpg","illus_thumb":"images/i/t/983.jpg","illus_file":"Illustration Asplenium scolopendrium0.jpg","illus_ar":0.597,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":984,"seq":974,"zh":"铁角蕨","en":"Asplenium trichomanes","sci":"Asplenium trichomanes","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":41,"desc_zh":"铁角蕨（学名：Asplenium trichomanes）为铁角蕨科铁角蕨属下的一个种，广泛分布于南极外各大洲。","desc_en":"Asplenium trichomanes, the maidenhair spleenwort (not to be confused with the similarly-named but very different maidenhair fern), is a small fern in the spleenwort genus Asplenium.","img":"images/984.jpg","thumb":"images/t/984.jpg","file":"Asplenium trichomanes subsp. trichomanes 001.jpg","ar":1.333,"py":"tiejiaojue tjj","cr_by":"Johan N","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null,"illus_img":"images/i/984.jpg","illus_thumb":"images/i/t/984.jpg","illus_file":"Illustration Asplenium trichomanes0.jpg","illus_ar":0.555,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":985,"seq":975,"zh":"银杏叶铁角蕨","en":"Asplenium ruta-muraria","sci":"Asplenium ruta-muraria","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":35,"desc_zh":"卵叶铁角蕨（学名：Asplenium rutamuraria）也称银杏叶铁角蕨、疏羽铁角蕨，为铁角蕨科铁角蕨属下的一个种。","desc_en":"Asplenium ruta-muraria is a species of fern commonly known as wall-rue (but which, as a fern, is not by any means closely related to common rue). It is a very small epipetric species, growing exclusively on limestone and other calcareous rocks.","img":"images/985.jpg","thumb":"images/t/985.jpg","file":"505 Asplenium ruta muraria, Asplenium septentrionale.jpg","ar":0.706,"py":"yinxingyetiejiaojue yxytjj","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":null,"illus_img":"images/i/985.jpg","illus_thumb":"images/i/t/985.jpg","illus_file":"Asplenium ruta-muraria — Flora Batava — Volume v1.jpg","illus_ar":0.759,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":987,"seq":976,"zh":"欧洲蕨","en":"Pteridium aquilinum","sci":"Pteridium aquilinum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dennstaedtiaceae","family_zh":"碗蕨科","iucn":null,"langs":50,"desc_zh":"欧洲蕨（学名：Pteridium aquilinum）是碗蕨科蕨属植物。","desc_en":"Pteridium aquilinum, commonly called bracken, brake, pasture brake, common bracken, and also known as eagle fern, is a species of fern occurring in temperate and subtropical regions in both hemispheres.","img":"images/987.jpg","thumb":"images/t/987.jpg","file":"DidzialapisSakys.JPG","ar":1.333,"py":"ouzhoujue ozj","cr_by":"Hugo.arg","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","北美洲"]},{"id":988,"seq":977,"zh":"Dennstaedtia punctilobula","en":"Dennstaedtia punctilobula","sci":"Dennstaedtia punctilobula","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dennstaedtiaceae","family_zh":"碗蕨科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Sitobolium punctilobulum, the eastern hayscented fern or hay-scented fern, is a species of fern native to eastern North America, from Newfoundland west to Wisconsin and Arkansas, and south in the Appalachian Mountains to northern Alabama; it is most abundant i…","img":"images/988.jpg","thumb":"images/t/988.jpg","file":"Dennstaedtia punctilobula2.jpg","ar":1.34,"py":"","cr_by":"Jaknouse","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"蕨类","origin":["北美洲"]},{"id":1255,"seq":978,"zh":"食蕨","en":"Pteridium esculentum","sci":"Pteridium esculentum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dennstaedtiaceae","family_zh":"碗蕨科","iucn":null,"langs":9,"desc_zh":"食蕨（学名：Pteridium esculentum）为蕨科蕨属下的一个种。","desc_en":"Pteridium esculentum, commonly known as bracken fern, Austral bracken or simply bracken, is a species of the bracken genus native to a number of countries in the Southern Hemisphere.","img":"images/1255.jpg","thumb":"images/t/1255.jpg","file":"Pteridium esculentum Chatswood West.jpg","ar":0.75,"py":"shijue sj","cr_by":"Poyt448 Peter Woodard","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"蕨类","origin":null},{"id":989,"seq":979,"zh":"槐叶苹","en":"Salvinia natans","sci":"Salvinia natans","order_en":"Salviniales","order_zh":"槐叶蘋目","family_en":"Salviniaceae","family_zh":"槐叶蘋科","iucn":"LC","langs":35,"desc_zh":"槐叶苹（学名：Salvinia natans），又称蜈蚣苹（台湾话：Giâ-kang-phîng），日语称为山椒藻（サンショウモ），属于漂浮性的水生蕨类植物，通常在春夏时不长孢子囊，等入秋后方由繁殖器官出现，可做为药用，这种植物广布于中国长江以南及华北、东北各地，四川更为普遍；此外越南、印度、台湾、日本和欧洲也有 ，其生长在淡水的沼泽湿地，也是一种重要的环境指标生物，由于目前不少淡水的水域环境遭到过度开发或污染，则逐渐变成一种濒临绝种的…","desc_en":"Salvinia natans (commonly known as floating fern, floating watermoss, floating moss, or commercially, water butterfly wings) is an annual floating aquatic fern, which can appear superficially similar to moss.","img":"images/989.jpg","thumb":"images/t/989.jpg","file":"Salvinia natans (habitus) 1.jpg","ar":1.336,"py":"huaiyeping hyp","cr_by":"Le.Loup.Gris","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/989.jpg","illus_thumb":"images/i/t/989.jpg","illus_file":"Illustration Salvinia natans0.jpg","illus_ar":0.594,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":990,"seq":980,"zh":"苹","en":"Marsilea quadrifolia","sci":"Marsilea quadrifolia","order_en":"Salviniales","order_zh":"槐叶蘋目","family_en":"Marsileaceae","family_zh":"蘋科","iucn":"LC","langs":31,"desc_zh":"苹（学名：Marsilea quadrifolia）为苹科苹属下的一个种。其种加词“quadrifolia”意为“四叶的”。","desc_en":"Marsilea quadrifolia is a herbaceous plant found naturally in central and southern Europe, Caucasia, western Siberia, Afghanistan, south-west India, China, Japan, and Vietnam, though it is considered a weed in some parts of the United States, where it has been…","img":"images/990.jpg","thumb":"images/t/990.jpg","file":"Marsilea quadrifolia denjisou01.jpg","ar":1.333,"py":"ping p","cr_by":"No machine-readable author provided. Keisotyo assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","欧洲","北美洲"]},{"id":991,"seq":981,"zh":"高贵紫萁","en":"Osmunda regalis","sci":"Osmunda regalis","order_en":"Osmundales","order_zh":"紫萁目","family_en":"Osmundaceae","family_zh":"紫萁科","iucn":"LC","langs":37,"desc_zh":null,"desc_en":"Osmunda regalis, or royal fern, is a species of deciduous fern, native to Europe, North Africa and West Asia, growing in woodland bogs and on the banks of streams. The species is sometimes known as flowering fern due to the appearance of its fertile fronds.","img":"images/991.jpg","thumb":"images/t/991.jpg","file":"OsmundaRegalis.jpg","ar":1.545,"py":"gaoguiziqi ggzq","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"],"illus_img":"images/i/991.jpg","illus_thumb":"images/i/t/991.jpg","illus_file":"Illustration Osmunda regalis0.jpg","illus_ar":0.631,"illus_by":null,"illus_lic":"Public domain","illus_licurl":null},{"id":992,"seq":982,"zh":"问荆","en":"Equisetum arvense","sci":"Equisetum arvense","order_en":"Equisetales","order_zh":"木贼目","family_en":"Equisetaceae","family_zh":"木贼科","iucn":"LC","langs":77,"desc_zh":"问荆（学名：Equisetum arvense），又名杉菜，为木贼科木贼属下的一个种。","desc_en":"Equisetum arvense, commonly known as field horsetail or common horsetail, is a species of vascular plant in the horsetail family Equisetaceae. Like all horsetails, it is a type of fern.","img":"images/992.jpg","thumb":"images/t/992.jpg","file":"Equisetum arvense 126536963.jpg","ar":0.75,"py":"wenjing wj","cr_by":"botany08","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"蕨类","origin":null,"illus_img":"images/i/992.jpg","illus_thumb":"images/i/t/992.jpg","illus_file":"Equisetum arvense Lindman DESC.jpeg","illus_ar":1.467,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":993,"seq":983,"zh":"犬问荆","en":"Equisetum palustre","sci":"Equisetum palustre","order_en":"Equisetales","order_zh":"木贼目","family_en":"Equisetaceae","family_zh":"木贼科","iucn":"LC","langs":43,"desc_zh":"犬问荆（学名：Equisetum palustre）为木贼科木贼属下的一个种。","desc_en":"Equisetum palustre, the marsh horsetail, is a perennial herbaceous pteridophyte belonging to the subclass of horsetails (Equisetidae). It is widespread in cooler regions of Eurasia and North America.","img":"images/993.jpg","thumb":"images/t/993.jpg","file":"Equisetum palustre detail.jpeg","ar":1.333,"py":"quanwenjing qwj","cr_by":"Kristian Peters -- Fabelfroh 16:29, 12 August 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","北美洲"],"illus_img":"images/i/993.jpg","illus_thumb":"images/i/t/993.jpg","illus_file":"Equisetum palustre — Flora Batava — Volume v6.jpg","illus_ar":0.687,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1256,"seq":984,"zh":"Equisetum telmateia","en":"Equisetum telmateia","sci":"Equisetum telmateia","order_en":"Equisetales","order_zh":"木贼目","family_en":"Equisetaceae","family_zh":"木贼科","iucn":"LC","langs":39,"desc_zh":null,"desc_en":"Equisetum telmateia, the great horsetail, is a species of Equisetum (horsetail) native to Europe, western Asia and northwest Africa. It was formerly widely treated in a broader sense including a subspecies (subsp.","img":"images/1256.jpg","thumb":"images/t/1256.jpg","file":"Equisetum telmateia ENBLA01.jpeg","ar":0.671,"py":"","cr_by":"Enrico Blasutto","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"]},{"id":994,"seq":985,"zh":"瓶尔小草","en":"Ophioglossum vulgatum","sci":"Ophioglossum vulgatum","order_en":"Ophioglossales","order_zh":"瓶尔小草目","family_en":"Ophioglossaceae","family_zh":"瓶尔小草科","iucn":null,"langs":38,"desc_zh":"瓶尔小草（学名：Ophioglossum vulgatum），为瓶尔小草科瓶尔小草属下的一个植物种。根肥厚肉质，茎短而直立， 叶片单叶全缘肉质，有时叶片上同时著生孢子囊枝，地生型的蕨类，可见于台湾低海拔地区，有时公园中空旷的草地上也可见到。整个叶片汤匙状一片片挺出地面，因此又俗称为一叶草，是一种治疮的中药材，在公园或学校绿油油的草地上偶见有人弯腰采草药，他们多半就是在寻觅瓶尔小草。","desc_en":"Ophioglossum vulgatum, commonly known as adder's-tongue, southern adder's-tongue or adder's-tongue fern, is a species of fern in the family Ophioglossaceae. The chloroplast genome was reported to have a size of 138,562 base pairs.","img":"images/994.jpg","thumb":"images/t/994.jpg","file":"Ophioglossum vulgatum Saarland 01.jpg","ar":0.75,"py":"pingerxiaocao pexc","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":null,"illus_img":"images/i/994.jpg","illus_thumb":"images/i/t/994.jpg","illus_file":"Ophioglossum vulgatum Lindman-1.jpg","illus_ar":0.486,"illus_by":"Carl Axel Magnus Lindman","illus_lic":"Public domain","illus_licurl":null},{"id":995,"seq":986,"zh":"东北石松","en":"Lycopodium clavatum","sci":"Lycopodium clavatum","order_en":"Lycopodiales","order_zh":"石松目","family_en":"Lycopodiaceae","family_zh":"石松科","iucn":null,"langs":53,"desc_zh":"东北石松（学名：Lycopodium clavatum）为石松科石松属下的一个种。台湾话称为石松仔（Tsio̍h-siông-á）、狮仔尾（Sai-á-bué），日语称为日阴蔓（ヒカゲノカズラ）。","desc_en":"Lycopodium clavatum (common clubmoss, stag's-horn clubmoss, running clubmoss, or ground pine) is the most widespread species in the genus Lycopodium in the clubmoss family.","img":"images/995.jpg","thumb":"images/t/995.jpg","file":"Lycopodium clavatum 151207.jpg","ar":0.885,"py":"dongbeishisong dbss","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null,"illus_img":"images/i/995.jpg","illus_thumb":"images/i/t/995.jpg","illus_file":"Lycopodium clavatum - Köhler–s Medizinal-Pflanzen-219.jpg","illus_ar":0.814,"illus_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","illus_lic":"Public domain","illus_licurl":null},{"id":996,"seq":987,"zh":"小杉兰","en":"Huperzia selago","sci":"Huperzia selago","order_en":"Lycopodiales","order_zh":"石松目","family_en":"Lycopodiaceae","family_zh":"石松科","iucn":null,"langs":45,"desc_zh":"小杉兰（学名：Huperzia selago，台湾话：Sió-sam-lân），又称小杉叶石松、小叶石杉，为石杉科石杉属下的一个种。","desc_en":"Huperzia selago, the northern firmoss or fir clubmoss, is a vascular plant in the family Lycopodiaceae. It is small-ish, sturdy, stiff and upright and densely scale-leaved. This plant is an evergreen, perennial pteridophyte.","img":"images/996.jpg","thumb":"images/t/996.jpg","file":"Huperzia selago.jpg","ar":1.333,"py":"xiaoshanlan xsl","cr_by":"User:Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":null},{"id":1257,"seq":988,"zh":"多穗石松","en":"Lycopodium annotinum","sci":"Lycopodium annotinum","order_en":"Lycopodiales","order_zh":"石松目","family_en":"Lycopodiaceae","family_zh":"石松科","iucn":null,"langs":34,"desc_zh":"多穗石松（学名：Lycopodium annotinum）或称杉叶蔓石松，为石松科石松属下的一个种。","desc_en":"Spinulum annotinum, synonym Lycopodium annotinum, known as interrupted club-moss, or stiff clubmoss, is a species of clubmoss native to forests of the colder parts of North America (Greenland, Saint Pierre and Miquelon, all 10 provinces and all 3 territories o…","img":"images/1257.jpg","thumb":"images/t/1257.jpg","file":"Lycopodium annotinum 161102a.jpg","ar":1.333,"py":"duosuishisong dsss","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"蕨类","origin":["亚洲","欧洲","北美洲"]},{"id":997,"seq":989,"zh":"Selaginella selaginoides","en":"Selaginella selaginoides","sci":"Selaginella selaginoides","order_en":"Selaginellales","order_zh":"卷柏目","family_en":"Selaginellaceae","family_zh":"卷柏科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Selaginella selaginoides is a non-flowering plant of the spikemoss genus Selaginella with a wide distribution around the Northern Hemisphere. It resembles a moss in appearance but is a vascular plant belonging to the division Lycopodiophyta.","img":"images/997.jpg","thumb":"images/t/997.jpg","file":"Lesser Clubmoss Selaginella selaginoides (6177389884).jpg","ar":0.75,"py":"","cr_by":"Len Worthington","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"蕨类","origin":null,"illus_img":"images/i/997.jpg","illus_thumb":"images/i/t/997.jpg","illus_file":"Illustration Selaginella selaginoides1 - clean.jpg","illus_ar":1.37,"illus_by":"Otto Wilhelm Thomé","illus_lic":"Public domain","illus_licurl":null},{"id":998,"seq":990,"zh":"Selaginella lepidophylla","en":"Selaginella lepidophylla","sci":"Selaginella lepidophylla","order_en":"Selaginellales","order_zh":"卷柏目","family_en":"Selaginellaceae","family_zh":"卷柏科","iucn":null,"langs":25,"desc_zh":null,"desc_en":"Selaginella lepidophylla (syn. Lycopodium lepidophyllum), also known as a resurrection plant and sometimes as the rose of Jericho (although distinct from the true rose of Jericho) is a species of desert plant in the spikemoss family (Selaginellaceae).","img":"images/998.jpg","thumb":"images/t/998.jpg","file":"Selaginella lepidophylla gruen.jpeg","ar":1.333,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["北美洲"]},{"id":1258,"seq":991,"zh":"小翠云","en":"Selaginella kraussiana","sci":"Selaginella kraussiana","order_en":"Selaginellales","order_zh":"卷柏目","family_en":"Selaginellaceae","family_zh":"卷柏科","iucn":null,"langs":16,"desc_zh":"小翠云（学名：Selaginella kraussiana），也称小翠云草，为卷柏科卷柏属下的一个植物种。 原产非洲，广东（深圳）、贵州（贵阳）等地植物园有栽培，成片生长。欧洲、美洲栽培并有逸生。","desc_en":"Selaginella kraussiana is a species of vascular plant in the family Selaginellaceae. It is referred to by the common names Krauss' spikemoss, Krauss's clubmoss, or African clubmoss, and is found naturally in parts of Sub-Saharan Africa and in Macaronesia.","img":"images/1258.jpg","thumb":"images/t/1258.jpg","file":"Selaginella kraussiana, Krantzkloof NR, c.jpg","ar":1.14,"py":"xiaocuiyun xcy","cr_by":"JMK","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["非洲"]},{"id":999,"seq":992,"zh":"泥炭藓","en":"Sphagnum palustre","sci":"Sphagnum palustre","order_en":"Sphagnales","order_zh":"泥炭藓目","family_en":"Sphagnaceae","family_zh":"泥炭藓科","iucn":null,"langs":24,"desc_zh":"泥炭藓（学名：Sphagnum palustre）为泥炭藓科泥炭藓属下的一个种。像这种类型的其他苔藓它可以吸收的水可达自身干重量的30倍，这归功于其弹性螺旋纤维。","desc_en":"Sphagnum palustre (Syn. Sphagnum cymbifolium), the prairie sphagnum or blunt-leaved bogmoss, is a species of peat moss from the genus Sphagnum, in the family Sphagnaceae.","img":"images/999.jpg","thumb":"images/t/999.jpg","file":"Sphagnum.palustre.-.lindsey.jpg","ar":1.506,"py":"nitanxian ntx","cr_by":"James K. Lindsey","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"苔藓","origin":null},{"id":1000,"seq":993,"zh":"大金发藓","en":"Polytrichum commune","sci":"Polytrichum commune","order_en":"Polytrichales","order_zh":"金发藓目","family_en":"Polytrichaceae","family_zh":"金发藓科","iucn":null,"langs":33,"desc_zh":"土马騣（学名：Polytrichum commune），又名金发苔，为土马騣科金发苔属下的一个种。呈直立状藉著假根固定在土壤内，为苔藓植物。","desc_en":"Polytrichum commune (also known as common haircap, great golden maidenhair, great goldilocks, common haircap moss, or common hair moss) is a species of moss found in many regions with high humidity and rainfall.","img":"images/1000.jpg","thumb":"images/t/1000.jpg","file":"Polytrichum commune.jpeg","ar":1.333,"py":"dajinfaxian djfx","cr_by":"Kristian Peters -- Fabelfroh 14:35, 21 October 2007 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"苔藓","origin":["北美洲","大洋洲"],"illus_img":"images/i/1000.jpg","illus_thumb":"images/i/t/1000.jpg","illus_file":"Polytrichum commune — Flora Batava — Volume v8.jpg","illus_ar":0.728,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1001,"seq":994,"zh":"地钱","en":"Marchantia polymorpha","sci":"Marchantia polymorpha","order_en":"Marchantiales","order_zh":"地钱目","family_en":"Marchantiaceae","family_zh":"地钱科","iucn":null,"langs":32,"desc_zh":"地钱（学名：Marchantia polymorpha）是地钱纲下的一种叶状苔类植物。 地钱广布全球各地，形态多变，包含三个亚种。 本种为雌雄异株，有雌雄株之分。","desc_en":"Marchantia polymorpha is a species of large thalloid liverwort in the class Marchantiopsida. M. polymorpha is highly variable in appearance and contains several subspecies. This species is dioicous, having separate male and female plants. M.","img":"images/1001.jpg","thumb":"images/t/1001.jpg","file":"Moos 5772.jpg","ar":1.333,"py":"diqian dq","cr_by":"Manfred Morgner ( ka-em-zwei-ein )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"苔藓","origin":null,"illus_img":"images/i/1001.jpg","illus_thumb":"images/i/t/1001.jpg","illus_file":"Marchantia polymorpha — Flora Batava — Volume v10.jpg","illus_ar":0.739,"illus_by":"Jan Kops","illus_lic":"Public domain","illus_licurl":null},{"id":1259,"seq":995,"zh":"极小浮萍","en":"Lemna perpusilla","sci":"Lemna perpusilla","order_en":"Arales","order_zh":"天南星目","family_en":"Lemnaceae","family_zh":"浮萍科","iucn":"LC","langs":13,"desc_zh":null,"desc_en":"Lemna perpusilla, the tiny duckweed or minute duckweed, is a species of aquatic flowering plant in the family Araceae. It is native to the central and eastern United States (but not the Deep South), and Quebec in Canada, and has been introduced to various loca…","img":"images/1259.jpg","thumb":"images/t/1259.jpg","file":"Lemna perpusilla 3.JPG","ar":1.333,"py":"jixiaofuping jxfp","cr_by":"Dalgial","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["北美洲"]},{"id":1260,"seq":996,"zh":"红珊藤","en":"Berberidopsis corallina","sci":"Berberidopsis corallina","order_en":"Berberidopsidales","order_zh":"智利藤目","family_en":"Berberidopsidaceae","family_zh":"智利藤科","iucn":null,"langs":10,"desc_zh":null,"desc_en":"Berberidopsis corallina is a species of ornamental plant and is native to Chile. It is claimed to be restricted to the forests behind the port of Coronel in Arauco province and may perhaps be extinct there; brought by Richard Pearce in 1862.","img":"images/1260.jpg","thumb":"images/t/1260.jpg","file":"Berberidopsis corallina.jpg","ar":0.607,"py":"hongshanteng hst","cr_by":"William Jackson Hooker (1785-1865)","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"]},{"id":1261,"seq":997,"zh":"绒毛饰球花","en":"Berzelia lanuginosa","sci":"Berzelia lanuginosa","order_en":"Bruniales","order_zh":"绒球花目","family_en":"Bruniaceae","family_zh":"鳞叶树科","iucn":null,"langs":8,"desc_zh":"绒毛饰球花（学名：Berzelia lanuginosa），又名刻球花，是饰球花属的一种大型常绿灌木，高可达2米（6英尺7英寸），原产于西开普省西部。它在六月至九月间开乳白色或黄色花，因其毛茸茸的花朵知名，也因此成为观赏植物，其种加词在拉丁语中的意思就是“毛茸茸的”。","desc_en":"Berzelia lanuginosa, commonly known as common button bush, is a species of flowering plant in the family Bruniaceae native to the Western Cape region of South Africa. It is a perennial shrub that is hardy from USDA hardiness zones 9a to 11.","img":"images/1261.jpg","thumb":"images/t/1261.jpg","file":"Berzelia lanuginosa 1DS-II 1-C3997.jpg","ar":0.667,"py":"rongmaoshiqiuhua rmsqh","cr_by":"SAplants","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["非洲"]},{"id":1262,"seq":998,"zh":"草珊瑚","en":"Sarcandra glabra","sci":"Sarcandra glabra","order_en":"Chloranthales","order_zh":"金粟兰目","family_en":"Chloranthaceae","family_zh":"金粟兰科","iucn":null,"langs":13,"desc_zh":"草珊瑚（学名：Sarcandra glabra）为金粟兰科草珊瑚属的植物。生长在山坡、沟谷林下荫湿处。 叶可提取芳香油，全草入药有消炎解毒、活血消肿，抗菌消炎之效。","desc_en":"Sarcandra glabra is a herb native to Southeast Asia. It is also known as herba sarcandrae or glabrous sarcandra herb. Other common names include the nine-knotted flower and the bone-knitted lotus. Aromatic oils may be extracted from the leaves.","img":"images/1262.jpg","thumb":"images/t/1262.jpg","file":"Sarcandra glabra2.jpg","ar":1.346,"py":"caoshanhu csh","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":1263,"seq":999,"zh":"瘿椒树","en":"Tapiscia sinensis","sci":"Tapiscia sinensis","order_en":"Huerteales","order_zh":"腺椒树目","family_en":"Tapisciaceae","family_zh":"瘿椒树科","iucn":"VU","langs":10,"desc_zh":"瘿椒树（学名：Tapiscia sinensis），为省沽油科瘿椒树属下的一种植物，为中国独有。其种加词“sinensis”意为“中华的”。瘿椒树是雄性两性异株的树，雄树的寿命天生要比两性树长，雄树能活1500年。","desc_en":"Tapiscia sinensis is a species of plant in the Tapisciaceae family. It is endemic to China. It is threatened by habitat loss.","img":"images/1263.jpg","thumb":"images/t/1263.jpg","file":"Tapiscia sinensis 01.jpg","ar":1.433,"py":"yingjiaoshu yjs","cr_by":"Wendy Cutler from Vancouver, Canada","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["亚洲"]},{"id":1264,"seq":1000,"zh":"Quintinia sieberi","en":"Quintinia sieberi","sci":"Quintinia sieberi","order_en":"Paracryphiales","order_zh":"盔被花目","family_en":"Paracryphiaceae","family_zh":"盔瓣花科","iucn":"LC","langs":7,"desc_zh":null,"desc_en":"Quintinia sieberi, known as possumwood, is a rainforest tree of eastern Australia. It is mostly found in rainforests at high altitude. The range of natural distribution is between the Clyde River, New South Wales (35° S) and the McPherson Range (28° S) just ov…","img":"images/1264.jpg","thumb":"images/t/1264.jpg","file":"Quintinia sieberi - Grose Valley.JPG","ar":1.333,"py":"","cr_by":"Poyt448 Peter Woodard","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":null},{"id":1265,"seq":1001,"zh":"蒺藜","en":"Tribulus terrestris","sci":"Tribulus terrestris","order_en":"Zygophyllales","order_zh":"蒺藜目","family_en":"Zygophyllaceae","family_zh":"蒺藜科","iucn":"LC","langs":71,"desc_zh":"蒺藜（学名：Tribulus terrestris，英文名称：Caltrop, Puncturevine Caltrop, Puncture Vine），古名茨（音同“瓷”），为蒺藜科蒺藜属植物。茎皮纤维可供作制纸之用；种子榨油可供作工业用，油饼则可作为肥料；全草于秋季时晒干可熏杀蚊虫；亦可作为牧草。本种果实因具刺状物而得名刺蒺藜。","desc_en":"Tribulus terrestris is an annual plant in the caltrop family (Zygophyllaceae) widely distributed around the world. It is adapted to thrive in dry climate locations in which few other plants can survive, and is a highly invasive species.","img":"images/1265.jpg","thumb":"images/t/1265.jpg","file":"Starr 030612-0063 Tribulus terrestris.jpg","ar":1.333,"py":"jili jl","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["亚洲","非洲","北美洲","大洋洲"]}];
